UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, citizen.  Those kobolds are thieves and cowards, but in large numbers they pose a threat to us.  And the humans of Stormwind do not need another threat.$B$BFor defeating them, you have my gratitude.',
