UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh? A letter? Wonderful news! I''ve been waiting on word from my dear old mother in Deathknell. Such a saint, she is. I wonder how she''s holding up.$B$BWhat? Too cheery? Not buying it, are you?$B$BWell, get lost then... it''s really no business who the letter''s from anyway. Go on! Get lost!$B$BCome back when you''ve got some coin to spend... loafer.$B$BNext thing you know, you''ll be coming back to rest after a long days adventure or some stupid thing like that.',
    `RequestItemsText` = 'Yes? Yes? What is it?$B$BThe forsaken; they certainly do have huge appetites. Make yourself at home... yes, rest those weary bones. My name''s Renee if you need anything at all.'
