UPDATE `quest_template` SET
    `OfferRewardText` = 'When I left the tainted lands of Lordaeron I returned to a grim state of affairs here in my homeland. But there is hope for Westfall yet. As proven by your valor in battle, it is obvious to me that you serve our cause with honor. It is with great pride that I induct thee into The People''s Militia. May the Light shine upon you.',
    `RequestItemsText` = '$N, now is no time for idle chatter. If you still wish to prove yourself to The People''s Militia you need to slay the Defias I notified you about earlier. Return to me when you have completed your duty.'
WHERE `entry` = 14;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I don''t like hearing of all these kobolds in our mine.  No good can come of this.  Here, take this as payment, and when you''re ready, speak to me again.  I would like you to go back to the mines one more time...',
    `RequestItemsText` = 'Have you been to the mines? Are you ready to report?'
