UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, the paw of Ursangous!  Your skill is impressive, $C; he is credited with numerous kills.  The crescent on his paw is no doubt a sign that he was trained by the night elves that skulk about Ashenvale.  Ursangous is... was one of the mightiest bears you''d find in these parts.  To have bested such a creature is a testament to your will and resolve.$B$BYour ancestors would be proud!',
