UPDATE `quest_template` SET
    `OfferRewardText` = 'A victory for $N in the Ashenvale Hunt!  Well done - the head of Shadumbra is a fitting trophy to claim for such an impressive fight, no doubt.$B$BShadumbra''s savagery was well known throughout the post here.  Any trip to the west, especially on foot trying to get out to the Zoram Strand, was wrought with danger because of this tiger.  Thanks to you, this danger has abated.',
