UPDATE `quest_template` SET
    `OfferRewardText` = 'By the Light! You bet I recognize that handwriting.',
    `RequestItemsText` = 'Marshal Haggard sent you? Why didn''t you say so?$B$BAh, good ol'' Haggard. Poor chap is going to be completely blind before long. Anyway, let me see what you''ve got there.'
WHERE `entry` = 78;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My, you have proved yourself to be quite a detective, $C.',
    `RequestItemsText` = 'This better be good, $C. Let me see what you have and tell me your tale. But by the Light, be quick about it. Darkshire''s defense is my number one priority. I have not the time to squander on dead-end leads.'
WHERE `entry` = 79;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Why yes! The writing on this page does in fact match that of the registry signatures.',
    `RequestItemsText` = 'Back again, $N? What do you have this time?'
WHERE `entry` = 80;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, let''s see what''s in this barrel!$B$BYes, yes, it looks as though it is all here. Here''s your fee for the package, good job on that. I stand to make five times that fee when I sell it to the tavern! Har har!$B$BThese extra bottles of Hinterlands Honey Ripple are going to be set for a special occasion. I think I''ll drink some with champagne. I''ll call it... champipple.',
    `RequestItemsText` = 'If you''re not here to buy anything, and you''re not here to deliver anything, then you''re wasting my time! You better have that ripple!'
WHERE `entry` = 81;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good work - I''ll start my analysis on these now!  I can tell you right from the start though... these are nothing like any insect form I have ever seen.  It''s almost as if these bugs are being controlled by an outside force or something.$B$BYou need to go talk to Fizzledowser right away; apparently there is an emergency that he needs your help with on the double!  I''m not sure, but I think it involves more of the bugs in the Tanaris desert!',
    `RequestItemsText` = 'You''re Junior Surveyor $N, yes?  Quickly now, there is a dire situation at hand!  Do you have the insect parts that Fizzledowser said you would?!'
WHERE `entry` = 82;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, these are nice bandanas, if a little rough...$B$BHere you are!',
    `RequestItemsText` = 'I''m running low on linen, $N.  Do you have any for me?'
WHERE `entry` = 83;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Mm, yum!  This pie is the best!$B$BI think my memory is coming back to me...',
    `RequestItemsText` = 'Ugh... I''m starving!  Do you have that pie for me, $N?'
WHERE `entry` = 84;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You lost a what?  Well I didn''t take no necklace, because I ain''t no thief!$B$BI might know who did but...<grin>...I''m too hungry to remember.',
    `RequestItemsText` = ''
WHERE `entry` = 85;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Though this wild boar meat is tough, simmer it enough and it sure does make for some tasty pie!',
    `RequestItemsText` = 'I don''t think it''s right feeding the boy who stole my necklace in the first place, but if that''s what it takes to get back what''s mine, then so be it!$B$BDo you have that boar meat?'
WHERE `entry` = 86;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, you found it!  Thank you, thank you dear!$B$BHere, take this.  It was my husband''s and he always said it was lucky.  If only he didn''t forget it on his last campaign! *sniff*',
    `RequestItemsText` = 'Hello, $N.  Have you found my necklace?'
WHERE `entry` = 87;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank goodness!  That pig was getting so big she''d have eaten our whole crop!  Thank you, $N.$B$BNow, do either of these suit you?',
    `RequestItemsText` = 'Did you see her yet?  Did you get her?'
WHERE `entry` = 88;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great work, $N. These supplies will help the bridge effort immensely. We''ll get this beauty shored up in no time.',
    `RequestItemsText` = 'This bridge isn''t going to build itself! Now where are those iron pikes and iron rivets?'
WHERE `entry` = 89;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very nice work, $N! Enjoy the delicacy known as Seasoned Wolf Kabob!',
    `RequestItemsText` = 'Were you able to find 10 Lean Wolf Flanks yet? How about the herbs from Felicia in Stormwind?'
WHERE `entry` = 90;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Court of Lakeshire recognizes your commitment to justice, $N. By enforcing the laws of the Kingdom you have helped uphold the justice of the land.',
    `RequestItemsText` = 'Turn in 10 Shadowhide Pendants to me, and you shall be rewarded.'
WHERE `entry` = 91;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N. Such fine specimens too! And here is your delicious delicacy known as Redridge Goulash!',
    `RequestItemsText` = 'I still need five pieces of Tough Condor Meat, five Great Goretusk Snouts and five helpings of Crisp Spider Meat.'
WHERE `entry` = 92;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah yes, a nice clutch of legs you have there! Let me just get these seasoned with my secret spices (no looking!) and get them to skittering on a skillet for a while...$B$BAnd, although Dusky Crab Cakes are my specialty and I won''t give out the recipe, here''s the recipe for a dish that''s almost as good.',
    `RequestItemsText` = 'Hail, $N. Did you get those Gooey Spider Legs yet?'
WHERE `entry` = 93;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You place the Glyph of Azora on the stone. It adheres itself... and you hear from it Theocritus'' disembodied voice:$B$BYou have my gratitude, young $N. You may now speak with me through this Glyph, and I might have future tasks for you... after I have probed the thoughts of my rival.',
    `RequestItemsText` = 'This Lion Statue has sat here for decades, and keeps a lonely watch over the infamous Tower of Ilgalar.$B$BThere is a depression at the base of the statue, where a gem or glyph might be set...'
WHERE `entry` = 94;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A mound of dirt is here, hastily piled up as if someone had need of hiding something...without much time to do it.',
    `RequestItemsText` = ''
WHERE `entry` = 95;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is the proof I asked for. You''ve done well, $N.$B$BI am pleased to be the first to congratulate you and give you this... your water totem.$B$BUse it well, and good luck.$B$BYour next test will not be for some time, so learn your lessons well. Pure water will not only give life back to those who are injured, but can have many other effects. I suggest you seek out a shaman trainer when you have the time. They might have other spells for you to learn.',
    `RequestItemsText` = 'You''ve returned. Splendid!$B$BHow went your journey to Silverpine? Did it take you long?$B$BIt is hard for me to tell if you were successful there because so much of the land has become corrupt. Its stench overwhelms any good that you might have done. But small successes are sometimes as important as large ones. Purifying the water there was instrumental for you, and for all shamans.'
WHERE `entry` = 96;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I knew it! Fine work, $N.',
    `RequestItemsText` = 'Yes, $N?'
WHERE `entry` = 97;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I know, $N: Stalvan is dead. I sensed a wave of hope ripple through the tainted forest. Once and for all, Duskwood is free from his blood thirst. My joy is hampered by thoughts of those who fell prey to the horrible beast. Nonetheless, you are a brave and cunning $C.',
    `RequestItemsText` = 'Yes, $N?'
WHERE `entry` = 98;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your persistence is commendable. With the knowledge you helped me gather, Arugal will fall and his reckless magic shall be undone. Cheers to you, $N.',
    `RequestItemsText` = 'Have you secured the Pyrewood Shackles yet, $N?'
WHERE `entry` = 99;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thanks to you. Thanks to the shamans.',
    `RequestItemsText` = ''
WHERE `entry` = 100;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very wise of you, $N. This Totem of Infliction will help to protect you against the evil which lurks throughout Azeroth and beyond. When you feel threatened, hold this totem and take comfort in its magical aura. Be brave, fair $C. You will need all the courage you can muster for I see much bloodshed in your future.',
    `RequestItemsText` = 'Bring to me 10 ghoul fangs, 10 skeleton fingers and 5 vials of spider venom. For you I shall enchant a Totem of Infliction which will harm those who attempt violent acts against you.'
WHERE `entry` = 101;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N. With valiant adventurers such as yourself fighting alongside The People''s Militia, Westfall just might return to the prosperous breadbasket it once was. Please accept this in recognition of your tireless efforts.',
    `RequestItemsText` = 'Have you collected 8 paws from those treacherous Gnolls yet?'
WHERE `entry` = 102;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Praise you, brave $C. The rocks of the Westfall Coast shall be lit thanks to your hard work. Many lives will be spared so long as the torch is kept lit.$B$BI died needlessly on this very shore. My afterlife plight is to see that no others follow my destiny.',
    `RequestItemsText` = 'The flame will not burn for long without oil, $N.'
WHERE `entry` = 103;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So the foul heathen, Murk-Eye is dead. Well done, $N. By your hands one life was laid to rest but perhaps many more were saved. The Great Sea, wrought with danger as it is, shall be a wee bit safer this night thanks to your heroics.',
    `RequestItemsText` = 'Have you laid waste to the menace known as Old Murk-Eye yet? He has been spotted roaming the coastline of Westfall.$B$BReturn to me when the foul beast is dead.'
WHERE `entry` = 104;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done it! Araj... the lich is finally defeated!$B$BYou''ve done a tremendous service to the Horde on this day, $N. Your bravery and perseverance are a testament to what it means to be a true hero. Please - accept this as a token for all to see and know that you have delivered the Horde a victory for the ages!',
    `RequestItemsText` = 'Your task has been given to you, $N. Do you have a shard from the lich''s phylactery as proof of the task being accomplished?'
WHERE `entry` = 105;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah!  I can''t stand us being apart.  I have to see her!!',
    `RequestItemsText` = 'You have what??  Maybell is the light of my dull life.  Hurry, let me see her letter!'
WHERE `entry` = 106;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My heart goes out to those two poor souls, Maybell and Tommy Joe.  I remember being young and in love, once.$B$BThere must be something I can do to help them!  Let me think...',
    `RequestItemsText` = 'You have a note from "Gramma" Stonefield, eh?  I haven''t seen Mildred in years!  I wonder what she has to say...'
WHERE `entry` = 107;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, so my friend sent you here?  How kind.$B$BWell the Stormwind Monarchy has abandoned our cause.  Now it is up to the People''s Militia to keep the land free from corruption.  If our cause interests you, I can put your combat skills to use in the name of freedom.',
    `RequestItemsText` = 'An... Any luck??'
WHERE `entry` = 109;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, I have the results right here.  They are... unsettling, to say the least$B$BOur initial suspicion that the bugs are being controlled by an outside force, we believe, is correct.  If this is the case, then we are dealing with not only a very powerful unknown force, but also a malignant one.  These bugs have been changed to be pure ravagers.  I''ve never seen anything quite like it.',
    `RequestItemsText` = ''
WHERE `entry` = 110;

UPDATE `quest_template` SET
    `OfferRewardText` = 'While our families are feuding, Tommy Joe and Maybell don''t have much of a future, but... maybe we can get them together for just a little while.$B$BHm, what can we do...',
    `RequestItemsText` = 'I can''t wait to hear how my friends react!$B$BThey''ll never expect it'
WHERE `entry` = 111;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You got them.  Good show!  Now, just one moment while I concoct the potion...',
    `RequestItemsText` = 'Do you have that crystal kelp?  I''m sure Maybell is anxious to see her beau...'
WHERE `entry` = 112;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you for delivering the report, Junior Surveyor $N; here is your pay for your diligent service to the Gadgetzan Water Company.$B$BWhile I am usually not thrilled about handing out our valuable information carte blanche to those who would otherwise pay good coin for it, I''ve known Pestlezugg for a number of years now.  If he recommends letting everyone know about it, then so be it.  Give me a moment and I''ll make you a copy.',
    `RequestItemsText` = 'Well Junior Surveyor $N, has ol'' Pestlezugg got that report ready yet?'
WHERE `entry` = 113;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh...my!  I feel guilty deceiving my family, but my feelings for Tommy Joe are too strong to ignore.$B$BThank you, $N.  I''ll drink this liquor as soon as I have the chance and sneak away to my love.$B$BAnd for you... please take this.',
    `RequestItemsText` = 'Did you deliver my letter to Tommy Joe?  What did he say??'
WHERE `entry` = 114;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. I''ll send these to be destroyed immediately.',
    `RequestItemsText` = 'How goes your conflict with the shadowcasters? Did you find the midnight orbs?'
WHERE `entry` = 115;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A job well done, $N! I know well the roads you had to journey to procure this fine array of liquor. But my patrons will be happy once again!$B$BMy wife is quite a seamstress. Please accept this cloak she made in return for your services.',
    `RequestItemsText` = 'I need you to pick up a keg of Thunderbrew Lager from Grimbooze Thunderbrew in the Westfall hills, a cask of Merlot from Stormwind, a bottle of Moonshine from Darkshire and a skin of Sweet Rum from Goldshire. Bring those back to me and I will see to it you are rewarded.'
WHERE `entry` = 116;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hops and Barley, yeast and malt$B$BThe taste-buds feel a virtual assault,$B$BNo need to plead, no need to beg$B$BFor Thunderbrew Lager comes in a keg!',
    `RequestItemsText` = 'Hurry, my friend, move with haste$B$BIn order for our rich lager to taste$B$BMore like beer and less like stew,$B$BHops are needed to make the brew.'
WHERE `entry` = 117;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Heh, so old Verner needs some shoes, does he!?!',
    `RequestItemsText` = 'What''s that? Verner sent you, you say? Well give me his note. And SPEAK UP!'
WHERE `entry` = 118;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, this really helps me out.$B$BBut what''s this? Argus sent a note with the crate...What?? Argus wants me to PAY him? Bah!$B$BWell, $N, thank you for your help.',
    `RequestItemsText` = 'Great, you''re back! Did you get the shoes?'
WHERE `entry` = 119;

UPDATE `quest_template` SET
    `OfferRewardText` = 'At ease, $C.$B$BMagistrate Solomon is a noble leader. His words carry great weight with me. I shall seek the counsel of the King and make the situation clear to him. Assure the good judge that he has the Stormwind Army''s support. Reinforcements will be sent as soon as word is given from His Majesty.',
    `RequestItemsText` = 'What have you there?'
WHERE `entry` = 120;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you for your time, $C. For your service to Lakeshire and Stormwind I reward you with these coins.$B$BNow if you''ll excuse me, I find this correspondence somewhat of a mystery. Something is amiss in our Kingdom. I fear this is the beginning of conflict, not the end.',
    `RequestItemsText` = 'Did the General send news? Are reinforcements on the way?'
WHERE `entry` = 121;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thanks! These will get me out of debt to Argus...',
    `RequestItemsText` = 'I know that greedy Argus will send someone to collect his scales if I don''t give them to him soon. Have you found those scales yet?'
WHERE `entry` = 122;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hm... I have heard of this "Collector" but I don''t know whom he''s working for.  Thank you for the schedule.  It will help us solve this mystery.',
    `RequestItemsText` = 'What?!?  We haven''t had our people working the Elwynn mines for months!$B$BLet me see that note you have...'
WHERE `entry` = 123;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you for all your help, $N.',
    `RequestItemsText` = 'Yes? Is there something I can do for you?'
WHERE `entry` = 124;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent recovery, $N! I never thought I''d see these tools again.',
    `RequestItemsText` = 'Were you able to find my tools?'
WHERE `entry` = 125;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Again, thank you for your help. The Stormwind army is so busy dealing with the orcs, they don''t have the troops to protect Redridge from local threats like the gnolls.',
    `RequestItemsText` = 'Yowler is a dangerous creature, $N. If you''re not ready for him, I understand.'
WHERE `entry` = 126;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Pleasure doin'' business with you, matey!',
    `RequestItemsText` = 'You have some sunfish for me, eh?'
WHERE `entry` = 127;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I see you have fought valiantly against the Blackrock Clan, $C. Your service to our township is great indeed.',
    `RequestItemsText` = 'Return once you have slain 15 Blackrock Champions.'
WHERE `entry` = 128;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thanks, I could really use the meal. Guarding Lakeshire from the orcs and gnolls is tough work!',
    `RequestItemsText` = 'Darcy sent me a lunch, did she? Such a kind heart she has. Well...let''s have it!'
WHERE `entry` = 129;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You need a bouquet of flowers? You haven''t been in town very long...have you already found for yourself a sweetheart here?$B$BI know I shouldn''t pry, but it''s nice to see that love is in the air... especially in dangerous times like these.',
    `RequestItemsText` = ''
WHERE `entry` = 130;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, those are lovely! I can''t wait to put them in some water!$B$BBut...these are Martie''s favorite flowers. Parker didn''t have you go to that jealous vixen for this bouquet, did he? You didn''t tell her who they were for, did you? If you did, then it wouldn''t surprise me if she poisoned them.$B$BOh, but it''s not your fault. Thank you, and here''s your meal.',
    `RequestItemsText` = 'Hello again, $N. Did Parker like the lunch I sent him?'
WHERE `entry` = 131;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Bah! I should have let that scoundrel rot when I had the chance. But this information is crucial. Good work.',
    `RequestItemsText` = 'Good to see you back, $N. What did Wiley have to say for himself?'
WHERE `entry` = 132;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, thanks. These will do just the trick!',
    `RequestItemsText` = 'I think I hear a pack of Ghouls scurrying around the back of the house - I better put that effigy up quick! Did you get those Ghoul Ribs for me?'
WHERE `entry` = 133;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank the Nec-...well, thank YOU, $N! You have more than earned your reward.$B$BAha! Happy! Happy nights ahead!!',
    `RequestItemsText` = 'Do you have my crate? If so, then please...give it to me quickly!'
WHERE `entry` = 134;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This matter might be more complex than Stoutmantle realizes.',
    `RequestItemsText` = 'What business do you have with me? I am a very busy man. . .'
WHERE `entry` = 135;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The footlocker slowly creaks open. Sand and water seem to be its only contents. But wait! A small crab scurries out with a clue to the treasure in his claws!',
    `RequestItemsText` = ''
WHERE `entry` = 136;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good work, treasure hunter!',
    `RequestItemsText` = ''
WHERE `entry` = 138;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''re on your way to the jackpot, treasure seeker!',
    `RequestItemsText` = ''
WHERE `entry` = 139;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The hinges on the old chest are rusty but they still work. You force the chest open and take the booty.$B$BCongratulations!',
    `RequestItemsText` = ''
WHERE `entry` = 140;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Edwin VanCleef. . .I know the name well. To think that a man so industrious and talented could turn into such a scoundrel unnerves me. I''ll need further proof before I believe this.',
    `RequestItemsText` = 'Did Master Shaw shed any light on things?'
WHERE `entry` = 141;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is indeed firm proof that VanCleef is in charge. Now all we need to know is where the Defias gang is hiding out.$B$BWe''ve had a stroke of luck while you were gone. We captured a thief trying to steal Saldean''s wagon. He has promised to lead us to the hideout in exchange for his life. I want you to defend the traitor so he can reveal the hideout. Return to me once you have uncovered the location.',
    `RequestItemsText` = '$N, were you able to gather any information? Did you locate the messenger?'
WHERE `entry` = 142;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good Messenger, you have served your master well.',
    `RequestItemsText` = 'Hail, $C. What business do you have with The People''s Militia?'
WHERE `entry` = 143;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I do say, this is not good at all. I did not realize that Stoutmantle''s situation was not unlike ours here in Lakeshire. What action is so important that it calls the Stormwind Army away from its people? Bah, I should not ponder aloud.$B$BHere, messenger. Accept these coins in exchange for your service to the Township. I might call upon you again.',
    `RequestItemsText` = 'Shall we expect the People''s Militia soon? Does Lord Stoutmantle''s news bode well?'
WHERE `entry` = 144;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you for making the long journey here. This is indeed important information.',
    `RequestItemsText` = 'You appear to have traveled from afar, $C. What business do you have here in Darkshire?'
WHERE `entry` = 145;

UPDATE `quest_template` SET
    `OfferRewardText` = 'By the Light! The Stormwind Army retreated from Westfall. And the Guard no longer protects Darkshire? There is some treachery abound. How could this be so?$B$BOh I forgot to reward your service, $C. Here are some coins. Now excuse me. Something is amiss in Stormwind and I must get to the bottom of it.',
    `RequestItemsText` = 'Ah, good to see you back, messenger. Shall I inform the Marshal that the Night Watch is on its way from Darkshire?'
WHERE `entry` = 146;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found him?  Well done, $N.  He won''t be "collecting" from the Elwynn Mines again!$B$BAnd this ring you found is interesting... it''s a membership ring for the old Stonemason''s Guild in Stormwind.  Why would a lowly thief have an artisan guild ring, and why are the Defias Thieves collecting money from our mines?$B$BDifficult questions.  I hope one day we''ll have answers.',
    `RequestItemsText` = 'Did you find the Collector?  Did you discover whom he''s working for?'
WHERE `entry` = 147;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, Ghost Hair Thread is what you need, is it? I''m afraid I have none in stock, but I can make some for you...if you can supply the ghost hair.',
    `RequestItemsText` = ''
WHERE `entry` = 148;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What is this? A comb? It''s lovely! And it glides through my hair as if it weren''t the stiff, stringy horror that it is.$B$BOh, if only I had a mirror...',
    `RequestItemsText` = 'Oh please, don''t look at me! I tore out these eyes with my own hands, but I can still feel your gaze!$B$BI''m hideous! Hideous! Please, look away!!'
WHERE `entry` = 149;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N. I hope you didn''t have too much trouble with those murlocs.$B$BIt''s strange seeing them so far from the sea. I wonder if they''re here because they''re running from something...',
    `RequestItemsText` = 'Do you have those fins? Hurry, we need those murlocs driven from the lake!'
WHERE `entry` = 150;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you so much, $N! Poor Old Blanchy will be so happy!',
    `RequestItemsText` = 'Old Blanchy is on her last leg. Did you happen to find any oats for her?'
WHERE `entry` = 151;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N. You have quite a knack for combat. Thanks to you the Coast of Westfall is a safer place.',
    `RequestItemsText` = 'Kill 7 Tidehunters, 7 Warriors, 7 Oracles and 7 Coastrunners and I will see to it that you are rewarded.'
WHERE `entry` = 152;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Nice work, $R. Please accept one of these items as payment for all your hard work.',
    `RequestItemsText` = 'Bring me 15 red leather bandanas and I''ll pay you well.'
WHERE `entry` = 153;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I can make a spool of Ghost Hair Thread with this, and have a few strands to spare. Here are some coins for those extra strands.',
    `RequestItemsText` = 'I sense that you have seen Blind Mary. You have my Comb...?'
WHERE `entry` = 154;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Most excellent, $N! VanCleef is as good as ours now that we know where he is hiding.',
    `RequestItemsText` = 'What business do you have with me? I am a very busy man...'
WHERE `entry` = 155;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good, you got the rot blossoms. And I''ll tell Althea Ebonlocke of the Night Watch that you were killing skeletons.$B$BKeeping the people of Darkshire safe is a grim burden for the Night Watch, and news that others are helping stem the tide of fiends in Duskwood is welcome news indeed.',
    `RequestItemsText` = 'Hi, $N. You have that rot blossoms for me yet?'
WHERE `entry` = 156;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Delightful! This will do splendidly...$B$BHere, good $N, take this as payment for your honorable deed.',
    `RequestItemsText` = 'I need to string the Ghost Hair Thread along my door and my windows to keep out unwanted spirits. Did you get it for me?'
WHERE `entry` = 157;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You need some Zombie Juice, do you? Hmm...that''s some strong stuff - I don''t usually get requests for it.',
    `RequestItemsText` = ''
WHERE `entry` = 158;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A thousand thanks, $N. You warm an old man''s heart with your foolish-...I mean...with your kindness!$B$BHere you are, friend. Take this as a token of my gratitude.',
    `RequestItemsText` = 'I need that Zombie Juice to keep me warm on these cold, dark nights. Did you get it for me?'
WHERE `entry` = 159;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Ello looks at the letter...>$B$BWhat language is this? It looks ancient...I can''t read it.',
    `RequestItemsText` = 'Abercrombie...? I don''t know a person of that name. You say you have a letter for me from this Abercrombie fellow?$B$BWell let''s have it then...'
WHERE `entry` = 160;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, well Ol'' Hinderweir is wise to be worried.',
    `RequestItemsText` = 'You say somethin'', sonny? Can''t hear a bloody thing besides the ringin'' in me ears. Say, what''s that you got there?'
WHERE `entry` = 161;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This report... we night elves know of the terror mentioned here.  Fizzledowser was wise to send this, and you, to me.$B$BThese creatures will consume the Tanaris desert rapidly; they are nothing short of one of the greatest menaces we all will ever face.  Familiarize yourself with this name, $N: silithid.  The insects mentioned here are the silithid, and they are the tools of one of the greatest threats that both the Horde and Alliance face.$B$BIf only we were smart enough to see that before.',
    `RequestItemsText` = 'Peace and tranquility be on to you, stranger.  Why have you sought me out this day?'
WHERE `entry` = 162;

UPDATE `quest_template` SET
    `OfferRewardText` = 'No! Please don''t kill me! It''s just me... Jitters!! They''re everywhere... I can''t escape them! Monsters in Raven Hill? N-n-n-o... couldn''t be. Only harmless Jitters.',
    `RequestItemsText` = 'Ah, $N! Back so soon? No doubt you''ve been at the hunt again? Don''t worry if you''ve had some setbacks, in the long run it will make you better!$B$B...You couldn''t get much worse, anyway...'
WHERE `entry` = 163;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These supplies will be most useful. The aid of the Carevin family is always appreciated. Here is a little something for your trouble.',
    `RequestItemsText` = 'You look a sturdy type, $C. Have you come to join our fight?'
WHERE `entry` = 164;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hehe, oh yes... of course, the Carevins.$B$BNo, nothing''s wrong but it is hard for me to go into town now. The roads are dangerous and I''m not getting any younger. Maybe you can do an old man some favors?',
    `RequestItemsText` = ''
WHERE `entry` = 165;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N, your bravery is remarkable. The People''s Militia thanks you for your service to the people of Westfall. With VanCleef dead, this marks the beginning of the end for the Defias Brotherhood. Hopefully some day soon peace will once again grace the plains of this fair land.$B$BI salute you, Lord!',
    `RequestItemsText` = 'How goes the hunt for Edwin VanCleef?'
WHERE `entry` = 166;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My suspicions were correct. My poor brother.... Well, thank you for bringing some conclusion to this mystery, even if the conclusion was grim.',
    `RequestItemsText` = 'Did you find any sign of my brother? Is there any hope after all this time?'
WHERE `entry` = 167;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you for collecting these, $N. Your efforts will help bring peace to the dead in the wake of this tragedy. I will see to it that the families are notified.',
    `RequestItemsText` = 'Were you able to retrieve any of my old co-worker''s Miners'' Union Cards?'
WHERE `entry` = 168;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Fantastic work, $N! Gath''Ilzogg led those brutes into battle, killing many innocent humans. Vindication is ours. This is the first step in reclaiming the keep for the kingdom of Stormwind!',
    `RequestItemsText` = 'What do you have there, $R?'
WHERE `entry` = 169;

UPDATE `quest_template` SET
    `OfferRewardText` = 'If the problems we''ve had here are indicative of what is happening elsewhere in our lands, by Magni''s beard, we have some troubles ahead of us! I can only hope that the king and Senate are taking steps to deal with the threat the troggs pose.',
    `RequestItemsText` = 'Tenacious little buggers, aren''t they?'
WHERE `entry` = 170;

UPDATE `quest_template` SET
    `OfferRewardText` = 'May the heavens bless you, $N. You''ve done more for Randis than most would ever think of doing for him. Thank you - you''re a shining star in the skies of the Alliance.$B$BPlease - if you can spare the time, come back and visit us. I know that Randis would like that, as would I.',
    `RequestItemsText` = 'It is a pleasure to see you again, $N. Have you attended to the duties you''ve volunteered for during Children''s Week?'
WHERE `entry` = 171;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Zug zug! My name is Grunth, and I guess you''re looking after me? You''re an adventurer, like my mom and dad were. My matron says that they died with honor in battle. I''m happy to meet you.$B$BI hope we''ll do plenty of things together. I have some things I''d like to do, and the matron says you''ll be like a big brother to me during this week. I''d like that a whole bunch.',
    `RequestItemsText` = ''
WHERE `entry` = 172;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Impressive, $N. It would seem that you are capable enough to handle yourself. Perhaps a more suitable challenge could be found for one of your abilities.$B$BIt is curious though... The worgen seemed to just appear out of thin air. But then, with all the other strange creatures that have moved across our borders, I suppose it''s only one of many concerns.',
    `RequestItemsText` = '$N, how fares the hunt?'
WHERE `entry` = 173;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is perfect, $N. The first step is complete!',
    `RequestItemsText` = 'Have you found a skilled engineer to create a bronze tube yet?'
WHERE `entry` = 174;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Why yes, I used to own a looking glass.',
    `RequestItemsText` = ''
WHERE `entry` = 175;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hah!  Well done!  I was starting to think no one would take down that monster!$B$BHere you are, $N.  And thanks - that Gnoll was giving me a headache the size of Blackrock Spire!',
    `RequestItemsText` = 'Yes, Hogger has been a real pain for me and my men.  You have something to report about the beast?'
WHERE `entry` = 176;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Most superb! This will work perfectly. Many thanks!',
    `RequestItemsText` = 'I showed Cog the beginnings of our star-viewing machine. He was impressed. Did you happen to find a reflective device?'
WHERE `entry` = 177;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have my gratitude, $N. I sent that message to the Shadowhide Pendants weeks ago and had believed it a failure. But it seems the spell did reach at least some pendants, after a significant delay.$B$BIn time I hope to learn how to send an attack through the pendants, to immobilize any Shadowhide Gnolls who wear them.$B$BBut before that is possible, I''m afraid that much more research is required.',
    `RequestItemsText` = 'I spoke to you through a pendant, you say? Hmm...give it to me, so that I might study it.'
WHERE `entry` = 178;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah! Wonderful. The wolf meat should do nicely. Oh, don''t worry, $N, I wouldn''t forget my part of the bargain. Here, one of these should fit you.',
    `RequestItemsText` = 'Wolves giving you a bit of trouble? You''d do well to avoid the fangs and claws and other sharp bits, yes?'
WHERE `entry` = 179;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So the evil Lieutenant Fangore is dead? Good riddance to that foul creature. You are very brave, $C. The Township of Lakeshire thanks you for your aid.',
    `RequestItemsText` = 'What news do you bring before the Court?'
WHERE `entry` = 180;

UPDATE `quest_template` SET
    `OfferRewardText` = 'At last! The stargazing device is complete! Thank you, $N. Now I can continue my research. . .',
    `RequestItemsText` = 'Were you able to convince Zzarc''Vul to lend us his monocle for our experiment?'
WHERE `entry` = 181;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Argh! Those Light-blasted trolls!$B$B<He takes a few breaths and seems to settle down... a bit.>$B$BA group of them came in the night and stole my journal! I knew better than to trust that good-for-nothing appr...',
    `RequestItemsText` = 'From what I''ve learned, these trolls hail from the Frostmane clan. I''m afraid I don''t know much else about them that would be of any use to you, $N.'
WHERE `entry` = 182;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent! I can go back to my... leisurely... hunting now. Thank you, $N.',
    `RequestItemsText` = 'How goes the hunt?'
WHERE `entry` = 183;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Loads of thanks, $N! As I was saying, these parts aren''t fit for honest folk anymore, but if things get better, then this deed will let us reclaim our land.$B$BI don''t have much to offer you, but here -- take this.',
    `RequestItemsText` = 'You have the deed to my farm?? That''s good news! Some ruffians stole it days ago... I thought it was gone for good!$B$BPlease, let me have it. We''re on our way out of Westfall and ain''t coming back any time soon, but if we do then we''ll need those papers...'
WHERE `entry` = 184;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Nicely done, $N.  You are ready to move on.',
    `RequestItemsText` = 'I don''t feel confident in training you further, $N, until you have proven yourself skilled in slaying the youngest of the tigers first.'
WHERE `entry` = 185;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I am impressed, $C.  You are progressing quite well.',
    `RequestItemsText` = 'If you strive for greater challenges you must first prove yourself with the task at hand.  Return to me after you''ve killed 10 Stranglethorn Tigers.'
WHERE `entry` = 186;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Most impressive.  I believe you are almost ready.',
    `RequestItemsText` = 'You must kill 10 Elder Stranglethorn Tigers before I give you the final challenge that will determine if you are a true tiger hunting master.'
WHERE `entry` = 187;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Most impressive, I do say!  You are a true Master Tiger Hunter, $N!',
    `RequestItemsText` = 'How goes the hunt for Sin''Dall?'
WHERE `entry` = 188;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh excellent, excellent. That''ll help a little, for the present...$B$B<He trails off, grumbling about profit margins and costs...>$B$BWhat? You''re still here? Reward? Oh, right... of course, here, take this... it should be more than enough.',
    `RequestItemsText` = 'You''ve had success I hope? All over the place, those trolls. Filthy devils.$B$BOh yes, that reminds me! Be sure to tell your friends, yes? We could use much assistance!'
WHERE `entry` = 189;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Off to a good start, $N!',
    `RequestItemsText` = 'A true panther hunter would be out in the fields, trying to stalk his prey. Show some commitment to your goal, $C, and get back out there.'
WHERE `entry` = 190;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Perfectly executed, $N!',
    `RequestItemsText` = 'Go kill 10 panthers!  Show us what you''ve got!'
WHERE `entry` = 191;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done well, $N!',
    `RequestItemsText` = 'What are you doing here, $N!  You should be crawling through the brush, trying to kill 10 Shadowmaw Panthers.  I thought you fancied yourself a big game hunter?'
WHERE `entry` = 192;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Off to a good start, $N!',
    `RequestItemsText` = 'Bhag''thera can prove to be an elusive beast. How fairs the hunt?'
WHERE `entry` = 193;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Nicely done,  old chap !',
    `RequestItemsText` = 'I never met a hunter who got any kills by standing around the campfire.  Were you planning on killing those Stranglethorn Raptors or were you hoping they would die of old age?'
WHERE `entry` = 194;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now that''s how you get a trophy or two over the ol'' hearth!  Nice killing, $N!',
    `RequestItemsText` = 'A true hunter sets his focus on his prey.  You, my friend, seem more concerned with chit-chatting around the campfire.  Now get out there and kill 10 Lashtails before I go and rid the entire bloody jungle of them in one hunt.'
WHERE `entry` = 195;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ho ho!! We have ourselves a true raptor slayer! Nicely done, old chap!',
    `RequestItemsText` = 'Bah!  What are you doing standing around, $N!  A true big game hunter never gives up once his prey is in his sights.  Those Jungle Stalkers aren''t going to come running up to this campfire and throw themselves in it.  Silly  bloke .'
WHERE `entry` = 196;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Master $N, the raptor slayer!$B$BHas a nice ring to it, eh?',
    `RequestItemsText` = 'How goes the hunt for Tethis? Tracked her all the way back to camp, did you?'
WHERE `entry` = 197;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These land mines will help us defend ourselves from that animal Kurzen and his men. Thank you for bringing them. If you need further work, I can probably find something for you to do. And you won''t have to deal with those goblins, hm?',
    `RequestItemsText` = 'Yes? What do you want? Oh, supplies from the goblins. Strange seeing a $R delivering them, usually they send their own. No matter... you didn''t touch them did you? Good good... we wouldn''t want anything to happen to our mines, oh no.'
WHERE `entry` = 198;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is an alarming discovery, to say the least!',
    `RequestItemsText` = 'Did you happen to discover any clues, $N?'
WHERE `entry` = 199;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These are Bookie Herod''s notes and records.$B$BAmong them are: a list of supplies within the camp, material requests from Colonel Kurzen, and various letters and correspondences.',
    `RequestItemsText` = ''
WHERE `entry` = 200;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmmm, so my information was correct, as usual. Interesting. Well, I don''t suppose they pose any sort of threat of interference with our operation, but perhaps they have a need for some of our excellent manufactured products. Hmmm...',
    `RequestItemsText` = 'Well? Did you have any luck in locating the camp?'
WHERE `entry` = 201;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I dared not believe the reports, but you bring us proof that... Kurzen and his leaders are defeated. You have saved us!$B$BThese jungles are filled with menaces of all types, but none had the cruel intellect of Kurzen. We may all breathe easier now that he is gone.',
    `RequestItemsText` = 'Dare I hope that Kurzen and his defenders are dead, $N?'
WHERE `entry` = 202;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done. The loss of those Jungle Fighters will relieve some of the pressure on our camp.$B$BBut now that you''ve had a taste of the forces we''re up against, do you still want to throw your lot in with us??',
    `RequestItemsText` = 'I hope you''ve been successful in your hunting, $N. We won''t last long against him without your help.'
WHERE `entry` = 203;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N. These remedies will keep more of us alive and in fighting shape. And the extracts will help us create our own remedies.',
    `RequestItemsText` = 'I''m waiting on those remedies and that extract, $N.'
WHERE `entry` = 204;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you.  I will study these fetishes and see if they hold the secret of Kurzen''s fall into evil.',
    `RequestItemsText` = 'Do you have those fetishes, $N? They might hold the secret to Kurzen''s degradation...I must know!'
WHERE `entry` = 205;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Aha! You''ve done it! You are a great force for good, $N, and may your strength never fade!$B$BI will study this Mind''s Eye and determine if it may be used for good. If not... then it must be destroyed.',
    `RequestItemsText` = 'I give you my blessing. Mai''Zoth''s strength is matched only by his evil.'
WHERE `entry` = 206;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N.  I will study these legends to see if there is some link between the trolls and the evil that has possessed Colonel Kurzen.',
    `RequestItemsText` = '$N!  Do you have the troll legends?  I must know their secrets!'
WHERE `entry` = 207;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Bloody well done! Right-o! Congratulations, $N, for succeeding where others have failed.$B$BI am honored to count you as a comrade of our great hunting party here. No one will ever doubt your expertise in hunting and tracking!$B$BCheers to you, I say! Cheers!',
    `RequestItemsText` = 'I see you''re back, old bloke. King Bangalash has caused me to come crawling back to camp many times. Hang in there.'
WHERE `entry` = 208;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, good work, good work! Ugh, though you could have done a better job cleaning off the-- Well, no matter, no matter! My thanks to you, $N, our operation will no doubt see increased output and productivity thanks to your help! Good good, now, onto other matters...',
    `RequestItemsText` = 'Tough buggers, aren''t they? Well, have you had any luck? Sorry to seem impatient, but this has been a huge thorn in my side! Well?'
WHERE `entry` = 209;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh I see, it''s a Krazek''s Crock Pot! An ingenious piece of work, but it can break a spring or throw a gear now and then. Let me see what''s wrong with this one...$B$BAha! Its steam charger is rusted out, it has a cracked knuckle-gasket and its fobulator is missing teeth. I''m surprised the pot could even boil a turnip in this state!$B$BCan I fix it? Of course I can fix it!$B$BBut there''s a price. Oh yes, there is always a price...',
    `RequestItemsText` = 'Hello! You brought me something?'
WHERE `entry` = 210;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done it! Araj... the lich is finally defeated!$B$BYou''ve done a tremendous service to the Alliance on this day, $N. Your bravery and perseverance are a testament to what it means to be a true hero. Please - accept this as a token for all to see and know that you have delivered the Alliance a victory for the ages!',
    `RequestItemsText` = 'Your task has been given to you, $N. Do you have a shard from the lich''s phylactery as proof of the task being accomplished?'
WHERE `entry` = 211;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, this will do nicely! Many, many thanks!$B$BNow if you''ll excuse me, I must get the haunch chopped, marinated and garnished for the banquet.',
    `RequestItemsText` = '$N! Do you have that haunch? I must begin preparing it soon, or the banquet will be ruined!'
WHERE `entry` = 212;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Fascinating. That the crystals have been tumbled using this process can only indicate that they are planning to use them as some sort of fuel or other catalyst. I don''t know much more than that. Samples will have to be dispatched to Head Chemist Gigglefont.',
    `RequestItemsText` = 'I need those stones, $N. By whatever means necessary! Just do it, don''t give me the details!$B$BIt''s about results, $N, nothing more, nothing less.'
WHERE `entry` = 213;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N! On behalf of The People''s Militia I salute you for your efforts. Soon we will return this land to the people with help from brave souls like you.',
    `RequestItemsText` = 'Have you been reclaiming our land from the Defias gang? If so show me 10 Red Silk Bandanas as proof.'
WHERE `entry` = 214;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, what Thorsen told you is true. You must be discrete with this. At one time, we rebels were fiercely loyal to Colonel Kurzen. But such was Kurzen''s corruption, our passion twisted into rage.  If it was made known that Private Thorsen has had recent dealings with Kurzen''s men, then one night he would find himself with a slit throat.$B$BTo my knowledge, only Sergeant Yohwa, Thorsen and I were privy to Thorsen''s mission. But there must be another. A traitor.',
    `RequestItemsText` = ''
WHERE `entry` = 215;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done $C, well done!  I will continue to send forces to thin out the furbolg, but I can at least count on a different path that will be free of Alliance entanglements.  The Horde conquest of Ashenvale is now in full swing!$B$BYou''ve earned your pay this day, hero.  I salute you!',
    `RequestItemsText` = 'Have you taken the fight to the Thistlefur?  With a clear path between our bases, our chances of claiming the whole of Ashenvale increase dramatically.'
WHERE `entry` = 216;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Most excellent, $N! You have brought hope to Loch Modan. With Grawmug dead, we stand a better chance of seeing the Troggs eliminated from the land.',
    `RequestItemsText` = 'Grawmug and his two guards, Gnasher and Brawler, are still alive. Your mission is not complete until all 3 have been brought to death. The Dwarven empire is counting on you, $N.'
WHERE `entry` = 217;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wonderful, $N! Many thanks for retrieving my notebook. Well, it would seem that the troll situation here in Coldridge Valley is under control and not much cause for worry.$B$BAfter I put the finishing touches on my report, I''ll need someone to courier it to my brother Senir.',
    `RequestItemsText` = '$N! Any luck?'
WHERE `entry` = 218;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have served the Kingdom well, $C.  Thank you for assisting Corporal Keeshan with his escape from those dreaded Blackrock Orcs.  You shall be rewarded for your brave acts this day.',
    `RequestItemsText` = ''
WHERE `entry` = 219;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, a vial of water created and blessed by Brine, and gathered by you, no less.$B$BThe liquid in this vial will be key in creating a sapta for you, but also used in one other task.$B$BThe sapta I create for you should be used to see the water spirits at the shrine in Silverpine Forest, south of the Undercity. The remaining drops, well, the remaining drops I will tell you about if you feel you are ready.$B$BAre you prepared for one more journey, $N?',
    `RequestItemsText` = 'Hello again, $N. You''re looking well.$B$BWhat brings you back to me so soon?'
WHERE `entry` = 220;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You performed well against the Dark Runners, $N. But it seems as though their numbers are inexhaustible. Every time we make progress, more spring up to refill their ranks.$B$BWhat is the evil power that draws them here? Why have they come to disturb our unhappy realm...$B$BI will put my faith in Master Carevin. No doubt he will get to the bottom of the problem.',
    `RequestItemsText` = 'Back so soon, $N? I hope you haven''t come to tell me you''ve given up.'
WHERE `entry` = 221;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N, to be honest with you, I did not believe that you would get this far, but you are clearly a $C to be reckoned with. In fact, if you wish to formally join Master Carevin''s struggle, I will gladly write for you a letter of recommendation.',
    `RequestItemsText` = 'Intimidating beasts aren''t they? But have no fear, $N, those who stand for the Light will never fall!'
WHERE `entry` = 222;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excuse me for my cold reception, $N, but as I''m sure you can tell, I am an extremely busy man. I see that you have impressed Calor--and I assure you, that is no small feat--and that he has given his recommendation.$B$BThere are unsavory types afoot, $N, and we can use the help of all who have proven themselves. We battle against demons, the undead, and those who would provide them aid. Be vigilant, be wary, and trust none who would not give aid to our cause.$B$BGlory under the Light.',
    `RequestItemsText` = 'Yes, what is it? Make it quick, I''ve pressing matters to attend to.'
WHERE `entry` = 223;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N! You demonstrated uncanny courage on the battlefield. Our war against the Troggs will be won with efforts such as yours. You have served King Magni well.$B$BIf you fancy yourself well-suited for this kind of adventuring, I suggest you speak with Mountaineer Gravelgaw. The Captain has him assigned to a rough patrol that I am sure he can use some help with. Check with Gravelgaw just inside the tower.',
    `RequestItemsText` = 'Loch Modan is under siege, $N! We need every able-bodied member of the Alliance to aid our cause. Have you killed 10 Stonesplinter Troggs and 10 Stonesplinter Scouts yet?'
WHERE `entry` = 224;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Morgan Ladimore?$B$BAhh, yes, of course. His was a long and sorrowful tale. I knew him, well, before he left for the war, but that was the last time I saw him. A noble and good man, he was, but he suffered a bad end.$B$BHere, I should have something here that can tell the tale better than my own recollections...',
    `RequestItemsText` = ''
WHERE `entry` = 225;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh good. You thinned out that pack quite a bit, and without those wolves nipping out our heels, we can bind our minds to dealing with Morbent Fel.$B$BHere, take some of these Flash Bundles. They make them in town, and a lot have been donated to Sven to help with his cause.',
    `RequestItemsText` = 'You still hunting wolves...?'
WHERE `entry` = 226;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Morgan Ladimore? Never heard of...$B$BOh, you mean Mor''Ladim! I guess you haven''t heard the story?$B$BWell, I''ll give you the short version. A wandering undead calling itself Mor''Ladim has been wandering Duskwood. From what we''ve gathered, it appears to be the undead body of Morgan Ladimore, of whom you apparently know. He''s been causing us all sorts of problems, attacking Watchmen on patrol and killing people.$B$B<She sizes you up.>$B$BYou seem to be capable enough, maybe you could lay him to rest.',
    `RequestItemsText` = ''
WHERE `entry` = 227;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You killed him? That''s no small accomplishment, $N! On behalf of the people of Darkshire and the Night Watch, I thank you.$B$BAh... there is one small matter, however...',
    `RequestItemsText` = 'I don''t blame you if you''re having trouble with him, $N. Some of our strongest Watchers have been lost to Mor''Ladim.'
WHERE `entry` = 228;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes? My father...$B$B<Her eyes become downcast.>$B$BI wish... there was something I could have done for him... If only I had talked to him before he...',
    `RequestItemsText` = ''
WHERE `entry` = 229;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Sven reads the book''s pages, then slams it shut.>$B$BThat shadowy figure I saw was a witness to my family''s death! There are questions I''d like to ask that man...if only I knew who he was!',
    `RequestItemsText` = 'You found what?? Please, let me see it...'
WHERE `entry` = 230;

UPDATE `quest_template` SET
    `OfferRewardText` = '<A ghostly voice sounds on the wind...>$B$BThis is...? Sarah? Could it be she''s still alive? The weight is removed from my shoulders...$B$B$N. Take my sword, Archeus. As my soul is put to rest, I have no more need for it. It was forged to do good, and though I have proved myself unworthy to hold it, perhaps you will carry on the Light through it.$B$BLys, my love...',
    `RequestItemsText` = 'Leave me be...'
WHERE `entry` = 231;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, Zinge needs a kit, does she?  It saddens me that Zinge does not choose to grace myself with her sweet presence.$B$BVery well, let me procure a kit for you.',
    `RequestItemsText` = 'Yes, and what may I assist you with?  Are you here on business for the Royal Apothecary Society, or have you arrived here merely to brighten my day?'
WHERE `entry` = 232;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, I''ve been waiting for these letters for quite some time...$B$BUnfortunately, these letters aren''t all for me. This one is addressed to Grelin Whitebeard. He''s not too far away if you''d like to deliver it to him.',
    `RequestItemsText` = 'Yes? Do you have something for me?'
WHERE `entry` = 233;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, excellent. It''s been a while since I received word from Ironforge.',
    `RequestItemsText` = 'Is there something I can help you with?'
WHERE `entry` = 234;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Welcome to the new frontier, $N.  Ashenvale is a land of opportunity, one where a young $C like yourself is able to find boundless chances to prove their mettle.  Look around the outpost here, and be sure to travel out to the Zoram Strand, as the Horde has another outpost there as well.$B$BYour presence here tells me that you''ve come to learn more about the hunt.  Listen close, and I will gladly share with you what you need to know.',
    `RequestItemsText` = ''
WHERE `entry` = 235;

UPDATE `quest_template` SET
    `OfferRewardText` = '',
    `RequestItemsText` = ''
WHERE `entry` = 236;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You accomplished your mission well, $R. The King himself would be proud.$B$BThe reinforcements promised to us never showed, however. Apparently the Alliance front is a sea of crimson from the blood of our fallen brethren. The news of the losses leaves a bitter taste in one''s mouth. But we must not let their deaths go for naught. We must rally in these grim times and bring glory back to the Alliance.$B$BSpeak with Mountaineer Wallbang for reassignment. You''re needed now more than ever.',
    `RequestItemsText` = 'We need more time, $R. Your orders are to kill 10 Stonesplinter Skullthumpers and 10 Stonesplinter Seers. Keep the enemy under pressure until we are granted reinforcements. This is no time for idle behavior.'
WHERE `entry` = 237;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good - it pleases me to be working with someone who takes pride in not wasting my time.$B$BAfter I make some adjustments to this kit, you''ll be ready to head out into the field. You''ll be using it to collect some vital data to the task at hand.$B$BIt will take just a moment for me to finish the modifications. While you are waiting, you should probably start thinking about what you''d like to bring to the desert with you.$B$BYes, I said the desert.',
    `RequestItemsText` = 'Yes, I think Luca is as disturbing as you do. It matters not - hand me the field sampling kit. I will need to make some adjustments to it in order to survey for the proper base materials.$B$BYou have the kit, don''t you?'
WHERE `entry` = 238;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Marshall Dughan sent you, eh?  Well you''re not from the army, but if Dughan sent you then that''s good enough for me!$B$BOur situation is, to say the least, a stressed one.  I hope you can give us a hand.',
    `RequestItemsText` = ''
WHERE `entry` = 239;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Aha! Thank you, $N. Those really hit the spot!$B$BAnd here, please let me pay you for these!',
    `RequestItemsText` = '$N, you''re here! Do you have my food?!?'
WHERE `entry` = 240;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, our model 4711-FTZ power sources! We normally use them to power the water wells, but THANKS TO THE VILE NOMADS, we have an over abundance of power sources right now.$B$BSure, I can get you a power source for whatever nefarious science experiment you think you''re trying to hide from me. It ain''t gonna be free though, $R. Nothing''s free in Gadgetzan.',
    `RequestItemsText` = ''
WHERE `entry` = 243;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There are Redridge gnolls that close to Elwynn?? They may be poised to advance into our homeland. Soon the people of Lakeshire may not be the only humans under siege!$B$BHere is your pay, though you bring us dire news. And it comes at a bad time, for we are ill equipped to deal with it.',
    `RequestItemsText` = ''
WHERE `entry` = 244;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah! You''re back. And not too much worse for wear, it''d seem. Of course, $N, the Night Watch is grateful for your work, and I did promise you a reward, so here.',
    `RequestItemsText` = 'You''d best be careful when dealing with the spiders, I''ve lost a few of my men to them, and trust me, it isn''t a pleasant sight to see a man hanging upside down in their webs after the venom has started to soften them up.$B$BI wouldn''t want to see one of the bugs having you for lunch.'
WHERE `entry` = 245;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Deputy Feldon listens to your report...>$B$BThere''s a sizable force of gnolls encamped there, and from what you tell me they are tough ones. It must not have been easy for you to gather this intelligence.$B$BHere you are, $N. We are grateful for your aid.$B$BAnd if you haven''t already done so, speak with Marshal Marris and Magistrate Solomon within Lakeshire. Our situation grows ever more desperate - those two will have need of you I''m sure.',
    `RequestItemsText` = 'Excuse me, $N, but we have a lot to keep our hands tied here. If you have nothing to report, then I must put my mind to other matters.'
WHERE `entry` = 246;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N, you have slain all three beasts that comprise the Ashenvale Hunt.  You have brought me adequate proof of their demise; there is no question of your strength and tenacity.  The blood of a hunter streaks through your veins, and you should be commended!$B$BPlease, accept this bauble as a sign of congratulations on your mighty deeds done in Ashenvale for the Horde today.  May your ancestors watch over you!',
    `RequestItemsText` = ''
WHERE `entry` = 247;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is a suitable vessel for the Glyph of Azora, allowing Theocritus to delve into the minds within Stonewatch Keep.',
    `RequestItemsText` = 'This jar once held a foul-smelling liquor, but now lies empty and forgotten on a pair of barrels.'
WHERE `entry` = 248;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, $N. In defeating the warlock Morganth, Stormwind is saved from a grave peril.$B$BI offer you this reward most humbly. And I would bid you peace, if these were peaceful times.$B$BBut instead, I will bid you luck with your trials, and victory in the conflicts ahead.',
    `RequestItemsText` = 'Hurry, $N, before my fears of Morganth spreading his power are made real!'
WHERE `entry` = 249;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The suspicious looking barrel contains a strange smelling powder.',
    `RequestItemsText` = ''
WHERE `entry` = 250;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Sirra begins translating the note...>',
    `RequestItemsText` = 'A note from Abercrombie the hermit, eh? I don''t know him, though if he lives out at the graveyard then I do know his brains have rotted out!'
WHERE `entry` = 251;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Ello reads the letter...and his face goes white. He then looks at you...>$B$BAlthough the aid you gave Abercrombie may have been motivated from kindness, your actions have doomed our town.$B$B<Ello becomes lost in his thoughts...>',
    `RequestItemsText` = 'Ah, is the note translated? Please, let me see it...'
WHERE `entry` = 252;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done it! The magic within his heart will be proof against the Embalmer''s evil, and a powerful aegis over the town of Darkshire.$B$BYou have done a great thing for our people, $N. Your name will remain in our annals forever.',
    `RequestItemsText` = 'Have you yet found Eliza''s grave? Do you have the Embalmer''s heart?'
WHERE `entry` = 253;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You dig through the semi-loose dirt over the grave...and find the remains of a coffin.$B$BWithin the coffin you can feel the vibrating scrapes of clawed fingers and the gnashing of rotted teeth...$B$BWill you open the coffin and retrieve the Embalmer''s heart?',
    `RequestItemsText` = ''
WHERE `entry` = 254;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, this is excellent news! Your efforts are greatly appreciated by myself and the people of Thelsamar. Better yet, if we can solve the ogre problem, we''ll be able to shift our focus to those Light-burning troggs.',
    `RequestItemsText` = 'Have you had any luck?'
WHERE `entry` = 255;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yech! What is that thing? And why would you bring it...$B$BBloody--! Is it? Well, Light burn me, is that the head of that bloody ogre? This certainly is a catch then! Here, your reward and the thanks of myself and the people of Thelsamar.',
    `RequestItemsText` = 'Yes? Is there something I can do for you?'
WHERE `entry` = 256;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What? Success?$B$BTake it from me, $Nama, you don''t let it get to your head. I mean, any unshaven boy with a bow could have killed such... small specimens. And I hope you don''t enjoy killing the buzzards so much, yes? We wouldn''t want them to become extinct.$B$BWell, err... Never let it be said that Daryl the Bold would not hold to his word.',
    `RequestItemsText` = 'No luck? Don''t feel too bad, $N...$B$BNot everyone can be me.'
WHERE `entry` = 257;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You seem a bit worse for wear. No doubt the boars gave you some trouble, hm? No worries, I will be discreet about your struggle, I can imagine how hard it must be for you without the accusations of wagging tongues.$B$BOh! You managed to kill the boars? I... well, that is... that is to say, I''m not surprised! Any child could have--bet?$B$BWhat bet?',
    `RequestItemsText` = 'It''s only natural to feel sorry for yourself when shown up by someone so new to this world. You shouldn''t feel bad, $N.$B$BHm? Did I get your name wrong?'
WHERE `entry` = 258;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have proven your resolve, and the Scarlet Crusade commends you.$B$BIf you do not shy from righteous slaughter, then perhaps your path lies with us...',
    `RequestItemsText` = 'The Scourge grows in power with the passing of each day. If you truly wish to halt its advances, then show me.'
WHERE `entry` = 261;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmm... Someone handled this book recently, someone who is driven by revenge. But the impressions left on it, at least the impressions from the original owner, are faint.$B$BI can tell, however, that the original owner of this book is not a native of Darkshire.',
    `RequestItemsText` = 'If you have something that belongs to the shadowy figure for whom you seek, then let me see it. I may be able to divine something of its owner.'
WHERE `entry` = 262;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I knew the second I laid eyes on you, $N, that you would make Ironforge proud. You have served King Magni well. Now that you''ve proven yourself to be such a loyal aid to the Kingdom, perhaps you should talk with the Captain to see if he''ll entrust you with a higher detail.$B$BI salute you, $N.',
    `RequestItemsText` = 'Back so soon? In case I didn''t make myself clear we need you to kill 10 Stonesplinter Shaman and 10 Stonesplinter Bonesnappers, $N. Now go get ''em, Trogg-Slayer!'
WHERE `entry` = 263;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You place the worthless pendant on the grave, and the gemstone within the setting seems to dull noticeably.$B$BAs you stand to leave, you look down at the pendant; it lies lifelessly over the hands of the relief sculpted into the top of the coffin. Your thoughts are interrupted by a stiff, cool breeze passing over the Sepulcher. For a moment everything around you is silent.',
    `RequestItemsText` = 'The stone is cold to the touch, but has obviously been abused. Trash litters the area; nicks and gashes decorate the relief atop the coffin; and the foliage around the grave has started to grow over the site.$B$BNo one cares for whoever is buried here, especially not any victims of the plague.'
WHERE `entry` = 264;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, yes. I sold this book a month ago to a shady person. He didn''t tell me his name, but he was a nervous, jittery chap, always looking over his shoulder.$B$BI hope that helps you...',
    `RequestItemsText` = 'Sometimes I''ll sell blank books to scholars and mages, or to anyone who wants to keep a journal.$B$BI remember well everyone to whom I sold a book within the last few months...'
WHERE `entry` = 265;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh yeah, I remember this book. Its owner rented a room for a few days, and spent his nights at the bar, writing.$B$BHe left town in a hurry, muttering about being hunted by...something. Last I saw him he was heading west out of town, looking for a new spot to hide.$B$BThe first place he''d find to the west is Raven Hill...',
    `RequestItemsText` = 'The Scarlet Raven doesn''t see the business it used to, but we still do get travelers passing through.$B$BIf you can describe the person you''re looking for, maybe I''ll remember him.'
WHERE `entry` = 266;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I am quite impressed, $N. You have done the Dwarven race a great favor by defending our lands. King Magni Bronzebeard himself would be proud!',
    `RequestItemsText` = 'Do you have 8 Trogg Stone Teeth to show me? If not, there is still work to be done, $N.'
WHERE `entry` = 267;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This journal explains much to me, and sets me on the path against the dark riders! I have seen these riders in Duskwood, and have seen them speak with the wizard Morbent Fel, at the Forlorn Rowe.',
    `RequestItemsText` = 'Did you find who the Shadowy Figure was?'
WHERE `entry` = 268;

UPDATE `quest_template` SET
    `OfferRewardText` = '<After reading the journal and hearing your intent...>$B$BAn evil taint has gained a foothold within the already beleaguered Duskwood. I thank the Light we have a hero such as you to face it.$B$BBut you must first prepare yourself for the coming trial...for the Necromancer Morbent Fel is immensely powerful, and has cast dark enchantments about himself to protect him from physical assaults. If you are to defeat him, you will need a weapon that is proof against these protections.',
    `RequestItemsText` = 'Rest, brother. I can tell you have traveled far, and you bear a heavy burden. Can you tell me what casts that dark shadow over you?'
WHERE `entry` = 269;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Lightforge Iron is a precious metal, but it sounds like your quest is a dire one. You''ve come a long way, Brother. With luck, you might just find what you seek!$B$BAnd if you do get the iron, I know who can fashion it into a weapon against this Necromancer you speak of in Duskwood.',
    `RequestItemsText` = ''
WHERE `entry` = 270;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Er... what''s this? A bear''s head, by the looks at it.$B$B<He runs a finger along his scar unconsciously.>$B$BWell, that''s quite an interesting kill you have yourself there. Couldn''t be that bear from back then...$B$B<He trails off then starts to visibly shake.>$B$BOh, take that away take it away! Get that grisly thing out of here!',
    `RequestItemsText` = 'Ah, $N! Back so soon? No doubt you''ve been at the hunt again? Don''t worry if you''ve had some setbacks, in the long run it will make you better!$B$B... You couldn''t get much worse, anyway...'
WHERE `entry` = 271;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve completed the Trial of the Sea Lion, $N - congratulations.$B$BEach task in acquiring the pendant shows that both agility and endurance are necessary to act in harmony with what you desire to do underwater. Neither can exist without the other, and both cannot be done without your willingness to embrace the aspect of the sea lion.$B$BRemember these lessons well, and count on them once you have gained your aquatic form.',
    `RequestItemsText` = 'Have you formed your pendant for me to inspect, $N? If you need help in locating the parts, try asking the local populace for information. Not only will you find what you seek, but it will give you a reason to explore this wondrous and sacred glade.'
WHERE `entry` = 272;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmph, it''ll take more than a Dark Iron ambush to stop the deliveries!$B$BBut Saean... I would never have suspected him to be one of their sympathizers. We''ve been working with him for almost a year now... maybe I missed the signs.$B$BWell, I''ll consider that later.',
    `RequestItemsText` = ''
WHERE `entry` = 273;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A disarming colloid? For Seaforium? Oh heavens!',
    `RequestItemsText` = 'What is that you bring from Ashlan?'
WHERE `entry` = 274;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This land is soothed by your efforts, and for this I will grant you a boon.',
    `RequestItemsText` = 'The Wetlands still weep, and the Fen Creepers still rage. Return to me when your task is done.'
WHERE `entry` = 275;

UPDATE `quest_template` SET
    `OfferRewardText` = 'By reducing the Gnolls'' number, you have tended to the health of the Wetlands. Although my faith in your people has been taxed in the past, $R, it may yet be restored.',
    `RequestItemsText` = 'Your task is still at hand, young $C.'
WHERE `entry` = 276;

UPDATE `quest_template` SET
    `OfferRewardText` = '... thank you. I will smash these flints and cast them into the sea, so that they may never again be used to burn living wood.',
    `RequestItemsText` = 'Do you have the Gnolls'' tools for fire?'
WHERE `entry` = 277;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Just in time, $N!',
    `RequestItemsText` = 'Do you have the needed items? Time is of the essence!!'
WHERE `entry` = 278;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, well done $N.$B$BAccept this as payment for fulfillment of your contract with the Merchant Marines.',
    `RequestItemsText` = 'Our merchants will not be safe until we are rid of Gobbler and those Murlocs.'
WHERE `entry` = 279;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The keg fizzles slightly as the Disarming Mixture settles in.',
    `RequestItemsText` = 'The top of the keg slowly twists off.'
WHERE `entry` = 280;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This crate is covered with clawed scratches, and the marks of water damage. Prying it open reveals soggy and rotted straw, as if something of value was stored in the crate. You search through the straw...$B$B...and find a an armload of red-colored bottles.',
    `RequestItemsText` = ''
WHERE `entry` = 281;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hm, well, if Whitebeard is sending you to Dun Morogh on important business, I can''t very well stop you, can I?$B$BAt least let me provide you with some advice and directions.',
    `RequestItemsText` = 'Hail! Have a care, $N, the tunnel to Dun Morogh is infested with troggs and is not safe for travel.$B$BIf you haven''t any pressing business in Dun Morogh, I''ll have to ask you to remain in Anvilmar until the tunnel is safer.'
WHERE `entry` = 282;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you so much, $N!! You have saved the Stonewrought Dam! Without your help, the Dark Iron terrorists would have surely seen to this mighty landmark''s demise. You have made the Kingdom and the Alliance proud, brave $C.',
    `RequestItemsText` = ''
WHERE `entry` = 283;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This barrel is largely untouched. Prying it open...$B$B...you are assaulted by the pungent odor of cheese. It''s a little wet, but still tasty!',
    `RequestItemsText` = ''
WHERE `entry` = 284;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This barrel is halfway buried amidst the mud and grass ...',
    `RequestItemsText` = ''
WHERE `entry` = 285;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The captain of the Blind Princess will be relieved to hear this precious cargo has been recovered. You have well earned this payment for services rendered.$B$BIt is good to see dependable folk like you, especially in trying times such as these.',
    `RequestItemsText` = 'Do you have the statuette?'
WHERE `entry` = 286;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, $N! I didn''t think you''d have much trouble finding the place, my directions are excellent, you know...$B$BLet me just finish up my report then.$B$B<He brings out some paper and scribbles on it momentarily.>$B$BThere! Well, haha, now this certainly is funny... I don''t suppose, $N, that you would mind doing one last favor for me?',
    `RequestItemsText` = 'You can''t find it? My directions were very clear! We don''t have much time, you''ve got to hurry! Don''t come back until you''ve found the cave.'
WHERE `entry` = 287;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah! That hits the spot, and loosens the tongue. Thanks, mate!',
    `RequestItemsText` = 'Oh, I''m so very thirsty! Won''t you buy a drink for this poor, pathetic fool?'
WHERE `entry` = 288;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My thanks to you, $N. And the gratitude of my cursed brethren goes to you as well.',
    `RequestItemsText` = 'In my dreams, I can sometimes hear the doomed moans of my brethren! Please, good sir, free them from the bonds and quiet their cries.'
WHERE `entry` = 289;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The key is rusted but it fits the lock neatly.',
    `RequestItemsText` = 'This chest is securely locked.'
WHERE `entry` = 290;

UPDATE `quest_template` SET
    `OfferRewardText` = '<He quickly peruses the report.>$B$BAuthority of the KING!? Has Magni taken complete leave of his senses! And that damnable Whitebeard... Taken matters into his own hands, has he? The Senate will not be pleased to hear about this, not one bit.$B$BWhat, are you still here? Go, before I call the guards!',
    `RequestItemsText` = 'Hmm... it would seem that my guards are becoming less discriminatory with petitioners. Well, what do you want? Make it quick.'
WHERE `entry` = 291;

UPDATE `quest_template` SET
    `OfferRewardText` = 'An Eye of Paleth? Amazing! Hmm... there''s something wrong with this one. You found it on one of those shipwrecks? Well that explains it! But... I didn''t know they had such an Eye on the Third Fleet...$B$BIt''s no wonder Fitzsimmons was so spooked. A Cursed Eye of Paleth is no cause for mirth.',
    `RequestItemsText` = 'That drunk Fitzsimmons sent you to me? Well, you can tell him I don''t have any extra ale. He''s going to have to panhandle someone else!'
WHERE `entry` = 292;

UPDATE `quest_template` SET
    `OfferRewardText` = 'An Eye of Paleth. But this one has seen much sorrow...it must have been witness to a terrible, terrible tragedy.$B$BLet me cleanse it, for the Eyes were created to shine bright, and their powers can be quite dangerous if tainted like this one.',
    `RequestItemsText` = 'What is that orb you have? It looks...soiled.'
WHERE `entry` = 293;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Killing is a dirty business, but you did your job well, $N. If I weren''t obligated to stay with the Prospector and Merrin, I''d be down there shedding blood right along side you.',
    `RequestItemsText` = 'Kill 10 Mottled Raptors and 10 Mottled Screechers, $N. My co-workers did not deserve the fate that was brought upon them. It''s time to even the score.'
WHERE `entry` = 294;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You did a bang-up job of clearing out those Raptors, $N!',
    `RequestItemsText` = 'I want to make those Mottled Scytheclaws and Mottled Razormaws pay for what they did. Have you killed 10 of each yet?'
WHERE `entry` = 295;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. Your efforts here will not be forgotten. Many innocent Dwarves died at this site, simply doing their jobs. The vengeance you delivered to those evil creatures should make them think twice before attacking King Magni''s subjects ever again.',
    `RequestItemsText` = 'Is Sarltooth dead? Have you redeemed the memory of the fallen?'
WHERE `entry` = 296;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You got them! Nicely done, $N!$B$BAnd you don''t look too worse for wear, even with those berserk Troggs about. I''m going to keep my eye on you...you show some promise.',
    `RequestItemsText` = 'Do you have those Idols? We must study them and report our findings to Ironforge!'
WHERE `entry` = 297;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Bah! Ironband''s having trouble with the Troggs. I wonder if he wants that blastpowder to aid his digging, or to aid his efforts against the Trogg beasts...$B$BWell, either way it''s powder well spent!$B$BBut what''s strange is, I sent him plenty of blastpowder weeks ago. I wonder where it went...',
    `RequestItemsText` = 'Oh, a progress report from the site? Very good!'
WHERE `entry` = 298;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah the Goaz Stone is complete! Fine work, $N. Fine work indeed. Now I can continue with the delicate translation of this Titan script. I can make out new words already! Hmm. . .it says here, "Old Gods. . .Chained Beneath the Land." This is the beginning of something epic.',
    `RequestItemsText` = 'Have you uncovered the four fragments yet, $N?  Ados, Modr, Golm and Neru...'
WHERE `entry` = 299;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Curse that Ironband! I sent him a load of blastpowder weeks ago, but he''s made no mention of it in this report.$B$BSo...where did the blastpowder go?!?',
    `RequestItemsText` = 'We Stormpikes don''t like being bothered with trivial matters, $C. I hope you brought news worthy of my valuable attention.'
WHERE `entry` = 301;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What? Stormpike wants you to personally see the shipment to Ironband?$B$BI... suppose that''s fine, the only problem is, I''ve already sent Huldar with the porters, Miran and Saean. You just missed them, they left just a short while ago.',
    `RequestItemsText` = ''
WHERE `entry` = 302;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You upheld your orders well, $C. You have proven yourself to be a valiant soldier and loyal servant to King Magni and for that I salute you! With the pressure you applied to the Dark Iron encampment, we now stand a chance of driving them off our lands for good. . .if only the damned reserve would show. . . .',
    `RequestItemsText` = 'Roggo has been unable to contact the reserve forces. We need offensive pressure on that Dark Iron encampment, $C. Now get back out there and serve your duty to King Magni!'
WHERE `entry` = 303;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Balgaras the Foul is finally dead. While his death will not bring back the many innocent dwarves who died needlessly by his hand, it will help to restore peace of mind to those who survived. With Balgaras dead, the remaining Dark Iron scum should be easy enough to manage. Now, we must wipe them out before a new leader is sent to these parts.$B$BYou have done well, $C.',
    `RequestItemsText` = 'Were you able to locate Balgaras the Foul yet, $C? He has been evading us for quite some time.'
WHERE `entry` = 304;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, thank the heavens you are here!',
    `RequestItemsText` = ''
WHERE `entry` = 305;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Such horrible news! At least 3 of them survived. But when will the killing end? I long for the day when King Magni''s subjects can live without fear.',
    `RequestItemsText` = 'Were you able to find Merrin? Did she send word?'
WHERE `entry` = 306;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Did you see a lot of Kobolds in there? I can''t wait for the order to clear them out of the mine. The thought of their grimy hands clawing around our mine makes my stomach rumble!',
    `RequestItemsText` = 'Do you have that Miners'' Gear, $N?'
WHERE `entry` = 307;

UPDATE `quest_template` SET
    `OfferRewardText` = 'For me? You''re a true hero, $N!',
    `RequestItemsText` = 'Hmph! There is all this booze down here. but I have strict orders not to touch it. If only I could get a taste of some of our Thunder Ale...that would sharpen my wits, no lying!'
WHERE `entry` = 308;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, thank the Light the powder is here. But it is troubling news that you bring as well. To think that the Dark Irons have sympathizers able to procure this sort of material for their dastardly plans.$B$BThat''s a matter for someone else to consider, some other time. I must put this powder to good use.',
    `RequestItemsText` = ''
WHERE `entry` = 309;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You quickly place Marleth''s barrel of Barleybrew Scalder among the Thunderbrew barrels.',
    `RequestItemsText` = 'The date on this barrel shows that it''ll soon be tapped.'
WHERE `entry` = 310;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Not bad, $N! Did you have a hard time getting past their guard?',
    `RequestItemsText` = 'Did you make the switch?'
WHERE `entry` = 311;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What a kind soul you are, $N! Thanks to your bravery I won''t find myself starving when the cold season flurries blow in.',
    `RequestItemsText` = 'Were you able to get into my meat locker, $N?'
WHERE `entry` = 312;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah yes, these manes will work great! You show a lot of grit, $C - I wager we''ll see great things from you.',
    `RequestItemsText` = 'Hey, $N. Been to the Grizzled Den yet? Those Wendigos can be fierce.'
WHERE `entry` = 313;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very well done! Veron will be so happy when he hears the good news. To kill Vagash is no easy task. I imagine one day you''ll be fighting alongside King Magni''s men on the Alliance Front.',
    `RequestItemsText` = 'Vagash still terrorizes the herd! Please help us by killing the wretched beast.'
WHERE `entry` = 314;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great! I can''t wait to use these in some of my recipes. There''s one in particular I think it''ll work great in...',
    `RequestItemsText` = 'Do you have that Shimmerweed? I almost have a batch of stout ready to brew, and I want to try throwing the weed in with this mixture.'
WHERE `entry` = 315;

UPDATE `quest_template` SET
    `OfferRewardText` = 'By Magni''s beard, you sure did a lot of hunting!! Thank you, $N.',
    `RequestItemsText` = 'Preparations are going well. How goes your hunting?'
WHERE `entry` = 317;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Bellowfiz needs some of my Evershine? Hm...all right.',
    `RequestItemsText` = ''
WHERE `entry` = 318;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. It''ll be nice to work our crafts without hearing so many growls and snorts outside the village.',
    `RequestItemsText` = 'Have you taken care of those wild animals?'
WHERE `entry` = 319;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, this will do just fine. I think I''ll open a bottle right now and have a taste...',
    `RequestItemsText` = 'Did you get that Evershine?'
WHERE `entry` = 320;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This chest is waterlogged, and its siding broken. Many claw marks mar both the inside and outside of the chest...as if Murlocs have searched through it and stolen its treasure.$B$BBut tucked deep within the chest is a single Lightforge Ingot. Unfortunately, many more will be needed if enough metal to fashion a weapon is to be gained.',
    `RequestItemsText` = ''
WHERE `entry` = 321;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That is quite a tale you have. And lightforge iron! Not for years have I worked with such a metal. It will be an honor to craft with it again. And you must return to me later with the story of your battle against the Necromancer.$B$BBut we get ahead of ourselves. First, your weapon against Morbent Fel...',
    `RequestItemsText` = 'How might I ply my craft for you, $C?'
WHERE `entry` = 322;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your skill in combat, $N, can not be doubted. Your resolve may yet see us through to the end of Morbent Fel!',
    `RequestItemsText` = 'Battle hard, $N. And do not despair, for despair is evil''s greatest weapon.'
WHERE `entry` = 323;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, you found them! Now let''s get this lightforge iron hammered into something useful, eh?',
    `RequestItemsText` = 'Did you find the lightforge iron you need?'
WHERE `entry` = 324;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, this will be proof against the fiend Morbent Fel! Well done!$B$BYou are ready. Morbent Fel will fall.',
    `RequestItemsText` = 'Hello, $N. You haven''t been gone that long, but I see a fire in your eyes I did not see before.'
WHERE `entry` = 325;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Opening the strongbox, it''s clear that this is where Herod keeps his more valuable coins and items.',
    `RequestItemsText` = 'The strongbox is bound in bronze, very sturdy, and very heavy.'
WHERE `entry` = 328;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. This note is the clue we need to root out the traitor!',
    `RequestItemsText` = 'Did you discover who knew Thorsen''s secret? Is there a traitor among us?'
WHERE `entry` = 329;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, yes I can check that for you. Let''s see...last week it was...$B$B...why, it was Private Merle scheduled with Thorsen. They had the same patrol times all of last week.',
    `RequestItemsText` = ''
WHERE `entry` = 330;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It pains me to find out it was Merle who betrayed us. He has always been a brave soldier, and I had thought his heart was true. But it is a great relief to have found him out - with a spy like him among us...we would not last long against Colonel Kurzen.',
    `RequestItemsText` = ''
WHERE `entry` = 331;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, so you''ve seen Renato? Well here you are, sir. A bottle of our special pinot noir. You''ll not find its equal in all of Azeroth!',
    `RequestItemsText` = 'Greetings and welcome, $N. Have you yet tried one of our fine wines?'
WHERE `entry` = 332;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It says here that Harlan''s business is booming.  That''s good news, but I wonder why people have need of all that armor.  I''ve heard nothing of open war...is there something the nobles aren''t telling us?$B$BWell, thank you for bringing the request.  Here''s your payment, and I''ll see to it that Harlan gets his supplies.',
    `RequestItemsText` = 'You bring word from Mr. Bagley?'
WHERE `entry` = 333;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, blast! I thought forgetting my kit would free me from work. Now I guess I''ll have to help the Larsons with their sewing...$B$BOh, well. Fun will come later I guess.',
    `RequestItemsText` = 'Are you here to buy clothes?'
WHERE `entry` = 334;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Most excellent! These are fine samples indeed!',
    `RequestItemsText` = 'Wishock will soon garner enough support to cause us much grief. Were you able to obtain the Tear of Tilloa or Musquash Root yet?'
WHERE `entry` = 335;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, thank you for bringing me this fine looking stout, servant. Here''s a copper for you. Now, out of sight with you and let me enjoy my drink!',
    `RequestItemsText` = 'Can you not see that I am busy? My words must be heard! I am very important to the future of this Kingdom!$B$BOh... what have you there? Why it looks like a refreshing drink...'
WHERE `entry` = 336;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh my! This book hasn''t rested on these shelves since before the rebuilding of Stormwind, years ago. It will have to be restored of course, it''s in bad shape, but I would be honored to place it within our rare books collection.$B$BThank you, $N. Please accept this as payment for returning the book!',
    `RequestItemsText` = 'Ooh! What''s that old book you have there? Can I see it??'
WHERE `entry` = 337;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve certainly saved me a heap of trouble, $N! I can''t thank you enough. It shouldn''t be long now until we see Master Nesingwary''s book in libraries throughout the world!',
    `RequestItemsText` = 'Have you assembled the chapters yet, $N?'
WHERE `entry` = 338;

UPDATE `quest_template` SET
    `OfferRewardText` = 'At last! Chapter I is complete!',
    `RequestItemsText` = 'I don''t suppose you were able to track down pages 1, 4, 6 and 8?  Those four are all we need to piece Chapter I back together.'
WHERE `entry` = 339;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Chapter II is finally complete! Well done!',
    `RequestItemsText` = 'We still need pages 10, 11, 14 and 16 to complete Chapter II, $N.'
WHERE `entry` = 340;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Phew! Good work, $N. Chapter III is now back together in one piece!',
    `RequestItemsText` = 'Any luck with pages 18, 20, 21 or 24?  Those are the only ones we need to piece together Chapter III.'
WHERE `entry` = 341;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Superb! We now have Chapter IV ready to go!',
    `RequestItemsText` = 'We just need three pages to finish off Chapter IV, $N.  Do you have pages 25, 26 or 27 yet?'
WHERE `entry` = 342;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Metallurgy? Ah yes, we have many books on the subject, and are happy to aid Brother Kristoff with his speech! Now...which particular book was it the good brother needed?',
    `RequestItemsText` = ''
WHERE `entry` = 343;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Mr. Sheaf is wondering where his book is? Well this is a tad embarrassing. I have the book, but I''m still making my copy and I''m not quite ready to give the original up!',
    `RequestItemsText` = ''
WHERE `entry` = 344;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You need what?? Maybe you haven''t noticed, but we''re busy fortifying Lakeshire''s defenses and repairing damage from recent orc attacks. If you need Rethban Iron Ore, you''ll have to get it yourself!',
    `RequestItemsText` = ''
WHERE `entry` = 345;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That''s the one! Thank you, $N. May the Light shine brightly upon both your body and spirit!',
    `RequestItemsText` = 'Were you able to find the book?'
WHERE `entry` = 346;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, splendid! I can use this ore to make my dye, and then can finish copying The Stresses of Iron.$B$BThank you, $N!',
    `RequestItemsText` = 'Do you have the Rethban Ore?'
WHERE `entry` = 347;

UPDATE `quest_template` SET
    `OfferRewardText` = '...feel strength returning....$B$BWhere might be? Booty Bay? Oh my! I had the strangest dream...$B$B...the weakness has not completely left me....',
    `RequestItemsText` = '....mother?$B$B...so cold...$B$B...heading into the Twisting Nether...h-h-h-hold me mother....'
WHERE `entry` = 348;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Witch Doctor Unbagwa like Gorilla Fangs! For you I talk to spirits. Make Mokk the Savage come.$B$BYou protect Witch Doctor Unbagwa from other Gorilla-beast through or no Mokk for you!',
    `RequestItemsText` = 'Witch Doctor Unbagwa knows what Mokk the Savage like. Yes, yes!$B$BMe speak with spirits and make he come, I do.$B$BBut other Gorilla-beast like spirit talkin'' too. You protect Witch Doctor Unbagwa and I make he come to you.$B$BWitch Doctor Unbagwa want something first. You bring a Gorilla Fang and me start spirit talking!'
WHERE `entry` = 349;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''re kidding? Shaw wants my help again? Of all the nerve...$B$BThe Defias Brotherhood, you say? Well, you''re certainly the bearer of wonderful news, aren''t you? Next you''re going to tell me that Deathwing is still alive and attacking the city.$B$BAll right, tell me everything from the beginning. And don''t leave out something you think might not be important. I need to know it all.',
    `RequestItemsText` = ''
WHERE `entry` = 350;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You place the egg... distress beacon... inside the chicken... homing robot.$B$BHums and whirs are heard from inside the robot as it struggles to stand up.  After the robot comes to life, Oglethorpe''s voice is heard once more, but now from inside the robot:$B$B"OOX-17/TN is working at least, but it needs major repairs!  It is much too heavy for you to carry it... but I think I have an idea.  Are you up for watching over it some more?"',
    `RequestItemsText` = 'You appear to have uncovered the wreckage of... a robotic chicken?  The voice from within the egg crackles to life again:$B$B"Yes, excellent work!  This is indeed my homing robot, though my sensors indicate that it needs a jump start before it can fly back to Booty Bay for repairs.  Go ahead and place the beacon inside the rover.  The beacon will take care of the rest!"'
WHERE `entry` = 351;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Aha! So Grimand finally finished my axe! I can''t wait to try it against some troggs and kobolds!$B$BMany thanks, $N. It was a long distance to travel for this delivery.  Here are some coins for your efforts.',
    `RequestItemsText` = 'You come all the way from Stormwind? I hear it''s getting dicey down there in the human lands, with brigands and orcs running about. A perfect place for a $C to prove his worth!'
WHERE `entry` = 353;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Revenge has a sweet taste, don''t you think?  When you destroyed the Agamands, did you catch any hint of free will within them?  I hope so.  I hope they knew fear before they were smashed into oblivion.$B$BIt is a foolish hope, I know.  But it is a hope I foster nonetheless.',
    `RequestItemsText` = 'Do you have the remains of the Agamands?  Are those cursed beasts finally destroyed?'
WHERE `entry` = 354;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Coleman speaks well of you, $N, telling of your successful forays into the Agamand Mills.$B$BThe Forsaken have need of your talents once again...',
    `RequestItemsText` = ''
WHERE `entry` = 355;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good. Your efforts do much to keep the Scourge at bay. A commendation will be sent to my superior, Executor Zygand.',
    `RequestItemsText` = 'Do you have a report of your patrol?'
WHERE `entry` = 356;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good, $N.  I will study this book and determine the identity of that lich.  You have served your Queen well.$B$B<Bethor opens the book and stares intently at its glowing pages...>$B$BAstonishing!  The book you retrieved belongs to no one other than Gunther Arcanus!$B$BGunther was a skilled Necromancer in life; he and I were friends and comrades-in-arms, before the Plague.  And judging from his book he has grown even more powerful in death.$B$BHis skills would be a great boon to us.',
    `RequestItemsText` = '$N, have you acquired the book?'
WHERE `entry` = 357;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Expertly done, $N.  The Scourge are mistaken if they think they can use those corpses against us, and the fluid you gathered from the Rot Hide slaves will be studied by our Apothecaries.  It may have secrets we can use against them.$B$BAs I said, well done.  But our struggle continues, and the conflict will surely offer you more chances to prove your worth to the Forsaken.',
    `RequestItemsText` = 'Is your task complete?  Have you destroyed those dog-things and drained them of their ichor?'
WHERE `entry` = 358;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Magistrate Sevren wants a report?  Very well: the defenders at The Bulwark are holding the majority of the Scourge at bay, but some do slip through on occasion.$B$BWe have seen sporadic Scourge activity east of this station, with a concentration around the Balnir Farmstead.',
    `RequestItemsText` = ''
WHERE `entry` = 359;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is troubling to hear of the Scourge slipping past the Bulwark.  The Lich King and his minions are ceaseless in their assaults.$B$BBut we will not give in.  He will not take us again!',
    `RequestItemsText` = ''
WHERE `entry` = 360;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh...my poor Thurman! I begged him to leave Agamand Mills with me and my father, but his family loyalty was too strong! And I knew it! I just knew it that Brand meant him harm!! Oh, curse this Plague, and the Scourge!$B$B<Yvette''s face then smoothes and grows cold.>$B$BBut regrets are for the weak. As a Forsaken, I have new goals and love is not one of them. I would thank you for delivering this letter, for I had wondered what happened to my past love.$B$BBut that life is over. Forever.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 361;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you.  Devlin''s bones will rest nicely on my mantle.$B$BIf my cold heart can find warmth, it is in knowing that the Agamands are destroyed.  They failed me and my family when the Plague came - now I swear I will smash their remains under my heel!',
    `RequestItemsText` = 'Did you find Devlin?'
WHERE `entry` = 362;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Another of the walking dead, hm? Must have been quite a shock, waking up in the crypt with only the cold and Mordo to greet you...$B$BI see the confusion on your face. Let me try to explain our... situation... to you.$B$BWe have been freed from the control of the Lich King by our new leader, Lady Sylvanas. The Dark Lady guides us in our war against the hated Scourge and the holdouts of humanity who dog our every step.',
    `RequestItemsText` = ''
WHERE `entry` = 363;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is unfortunate that the Scourge cannot be brought into the fold, their large numbers would be useful in the battles ahead.$B$BBut they will not join us, so we have no choice but to destroy them.',
    `RequestItemsText` = 'You will not go far in this new life if you are unable to kill even the weakest of zombies, $N. Do not return until you have success to report.'
WHERE `entry` = 364;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have performed your bidding well, young $C.  You are proving yourself to be quite an asset to The Dark Lady''s army.',
    `RequestItemsText` = 'Deathguard Simmer sent word that you were going to provide me with some much needed reagents.  Were you able to gather 10 pumpkins yet, $N?'
WHERE `entry` = 365;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My book?!?  So you were the thief who stole it!$B$BBut...what is this new enchantment upon it...Bethor?  He is in  Lordaeron?$B$BIf he still exists, then perhaps he too escaped from the Lich King''s grasp...',
    `RequestItemsText` = 'Your masters are fools to send you here, for I will never again be a Scourge slave!'
WHERE `entry` = 366;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, $N and I thank you for your efforts.',
    `RequestItemsText` = 'Have you collected 5 vials of darkhound blood yet, $N? Time is fleeting!'
WHERE `entry` = 367;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The scales are perfect, $N. Exactly what I needed for this concoction.',
    `RequestItemsText` = '$N, were you able to obtain 5 Vile Fin Scales from the Murlocs?'
WHERE `entry` = 368;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, this venom will do perfectly, $N. Everything else has been added to my concoction and boiled down. Finally, I am ready to try this new deadly agent!',
    `RequestItemsText` = 'Do you have some venom from a Vicious Night Web Spider yet, $N?  It''s the final component I need in order to test my experiment.'
WHERE `entry` = 369;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Captain Perrine''s death will undoubtedly please The Dark Lady. You have performed your duty well, $C.',
    `RequestItemsText` = 'Young $C, you shouldn''t be wasting your time here in Brill when your people need you fighting for their cause. Now, take up arms and travel to the southwest, to the ruined tower, and slay Captain Perrine along with 3 Scarlet Zealots and 3 Scarlet Missionaries. We shall herd the Scarlet Crusade like cattle to their demise.'
WHERE `entry` = 370;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Captain Vachon''s death will slow down the Scarlet Crusade''s advancement in Tirisfal quite a bit. But other threats loom.',
    `RequestItemsText` = 'I see you have returned but your task is not complete. Perhaps you are at ease with the mere humans interfering with The Dark Lady''s plan? Or perhaps you can heed the call of duty and slay Captain Vachon and his band of Scarlet Friars!'
WHERE `entry` = 371;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done extremely well, $C.  With ruthless fighters like you conquering in the name of The Forsaken our race is one step closer to defeating Arthas once and for all.  I have a good feeling about you, comrade.',
    `RequestItemsText` = 'You have not yet performed your duty, $C.  We cannot expect to carry out The Dark Lady''s plan with the Scarlet Crusade pestering our soldiers.  Bring about their deaths and perform your duty to Sylvanas!'
WHERE `entry` = 372;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Edwin VanCleef, you say? I would as much expect a letter from my dead grandmother... So you''ve killed him then? Pardon me in saying, but I''m somewhat surprised. He was a peerless fighter in his younger years. Let''s see what he finds the need to write to me about after so many years.$B$B<Baros peruses the letter.>$B$BEdwin... I see the years haven''t changed you a bit, an idealist as ever, and a romantic. He doesn''t care who he hurts, $N. Revenge has consumed him. But then, I''m not sure I can blame him.',
    `RequestItemsText` = 'Yes? Is there something I can help you with?'
WHERE `entry` = 373;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Varimathras would be proud. You serve your leaders well, $C.',
    `RequestItemsText` = 'Have you collected 10 Scarlet Insignia Rings yet, $C?'
WHERE `entry` = 374;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I appreciate your efforts, $N. May Slyvanas recognize your bravery one day. . . .',
    `RequestItemsText` = 'Do you have five Duskbat Pelts and some Coarse Thread yet, $N?'
WHERE `entry` = 375;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. This armor should help you out.$B$BHopefully, it should do you more good than the last one to wear it...',
    `RequestItemsText` = 'Do try your best to keep yourself unharmed until I get you some armor.'
WHERE `entry` = 376;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So Dextren Ward finally paid for his crimes against humanity? Good riddance to the scum I say. And cheers to you, my friend! Not only have you given the families of the dead the peace of mind they deserve, you sent a poignant message to those corrupt bureaucrats in the House of Nobles. Stormwind must rise to the needs of the people of Duskwood or we will break free from their tyranny.',
    `RequestItemsText` = 'So long as a molester of the dead like Dextren Ward is permitted to live, justice stands betrayed. Return to me once Lord Ebonlocke''s sentence of death is carried out on that defiler, Ward. We shall give the families of the dead the closure they deserve and better yet, we will send a clear message to the House of Nobles in Stormwind.'
WHERE `entry` = 377;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So Kam Deepfury finally got to feel what it is like to be on the receiving end of Death? Good. Serves the cowardly Dark Iron scum right. You have done well, $C. The victims of the Thandol Span attack were but mere victims in a world torn with war and unrest. Their families will have the peace of knowing Deepfury got the punishment he deserved. Longbraid''s brother''s death has been avenged.',
    `RequestItemsText` = 'I won''t let foolish Human bureaucracy interfere with Dwarven matters, $N. Kam Deepfury is a proven conspirator in the Thandol Span attack. King Magni''s good people lost their lives because of Deepfury''s deceit. The Humans might be content to let Deepfury rot in The Stockade but I will not sleep soundly at night until Deepfury is slain.'
WHERE `entry` = 378;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent, the power source is yours. Now, it isn''t completely designed for use in a science kit like that, so you''ll only have a limited amount of time before all the data you collect will go kablooey!$B$BWhen you collect everything you need for whatever it is you are doing, bring it to me and I''ll shut it down properly. You''ll have at most two hours to get what you need to get done, done.$B$BIf you don''t get it done in time, I can always sell you another power source to try again. You heard me - sell!',
    `RequestItemsText` = 'Well, did the nomads ''volunteer'' up those water pouches for you?'
WHERE `entry` = 379;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmm, well, it''s a start. It''ll take a few weeks or months to fully clean out the infestation. After that, we''ll have to get down there with some torches to burn away the webbing.$B$BYou''ve done your duty well, $N, I''m sure I can find something else for you to do.',
    `RequestItemsText` = 'Be wary of the spiders'' venom, $N. If you feel a sharp burning, you may want to have it looked at.'
WHERE `entry` = 380;

UPDATE `quest_template` SET
    `OfferRewardText` = 'If only they listened to reason, eh, $N? Perhaps we could sit them down for reasonable discourse... ha!$B$BLight-blinded fools.',
    `RequestItemsText` = 'Those fools... They happily send themselves to their own graves.'
WHERE `entry` = 381;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmm... Let''s see what you''ve got...$B$B<He begins to rifle through the documents you recovered.>$B$BSome news of their exploits against us... Worthless. Scouting reports... New orders, "Continue to build up a camp near the ruined city..." Nothing we didn''t know already... Ah, what''s this? A map of the dispositions of some of their field commanders and agents! We can use this.',
    `RequestItemsText` = 'How goes your mission, $N?'
WHERE `entry` = 382;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, this is very good. You''ve done well in obtaining this information, $N. Hmm... names of the officers in the Tirisfal Glades...$B$BImagine the blow we could deal to the morale of those bloody zealots if we were to kill their leaders in one swift strike.',
    `RequestItemsText` = 'Yes, what do you want?'
WHERE `entry` = 383;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Malt is brewed, the Boars are dead$B$BAnd before all is done and anything said$B$BWe will have to fight for first dibs$B$BOn these savory Beer Basted Boar Ribs!',
    `RequestItemsText` = 'I''m going to need six crag boar ribs and a mug of Rhapsody Malt, $N.'
WHERE `entry` = 384;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well now, these are excellent specimens you collected, $N. Good money for high quality materials, that''s for sure.',
    `RequestItemsText` = 'Did I tell you about the time I almost lost my hand to one of the crocs? Nasty bugger it was, teeth like knives. But I was lucky... Jammed the brute''s jaw shut with my knife. Still have the knife around here somewhere...'
WHERE `entry` = 385;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Targorr the Dread has finally met his fate. I for one am glad to hear the beast now knows what it is like to be on the receiving end of Death''s ruthless grip. You have done well, $N. Sometimes the truest justice can only be found outside the courtroom and beyond the clouded vision of politics.',
    `RequestItemsText` = 'Have you been to Stormwind yet, to The Stockade? I fear whatever trickery that has kept Targorr the Dread alive for this long will eventually bring about his freedom. He was sentenced to die, $N, not act as some political pawn on a noble''s whim.'
WHERE `entry` = 386;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your efforts in The Stockade were valiant, $N. It''s obvious this problem is bigger than the both of us. But you have performed well and for that I am thankful.',
    `RequestItemsText` = 'The Stockade is still overrun! These Defias Rats must be shown that their actions will not be tolerated. Now get back down there and show some force!'
WHERE `entry` = 387;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So these bandanas -- filthy tokens of corruption -- are what my Mac had to die for?  Such a waste.  Such a tragic sacrifice.$B$BBut alas, I cannot return to the past.  Just know, $N, that you have brought my family justice through your deeds.',
    `RequestItemsText` = 'I see you are back, $C. Have you collected 10 Red Wool Bandanas from those Defias Scum in The Stockade yet?'
WHERE `entry` = 388;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What in the Light do you want? Can''t you see we have a crisis here?$B$BBazil Thredd?! Why would you want to speak with that bastard? How am I supposed to know you''re not one of his cronies, come down to help with his bloody riot? If all the blasted cells weren''t open, I might throw you in one for a while!',
    `RequestItemsText` = ''
WHERE `entry` = 389;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Without Thredd to lead them, hopefully the riots will be more controllable. We shall see.$B$BI must say, after a half hour, I hardly expected you to come out, but it seems I misjudged you.$B$BI''d guess, then, that you didn''t get much useful information out of him? But I know a thing or two that might be of interest to you about Thredd''s activities.',
    `RequestItemsText` = 'Either you bring me Thredd''s head, or I''ll take yours, understand, $N?'
WHERE `entry` = 391;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmm. Maelik? No, the name doesn''t sound familiar and neither does this description. But it could be anybody! A former Stonemason, one of the Defias Brotherhood... Though if he is as well connected as Thelwater suggests, perhaps someone else might recognize him. Let me think.',
    `RequestItemsText` = 'Yes, $N? What have you found?'
WHERE `entry` = 392;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What? What''s this? Yes, I think I do know who this man is, but his name is not Maelik. Assassins wear many names and many masks, discarding them as they lose their usefulness. Another alias known to be used by this man is Marzon; though even that is surely not his true name.$B$BRegardless, he is an assassin and I know a good deal about him.$B$BMarzon is currently under the employ of Lord Gregor Lescovar, a lord of shady reputation, even given the corruption of the nobility of Stormwind.',
    `RequestItemsText` = 'Greetings. Of what service can I be to you, $C?'
WHERE `entry` = 393;

UPDATE `quest_template` SET
    `OfferRewardText` = 'He is dead, then? Your justice was swift, $N. I pray to the Light that I never become your quarry!$B$B<He laughs and claps you on the shoulder.>$B$BI mean no criticism, $N. How could I, being the master of all assassins? But in truth, you have done the people of Stormwind a great service, and for that, I thank you.',
    `RequestItemsText` = ''
WHERE `entry` = 394;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It''s good to see you, $N. I have heard that Lord Gregor Lescovar was found dead not long ago.$B$BIt would seem that you were successful in your mission. You have my gratitude that you have saved me, and many others, from VanCleef''s revenge.',
    `RequestItemsText` = ''
WHERE `entry` = 395;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You are to be commended for the service you have done for Stormwind, $N. If VanCleef had been successful in his machinations, he would no doubt have done considerable harm to the kingdom - something we must obviously avoid.$B$BTake this, $C, as a token of the King''s appreciation. I am only sorry he cannot present it to you himself, but he is away on a diplomatic mission and shall not return for some time.',
    `RequestItemsText` = '$N, yes? I was informed by Baros Alexston that you would be coming. I must say, I am most interested in what you have to say.'
WHERE `entry` = 396;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Master says give gift to $N. Zggi wants to keep nice gift but Zggi knows better than to betray Master.',
    `RequestItemsText` = ''
WHERE `entry` = 397;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Maggot Eye''s dastardly acts have finally been avenged.  Maybe your acts of valor will send a clear message to those who wish to bring harm to our people.  On behalf of the town of Brill I thank you, $N.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 398;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, thank you, $N! It''s of no practical use to me, but the sentimental value... Needless to say, thank you for bringing this to me... at some cost to your own well-being, not to mention the time it took to go all the way down to Westfall. You have my gratitude, and have this as a token of my thanks.',
    `RequestItemsText` = '$N! Did you have any luck?'
WHERE `entry` = 399;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have my tools? Well done, lad, well done! I just broke my last fang-ratchet an hour ago and I need one of those to finish repairs on Pilot Stonegear''s siege engine. You did a good thing by lugging those tools here, $N.$B$BHere, take these coins for your help.',
    `RequestItemsText` = 'Hm?  You look a little young to be a siege engine pilot.  But no matter...do you need something fixed?$B$BWell take a number and get comfortable.  I''m working on a couple engines right now and won''t have time for another job for at least a few days.$B$BOr, were you here for something else...?'
WHERE `entry` = 400;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There we are.  It''s translated...$B$B<The air grows heavy, as if a thick, black curtain is drawn over the land...>',
    `RequestItemsText` = ''
WHERE `entry` = 401;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This barrel of ale is guarded by Jarven Thunderbrew.  As long as he''s in the basement, no barrels may be disturbed.',
    `RequestItemsText` = ''
WHERE `entry` = 403;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done.  I regret not being there to see you smash those undead into rotting pulp!',
    `RequestItemsText` = 'Have you completed the task with which I have charged you?  Do you have those putrid claws?'
WHERE `entry` = 404;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, you are the agent sent by Magistrate Sevren.  Then yes, your business with me is crucial.$B$BI trust Sevren has mustered someone suitable for my task...but we shall see.',
    `RequestItemsText` = 'Greetings.  Either you do not know who I am, or your business with me is urgent.$B$BBecause if neither of these were true, then you would not be foolish enough to disturb me...'
WHERE `entry` = 405;

UPDATE `quest_template` SET
    `OfferRewardText` = 'By the Light!  Finally some food!  Sweet, sweet pumpkin. . . .',
    `RequestItemsText` = 'Stay away, foul and unholy creature!  May the Light protect me!  The Scarlet Crusade shall rid Azeroth of your. . .$B$B. . .oh wait.  Is that food for me?  I am so hungry. . .'
WHERE `entry` = 407;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your actions struck a telling blow against the Scourge.  And your victory will not go unnoticed - not by the Forsaken, nor by our enemies.$B$BContinue the struggle as we all do, $N, and one day we will drive the Lich King himself from Azeroth!',
    `RequestItemsText` = 'Time is not a luxury we have, $N.  With each passing hour, the Scourge''s hold on Tirisfal Glades grows more firm.'
WHERE `entry` = 408;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have defeated Lillith Nefara, proving you are an enemy of the Scourge.  Incredible.$B$BI had believed I was the only Undead with free will, but you have shown me there are others who have broken the Lich King''s domination.',
    `RequestItemsText` = 'I await proof of your allegiance, $C.'
WHERE `entry` = 409;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You place the Candle of Beckoning upon the table and light it...',
    `RequestItemsText` = 'This is an old, beaten, bloody table.'
WHERE `entry` = 410;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You convinced him to join us!  You have done a great deed for the Forsaken, $N.  The Dark Lady will be informed.',
    `RequestItemsText` = 'Have you returned Gunther''s book?  Has he responded?'
WHERE `entry` = 411;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These Gyromechanic Gears and Restabilization Cogs are in perfect accordance with Ozzie''s schematics for the Recombobulation Device. Once I add some hyrdolubricant to the inner combustion pistons, adjust the crank-o-ratchet and increase of the viscosity of the electrogum gel, the gnomish race will be as good as new.',
    `RequestItemsText` = 'The Recombobulator will be up and running as soon as we have sufficient Restabilization Cogs and Gyromechanic Gears.'
WHERE `entry` = 412;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Mountaineer Barleybrew tastes the Shimmer Stout...>$B$BOh. Whoa! This stuff really puts a shine in your eyes. I feel like I can see in the dark!',
    `RequestItemsText` = 'Hello, $C! And what business takes you all the way out here?$B$BSomething exciting, I hope. I haven''t been in a good fight in days, and this barrel of ale is almost dry...'
WHERE `entry` = 413;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now, let me have a taste...$B$BMagni''s Beard! This stuff gets your head turning! And it lightens the limbs, too.$B$BI feel like I can fly!',
    `RequestItemsText` = 'Greetings, $C, and welcome to Thelsamar!'
WHERE `entry` = 414;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N! You know that Shimmerweed you brought me? Well I used it in a few recipes I''ve been working on, and one of them turned out great!$B$BHere, try it out and tell me what you think...',
    `RequestItemsText` = ''
WHERE `entry` = 415;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ugh! When I asked for those ears I didn''t realize they''d smell so bad!$B$BHere''s your reward, $N. Well done.',
    `RequestItemsText` = 'Hail, $N. How goes the rat catching?'
WHERE `entry` = 416;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is grim news, for Hildelve was a good friend. And I wish I could have been there with you when you found the beast, Mangeclaw!$B$BThank you, $N. Your deed will be remembered by the pilots of the Ironforge Siege Brigade.',
    `RequestItemsText` = 'Hello, $N. Do you have word of my friend Hildelve?'
WHERE `entry` = 417;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Trust me, it seems a lot harder than it looks, but...$B$BOh, I''ve never known someone to take much interest in the making of sausages, but I''ll give you the recipe just in case. Here you go, mind you eat them fresh!',
    `RequestItemsText` = 'I''m all ready to start cooking, do you have the ingredients for me?'
WHERE `entry` = 418;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here is the corpse of a dwarf -- mauled, frozen, and picked clean by mountain scavengers. Clutched in its hand is a book containing the roughly scribbled notes of Mori Hildelve. And around its frame, still in superior condition, is a Brigadier''s Vest.$B$BThis grisly scene must have been where the Siege Engine pilot met his end.',
    `RequestItemsText` = ''
WHERE `entry` = 419;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What''s this? Ah, my brother''s report. Hmm...$B$BI told him to be sparing with the use of the King''s name, but he didn''t listen. No harm, I suppose, though it''s sure to ruffle some feathers in the Senate. Not that those weren''t some feathers that needed ruffling! Hah!$B$BNonetheless, I guess that means that I should send my report on to Ironforge as well, but I must admit I''m a bit behind. Bloody cold.$B$BI should have some work for you later, if you''re interested.',
    `RequestItemsText` = 'How are you? Like to share a drink with me, perhaps? Not much else to do in the cold.'
WHERE `entry` = 420;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have served me well, $C.  It is obvious to me that you will be a worthy aide to me as I prepare to rid Silverpine Forest of Arugal''s curse.',
    `RequestItemsText` = 'If you wish to prove yourself to me, you must kill 5 Moonrage Whitescalps.  Accomplish that task, and I will see to it your skill is put to more worthy assignments.'
WHERE `entry` = 421;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is precisely the spell I was in search of, $C.  If your dedication to The Dark Lady''s cause remains infallible you will find you have quite a future amongst The Forsaken.',
    `RequestItemsText` = 'Before I know what we are dealing with here, $C, I need to study the spell known as Remedy of Arugal.  Bring it to me now or I shall be forced to find myself a worthy servant.'
WHERE `entry` = 422;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I hope I can acquire enough energy from such a limited sample. Perhaps I should have had you get more shackles.$B$BNonetheless, you showed great skill in collecting these, $C.',
    `RequestItemsText` = 'I will need 6 Glutton Shackles and 3 Darksoul Shackles before I can assess the situation and devise a final solution for Arugal. Now heed your bidding and slay Moonrage Gluttons and Moonrage Darksouls until you have what I need.'
WHERE `entry` = 423;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Most excellent. The mine will provide superb resources for our forces as we spread throughout Silverpine and into Azeroth.',
    `RequestItemsText` = 'Has Grimson the Pale been slain? Varimathras will not be pleased if we ignore his bidding.'
WHERE `entry` = 424;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, thank you.  You have my gratitude, $N.$B$BAnd I will include you in the report I make to my superiors.',
    `RequestItemsText` = 'Have you killed Ivar the Foul?  If you won''t do it for me and my brother, then do it for the Forsaken.'
WHERE `entry` = 425;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your efforts in the war are felt among us, $N.  I will not thank you for doing what is necessary, but the Deathguards of Tirisfal will remember your name.',
    `RequestItemsText` = 'Our battles with the Scourge wage on, $N.  Do your part and throw those cursed, mindless undead back into the Plaguelands!'
WHERE `entry` = 426;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Most excellent, $C.  Your skill in the art of combat is undeniable.',
    `RequestItemsText` = 'If you wish to prove your worth to The Dark Lady, slay 10 Scarlet Warriors, $C.'
WHERE `entry` = 427;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found us! And not a moment too soon...',
    `RequestItemsText` = ''
WHERE `entry` = 428;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Renferrel takes the hearts.>$B$BIt is troubling to hear our Deathstalkers have failed their mission.$B$BLet us hope that these failures are rare.$B$BI''ll give you the potion in a moment, but here is its recipe - if those Deathstalkers find themselves in need of future aid, then perhaps you can give it yourself.',
    `RequestItemsText` = 'My time is short, $C, for the Dark Lady has charged me with a grave task.'
WHERE `entry` = 429;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Quinn takes the potion and drinks it.>$B$BYes, I can feel it working.  I will soon be able to travel.$B$BYou have done me a great favor, $N.',
    `RequestItemsText` = 'My sister told me you were here to aid us.  Is that true?'
WHERE `entry` = 430;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You grab one of the candles and place it in your pack.',
    `RequestItemsText` = ''
WHERE `entry` = 431;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, that makes me feel a little better...$B$BBut I won''t be happy until they''re all dead! All of them!',
    `RequestItemsText` = 'It makes me so mad! Grrr...'
WHERE `entry` = 432;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is a start. Hopefully we can take advantage of it, and move some Mountaineers in to secure the area. Then we can begin to restore our infrastructure and get the miners back to work.$B$BThank you for your assistance, $N.',
    `RequestItemsText` = 'If we can remove the troggs from Gol''Bolar quarry, it will be the first step of many that we will have to undertake to rid ourselves of this menace.'
WHERE `entry` = 433;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So it is done? Good. Thank you greatly for your discretion, $N. You''ve proven worthy on more than one count. I''ll be sure to keep my eyes on you and your progress within the Alliance.$B$BBe sure to keep your nose clean.',
    `RequestItemsText` = 'Yes, $N? Are things going well with Tyrion? He apprised me of the situation and I''ve helped him trick Marzon into going to the castle.$B$BMarzon has been a thorn in the side of many people in Stormwind; many of which are close friends of mine. No one messes with my friends... not if they know what''s healthy for them.$B$BIt''s just a shame I''m indirectly doing a favor for Shaw and SI:7 in the meantime. Oh well, not every plan is perfect.'
WHERE `entry` = 434;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you for the aid, $N.  I had feared Erland was overcome by the dangers of Silverpine.  With your help, I see that he has not.',
    `RequestItemsText` = ''
WHERE `entry` = 435;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Jern wants to know what the slowdown is, eh?$B$BIronband is putting together his latest progress report with details, but I can tell you this:$B$BIt''s the Troggs!!',
    `RequestItemsText` = ''
WHERE `entry` = 436;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I heard of your successful raid against the rot hides, $N, and this essence is proof of Nightlash''s death.$B$BThe Scourge have lost ground this day.  Your value to the Forsaken grows.',
    `RequestItemsText` = 'Have you defeated Nightlash, $N?  Our success against the rot hides depends on her destruction!'
WHERE `entry` = 437;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Heaped within this boat is a pile of wrapped corpses. And looking east across Lordamere Lake, an opposing dock on Fenris Isle can be seen.$B$BThe fate of the corpses must lie on Fenris Isle.',
    `RequestItemsText` = ''
WHERE `entry` = 438;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You say that this ring was worn by a woman, recently killed?$B$BThe only nearby source of such a body would be the mass graves in Tirisfal. The Rot Hide Gnolls must be taking those corpses to Fenris Isle!',
    `RequestItemsText` = '$N. You return, so I assume your investigations bore fruit?'
WHERE `entry` = 439;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A Deliah did live in Brill not long ago. She was buried in the mass grave but if what you say is true, then the Rot Hide Gnolls must have stolen her body and taken it to Silverpine.$B$BThe Rot Hides, like all the Scourge, must be destroyed. I trust you are taking steps to make that happen.',
    `RequestItemsText` = 'Hello, $N. What brings you back to Brill?'
WHERE `entry` = 440;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, this ring was my wife''s. Her fate was the fate of all who fail to endure these harsh times. I feel nothing for her death, nor for the story you tell of her body''s abduction.$B$BSuch feelings have long since grown cold within me. But desire does still burn in my dead heart, $N.$B$BDesire for revenge.',
    `RequestItemsText` = 'Do I know you?'
WHERE `entry` = 441;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The death of Thule Ravenclaw was no small event, $N. Renferrel tells me that the energies released when you destroyed Thule were felt even as far as the Sepulcher.$B$BYour actions ring through the ranks of the Forsaken. Your value to us grows.',
    `RequestItemsText` = 'The Scourge cannot be allowed to remain in Silverpine, $N. Come back to me when you have proof of Thule''s death.'
WHERE `entry` = 442;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good.  This ichor will help us understand the nature of the rot hides, and may show us their weakness...$B$B...if they have one.',
    `RequestItemsText` = 'Do you have the rot hide ichor, $N?'
WHERE `entry` = 443;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This substance is laced with powerful spells, some of which I have not seen for a long, long time...$B$BOne moment -- I must invoke a spell of divination...',
    `RequestItemsText` = 'My studies require great concentration.  So I hope your visit is not a frivolous one.'
WHERE `entry` = 444;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, how good of Apothecary Johaan to send his research.  With so many new developments here in Silverpine, I nearly forgot about the findings coming out of Lordaeron and Tirisfal Glades.  Which reminds me, I need to get those samples off to the Necropolis soon.$B$BBut you must excuse my rambling.  Extend your stay in Silverpine, $N.  We could use an able bodied $C like you around here.',
    `RequestItemsText` = 'What business do you have with me, $C?'
WHERE `entry` = 445;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This scroll is laced with powerful magic.  I''ve never used such forces in a potion ... it will be a powerful mixture, and should serve you well should you attack Thule in his stronghold on Fenris Isle.',
    `RequestItemsText` = 'Greetings, $N.  What did Bethor have to say?'
WHERE `entry` = 446;

UPDATE `quest_template` SET
    `OfferRewardText` = 'How good of Apothecary Renferrel to send you to me, $N.  These samples will indeed prove useful to the cause.  I will begin studying their toxic and contaminable properties at once.',
    `RequestItemsText` = 'Hail, $C.  What business do you have with the Royal Apothecary Society?'
WHERE `entry` = 447;

UPDATE `quest_template` SET
    `OfferRewardText` = 'If what Bethor says is true then Thule Ravenclaw is a force that must be dealt with, and dealt with soon.$B$BTo aid in this task, you may take something from our arsenal here...',
    `RequestItemsText` = ''
WHERE `entry` = 448;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I hadn''t accounted for the level of Scourge presence we''ve seen in Silverpine Forest, nor for the troubles our Deathstalkers have had in their scouting efforts.$B$BYour aid to our Deathstalkers was invaluable, $N.  And you will be commended.',
    `RequestItemsText` = 'Did you discover the fate of the Deathstalkers?'
WHERE `entry` = 449;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Apothecary Berard''s journal! Why you are quite brave, $N. Now let''s see what Berard was up to before he went mad. . .',
    `RequestItemsText` = 'I see you are back, $N.'
WHERE `entry` = 450;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Such a blow to the Royal Apothecary Society to lose Berard. But through your hard work and Apothecary Renferrel''s diligent research Berard''s studies will still be useful to The Dark Lady''s plight.$B$BWe are on the cusp of something great here, $N. If you were not so skilled in the ways of combat I would try to recruit you for membership in the Society.',
    `RequestItemsText` = 'What brings you back to the Undercity, $N?'
WHERE `entry` = 451;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You fought like a true disciple of the Dark Lady, $N. With the council dead, perhaps we can gain control of this town once and for all and drive Arugal from Shadowfang Keep. I salute you!',
    `RequestItemsText` = ''
WHERE `entry` = 452;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Jitters sighs...>$B$BYes, I''m the author of that book. You finally found me, eh?$B$BWell if you read that journal...then you only know the half of it!',
    `RequestItemsText` = 'Who are you?? Leave me be!'
WHERE `entry` = 453;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hello, $C.$B$BYou''ll be escorting me to the excavation site? That''s good to hear... After Saean and his cronies, who knows what else the Dark Irons might have up their sleeves?$B$BAnyways, let me just make some final checks. Talk to me again when you''re ready to go.',
    `RequestItemsText` = ''
WHERE `entry` = 454;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your report is full of bad news!$B$BI see the Dragonmaws are making a strong move into Algaz. Normally the Dragonmaws just hide up in the hills. What made them surge into Algaz is still a mystery...$B$BThank you, $N. And we''ll probably want your help dealing with these orcs.',
    `RequestItemsText` = 'You''re coming from Loch Modan? How is the orc situation at Algaz Gate?'
WHERE `entry` = 455;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You performed your duties well, $N.',
    `RequestItemsText` = 'There is still work to be done, $N. Return to me once you have thinned the nightsaber and thistle boar populations.'
WHERE `entry` = 456;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have proven your dedication to nature well, $N. A young $C like yourself has a promising future.',
    `RequestItemsText` = 'Your task is not yet complete, $N. Return to me once 7 mangy nightsabers and 7 thistle boars have been killed.'
WHERE `entry` = 457;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I see you found me, young $R. Melithar is a wise druid to have sent you.',
    `RequestItemsText` = ''
WHERE `entry` = 458;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your service to the creatures of Shadowglen is worthy of reward, $N.$B$BYou confirmed my fears, however. If the grells have become tainted by the Fel Moss, one can only imagine what has become of the Gnarlpine tribe of furbolgs who once lived here.$B$BShould you find yourself in Dolanaar, able $C, seek out the knowledgeable druid, Athridas Bearmantle. He shares our concern for the well being of the forest.',
    `RequestItemsText` = 'Satisfy my suspicions, $N. Bring to me 8 Fel Moss.'
WHERE `entry` = 459;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N.  I had feared the Gnolls destroyed my body.  It is good to know they did not.',
    `RequestItemsText` = 'This grave was hastily dug.'
WHERE `entry` = 460;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There we are, it''s open.  Leave me here.  I spent the best days of my life in this keep, and the thought of resting within its walls gives me comfort.$B$BBe sure to close the alcove tight - I don''t want those Rot Hides to find me.$B$BOh, and take this.  You''ve earned it.',
    `RequestItemsText` = 'This is the spot!  Bring me closer...'
WHERE `entry` = 461;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The roots and ferns speak well of you, small one. Although I have many names, I answer to only a few. But you may call me Rethiel.$B$BAnd you must harken...for these lands weep from festered wounds, and I would charge you to heal them.',
    `RequestItemsText` = ''
WHERE `entry` = 463;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well fought, $N. The Dragonmaws are not the same threat they were when they had dragons, but they''re still fierce opponents.$B$BThe Dragonmaws are led by Nek''rosh, son of Nekros, who was the former head of the Dragonmaws years ago. Nekros used powerful magic to tame the Red Dragons, but when that magic failed him...the dragons were not happy.$B$BNekros was killed, and his son has vowed revenge against the dragons who slew his father.',
    `RequestItemsText` = 'Have you attacked the Dragonmaw encampment?'
WHERE `entry` = 464;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You place some of the tinder on the catapult then strike a spark onto it.$B$BFlame erupts and quickly spreads!',
    `RequestItemsText` = 'The first catapult is before you. Will you set it aflame?'
WHERE `entry` = 465;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You got the ore! Well done, $N! I''ll get someone to work with this right away. Let''s hope he doesn''t blow himself up!',
    `RequestItemsText` = 'Where is that ore, $N?!'
WHERE `entry` = 466;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hello $N. You''re here about the task I have, eh? It''s good to see a young $R like yourself whose blood burns at the prospect of adventure!',
    `RequestItemsText` = ''
WHERE `entry` = 467;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hello, $C! You''re here for the scouting mission, are you? Very good!$B$BI hope your gear is in good condition, because this "scouting" mission has changed into something more messy...',
    `RequestItemsText` = ''
WHERE `entry` = 468;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmm, this is from Einar, right? Hasn''t delivered his skins to me in person for almost a week now. No doubt it''s some differences with the wife!$B$BMaybe I''ll have my wife go speak with Sida sometime...',
    `RequestItemsText` = 'Hello there, $C. Could I interest you in a pair of boots? Perhaps some newly cured skins?'
WHERE `entry` = 469;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, thank you, $N! I was afraid that it was lost for good!$B$B<She quickly empties the contents of the ooze-covered bag onto the ground, before scooping them up.>$B$BHm, I don''t have much use for this anymore, but wash it off and I''m sure you could make use of it.',
    `RequestItemsText` = 'Did you find my bag?'
WHERE `entry` = 470;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmm... Don''t suppose you''d be interested in becoming my apprentice, would you?$B$BHah! No, I''m just kidding. You''re much too old, for one thing. Besides - from the looks of you, it would seem that you have other ambitions in life. Nonetheless, these are some fine skins you''ve procured, and I''ll be able to put them to good use.',
    `RequestItemsText` = 'My apprentice is like a son to me. It''s going to be hard for him to live his life with only one leg.$B$BAh, $N, how goes it? Do you have my skins?'
WHERE `entry` = 471;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What brave $C sends word from Menethil? Ah $N, they call you.$B$BYou bring hope to a hopeless situation. ''Tis good news indeed that young Harlo survived. While fleeing he received a grievous wound. We had but little time to send him on his way on the back of the only surviving steed with the regiment.$B$BBut now we face a perilous situation. Dun Modr has fallen and we are but a shadow of the great regiment we once were.',
    `RequestItemsText` = ''
WHERE `entry` = 472;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N. Valstag briefed me on your past success with the Dragonmaw Orcs at Dun Algaz. You''re a $R of worth.$B$BAnd I have a task for you.',
    `RequestItemsText` = ''
WHERE `entry` = 473;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Stoutly done, $N. You have dealt a telling blow to the Dragonmaw orc clan. They may never recover. And the destruction of those catapults has made Menethil Harbor safe.$B$BYou are a $R of merit, and the kingdom of Ironforge rewards those who serve it well.',
    `RequestItemsText` = 'Have you killed Nek''rosh?'
WHERE `entry` = 474;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank the forest spirits you are here! I knew Athridas would sense trouble and send help.',
    `RequestItemsText` = ''
WHERE `entry` = 475;

UPDATE `quest_template` SET
    `OfferRewardText` = 'By the stars! This is quite disturbing indeed!',
    `RequestItemsText` = ''
WHERE `entry` = 476;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Prying open the lid of the crate, you find an assortment of carefully-packed objects. On the top of the crate lies a bundle of maps, yellowing with age, that appear to depict Silverpine Forest and other parts of western Lordaeron.$B$BUnderneath the maps is a mysterious-looking magical pendant.>',
    `RequestItemsText` = ''
WHERE `entry` = 477;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Maps and this... pendant, hm? Interesting.',
    `RequestItemsText` = 'Have you learned anything useful, $N?'
WHERE `entry` = 478;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Dalar has found that the weaving is quite far along, despite the setback.$B$BA wizard of great power is guiding the magic energy. He must be stopped quickly.',
    `RequestItemsText` = 'We must hurry, their plans must not come to fruition, or we may lose our hold on Silverpine Forest.'
WHERE `entry` = 479;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The magic of the wizards dissipates, and the ley energies fade into dormancy. Your efforts have been fruitful, $N, and we have dealt a major blow to our enemies, and to the overbearing wizards of Dalaran.$B$BWe must be vigilant, however, knowing that source of energy lies so close at hand... Plans must be made for the future.',
    `RequestItemsText` = 'Quickly, time runs short, $N!'
WHERE `entry` = 480;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Interesting, more machinations of the Kirin Tor, it would seem. This is a powerful artifact. It was used frequently by powerful wizards of the Kirin Tor to channel magical energies.$B$BThat they are delivering so many to Ambermill indicates that they must be undergoing a project of some magnitude.$B$BI will see if I can pierce their shields and ascertain their intent.',
    `RequestItemsText` = 'Yes, $C? What is it?'
WHERE `entry` = 481;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ill news you bring, $N. If Dalar is correct--and I''ve no reason to believe he isn''t--we must move quickly.$B$BI must confer with him on our plan of attack. But in the meanwhile we will have to delay their progress.',
    `RequestItemsText` = ''
WHERE `entry` = 482;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have succeeded, young $C! Well done. And just in time I might add.',
    `RequestItemsText` = '$N, the kidnapped Druids of the Talon will be forever trapped in the Emerald Dream if we cannot retrieve the Relics of Wakening from the Ban''ethil Barrow Den to the west.$B$BFor every minute we delay their fate comes one step closer to eternal doom.'
WHERE `entry` = 483;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Nice work you''ve done here, $N. The quality of these skins is superb. I''ll have to get them into the curing process as soon as possible. Oh, but before I get to that, there''s some other work I need done that I think you might be able to take care of.',
    `RequestItemsText` = '$N, right? Do you have my skins?'
WHERE `entry` = 484;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You place the egg... distress beacon... inside the chicken... homing robot.$B$BHums and whirs are heard from inside the robot as it struggles to stand up. After the robot comes to life, Oglethorpe''s voice is heard once more, but now from inside the robot:$B$B"OOX-09/HL is working at least, but it needs major repairs! It is much too heavy for you to carry it... but I think I have an idea. Are you up for watching over it some more?"',
    `RequestItemsText` = 'You appear to have uncovered the wreckage of... a robotic chicken? The voice from within the egg crackles to life again:$B$B"Yes, excellent work! This is indeed my homing robot, though my sensors indicate that it needs a jump start before it can fly back to Booty Bay for repairs. Go ahead and place the beacon inside the rover - the beacon will take care of the rest!"'
WHERE `entry` = 485;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N you have proven yourself a most worthy and able $C. A night elf who follows the path of honor as sure as you do is certain to find great glory in this world.$B$BMay the forest spirits protect you wherever your travels may take you.',
    `RequestItemsText` = 'Our brethren cannot be awakened until Ursal the Mauler has been slain, $N.'
WHERE `entry` = 486;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have served the good people of Dolanaar and Darnassus well, brave $C. As a member of the Sentinel force of Teldrassil I salute your efforts.',
    `RequestItemsText` = 'The road is still not safe, $C. Travel forth and slay 6 Gnarlpine Ambushers and return to me.'
WHERE `entry` = 487;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ha ha! Well, done indeed.$B$BWho would have ever guessed that I, Zenn Foulhoof, would have a $R to do my bidding? Certainly not me! But so it goes... this beloved world of ours is full of surprises.$B$BThree cheers for the naive and gullible!',
    `RequestItemsText` = 'Have you been a busy little bee, $N? I''ve been waiting for you to bring me what I need.'
WHERE `entry` = 488;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, what a sweet $R! I knew you would come in handy!',
    `RequestItemsText` = 'What do you have for me, $N? A lovely snack I presume?'
WHERE `entry` = 489;

UPDATE `quest_template` SET
    `OfferRewardText` = '...what is this?  Thule had our Woven Wand?  I thought it was lost when our friendship sundered and he sided with the Lich King!$B$BHe must not have invoked its power, for if he had I would have sensed it.  And it is good that he did not use it...$B$BThis is a marvelous find.  You have my gratitude, $N, and will be rewarded.',
    `RequestItemsText` = '$N.  Have you defeated Thule Ravenclaw?'
WHERE `entry` = 491;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, a drink at last.  I''m sure it''s no Rhapsody Malt but I''ll take anything to whet the old whistle at this point.',
    `RequestItemsText` = 'Why if I had my trusted rifle you''d be as good as dead, $C.  Just wait until the Steam Tank Brigade arrives to rescue me!'
WHERE `entry` = 492;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, most excellent.  Apothecary Renferrel has my utmost respect.  I am anxious to study his work.',
    `RequestItemsText` = 'You have something for me?'
WHERE `entry` = 493;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The raven''s cry from the west doth beckon?$B$BSuperb news!  Hillsbrad is ripe for attack.  We can carry out our plan of destruction now.  Varimathras will be pleased.',
    `RequestItemsText` = ''
WHERE `entry` = 494;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You were sent by Shalindra? Very well then, you''ll find I don''t waste much time with idle chatter.$B$BMug''Thol is an irritant, and we will deal with him quickly, thoroughly, and without incident.',
    `RequestItemsText` = ''
WHERE `entry` = 495;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These specimens are perfect. Well, $N, you have managed to bring me the slightest hint of joy on yet another miserable day. Your efforts are appreciated.',
    `RequestItemsText` = 'I see you are back. I hope you were able to gather the agents I need. Another deathless day will put me in such a gloomy mood.'
WHERE `entry` = 496;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So the humans thought to turn our warriors into slaves, did they? We''ll show them!$B$BIt would seem that they have taken Gol''dir, our leader, to another location. We must find him and rescue him. But we currently have no clue where he is...$B$BWhen we have a lead, I will be sure to tell you, $N.',
    `RequestItemsText` = 'You must make haste, $C. I shudder to think what the humans might be doing to Drull and Tog''thar.'
WHERE `entry` = 498;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Croak!',
    `RequestItemsText` = 'Ribbit!'
WHERE `entry` = 499;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good, $N You must have hacked through a whole mess of ogres to get all these knucklebones.$B$BThat should keep them out of our hair. At least, for a while.',
    `RequestItemsText` = '$N, are you still hunting ogres? Do you have the knucklebones I had you gather?'
WHERE `entry` = 500;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Superb collecting, $N.',
    `RequestItemsText` = 'I remember you, $N.  You were going to help me out in concocting my latest elixir.  I''ll need that blood before I can bring my own special brand of misery to the inhabitants of Hillsbrad.'
WHERE `entry` = 501;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You pour some of the elixir into your hand and hold it before Stanley''s mouth.',
    `RequestItemsText` = 'Woof?'
WHERE `entry` = 502;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. I led the expedition from Durotar under the Warchief''s orders, but as you can see, our plans went somewhat awry. They have held me captive here in this town, forcing me to work, hauling burdens, digging...$B$BWhat I have suffered is unimportant, however. There is important information you must deliver to whomever is leading our group now.',
    `RequestItemsText` = 'Give me the key, $C, I will undo the lock myself.'
WHERE `entry` = 503;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good. Here is your reward.$B$BAnd when you were hunting those Warmongers, how did Alterac city look? It''s in bad shape I would guess. Ogres are not known for their cleanliness.$B$BThankfully, your efforts will help keep them away from Southshore.',
    `RequestItemsText` = 'You have more Warmongers to slay, $N. You should be up on the mountains on your task, not down here with your weapon stowed.'
WHERE `entry` = 504;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. Although they may still be lurking about, we hope that some of the thieves and footpads you slew were responsible for the last magistrate''s death. But even if they weren''t, the Syndicate is a taint on this land and a stain on the human race.$B$BTheir deaths are welcome to Southshore.',
    `RequestItemsText` = 'You have slain those Syndicate thugs, I trust?'
WHERE `entry` = 505;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The nerve of those overbearing humans! We''ll show them that the orcs shall never submit to their will!$B$BThis will now be our mission, in addition to recovering the trinket the Warchief desires. It would seem that by accomplishing one, we will also accomplish the other.',
    `RequestItemsText` = ''
WHERE `entry` = 506;

UPDATE `quest_template` SET
    `OfferRewardText` = 'No, no please don''t hurt me! I never meant your people any harm, he''s had me against my will! Please... spare me!',
    `RequestItemsText` = 'W-what do you want?'
WHERE `entry` = 507;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is strange that the Warchief would expend so much over such a small thing. I do not claim to understand him, but I will follow him, whatever his commands. You did well, $N, no doubt the Warchief will be glad to hear of your success.',
    `RequestItemsText` = 'You''ve returned, $N. Success to report?'
WHERE `entry` = 508;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, the horrible reek of Mudsnout Blossoms.  At least those filthy Gnolls are good for something.',
    `RequestItemsText` = 'Any luck at Nethander Stead?'
WHERE `entry` = 509;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Maleb reads the documents.>',
    `RequestItemsText` = '$N, you look anxious. Is there something you wish to tell me?'
WHERE `entry` = 510;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What is this? Hold a moment... let me take a closer look.',
    `RequestItemsText` = 'Yes, $N? Do you have some business with me?'
WHERE `entry` = 511;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Stripping the Syndicate of its nobility will remove its ability to act decisively, and reduce it to nothing more than a gang of thugs.$B$BYou serve your Alliance well, $N.',
    `RequestItemsText` = 'Have you been hunting the Syndicate? Do you have those rings?'
WHERE `entry` = 512;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Apothecary Lydon sent you?  Ah, why didn''t you say so!$B$BDespite his gloomy disposition, Apothecary Lydon is one of our most dedicated and skilled members.$B$BThe good chap sends Mudsnout Composite!  I know what our friend in Hillsbrad is up to now.  And I like the way he thinks.  The Dark Lady would be most impressed with the progress he is making toward the new plague.',
    `RequestItemsText` = 'Can you not see I am busy, $C?  The Dark Lady insists on a new plague before the Scourge advance from Northrend overwhelms us.  And with the human threat pressing from the south, time becomes my most precious commodity.  This better be important!'
WHERE `entry` = 513;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, encryption! A specialty of mine. Let me see here...',
    `RequestItemsText` = 'Dibbs from Southshore sent you, did he? How is the old bookworm doing?'
WHERE `entry` = 514;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The excitement of this experiment has me feeling giddy! You have been such a great help, $N. Together we will spread death and disease to this land!',
    `RequestItemsText` = 'So glad to see you back, $N. I was growing so terribly bored here. Not a single entertaining thing to do besides poison and disease Umpi and reanimate her. . .over and over and over again.$B$BHow went the trip to the Undercity? Were you fortunate enough to slaughter any humans along the way?'
WHERE `entry` = 515;

UPDATE `quest_template` SET
    `OfferRewardText` = 'If our scouts and agents continue to procure valuable information such as this, we shall have the Lich King''s Scourge removed from our lands in no time.',
    `RequestItemsText` = 'Have you located their base yet, $N? Time is of the essence!'
WHERE `entry` = 516;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Finally! Now we are ready for action!',
    `RequestItemsText` = 'Sometimes I get so bored out here in Tarren Mill I like to open up the formaldehyde jar and let the lovely aroma waft through the air. Makes Umpi a little nervous though.$B$BSo were you able to get a keg from the Dwarves? I swear if I have to stare at this deadly elixir without using it on someone for another day I am going to scream.'
WHERE `entry` = 517;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The snow blooms red with the blood of the ogres, but we cannot cease our efforts until the spirit and numbers of the Crushridge have been crushed and ground into the dirt and snow.',
    `RequestItemsText` = 'I note that your task is unfinished, $N. Shall I inform Sharlindra of your ineptitude?'
WHERE `entry` = 518;

UPDATE `quest_template` SET
    `OfferRewardText` = '...and I thought ogres smelled foul enough to begin with.$B$BWhen you bring me Mug''Thol''s head, I will have the four of them mounted on pikes above Alterac. A fitting monument to those who go against the Dark Lady''s wishes.',
    `RequestItemsText` = 'I want their heads, $N, not excuses.'
WHERE `entry` = 519;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done your duty well, $N. Mug''Thol''s head shall adorn the highest peak of the ruins of Alterac, and the Deathguard will sweep the remnants of the Crushridge into the ground.',
    `RequestItemsText` = 'Three heads I have, a fourth I need. It will be Mug''Thol''s, or it will be yours, $N. That I promise.'
WHERE `entry` = 520;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So this is the relic the ogre used to duck the will of the Dark Lady...$B$BStrange that something so simple could wield so great a power. And to fall into as clumsy hands as those. Well done, $N, I will deliver the crown to Lady Sylvanas, and see that she hears of your accomplishment.',
    `RequestItemsText` = 'Yes? Do you have something to report?'
WHERE `entry` = 521;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Maleb inspects the contract.>$B$BThat explains the latest attack on Southshore. The Syndicate must be after me, just as they were the last magistrate!',
    `RequestItemsText` = 'You look out of breath! Do you have something to report?'
WHERE `entry` = 522;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. My head rests a little easier, knowing that villain lost his.',
    `RequestItemsText` = 'Baron Vardus cannot think Southshore will allow him to send his thugs against us with impunity. I want his head!'
WHERE `entry` = 523;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You rest the tainted keg on the dusty rug.',
    `RequestItemsText` = 'A musty smell emanates from the rug.'
WHERE `entry` = 524;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Maleb reads the letter.>$B$BThis is translated from a letter you found in a Syndicate encampment? This was not written by a thief, or even a noble of Alterac.$B$BIt appears The Syndicate has ties to another power, and I shudder to think what that might be.',
    `RequestItemsText` = '$N. Have you been traveling through the foothills and mountains again? What news do you bring?'
WHERE `entry` = 525;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, you found them! Now let''s get this lightforge iron hammered into something useful, eh?',
    `RequestItemsText` = 'Did you find the lightforge iron you need?'
WHERE `entry` = 526;

UPDATE `quest_template` SET
    `OfferRewardText` = 'At ease, $C.  I see you have returned from battle.  My sources tell me you performed well on the Hillsbrad front.',
    `RequestItemsText` = 'As High Executor of Tarren Mill, under the direct command of Varimathras and the Dark Lady, you are subject to follow my command.$B$BPerhaps you take this war with the Alliance lightly?  If such is the case I should behead you right here and now.  Otherwise, travel west to the town of Hillsbrad and wage battle against the humans, as ordered.$B$BDismissed.'
WHERE `entry` = 527;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The grip of death is tightening around the town of Hillsbrad. The battle goes well.',
    `RequestItemsText` = 'You have your orders, $C. Quit dawdling here in Tarren Mill when there is work to be done elsewhere.'
WHERE `entry` = 528;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Mission accomplished, $C. And carried out quite skillfully, I might add.',
    `RequestItemsText` = 'Were you able to carry out your orders, $C? Did you dispose of Verringtan and his assistants? And where is that iron shipment?'
WHERE `entry` = 529;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, good. These hands killed my wife, Deliah. Revenge for her murder was my only care, and you were the instrument of that revenge.$B$BHere, take the ring you returned earlier. Deliah has been dead to me for so long, her ring is a bauble I no longer care to keep. Instead, I will keep these hands as a remembrance of my friend''s betrayal.',
    `RequestItemsText` = 'Do you have those hands, $N?'
WHERE `entry` = 530;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thanks for helping me out with my little plan, $N. I''ve been itching for months to get back at that snooty, stuck-up boy, and I''d say we did a pretty good job! Here, have this, you''ve earned it.',
    `RequestItemsText` = 'Great job, $N! We really showed him! Here, give me the head and I''ll take care of it.'
WHERE `entry` = 531;

UPDATE `quest_template` SET
    `OfferRewardText` = 'News of your glories in Hillsbrad traveled fast. You have done well, $C.',
    `RequestItemsText` = 'What news have you?'
WHERE `entry` = 532;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Finally, we know where Gol''dir is being held. The camp in question is not too far from here, and hopefully they will not be as well prepared as they were when they captured us the first time.',
    `RequestItemsText` = 'Have you found anything? I fear Gol''dir''s prospects grow worse by the day...'
WHERE `entry` = 533;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Given my impending death, I think I can safely say that this is the sweetest tasting thing ever... Here, take this, won''t do me any good when I''m dead.$B$BWell, get on with it!',
    `RequestItemsText` = 'Did you bring me something to drink or did you just come back to finish the job?'
WHERE `entry` = 535;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I hope this will be enough to convince Redpath that I''ve--ha!--been carrying out his orders and ridding Southshore of the terrible and horrible menace of the dreaded murlocs! For there could be no greater evil than the ravages of overgrown fish!',
    `RequestItemsText` = 'Another ale, please, the last one just seemed to have disappeared!$B$BLight, how much longer am I going to be stuck out here?$B$BOh, it''s you, $N. Have you killed those murlocs yet?'
WHERE `entry` = 536;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N. The Argus Wake does not sound like a group we want running the Syndicate.$B$BAnd although you may have destroyed their leader here, Nagaz was merely the servant of another. The Argus Wake might run deep through the continent of Azeroth.$B$BOr even the world.',
    `RequestItemsText` = 'Did you find the envoys of The Argus Wake?'
WHERE `entry` = 537;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah yes, I remember Milton. A bookworm, no doubt. Bless him.$B$BAnd he''s right. The Ruins of Alterac still hold stores of knowledge in danger of being lost!$B$BOgres now dwell in Alterac, and they don''t care much for higher learning.',
    `RequestItemsText` = ''
WHERE `entry` = 538;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Dark Lady will be pleased when she learns that she has a new mine from which she can arm her soldiers.',
    `RequestItemsText` = 'You were given direct orders to attack the Azureload Mine. Your reasons for loafing about Tarren Mill better be good or I will behead you for treason.'
WHERE `entry` = 539;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, you got them! Splendid! I must begin studying the Arm of Gri''lek immediately!',
    `RequestItemsText` = 'I wish I could search the ruins too, but I fear these bones wouldn''t hold me during my climb up the mountains. However, how does your hunt for knowledge progress, $N?'
WHERE `entry` = 540;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your actions on the battlefield are worthy of the highest praise.',
    `RequestItemsText` = 'Dun Garok proves to be too much of an obstacle for you, $C? And here I thought you had established yourself valiantly in Hillsbrad.$B$BIf you''re not up to handle the mission assigned to you, I will find another who can produce better results. As for you, well, I am sure the Dark Lady could always use more grave diggers back in Tirisfal Glades.'
WHERE `entry` = 541;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My oh my! Look at these! I can''t believe they survived the ruination of Alterac. And all those ogres too!$B$BThank you, $N. Thank you so much! You have helped preserve human knowledge, and you add to the grandeur of the Royal Library of Stormwind.',
    `RequestItemsText` = '$N, you''ve returned! How did your foray into Alterac go? Did you bring anything back with you?'
WHERE `entry` = 542;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, this is splendid.  This will have to be cleaned of course, but you really outdid yourself, $N.  I will have someone prepare the tiara and place it within our collection posthaste.$B$BAs I''m sure you will agree, our gratitude is as grand as our collection.',
    `RequestItemsText` = 'Salutations, $N.  Do try to avoid stepping on my pant cuffs.  This outfit is newly tailored.'
WHERE `entry` = 543;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done a great service for the Forsaken, $N.  These artifacts have been sorely missed.$B$BAnd it is good to hear that Kegan and the other betrayers have found justice.',
    `RequestItemsText` = 'Did you find the thieves?  And more importantly, did you find what they stole?'
WHERE `entry` = 544;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good.  Those ruins should now be safe enough to search, if one is careful.$B$BThank you, $N.',
    `RequestItemsText` = 'Have you yet thinned the Dalaran patrols around their ruins?'
WHERE `entry` = 545;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Precious skulls! So beautiful! I owe you as promised, $N!',
    `RequestItemsText` = 'So the lucky $N returns? How many humans have you slaughtered today? Hundreds I do hope!$B$BHave you any skulls for me?'
WHERE `entry` = 546;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found it!$B$BAh, I feel so complete with my precious sword back in my hand. Many thanks to you!',
    `RequestItemsText` = 'Were you able to retrieve my sword, $N? High Executor Darthalia will hang me from the rafters if she discovers my folly.'
WHERE `entry` = 547;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent, $C. At this rate, the Syndicate pest will be rid from the land in no time.',
    `RequestItemsText` = 'Do you have nothing better to do than stand here before me, $C? As High Executor, I have more pressing matters than to stare at your rotting visage.'
WHERE `entry` = 549;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So you are the infamous $C who struck such a decisive blow against the Alliance forces in the Hillsbrad Foothills? Word of your glorious exploits traveled quickly to the Undercity.$B$BYou have quite a future in the Dark Lady''s ranks if you continue to show such leadership and expertise in battle.$B$BWhile our primary threat is the Lich King''s Scourge army descending from the north, the human "problem" continues to impede our battle plans. You, however, have shown that the humans can and will fall.',
    `RequestItemsText` = 'What brings a $C all the way to the Undercity from the battlefield?'
WHERE `entry` = 550;

UPDATE `quest_template` SET
    `OfferRewardText` = 'More encrypted notes?$B$BI wish I had the talents to decrypt all the strange bits of writing that trickle down from Alterac. But I''m afraid I lack the knowledge.',
    `RequestItemsText` = 'Oh. You have something you''d like me to look at? Some scrap of lore gathered from up in the mountains, I hope...'
WHERE `entry` = 551;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found it!  Most excellent, $N!',
    `RequestItemsText` = 'Have you recovered Helcular''s Rod yet?  There are so many Yeti in this region, it will be very difficult to locate.  But we must have it in order to proceed.'
WHERE `entry` = 552;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A great rumbling emanates from the ground.',
    `RequestItemsText` = 'Helcular''s grave teems with a mystical energy.'
WHERE `entry` = 553;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A wise decision. I don''t believe there is a scholar other than myself with the skills to translate this scroll. And if its contents prove interesting, fear not. I will send for you.',
    `RequestItemsText` = 'More interruptions?$B$BAh, this parchment is covered with a very intricate, finely woven spell. I can untangle it, of course, but it''s going to take time. And time is very valuable to me...$B$BPerhaps I will just purchase it from you?'
WHERE `entry` = 554;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Everyone will be so pleased: Chef Jessen''s Soothing Turtle Bisque is served once again!',
    `RequestItemsText` = 'Any luck finding the ingredients? I''ll tell you, this territory isn''t the peaceful place it once was. Ah, if only this unrest never occurred...'
WHERE `entry` = 555;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These will do nicely.  Although it looks like their magic is faded, it would be best if the Magus'' initial experiments were on inert specimens such as these.$B$BThank you, $N.',
    `RequestItemsText` = 'Do you have the Worn Stone Tokens, $N?  The Magus is eager to unlock their secrets.'
WHERE `entry` = 556;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found them.  I trust the elementals from which you removed these bracers were amenable?$B$BHm...death has not only stopped my heart, but robbed me of my comedic timing, it seems.$B$BWell thank you, $N.  You serve the Magus, and hence the Dark Lady, well.',
    `RequestItemsText` = 'Hello, $N.  Elementals are tough quarry, but I know you''re up to the task.  Do you have those bracers of binding?'
WHERE `entry` = 557;

UPDATE `quest_template` SET
    `OfferRewardText` = 'WOW! You got Lady Jaina''s autograph for me! Thank you very much! And wow... she wrote a personal message on here - to me! I knew she''d be totally cool, and maybe someday I''ll thank her myself... when I become a hero of the Alliance!$B$BYou''re the best, $N. Thank you for being so nice to me.',
    `RequestItemsText` = 'Someday, I wanna be a hero just like Jaina... well, a boy hero that is.'
WHERE `entry` = 558;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh for the Love of the Light... they''re dripping on the ground.$B$BCan''t stand touching those things, myself. Fish are all well and good, but when they grow legs and start walking around... Haven''t eaten a fish in weeks, let me tell you, and in Southshore, that means you aren''t eating much.',
    `RequestItemsText` = 'Did you get those heads for me, $N?'
WHERE `entry` = 559;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Farren''s errand boy, are you?$B$BIf you assisted Farren in procuring these heads, then thank you. Southshore needs hard workers and effort to maintain its protection.',
    `RequestItemsText` = 'Greetings, citizen. Have you come to lend your arm to upholding the safety of Southshore?'
WHERE `entry` = 560;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The naga, eh? Redpath must have just received the same information as me... Ha! He''ll not receive a promotion from my toil. Let me explain.',
    `RequestItemsText` = ''
WHERE `entry` = 561;

UPDATE `quest_template` SET
    `OfferRewardText` = 'With the naga put down in Southshore, I''ll be a shoe-in to be reassigned. I''ll get to see Stormwind again... get away from this Light-forsaken port.',
    `RequestItemsText` = 'I''ve a letter ready to go to Major Samuelson in Stormwind. All I need are the results.'
WHERE `entry` = 562;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What''s this? Ah... so my attentive pupil has applied himself to the problem of the naga in Southshore. Thank you for bringing this to me, I will certainly take it into account when I review personnel assignments in the next month.',
    `RequestItemsText` = 'Greetings, citizen. May the Stormwind city guard be of assistance?'
WHERE `entry` = 563;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ain''t that great news! Should-a gone and found me a regular ol'' war hero from day one to take care of them beasts. You''d-a made your pappy proud, $N.',
    `RequestItemsText` = 'Mountain Lions killin'' off our horses left and right and here you are wantin'' to jibber-jabber about the weather and what not.$B$BOught to go and find myself a real hero. More killin'' and less talkin''.'
WHERE `entry` = 564;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now it is time for the great Bartolo to work his magic! I require no wizard''s staff, no $C''s rod. For I, the great Bartolo, work magic with a mere needle and thread!',
    `RequestItemsText` = 'So you have returned to the great Bartolo. Perhaps you have finished gathering the materials needed for your Yeti Fur Cloak? Or maybe you just enjoy basking in the greatness of me, Bartolo!'
WHERE `entry` = 565;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Productive work you do, $N. With Baron Vardus dead, the number of Syndicate leaders grows smaller. Their resistance and irritation will be short-lived.',
    `RequestItemsText` = 'Ah, $N. Perhaps you''ve come to collect the bounty on the head of Baron Vardus?'
WHERE `entry` = 566;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You are quite the bounty hunter, $C.  Well done.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 567;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your duty was performed with honor, $C.',
    `RequestItemsText` = 'Our supply efforts are still being hampered by the indigenous raptor population, $C.'
WHERE `entry` = 568;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done.  You have served the Warchief with honor.',
    `RequestItemsText` = 'Have you made any progress with the ogres of the Mizjah Ruins yet, $C?'
WHERE `entry` = 569;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your knowledge of the jungle is strong, $N.  These specimens will be perfect.  I will thank the spirits for sacrificing such fine beasts for the cause of the Horde.',
    `RequestItemsText` = 'What news do you bring?'
WHERE `entry` = 570;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A most ideal sinew, $N. Your efforts will pay off soon.',
    `RequestItemsText` = 'Has fortune been on your side, $N? Were you able to obtain an aged gorilla sinew?'
WHERE `entry` = 571;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Most excellent. I will prepare these at once.',
    `RequestItemsText` = 'Did your gathering efforts prove fruitful?'
WHERE `entry` = 572;

UPDATE `quest_template` SET
    `OfferRewardText` = 'With this Holy Spring Water the ceremonial choker is ready for enchantment.$B$BWear this with pride, $N, in the name of the Warchief and in defense of the mighty Horde.',
    `RequestItemsText` = 'I am almost ready to complete the enchantment. Have you performed my bidding?'
WHERE `entry` = 573;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N. Sergeant Yohwa trusted your abilities, and I trust her. The defeat you brought to Kurzen''s forces is almost too much to hope for. I had feared we rebels were alone, and alone we could never stand up against the Colonel''s brilliance.$B$BPerhaps hope of our survival yet remains.',
    `RequestItemsText` = 'Sergeant Yohwa tells me you are skilled and brave, $C. Do you have something to report?'
WHERE `entry` = 574;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These skins should do. Their quality isn''t too important, given that they''ll make up the inside layer of the boots, but it''s still important that they''re comfortable.$B$BIf they''re a bit too rigid, I''ll use some tiger blood to soften it up. Tricks o'' the trade, you know?',
    `RequestItemsText` = 'My equipment is all ready to go, $N, I just need those skins. We don''t want to keep Riddlevox waiting, that''s for sure.$B$BIt''s not a good idea for anyone to keep the chief inventor of the Tinkers'' Union unsatisfied.'
WHERE `entry` = 575;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Shiver me timbers and timber me shivers! Ye found me beautiful eye! Let''s see if she still fits.$B$BShavas ho! Blimey, I can see!!',
    `RequestItemsText` = 'Ahoy, me bucko! Might not be able to see but I can smell ye from halfway across port.$B$BCould really use me eye back. Captain''s going to keelhaul me when he finds out me peeper is in the hands of them dirty Bloodsail Buccaneers.$B$BWhat good is a lookout who can''t see? The crow''s nest used to be me home...without me deadlights I''d be lucky to scrub the bilge.'
WHERE `entry` = 576;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My boots... they''re like sausages, $N. Look great, taste great. I tell you they''re filled with nothing but the finest ingredients and meats, and you eat it, and you love it.$B$BIt''s safer--and more enjoyable--if you just trust me, and don''t ask too carefully what''s really inside.',
    `RequestItemsText` = 'Drizzlik''s Excelsior leather boots, finest workmanship, one-hundred percent high quality saltwater crocolisk skin boots. None finer!$B$BCan''t beat a glowing description like that, can you?$B$BExcept, maybe, if you have those skins for me?'
WHERE `entry` = 577;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So the stories were true! Incredible!$B$BHowever, we will need to figure out a way to defeat the curse of the Stone of the Tides, if we are to retrieve it. The curse is magical business, we''ll need one of those wizards to help us out.',
    `RequestItemsText` = 'The trolls truly possessed some amazing magical objects, $N. And now, perhaps, I have the opportunity to add one to my extensive collection. Did you have any luck finding the source of the rumor?'
WHERE `entry` = 578;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Do any of these titles interest you, $N?',
    `RequestItemsText` = 'King Varian has placed great importance on learning, and thus has provided funds for making copies of various tomes and writings available to the public. It''s very simple. You bring me a library scrip, and I can give you a copy of one of the available books.'
WHERE `entry` = 579;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Shiver me timbers! Ye found the Cap''n''s grog!$B$BI owe ye big time, friend.$B$BSeems like a storm is a brewin'' outside. Maybe I''ll just keep warm with one o'' these here bottles while we wait for it to pass....',
    `RequestItemsText` = 'Sink me! I''m almost outta booze here! Cap''n is goin'' to weigh anchor and Ol'' Slim will be caught dry as the Tanaris Desert. And once he discovers his port is missing. . . blimey!'
WHERE `entry` = 580;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These are good tusks, $N.  You prove that you have the strength to hunt the Bloodscalps.$B$BAnd that is good, because you are not done hunting them.',
    `RequestItemsText` = '$C.  Show me you have made prey of the Bloodscalp tribe.$B$BShow me your trophies.'
WHERE `entry` = 581;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N.  I will inspect these heads to ensure poor Yenniku was spared the headhunter''s axe.',
    `RequestItemsText` = '$N.  I fear for our chief''s son.  Do you have the shrunken heads so I may inspect them?'
WHERE `entry` = 582;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Jolly nice to make your acquaintance, $N. Haven''t seen a $C around these parts for some time.$B$BI situated myself with this expedition for one purpose: to hunt a great and elusive beast. Seeing that you''re a hero of sorts I am willing to let you take part in the hunt, but you must first prove yourself.$B$BI shall teach the ways of raptor killing to you. Ajeck will train you with tiger hunting. And Sir Erlgadin is a master of panther tracking.$B$BProve your skill and I''ll let you in on the big hunt.',
    `RequestItemsText` = ''
WHERE `entry` = 583;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You place the heads of Gan''zulah and Nezzliok within the cauldron...',
    `RequestItemsText` = 'The greenish broth within the cauldron bubbles.'
WHERE `entry` = 584;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes. These will serve me well. When my spirit is freed, I will enter the Nether with three fine servants!$B$BYou are a credit to your $R clan, and you have appeased me.',
    `RequestItemsText` = 'I await the skulls...'
WHERE `entry` = 585;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I do not want to believe it, but I cannot deny what you have done. And my rage eases, now that Ana''thek is defeated.$B$BYour might will drive you to great deeds, $N. But one day...I will see you in the Nether and we will again match strength.$B$BI will be waiting.',
    `RequestItemsText` = 'Although my own flesh boils off my skull, I can still smell your fear.$B$BHah!  You will never complete my task...'
WHERE `entry` = 586;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good show, $N! And just before I need to ship out too! Can''t thank you enough, old friend.',
    `RequestItemsText` = 'Any luck finding the goods, matey?'
WHERE `entry` = 587;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Zanzil the Outcast??$B$BIf Yenniku is held by that troll, a vile and powerful witchdoctor, then I fear that only a faint hope remains. Faint. And tiny as the smallest insect.$B$BBut still, it is hope.',
    `RequestItemsText` = ''
WHERE `entry` = 588;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, $N. These shards are well formed. Already I hear them sing to me.$B$BAnd while you were gone, I spoke with the spirits of the jungle. I know where the Mind''s Eye rests...$B$B...And who guards it.',
    `RequestItemsText` = 'Do you have the shards, $N? They are needed for my final ritual, after we have the Mind''s Eye.'
WHERE `entry` = 589;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Incredible! What skill!$B$BThought you''d be easy prey, $N. Got me good, you did.$B$BHere''s the coin I promised... not as much as I said it''d be, but that''s on a count o'' me lying to ya in the first place.',
    `RequestItemsText` = ''
WHERE `entry` = 590;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You retrieved the eye! Your might is the stuff of legends, $N!$B$BAnd in getting the Eye, you must have defeated Mai''Zoth and sent him to the Nether. That is why the spirits would not mention him before.$B$BIt is good that he is gone from the world of flesh and bone, but now that he is in the realm of spirits...I fear he will begin a new reign.$B$BBut that is a worry for another time. Now, I must perform a ritual to bend the Mind''s Eye to our needs...',
    `RequestItemsText` = 'Greetings, $N. The spirits sing praise of your bravery, yet they tell me no tales of your quest against Mai''Zoth.$B$BDo you have the Eye?'
WHERE `entry` = 591;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done it! You freed Yenniku from the will of Zanzil, and completed the mission I had thought was so desperate.$B$BOur tribe will remember your name in songs, $N, and we will etch your tale in stone so that it will live forever.',
    `RequestItemsText` = '$N. Kin''weelay told me you set out to capture Yenniku.$B$BIs it true? Do you have him?'
WHERE `entry` = 592;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You place the Soul Gem upon his forehead. He shudders as his soul is sucked in, leaving his body, a mindless husk, behind.',
    `RequestItemsText` = 'Yenniku stands stunned before you, his mind in another place...'
WHERE `entry` = 593;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Have you come to free me?',
    `RequestItemsText` = ''
WHERE `entry` = 594;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Inside the skiff, you discover a map with some hastily written text on it along with some coins.',
    `RequestItemsText` = ''
WHERE `entry` = 595;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, very good.  I will boil these, and leech them, and the spirits of their owners will weaken as I render their necklaces to paste!$B$BHere, $N.  This will repay my debt to you.',
    `RequestItemsText` = 'The Bloodscalps will one day be crushed by the Darkspears!  Do you have the necklaces of our doomed foe?'
WHERE `entry` = 596;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Sure, I remember you, $C. Back from scouting I see....',
    `RequestItemsText` = ''
WHERE `entry` = 597;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your strength is great to have gained these necklaces, $N. The Skullsplitters fall to you like young saplings stomped to earth by a Basilisk!$B$BYour deeds are a boon to us.',
    `RequestItemsText` = 'The Skullsplitters will curse the day they brought us to war! Is your task complete?'
WHERE `entry` = 598;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Bloodsail Buccaneers attacking Booty Bay? They might as well throw themselves off the Overlook Cliffs. Nonetheless, by bringing me this information you have done my fleet of swashbucklers a great service. The Blackwater Raiders thank you.',
    `RequestItemsText` = ''
WHERE `entry` = 599;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great! Wonderful! I can get a bundle for these!!$B$BThat Venture Company sure picked the wrong jungle to mine in, didn''t they? We''d all be in better shape if they moved out of here.$B$BThank you, $N. You''ve done a good deed this day.',
    `RequestItemsText` = 'Do you have those crystals?? I need them!!$B$BI mean...I need to know the evil Venture Company is losing ground in Stranglethorn. Because, you know, we honest folk have to make a living!'
WHERE `entry` = 600;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hm, I haven''t the eye to examine these bracers to see if any of them will be of any use, but I''m sure at least one of them will be able to help. Take them to Dalaran and have a mage look at them.$B$BAfter all, I can''t very well leave Booty Bay just to chat with those tiresome old mages.$B$BNot that I''m worried anyone would try to elbow their way into being the new baron. No one crosses Revilgaz and lives to tell of it.',
    `RequestItemsText` = 'Have you had any luck, $N?'
WHERE `entry` = 601;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Stone of the Tides? Most interesting. It might surprise you to know that I wrote a tome - several years ago - pertaining to the legends of the Gurubashi Empire. I do know quite a bit about the Stone.$B$BAt least one of these bracers appears to have some magical residue I can analyze.$B$BLet''s see what I can see...',
    `RequestItemsText` = 'If you wouldn''t mind, I am rather busy right now.'
WHERE `entry` = 602;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My dagger? What are you, some sort of comedian?$B$BWhat? Do you just want me to repeat the story of how I''ve gone from the best knife fighter in Booty Bay to the laughing stock of piratedom!$B$BI lost a knife fight to one of the Bloodsail Buccaneers--bunch of right bastards they are!--and he took my blade as spoils.$B$BIt''s not as though I can get by as a knife fighter with insults and a sharp tongue alone...',
    `RequestItemsText` = ''
WHERE `entry` = 603;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Perfect, $N. Now that we know their plan, it''s just a matter of time.$B$BAnd to think the fools have dropped anchor just off the cape....',
    `RequestItemsText` = 'Ahoy, $N. What word do you bring of the Bloodsail encampment to the south?'
WHERE `entry` = 604;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Aha!  These will do nicely, $N.  Yes, quite nicely!$B$BHere is your cut, and...it was a pleasure doing business with you.',
    `RequestItemsText` = 'Do you have those shards yet?  I''ll give you a decent cut from the profits!'
WHERE `entry` = 605;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ack! Where''d you get these? No, don''t tell me. I don''t want to know!$B$BWho sent you? Sea Wolf?',
    `RequestItemsText` = 'Hey! I don''t like the look you''re giving me, mister.'
WHERE `entry` = 606;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Heh heh, well done! And when you showed Shaky those giblets, how hard did he shake?$B$BHah! He''s so easy to read, when I play cards with him I can''t help but win!$B$BThanks for your help, $N. Now it''s your turn to get paid...',
    `RequestItemsText` = 'Here here, $N. Did you get Shaky''s payment?'
WHERE `entry` = 607;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, what a great day for the Blackwater Raiders! Three cheers to you, $N!',
    `RequestItemsText` = 'What''s the problem, $N? We need to attack before the Bloodsail Buccaneers do!'
WHERE `entry` = 608;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great! I can get a good price for these, especially for what''s inside Maury''s foot! Thanks much, $N!$B$BI hope those three learned their lesson: don''t bet something you can''t afford to lose.$B$BAnd maybe it''s too late for them, but...they should be careful of who they gamble with.',
    `RequestItemsText` = '$N, did you find those three dogs? Did you collect their valuables?'
WHERE `entry` = 609;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You beat Duncan? I guess you aren''t as wet behind the ears as you looked at first glance.$B$BI suppose that also means I shouldn''t challenge you to a fight any time soon!',
    `RequestItemsText` = 'I''d never been beat before, you know, $N? Sure I''d been cut, can''t get in a knife fight without that, but he just smacked me on the side of the head, blacked me out. When I came to my blade was gone.$B$BAs much as my nickname might indicate, I still need a knife to fight, and for me, it has to be that one.'
WHERE `entry` = 610;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Amazing! The Stone of Tides! It shall have a place of prominence in my collection of ancient troll artifacts. Did you see how it almost seems as though a tide is trapped within its surface? Magnificent!',
    `RequestItemsText` = 'Have you retrieved the Stone of the Tides for me, $N? I''ve already cleared out a space and purchased a fine stand for it.'
WHERE `entry` = 611;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found it! Thanks a million, $N. You''ve been a big help to me!$B$BHere you go - you earned this!',
    `RequestItemsText` = 'Ahoy, $N! Have you yet found Maury''s Key?'
WHERE `entry` = 613;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found it! Oh happy day, this is! Thank you, $N. Getting back my chest cools some of the fire in me.$B$BBut my revenge isn''t complete...',
    `RequestItemsText` = 'Ahoy, $N! Did you find Gorlash? That chest was my favorite, and it has a hidden compartment that held my greatest treasures!'
WHERE `entry` = 614;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hello hello, $N. Captain told me you''re going after Negolash, eh?',
    `RequestItemsText` = ''
WHERE `entry` = 615;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Interesting. Some time ago, I seem to remember reading a book once that suggested...$B$BAh, of course, a troll legend it was. If what Krazek reports is true, perhaps I will soon be able to add the Stone of the Tides to my collection of ancient artifacts and relics.',
    `RequestItemsText` = ''
WHERE `entry` = 616;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N. 10 stalks of akiris reed wasn''t too much a challenge after all, huh? No offense to the naga, but hey, everybody''s gotta make a living.',
    `RequestItemsText` = 'If ya got no business with me, then move along, $N.'
WHERE `entry` = 617;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You got my cutlass from Negolash! I can''t believe my fortune, $N! Meeting you has turned my luck to the better, make no mistake there!$B$BThank you! And if I ever get a new ship and you''re looking to sail the seas, you would be my honored guest.',
    `RequestItemsText` = 'Did you get my cutlass, $N?'
WHERE `entry` = 618;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You pile food and drink upon the raft...',
    `RequestItemsText` = 'This is an abandoned lifeboat.  Printed along its side in scratched, faded paint are the words:$B$B"Smotts'' Revenge"'
WHERE `entry` = 619;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, very good! Here is your pay.$B$BAnd here is a little something extra... for your discretion.',
    `RequestItemsText` = 'Do you have the samples of Zanzil''s Mixture??'
WHERE `entry` = 621;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It''s fixed! This is great, now I can get dinner started! Thanks so much, $N.$B$BI hope you were okay in Booty Bay. That place can get pretty rough, and... I heard rumors that the goblins will sometimes drag drunk sailors to their slave boats and take them to who-knows-where... to do who-knows-what...',
    `RequestItemsText` = 'Hello, $N. Did you make it to Booty Bay? Did the goblin Krazek fix my pot??'
WHERE `entry` = 622;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What?! I got a lot better things to do then talk to the likes of you, $C. Make it worth my while or get outta my face.$B$BHuh? Bloads sent ya, huh? Well, whaddaya got for me?$B$B<Privateer Groy looks over the bundle carefully.>$B$BNot bad, not bad at all. Another bundle will make my client quite happy.$B$BI suppose yer next question''s gonna be about money, huh, $C? Of course it is!$B$BHere, take this coin and some advice: get off my docks.',
    `RequestItemsText` = 'Yeah?'
WHERE `entry` = 623;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The soggy parchment contains the next clue....',
    `RequestItemsText` = ''
WHERE `entry` = 624;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You find a musty scroll.',
    `RequestItemsText` = ''
WHERE `entry` = 625;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You open the chest to discover....',
    `RequestItemsText` = ''
WHERE `entry` = 626;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, splendid! That was a big favor you did for me.$B$BHere is your payment...',
    `RequestItemsText` = 'Hello, $N. Did you have luck getting the bloodstone?'
WHERE `entry` = 627;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great! Thanks to your help I''ll have this order filled and sent off to Director Riddlevox on the next boat to Undermine. Ahead of schedule, even!$B$BFor all your hard work, here, I made some extras, so take a pair. It''s on Drizzlik.$B$BAnd remember, there''s no boot so fine as one of Drizzlik''s Excelsior line!',
    `RequestItemsText` = 'I read somewhere that the saltwater crocilisks are slowly dying out... bad news for my business, isn''t it?$B$BAnyways, I hope you have that elder saltwater crocolisk skin for me!'
WHERE `entry` = 628;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is good. When I return to Orgrimmar I will place this shard in a sacred place. It will remind us of the might and honor of Gri''lek.$B$BThank you, $N. Your deeds mark a growing friendship with the Darkspear tribe.',
    `RequestItemsText` = 'I await the Tablet Shard, $N.'
WHERE `entry` = 629;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N, you have saved me from a great dishonor. If it was within my power, I would offer you a place among my tribe. But for now, all I can only offer you is this token for the courage and nobility you have shown.',
    `RequestItemsText` = 'I thank my ancestors someone has come to aid me. Do you have the key that will free me?'
WHERE `entry` = 630;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You search the tiny, dwarven corpse. Engraved into the helmet you can clearly read: Ebenezer Rustlocke.',
    `RequestItemsText` = ''
WHERE `entry` = 631;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh my, the news is grave....',
    `RequestItemsText` = 'Any sign of Ol'' Rustlocke, $N?'
WHERE `entry` = 632;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The remaining bridge is saved! You have done a great service to King Magni and the people of Khaz Modan.$B$BNow if we can only hold out long enough for reinforcements to show...',
    `RequestItemsText` = 'The cache of explosives must be destroyed!'
WHERE `entry` = 633;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My condolences go out to Longbraid and his brave soldiers. The news of the Thandol Span tragedy and the fall of Dun Modr hangs heavy in my heart.$B$BBut Stromgarde has fallen! Hence our presence here at Refuge Pointe. We are faced with retaking our own great city.$B$BHonor and duty require that we do not leave the Highlands until Stromgarde raises the mighty banner of the King once again. I will send word to Longbraid that he is on his own...',
    `RequestItemsText` = ''
WHERE `entry` = 634;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This crystal pulses, as if a living force is trapped within it.',
    `RequestItemsText` = ''
WHERE `entry` = 635;

UPDATE `quest_template` SET
    `OfferRewardText` = '',
    `RequestItemsText` = ''
WHERE `entry` = 636;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You say you saw my Sully pinned beneath the icy waters? Say it isn''t so!$B$BLet me read what he wrote....',
    `RequestItemsText` = 'You look as though you have traveled a great distance and seen much turmoil in your time, $C. These times we live in are trying on the soul. What news do you bring to me now?'
WHERE `entry` = 637;

UPDATE `quest_template` SET
    `OfferRewardText` = 'How you doing, $C? The task set before us by Vol''jin will be a difficult one, and any assistance you might provide will be appreciated and necessary.',
    `RequestItemsText` = ''
WHERE `entry` = 638;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent, mon. That''s a good start to collecting the sigils we''ll need to remove Trol''kalar from Trollbane''s tomb.',
    `RequestItemsText` = 'Have you located the first sigil yet? It is most likely carried on the person of one of the Syndicate agents in Stromgarde.'
WHERE `entry` = 639;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, you need me to reconstruct this sigil? It shouldn''t be too difficult... all the pieces seem to be here and the magical structure will be easy to reform.$B$BYou might want to close your eyes.',
    `RequestItemsText` = 'Throm''ka, $C. Zengu informed me that you required my assistance?'
WHERE `entry` = 640;

UPDATE `quest_template` SET
    `OfferRewardText` = 'We''re halfway to being able to remove Trol''kalar from Trollbane''s tomb. We are not exactly sure where the third sigil is, as its holders seem to move around Arathi quite a bit, but I have faith that you''ll be able to find it.',
    `RequestItemsText` = '$N! Do you have the second sigil?'
WHERE `entry` = 641;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah!  You activated these shards.  Already I feel more myself!$B$BBut alas, I am still far from free...',
    `RequestItemsText` = 'This cluster of shards looks much like the Shards of Myzrael.  But the same feeling of security does not pulse through them.'
WHERE `entry` = 642;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Losing their cavalry leader will prove a large blow to the Stromgarde defenders. Better yet, it means that we are only one sigil from being able to have Trol''kalar for ourselves.',
    `RequestItemsText` = 'Valorcall will not be easy to track down, $N. Mounted on horseback, he can cover ground quickly. Nonetheless, we must have his sigil.'
WHERE `entry` = 643;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Quite a day this is, $C. The blood of Trollbane will no longer haunt my people, and the sigils needed to take Trol''kalar are in our possession. Soon, very soon, we will strike against the hated trolls of Zul''Gurub.',
    `RequestItemsText` = 'You''ve returned, $N. Is the line of Ignaeus Trollbane broken?'
WHERE `entry` = 644;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Matching the lines on the face of Trollbane''s tomb with the glowing lines of the Sigil of Ignaeus, a flash of light consumes the Sigil, and the legendary sword Trol''kalar is released from the stone hands'' grip.',
    `RequestItemsText` = 'Etchings in the stone upon the face of the tomb of Trollbane match the glowing lines of the Sigil of Ignaeus...'
WHERE `entry` = 645;

UPDATE `quest_template` SET
    `OfferRewardText` = 'For generations, the forces of Strom and Arathor ravaged the trolls. Now their greatest weapon is in our hands. Our inching progress in the steamy forests of Zul''Gurub will be no more.',
    `RequestItemsText` = '$N! Have you taken the sword?'
WHERE `entry` = 646;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, nothing like Foggy MacKreel''s Moonshine to warm you up on a brisk day! And here I was thinking the little bugger was going to be overdue on his bills again. Thank you, friend! Many thanks indeed!',
    `RequestItemsText` = 'What''s the good word, $R?'
WHERE `entry` = 647;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, YOU''RE the great savior of OOX-17/TN!  I cannot even begin to express my thanks for your assistance!  My homing robot series needs more developing, but your recovery has saved me countless hours of rebuilding time, as well as many gold pieces in rebinding costs!$B$BPlease, take your choice of any of these items I have.  Hopefully, you will make good use of one of them.  Thank you again for your generous assistance, my robots and I are in your debt!',
    `RequestItemsText` = ''
WHERE `entry` = 648;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh yeah, about the ripple dad wants! He wants to sell the ripple to a tavern here in Orgrimmar, but we''ll get more money if it is in its original packaging. I know someone who can do that, and he''s in the Hinterlands where the ripple is. But he''s, um, a high elf.$B$BWell, he''s a good high elf, as he''s not a part of the Alliance. Well, he''s not so much a good high elf as he is a drunken high elf. He loves, and I mean LOVES the hooch.',
    `RequestItemsText` = ''
WHERE `entry` = 649;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, so you know Malton? He is an old drinking companion of mine. You see, I have found something that transcends the boundaries of artificial treaties and alliances - alcohol. Were we all to slake our thirsts on its blissful qualities, we all would be in a much better place spiritually.$B$BAlas, something tells me that your visit here is not to learn of alcohol''s redeeming values, now is it.',
    `RequestItemsText` = ''
WHERE `entry` = 650;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Myzrael speaks through the stone.>$B$BYou have done it!  You opened the Stones of Binding!  I can feel the shackles about me loosen, and freedom draws ever closer.$B$BYou are a noble $C, $N.  My rescuer!',
    `RequestItemsText` = 'This is the Stone of Inner Binding.  It is the strongest of the binding stones and must be unlocked for the others to open.'
WHERE `entry` = 651;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You place the rod in the keystone. And a shudder is felt beneath you...',
    `RequestItemsText` = 'The Keystone is charged with tremendous geomantic energy.'
WHERE `entry` = 652;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Lady told me of your coming, $C. You are welcome in my abode for you, like I, serve a higher cause.',
    `RequestItemsText` = ''
WHERE `entry` = 653;

UPDATE `quest_template` SET
    `OfferRewardText` = 'All right then, it will take me just a second to remove the power source. After that, you can do with it whatever you like now without having to worry about losing the data inside.',
    `RequestItemsText` = 'Well, did you get everything you needed? If you didn''t and the power runs out, everything inside will be ruined and you''ll have to start over.$B$BHey, don''t look to me for sympathy; I''m all about the Gadgetzan Water Company making a profit, and if that means selling you power sources until we can afford to import water in from the icy springs of Dun Morogh, so be it!'
WHERE `entry` = 654;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, Gor''mul you speak of. Yes, from what he says, it seems he has never recovered from the death of Doomhammer.$B$BGor''mul was a captive here when Thrall and Orgrim fought to free the camp, but as the earth shook and our brethren escaped, he was left behind. He wandered alone and lost for years without direction or hope, until we returned to establish ourselves here in Hammerfall.',
    `RequestItemsText` = ''
WHERE `entry` = 655;

UPDATE `quest_template` SET
    `OfferRewardText` = 'As the eldritch shackles are placed around the Shards, an unhuman wail is heard from far below. The scream is followed by a roar.$B$BThe Shards of Myzrael no longer invoke feelings of warmth and security as they once did. Now they pulse with an open menace... as if the thing beneath them holds ill will toward the surface.',
    `RequestItemsText` = 'The Shards of Myzrael are now strangely quiet.'
WHERE `entry` = 656;

UPDATE `quest_template` SET
    `OfferRewardText` = 'If it brings Phin peace, I''ll destroy every single one of the Forsaken personally. He''s done so much for us since the plague. We never thought we''d find friends or family again.$B$BWhen you''re prepared, come let me know. We''ll get started right away.',
    `RequestItemsText` = ''
WHERE `entry` = 657;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent!$B$BLet''s see what this is about...',
    `RequestItemsText` = 'We appreciate your help in looking for that courier, $N.$B$BWhile you were gone, Kin saw an apothecary come out of that same house to the south of here. I''m confident that they''re up to no good--I just need proof of it before we go off and do something rash.$B$BHave you had any luck yet?'
WHERE `entry` = 658;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Try and stay as quiet as possible, traveler.$B$BOrcs don''t take too well to being spied on, and there is more to this farm than meets the eye.',
    `RequestItemsText` = ''
WHERE `entry` = 659;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done a great service for us, $N. Thank you.$B$BI hope Kin wasn''t too much of a handful down there. She''s very friendly, but can be just as deadly when you''re her enemy.',
    `RequestItemsText` = 'Is Kinelory safe?'
WHERE `entry` = 660;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, the two troublemakers are all right after all? Haha, I''m glad to hear it. I thank you for bringing me news of their whereabouts and status--it pleases me greatly that they are still alive; the two of them are irreplaceable as friends and traveling companions.$B$BBut... it''s more important I thank you properly for your help. Here. Take this along with my group''s thanks.$B$BWith any luck, we''ll figure out what the Forsaken are up to, and put an end to it.',
    `RequestItemsText` = ''
WHERE `entry` = 661;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Knowing this information is secure will bring some ease to the command in Booty Bay. Well done, $N.',
    `RequestItemsText` = 'How goes the search and recovery mission, $N?  We really need to get those Logs and Charts back from the Maiden''s Folly and Spirit of Silverpine.$B$BIf the information from those sources were to fall into enemy hands, Fleet Master Seahorn would force us down the plank.$B$BThat is if we ever get out of this mess...'
WHERE `entry` = 662;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahoy, matey.$B$B''Twas a horrible mess. Seahorn will have my ship if he finds out what went down.$B$BOne of the Professor''s contraptions indicated the lost treasure was near this cove. I brought the Harbinger in to dock and signaled for the Spirit of Silverpine and Maiden''s Folly to follow suit.$B$BThen the sea rumbled. The tides lowered and the two ships crashed into the reef.$B$BIt''s not just a reef. Something''s down there....$B$BHelp my crew out and you''ll be rewarded handsomely.',
    `RequestItemsText` = ''
WHERE `entry` = 663;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Nice work out there, $N.$B$BThose scum deserved what they got. While nothin'' will ever bring me ship or me crew back, the death of those naga gives me some solace.',
    `RequestItemsText` = 'Bah, maybe I should go kill those naga scum myself. It''s obvious you''re not goin'' to do it.$B$BMaybe I can find some knitting needles so you can keep yourself busy.'
WHERE `entry` = 664;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The goggles work perfectly now! Well done, $N.',
    `RequestItemsText` = ''
WHERE `entry` = 665;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Most superb, $N! The Captain will be very pleased! And just wait until word gets back to Fleetmaster Seahorn!',
    `RequestItemsText` = 'How did the goggles work? Did everything function properly? Adjustments can be made if necessary.$B$BOh, and I''ll need those goggles back when you''re done. I am sure Captain O''Breen will have many uses for them later on.'
WHERE `entry` = 666;

UPDATE `quest_template` SET
    `OfferRewardText` = 'We survived the attack!$B$BWe could not have done it without you, $N.$B$BWe''ll be heading out as soon as the tide rises. If you weren''t such a promising hero I''d offer you a place on my crew. But I can tell you have bigger fish to fry.$B$BEven if you are a puny $R....',
    `RequestItemsText` = ''
WHERE `entry` = 667;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So the little gnomes proved their worth after all? I knew we kept those ankle biters around for a reason!',
    `RequestItemsText` = 'Ahoy, $C. What brings you to the bridge?'
WHERE `entry` = 668;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, leave it to good old Shakes O''Breen! I knew that he was the right Captain for the mission!',
    `RequestItemsText` = 'What brings you to Booty Bay, $C?'
WHERE `entry` = 669;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you for making such a long and perilous journey. You have the gratitude of the Blackwater Raiders.',
    `RequestItemsText` = 'So was Seahorn impressed? I bet you his smile reached from Booty Bay to Ratchet.'
WHERE `entry` = 670;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It will take some time for me to ascertain the true intentions of the Syndicate, but their obvious association with dark, demonic magic troubles me. I will tell you when I know more.',
    `RequestItemsText` = 'Once-cursed blood still runs through my veins, $N. If someone... something is summoning demons, it must be stopped.'
WHERE `entry` = 671;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent. The spirits of the raptors that gave these eyes will lend strength to the bearer of this amulet.',
    `RequestItemsText` = 'I will create an amulet that will give Gor''mul some of the strength of the raptors. Perhaps that will awaken some flame within him...'
WHERE `entry` = 672;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My restless nights will turn to peaceful slumber when I have destroyed this orb. Thank you, $N. It is a chilling reminder of the terrible power the demons held over the orcs before Hellscream released them from their curse.',
    `RequestItemsText` = 'The burning in my blood... it grows by the day. The warlock must be stopped.'
WHERE `entry` = 673;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What is this? Polished bone. What use have I for polished bone? Will a trinket restore the Horde to its glory?',
    `RequestItemsText` = 'What hope is there when the hand of a coward can slay the mightiest of the mightiest? What hope, I ask you!'
WHERE `entry` = 674;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It did not work, I see. Nonetheless, I feel that showing him the power of the shamans will eventually return Gor''mul to his once proud self. The amulet''s power was not great enough to show him our newfound power.',
    `RequestItemsText` = ''
WHERE `entry` = 675;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, you think you''re strong enough to help Hammerfall? So be it.$B$BTallow either sent you to that ogre mound in the hopes that you would kill yourself or he thinks you''re strong enough to aid us. Either way, you''re here now and I am in need of more soldiers in our fight against the constant attacks.$B$BIf you plan on staying in Hammerfall then get some rest, and come speak to me again when you''re ready. There''s no shortage of fighting to be had.',
    `RequestItemsText` = 'I have not the time to sharpen my axe, let alone leave the outpost to slay those beasts that would try and slay my kin.$B$BYou do not seem to have the experience of a grunt let alone a full-fledged $C, what do you want, $N?'
WHERE `entry` = 676;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The signs of war are upon your garments, and sweat drips from your brow. Good, very good indeed.',
    `RequestItemsText` = 'If you have not yet completed my task, then perhaps you are a coward in heart as well as a tyro in war.'
WHERE `entry` = 677;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You are as strong as a kodo, and your lust for battle does your people proud.',
    `RequestItemsText` = 'You hesitate. Why? You have shown great strength thus far, $N. Do not fail me now.'
WHERE `entry` = 678;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You do your people proud, $N. The threat has been greatly lessened, and I am sure we will begin to thrive here in the Highlands.',
    `RequestItemsText` = 'I see your courage finally wanes. It seems my instincts were correct about you: your strength is nothing compared to your bravado.$B$BReturn to me when the beast''s head has been severed, or return never again.'
WHERE `entry` = 679;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done me a great service, $N. Know that my husband''s life and the safety of Hammerfall has been protected for another day because of your deeds. Please take this as a reward for your courage.',
    `RequestItemsText` = 'Near the Tower of Arathor--that is where you will find Or''Kalar. His death will stop the attacks on Hammerfall and protect my husband''s life.$B$BI see in your eyes that you think me weak--even dishonorable--for my silence. Some day you will learn what it is to love as I do. Perhaps then you will understand a different kind of strength and honor.$B$BIn the meantime, do as I ask, and slay Or''Kalar.'
WHERE `entry` = 680;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good, $N. With the deaths of those Syndicate members we should have an easier time receiving supplies from Southshore.$B$BPerhaps our cause yet has hope.',
    `RequestItemsText` = '$N, with each passing hour our hold on Stromgarde grows more tenuous. You must make haste or our city will surely fall.'
WHERE `entry` = 681;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. We will inform the families of these fallen soldiers that they were killed in battle.$B$BIt will be grim news to bear, but it is better than the uncertainty of a missing loved one.',
    `RequestItemsText` = 'Have you retrieved any Stromgarde Badges, $N? The Syndicate must learn they cannot profit from our dead.'
WHERE `entry` = 682;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It will take but a moment for me to peruse this letter...',
    `RequestItemsText` = 'So you are $N the $C? News of your contributions to the Alliance has traveled quite far, you know?$B$BOn what business do you come before me today?'
WHERE `entry` = 683;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You took down Marez Cowl? Well done, $N. Well done indeed!$B$BMarez menaced our Stromgarde defenders, and it is rumored she was an emissary between the Syndicate and some other, darker power. We are glad to see she''ll longer ply her powers against us.',
    `RequestItemsText` = 'Greetings, $C. You have a report to make?'
WHERE `entry` = 684;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Falconcrest and Otto? Wonderful!$B$BHere is your reward, $N. I am happy to pay it.',
    `RequestItemsText` = 'Hello. Do you have a report to submit?'
WHERE `entry` = 685;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So King Magni Bronzebeard himself sent ye?$B$BMy, my! This must be important!',
    `RequestItemsText` = ''
WHERE `entry` = 686;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hello. Hello, hello hello hello hello HELLO!$B$BI''m sorry - wait, no I''m not! Don''t be rude!$B$BOh no...that was crazy talk.$B$BBut...sometimes being crazy is my only solace.',
    `RequestItemsText` = ''
WHERE `entry` = 687;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Welcome, $C. The Lady has informed me of your coming, and if we are to bring her back to the surface then we have much to discuss...',
    `RequestItemsText` = ''
WHERE `entry` = 688;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Perfect! Better than I could have imagined!$B$BAnd I have quite an imagination you know...',
    `RequestItemsText` = '$N, $N, $N! Tell me you have enough Alterac Granite for me to begin my masterpiece in honor of Sully Balloo.'
WHERE `entry` = 689;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, Malin sent ye? I don''t care if Muradin rose up from the dead and whisked ye here on a dragon. I''m busy! Talk to Kryten if you need somethin''.',
    `RequestItemsText` = ''
WHERE `entry` = 690;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Incredible! I can see why Malin asked you to come join us - very well done indeed!$B$BAt this rate, Skuerto and I will be headed back to Stormwind in no time at all.$B$BI believe my dwarven companion is back from scouting Boulderfist Hall; go speak to him when you''re ready.$B$BIt looked as though he might have had a bit of a scuffle with the ogres. Don''t mention that to him, though; he''s very sensitive about criticisms to his skills at scouting.',
    `RequestItemsText` = 'Have you had any luck so far, $N?$B$B<Kryten makes some notes in his journal as he reads.>$B$BIf my research is correct, the tusks should come from any Witherbark troll. The medicine pouches come from the Witherbark witch doctors, and the strongest of the Witherbark shadow hunters should carry the special knife given to them after they''ve completed their rites of passage. There''s no way to tell which shadow hunters will have the knife until you do battle.'
WHERE `entry` = 691;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, you found them! Good work, $N! These might be the only chance we have against the evil of Myzrael!$B$BJust let me find my scrap-ratchet and see if I can re-attach these fragments...',
    `RequestItemsText` = 'Did you find those fragments?!?! You''ll need the Scroll of Myzrael if you want to trap her again, before it''s too late!'
WHERE `entry` = 692;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Brilliant, $N. One item down an'' three more to go, based on my list. The other three items are all in Stromgarde.$B$BTake a rest an'' get your strength back--the next phase of my plan''ll require a little more time an'' effort. Come back to me after you''ve gotten a warm meal an'' some rest.',
    `RequestItemsText` = 'Our goal is the wand, $N. Focus on that for now.'
WHERE `entry` = 693;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You amaze me, $N. Well done again.$B$BGive me a moment to cast the proper spell to enchant the gem, an'' you''ll be ready.',
    `RequestItemsText` = '$N, hello again. Have you found an azure agate yet?'
WHERE `entry` = 694;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good, good.$B$BIf there are no other delays, how about we get started?',
    `RequestItemsText` = ''
WHERE `entry` = 695;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Malin couldn''t''ve asked a worthier person to come here an'' aid us, $N. You''ve done a grand job!$B$BHe''ll be pleased to see what an overwhelming success our mission''s been.',
    `RequestItemsText` = 'You do this, an'' I''m sure Malin''ll be more than pleased with you.'
WHERE `entry` = 696;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Archmage Malin opens the letter, and his eyes grow wide.>$B$BBy the Light, you''ve done it. How wonderful. Trelane will be so pleased. I''m sure Kryten and Skuerto are just as excited as I am to have them on their way back to Stormwind.$B$BThank you, $N. Please, take this to help you in your journeys.',
    `RequestItemsText` = 'Yes? You look vaguely familiar. I do apologize, but have we met? I get so busy I lose track.'
WHERE `entry` = 697;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah! Wonderful. Fresh meat for the fire tonight. Thank you, $N.$B$BYou''ve helped make the coming nights more tolerable. The fire burns bright, and our stomachs will be full.$B$BIts a pleasant surprise to have you bring us a shipment; Dar''s not the most attractive orc anyone''s laid eyes upon, but at least his attitude reeks far less than his smell.',
    `RequestItemsText` = 'Lok''tar, $C. Traveling through the swamps isn''t a risk taken lightly. You''re brave to test your mettle here.'
WHERE `entry` = 698;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Glad to see you''re alive and well, $N.$B$BThese claws should make do nicely. The more weapons we have at the ready for attacks against us, the better off we''ll be.$B$BI''ll get started on your weapon as soon as possible. It will only take a short time. I''ve become quite adept and quick at their production.',
    `RequestItemsText` = 'Good mead, a warm fire, an army of orcs and an arsenal of weapons... that''s all we really need out here along the coast. I don''t regret my position out here safeguarding Stonard, but it would be nice if we could one day get a burrow, or at least a tower.'
WHERE `entry` = 699;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The granite seems but a small token compared to a great dwarf''s life. But no dwarf shall last on this planet for eternity.$B$BLet us just hope that the memorial stands as a reminder to those who will trod the great Azeroth of the future. Lest we not forget it is for them that brave soldiers such as Sully Balloo so valiantly gave their lives.',
    `RequestItemsText` = ''
WHERE `entry` = 700;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, these will work perfectly. I will transfer their power and the spirit of the raptors into this orb. This orb will imbue Gor''mul with the fiery strength and intelligence of the raptor.',
    `RequestItemsText` = 'My preparations are made, all I require are the raptor hearts.'
WHERE `entry` = 701;

UPDATE `quest_template` SET
    `OfferRewardText` = 'At least it is something interesting you bring to me this time. A strange power it emits...',
    `RequestItemsText` = 'Returned again have you? Indeed there is nothing more I could wish for now than more of Tor''gan''s pity.$B$BWhat have you for me this time? Perhaps a piece of brightly colored string? Or a length of rope to end this misery of mine...'
WHERE `entry` = 702;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, I''ll get started on those wings right away. I can almost taste them already!$B$BAnd here''s the recipe in case you want to make them yourself!',
    `RequestItemsText` = 'Hello, $N. Did you bring me my wings?'
WHERE `entry` = 703;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done! With luck and diligence, we will find whatever link exists between the troggs and these ancient artifacts.$B$BYou have done a great deed for the Prospectors, $N. Your efforts will not be forgotten. And neither will Agmond.',
    `RequestItemsText` = 'Did you find those urns, $N? We must find the link between them and the troggs!'
WHERE `entry` = 704;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These will work great! I just need to smash them into powder...then mix them with a little of this and a little of that.$B$BWatch out, scavengers! Prepare to be flashed!',
    `RequestItemsText` = 'Did you get my pearls?  I''m almost out of flash bombs!'
WHERE `entry` = 705;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah yes, this will do excellently. This will enable your weapons to strike with searing heat!',
    `RequestItemsText` = 'How goes the hunt, $C?'
WHERE `entry` = 706;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So Stormpike sent you, did he? Good.$B$BI have a big task for you...',
    `RequestItemsText` = ''
WHERE `entry` = 707;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Och, where''d ye say ye found it?$B$BThe pilot of this plane has been missing for weeks, always knew but still held hope.$B$BI will hammer this into our walls along with his name. Thank ye, $N.',
    `RequestItemsText` = 'What is it, $N?'
WHERE `entry` = 708;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, fortune is with us! Thank you! We may yet be saved!',
    `RequestItemsText` = 'Did you find the tablet? It must hold secrets! Secrets to save us!'
WHERE `entry` = 709;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These shall do nicely, $N. Thank you. Hmm, a bit more sand than I''d anticipated. Have to adjust the coefficient of friction. No, wait; it should still be negligible with the frost oil.$B$B<Mumbling to himself, Lotwil puts one fist into the palm of his other hand and stares at them as if fascinated.>',
    `RequestItemsText` = 'This area''s perfect for-- Could you hold these in place for a moment? Yes, just like that, along the vector normal. Now, what was I... Right. Perfect for testing my latest project. The raw materials, the open space... what more could an intelligent and enlightened practitioner of the arts ask for?'
WHERE `entry` = 710;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N, simply amazing! I would have thought it''d take half a dozen tauren to bring all these to me.',
    `RequestItemsText` = 'I''m most pleased, $N. My spells affected the smaller pieces just as I predicted. If this experiment is as successful as I foresee, then the elementals I''ll be able to control will put anything summoned prior to this to shame.'
WHERE `entry` = 711;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N, have you ever considered becoming a research assistant? No? I''m not sure what I''ll do without your abilities here. Intelligence, curiosity, and strength--all combined into one package.',
    `RequestItemsText` = 'The stone slabs you found were ideal, $N. Lucien will be taking the extra ones back to Kharanos when we''re done here. After all, they could prove useful again.$B$BFor instance, they''d be a nice basis for a handy little shelter once I start looking into a multidisciplinary approach to high-yield explosives...'
WHERE `entry` = 712;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Stupendous! This should be the perfect coolant for my new bracers. If the enchantments don''t last a century, then I''ll give all my belongings to Servo.$B$BAll the mages of the Assembly will be in such awe after I finish this, $N. You just wait and see.',
    `RequestItemsText` = 'Have you found the oil I need? It would be so helpful if you were able to find some.'
WHERE `entry` = 713;

UPDATE `quest_template` SET
    `OfferRewardText` = 'HA!$B$B<Lotwil grabs the gyrochronatom from you.>$B$BPerfect... just about done. No, really. I AM almost done now. This project is my top priority... at the moment. Let me pop this into place, and you can see for yourself what you''ve helped me create. It''ll just take me a few more minutes... maybe... possibly longer. Well, maybe a lot longer. We''ll see...',
    `RequestItemsText` = 'Yes, yes, yes. Just a moment.'
WHERE `entry` = 714;

UPDATE `quest_template` SET
    `OfferRewardText` = 'YES!$B$BI mean, thank you, $N. These will be helpful while traveling through the Badlands.',
    `RequestItemsText` = 'He''s getting closer to finishing. How are things going on your end?'
WHERE `entry` = 715;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here you go, $N. Try these on.',
    `RequestItemsText` = 'I wouldn''t wait too long to get that bracer, $N.$B$BWho knows what''s going to happen next?'
WHERE `entry` = 716;

UPDATE `quest_template` SET
    `OfferRewardText` = 'No longer will the Kirin Tor need to worry over the prisoners of Lethlor. I will return to report success to my master. Krasus will no doubt be pleased.',
    `RequestItemsText` = 'Strong magics and powers held the drakes'' prison for so long, but we cannot allow any possibility that Blacklash and Hematus may be released.'
WHERE `entry` = 717;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thanks so much, $N. While you were gone, I... er... swallowed a mouthful of sand. It...$B$BWell, enough of that, we''ll go out and get some food tonight. Eat like kings!',
    `RequestItemsText` = 'The desert''s a bad place to be hungry, my friend, let me tell you that.$B$BHey... what''s that over there...'
WHERE `entry` = 718;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ye''re me savior, $C. I''m glad someone could teach those Shadowforge a lesson or two. Thanks for yer help.',
    `RequestItemsText` = 'Not sure what the Shadowforge were lookin'' for, but they definitely had a purpose.'
WHERE `entry` = 719;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hammertoe''s alive?! This is amazin'', $N!',
    `RequestItemsText` = ''
WHERE `entry` = 720;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes? Ah''m sorry... <cough> Feel so weak. Can ye come closer, $C?$B$BRyedol sent ye? Muradin be praised, that boy''s not as slow in the head as I once thought. <cough>',
    `RequestItemsText` = ''
WHERE `entry` = 721;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ha! <cough cough>$B$BAh knew you''d find me amulet, $N.$B$B<weeze> Well done indeed, $N. <cough>',
    `RequestItemsText` = 'The Shadowforge clan... is dangerous. Be careful. You must find the amulet.'
WHERE `entry` = 722;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hammertoe''s amulet? I think my spirits were higher when I thought he was dead. Knowin'' fer sure only makes the pain worse. This amulet was his life''s work. I can''t let his death be in vain.',
    `RequestItemsText` = 'I''d say it was a bad day, but this is the Badlands: every day''s a bad day.'
WHERE `entry` = 723;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh! Well, this is a different matter entirely. You probably don''t realize the gravity of this matter yet, do you?$B$BI care deeply about Hammertoe''s demise, but if he sent you here with his amulet, then he understood what''s at stake.$B$BWe will have to take time to mourn his death later.$B$BLet me show you one of the reasons this amulet is so valuable.',
    `RequestItemsText` = 'Ah, yes. Another traveler seeking something from the dwarves.$B$BSir, I''m truly sorry, but I''ve no time to answer meaningless questions right now.'
WHERE `entry` = 724;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, word from Historian Karnik. Excellent.$B$BI always have time for his business.$B$B<Advisor Belgrum opens the note and begins to read.>',
    `RequestItemsText` = 'Hmm? Yes, $C.'
WHERE `entry` = 725;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''re treating this matter with an urgency I''d expect from the king himself, $N.$B$BAll right, then. I know what''ll bring the Shadowforge down.$B$BTheir presence in Uldaman can be slowed if we strike them at their base of operations: Angor Fortress.',
    `RequestItemsText` = ''
WHERE `entry` = 726;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh. Greetings, brother.$B$BAnd praise to the dwellers beneath.',
    `RequestItemsText` = 'Hello. Welcome to my shop, but watch what you touch.$B$BKnowledge can be deadly.'
WHERE `entry` = 727;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Be discrete with your signs, $C. There are those who do not believe the righteousness of our pledge.$B$BAnd there are those who would see us fail if they knew of us.$B$BWe must always be careful. And watchful. And patient.',
    `RequestItemsText` = 'Ah, we have an eager $C, I see. Are you here to learn from my collection? Good!$B$BBut be warned: just as knowledge gives power to the strong...it will drive the weak mad.'
WHERE `entry` = 728;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hollee. is that you? I need some help chiseling this stone. Hand me my stone brush, I think I see something.$B$BHey, you''re not Hollee! Don''t suppose you''ve seen my stone brush?$B$BNever mind that now! I promised the League I''d send the mysterious fossil I found. Where did Hollee go?$B$BSo much work to be done! Now where is that mysterious fossil... and my brush... and Hollee...$B$BAnd who are you... ''tis no matter, so long as you''re here to help.$B$BLet me know when you''re ready to start looking.',
    `RequestItemsText` = ''
WHERE `entry` = 729;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I''m so glad Chief Archeologist Greywhisker sent for us....',
    `RequestItemsText` = ''
WHERE `entry` = 730;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank the stars Prospector Remtravel is safe! I told you he was absent minded. I can''t believe he insisted on staying there with all of those horrible creatures lurking about.',
    `RequestItemsText` = 'Is the prospector alive?'
WHERE `entry` = 731;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good tidings you bring bearing the Sign, $N. The Sign of the Earth was created by the Dark Iron dwarves of Angor Fortress to bind two of Deathwing''s ruthless lieutenants, the twins Blacklash and Hematus.',
    `RequestItemsText` = 'The nomadic band of ogres travels between their camps across the Badlands; heat rising from the dry earth and the swirling winds will make it difficult to track their progress. I have heard that sometimes they travel through Camp Boff. If you are lost, you might try your search there.'
WHERE `entry` = 732;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It''s a start, $N, and it''ll have to do until we hear word from Ironforge or the Explorers'' League.$B$BNow, if only I could find some salt somewhere for my quenching barrel...',
    `RequestItemsText` = 'Well, I''ve made do with what I could, but... it''s not much. Have you found any more supplies?'
WHERE `entry` = 733;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Cog #5, huh? Yeah, this isn''t going to be good.',
    `RequestItemsText` = ''
WHERE `entry` = 734;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You are resourceful, $C. If it truly is your charge to begin a new chapter of our order, then I believe you will run it well.',
    `RequestItemsText` = 'Do you have the relics for which I asked?'
WHERE `entry` = 735;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I am impressed! You possess great skill, or great fortune, to have gained these relics. Either way, you are an asset to us.',
    `RequestItemsText` = 'How goes your mission, $C.'
WHERE `entry` = 736;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You got it! Oh, hope glimmers!$B$BYour efforts may yet save us, $N. A monument they should make of you! A shrine they should build! May your name be praised until your grandchildren have grandchildren!$B$BUnless...THEY are freed and rise to the surface.  If that happens then you can forget about children.$B$BIf THEY are freed, then we''re all worm food.',
    `RequestItemsText` = 'Ho! You were gone a long time. Did you get the digest?'
WHERE `entry` = 737;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This skeleton must be the unfortunate remains of Agmond. His body is broken and battered, and his bones picked clean.',
    `RequestItemsText` = ''
WHERE `entry` = 738;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is sobering news, $N. But Agmond had a strong arm and a fierce hammer-swing, and his skull was as thick as they come! Although he was killed by those cursed troggs I''m sure he took a lot of them down with him.',
    `RequestItemsText` = 'Do you have news of Agmond''s fate? Did you find him?'
WHERE `entry` = 739;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh my! Leave it to Prospector Remtravel to discover such a find!',
    `RequestItemsText` = 'What can I do for you, $R?'
WHERE `entry` = 741;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Welcome to the new frontier, $N.  Ashenvale is a land of opportunity, one where a young $C like yourself is able to find boundless chances to prove their mettle.  Look around the outpost here, and be sure to travel out to the Zoram Strand, as the Horde has another outpost there as well.$B$BYour presence here tells me that you''ve come to learn more about the hunt.  Listen close, and I will gladly share with you what you need to know.',
    `RequestItemsText` = ''
WHERE `entry` = 742;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, $N. You seem well prepared to travel onward. Let the wind always be at your back.',
    `RequestItemsText` = 'The Windfuries are deadly foes. Their strength in battle is only rivaled by their desire for fresh meat.'
WHERE `entry` = 743;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you for your help, $N.$B$BMy part in my brother''s ceremony is almost complete. Giving him his headdress and witnessing the ceremony are all my duty requires of me.',
    `RequestItemsText` = 'This headdress will certainly be a wonderful gift for my brother.'
WHERE `entry` = 744;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N, it is good you''ve taken my task seriously. Respect of the land and its creatures is important. Death and life are a circle... a necessity. One cannot exist without the other. Take time to ponder this and do well to never forget it.',
    `RequestItemsText` = 'If the Palemanes had respected the land and its inhabitants more, this conflict would have never occurred.'
WHERE `entry` = 745;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N.  This will calm the beasts of Mulgore.  And, spirits willing, it will teach the dwarves that hollowing the land is not the path to knowledge.',
    `RequestItemsText` = 'Hello, $N.  Do you have the Broken Tools?  The dwarves'' digging will enrage the kodos of Mulgore.  This defilement must be stopped!'
WHERE `entry` = 746;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The tauren of Narache thank you, $N. You show much promise.',
    `RequestItemsText` = 'Providing meat and feathers for the tribe is the first step in proving yourself as a hunter before the Chief.'
WHERE `entry` = 747;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, $N.  I will take these and bind their power into a totem of cleansing.',
    `RequestItemsText` = 'Do you have the paws and talons, $N?'
WHERE `entry` = 748;

UPDATE `quest_template` SET
    `OfferRewardText` = 'All sides of the crate are stamped with the sign of the Venture Co. Mining Division. Notes printed carefully on the side of the carton indicate that the contents are due for processing at one of their central plants.',
    `RequestItemsText` = ''
WHERE `entry` = 749;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The tauren of Narache thank you for these provisions, $N. With your skill in the ways of the hunt you will surely be revered in Thunder Bluff someday.',
    `RequestItemsText` = 'If you can provide pelts for the tribe I will pass word along to my father, Chief Hawkwind, of your generous deeds.'
WHERE `entry` = 750;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It does indeed appear that the Venture Co. is attempting to rob us of our natural resources. It is good to know this for true, and now it seems, we must do something about it.',
    `RequestItemsText` = 'Hail, $N. Have you learned anything new about the Venture Co.''s plans and operations in our homeland?$B$BIf they plan to exploit our lands as they have others, the Outrunners will be quick to put an end to it.'
WHERE `entry` = 751;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You traveled all this way just to help an old woman? My my, aren''t you a keeper?',
    `RequestItemsText` = ''
WHERE `entry` = 752;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You carried this pitcher back at the Greatmother''s bidding, I see.$B$BYour willingness to help others and provide for the tauren of Camp Narache leads me to believe you would make the tribe proud in Thunder Bluff someday.',
    `RequestItemsText` = 'You look as though you have returned from the plains. Do you have any word from Greatmother Hawkwind?'
WHERE `entry` = 753;

UPDATE `quest_template` SET
    `OfferRewardText` = 'News of your deed reached me moments ago -- already the beasts near the well drink from it eagerly.$B$BYou have done a great thing for the land, $N.  And you have done a great thing for the Tauren people.',
    `RequestItemsText` = ''
WHERE `entry` = 754;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Chief Hawkwind sent you? Embarking on the Rites of the Earthmother is no small task...',
    `RequestItemsText` = ''
WHERE `entry` = 755;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N.  The purity with which these beasts hunt is vital in the creation of the next cleansing totem.$B$BThe goblins will never learn the difference between contending with the land, and living in harmony with it.',
    `RequestItemsText` = '$N, do you have the claws I sent you to gather?  The Thunderhorn Water Well grows more tainted with each passing hour!'
WHERE `entry` = 756;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have passed the first test of the Rites of the Earthmother. The tribe will be proud.',
    `RequestItemsText` = 'Have you completed the Rite of Strength, $N? I require proof of your valor against the enemy of our tribe, the Bristlebacks.'
WHERE `entry` = 757;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ancestors of the Thunderhorn clan spoke to me in a dream, praising you for your actions near their well.$B$BFor their gratitude, they wish to give you this...',
    `RequestItemsText` = 'The Thunderhorn Water Well is still tainted, $N.  Please, you must perform the ritual!'
WHERE `entry` = 758;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good, $N.  I can feel the sacrifice of the land in this offering, and my spirit swells with sadness, and pride.',
    `RequestItemsText` = '$N.  Do you have the teeth I asked for?'
WHERE `entry` = 759;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done it.  You have cleaned the wells, and healed our land.  Bloodhoof village is grateful, $N.$B$BMay the wind whisper your deeds for a hundred seasons, and may the waters of Mulgore remain clean forever.',
    `RequestItemsText` = 'The last water well remains fetid and poisonous, $N.  You must not delay!'
WHERE `entry` = 760;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I know that gathering these quills was not an easy task, $N.  In doing this, you prove that you are a $C of merit.  It is good to have you at Bloodhoof Village.',
    `RequestItemsText` = 'Have you found the swoops, $N.  Do you have their quills?'
WHERE `entry` = 761;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N, your dedication to Ironforge and to the dwarven people cannot be refuted. I thank you for your help in this matter.$B$BI shall send word to Historian Karnik informing him that you have succeeded, and I shall also have aid sent to the Badlands as soon as possible to help recover the excavation site. Thank you again.$B$BBefore you go, there is one more thing I would ask of you in the name of King Bronzebeard.',
    `RequestItemsText` = 'Time is of the essence, $N. Ragnaros will not wait for us to prepare.'
WHERE `entry` = 762;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Word from my good friend, Chief Hawkwind! Ah, I can see by his carvings you are of a special breed.',
    `RequestItemsText` = 'What brings you to my village, $C?'
WHERE `entry` = 763;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I don''t think there could be too much misinterpreting or ignoring of that signal, hm? The Venture Co. will know not to take the tauren lightly, or to be so arrogant as to believe we would allow them to steal the natural resources around us without protest.',
    `RequestItemsText` = 'The Venture Co. was refused mining rights here in Mulgore, but it would seem that they do not take no for an answer. We tauren are not ones to mince words, however, and we have other ways of getting our message across.'
WHERE `entry` = 764;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My anger is somewhat lessened at the news that the villain Fizsprocket is dead. I will go through his personal effects and see if there is any additional information about what the Venture Co. has planned for the future. Thank you for your efforts, $N.',
    `RequestItemsText` = 'I seethe with anger at the thought of the atrocities the Venture Co. is willing to perpetrate against us in the name of profit.'
WHERE `entry` = 765;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, thank you, $N. Using the items you brought me, I will be able to create the remedy I need to stop the spread of the infection and, eventually, cure it completely. I owe you my life in thanks.$B$BBut I''ll never forget that screeching call when Mazzranache came upon me, the blaze of color as its beak descended...$B$BBe wary on your travels.',
    `RequestItemsText` = 'My fever grows worse and I find my mind drifting into delirious nightmares... I should have known that I wouldn''t be able to handle a beast my grandfather was unable to defeat...$B$BDo you have the ingredients for the remedy? I fear if I do not clean the infection soon, it will be the death of me.'
WHERE `entry` = 766;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I sensed you would be coming to me, $C. I can always recognize one who is trying to pass the Rites of the Earthmother.',
    `RequestItemsText` = ''
WHERE `entry` = 767;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, these are very nice pieces. They''ll make fine leather goods.$B$BHere, $N. Take this in trade...',
    `RequestItemsText` = 'Hello again. Have you been hunting? Do you have skins for me?'
WHERE `entry` = 768;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, good. Thank you, $N. My heart swells with pride to see youths interested in the craft of leatherworking.',
    `RequestItemsText` = 'Do you have my supplies, $N?'
WHERE `entry` = 769;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I can barely believe my old eyes! You defeated the great wolf Ghost Howl? I look upon you with new respect, young $C. You are a $C of extreme skills!$B$BLet me offer you something. My days of hunting are over, but I would be honored if you used one of my weapons in your hunts.$B$BMay it strike true, and bring you renown.$B$BAnd let us hope that Ghost Howl''s spirit has finally found peace.',
    `RequestItemsText` = ''
WHERE `entry` = 770;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I see you have learned to gather from our sacred land, $N. It will take but a moment for me to brew the Water of the Seers.',
    `RequestItemsText` = 'Once you have gathered enough well stones from around the water wells and Ambercorn from beneath the trees, I will prepare the Water of the Seers for you.'
WHERE `entry` = 771;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Be not afraid, $N. You have successfully passed the Rite of Vision.',
    `RequestItemsText` = ''
WHERE `entry` = 772;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have shown great diligence in your yearning to pass the Rites of the Earthmother, $N.$B$BWe, the Ancestral Spirits, represent the mighty tauren who gave their lives bravely to found and protect our great city of Thunder Bluff. I hereby pass the duty of that protection over to you.$B$BYou have passed the Rite of Wisdom, young $C. Enter Thunder Bluff with pride.',
    `RequestItemsText` = ''
WHERE `entry` = 773;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hail, young $C. I see you found your way to my doorstep.',
    `RequestItemsText` = ''
WHERE `entry` = 775;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done! A fine kill that was.$B$BI will send a gathering party to collect the carcass so we can retrieve the hide and meat.$B$BYou have done a great deed for your people, $N.',
    `RequestItemsText` = 'Have you tracked down Arra''chea yet?'
WHERE `entry` = 776;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, perfect. Stand back while I prepare to make more history!$B$B<Lotwil continues to work feverishly.>',
    `RequestItemsText` = '<Without looking up from the shackles, Lotwil holds out a hand and waggles his fingers impatiently.>$B$BThe cog, $N, the cog!'
WHERE `entry` = 777;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. That was quite an ordeal, wasn''t it?$B$BI''m not sure what could have gone wrong. It was a good thing my magics were here to help send the creature back to its home plane.$B$BPerhaps a little token of appreciation for all your hard work...',
    `RequestItemsText` = 'Not quite the outcome I was expecting. Could you get my shackles back?'
WHERE `entry` = 778;

UPDATE `quest_template` SET
    `OfferRewardText` = 'As you place the Runestones into the matching recesses, a violent rumbling shakes the earth as the Seal is broken.',
    `RequestItemsText` = 'The Seal of the Earth lies here, with three recessed alcoves for the Amethyst Runestone, the Opal Runestone, and the Diamond Runestone.'
WHERE `entry` = 779;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Most excellent. These ingredients will make a fine stew and the loss of those boars should be a fair lesson to those vile Bristlebacks.',
    `RequestItemsText` = 'The aggression of the Battleboars is increasing. Have you sent them a clear message and brought back some snouts and flanks yet?'
WHERE `entry` = 780;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is quite alarming indeed! But with this information we can call on our brethren from Bloodhoof Village to help thwart the attack. You have saved the lives of many tauren, $N.',
    `RequestItemsText` = 'You have a look of concern about you, $N. What news do you bring?'
WHERE `entry` = 781;

UPDATE `quest_template` SET
    `OfferRewardText` = 'With Tho''grun dead, his corpse picked clean by the desert winds and scavenging buzzards, the ogres will be put into disarray. Though a small victory, this will lead to a much larger one$B$BThe Sign of the Earth is now in our possession, and we can open the black drakes'' prison in Lethlor.  We shall free them from endless imprisonment, albeit to their doom!',
    `RequestItemsText` = 'Tho''grun''s betrayal... is there any wonder why the ogres are part of the Horde no longer? I will be glad to see him dead, and the Sign of the Earth returned.$B$BIf you''ve not dispatched him yet, then waste no time going to Camp Boff.  It is to the southeast of Kargath.'
WHERE `entry` = 782;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, good.  Another volunteer.  We''re getting a lot of you these days.$B$BI hope it''s enough.$B$BThe human lands are threatened from without, and so many of our forces have been marshaled abroad.  This, in turn, leaves room for corrupt and lawless groups to thrive within our borders.$B$BIt is a many-fronted battle we wage, $N.  Gird yourself for a long campaign.',
    `RequestItemsText` = ''
WHERE `entry` = 783;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Word of your bravery travels fast, $C. Tales of your victory at Tiragarde Keep will be heralded in Orgrimmar.',
    `RequestItemsText` = 'You have your orders, $N. The safety of Durotar is in question. Complete the task before you or hang your head in shame.$B$BShow your honor and defeat the humans of Tiragarde Keep.'
WHERE `entry` = 784;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Horde would surely prevail if the Kolkar centaurs were to attack.$B$BBut by preventing such an attack, we have spared our mighty warriors unnecessary bloodshed.$B$BAnd as sure as there is sand in the Tanaris desert, we know that there will be blood spilled before these trying times are through.$B$BYou have served your people well, $C.',
    `RequestItemsText` = 'The centaurs have proven to be a consistent nuisance to the Horde. Their intentions to lay siege to our homeland cannot be tolerated.'
WHERE `entry` = 786;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Another one of Eitrigg''s recruits, hm?$B$BA sorry state of affairs we find ourselves in if this is the best the Horde can produce. No matter. By the time we think you''re ready to leave the Valley, you''ll be a proud warrior of the Horde.',
    `RequestItemsText` = ''
WHERE `entry` = 787;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmmm, not bad, $N. But don''t let it get to your head...you''ll fight tougher than boars in your career.$B$BNonetheless, you''ve proven yourself well, and your next trial will be against a considerably more dangerous opponent, so you''ll need some extra protection.',
    `RequestItemsText` = 'I hope you haven''t returned to try and convince me that you have completed your task, $N? No, of course not. I would think better of you.'
WHERE `entry` = 788;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There is an important lesson that you must take away from fighting scorpids. The smallest or largest of opponents can still send you to your doom. In fierce combat, any number of things can prove your downfall.$B$BI have no more to teach you, $N. You have done well, and I will watch your progress with interest.',
    `RequestItemsText` = 'The carapace of a scorpid isn''t so thick that the strength of a determined $C will be deterred. Strike strongly and without doubt, and the scorpids should prove easy prey.'
WHERE `entry` = 789;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My blow was not enough to kill him, but looking at the damage I inflicted gives me some small measure of pride. That small measure will be all I have to sustain myself if I die, and in that light, the short list of my life''s accomplishments fills me with anger.',
    `RequestItemsText` = 'Ahhh... my father always said I would never amount to much, and here, lying beneath a tree as life seeps away, I''m afraid it looks like he was right.$B$BAt least I wish to die knowing that my last enemy in life lays dead.'
WHERE `entry` = 790;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Most excellent, $N. Any good $C will surely find a use for this bag on the battlefield.$B$BI salute your vigor and willingness to die in the name of the Horde!',
    `RequestItemsText` = 'I fought proudly alongside the Warchief when these lands were pioneered. The scars of battle mark my skin.$B$BThe honor of the Horde has been upheld with the help of my axe and battlecry during the defeat of Archimonde, when the unholy alliance was made with the humans and elves, wrought from necessity.$B$BBut my position as watchman and provider has given me a new sense of worth.'
WHERE `entry` = 791;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, $N.$B$BAlthough the Vile Familiars were merely pets of the darker powers within the Burning Blade, your success against them foretells greater deeds ahead.',
    `RequestItemsText` = 'To prove yourself against the Burning Blade, you must first defeat its Vile Familiars. Return to me when you have done this.'
WHERE `entry` = 792;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The black dragonflight continues to ally with the renegade Blackrock orcs, and both must be brought into line, or removed. With Blacklash and Hematus dead, we can turn our attentions westwards, towards Blackrock Spire.',
    `RequestItemsText` = 'There are few enemies more deadly than dragonkind, and there were few dragons that fought as ferociously as Blacklash and Hematus.'
WHERE `entry` = 793;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You retrieved it! Well done!$B$BYour efforts within the Burning Blade Coven are key in rooting out this cult in the Valley of Trials. But I fear they have further aims in our land.$B$BWe have not seen the end of them.',
    `RequestItemsText` = 'Is your task complete, $N? Do you have the Burning Blade Medallion?'
WHERE `entry` = 794;

UPDATE `quest_template` SET
    `OfferRewardText` = 'As you place the Runestones into the matching recesses, a violent rumbling shakes the earth as the Seal is broken.',
    `RequestItemsText` = 'The Seal of the Earth lies here, with three recessed alcoves for the Amethyst Runestone, the Opal Runestone, and the Diamond Runestone.'
WHERE `entry` = 795;

UPDATE `quest_template` SET
    `OfferRewardText` = 'From your description of the beast, I believe you must be speaking of Sarkoth! It is no wonder that Hana''zua was overtaken by it. Aid will be dispatched to him immediately, trouble yourself no more with Hana''zua''s plight.$B$BHowever, I must say, I am most impressed to hear that you brought Sarkoth to death. It is a feat to be proud of, $N. And that you would fight for a stranger''s honor, while other tasks occupied your time, your own honor is heightened.',
    `RequestItemsText` = ''
WHERE `entry` = 804;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hm... your report comes at a bad time. The Burning Blade is not seen here in Sen''jin, but their evil has taken seed off the coast, on the Echo Isles.$B$BThe orcs are friends of the Darkspear Trolls. Honorable friends. We want to help the orcs, but... we need help too.',
    `RequestItemsText` = ''
WHERE `entry` = 805;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Aha! You got him!$B$BYou do your clan proud, $N. And because of you, Durotar is free of one more agent of evil.',
    `RequestItemsText` = 'Did you find Fizzle, $N? He, and rest of the Burning Blade, must be scoured from our lands!'
WHERE `entry` = 806;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done us all no small service with your keen eye, hunting these beasts. I''ve already called for a runner to send these to Orgrimmar where the Warchief''s trusted eyes will work to see where the corruption stems from.',
    `RequestItemsText` = 'Bring me the hearts for study and then I''ll have them destroyed. Durotar will not fall to corruption!'
WHERE `entry` = 807;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. You have saved Minshina. You have saved my brother''s spirit from slavery!',
    `RequestItemsText` = 'Do you have my brother''s skull, $N? Is he finally free?'
WHERE `entry` = 808;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Neeru wants the Demon Seed destroyed, does he? Strange...$B$BVery well. If he wishes the seed gone, then I will tell you how to remove it.',
    `RequestItemsText` = ''
WHERE `entry` = 809;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These carapaces will serve to make plates of armor to protect our hunters from the scorching heat and dangers of the savannah. Thank you, $N.',
    `RequestItemsText` = 'Do you have the carapaces?'
WHERE `entry` = 810;

UPDATE `quest_template` SET
    `OfferRewardText` = 'We will further armour hunting parties with the strength of our new home. Keep yourself open to the wisdom of the land, $N.',
    `RequestItemsText` = 'Be careful not to underestimate the scorpids if you strike out at them alone.'
WHERE `entry` = 811;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N, you''ve saved my life. Thank you.$B$BPlease take this; I hope it can at least help you in your travels, if not bring you some coin. From what you say, I won''t be usin'' it anytime soon. Kor''ghan is gonna march me through more of his rituals until I prove myself. More killin'' boars, more gatherin'' scorpid tails... <sigh>',
    `RequestItemsText` = 'I''m almost glad I can''t return to Sen''jin as I am now. My weakness and stupidity would surely be mocked.'
WHERE `entry` = 812;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here is the antidote, $N. Take it to Rhinag as soon as you can, and be cautious.',
    `RequestItemsText` = 'Remember, no matter what creature you hunt, you would do well to study it and understand its behavior. That knowledge could save your life.'
WHERE `entry` = 813;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Get me some Chunks of Boar Meat if you want to make yourself useful...',
    `RequestItemsText` = 'You want to eat, you get me some more meat!'
WHERE `entry` = 814;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You might be weak, but at least you''re not clumsy, $N.$B$BHere, take this and get outta my way. I''ve got cooking to do.',
    `RequestItemsText` = 'Breakfast, lunch, dinner! Who cares which meal it is? It still has to be cooked by someone--namely me!'
WHERE `entry` = 815;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, my son... my beautiful son.$B$BUncertain of my son''s fate, I have tormented myself since he left. Now that I know what''s happened, perhaps I can finally begin to mourn.$B$BThank you, $N. Please take this. I was going to give it to Kron as a gift when he returned successful. Now that I know he is dead, I cannot bear to look at it.',
    `RequestItemsText` = 'I pray that Kron will return to me, but I''m almost certain I know his fate already.'
WHERE `entry` = 816;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I am pleased, $N. Because of your help, our people will be protected, and not go cold as the seasons change.$B$BThank you.',
    `RequestItemsText` = 'I remember my first tiger hunt, $N. I chose to hunt on the largest of the Echo Isles, and I sat perfectly still in the shadows of its foliage for almost a full day... watching... waiting.$B$BMy muscles were taut, and I was ready to strike. It was one of my greatest victories when that tiger finally took the bait.'
WHERE `entry` = 817;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, young one... well done indeed.',
    `RequestItemsText` = 'Time is the true test of your strength and will. Lose patience or give in to weakness, and your true self will be shown.'
WHERE `entry` = 818;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, I''ll be...$B$BThis was one of Chen Stormstout''s kegs. He traveled with Rexxar a long time ago. I haven''t seen or heard about him in a kodo''s age. I appreciate you bringing this to me, $N.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 819;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done me a great kindness this day, $N. With my vision restored, I will be able to help out more around the village. More than strength, you''ve a spirit of honor.',
    `RequestItemsText` = 'Have you retrieved the herbs?'
WHERE `entry` = 820;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Haha... I never thought I''d make more of this stuff ever again.$B$BYou''ve stirred in me a great sense of nostalgia, $N. Kind of reminds me of the last time I made a batch of trogg brew. Thank you. The memories warm my stomach.',
    `RequestItemsText` = 'How''s the search going?'
WHERE `entry` = 821;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Haha! I knew you couldn''t resist some of this brew. Come back again anytime you want some more, $N. Just bring me more of the ingredients I had you collect.',
    `RequestItemsText` = 'You working hard at finding those ingredients, $N?'
WHERE `entry` = 822;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes? You have something to report? Well then, let''s have it!',
    `RequestItemsText` = ''
WHERE `entry` = 823;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This globe... it is most disturbing.  Many of the more powerful elementals receive their power and energy through such devices.  To find one like this nearly intact is one thing - to find it so tainted is another.$B$BI will see that this globe is studied properly by the Earthen Ring.  Perhaps we can bring an end to this corruption of the elements.  Please - accept this as a fair exchange for bringing this globe to the attention of the Earthen Ring.',
    `RequestItemsText` = 'Ah, hello there.  I spend a great deal of time studying the water - all the elements really - so much so that sometimes I don''t even notice people around me.$B$BIs there something I can help you with?'
WHERE `entry` = 824;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your recovery mission was a success, $C. I will see to it that these tools get to Orgrimmar with the next caravan.$B$BNicely done.',
    `RequestItemsText` = 'Once we learn how the humans operate their strange machinery, we will stand a greater chance of defeating them in future battles.$B$BWith our new gained knowledge, the Horde only stands to grow in strength.'
WHERE `entry` = 825;

UPDATE `quest_template` SET
    `OfferRewardText` = 'With Zalazane gone, our tribe can again sleep in peace.$B$BThank you, $N. The Darkspear tribe owes you much. If you suffer from an ailment, visit my assistant Bom''bay, behind me. His voodoo is strong...',
    `RequestItemsText` = 'Is Zalazane defeated, $N?'
WHERE `entry` = 826;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good. Hiding within these collars is the secret behind the Burning Blade. And I will uncover that secret...',
    `RequestItemsText` = 'Have you yet entered Skull Rock, $N? Do you have the Searing Collars?'
WHERE `entry` = 827;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Welcome, $N. Word reached me of your coming, and of your exploits in Durotar.$B$BYou are a $C of growing skill and renown.$B$BStay on the pure path, and your future will be great indeed.',
    `RequestItemsText` = ''
WHERE `entry` = 828;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, and where did you get this? Good Margoz in Razor Hill sent you to me, did he?$B$BWell, let me take a closer look...',
    `RequestItemsText` = 'My most humble greetings, $C. How might I help my $R brother today?'
WHERE `entry` = 829;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This does not bode well at all. You were wise to bring this information to my attention.',
    `RequestItemsText` = 'There is a look of concern on your face, $C. What have you there?'
WHERE `entry` = 830;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Countless times I urged the Warchief not to trust the humans, but personal pride is not what is at stake here.$B$BYou have served the Horde honorably, young $C.$B$BNow excuse me, I must counsel Thrall on these matters at once....',
    `RequestItemsText` = 'Can you not see that I am busy? This had better be pressing....'
WHERE `entry` = 831;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Examines the Eye of Burning Shadow>$B$BIntriguing. The voice you heard mentioned my name? I am known for hunting down enemies of our Warchief, but...it is strange that I was singled out. Stranger still that the Burning Blade cultists from whom you recovered this pendant have a name so close to my own.$B$BI must study this pendant. I must study and, and must ponder the meaning of its message.$B$BThank you for bringing this to my attention, $N. You have done your people a great service.',
    `RequestItemsText` = 'You have something vital to report. I can sense it behind your eyes.'
WHERE `entry` = 832;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done. You have sent those foul Bristlebacks a clear message. They will think twice before attempting to meddle in this holy spot again.',
    `RequestItemsText` = 'The Bristleback Interlopers must be driven away from our sacred burial ground, $N.'
WHERE `entry` = 833;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hey, now isn''t that just the thing! You''ve got our supplies back for us. That''s great. I''ll be able to get back to work just as soon as I can find someone to haul these sacks for me.',
    `RequestItemsText` = 'I''m great at what I do, don''t get me wrong, but this is ridiculous! What am I supposed to do, build sand castles?'
WHERE `entry` = 834;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I think I can breathe easy now, knowing that the harpies won''t be bothering our supply caravans anymore. And not one moment too soon, either. I hear I''m being sent some fun little toys with the next shipment!$B$BYou''re pretty good at what you do, $N, you ought to track down my boss in Ratchet. I''ll bet he could find some work for you.$B$BOh, and don''t worry, I wouldn''t forget to pay you for the service you provided me.',
    `RequestItemsText` = 'You wouldn''t think it from a guy like my boss Gazlowe, but he always seemed to know the score. "Don''t be afraid to take that big step," he said.$B$BHarpies won''t stop bothering us and the caravans won''t stop being attacked unless we do something about it, eh?'
WHERE `entry` = 835;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, YOU''RE the great savior of OOX-09/HL! I cannot even begin to express my thanks for your assistance! My homing robot series needs more development, but your recovery has saved me countless hours of extra rebuilding time, as well as many gold pieces in manufacture costs!$B$BPlease, take your choice of any of these items I have. Thank you again for your generous assistance $N, my robots and I are in your debt!',
    `RequestItemsText` = ''
WHERE `entry` = 836;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I will pass along word that the quilboars have been removed from their lairs, and that their structures may be set to fire. The removal of the Razormane from Durotar brings us closer to fully securing the borders of our new homeland.',
    `RequestItemsText` = 'Though they do possess some intelligence and some organization, I find it constantly amazing that the quilboars were able to capture and hold so much territory in Kalimdor. Perhaps they are more crafty an enemy than I give them credit for...'
WHERE `entry` = 837;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, $C, the High Executor mentioned you might be the one to trust in the matter of they key. I''ve dedicated a fair portion of my recent studies to the Scholomance, and I believe I know a means by which you can acquire one that will let you past the front door at will.$B$BThis task will not be easy, but such tasks seldom are. You most assuredly look like the type to know this as fact.',
    `RequestItemsText` = ''
WHERE `entry` = 838;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, so Takrin sent you? He''s an excellent scout, I''m not sure what I''d do without him.$B$BI''ll sign your recruitment letter, but what we really need is someone at the Crossroads.',
    `RequestItemsText` = 'What do you want, pup? If you''re not here for recruitment, I don''t have time for you.'
WHERE `entry` = 840;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very well, here is another power source. I highly recommend you using it properly this time, unless you are eager to spend ten more water pouches for another water source.',
    `RequestItemsText` = 'Well, have you got the ten water pouches?'
WHERE `entry` = 841;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Alright, $N. You want to earn your keep with the Horde? Well there''s plenty to do here, so listen close and do what you''re told.$B$BI see that look in your eyes, do not think I will tolerate any insolence. Thrall himself has declared the Hordes females to be on equal footing with you men. Disrespect me in the slightest, and you will know true pain.',
    `RequestItemsText` = 'Well well well, what do we have here? Has Kargal deemed me worthy of another recruit?'
WHERE `entry` = 842;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Khazgorm met the fate he earned. I feel no remorse for the fool. He was an infidel on these lands.$B$BMay his death serve as a warning to all those who threaten to disrupt our way of life.$B$BNow let me take a moment to study the dwarf''s journal....',
    `RequestItemsText` = 'Many innocent tauren lost their lives or were forced off their ancestral birthplace when the dwarves of Bael Modan arrived. My land must be reclaimed!'
WHERE `entry` = 843;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good, $N.  With the plainstriders gone we''ll have an easier time keeping our supply chains intact.  And I hope you learned a few tricks out there in the Barrens, for your next prey has a little more fire in its blood than the plainstriders...',
    `RequestItemsText` = 'Have you collected the plainstrider beaks?'
WHERE `entry` = 844;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Not bad, $N.  Those zhevra hold a lot of strength in their legs.  A sharp kick from them can knock even a tauren on its haunches!$B$BIt looks like you have some strength in you too.  Are you ready for a real challenge?',
    `RequestItemsText` = 'How many zhevra have you slain?'
WHERE `entry` = 845;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I see you are quite industrious, $C.$B$BNo doubt we shall soon have a fitting surprise for those dwarves.',
    `RequestItemsText` = 'I see you are back, $N.$B$BWhile Khazgorm''s death might delay the digging in my ancestral lands some, it will by no means bring a total end to the destruction.$B$BThe Keep at Bael Modan is an increasing military threat. Built to defend the dig site, it is now poised for offensive force as well.$B$BIf you have the ingredients I requested, I can fashion a charge that will make the hasty dwarves reconsider their actions here in the Barrens.'
WHERE `entry` = 846;

UPDATE `quest_template` SET
    `OfferRewardText` = 'When the enchantment wears off, I will speak with Gor''mul. My thanks to you for your help in returning Gor''mul to the land of the living. I have no doubt he thanks you greatly as well.',
    `RequestItemsText` = ''
WHERE `entry` = 847;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, yes.  These are good specimens.  Potent.$B$BI am Forsaken, and we honor our contracts.  Here is your reward, $N.',
    `RequestItemsText` = 'Do you have the spores, $N?  There is a concoction I must send to my associate in Thunder Bluff, which requires the spores...'
WHERE `entry` = 848;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, $N! May you be revered in Thunder Bluff as a defender of sacred tauren lands and a champion of the lost tribe.',
    `RequestItemsText` = 'Once the dwarven flying machine has been destroyed I will feel the sweet satisfaction of revenge.'
WHERE `entry` = 849;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N.  The centaur are low, brutish creatures, but a few have the wit and vision to lead.  And those are the most dangerous.$B$BBarak was such a centaur.  It is good that he is dead.',
    `RequestItemsText` = 'Hello, $N.  Do you have Barak''s Head for me?'
WHERE `entry` = 850;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good.  You must have really stirred up those centaur -- our guards spotted activity down near the Stagnant Oasis, which was probably you.$B$BYou should be proud of your deed, $N.  There is much bravery in you.',
    `RequestItemsText` = 'Did you find Verog, $N?'
WHERE `entry` = 851;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I commend you, $N.  These centaur are undisciplined and cannot focus their rage as the orcs can, but they are fierce nonetheless.  In defeating them, your valor is proven.',
    `RequestItemsText` = 'Is Hezrul defeated, $N?'
WHERE `entry` = 852;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, the spores from the Barrens that Helbrim was gathering.  He garnered your aid in delivering them?  Good.$B$BAnd the emulsion is still potent, so you must have wasted no time in the delivery.  Well done, $C.',
    `RequestItemsText` = 'You have something from Apothecary Helbrim?'
WHERE `entry` = 853;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is good to see that more of our $R allies have come to assist us from as far away as Thunder Bluff. Again, I welcome you.',
    `RequestItemsText` = ''
WHERE `entry` = 854;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Nicely done.  I''m sure you''ve struck fear into the surviving centaurs, $N.  If they have sense, they''ll now calm themselves and stop their advances.$B$BBut I don''t think they will, and that is unfortunate.$B$BUnfortunate...for them.',
    `RequestItemsText` = 'How goes your hunting, $N?'
WHERE `entry` = 855;

UPDATE `quest_template` SET
    `OfferRewardText` = 'At last, the power is mine again! Mine I say!',
    `RequestItemsText` = 'Where is the Tear of the Moons? I need it now! Need I say!'
WHERE `entry` = 857;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yep, this looks like the right key. Let me just make sure I know how to work this thing...$B$BHmm... rotation control... This regulates speed and stability... fine arm movement control. Just look at this! I can''t believe the Venture Company could design something this much better than ours. I''ve got to get this back to Ratchet!',
    `RequestItemsText` = 'Quick, we need to get out of here before someone gets suspicious!'
WHERE `entry` = 858;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You want to hunt in the Barrens?$B$BYour eyes are eager, and young.  They''re not yet squinted from tracking your prey across this land''s dry plains.$B$BBut worry not. We''ll toughen your body and your mind.  And we''ll teach you that there is more to hunting than finding and killing your quarry.$B$BPrepare yourself.  Your journey begins.  Now.',
    `RequestItemsText` = ''
WHERE `entry` = 860;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Skorn Whitecloud is a wise tauren.  He has hunted for years and years, and although his body is old, his spirit burns fiercely.  We are honored to have him with us.$B$BIf Skorn sent you to me, then  you too must have the hunter''s spirit.  And to have gathered these claws shows your burgeoning skills.$B$BPerhaps you are ready to walk the path.',
    `RequestItemsText` = 'Greetings.  There is an air about you that tells me much.  Do we have business, you and I?'
WHERE `entry` = 861;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Normally I don''t like to eat these rodents when they''re so.... so... ripe. Like to let them rot for a few weeks to really bring out the flavor. But you look so hungry.$B$BLet me fix you some Dig Rat Stew. Ah, there we go.$B$BHere you go!',
    `RequestItemsText` = 'Whack enough dig rats yet, $N?'
WHERE `entry` = 862;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hopefully we''ll be able to get something of value from the wrecked shredder prototype... my time''s running out! I''ll dispatch a salvage team to Wizzlecrank''s location on the double.$B$BOh, let me give you something for your trouble, too.',
    `RequestItemsText` = 'Can I help you?'
WHERE `entry` = 863;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I will analyze this data immediately. Perhaps Keever''s insanity will prove to be my genius after all.$B$BAs for you... you are useful to me, and I reward quite well those who remain useful. Take this item, this coin, and most importantly my thanks along with them.$B$BCheck back with me from time to time - I wager that our working together on this project is not at an end.',
    `RequestItemsText` = 'Welcome back. At least, welcome back if you have returned with a sealed testing kit. Otherwise, I will pretend not to notice your utter incompetence and spare my wrath from you until you do as you have been tasked and accomplish my task.'
WHERE `entry` = 864;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great, you got them!  Now I just need to ground them down and mix them with some wine, and...',
    `RequestItemsText` = 'Did you get the horns, $N?  Those things are going to make me a fortune!'
WHERE `entry` = 865;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes yes, these are very nice! I will grow specimens from these roots and study them. I hope to find new properties from them. Hidden, valuable properties...!$B$BAnd don''t worry -- if I do then you''ll be the first to know. Because I''ll need someone to gather more!',
    `RequestItemsText` = 'Hello, $N. Did you get those root samples?'
WHERE `entry` = 866;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, these are nice. Real nice... Good job, $N. I look forward to seeing more of your work in the future.',
    `RequestItemsText` = 'Cut up enough of them yet? Keep slicing and taking trophies. I want 8 Witchwing talons.'
WHERE `entry` = 867;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You please me, $N. The eggs and the tool. Well done.$B$BAnd for your reward...',
    `RequestItemsText` = 'Be careful with the eggs you find, $N. If they break, they be no good to me.'
WHERE `entry` = 868;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You got rid of the raptors!$B$BThank you, $N.  You are a $C of worth.',
    `RequestItemsText` = 'Do you have those heads, $N?'
WHERE `entry` = 869;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found a fissure in the earth, with gases bubbling from it?  Strange.  This may be an answer to our questions, but we cannot yet be sure.$B$BBut it is a clue.  And I am grateful that you found it.',
    `RequestItemsText` = 'Have you been to the Forgotten Pools, $N?  Did you find anything?'
WHERE `entry` = 870;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, $N. Those insolent quilboars will finally learn that the might of the Horde is not to be ignored.',
    `RequestItemsText` = 'The longer it takes to stop these attacks, the harder it will be to provide supplies for the people of the Crossroads.'
WHERE `entry` = 871;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N. With Kreenig''s death, there will be a definite decline in the attacks on our caravans.$B$BYour people should be proud to count you among them.',
    `RequestItemsText` = 'Cut off the head of their leader, and chaos ensues, $N. Learn this lesson well. It will aid you in the future.$B$BThe boars will flounder without direction, and we will be able to take back the Barrens.'
WHERE `entry` = 872;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You now are one with Isha Awak, $N. His spirit is with you. He lurks in your eyes...$B$BEyes that, one day, will learn to see.',
    `RequestItemsText` = 'Fear not the waters, $R.'
WHERE `entry` = 873;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My brother sent you, did he?  Then you must have proven yourself to him.  If you have earned the respect of Jorn, then you have my respect as well.$B$BAre you ready to tread farther down the hunter''s path?',
    `RequestItemsText` = ''
WHERE `entry` = 874;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent work my friend. I think you''ll go far within the Horde.',
    `RequestItemsText` = 'Do you have 6 Harpy Lieutenant Rings yet? Justice must be dealt to them for their vicious attacks on the Horde.'
WHERE `entry` = 875;

UPDATE `quest_template` SET
    `OfferRewardText` = 'HA! Well done, $N! Very well done... I wasn''t sure you were up to the task, but you''ve proved yourself quite the cut-throat. Thank you again for helping us suppress the Harpy epidemic. Here is your reward, use it well.',
    `RequestItemsText` = 'You''re not getting anything until I see Serena''s head.'
WHERE `entry` = 876;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your findings are amazing!  The seeds I gave you were dried, and dead.  Whatever rests under these oases can create life from nothing!$B$BWe must study this more...',
    `RequestItemsText` = 'Have you been to the Stagnant Oasis?  Was there a fissure beneath its waters?'
WHERE `entry` = 877;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, yes... filled with joy because finally <snort> the Bristleback know my tribe''s pain, $R. That is how I should feel, but that <snort> is not the case.$B$BYou aid your people and they honor you. Mangletooth aids his people, and what do they do? They turn their backs on him. They forget him and leave him to rot in cage!$B$BI aid them even from locked behind bars and they send no one to save me!',
    `RequestItemsText` = 'More information <snort> for the Horde when you''ve killed the Bristleback''s wise ones, $R. <snort> Not a moment earlier! Mangletooth is no fool.'
WHERE `entry` = 878;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is done then. Better it ends this way, says Mangletooth. <snort> They should have <snort> made sure I was dead when they turned their backs on me instead of leaving <snort> me here in this forsaken cage.$B$BThere is but one task left for you to finish, $R.',
    `RequestItemsText` = 'How goes your hunt, $R? <snort>$B$BThork thinks he knows the truth about who leads the raids against his people, <snort> but he shall learn how wrong he is if you are successful.$B$BMy death is inescapable, but you have caused great pain to my enemies, so Mangletooth regrets nothing. <snort>'
WHERE `entry` = 879;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N.  Studying the beasts of an area can tell much about the area itself.  We shall see what tale these shells tell.$B$BPlease accept my gratitude for your aid ... and perhaps you can use these coins.  I find that I do not need them.',
    `RequestItemsText` = 'How goes your collection?  Did you get the shells?'
WHERE `entry` = 880;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve beaten Echeyakee, and though his days of hunting are over... his spirit is with you.  He will show you the strength found in subtlety, and the honor in mercy.$B$BYour path is still long, $C.  Let''s hope you stride it well.',
    `RequestItemsText` = 'The great cat calls to you, $N.'
WHERE `entry` = 881;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This fang is merely a token, but what it represents is profound.$B$BIshamuhale''s strength is in you, $N.  May you use it with temperance.  That is your burden.$B$BThat is your honor.',
    `RequestItemsText` = '$N, have you bested Ishamuhale?'
WHERE `entry` = 882;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Lakota''mani is called "Earthshaker" in our language, and his steps are like gathered thunder.  He is with you now, and his courage mingles with yours.  Together there is no conflict you cannot face.$B$BWalk tall, $N.  Walk tall, Earthshaker.',
    `RequestItemsText` = '$N, when you approached I saw a new power in your stride.  Tell me -- has your spirit met with the great Lakota''mani?'
WHERE `entry` = 883;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The thunder lizard Owatanka is called "Bluebolt" by the tauren, for within him resides a speed that belies his size.  It is said that lightning struck Bluebolt long ago and, fed from the sky''s rage, the great beast''s energy is without limit.$B$BMay his energy flow through you, $N.  For you now keep pace with Owatanka.',
    `RequestItemsText` = '$N, there is a new power behind your eyes!  You have met with the mighty Owatanka, have you not?'
WHERE `entry` = 884;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The thunderhawk is a rare beast of the Barrens, and its death can portend great fortune, or great doom.$B$BBut Washte Pawne, called "Spirit Biter" in Taurahe, can bring neither... or both.$B$BThe pain you felt from hunting Spirit Biter is the pang all feel who make great gains at great costs.  The sting you felt is the pain of regret.$B$BBut I can see you have conquered this.  You have learned that regret turns to wisdom, and that through pain one gains strength.$B$BYou have learned much, $N.',
    `RequestItemsText` = 'There is new resolve within you, $N.  A resolve born from pain...$B$BAre you burdened with the death of Washte Pawne?'
WHERE `entry` = 885;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My brethren in Thunder Bluff were wise to send you, young $C.  For the mystery of the Barrens is one that I alone cannot unravel.$B$BWith your aid, let us hope we can find answers to our questions.',
    `RequestItemsText` = ''
WHERE `entry` = 886;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You did good, kid. A little more work like that, and it''ll be one less thing I''ll have to worry about. Hopefully they''ll be convinced that they should relocate their operation elsewhere.$B$BIn the meantime, there is the small matter of getting back the goods they stole from me!',
    `RequestItemsText` = 'I don''t even want to think about the profits I''ve lost from pirate raiding, and now they set up camp on my doorstep? It''s getting out of hand, Undermine''s got to do something about it.'
WHERE `entry` = 887;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It''s a relief to get all this stuff back, so thanks for your help, $N. You know, I could use a $R like you to help out with my operation here. If you''re ever looking for work, don''t forget about how well Gazlowe pays for service!',
    `RequestItemsText` = 'Did you find my things, $N?'
WHERE `entry` = 888;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good. Go with Agamaggan''s spirit as your guide, $R. Return to me if you desire more of Agamaggan''s magics.',
    `RequestItemsText` = 'Bring Mangletooth 10 blood shards and I will bless you with great speed. You will run with zhevra and the wind will be jealous of you.$B$BIt will not last long, but it should be enough to help you travel throughout the Barrens.'
WHERE `entry` = 889;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, Gazlowe sent you, did he? Just a moment, let me take a look here and check my own logs and make sure I didn''t have Gazlowe''s shipment sent to the wrong place.$B$BBet he''s waiting for those boots from Drizzlek...',
    `RequestItemsText` = 'Wares to send on the next ship, $N?'
WHERE `entry` = 890;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Alas, the righteous Alliance guns have been silenced. You shall be rewarded for your aid, $N.$B$BNow to tend to the grim task of recovering the bodies of the dead....',
    `RequestItemsText` = 'My fleet is in peril with Captain Fairmount and her damned cannoneers blasting away from Northwatch Hold. I want her soldiers to pay as well. Fill my hand with medals from their dead and I will know that vengeance has been given to my fallen privateers.'
WHERE `entry` = 891;

UPDATE `quest_template` SET
    `OfferRewardText` = 'No dice, eh? I guess it must have been the Freebooters then... Dizzywig''s on the level, I''m sure he wouldn''t cheat me like that. After all, he is on the payroll.$B$BLooks like I''ve got some goods to get back, $N. What do you say?',
    `RequestItemsText` = 'So, what did Dizzywig have to say?'
WHERE `entry` = 892;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent, excellent specimens indeed.$B$BThe quilboar are further along than I had expected.$B$BHere, $C, take this and get out of my way. I''d better take a closer look at these weapons. We may have underestimated our enemy, and that''s the kind of mistake we can''t afford to make.',
    `RequestItemsText` = 'I, too, have doubts that the pathetic quilboars could attain any level of skill in the area of smithing, but I do as the Warchief commands, and I shall learn what I can about the Razormane tribe.$B$BI have had more menial tasks, and I do so willingly if it aids the orc people.'
WHERE `entry` = 893;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A variety of buttons, levers and blinking lights are somewhat erratically arrayed on the face of the control console. A small gauge indicates that the apparatus is currently operating within optimal levels, and indicates that control valves one through three are currently open. There is a small keyhole set into the lower right side of the control panel.',
    `RequestItemsText` = ''
WHERE `entry` = 894;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahhhh! That sort of business. You know, I saw the Heedless once on the open seas. Fearsome ship, or was that boat... those sailors are so particular!$B$BAnyways, watching her glide across the water was quite a sight to see. I''m glad her infamous captain will trouble my ships no longer.',
    `RequestItemsText` = 'What''s happening? Something I can help you with? Goods to ship, perhaps an engineering job?'
WHERE `entry` = 895;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Look at the size of that thing, $N! We''re going to be rich! Let''s see, according to the rates I''ve seen on gems going into Undermine, I should be able to figure out your cut--fifty percent, don''t worry!$B$BNow let''s see... I think this should do about right. Pleasure doing business with you, $N.',
    `RequestItemsText` = 'If only we knew which one of the miners had found the emerald, it''d be a walk in the park...'
WHERE `entry` = 896;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I can tell nothing of the nature of this beast, for its spirit has fled. But as you guessed, it does not belong in the Barrens. I fear it may herald a grim future for our people...$B$BBut for now, prepare yourself, and let us hope that time unravels the mystery of this creature.',
    `RequestItemsText` = 'You seemed troubled, $N. How go your lessons in the Barrens? Did you find something that disturbs you?'
WHERE `entry` = 897;

UPDATE `quest_template` SET
    `OfferRewardText` = 'And to think, we thought Firebough was long dead!$B$BYour heroics have earned you a place of honor with the Thalo''dan Privateers, $N.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 898;

UPDATE `quest_template` SET
    `OfferRewardText` = '$C, you take my task seriously, and for that I thank you.$B$BAlthough my desire for revenge remains, I can at least smile seeing that the quilboars have felt pain themselves.',
    `RequestItemsText` = 'The quilboar will pay for this, $N. I swear it.'
WHERE `entry` = 899;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The lights indicating the three control valves dim as they are shut off. Green lights slowly fade into yellow, and the switch controlling the apparatus is now moveable, with the valves closed, it can be turned off.',
    `RequestItemsText` = 'Blinking lights on the control console indicate that the main control valves have not been closed off.'
WHERE `entry` = 900;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Turning the key in the lock, the control console unlocks. A red light at the top of the console turns off and all power drains from the terminal.',
    `RequestItemsText` = 'The console lights are dimmed and the gauges and dials all read at their zero positions, everything idling.'
WHERE `entry` = 901;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is... er... interesting... yes. I''ll have it sent along to the Tinkers'' Union headquarters in Undermine. I''m sure after some careful dissection and research, they''ll be able to make some sense of it.',
    `RequestItemsText` = 'Oh, you''re back, $N! Do you have the samophlange?'
WHERE `entry` = 902;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, I see you''ve been busy, lurking in the grasses and hunting prowlers.  Do you think, then, it is time to face a champion among them?',
    `RequestItemsText` = 'How goes your hunt, $N?  Have you found the prowlers?'
WHERE `entry` = 903;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So you''ve been to the nests and placed the feathers of your prey within them.  That took a fair portion of courage, no doubt about it.$B$BDo you feel a little tougher, $N?  Because you look tougher now then when you first came here.  I guess the Barrens is doing its job.',
    `RequestItemsText` = 'Have you been to the nests, $N?'
WHERE `entry` = 905;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found the Razormane leader and killed him yourself, $N? Amazing.$B$BI am without words, but that does not mean I am without thanks. The people of the Crossroads would do well to respect your strength.$B$BI must admit, I thought the leader of these raids on our supply lines was another quilboar. Thank you again, $N.',
    `RequestItemsText` = 'Yes, what is it?'
WHERE `entry` = 906;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is good to see you return with proof of victory.  And it is good to know you have done so with your bones unbroken.',
    `RequestItemsText` = 'Are the thunder lizards defeated, $N?'
WHERE `entry` = 907;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is exactly what I need! A fathom core is an incredible well of information that we will be able to draw much good from. Whatever the Twilight''s Hammer is up to in there - and believe me when I say it is no good - my comrades and I will now uncover.$B$BYou''ve done well here today; the Earthen Ring looks upon you warmly for assisting us. You''ve also helped the Horde as a whole, and for that you should be proud.',
    `RequestItemsText` = 'Have you been successful in locating the fathom core? Without it we''ll have no idea what the Twilight''s Hammer is exactly up to down there.'
WHERE `entry` = 908;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This... this is quite the find, $N.$B$BYou acquired this from Baron Aquanis in Blackfathom, you say? Baron Aquanis has long been thought of as a corrupted elemental power; this globe will prove what exactly had corrupted him. While it would be no surprise if it turned out to be the Twilight''s Hammer, our studies will also show how they did it as well.$B$BYou did well in bringing this to me. Please - take this, along with the Earthen Ring''s warmest regards.',
    `RequestItemsText` = 'Ah, hello again $N. I was just reading the waves the sea, much like I always do. What brings you to the outpost?'
WHERE `entry` = 909;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wow, the ocean is HUGE!  There were a lot of seagulls and stuff too - It''s just as noisy and as bustling as I thought it would be.  There are pirates near by too - so cool!$B$BThank you for taking me to Ratchet, $N.  That was so awesome!',
    `RequestItemsText` = 'Are we there yet?'
WHERE `entry` = 910;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wow, Ashenvale is where real adventure happens!  Have you ever fought in Ashenvale, $N?  When I become a hero when I grow up, I wanna come to Ashenvale and fight for the glory Horde!$B$BThank you for taking me to the frontier, $N.  You''re the best!',
    `RequestItemsText` = 'Are we there yet?'
WHERE `entry` = 911;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You, like the thunderhawk, should be proud.  You have bested every foe we set you before, and have done so with strength, courage and honor.$B$BBut your path, $N, continues.  In fact, you will find that true hunters forever strive, forever walk their path with the same pride you have shown me.$B$BNow, it is time to move on.',
    `RequestItemsText` = 'Is it done? Have you slain the thunderhawk?'
WHERE `entry` = 913;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done it, $N.  You killed the leaders of the Druids of the Fang.  My dreams are now free of their wicked faces, and you have helped save the Barrens from a cursed future.$B$BI thank you, $N.  I thank you for myself, for the druids of Thunder Bluff, and for the land.',
    `RequestItemsText` = 'Memories of my nightmares haunt me, $N.  Have you defeated the leaders of the fang and acquired their gems?'
WHERE `entry` = 914;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Mmmmmmmmm!  I love their strawberry ice cream!  If there''s one thing Tigule and Foror know to do, it''s make ice cream!$B$BThank you very much $N - this is the best treat ever!',
    `RequestItemsText` = 'I wish they''d make more flavors of ice cream other than strawberry, but I guess I''m lucky that strawberry is my favorite!'
WHERE `entry` = 915;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. When I return to Darnassus I will compare the venom within these sacs with the venom of other spiders. It is my belief that it will have properties linked to the recent growth of our new world tree.',
    `RequestItemsText` = 'Did you gather the venom sacs, $N?'
WHERE `entry` = 916;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, very good. I will have this egg and the venom transported to Darnassus, then return there when my studies are done here. I expect to find out a great deal from these specimens, $N. You have been a great help to me.',
    `RequestItemsText` = 'Have you been inside the Shadowthread Cave, $N? Did you find a spider egg?'
WHERE `entry` = 917;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You got them. This is good!$B$BI will plant these seeds in special soil I have prepared. I believe the seeds will sprout into timberlings who are much more docile. Perhaps later you can see the results!',
    `RequestItemsText` = 'Do you have the seeds? I am eager to plant them.'
WHERE `entry` = 918;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That''s a lot! I''m afraid they''re spreading at a dangerous rate. I hope I can solve the riddle of what is tainting them.$B$BThank you for your help, $N. The land is a cleaner place from your efforts.',
    `RequestItemsText` = 'Hello, $N. Have you found any sprouts near the waters?'
WHERE `entry` = 919;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, $N. I was hoping you''d be prompt in answering my summons. I have an important task that I would like you to perform.',
    `RequestItemsText` = ''
WHERE `entry` = 920;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So you have heard the first part of the aftermath of the Battle of Mount Hyjal. There is much more to be told and the task you have begun here will continue through the rest of your journey through Teldrassil and into Darnassus.',
    `RequestItemsText` = 'The moonwells hold the waters of the Well of Eternity, the ancient source of magic that has wrought so many horrors upon our world.$B$BThe druids take advantage of its properties, and the Sentinels revere the wells as shrines to Elune, but sorcery is forbidden to all.'
WHERE `entry` = 921;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, a timberling seed? I wanted to try growing one of these to help Denalan with his studies.$B$BBut I''m afraid I''ve discovered that a corruption has grown in many of the timberlings, and seeds from such creatures carry their parent''s taint. They are beyond my talents to repair.$B$BDenalan is very skilled with things that grow. He may find a cure for future timberlings. He may be their only hope.',
    `RequestItemsText` = 'Hello...$B$BAnd how may I help you?'
WHERE `entry` = 922;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done! These tumors are the symptom of the timberling''s disease. They are filled with a poison that we must cleanse from our new land.$B$BI will dispose of these tumors. Thank you, $N.',
    `RequestItemsText` = 'Have you been to Wellspring Lake, $N? Have you been hunting the timberlings there?'
WHERE `entry` = 923;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your task is complete. You have destroyed the Demon Seed as Neeru bid. But this is not the end...$B$BThe destruction of the Demon Seed sent waves of power through the ether, waves of staggering force. I felt them, and I am sure other beings did as well. Others who will wonder why their toy was broken...$B$BBut regardless of future troubles, I have something for you. Neeru sent it as payment. And he bid me thank you.$B$BSo, thank you.',
    `RequestItemsText` = 'The Demon Seed still exists. I can sense its power...'
WHERE `entry` = 924;

UPDATE `quest_template` SET
    `OfferRewardText` = 'WOW!  You got Cairne''s hoofprint for me!  Thank you very much!  And wow... he wrote a personal message on here - to me!  I knew he''d be totally cool, I just did!  Maybe someday I''ll thank him myself... when I become a hero of the Horde!$B$BYou''re the best, $N.  Thank you for being so nice to me.',
    `RequestItemsText` = 'When the orcs were alone and without friends, the tauren welcomed them to a strange land and shared with them without asking anything in return.  That''s honor, $N.'
WHERE `entry` = 925;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These stones are infused with magical energy, but purposefully flawed. They are very unstable and once removed from the table they will consume themselves quickly.',
    `RequestItemsText` = ''
WHERE `entry` = 926;

UPDATE `quest_template` SET
    `OfferRewardText` = '...What is this? A timberling heart?? It''s covered with a foul moss!$B$BThank you for bringing this to me, $N. I will examine the heart and, if fortune shines, determine the nature of the moss about it.',
    `RequestItemsText` = '$N! You have something for me?'
WHERE `entry` = 927;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, I see. You were sent by Tenaron. Well then, it would seem we have much to talk about, much to do, and little time to do it in.$B$BI think we''d best get started.',
    `RequestItemsText` = 'Greetings, $C. For what purpose do I owe the pleasure of our meeting?'
WHERE `entry` = 928;

UPDATE `quest_template` SET
    `OfferRewardText` = 'After the Battle of Mount Hyjal, we were without direction. Nordrassil smoked from the fire it unleashed, and our immortality--the very essence of our beings!--was lost.$B$BIt was in this trying time that the Betrayer was freed from his prison, and Shan''do Stormrage disappeared. A dark time for all.',
    `RequestItemsText` = 'Hello again, $N. Have you completed your task?'
WHERE `entry` = 929;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found this on Teldrassil? Intriguing... this fruit is exotic. Perhaps its seeds were brought here from far off. Perhaps even as far as Azeroth! And there''s something about this fruit... it seems to have reacted very strangely with the soil of Teldrassil.$B$BThank you, $N. Now if you''ll excuse me, I must study this further...',
    `RequestItemsText` = '$N, you look like you have something to tell me. Do you have news concerning the timberlings?'
WHERE `entry` = 930;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Where did you get this? I haven''t seen a plant like this since a sojourn I made to the Swamp of Sorrows... decades ago! It''s amazing that a specimen made its way to Teldrassil. And it''s grown to such a size!$B$BThank you, $N. Forgive my shortness of words, but there is a test I would like to perform on this frond...',
    `RequestItemsText` = 'You have something for me?'
WHERE `entry` = 931;

UPDATE `quest_template` SET
    `OfferRewardText` = 'With Lord Melenas laid to rest I can finally move on to other matters. Thank you, $N.',
    `RequestItemsText` = 'Did you kill Lord Melenas yet? It is vital that he be taken care of quickly and quietly, $N. His continued existence is an embarrassment to us all.'
WHERE `entry` = 932;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Shan''do Stormrage never returned, and the druids were in disarray, and to this day we still do not know what became of him. With Malfurion missing, Arch Druid Fandral Staghelm took over the leadership of the druids, convincing the Circle of Ancients in Darkshore that it was time for our people to rebuild, and that it was time for our people to regain their immortality.$B$BWith the approval of the Circle, Staghelm and the most powerful druids grew Teldrassil, the new World Tree.',
    `RequestItemsText` = 'At first the reports of crazed furbolg attacks were dismissed. Who could have thought that the peace-loving bear-men would turn to mindless rage? Yet another of the problems that plagues us here in our new home.'
WHERE `entry` = 933;

UPDATE `quest_template` SET
    `OfferRewardText` = 'To be in the presence of the Oracle Tree... it is almost to feel wisdom take form. Let me continue the telling...$B$BWith Teldrassil grown, the Arch Druid approached the dragons for their blessings, as the dragons had placed upon Nordrassil in ancient times. But Nozdormu, Lord of Time, refused to give his blessing, chiding the druid for his arrogance. In agreement with Nozdormu, Alexstrasza also refused Staghelm, and without her blessing, Teldrassil''s growth has been flawed and unpredictable...',
    `RequestItemsText` = 'Along with the druids, the Oracle Tree and the Arch Druid have been carefully monitoring the growth of Teldrassil. But though we have a new home, our immortal lives have not been restored.'
WHERE `entry` = 934;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah yes, the water I had requested. Tenaron and Corithras certainly took their time in having it delivered... perhaps not choosing the most reliable of messengers... hmm.$B$BNonetheless, I can finally get back to my work then. The weight of Teldrassil''s problems fall upon my shoulders. A yoke I would wish to soon be rid of.$B$BTake this, you may find some use for it.',
    `RequestItemsText` = 'I know that I did not summon you, so I cannot help but wonder why it is you have come to speak with me.$B$BWhatever it is, please make it quick.'
WHERE `entry` = 935;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Greetings, $C; I am glad you are interested in assisting our research. There is much to do, and I would be doing you a disservice if I informed you that the work this entails is not dangerous. Hopefully this will not scare you off... but from the looks of you, I take it that danger is something that you have dealt with before.',
    `RequestItemsText` = ''
WHERE `entry` = 936;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I am impressed by what you have accomplished here in so short a time, $N. Would that I could ask you to remain here to assist me with my duties... but I know in my heart that greater tasks lie ahead for you.$B$BI have noticed the Oracle Tree has just shed a piece of its bark. No doubt it has a task that it wishes completed. You should speak with it.',
    `RequestItemsText` = 'Their slashing talons and piercing beaks may prove a difficult match for your own abilities, $N, but I have faith that you will not fail in this task.'
WHERE `entry` = 937;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, thank you, $N! I feared I would never see Mist again, knowing only her death in my heart, never to be united with my faithful companion. I owe you more than you can know, and you have my eternal gratitude.',
    `RequestItemsText` = 'Mist... It was my fault! The witches caught me off guard... I should not have let them take you...'
WHERE `entry` = 938;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I sense the suffering of ancient ones, $N...$B$BHolding these items is almost unbearable...',
    `RequestItemsText` = 'What is it, $C? You look concerned.'
WHERE `entry` = 939;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I wondered why the Oracle Tree had not communicated with me for so long... It seems that some problems are lessened while others grow to greater concerns.$B$BI fear my work on Teldrassil shall never be completed, and our immortality never restored.$B$BNonetheless, you have done the Oracle Tree''s task well, and should be rewarded for your diligence.',
    `RequestItemsText` = 'Hmm... You come with the spirit of the forest strongly within you, $C. What business do you have with the Arch Druid of the Kaldorei?'
WHERE `entry` = 940;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You place the heart within the planter, and it quickly digs itself in!$B$BA few seconds later it wriggles back out, cleansed. It pulses slightly... beckoning for you to take it.',
    `RequestItemsText` = 'This planter is filled with soil, specially prepared by Denalan.'
WHERE `entry` = 941;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh my! You say this came from the distant lands of Kalimdor?$B$BAmazing! Simply amazing!',
    `RequestItemsText` = 'What ya got there, friend?'
WHERE `entry` = 942;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Most excellent, $N!$B$BNow to see if I can use the stone to decipher the powers of the fossils.',
    `RequestItemsText` = 'With the Stone of Relu I will be able to release the hidden secrets of my fossil as well as Remtravel''s fossil from Darkshore, $N.'
WHERE `entry` = 943;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Twilight''s Hammer is at the Master''s Glaive?$B$BUnfortunate.$B$BThe old lord impaled by the glaive is long dead, but that does not mean slivers of his power do not still remain.$B$BThe Twilight''s Hammer must be seeking this power.',
    `RequestItemsText` = 'The Master''s Glaive, $N.$B$BGo there, then speak with me again.'
WHERE `entry` = 944;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My sister was where?? Therylune doesn''t mind getting herself dirty, but still! That''s a long way to wander, and the Master''s Glaive is an unwholesome place...$B$BWell thank you, $N. It was very nice of you to let me know she''s all right.',
    `RequestItemsText` = ''
WHERE `entry` = 945;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Many thanks, $N. These mushrooms are fine specimens!$B$BAnd when you were at Cliffspring Falls, did you find anything to confirm the warnings of the Ancients?$B$BThe Ancients are wise, but I had hoped that, this time, they were wrong.',
    `RequestItemsText` = 'Do you have my mushrooms, $N? Have you been to the cave?'
WHERE `entry` = 947;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N. You are here.$B$BGood.$B$BWe have matters...to discuss. You and I.',
    `RequestItemsText` = ''
WHERE `entry` = 948;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This book is hand printed in an ancient language, and illustrated by a master artist.',
    `RequestItemsText` = ''
WHERE `entry` = 949;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A chaotic, primal magic surrounds this parchment of scribbles. I sense the work of the old ones in it.$B$BLet us hope it reveals the purpose of the Twilight''s Hammer in Darkshore...',
    `RequestItemsText` = '$N. You return.'
WHERE `entry` = 950;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you. These relics are from a time when Mathystra shone. That once great bastion of the elves has faded, but shards of its magic remain. Let us hope we can unlock the secrets of that place before our enemies...$B$BBe vigilant, $N.',
    `RequestItemsText` = '$N. Has your rooting through the Ruins of Mathystra been fruitful?'
WHERE `entry` = 951;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah. Thank you, $N. It is strange, though. The Arch Druid always seems in such a hurry. The forest knows that all shall come to pass in the appointed time. Shan''do Stormrage understood that.',
    `RequestItemsText` = 'Ah. $C. How may Onu assist you?'
WHERE `entry` = 952;

UPDATE `quest_template` SET
    `OfferRewardText` = 'We have few records from the time around the War of the Ancients, especially near the destruction of the Well of Eternity. Given the upheaval and cataclysmic events that were taking place, it is no big surprise.$B$BThank you, $N. With your help, my work here is finished, and I will be able to deliver a full report to the Circle.',
    `RequestItemsText` = 'When you have studied the tablets and learned of Ameth''Aran''s fall, I will take the knowledge on to Auberdine, and inform the Circle of Ancients.'
WHERE `entry` = 953;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh... To what could I possibly owe the exceedingly special honor of a $R such as yourself as company. Truly it says much of my current companions--with no offense to my hosts, the noble grells and satyrs--that your presence could be considered an improvement.$B$BBut please, do not let my uncivil tongue drive you from the place. It has indeed been many years, decades even, since I had civil accompaniment.',
    `RequestItemsText` = ''
WHERE `entry` = 954;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Indeed... The grells of Bashal''Aran do not possess that which I am searching... however they have come into contact with it recently. Recently... I would reckon that by your time, not mine. Recent for me stretches into the veil of the past, almost another Age...',
    `RequestItemsText` = 'Once I have the earrings, I will cast the spell to search for the whereabouts of the seal that binds me. For centuries I have thought on the freedom destroying the seal would bring to me... Perhaps those centuries have taken a toll upon my mind that I might never recover...'
WHERE `entry` = 955;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It... it is hard for me to even believe that what I hold now is that which has held me for so long. Let us waste no time, $N. When the seal is destroyed, I might walk the forests of the earth freely again.',
    `RequestItemsText` = 'The pillars of this shrine are as the bars of a prison to me, $N. No strength I still possess might break them, and no magic I wield might destroy them...$B$BFor a thousand years and more I have stared at them, wondering if at long last I outlived even the stone, would I be free? Or would it be invisible bars that held me then...'
WHERE `entry` = 956;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I am freed, $N! I can now see with my own eyes the changes that have come to our world... Only bits and pieces have I known. To think that when I last walked freely, the Well still stood and the Highborne held court with Azshara, our beloved queen.$B$BI sense that my jailor, my former master, Athrikus, still lives... Already my feelings of hopelessness will give way into thoughts of vengeance.',
    `RequestItemsText` = 'In truth, $N, I am afraid... Afraid that your coming--all of this--is merely a figment of a deranged mind. Can you know the torture that this is? I... Please, you must go quickly.'
WHERE `entry` = 957;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Though it is surely a figment of my imagination, I feel as though I can almost feel the taint of foul Highborne magic upon them. I will have these destroyed, so that their long dormant evil might never be released again.',
    `RequestItemsText` = 'If only the tools of their undoing could have been destroyed in the cataclysm that destroyed our world... Nonetheless, we must do what we can to ensure that the horrors of our past are not repeated in the future.'
WHERE `entry` = 958;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Superb! And just as I was about to lose my job too! I will see to it that Gazlowe gets this gift immediately.$B$BThank you, $N. Nicely done, I say!',
    `RequestItemsText` = 'The dockmaster has been on my case ever since Mad Magglish made off with that 99-year-old port. I guess that bottle was intended as a gift for Gazlowe from none other than Baron Revilgaz himself.$B$BIf you''re brave enough and patient enough to seek out Mad Magglish and get that port back, I''ll see to it you get a nice reward.'
WHERE `entry` = 959;

UPDATE `quest_template` SET
    `OfferRewardText` = '',
    `RequestItemsText` = ''
WHERE `entry` = 960;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The finding of Twilight''s Hammer cultists is troubling.  I must meditate on their intentions...$B$BWhen you have more information, speak to me through a scrying bowl.  If you require a phial of scrying in order to create a bowl, then...here is another.',
    `RequestItemsText` = ''
WHERE `entry` = 961;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, splendid specimens. You have done well, $N.',
    `RequestItemsText` = 'I am eager to see if you can gather enough Serpentbloom from the Wailing Caverns. I''ve sent many to do my bidding but none have returned.'
WHERE `entry` = 962;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. Perhaps it would have been better... if I had done it myself. But even after these thousands of years, I could not bear to raise my hand against my beloved.$B$BPlease, I would be alone with my grief...',
    `RequestItemsText` = 'With a great sorrow in my heart, I followed the Shan''do Stormrage into hibernation, and took my sorrow to my dreams, sleeping for the passing of thousands of years.'
WHERE `entry` = 963;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This''ll work, $N! My turn now - I will imbue these with a suitable temper that will allow them to survive the intense forging process they will eventually go through.$B$BThe next step will be to get an appropriate mold for the key. I know a goblin blacksmith in Tanaris that has in the past made molds for similarly macabre items. He works for whom goblins usually work for - the highest bidder.',
    `RequestItemsText` = 'Kill many and kill often, $C - we''ll need a decent supply of suitable skeletal fragments to make up the outer layer of the key. They don''t call it a Skeleton Key for nothing, you know.'
WHERE `entry` = 964;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Elissa sent you? Then it is good tidings you bring. I have troubling news to report to her, and had no means with which to deliver it.',
    `RequestItemsText` = ''
WHERE `entry` = 965;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Many thanks, $N. This should shed some light on this warlocks'' gathering...$B$BHmm... the Cult of the Dark Strand... I have never heard of this group before. Having no knowledge of their history, it is all but impossible to say what their plans must be.$B$BThere is no more time to delay. Warning must be delivered to Delgren immediately.',
    `RequestItemsText` = 'Have you found any more of their scrolls? I should be able to piece together a larger picture of the cult if you can find them.'
WHERE `entry` = 966;

UPDATE `quest_template` SET
    `OfferRewardText` = 'If you don''t mind my saying, you seem a bit well-equipped for a messenger, hm? I suppose Balthule wanted to be certain that his letter reached my hands. Let''s see what he has to say...$B$BThis is disturbing news. When undead or demonic forces are found, I help the Sentinels destroy them.$B$BAt first I was unaccustomed to the manners of the night elves, but I have grown to respect them greatly as allies.',
    `RequestItemsText` = 'You have some business with me, $C?'
WHERE `entry` = 967;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, a copy of The Powers Below. An interesting text, this is. And some might find it useful...$B$BBut this one''s in sad shape. And look here! There are notes in the margin of almost every page!$B$BHm...I know this copy. I sold it to Bolgar last year. Are you...a friend of his? Yes, I thought you were. You have that same fire behind your eyes!$B$BWell, by definition, a friend of Bolgar''s is a friend of mine. And we take care of our own, yes?',
    `RequestItemsText` = 'Hello, sir.$B$BMay I interest you in one of my tomes?'
WHERE `entry` = 968;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, yes... I will make da charm for ya now. Just you wait!',
    `RequestItemsText` = 'Bring back da shards, and I be tellin'' you more!'
WHERE `entry` = 969;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmm, some dark magic enchants this soulstone. Let''s see what''s trapped inside, shall we?',
    `RequestItemsText` = 'Have you acquired that soul gem?'
WHERE `entry` = 970;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found the manuscript! What a joyous day this is! Copies will be made and distributed, and the ancient knowledge of Lorgalis will finally be known to my brothers and sisters!$B$BYour service to us is more than you know, $N. But I hope that this gift shows you the gratitude we extend to our allies.',
    `RequestItemsText` = 'The journey to Ashenvale is long, and your task is not easy. But if you get me the manuscript, $N...then your reward will be great.'
WHERE `entry` = 971;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Take the water sapta and find the corrupted pool of water in Silverpine, $N. I have great faith in your abilities.',
    `RequestItemsText` = ''
WHERE `entry` = 972;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It was a grand thing you did today, $N. You should be quite proud of yourself for having faced down a warlock of such power.$B$BNow, let''s see what we can learn from Ilkrud''s writings.',
    `RequestItemsText` = 'You look a bit shaken up, $N. Are you well?'
WHERE `entry` = 973;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, I definitely see the correlation here between the temperature of the volcano and the hot springs. I''ll have to double-check my equations for accuracy, but it seems like the distance and the rate that the heat is transferred... Hmm...',
    `RequestItemsText` = 'I''d go there myself, but... I''m a little scared of the fire elementals there!'
WHERE `entry` = 974;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here it is, $N. Remember, ya have ta carry it with you. Why don''t ya head back to Winterspring, an'' see what ya be findin'' there?',
    `RequestItemsText` = ''
WHERE `entry` = 975;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well today, $C. The items we sent to aid Auberdine will be of immediate use in dealing with the dark threats that infest the forest.$B$BTake these with my heartfelt thanks.',
    `RequestItemsText` = 'The Sentinels have a great need for supplies to reinforce themselves in Darkshore.'
WHERE `entry` = 976;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I can''t wait to show my friends! Now, just wait a moment while I attach these...$B$BPerfect!',
    `RequestItemsText` = 'I''ve just about finished attaching the fur, $N. Please, hurry back with those horns!'
WHERE `entry` = 977;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now I can compare the feathers... Let''s see...',
    `RequestItemsText` = 'Where could these powers have originated from? I think we are on the right track to find the answer, $N.'
WHERE `entry` = 978;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hi! Erelas sent you? Great, I was just preparing to travel up to the caves now, and I wouldn''t mind company.',
    `RequestItemsText` = ''
WHERE `entry` = 979;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hi there, $N. Yes, what Krakle told you is true...',
    `RequestItemsText` = ''
WHERE `entry` = 980;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I knew you would be up to the task, $N.$B$BI sense great deeds before you, and that you will right many of the wrongs that plague our lands. Bear my blessings, $N, as well as this gift.',
    `RequestItemsText` = ''
WHERE `entry` = 981;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done us here in Auberdine a great service, lad. We''ll make sure that their effects are properly taken care of.$B$BAs for you, please have this. It is the least I can do for someone with the bravery to set things right.',
    `RequestItemsText` = 'The captains of those ships were good night elves, and they deserve a better fate than they were given. Perhaps tending to their personal effects will be the best way to put their spirits to rest.'
WHERE `entry` = 982;

UPDATE `quest_template` SET
    `OfferRewardText` = 'As you place the Crawler Legs inside the machine, you hear gears begin to grind. Judging from the banging sounds coming from the Buzzbox, you believe the Crawler Legs are being put in their proper place. Soon the machine begins to hum, and you hear a tiny voice calling out from within.$B$B"Hello? Uhh... Hello! You fixed it! This is Wizbang by the way! Thanks a lot... Hey, you wouldn''t want to fix another one, would ya?"',
    `RequestItemsText` = 'Buzzbox 827 sits with an eerie silence. A single flashing light indicates that it needs 6 Crawler Legs to be placed in its holding box.'
WHERE `entry` = 983;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is terrible news indeed, $N.$B$BWith the furbolgs this close to Auberdine, we will have to prepare ourselves for the inevitable.$B$BThank you, $N.',
    `RequestItemsText` = 'How goes your search, $N?'
WHERE `entry` = 984;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wash the blood from your garments, $N, and do not mourn what you had to do. Instead, give thanks. You have lessened the threat to our people here in Auberdine, even if Darkshore is still in jeopardy from the effects of fel moss.',
    `RequestItemsText` = 'Do not stay your hand from what must be done, child. I know how repulsive the idea of killing the creatures of the forest must be, but in this case it is necessary. No cure has been discovered for the corruption let loose upon the forest, and we must do what we can to halt its progress until one is found.'
WHERE `entry` = 985;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These will do nicely, $N. I shall set to work on the cloak immediately.$B$BGive me a few moments, then return to me.$B$BOh, one more thing: after you''ve used the enchantment on the cloak you''ll be limited in your interactions with others. If you can help it, do no more than speak to others. Much more than that could dispel the illusion.',
    `RequestItemsText` = 'I can''t in good conscience permit you to seek Volcor until I''ve crafted that cloak for you.'
WHERE `entry` = 986;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, a $C from Darkshore. Selarin has done well to send you here so quickly, $N. I wish your trip here wasn''t under such dire stress. Perhaps with your help we can improve matters.$B$BI would start my visit by speaking to the other citizens of Astranaar. Some could surely use your aid.',
    `RequestItemsText` = ''
WHERE `entry` = 990;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Teronis'' body lies broken atop the island. For some unknown reason, the murlocs have left it alone.$B$BThe deep slashes across his corpse obviously came from the weapons and claws of the murlocs.',
    `RequestItemsText` = ''
WHERE `entry` = 991;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What''s this?  You were ambushed by some sort of bad mojo creepy-crawly?  Oh, this does not bode well for the Gadgetzan Water Company, no indeed...$B$BI guess I should have told you about the reports coming in on some crazy bug-creatures that appear to be sucking up all the water in the desert.  At first, I thought it was just a crock.  We have enough trouble with the nomads as is; I thought it was just more of their shenanigans.  Well, now we know at least!',
    `RequestItemsText` = 'Welcome back, Junior Surveyor $N!  Have you completed your assignment yet?'
WHERE `entry` = 992;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wonderful! Terenthis found someone to help me.$B$BAnd look. a moonstalker cloak...<cough> Oh... that hurts. Thank you, $N.$B$BThe furbolgs wounded me before I managed to evade them. Give me a moment, and I should be fine to talk some more.',
    `RequestItemsText` = ''
WHERE `entry` = 993;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N! I''m pleased to see you''ve returned successfully. Your assistance to Volcor has given me faith that we can overcome the challenges facing us here in Darkshore and beyond.',
    `RequestItemsText` = ''
WHERE `entry` = 994;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N! I''m pleased to see you''ve returned successfully. Your assistance to Volcor has given me faith that we can overcome the challenges facing us here in Darkshore and beyond.',
    `RequestItemsText` = 'Yes, $N?'
WHERE `entry` = 995;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You apply two Cenarion plant salves to the windblossom. It immediately begins to shed its corrupted form, blossoming into a vibrant and healthy plant.',
    `RequestItemsText` = 'You have found a sickly, corrupted version of what appears to be a windblossom plant.  The berries that hang from the plant appear rotten and poisonous.  It desperately needs some sort of attention if it is to be turned back to normal.'
WHERE `entry` = 996;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, it''s here! I have waited for this rare earth for quite some time. I hope it''s still fresh...$B$BThank you for bringing it to me, $N. You are a $R who is generous with their time.',
    `RequestItemsText` = 'You have something for me?'
WHERE `entry` = 997;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You apply two Cenarion plant salves to the windblossom. It immediately begins to shed its corrupted form, blossoming into a vibrant and healthy plant.',
    `RequestItemsText` = 'You have found a sickly, corrupted version of what appears to be a windblossom plant. The berries that hang from the plant appear rotten and poisonous. It desperately needs some sort of attention if it is to be turned back to normal.'
WHERE `entry` = 998;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Greetings, $C.$B$BI am pleased to see the likes of you taking an interest in the well being of nature; tales of your mighty deeds precede you, and you are welcomed here. Seeing you before me instills the feeling of confidence that the Cenarion Circle will get the proper aid it needs.$B$BOur connection with the Cenarion Circle in Moonglade transcends racial and political divides. Remember this as you work on behalf of the Circle, and you will do well.',
    `RequestItemsText` = ''
WHERE `entry` = 1000;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Buzzbox hums to life soon after you place the Thresher Eyes inside. There is a moment of static before you hear a familiar tiny voice call out.$B$B"Crawler wine is the best..." *hic*$B$B"What? Oh, you fixed it already? Wow, you''re a fasht one. Sho, would ya like to fix another?"$B$BYou believe you hear a liquid being poured into a cup, followed by loud gulping sounds.',
    `RequestItemsText` = 'The machine''s hatch is open and it seems to wait expectantly for 3 Thresher Eyes to be placed inside.'
WHERE `entry` = 1001;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Buzzbox suddenly leaps into action, and you can hear the distinct sounds of teeth being ground to dust coming from within.$B$B"Sho, ya made it! Thatsh exshellent newsh... Sho... Why doncha move along? Oh! Unless you want another job!"',
    `RequestItemsText` = 'Though you have yet to place the 6 Moonstalker Fangs inside, you believe you hear the sounds of static and incoherent gnome ramblings coming from within. Could someone else have fixed the machine already?'
WHERE `entry` = 1002;

UPDATE `quest_template` SET
    `OfferRewardText` = '"Sho yash gotsh the scalps in? That''sh sho great... Wha? Well, yesh I shuppose ya have realized that I can speaksh to ya without the materials in the machine. But I was telling the truth when I shaid they were broken!$B$BSee, in addition to being communimacation toolsh, the Buzzboxes also brew and distill fine liquor. Shorry for any deceptshion, but the nightelves do not apprecimerate my liquor trade in their townsh. I put shomething special in thish box to show my gratitude for yer effortsh. Enjoy!"',
    `RequestItemsText` = 'You hear singing coming from Buzzbox 525.$B$B"Though crawler wine''s shweet, and thresher ale fine, and moonstalker moonshine ish grand. There''s nothing sho dear, as a thistle bear beer, and shoon I shall have shome on hand!"$B$BThe hatch is open and awaits the 4 grizzled scalps as you hear the song repeated over and over.'
WHERE `entry` = 1003;

UPDATE `quest_template` SET
    `OfferRewardText` = '',
    `RequestItemsText` = ''
WHERE `entry` = 1004;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found it! Thank you, $N!$B$BThe old city of Zoram holds many secrets, and this statuette may be the key to many of them.',
    `RequestItemsText` = 'Have you found the statuette, $N?'
WHERE `entry` = 1007;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very well done, $N.  Your actions in the Zoram Strand against the naga are commendable.$B$BI know your feat was not easily accomplished, for the strength and guile of the naga is well known to the night elves.  We know this, for we share a history with them.$B$BIt is a history I care not to repeat.',
    `RequestItemsText` = 'We cannot allow the naga to invade our coasts, $N.  It is vital that you go to the Zoram Strand and complete your mission.'
WHERE `entry` = 1008;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found the ring! Thank you, $N. Please take this as payment, and know that your deeds today will remain forever in my memory.',
    `RequestItemsText` = 'It is said that the Ring of Zoram is the key to any lock within the city. Do you have it, $N?'
WHERE `entry` = 1009;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, you have the hair!  Now I will mix a cure for the child, and pray my concoction works.$B$BAnd... Forsaken are at Bathran''s Haunt?  Very troubling to hear, that is.  Very troubling indeed...',
    `RequestItemsText` = 'Have you gathered the Bathran''s Hair, $N?  The child''s health grows weaker by the hour...'
WHERE `entry` = 1010;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good, $N. Now... by testing the contents of this bottle, the goals of the Forsaken will be revealed!',
    `RequestItemsText` = 'Did you find the camp, $N? Do you have a bottle of disease?'
WHERE `entry` = 1011;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I felt the anguish of the Dor''danil Barrows lessen, and knew you had completed your task.$B$BIt was grim work you did, $N, for the spirits you destroyed were merely victims of the Forsaken''s evil. But with their destruction, let us hope the other maddened spirits find peace.',
    `RequestItemsText` = 'The anguish of the Dor''danil druids still haunt my dreams, $N. You must destroy their leaders!'
WHERE `entry` = 1012;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good.  This book will add nicely to my collections of the workings of Ur.  His knowledge was great, but his conscience held him from true power.  And so when the Scourge came and his strength was tested, it failed.$B$BWe of the Forsaken cannot afford such weakness, if we are to survive...$B$B...If we are to conquer.',
    `RequestItemsText` = 'Did you find the book, $N?'
WHERE `entry` = 1013;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Silverpine Forest is finally free from the vice of that wretch Arugal. You have done the Dark Lady a great service, $N. Your tenacity shall be rewarded.',
    `RequestItemsText` = 'With Arugal''s death we stand to increase the Dark Lady''s stronghold on Lordaeron.'
WHERE `entry` = 1014;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What makes you think I wish to be pestered by the likes of you, $C? Wait - let me stop the important duties I attend to on a daily basis so I can help you locate a doodad somewhere. By all means, the welfare of Darnassus - nay, all of Teldrassil - should come second to the acquisition of a bauble for your collection.$B$BThe fools in Moonglade waste my time with their call for assistance, and now I must endure this?',
    `RequestItemsText` = ''
WHERE `entry` = 1015;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N, this should give us the information we need to have the culprit discovered. How would you feel about taking out the mage who fills our pools with corrupt elementals? The corruption of Ashenvale and beyond makes my stomach turn on its own--to have a wizard actively attempting to destroy it further sickens me to no end. We shall make him pay.',
    `RequestItemsText` = 'Since you must destroy the bracers to kill the elementals, it will probably be difficult to find the specific ones that contain the information the divining scroll needs. You can trade bracers with others in order to obtain the ones you need, or perhaps you have the divined paper already?'
WHERE `entry` = 1016;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now I can see that repugnant smile wiped from his face forever. You have done very well, $N. Take this, the Light of Elune, drink of it when all seems lost and death is near. It may save you, Goddess willing.',
    `RequestItemsText` = 'Is it done? Is Sarilus Foulborne dead?'
WHERE `entry` = 1017;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Greetings, $C.$B$BI am pleased to see the likes of you taking an interest in the well being of nature; tales of your mighty deeds precede you, and you are welcomed here.  Seeing you before me instills the feeling of confidence that the Cenarion Circle will get the proper aid it needs.$B$BOur connection with the Cenarion Circle in Moonglade transcends racial and political divides.  Remember this as you work on behalf of the Circle, and you will do well.',
    `RequestItemsText` = ''
WHERE `entry` = 1018;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What makes you think I wish to be pestered by the likes of you, $C?  Wait - let me stop the important duties I attend to on a daily basis so I can help you locate a doodad somewhere.  By all means, the welfare of Darnassus - nay, all of Teldrassil - should come second to the acquisition of a bauble for your collection.$B$BThe fools in Moonglade waste my time with their call for assistance, and now I must endure this?',
    `RequestItemsText` = ''
WHERE `entry` = 1019;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is from Orendil?$B$BHis skill with herbs and healing is great.  This cure gives me hope, when before I had little...',
    `RequestItemsText` = 'I must apologize, for I have no time to speak.  My child, Relara, is deathly ill!'
WHERE `entry` = 1020;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Judging by the gaping wound in her side, Anilia is on the verge of death.',
    `RequestItemsText` = ''
WHERE `entry` = 1021;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Tome of Mel''Thandris works in strange ways. The events it records, the events it shows... No one truly understands why it does what it does.$B$BNonetheless, it is clear that what Priestess Starsong received--this Scythe of Elune--bears further investigation.',
    `RequestItemsText` = 'The tome of the shrine is a mysterious object. It is not a book in the traditional sense. The leaves of the tome were blessed by Mel''Thandris herself, and records events of import in its pages.$B$BIt is hard for me to explain. If you go to the shrine, you will understand.'
WHERE `entry` = 1022;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is terrible, $N. Teronis is dead?!$B$BThe time for mourning will come, but for now we must focus our efforts. I shall send some of the Sentinels to recover Teronis'' body as soon as possible.$B$BYou have Teronis'' journal and the gem he was seeking. Do you think you''re capable of completing his task? I would rest much better knowing his death was not in vain.',
    `RequestItemsText` = 'Ah, welcome back, $N.'
WHERE `entry` = 1023;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, Raene sent you? It must be serious indeed. What can I help you with?',
    `RequestItemsText` = 'Hello. How are you?'
WHERE `entry` = 1024;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, $N. Thank you.',
    `RequestItemsText` = 'The furbolg were not always our enemy, $N. But times change, and it is no longer a time of peace here in these dark woods.'
WHERE `entry` = 1025;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I''m pleased to see you''re back, $N.',
    `RequestItemsText` = 'It upsets me so that the treants have become corrupt. I wish I could do more to help them.'
WHERE `entry` = 1026;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found the final piece? Wonderful for you... and for Raene.$B$BI guess we''ll have to see about repairing it, won''t we?',
    `RequestItemsText` = 'Did you find the final piece of the rod, $N?'
WHERE `entry` = 1027;

UPDATE `quest_template` SET
    `OfferRewardText` = 'After the glow dies, you can see the re-enchanted rod within the shrine''s basin.',
    `RequestItemsText` = 'You can sense a subtle yet powerful force within the shrine and surrounding trees.$B$BYou begin placing the rod within the shrine and a soft thrumming noise emits from around you as the shrine begins to glow...'
WHERE `entry` = 1028;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve recreated the rod Teronis had set out to find? That''s wonderful to hear.$B$BTeronis would be proud to see his quest is continuing even after his tragic passing.',
    `RequestItemsText` = ''
WHERE `entry` = 1029;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, yes... you are one of my kind, but still whole. Still clean.$B$BI am unsure how you have escaped the atrocities the night elves have visited upon our people, but I am glad to know that I am no longer alone.$B$BCorruption now runs through the veins of our kin, young one, corruption brought down upon us by the prideful night elves. They are the ones who did this to our people... They are the ones I blame for being cast out of my tribe.$B$BAt night I can still see the campfires burning in the darkness.',
    `RequestItemsText` = ''
WHERE `entry` = 1030;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Anilia died? No... that can''t be! It was just yesterday that we were running and playing together in the woods.$B$BI guess those days are over...',
    `RequestItemsText` = 'Have you found them? What did Anilia say? Where is she?'
WHERE `entry` = 1031;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, kind $R. My sister''s spirit is gladdened by your efforts.',
    `RequestItemsText` = 'Please, help me avenge Anilia''s death.'
WHERE `entry` = 1032;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, you found it! I will place the tear in a stew, and pray that it will cure her.$B$BThank you! Thank you, $N!',
    `RequestItemsText` = '$N, did you find Iris Lake? Do you have the Tear?'
WHERE `entry` = 1033;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You gathered the dust! I will create a poultice from these -- it should bring down Relara''s fever.$B$BThank you again, $N. Without your help, my child would surely perish.',
    `RequestItemsText` = 'Do you yet have the Stardust, $N?'
WHERE `entry` = 1034;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, $N, you have saved my daughter! I know the power of the moonstone will give back my daughter her strength!$B$BI can never repay you fully for the aid you have given me, but... please, take this. Other than Relara, it is my most dear possession.',
    `RequestItemsText` = 'Did you face the Shadethicket Oracle, $N? If so, then please hand me the fallen moonstone. Relara has strength left for only a few more breaths!'
WHERE `entry` = 1035;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Avast ye, scallywag. I hears that ye be the type for a bit o'' the skullduggery. Well, if yer no friend of Booty Bay, then ye might have a special place with the Bloodsail Buccaneers.$B$BArrrrr...',
    `RequestItemsText` = ''
WHERE `entry` = 1036;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Velinde Starsong? That the priestess disappeared some time ago is almost certainly common knowledge. As to further details about the events that surrounded her departure... it would take good reason for me to divulge such information.',
    `RequestItemsText` = ''
WHERE `entry` = 1037;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It seems that Velinde''s disappearance is more troubling than it originally appeared. Even still, I cannot believe that she has come to a bad end. Perhaps it would be beneficial for us to make contact with her.$B$B$N, since you have shown a vested interest in this matter, I would like to enlist your aid.',
    `RequestItemsText` = 'What''d you find out?'
WHERE `entry` = 1038;

UPDATE `quest_template` SET
    `OfferRewardText` = '$R, eh? Must admit, we don''t get much of your type out here. Looking for someone, eh? Just give me a moment, I''m sure I have it written in one of my ledgers.$B$BLot of people travel through here, though, so just give me a moment.',
    `RequestItemsText` = ''
WHERE `entry` = 1039;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes? Now, it doesn''t look to me like you''re the sort with goods that need shipping, so either you''re looking for a job with my caravan--and there''s no jobs to be had now--or you''re probably talking to the wrong goblin.$B$BSo which one is it?',
    `RequestItemsText` = ''
WHERE `entry` = 1040;

UPDATE `quest_template` SET
    `OfferRewardText` = 'With all the strange happenings of the last few years, I keep as good records of strangers as I can. Never know when it might come in handy... though it''s usually not pleasant business when it does. Not to suggest anything about this Velinde you''re looking for.',
    `RequestItemsText` = ''
WHERE `entry` = 1041;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Dark times these are. Ill news is whispered from every swaying branch, and evil can be found under every rock.$B$BAnd in such times an unknown stranger enters my home and asks of worgen... I''ll ask no forgiveness for my suspicions, only answers.$B$BAnd answers, I will have.',
    `RequestItemsText` = ''
WHERE `entry` = 1042;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is an interesting story you tell, $N. Though the Carevin family''s influence is not large enough that we might find the root of these troubles and finish them once and for all, we will do what we can to contain the worgens'' numbers in Duskwood.$B$BAlready I have instructed Calor to make this his first priority.',
    `RequestItemsText` = 'The woods are perilous for the unprepared. Keep your weapons close at hand and your wits even closer, or your next journey into the haunted forest may be your last.'
WHERE `entry` = 1043;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So this is the fate of Velinde, is it? The high priestess will be disappointed to hear of this, they were good friends before her disappearance. Still, the Scythe of Elune was surely granted to her as a boon by our goddess, and it is unsettling to me that it has fallen out of her servants'' hands.$B$BAnother matter for another time, however. I owe you my thanks in no small amount for what you have accomplished.',
    `RequestItemsText` = ''
WHERE `entry` = 1044;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, my friend.$B$BThe forest is still tainted, but at least we know we have done a small part to return it to its former glory. If you wish to return to me again, I would enjoy the company of my own kind.$B$BBe well. Perhaps our tribes will meet again under less violent times.',
    `RequestItemsText` = 'Have you slain Ran yet, my friend?$B$BEven the Night elves do not truly deserve his wrath. His hatred burns even brighter than my own, but his mind is no longer his own. He is a threat to all the natural creatures of this forest.'
WHERE `entry` = 1045;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, this is the skull of the fiercest furbolg threat in Ashenvale?$B$BI am more than pleased with your abilities, $N. The Sentinels cannot thank you enough. I hope we can rely on you again in the future to help our people.$B$BI shall put this skull and Dartol''s Rod in a place of reverence for others to see.$B$BTeronis would be proud. Thank you again.',
    `RequestItemsText` = 'The Sentinels do what they can here in Ashenvale, but it''s thanks to $Rs like you that we have gained the ground we have.'
WHERE `entry` = 1046;

UPDATE `quest_template` SET
    `OfferRewardText` = '',
    `RequestItemsText` = ''
WHERE `entry` = 1047;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have served the Dark Lady well, $C. ''Twas no small task I asked of you.$B$BYour loyalty to the Forsaken has been noted. And your tenacity in combat will be remembered.',
    `RequestItemsText` = 'Perhaps I was not explicit in my orders, $C. I want High Inquisitor Whitemane killed once and for all. And while you''re at it, take out her top brass as well.$B$BKill that zealot, Scarlet Commander Mograine. Lay waste to Herod, the Scarlet Champion. And slaughter Houndmaster Loksey and his filthy mutts too.$B$BNow begone!'
WHERE `entry` = 1048;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Compendium of the Fallen! I was beginning to wonder if the very book existed!$B$BYou have served the tauren of Thunder Bluff well, $N. Your dedication shall not be forgotten.',
    `RequestItemsText` = 'Cairne is a brave and noble leader and I would trust him with my own life. But it is others that I do not trust in this political climate.$B$BOnce I have a chance to gather all the knowledge available I can provide sound council to the Chieftain.$B$BHave you had a chance to travel to Tirisfal Glades? To the Scarlet Monastery? The Compendium of the Fallen is just one piece in this complicated puzzle...'
WHERE `entry` = 1049;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have rescued the sacred text!$B$BYour journey was long and acquiring the book was undoubtedly no easy task. But the dwarves of Ironforge stand to benefit from your success.$B$BThank you, $N, on behalf of the Explorers'' League.',
    `RequestItemsText` = 'The Monastery was a seminary for Paladins-in-training. Once a stronghold of the Light, it fell into the hands of the crazed zealots of the Scarlet Crusade.$B$BThe Crusade believed their goal a noble one: to purify the land of the undead plague. But insanity tainted their plight and now they stand enemies to all.$B$BBring Mythology of the Titans to me so I can study it and house it here in Ironforge.$B$BThe corrupt halls of the Monastery are no place for such a historical treasure.'
WHERE `entry` = 1050;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Vorrel led such a troubled existence. And what a good mate he was...$B$BDamn those filthy humans!$B$BVorrel is gone, never to enjoy undeath again. At least I can take solace in the revenge you took in his name. For that I thank you.$B$BNow let me be to mourn....',
    `RequestItemsText` = 'What do you want, stranger?'
WHERE `entry` = 1051;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Brother Anton still spreads the word of the Scarlet Crusade? Oh my....',
    `RequestItemsText` = 'Who goes there? What do you want from me?'
WHERE `entry` = 1052;

UPDATE `quest_template` SET
    `OfferRewardText` = 'While disciples of the Light never revel in the loss of life, we must accept that on occasion, such sacrifices must happen for the greater good of the Kingdom and the planet.$B$BThrough your deeds in the Monastery you have spared many innocent lives, $N. I salute your tenacity.',
    `RequestItemsText` = 'The corruption in the Monastery will not end until the highest ranking officials have been removed.$B$BIn the name of the Light, slay High Inquisitor Whitemane, Scarlet Commander Mograine,  Herod, the Scarlet Champion and Houndmaster Loksey. Once they have fallen, perhaps the true cause can be rekindled. Until then, anyone who crosses the path of the Crusade lies in peril.$B$BVenture forth from Southshore and make it so!'
WHERE `entry` = 1053;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N.$B$BWe are under constant threat from the furbolg. Hopefully this will keep them at bay for a bit longer.',
    `RequestItemsText` = 'The furbolgs'' corruption has caused Ashenvale to become a fraction of its former glory.'
WHERE `entry` = 1054;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done it, $N! Well done!',
    `RequestItemsText` = ''
WHERE `entry` = 1055;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Alas, you arrive. I see Faldreas has listened to the forest spirits...',
    `RequestItemsText` = ''
WHERE `entry` = 1056;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now that the Bloodfuries have suffered such a great loss, perhaps the true work of restoring the land can begin....',
    `RequestItemsText` = 'There is much work to be done before the Charred Vale can be restored to the lush forest it once was.$B$BClear the area of those foul menaces, $N! Only then can we begin to reclaim what belongs to nature.'
WHERE `entry` = 1057;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh how happy these little woodland nymphs shall be! We''ll make them feel right at home with this special concoction!',
    `RequestItemsText` = 'Look at our poor little elf friends. All caged up with no forest to frolic in!$B$BNow were you able to find me some sap? How about the whiskers from the twilight runners? Don''t suppose you have that fey dragon scale on you?$B$BAnd eyes! I''ll need so many eyes! You just can''t mix up a fierce forest magic brew without a good helping of eyes!'
WHERE `entry` = 1058;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Keeper Albagorm was wise to send you with such urgency.$B$BLet us see if we cannot call forth aid from the great forest to travel to the Charred Vale before it is too late.',
    `RequestItemsText` = ''
WHERE `entry` = 1059;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, a letter from Darsok. I have not heard from him in many years.$B$BSo the last of the Bloodfeathers are dead, eh? That is good news, I can remember when my friend Rokhan went with that crazy mok''nathal to kill her older sister. Ah, to be young again, like you.',
    `RequestItemsText` = 'You seem a shady character. You have something for me to see?'
WHERE `entry` = 1060;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, a $C. Very good. We will need your skills to deal with these plunderers!',
    `RequestItemsText` = ''
WHERE `entry` = 1061;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Bravely done, $N.$B$BWe may ultimately need the wisdom of tauren elders to calm the spirits of Stonetalon, but...$B$BRidding the Venture Company of its personnel is a good first move against them.',
    `RequestItemsText` = 'The Greatwood Vale lies to the northwest, $N.  Go.  Strike fear into those who would pillage this land!'
WHERE `entry` = 1062;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I bid you greetings.  You are here seeking counsel?',
    `RequestItemsText` = ''
WHERE `entry` = 1063;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Magatha sent word of your coming, $N.  Although my heart beats no longer, I still feel sorrow for the spirits of Stonetalon.$B$BThe Forsaken are eager to offer what help we can.',
    `RequestItemsText` = ''
WHERE `entry` = 1064;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A note from Zamah? Her needs must be great to send word from so far. Let us see what she says...$B$BAh, splendid! I know exactly what to do!',
    `RequestItemsText` = 'Ah, are you here with my new test subjects?'
WHERE `entry` = 1065;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good!  I trust the Syndicate gave you little trouble?$B$BAs I mentioned, the blood of innocents is not an easy thing to obtain.  We are lucky the Syndicate shadow mages did the difficult work for us.$B$BNow hold a moment while I create my concoction...',
    `RequestItemsText` = 'Did you find the Syndicate Shadow Mages, and collect from them the blood?'
WHERE `entry` = 1066;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A toxin from Apothecary Lydon? Very good. If I know Lydon, then this toxin will be quite effective against the Venture Company...',
    `RequestItemsText` = 'You have returned, $N. Do you bring aid from Apothecary Lydon?'
WHERE `entry` = 1067;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The destruction of the machines XT:4 and XT:9 have soothed many of the spirits of Stonetalon, $N.  With their loss, let us hope the Venture Company will remove itself from these mountains.$B$BFor if they do not, then I fear the atrocities this place has suffered will pale to what lies ahead.',
    `RequestItemsText` = 'The tree spirits wail at the loss of their brethren, $N.  You must destroy the shredders XT:4 and XT:9, or I fear Stonetalon will never be healed.'
WHERE `entry` = 1068;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You got them!  Thank you!$B$BI''ll have these sent to Dizzywig and get them shipped to Booty Bay.  I can already taste the profits!$B$BHere is your cut, $N.  I couldn''t have made this deal without you.',
    `RequestItemsText` = 'Did you get the eggs, $N?  I already made a shipping deal with Wharfmaster Dizzywig!'
WHERE `entry` = 1069;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, you''ve come from Ashenvale at the behest of Thenysil -- how I miss her, my homeland and friends. She must be doing well with the Sentinels to be sequestering adventurers for other tasks. I''m proud of her.$B$BIt is a pleasure to meet you, $N.',
    `RequestItemsText` = ''
WHERE `entry` = 1070;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thanks so much for your help, $N. You''re actually back just in time.$B$BI think I''ve got the perfect plan. Explosives. No, that''s not the plan, but it''s part of the plan.$B$BSee, I''ve been using high explosives--don''t worry, they''re not as dangerous as everyone thinks--to scare the goblins back a bit. I can herd ''em pretty good with a few key detonations along the mountains'' edges, but I''ve been low on supplies now for a few days.',
    `RequestItemsText` = 'How goes the battle on your end, $N?'
WHERE `entry` = 1071;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahhh. Gaxim sent you, huh? How do I know you''re not lying to me?! Hmm? Hmm?',
    `RequestItemsText` = ''
WHERE `entry` = 1072;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This''ll do nicely.$B$BIf I didn''t know better, stranger, I''d say you knew somethin'' about alchemy. Good, good... the world''s not all about swords and sorcery, you know?',
    `RequestItemsText` = 'I can''t make any Nitromirglyceronium if I don''t have the potions... they''re vital to its creation.'
WHERE `entry` = 1073;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your task has been done flawlessly, $N.$B$BNG-5 is the unequivocal component in the recipe to ignite the wagons of dynamite.$B$BWhat? Yes, dynamite... wagons of it. It''s the perfect distraction, I tell you... just wait and see.',
    `RequestItemsText` = 'Ah, goodie goodie, you''re back.'
WHERE `entry` = 1074;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now, this spell you need; one that will allow you detonate explosives from a distance... hmmm.',
    `RequestItemsText` = ''
WHERE `entry` = 1075;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Allow me just a few moments and I shall have your scroll ready for you.',
    `RequestItemsText` = 'Hello, $N. Have you found the component I need?'
WHERE `entry` = 1076;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is perfect, $N! Well done.$B$BThis spell, mixed with the NG-5, shall make the perfect remote explosive.$B$BWe''ll be able to create the perfect distraction for you so you can sneak in and steal the Venture Co.''s letters and engineering plans.$B$BThat will surely slow down their deforestation acts.',
    `RequestItemsText` = 'Haha! you''re back! Do you have it? Do you have the spell?'
WHERE `entry` = 1077;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is perfect, $N. Thank you greatly.$B$BPerhaps one day in the future I''ll be able to help you as you have helped me.',
    `RequestItemsText` = 'Hello again, $N.$B$BHave you already returned from the Vale in Stonetalon with those scales?'
WHERE `entry` = 1078;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Truly amazing! This is a huge blow to the Venture Co.$B$BWe''ll be able to find weaknesses in their machines and also incorporate their designs into our own creations. This is a wonderful day, indeed.',
    `RequestItemsText` = 'Did you get the plans, $N?'
WHERE `entry` = 1079;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Incredible, $N! Kaela and the Sentinels will be so happy. With your skill and my creations, we''re unstoppable.',
    `RequestItemsText` = 'How''d it go, $N?'
WHERE `entry` = 1080;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hello, $N. I have indeed heard your name before, and although you are still full of youth, I am pleased to see the path you have set for yourself.$B$BYou would do me a great honor if you would accept this as a gift of appreciation.',
    `RequestItemsText` = ''
WHERE `entry` = 1081;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. You have done a service to the Sentinels.$B$BI''m glad to see Kaela... and even Gaxim, are doing well.$B$BYou''ve earned our appreciation.',
    `RequestItemsText` = ''
WHERE `entry` = 1082;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The remains of our enemy... your strength serves us well, $N. Thank you.',
    `RequestItemsText` = 'The first time I saw the Charred Vale I almost wept, $N.'
WHERE `entry` = 1083;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N.$B$BThis should be more than sufficient for Gaxim to figure out how the treants were corrupted. I shall give this to him right away.',
    `RequestItemsText` = 'I have a feeling Gaxim will find a use for the shrapnel regardless of how the Venture Co. has used it in the past.'
WHERE `entry` = 1084;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Treacherous...treacherous and dangerous, that''s what this land is.$B$BBut I''m here to show the night elves that it''s a little safer with the help of good ole engineering and a dash of magic.$B$BSee, swearing off magic completely won''t help the night elves -- they need it. The world needs it. And with engineering and alchemy to boot, you can''t go wrong. The possibilities are endless.',
    `RequestItemsText` = ''
WHERE `entry` = 1085;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found the port? Well done, $N! I am sure the goblins were quite surprised from your delivery! Let us hope that toxin finds its way to their headquarters.$B$BYou have served your people well, and I advise you to ignore any guilt you might harbor for poisoning the Venture Company. They are deserving of far worse.$B$BAnd if there is one mote of wisdom the Forsaken might teach its allies, it is this:$B$BDo not shy from dark paths... if those paths lead to victory.',
    `RequestItemsText` = 'You must find the Venture Company airport if it exists, $N.'
WHERE `entry` = 1086;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Already I can feel it... yes... power so sweet... the rushing flood. The kaldorei are foolish to spurn the gifts of this world, to reject the coursing of magic as it flows singing through your veins.$B$BWhat a pale mockery life is without its burning embrace!',
    `RequestItemsText` = 'Here, channeling magic is like drawing water from a well with a bucket full of holes.'
WHERE `entry` = 1087;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I knew Ordanus once, long ago. He had the arrogance of his kind, holding himself above even the Highborne.$B$BHis head does not rise so high now, does it, $N?$B$BI promised you a reward, and you shall have it. Attend to me.',
    `RequestItemsText` = 'When my master bade me to the peak of Stonetalon, I expected that all I would need was to lay waste to the night elves that crawled the sacred ruins of our ancient temple of Azshara, their touch despoiling its sanctity... but Ordanus had slipped my grasp.'
WHERE `entry` = 1088;

UPDATE `quest_template` SET
    `OfferRewardText` = 'As the three keys are slid into their matching openings, in the middle of the glowing light a number of items appear.',
    `RequestItemsText` = 'Three keyholes are carved into the stone.'
WHERE `entry` = 1089;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thanks, $N. It was looking a little dicey there for a second and we''ve probably drawn far too much attention to ourselves.$B$BThe important part is that we have the ore sample, though, and we should get it to Ziz as soon as possible.',
    `RequestItemsText` = ''
WHERE `entry` = 1090;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is interesting indeed.$B$BYou and Gaxim have done very well, $N. Thank you.',
    `RequestItemsText` = 'Yes, $N? What can I do for you?'
WHERE `entry` = 1091;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahhh, I knew that I did the right thing by telling Piznik to stay behind. I''m sure the engineers in Undermine will be most interested to look at this...$B$BOf course I''ll want to keep a little piece for myself, but what they don''t know won''t hurt them, yes?',
    `RequestItemsText` = 'Something I can help you with?'
WHERE `entry` = 1092;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hey, is that what I think it is? Great!$B$BNow, let''s see. Ugh... how am I supposed to understand this stuff... can''t figure out the way gnomes think. Lemme tell you, I''m surprised they could build the wheel, let alone those flying machines they like so much.',
    `RequestItemsText` = 'Did you find those plans? I''m eager to impress the new boss. Hopefully, once he''s convinced of my loyalty--well, as much as he can be convinced... goblin''s honor, you know?--he''ll feel comfortable making use of my rather impressive genius.'
WHERE `entry` = 1093;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Fizziks, eh? Can''t say I trust him, but this information seems good enough. What I wouldn''t give to have the Venture Company out of my hair.$B$BThey do come up with some good machines though... I can''t deny that we''ve benefited from using some of the improvements they''ve devised.',
    `RequestItemsText` = 'Hello there! How can I help you?'
WHERE `entry` = 1094;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Eliminate Gerenzo? Now there is a prospect that I have no objections to.$B$BGnomes are bad enough as it is, but what I learned about Gerenzo only makes it worse. Apparently, he was one of the head engineers in Gnomeregan, where he was working on their secret project--we could never infiltrate Dun Morogh well enough to find out specific details. It was a failure. Our reports say that whatever it was literally exploded in their faces.',
    `RequestItemsText` = ''
WHERE `entry` = 1095;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Look at that thing... it''d take a gnome to come up with something like that. I can''t understand why you''d cut off an arm, and replace it with that, when you could just keep both arms and add a third!$B$BGnomes, I tell you...$B$BAt least Gerenzo''s out of commission. Hopefully that''ll be enough proof, and Sputtervalve will assign me to one of the Tinkers'' Union workshops in Gadgetzan or maybe even Undermine.',
    `RequestItemsText` = 'Sputtervalve will want some sort of proof that Gerenzo''s dead. I think his mechanical arm will probably do.'
WHERE `entry` = 1096;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''re here to help with my delivery?  Very good!',
    `RequestItemsText` = ''
WHERE `entry` = 1097;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Vincent''s body lies broken, and still.$B$BAlthough Deathstalker Adamant will send his report to Hadrec... whatever additional details Vincent gained must remain with him.$B$BBut clutched in his hand is a small trinket...',
    `RequestItemsText` = ''
WHERE `entry` = 1098;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You say you found this journal on a deceased dwarf? Give me but a moment to peruse the pages...',
    `RequestItemsText` = 'From your look of concern, I can tell that something is amiss....'
WHERE `entry` = 1100;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The crone has been laid to rest. This is fantastic news, $N.$B$BIn these times of peril, it is refreshing to see one as brave as yourself.$B$BWith Razorflank''s minions taken care of, our studies in the area can continue. Perhaps now we can gain further knowledge of exactly what happened to corrupt the resting place of Agamaggan.$B$BHowever, I fear the answer to that question lies in treachery as well...',
    `RequestItemsText` = 'So long as Charlga Razorflank is mustering a force in Razorfen Kraul, these lands are in great danger.'
WHERE `entry` = 1101;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I see the nasty tribe of Razorfen Kraul now knows the pain of my people. Serves the foul beasts right.$B$BTo drive one from a holy land is a sin worthy of the most severe revenge.$B$BThank you, $N, for aiding me in my plight.',
    `RequestItemsText` = 'Once I know the foul beasts of Razorfen Kraul have been driven from their foul lair, I will be able to rest in peace, knowing that revenge has been served.$B$BHave you the driven the quilboar from the Kraul? Do you bring to me good news in the form of Razorflank''s heart?'
WHERE `entry` = 1102;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahhh, den yur ready...$B$BI''ll put me items in the brazier den, and you c''n talk wit'' da spirit too.$B$BAn'' dontchu worry none ''bout seein'' into da spirit world wit'' da sapta... ol'' Tiev know a trick or two ''bout how da sapta magic works.$B$BCome now, head down wit'' me to the shrine and let''s speak to da spirits together, brotha.',
    `RequestItemsText` = 'Ya have the sapta, brotha?$B$BI know another that had trouble after defeating da corrupt water spirit--seems he waited too long and he came out of the spirit world too quick fer his taste. Hate to see dat happen to another, so I''ll just wait here fer a bit to make sure no one else be needin'' me help.'
WHERE `entry` = 1103;

UPDATE `quest_template` SET
    `OfferRewardText` = 'All right!  This venom is going to work great!  Thanks, $N!$B$BNow I just need to boil it down, apply skipper-otomer, add a nega-catalyst, and... Drat!  Where are my notes!?',
    `RequestItemsText` = 'Hi hi hi!  Did you get that venom??'
WHERE `entry` = 1104;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You got them!  Thanks, $N!$B$BWow, these shells are harder than I thought!  Heh, when I work with them I''ll probably bend a whole box full of tools!',
    `RequestItemsText` = 'My brother is making progress with his new fuel design, and that has me worried.  I need to start work on a tortoise shell fuel tank as soon as possible!$B$B$N, do you have those shells yet?'
WHERE `entry` = 1105;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Fizzle sent you? Well that changes things! Of course I''ll help you. Fizzle and his brother are two of the few people who don''t want me dead!$B$BSo Fizzle wants to make pistons, eh? Pistons strong enough to take whatever stresses he has planned, and if I know Fizzle, then this new car of his is a volcano on wheels!',
    `RequestItemsText` = 'Well, you found me. Good for you.$B$BAre you here about that axe I made for Gath''Ilzogg? Or are you here to reclaim Duchess Pamay''s honor?$B$BActually, I don''t care which it is. If you''re here to fight, then let''s get it over with...'
WHERE `entry` = 1106;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N! After I grind these down and fuse them with a few other ingredients, the composite will be ready. And after that, the car will be safe from its own speed.$B$BSafe, as long as it doesn''t hit anything...',
    `RequestItemsText` = 'Do you have the tail fins?  If I can''t protect our car from its own speed, then it won''t last long in these races.'
WHERE `entry` = 1107;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah yes, these will do fine. Now let''s put them in some heat and see how they fare...',
    `RequestItemsText` = 'Did you find any indurium flakes, $N. I have my forge heated up and ready to test them.'
WHERE `entry` = 1108;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Splendid! This is just the start we needed, $N.',
    `RequestItemsText` = 'Ah, I see you have returned. Were you able to procure any Kraul Guano?'
WHERE `entry` = 1109;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Whoa, look at all that!  There''s some good stuff in that heap of junk.  I''m sure I can pawn it off for a hefty sum.$B$BAnd... is that an ear I see squashed between those two sheets of metal??  Ouch!  Heh, I sure wouldn''t want to be that pilot!$B$BThanks, $N.  Here''s your pay.  And here''s some advice, free of charge...$B$BIf you look hard enough, you can always find profit in someone else''s tragedy.',
    `RequestItemsText` = '$N, have you been out into the Flats?  Did you bring back that load of parts I wanted?'
WHERE `entry` = 1110;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh yes.  Parts for Kravel.  I''m glad you''re here.  These things have been sitting out here for days, and I was afraid they''d rust!',
    `RequestItemsText` = 'Speak up!  Tell me, are you dropping off or picking up?'
WHERE `entry` = 1111;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great, you got them!  Now we need to get them to the gnomes.  But first...$B$BLet''s take out one small item...',
    `RequestItemsText` = 'Did you make it to Ratchet and get those parts?'
WHERE `entry` = 1112;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My what an abundance of gore you have brought me, $N! Your efforts have been most excellent!',
    `RequestItemsText` = 'Have you returned from the Scarlet Monastery? I''ll need many hearts for this delightful experiment!$B$BNo doubt, Varimathras and the Dark Lady will be pleased to be rid of the Scarlet Scum as well...'
WHERE `entry` = 1113;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There they are!  My hydro ratchets and repeater bolts!  These will do just fine.  Thank you!',
    `RequestItemsText` = 'You have something for me?  That''s great!  let''s see it!'
WHERE `entry` = 1114;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You want to know about Nazz Steamboil? He''s a racer pilot out in the Shimmering Flats, isn''t he?$B$BYeah, I might be able to find something out about him... but it won''t be easy. Or fast.$B$BOr cheap.',
    `RequestItemsText` = ''
WHERE `entry` = 1115;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, look at that. You found the dream dust!$B$BAnd how did you like the swamp, $N? It''s not easy to get a hot meal there, is it?',
    `RequestItemsText` = 'Back so soon? Do you have my dream dust?'
WHERE `entry` = 1116;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well well! This is interesting... very interesting. Heh, perhaps I should bow to the goblin pilot the next time I see him.$B$BThis is worth plenty, $N. I''m sure Nazz will pay a small fortune to keep his secret... a secret.',
    `RequestItemsText` = 'Did you get anything on Nazz Steamboil? Anything he might want to keep a secret??'
WHERE `entry` = 1117;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I see. Kravel has a big scheme planned. He has a sinister mind -- I like that about him.$B$BSo you''ll need something to addle wits, eh? Something powerful...$B$BI wonder if the mixture Zanzil feeds his zombies could be used...',
    `RequestItemsText` = 'Hello hello. And what brings a noble $R such as you down to Booty Bay?'
WHERE `entry` = 1118;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wonderful! Fizzlebub came through! I''ll remember that next time I see him.$B$BAnd thank you, $N. You''re doing a great job, and we both stand to make a lot of money from this...',
    `RequestItemsText` = 'Hello, $N. Was Fizzlebub able to help us?'
WHERE `entry` = 1119;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Stout? How considerate! Thank you!$B$BWe shouldn''t be drinking with the race coming up, but... maybe my boys could do with just a little. Besides, it can''t be that strong, can it?',
    `RequestItemsText` = 'Hi! You have something for me?'
WHERE `entry` = 1120;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What do we have here? Booze, eh?$B$BWell, I don''t mind if we have just a little...',
    `RequestItemsText` = 'What are you looking at?'
WHERE `entry` = 1121;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It says here that the fool''s stout was a success. That''s good news!$B$BIf you ever want more of the stuff, then let me know and I''ll have you gather more of Zanzil''s Mixture.',
    `RequestItemsText` = 'Hello $N. How''d that stout work out? It''s strong stuff, isn''t it?'
WHERE `entry` = 1122;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I am Rabine Saturna, and on behalf of Keeper Remulos and all of the denizens of this sacred glade I bid you welcome.$B$BI appreciate your interest and eagerness to assist the Cenarion Circle. The tauren have shown an incredible propensity to the tenets of Cenarius, and by their proxy the Horde is welcomed within the safety of this glade. The preservation of Azeroth is a common goal we both share.$B$BYou are among friends here, $N.',
    `RequestItemsText` = ''
WHERE `entry` = 1123;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Rabine sent you, did he? Well, consider yourself welcomed here... as much as this desolate and forsaken land can welcome someone.$B$BI wasn''t alive during the time of the great tribulations that took place here, but there are parts of this desert that might as well be eerie pictures of that forgotten past. With your help, the Cenarion Circle might be able to bring finality to a threat that was supposed to have died generations ago.',
    `RequestItemsText` = 'This is a dangerous land to be so casual, $C. What brings you to the wastes of Silithus?'
WHERE `entry` = 1124;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I had thought that maybe the huge swirling hive near the ruins of the village had played a part in its demise. It would seem that your work has proven this to be correct; the proximity of the hive poses a threat to any future work we may do here.$B$BI thank you for your benevolence in freeing the souls of the fallen; such work is never easy, I know. When you''re ready, however, I''d like to ask for your assistance once more...',
    `RequestItemsText` = 'Alliance or Horde, it doesn''t matter - no being deserves to be trapped on this world as a tortured spirit.  The freeing of these souls will make things right, $N.'
WHERE `entry` = 1125;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What the... what is it?$B$BIt has the shape of a... box, maybe? It''s encrusted over something fierce. Wait, there a portion here that''s exposed... is that a book underneath all this gunk?$B$BI think you''ve stumbled across quite the find here, $N... well, at least I hope it is. Perhaps it is a journal or a log from ancient times, preserved in this shell.$B$BI think I know a way to find out what this is.',
    `RequestItemsText` = 'Well, did it work? You''re still in one piece, which is good news. Did you find anything?'
WHERE `entry` = 1126;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, very good! Here is your pay.$B$BAnd here is a little something extra... for your discretion.',
    `RequestItemsText` = 'Do you have those Zanzil mixtures yet, $N?'
WHERE `entry` = 1127;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, $N, you have come.  Now, are you prepared to journey through distant lands?$B$BIf so, young $C, then listen on...',
    `RequestItemsText` = ''
WHERE `entry` = 1130;

UPDATE `quest_template` SET
    `OfferRewardText` = 'In defeating the creature Steelsnap, you have cleansed the Thousand Needles of a horrible taint.$B$BAnd that, $N, is your lesson this day.',
    `RequestItemsText` = 'Have you defeated the foul Steelsnap, $N?'
WHERE `entry` = 1131;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good day to you! You were sent by Mr. Flint in Menethil Harbor? Well Mr. Flint is a strong judge of character. If he sent you, then there''s no doubt you belong here in Kalimdor!',
    `RequestItemsText` = ''
WHERE `entry` = 1132;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You are here to offer your services to the Alliance, $N? We welcome the aid, for although its beauty remains... Ashenvale Forest is not the peaceful place it once was.',
    `RequestItemsText` = ''
WHERE `entry` = 1133;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. It saddens me to order the slaughter of creatures who may not willingly aid our enemies, yet it is my duty to do so.$B$BYour heart might weep for the pridewings you slew, my friend, but may your heart then swell in knowing that your allies are safe from the pridewings'' venom.',
    `RequestItemsText` = 'Do you have the pridewing venom sacs, $N? We cannot allow the orcs to use the beasts'' poisons against us!'
WHERE `entry` = 1134;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, most of these are nearly bursting with venom, $N. Such are normally only gathered from young wyverns, or fertile females. It must have been quite a slaughter up there in Highperch!',
    `RequestItemsText` = 'Did you find Highperch, $N? Any luck with the wyverns there?'
WHERE `entry` = 1135;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Both strength and cunning were needed to find and defeat Frostmaw, $N.  You have both.$B$BYour path has taken you to the valleys of Thousand Needles and to the high mountains of Alterac.  It will one day lead you through all the Earthmother''s lands, for such is the way of the hunter.',
    `RequestItemsText` = 'Have you been to the Alterac Mountains, $N?  Did you face the elusive Frostmaw?'
WHERE `entry` = 1136;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N, you''re back! You found Martek? You spoke with him? What did he say? Can he help??$B$BTell me, tell me, tell me!!',
    `RequestItemsText` = ''
WHERE `entry` = 1137;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wow, these fine crab chunks are what I need.  Thanks $N!  I found this while I was fishing a while ago, and I have no use for it.  Maybe you can do something with it.  It sure don''t make any good crab dishes.$B$BI told you all about crabs, right?',
    `RequestItemsText` = '...lemon crab, whipper root crab, and Ironforge surprise crab.  That''s about it.$B$BOh, hello there $N.  Do you have them fine crab chunks I was telling you about?'
WHERE `entry` = 1138;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Advisor Belgrum shakes his head in disbelief as you hand him the stone shard.>$B$B$N, this is amazing. I shall have this brought to the king''s mages as soon as possible. They will want to study it to find out if the legends are true. But that is a discussion for another time: you have aided our people more than I would have ever expected--thank you.',
    `RequestItemsText` = 'Hammertoe''s quest must be actualized, $N. I owe him that much.$B$BYour return to Uldaman is imperative not only to that goal, but also to the safety of all dwarven kind. With the tablet in the hands of the Dark Irons who knows how powerful their army of golems would become.'
WHERE `entry` = 1139;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Perhaps the satyrs have been allowed to persist in the forest for too long. I will speak with Elissa about it when next I travel to Auberdine.$B$BNonetheless, with the soulgems destroyed, Athrikus'' power will be greatly diminished. We must seize on this opportunity to eliminate him and his cult.',
    `RequestItemsText` = 'I heard whisper once that the satyrs'' history is somehow related to that of the night elves, but I have found my esteemed hosts reticent to speak of the matter.'
WHERE `entry` = 1140;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Them''s some real nice groupers, $N!  Thanks for helping me out!$B$BYou''re at least as good of a fisherman as my cousin, Graun Blump.  She also has a beard and she smells kinda funny, but that don''t do nothing to stop her fishing.  I reckon you have what it takes to use a Blump Family Fishing Pole.',
    `RequestItemsText` = 'There''s plenty of good dishes you use Darkshore groupers for.  They''re good to eat, but I think it''s more fun catching them.$B$BYou caught any Darkshore groupers yet?'
WHERE `entry` = 1141;

UPDATE `quest_template` SET
    `OfferRewardText` = 'No!$B$B''Tis not fair. Oh, cruel and intolerable world!$B$BI must now carry this burden of grief and not let Heralath''s work die with him.$B$BYou were brave to journey from such a dangerous place, $N. But please leave me now.$B$BIn solitude I shall mourn.',
    `RequestItemsText` = 'What brings you to my home, $R?'
WHERE `entry` = 1142;

UPDATE `quest_template` SET
    `OfferRewardText` = 'With the death of Athrikus, I hope that the demonic forces in this area will be driven back. I have no doubt that they will regroup and return, but then we shall be even more prepared to meet their threat.',
    `RequestItemsText` = 'Athrikus Narassin is an ancient and powerful warlock. Perhaps we should wait for Delgren''s assistance, but he obviously had much faith in you to send you alone.'
WHERE `entry` = 1143;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thanks again, friend! I told you I''d make it worth your while.',
    `RequestItemsText` = ''
WHERE `entry` = 1144;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, a note from Korran. He has been a loyal servant for some time now. I was wondering how his duties were going in the Crossroads.',
    `RequestItemsText` = 'I envy you, $C. You have the look of someone who''s been outside the walls of Orgrimmar for a while.$B$BI myself would travel in the name of the Warchief if Thrall didn''t have need of my skills here in the city. But he leads us well, and I trust his judgement--I remain here for as long as he needs me.'
WHERE `entry` = 1145;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Don''t mind the thundering echoes off the mountains'' walls. The goblins and gnomes are out among the Flats racing one another in atrocities created by what they call science. There are bigger threats here in Thousand Needles, one of which killed more than half my war party.$B$BBut we remain here until we hear word from Belgrom in Orgrimmar. Until then, we hold our position here, and stay vigilant.',
    `RequestItemsText` = 'War brings my group and I to the Shimmering Flats, $C. What brings you here?'
WHERE `entry` = 1146;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ha! That ichor you''re covered in actually makes you prettier, $N! It certainly does make you reek at the same time though. Don''t stand too close to the kodo; you''ll either start a stampede or cause them to go into heat.$B$BI think my companions would agree that your smell alone is proof you''ve done your part to help us against those insect creatures. Thank you, $N.',
    `RequestItemsText` = 'With the amount of travelers heading out to the Flats for those races, I''m sure we can convince enough adventure seekers to help push back those insects. My party and I won''t be able to leave until we do.'
WHERE `entry` = 1147;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, you''ve seen Moktar recently? He always be lookin'' out for me. I''m sorry to hear he spends his time watching over his little war band instead of seeing battle, but I''m sure he be takin'' great joy in killing members of the Explorers'' League.$B$BYou be smart to bring me these specimens, $N. Along with the eggs we be findin'' in the Field of Giants, these should give me a good start in figuring out what these insects are, and what they be wantin''.',
    `RequestItemsText` = 'Ah, it been a long time since you''ve come to see me, $N. What can I do for you today? You be looking like you''ve seen the face of battle recently. Good... good for the Horde and good for you. The more battle you''ve seen, the more helpful you''ll be; stronger, too.'
WHERE `entry` = 1148;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is not until faced with unforeseen adversity that we begin to see how strong our spirits are. You took the leap of faith even though you had no guarantees that you would survive. Your mind is open, and your spirit is prepared for what is to come.$B$BIf you are willing, then the next of your tests is ready.',
    `RequestItemsText` = 'Faith. It is far more important than some realize.$B$BIt does not matter what you believe sometimes. It is just important that you believe in something.'
WHERE `entry` = 1149;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Grenka was powerful, even by troll standards. You should be proud of your accomplishment this day.$B$BDuring your test of faith you displayed strength of spirit, and now you have shown endurance in battle by taking on the Roguefeather harpies, but the time has come for a new test.',
    `RequestItemsText` = 'You must be prepared spiritually, physically and mentally for the challenges that lie ahead of you.$B$BToo often do we rush forward before we are ready. I consider it my duty to the youth, no matter which tribe they belong to, to prepare them for the dangers they may face after they leave the sanctity of their home.'
WHERE `entry` = 1150;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Test of Strength is done. You have shown strength and bravery, and you are now prepared for the final test before these rites are completed.',
    `RequestItemsText` = 'Rok''Alim is also called the Pounder by the centaur tribes in Thousand Needles because of the thundering his fists make as he pummels the creatures brave, or stupid, enough to stand in his path.'
WHERE `entry` = 1151;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The days and nights grow colder throughout the world as goblins rape the land, and the night elves point fingers at the younger races. The Forsaken and orcs are not the only ones to blame for the hardships found throughout Kalimdor and Lordaeron. Many of the intelligent races have contributed to the world''s pain. Dorn knows this, and he has sent you to me because you have shown the attributes necessary to realize it also.$B$BNow you stand before Braug.',
    `RequestItemsText` = ''
WHERE `entry` = 1152;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A good sample, $N. A good sample indeed.$B$BThose travelers can no longer lord over me the ore they found, now that you have been successful.$B$BI shall get to work on it immediately. If it proves strong enough, I will send a weapon crafted from the material back to the warchief to show him our success.$B$BI shall not forget your help, $C.',
    `RequestItemsText` = 'I saw the travelers again - the ones that would not sell me a sample of the ore. I spit at them for not helping the warchief.$B$BMay they die in battle like cowards and not like warriors as should be the right of all people who ally themselves with the Horde.'
WHERE `entry` = 1153;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is the book I named. There is hope you will answer my question correctly then... unless you''ve forgotten to study its contents.$B$BWhen you are prepared, speak to me again and I shall ask a question of you.',
    `RequestItemsText` = 'Bring me the book after you''ve studied it. I will not ask you your question until after you have given me the book.'
WHERE `entry` = 1154;

UPDATE `quest_template` SET
    `OfferRewardText` = '',
    `RequestItemsText` = ''
WHERE `entry` = 1157;

UPDATE `quest_template` SET
    `OfferRewardText` = '',
    `RequestItemsText` = ''
WHERE `entry` = 1158;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Braug sent you? Impossible.$B$B<Parqual looks you up and down.>$B$BBraved Dor''Danil, took a leap of faith, fought and overpowered a powerful elemental? Bah! You''re probably a farce; some adventurer that overheard talk in a tavern. And now you think you have what it takes to pass my test. So be it... $C.',
    `RequestItemsText` = ''
WHERE `entry` = 1159;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is the book I sent you to search for.$B$B<Parqual slowly caresses his hand over the top of the book as he stares down at it.>$B$BSo now you wish a question to prove your mind is as powerful as your body and spirit. If you have studied the book long enough, then I shall ask you your question and you can be done with these tests!',
    `RequestItemsText` = 'I hope you made the Scarlet Crusade suffer some before stealing the book from them.$B$BMy views of their kind are not unwarranted. The Crusade may have been followers of the Light at one time, but now, they seek to destroy any creatures that have not sided with their religion. They believe all undead, Forsaken or otherwise, must be cleansed, and those traveling in their lands must either be insane, or subject to the undead''s powerful magics. Idiots. Idiots and fools; all of them.'
WHERE `entry` = 1160;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You stand before me as a figure of vengeance, and I bow down before you in thanks.$B$BWith that cow''s death, and knowing that their seed will no longer spread over the face of Azeroth, I can put my energy into something more lucrative. I hope you looted their farmstead after you finished them off.',
    `RequestItemsText` = 'Kill them all and bring me their heads!'
WHERE `entry` = 1164;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You good $R. Me miss things very much. Me like you now.',
    `RequestItemsText` = 'Me thirsty for grog. Me miss snuff too. Where is strongbox? You go get for Overlord Mok''Morokk.$B$BGo find south in old home. Me too busy leading ogres to get.'
WHERE `entry` = 1166;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, it''s good to see you again, $N! The strangest things have been happening around here, I''m glad you showed up!$B$BIt was very strange, $N. Everything seemed normal--well, as normal as things get around here--and then suddenly there was a blinding flash of light from the upper room of the tower. Then came the screams. The cries split the air, and lightning struck the ground from time to time. What''s going on?',
    `RequestItemsText` = ''
WHERE `entry` = 1167;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You kill many of the black dragon army. You brave $R.$B$BMake Tharg happy.',
    `RequestItemsText` = 'Mok''Morokk tell all ogres to stay and keep this place safe. Me think ogres need to kill black dragon army and get old home back.$B$BYou help ogres get home back. Help ogres get revenge.'
WHERE `entry` = 1168;

UPDATE `quest_template` SET
    `OfferRewardText` = '''Twas a perilous affair, no doubt, collecting all of these hearts and tongues. I shall delve into the depths of the arcane to trace the origin of the black menace which has descended upon our former home.',
    `RequestItemsText` = 'With the hearts and tongues of scorched offspring of the black dragon army, I can decipher what wretched beast introduced her spawn into our home. Perhaps with a greater knowledge of our aggressors, we can seek to destroy them once and for all and reclaim Stonemaul Village from ruin.$B$BOf course, convincing Mok''Morokk to move his lethargic, fat mass out of this muck hole is going to be an epic quest in and of itself...'
WHERE `entry` = 1169;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Why you tell me ''bout dragons? Me no like dragons. Me like it here. No dragons here.',
    `RequestItemsText` = ''
WHERE `entry` = 1170;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That lazy coward!$B$BMok''Morokk displayed strength when Rexxar was our leader. But soon after Rexxar''s departure Mok''Morokk fell prey to temptations of power. Rather than lead, he demanded. He does not serve his people but rather expects us to serve him.$B$BSomething must be done.',
    `RequestItemsText` = ''
WHERE `entry` = 1171;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Splendid! It will be sometime before Onyxia can produce more eggs.$B$BOn behalf of my people, I thank you, $N.$B$BI have asked much of you so far. Perhaps you can do the Stonemaul Clan one last service.$B$BMok''Morokk is not fit to lead us. Tharg would make an excellent leader but is hindered by his injuries and age. Drive Mok''Morokk from this place by force. Only then can we appoint a new leader to return us to our proper home in the south.',
    `RequestItemsText` = 'You must hurry to the Dragonmurk, $N. With Onyxia''s eggs riddled around the Wyrmbog, we face overwhelming numbers unless something is done quickly.$B$BDestroy her eggs! Don''t let the black dragon plague spread across our homeland!'
WHERE `entry` = 1172;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That cowardly fat mass Mok''Morokk fled like a scared child. You have done a great service, $N.$B$BNow my people can appoint a new leader, one who will help us reclaim our old home once and for all.',
    `RequestItemsText` = 'I thought you were going to attempt to drive Mok''Morokk out of the village. Instead you have come to me to chat?'
WHERE `entry` = 1173;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I hope you didn''t kill any of the basilisks on the tracks themselves! It takes a long time for the carcasses to decay in the sun, and I''d rather not have to take a shovel out to clean up.',
    `RequestItemsText` = 'It''s bad enough having to clear out the wreckage of the racers without having to pick them out of burnt animal parts.'
WHERE `entry` = 1175;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great! I can get the crew working on this right away. Thanks, $N!',
    `RequestItemsText` = 'Do you have those bones for me? I was just about to start working on lightening the steering rig, but I don''t want to open her up without all the parts I need.'
WHERE `entry` = 1176;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Me like fishy head!$B$BMe no eat you now.',
    `RequestItemsText` = 'Gimme food or me eat you.'
WHERE `entry` = 1177;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Pozzik sent you, huh? You know, Pozzik was one of the most respected tinkerers in Undermine before he retired to start working on the racers.$B$BThe first thing he did when he joined the team was develop the two engine model racers. Could be that the businesses will suffer without him working with the Tinkers'' Union, but who cares, right? There''s nothing like the races!',
    `RequestItemsText` = ''
WHERE `entry` = 1178;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah! Longbeard sent you with a load of helmets! Hooray!$B$BNow maybe we can talk a pilot into driving our car...',
    `RequestItemsText` = 'Watch where you''re stepping! Watch watch watch!! This is delicate stuff you see here, and if we''re to win then it must all work perfectly!'
WHERE `entry` = 1179;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Shipments to Ratchet? Let me just check the logbooks...$B$BNo, the most recent shipment I have on record of going out to Ratchet were boots from Drizzlik. Hasn''t been much else, other than building supplies and tools. Definitely no race parts.',
    `RequestItemsText` = ''
WHERE `entry` = 1180;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, sure of course I know what you''re talking about. Nope, can''t help you though. Some of my men were supposed to go track down the blueprints for the fuel regulator, but they came back empty-handed.',
    `RequestItemsText` = ''
WHERE `entry` = 1181;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now, let me just get a copy of these blueprints for my own notes and you can bring these straight to Pozzik. Wouldn''t want him to think that one of his sponsors was abandoning him.',
    `RequestItemsText` = 'Much as I hate to admit it, that gnome team they have out there is pretty good. Our boys need every edge they can get.'
WHERE `entry` = 1182;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I was hoping that it would be already assembled, but this does present the unique opportunity to improve on the design from the ground up. Thanks, $N. I''ll be able to sketch up some improved schematics, build the thing, and have it installed real soon.',
    `RequestItemsText` = '$N! Did you manage to track down the fuel regulator?'
WHERE `entry` = 1183;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I''m appreciative of your efforts, $C. The warchief will enjoy hearing how tenacious you have been in your duties.$B$BOh, of course I will mention your name to him. He speaks to me often and values my opinions greatly.$B$BGo now, I have much to do. And if you speak to Korran soon, and he has news of these creatures, then return to me--I would think they are a threat that must be taken seriously.',
    `RequestItemsText` = ''
WHERE `entry` = 1184;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hey, it''s you again! Well, I mean you - as in the you that is $N! Yes - that you!$B$BHey, let me start over!$B$BThat object you found in Silithus - it was in fact a book. It was a journal written in a very ancient dialect of what we now call the Darnassian tongue. It''ll take a while, but I''m going to go over it very thoroughly. I thought you should know that what you found was extremely valuable for the Circle.$B$BThe den mother''s all excited and everything!',
    `RequestItemsText` = ''
WHERE `entry` = 1185;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''re the $R that''s been helping Pozzik out, right? I was like you once, running around the pit area, helping with whatever work the mechanics would let me do.$B$BNow look at me! The goblin racing team''s pilot extraordinaire!',
    `RequestItemsText` = ''
WHERE `entry` = 1186;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Just take a look at this beauty! Fifteen pounds of solid seaforium power! Once I get this strapped on to the side of my racer, I''ll be around the track so fast I''ll beat the gnomes twice!',
    `RequestItemsText` = 'How''m I supposed to show my face around the track without a little extra kick to get me going? It''s a travesty, I tell you.'
WHERE `entry` = 1187;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Only Razzeric would take a look at this and say that I''d somehow put some sort of safety lock on it. This booster is almost completely seaforium explosives. I already modified it so that more of its payload would be delivered upon use, but Razzeric is never content unless he goes to eleven!',
    `RequestItemsText` = 'As I''m sure you know, the Gizmorium can service all of your tinkering needs! How can I help you?'
WHERE `entry` = 1188;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now that''s more like it! I wish I could see the look on the gnomes'' eyes when they see me set this baby off.$B$BToo bad I''ll be too busy pulling off a new course record!',
    `RequestItemsText` = 'Can you believe Pozzik put a bucket of sand on the racer? How am I supposed to hit my maximum speed with a bucket of sand under the seat?'
WHERE `entry` = 1189;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Scribbled in a hasty, hurried hand, a scroll of notes and designs for the refinement of some raw material.',
    `RequestItemsText` = ''
WHERE `entry` = 1190;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Let''s go!',
    `RequestItemsText` = ''
WHERE `entry` = 1191;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent! I''ll get the crew to work right away on the parts we''ll need for the next race.',
    `RequestItemsText` = 'I''d like to integrate indurium into different parts of our racers, but I need large amounts of raw indurium to create these parts.$B$BYou can find indurium ore in the Uldaman excavation in the Badlands, across the sea in Khaz Modan.$B$BThe gnomes are getting their own supply of it, so it''s important we get our own to keep pace with them.'
WHERE `entry` = 1192;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The thorium widget slides effortlessly into place, creating a conduit to pour the frost oil down. Once the last drops of oil have been emptied into it, the trap snaps into position.$B$BWoe be to any unwary ogre that should just so happen to wander by!',
    `RequestItemsText` = 'A large, broken trap lies before you. From the looks of it, the ogres have tried to repair the trap but to no avail. A hastily written note lies next to the trap, and strangely enough it details exactly what is needed to repair it: a thorium widget and some frost oil. Were the trap repaired, an ogre passing near it might get trapped, and could be avoided.$B$BClearly, it would seem fortuitous that very few ogres know how to read.$B$BClearly.'
WHERE `entry` = 1193;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Indurium? Interesting... If it is capable of resisting heat to the degree that you say, it would explain the performance increase the gnomes have displayed of late.$B$BThis sample you''ve brought to me will be invaluable, also. I will be able to perform some tests on this, but I''ll need more for this to actually be of any use to us.',
    `RequestItemsText` = ''
WHERE `entry` = 1194;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good. This should fill Rau''s request just fine. Could you deliver this to him? You might enjoy spending some time out in the Needles.',
    `RequestItemsText` = 'Once we have the filled phial, we can send it along to my associate, Rau, in the Thousand Needles. He was the one who requested the phial of water, so he''ll better know how we can make use of it.'
WHERE `entry` = 1195;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hm, yes, this phial of water will serve our purposes perfectly. Because of the shared ancestry of the dryads and the centaurs, the water of the moonwells will enable us to breach the protection of the eternal flame surrounding the centaur relic.',
    `RequestItemsText` = 'I don''t suppose you''ve been sent by Zangen, hm?'
WHERE `entry` = 1196;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I sense a strange energy emanating from the Hoof... I have no doubt that we will discover surprising new information about the centaur from its study.$B$BMy thanks, $N. Now I must begin to decipher the mysteries you have brought to me.',
    `RequestItemsText` = 'I am eager to put my hands upon the Cloven Hoof. Have you taken it yet?'
WHERE `entry` = 1197;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Dawnwatcher Shaedlass was good to send you. There is indeed a wicked plot underway in this corrupted place.',
    `RequestItemsText` = ''
WHERE `entry` = 1198;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You are no doubt of brave and noble blood, $N. The Argent Dawn commends you for your efforts against evil.',
    `RequestItemsText` = 'Blackfathom Deeps was once an ancient night elf temple. It once housed a most powerful moonwell. Who knows what evil brews there now at the hands of the Twilight''s Hammer.$B$BHave you made any progress in ridding their presence?'
WHERE `entry` = 1199;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Kelris has eluded us for quite some time.$B$BIt seems as though whenever evil made its presence known in these parts, Kelris had played a role. For some time we considered him dead or missing.$B$BBut this makes perfect sense. By ending his reign you have spared the lives of many innocent people.$B$BBy the light! To sacrifice someone to a servant of an Old God for one''s personal gain is beyond reproachful!$B$BYou have done a great deed, $N. I salute you on behalf of the Argent Dawn.',
    `RequestItemsText` = 'Time is a precious commodity, $C.$B$BMy role here in Darnassus is to ensure that the Argent Dawn thrives and that the evil forces encroaching upon Kalimdor are thwarted.$B$BState your business quickly or be on your way.'
WHERE `entry` = 1200;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good work.  Their infiltrators are skilled, but they''re not good enough to escape the watchful eye of the Horde!',
    `RequestItemsText` = 'Did you find the infiltrators, $N?'
WHERE `entry` = 1201;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I commend you, $N. This was not an easy mission. But the documents you gained are valued greatly by our superiors.',
    `RequestItemsText` = 'Did you find the documents, $N?  They hold information vital to the stability of the Alliance and, hence, vital to the security of the Horde.'
WHERE `entry` = 1202;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That''s a good blade. It has a good swing. It''s a good swing blade. Thank you. Thank you, thank you, thank you!!! Now I want to try it....$B$BLater. I''ll try it later. But like I was saying... thanks.',
    `RequestItemsText` = 'You have my blade??'
WHERE `entry` = 1203;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These will do fine!  Thank you, $N!$B$BNow I''ll try different cooking techniques on these tongues to find the best way to bring out their flavor.$B$BEventually I''ll have a dish worthy of serving at the Blue Recluse in Stormwind!',
    `RequestItemsText` = 'Did you get the forked tongues?'
WHERE `entry` = 1204;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good, $N.$B$BI am sure the hunt was not easy, but it is good to know the beast''s pain has finally ended.',
    `RequestItemsText` = 'Do you have the tooth of Deadmire, $N?  Have you ended the creature''s suffering?'
WHERE `entry` = 1205;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You got the eyes! You got the eyes! Tasty, tasty spider eyes!$B$BSome eyes... when you stare at them they stare back. Eat those last. They keep you company... out in the swamp.$B$BHello, little spider eyes. Hello! You taste like chicken. Gooey, salty chicken!$B$BMmmh.',
    `RequestItemsText` = 'Where are those eyes?'
WHERE `entry` = 1206;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, that''s the spice! Now here''s some swampy good stew.',
    `RequestItemsText` = 'Spice.  We could all use some spice in our life.  You agree?'
WHERE `entry` = 1218;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hm... I can''t read orcish very well, but this looks like a report... written by an orc spy!',
    `RequestItemsText` = 'Do you have a report to make?'
WHERE `entry` = 1219;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A report from an orc spy! How did you find this? No matter -- let''s see what it says...',
    `RequestItemsText` = 'You have something for me?'
WHERE `entry` = 1220;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great, you got them!  I can sell these to my contacts for a bundle!$B$BThanks for the delivery, $N!  You are a great partner.',
    `RequestItemsText` = 'Do you have the tubers, $N?'
WHERE `entry` = 1221;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Mr. Ignatz was just here with the bogbean leaves, and he told me you helped him out of some real trouble.$B$BThank you, $N.  I will ask my uncle to treat you to a feast the next time you visit the Blue Recluse in Stormwind.',
    `RequestItemsText` = 'Have you seen Mr. Ignatz? I sent him into the swamp some time ago and he hasn''t returned!'
WHERE `entry` = 1222;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good work, $N. Our agent, Marg Nighteye, was stationed outside Theramore. He was charged to spy on the city.$B$BThis is his latest report, and it may be his last -- from your testimony, I fear that Marg met his end in the swamp...',
    `RequestItemsText` = 'You have something for me?'
WHERE `entry` = 1238;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is the head of Marg Nighteye! As I feared, he is dead.',
    `RequestItemsText` = 'You have another matter to report, $N?'
WHERE `entry` = 1239;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, I now see. The spirit of this orc is bound in our world, boiling with rage from a task yet undone.$B$BWell, let us have words with this angry orc...',
    `RequestItemsText` = 'There is an angry spirit about you, brother. What brings you to Kin''weelay?'
WHERE `entry` = 1240;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmm... <Jorgen looks up at you through squinted eyes.>$B$BAll right. I''ll help ya, but not because I want to, but because I''m obligated.$B$BAnd let''s get one thing straight: you''re knowin'' far more than you should to begin with. Let''s keep this our little secret, and don''t go blabbin'' at any taverns about anything you find out. Understand?',
    `RequestItemsText` = 'Hmph, you better have good reason to interrupt a man and his fishin''. I don''t take kindly to peddlers, let alone beggars.'
WHERE `entry` = 1241;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I''m sorry, a letter for me? Well, I''ll be... not often you get a delivery that''s not a crate or barrel when all you do is work. Let''s see what this is about.$B$B<Elling looks up at you while he opens the letter.>$B$BYou look a little tense, you okay, $N?',
    `RequestItemsText` = 'Hello, $N. Is there something I can do for you? Perhaps you''d like to try some of our special Trias cheddar? Or a block of Darnassian bleu?'
WHERE `entry` = 1242;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, Trias sent you, huh? That''s a little different.$B$BFeel free to fight whatever monstrosities come at you from the darkness. I''m sure you''ll be able to handle it pretty easily if you''re the type to be hanging around with the likes of him.$B$BSo, what does my friend need of me on such a gloomy day as this?',
    `RequestItemsText` = 'Not too safe to be traveling about in the woods, $N. Be careful, and if you see anything suspicious or dangerous, contact the Watchers immediately. Don''t try and take anything on yourself. We''re not responsible for anything terrible that might happen to you.$B$BBut we both know you''re gonna ignore me and fight whatever comes out of the darkness anyway, don''t we? Haha, yeah, you adventurer types... all the same.'
WHERE `entry` = 1243;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''re back safe and sound. Couldn''t ask for much more than that, could you?$B$BNow, let''s see what we have here. This looks pretty official as far as any Defias documents I''ve seen. But it could be a dupe just to throw you off track of whatever it is you''re looking for.',
    `RequestItemsText` = 'Be careful out there, $N. I know Trias was the one to send you here, but that doesn''t mean there isn''t anything lurking out in the woods that couldn''t cause you some trouble... especially with you investigating the Defias.'
WHERE `entry` = 1244;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yeah... this is an interesting read. Jorgen and DeLavey were smart to bring me in on this.$B$BSeems the Defias have been trying pretty hard to complete this plan of theirs. Hmm... what''s this? Fist? That''s a familiar name.',
    `RequestItemsText` = 'I see you''re back, and in one piece. We both know you''re not here for cheese, so let''s cut out the pleasantries. Was Backus any help, or have you even left for Duskwood yet?'
WHERE `entry` = 1245;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What?!$B$BYou come into me alley and ask questions about me personal business? Business which you obviously have nothing to do with.',
    `RequestItemsText` = ''
WHERE `entry` = 1246;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good to see you''re still alive, $N. So, it went well with Dashel then, huh?$B$BI''ve been reading up more on this plan of theirs, and although it doesn''t state the name of the diplomat they were after, it does talk about this plan B they enacted after failing on their first attempt to capture him.$B$BThis Slim that Dashel mentioned doesn''t have any other name written here, but if you say he''s in Menethil, then that''s a start.',
    `RequestItemsText` = ''
WHERE `entry` = 1247;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Welcome, welcome, welcome, $N. Good of you to join us. Perhaps an ale today? Or some mutton?$B$BName your pleasure and I''ll see to it that you''re taken care of. My name is Mikhail, and I look forward to serving you.$B$BHmm? What''s that? Trias? Keep your voice down, my friend. This isn''t something for the whole tavern to hear about.',
    `RequestItemsText` = ''
WHERE `entry` = 1248;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Caught him, huh? Good for you. I''m surprised that was Slim.$B$BI''ll be honest, I never thought I''d miss the excitement of some of the more devious underground activities. I guess old habits die hard. Don''t mention that to Elling--he''d probably try and get me to come back to Stormwind if he heard I missed the action.$B$BI''m glad I could at least be of a little service to you while you were in Menethil. If you need anything else, just ask.',
    `RequestItemsText` = 'Did he slip away? He looked a little shady the way he was watching us.'
WHERE `entry` = 1249;

UPDATE `quest_template` SET
    `OfferRewardText` = 'THE KING?! I mean... the king? The real king? Are you joking? You didn''t mention you were looking for the king''s kidnappers. I didn''t even hear he was missing--that would explain his son being crowned some.$B$BI''ll send word to Elling right away. He''ll want to know you''re on the trail.$B$BI would never have guessed Jahn would sell out Stormwind for some lousy coin. Even a rogue''s got to have honor when it comes to some things.$B$BThe key now is to find this Hendel. And I think I can help with that.',
    `RequestItemsText` = ''
WHERE `entry` = 1250;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I grant that humans have strange decorating tastes, but would they use a plain iron shield to adorn their fireplace? Perhaps this shield was placed there by the ones who burned the inn.$B$BA warning? A threat?',
    `RequestItemsText` = 'What''s that you have there, $N? Evidence from the remains of the Shady Rest Inn?'
WHERE `entry` = 1251;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It''s never good news when a guard''s badge is brought to me.$B$BSometimes it''s a man or woman who''s fallen in battle, and I''m left to bring the news to the grieving family. Other times we never find out what happened to them. And other times it''s even worse than that.',
    `RequestItemsText` = 'Have you found anything of interest at the Shady Rest Inn?'
WHERE `entry` = 1252;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hm, I''m no expert with the construction of arms and armor. Their use, yes, but not their making.$B$BThis shield seems as ordinary as any, excepting the damage from the fire that engulfed the inn.',
    `RequestItemsText` = 'Have you found evidence from the site of the Shady Rest Inn?'
WHERE `entry` = 1253;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These are wonderful specimens, $N!  The shells are in perfect condition, and the meat is pink and tender.  The blood of a chef is in your veins, I''m sure of it!',
    `RequestItemsText` = 'My research with the Mudrock tongues is progressing nicely.  I trust your crab hunt goes well?'
WHERE `entry` = 1258;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hello, $N. You''d like information about a specific member of the Theramore guard? Reethe, was it?$B$BJust give me a moment to find the right book.',
    `RequestItemsText` = ''
WHERE `entry` = 1259;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, my uncle sent you, did he?$B$BWell I''ve been researching recipes and I have some leads, but I need help.$B$BHelp from someone willing to get his feet wet.',
    `RequestItemsText` = ''
WHERE `entry` = 1260;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This pendant was worn by a soldier of Stormwind??$B$BThank you, $N. You have revealed the secret of Marg''s death. But this pendant is a new mystery to solve, one that may have dire effects on the Alliance, and the Horde.',
    `RequestItemsText` = '$N, did you discover Marg''s fate?'
WHERE `entry` = 1261;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This pendant was crafted with great skill and precision, $N. No orc would covet such a jewel...$B$BBut many humans would.$B$BI will have this pendant studied. In time let us hope that its mysteries will be revealed to us.',
    `RequestItemsText` = 'You traveled from Brackenwall Village in Dustwallow? How fares Nazeer, and how fare his efforts in the marsh?'
WHERE `entry` = 1262;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A pleasure to meet you, $N. I am Commander Samaul. I''m in charge of Miss Proudmoore''s forces here in Theramore.$B$BAlthough I''m quite busy, if you have any questions, please feel free to speak up. I might have to keep it short, but there''s no reason for me to be rude if you need my help.$B$BIf you plan on traveling out of the city, I''d suggest you be careful. Besides ogres, orcs and murlocs, the southern part of the swamp is filled with black dragons.',
    `RequestItemsText` = ''
WHERE `entry` = 1264;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The man you seek, the one known as Hendel, is not here. Other sources have brought to the Lady Proudmoore information I believe you already know. She has asked me to find you, and give you aid in your venture. If you would allow it, I will tell you where to find Private Hendel so we can bring him to justice.',
    `RequestItemsText` = 'Yes, $N?'
WHERE `entry` = 1265;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hello, citizen. This is a dangerous place to be wandering about. I wouldn''t hang around too long if you value your life.$B$BIf you keep your questions short, I''ll see if I can help you. Just keep your eyes open for any of those filthy ogres. Rumor has it there''s a Horde base somewhere in the swamps. The infiltrators are doing what they can to find it, but the process has been slow going and we''ve had little progress.',
    `RequestItemsText` = ''
WHERE `entry` = 1266;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Let me be first to thank you for all you''ve done, $N. You have been an incredible blessing to my people and the people of Stormwind. I am sorry I couldn''t make your acquaintance under better circumstances.$B$BUnderstand also that I cannot overtly thank you for your efforts, but I assure you again, it is appreciated.$B$BWhen you visit Theramore in the future, seek me out and I shall try to keep you appraised of the situation.$B$BThank you again, $N.',
    `RequestItemsText` = ''
WHERE `entry` = 1267;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hoofprints... It could have been the quilboar, I suppose. Or maybe even the centaur. Their presence in the Barrens is not insignificant, and I would not think it a stretch to commit such an act.',
    `RequestItemsText` = ''
WHERE `entry` = 1268;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I know this human, Paval Reethe. Pathetic, even for his kind. He deserted his fellow soldiers and is now hiding out in the woods.$B$BI sent Ogron out to track him down. Some of the others suspect he''s been stealing from our supplies. I think I saw Ogron heading off to the southeast.',
    `RequestItemsText` = 'Have you found any leads on what happened at the Shady Rest Inn?'
WHERE `entry` = 1269;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Stinky was here with the herbs I ask of him, and he told me you helped him out of a bind. Good work! A friend of Stinky''s is a friend of mine!$B$BHe asked me to give you this if I ever saw you, right before he walked back south toward the marsh.',
    `RequestItemsText` = ''
WHERE `entry` = 1270;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My nephew said you aided him with his research in Dustwallow, and that you helped his associate out of a tight spot.  Well, we Sterns stick together and we don''t ignore our friends!$B$BSo wash your hands, $N, because we''re about to throw a party in your honor!',
    `RequestItemsText` = ''
WHERE `entry` = 1271;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmph. It is good that Reethe will no longer be lurking around the swamp, but it is a shame that humans are built so frail that he could not recover from a little arrow wound.$B$BIt seems that this thread of the mystery has led nowhere, and we must look elsewhere.',
    `RequestItemsText` = 'Did you find Reethe?'
WHERE `entry` = 1273;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hello, $N. I am Bishop DeLavey.$B$BNo doubt if you''re asking me about my business here in the keep then young Thomas has succeeded in requisitioning you to help our kingdom. He has always been adept at following my requests.$B$BI''m afraid I don''t have time to elaborate much, so allow me to be blunt... and please, try to keep this from becoming common knowledge.',
    `RequestItemsText` = ''
WHERE `entry` = 1274;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have traveled far and undoubtedly faced great peril.$B$BYour actions have been selfless. ''Tis for the good of all Azeroth that you help me with my research. I thank you, $N, for all that you have done.$B$BNow if you''ll excuse me I have much work to do....',
    `RequestItemsText` = 'Once I have enough samples to study, my true work can begin. With the corrupted brain stems of both the satyr and naga of Blackfathom Deeps I can try to draw a correlation between the mutations.$B$BPerhaps with that gained knowledge we can prevent the blood elves from delving deeper into deformity and evil.'
WHERE `entry` = 1275;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, you are certainly correct. This is a shield that I made.$B$BI''m afraid there''s not much more I can tell you though, $N. I craft so many different shields and sets of armor, I can''t keep track of them all.',
    `RequestItemsText` = 'Hello there, $C. Something I can help you with?'
WHERE `entry` = 1276;

UPDATE `quest_template` SET
    `OfferRewardText` = 'James Hyal''s his real name. He opened an inn at the edge of the Barrens. Wanted to make a nice place for travelers to stop over...$B$BMight be he was thinking too big, but the inn did do well for a while. Then we lost control of the roads in the marsh, and the ogres took over.$B$BJames was too stubborn to give up his dream for safety within our walls, and the Shady Rest Inn was burnt to the ground. We''re investigating, but haven''t had much luck. If you want to help out, see what you can find in the rubble.',
    `RequestItemsText` = ''
WHERE `entry` = 1282;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hoofprints, eh? It is true that there is an extraordinary amount of centaur activity in the lands near the Dustwallow Marsh. In brief excursions into the Barrens, we found their camps and holdings dotting the area.',
    `RequestItemsText` = ''
WHERE `entry` = 1284;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Missing? That would be Tesoran''s kind way of saying traitor.$B$BNo doubt he''s one of those fools so blindly loyal to Admiral Daelin that he turned traitor. Isn''t that a delicious irony? The deserters accuse us of betraying the Alliance.',
    `RequestItemsText` = ''
WHERE `entry` = 1285;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Did Vimes send you? Couldn''t do his dirty work himself, could he...',
    `RequestItemsText` = ''
WHERE `entry` = 1286;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I will send Lieutenant Caldwell to deal with the deserters at Lost Point. In addition, I will instruct him to find Reethe. The marsh is not so big and trackless that he should be unable to find him.',
    `RequestItemsText` = ''
WHERE `entry` = 1287;

UPDATE `quest_template` SET
    `OfferRewardText` = '',
    `RequestItemsText` = ''
WHERE `entry` = 1288;

UPDATE `quest_template` SET
    `OfferRewardText` = '',
    `RequestItemsText` = ''
WHERE `entry` = 1289;

UPDATE `quest_template` SET
    `OfferRewardText` = 'James? Oh, he left quite some time ago.$B$BFelt the second wind of patriotism, I suppose. Not hard to see why he would. With all the insanity in Lordaeron, many people joined up with Jaina Proudmoore when she went across the sea.',
    `RequestItemsText` = ''
WHERE `entry` = 1301;

UPDATE `quest_template` SET
    `OfferRewardText` = 'James Hyal, James Hyal... Why does that name sound so familiar?$B$BOf course! The Shady Rest Inn incident. If you have any information about what happened there, I would urge you to speak with Captain Vimes about it. He''s handling the investigation.',
    `RequestItemsText` = ''
WHERE `entry` = 1302;

UPDATE `quest_template` SET
    `OfferRewardText` = '',
    `RequestItemsText` = ''
WHERE `entry` = 1318;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hm... interesting piece of iron you have here. Definitely not made by any of the blacksmiths I know over on this side of the sea, and it''s certainly not my work.',
    `RequestItemsText` = 'Something for me to look at?'
WHERE `entry` = 1319;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That''s not much information to work on, but we''ll have to keep it in mind. Hopefully some of the other pieces of this mystery will fall into place, and paint a more helpful picture of what happened.',
    `RequestItemsText` = ''
WHERE `entry` = 1320;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is good shield. Very strong, heavy, good. But Do''gol don''t need it. I make shields, not buy them, $N.$B$BYou should know that.',
    `RequestItemsText` = 'Something for me, $C?'
WHERE `entry` = 1321;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I don''t like spiders that are so big I can''t sit on them and squish them.$B$BThanks for getting them, $N. Now I rip them open and pour them onto the shield...',
    `RequestItemsText` = 'Did you get them sacs from the spiders?'
WHERE `entry` = 1322;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Mosarn? Sounds familiar... I can''t put my finger on it. Maybe it''ll come to me later.$B$BIt probably isn''t important. A shield can come from anywhere and not mean anything...',
    `RequestItemsText` = ''
WHERE `entry` = 1323;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I assure you, we''re all quite upset about current events, but allow us to take him back to Theramore for some questioning, and we''ll see about finding the King.$B$BI''m sure my lady Proudmore would like to thank you for your help. Speak to her when you have a moment.',
    `RequestItemsText` = 'Hello again, $N. I hope you don''t mind the assistance, but we couldn''t have Hendel escaping, or worse, wind up dead.'
WHERE `entry` = 1324;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, a request from one of the Stormpikes. That''s a proud clan, full of quality dwarves. Rich ones, too.$B$BThank you, $N. I''ll get to work on Mountaineer Stormpike''s shield by the end of the day.',
    `RequestItemsText` = 'A letter from the dwarven lands? I wonder who would call from so far to the north...$B$BPlease, let me see the order.'
WHERE `entry` = 1338;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That''s right. I have a task that I can''t do while I''m guarding. In fact, it''ll take you far from Loch Modan.$B$BYour perfect chance for adventure!',
    `RequestItemsText` = ''
WHERE `entry` = 1339;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, very good.  If initial reports are true, then the toxicity of these hearts could lead to further advances in our knowledge of poisons.$B$BThis is a welcome delivery, $N.  Your reward is well earned.',
    `RequestItemsText` = 'You have a package for me?'
WHERE `entry` = 1358;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah yes, the heart samples of which Renferrel spoke. I am eager to experiment with these... it is always of interest to the Royal Apothecary Society when new forms of toxins are discovered.',
    `RequestItemsText` = 'You have something for me?'
WHERE `entry` = 1359;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, I feel complete again - thank you kindly.$B$BSome dwarves may treasure the luster of metal, and some may treasure the glint of gems... but a Stoutarm without a treasured stein in hand is hardly a Stoutarm at all!',
    `RequestItemsText` = 'Well now, we''re you able to get slap around those troggs long enough to get into my chest and nab my treasure?'
WHERE `entry` = 1360;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, I am recruiting.  This mission leads into Desolace, against the centaur there.  I will be brief so that you may quickly begin.',
    `RequestItemsText` = 'I note that your task is unfinished, $N. Shall I inform Sharlindra of your ineptitude?'
WHERE `entry` = 1361;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You are here on orders from Regthar?  Then you are here to deal with the centaur.  Good.$B$BI hope you''re rested.  I don''t know how our campaign against the centaur will end, but I know the struggle will be long.$B$BHave a seat, and listen.',
    `RequestItemsText` = ''
WHERE `entry` = 1362;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It wasn''t my fault. Really it wasn''t.',
    `RequestItemsText` = ''
WHERE `entry` = 1363;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, most splendid!$B$BFor some time I had feared my request for Khadgar''s Essays on Dimensional Convergence had been overlooked by Master Mazen of the Academy of Arcane Arts and Sciences.$B$BHe must be bogged down with requests considering the many strange happenings going on.$B$BNow, if you''ll excuse me, I need to begin my research at once. To finally glimpse the insight of one as great as Khadgar excites me to no end.',
    `RequestItemsText` = 'What brings you to Nethergarde Keep, $R?'
WHERE `entry` = 1364;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done.  This swift act against the Kolkar is an effective show of strength, and strength is what the centaur understand best.$B$BThe death of the Kolkar leader will not only disrupt that clan, but give pause to the others.',
    `RequestItemsText` = '$N, have you defeated Khan Dez''hepah?'
WHERE `entry` = 1365;

UPDATE `quest_template` SET
    `OfferRewardText` = 'By now, the centaur must know your name.  I''m sure they know it, and respect it, and fear it.  And just as they know you, they know the banner under which you ride.$B$BThe banner of the Horde.',
    `RequestItemsText` = 'How is your collection of ears, $N?  Large?'
WHERE `entry` = 1366;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Gelkis cry when they hear your name, $N. They fear you and they hate you. They hate you like they hate the Magram!$B$BMaybe you are strong like the Magram. We will see...',
    `RequestItemsText` = 'Leave! The Magram do not speak with the weak. We kill them!$B$BIf you want to speak with me, then show me you are strong. Return after you slay many Gelkis.'
WHERE `entry` = 1367;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The earth speaks to me.  And it says you have killed many Magram.  This is good.$B$BIf you are a friend of the Gelkis, then listen.  I have more tasks for you.',
    `RequestItemsText` = 'Your two feet step on Gelkis earth. You are not welcome here!$B$BProve you seek friendship with the Gelkis. Kill Magram centaur. Return when the ground is wet with Magram blood.'
WHERE `entry` = 1368;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You got the tears! Now the Gelkis will know that Theradras will not help them. She will not cry when we crush them! The Magram will rule!$B$BYou are smart to help us, $N. We are the strongest.',
    `RequestItemsText` = 'If you are not our enemy, then you will do what I ask!'
WHERE `entry` = 1369;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good.  I can hear the loud Magram bellies grumble from their village, far away!$B$BI will give this meat to the Gelkis.  And we will fight for many days without rest.$B$BWhat you did is good for the Gelkis, $N.',
    `RequestItemsText` = 'Return after you further prove your worth to the Gelkis!'
WHERE `entry` = 1370;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, this is what I had! I will make it move again. It makes me laugh!',
    `RequestItemsText` = 'If you are not our enemy, then you will do what I ask!'
WHERE `entry` = 1371;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Zraedus was just telling me about the nosey little Infiltrator before you arrived.$B$BQuite a problem, indeed. The last thing we need is a busybody sniffing around Beggar''s Haunt.$B$BI am sure the orcs of Stonard would be quite anxious to hear what our friend has to say. Seeing that they are our allies, ahem, we must help them to get any information they can from the human.$B$BWork with me, $N, and we will deliver a truth serum to Stonard.$B$BFor the Horde!$B$B...did I get that right?',
    `RequestItemsText` = ''
WHERE `entry` = 1372;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, this is the shard of which the earth whispered. I can feel strong magic in it! I will use this magic against the enemies of the Gelkis.$B$BYou have done one more task for us, $N. Maybe soon, we will call you friend.',
    `RequestItemsText` = 'Show me you are a friend of the Gelkis, $N.'
WHERE `entry` = 1373;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Khan Jehn was strong, but stupid. He thought his own strength was great. He did not see that earth magic is stronger. The Magram centaur will now fall without their leader, and the Gelkis will one day rule!',
    `RequestItemsText` = 'Show me you are a friend of the Gelkis, $N.'
WHERE `entry` = 1374;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Khan Shaka is dead!  I will place his head on a pike, and keep it with me so Shaka can see the strength of the Magram!',
    `RequestItemsText` = 'Do tasks for the Magram, and I will help you.'
WHERE `entry` = 1375;

UPDATE `quest_template` SET
    `OfferRewardText` = 'He is dead! Khan Hratha is dead! And now the Maraudine will fall! When the Gelkis rule this land, $N, we will remember you. And the spirits of the earth will sing your name for all time.',
    `RequestItemsText` = 'Is Khan Hratha dead? Do you have the key fragment?'
WHERE `entry` = 1380;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Khan Hratha is dead!  Now the Magram are the strongest of the centaur!  We will crush the others, and rule Desolace!$B$BWe will remember, you, $N, and you will be spared our hooves when all others are trampled.',
    `RequestItemsText` = 'Do what I ask.  Prove to me that you are an ally of the Magram!'
WHERE `entry` = 1381;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your name is whispered among the Gelkis. You have much Magram blood on your hands. This is good.$B$BMaybe it is also good if we speak. Speak of what you can do for the Gelkis, and what we can do for you.',
    `RequestItemsText` = 'Be gone! The Gelkis do not want you here. Leave now!!$B$BReturn after killing many Magram, and then I will speak with you.'
WHERE `entry` = 1382;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Splendid, $N! And just in time too. From what Zraedus tells me, the Infiltrator has recovered from his wounds and is ready to be questioned by the orcs.$B$BGive me but a moment to prepare the pois - I mean prepare the truth serum.',
    `RequestItemsText` = 'That Infiltrator in Stonard will surely.... open up... after he drinks my special serum. Haha!$B$BThe ingredients required are by no means easy to procure. Shadow Panthers are common in the Swamp but collecting enough hearts for our purpose can be daunting. And the Mire Lord can be such a fussy beast.$B$BAs for the Deepstrider tumor, they are terribly difficult to find. But the chemical reaction I can draw from it is second to none.'
WHERE `entry` = 1383;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You do a good thing for the Gelkis. The Kolkar are weak and will die. Their magic is pathetic and will not save them. You showed them this, and their fear will make them even more feeble!$B$BAnd in our lands, the feeble soon die.',
    `RequestItemsText` = 'You have the charms? You showed the Kolkar they are weak?'
WHERE `entry` = 1384;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Many Gelkis fall to you. I like that. Maybe you can do more things I like. Maybe you and the Magram can be friends.',
    `RequestItemsText` = 'You will go now, or the Magram will crush you! To be our friend, you must kill Gelkis.'
WHERE `entry` = 1385;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Kolkar fear you now! I hope you laughed when you killed them. It is better to laugh when you kill, so the enemy can see he is weak.',
    `RequestItemsText` = 'Are you afraid of the Kolkar? Why do you not kill them? Maybe you forgot how to kill. Hurry and kill Kolkar before they are dead!'
WHERE `entry` = 1386;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, the ears. Well done.$B$BYour service to the Alliance is unquestioned, $N. The blood you spilled in Desolace will, no doubt, save countless lives.',
    `RequestItemsText` = 'Do you have a report, $N?'
WHERE `entry` = 1387;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I knew old Faustin would come up with something good! You were a tremendous help, no doubt.$B$BNow let''s get down to business, shall we?',
    `RequestItemsText` = 'I hope you have proven yourself of use to our dear friend, Apothecary Faustin.'
WHERE `entry` = 1388;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. We, are in your debt.',
    `RequestItemsText` = 'Do you have the crystals?'
WHERE `entry` = 1389;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thanks for the done work!',
    `RequestItemsText` = 'NULL'
WHERE `entry` = 1390;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A drink for me? How kind. It''s been days since they''ve allowed me to drink. Let me drink this down and then I''ll tell you what I''ve learned....',
    `RequestItemsText` = 'Please have mercy on me! I have information that goes beyond alliance boundaries. While I am no sympathizer of the Horde, there is political treachery going on that must be revealed!'
WHERE `entry` = 1391;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have gained the weapon of the dreaded Noboru? Is he then dead?$B$BThis is a joyous day for the Harborage. Noboru and his gang were a terror to us, wandering the swamps and killing any Draenei who crossed his path. He was a direct threat to our survival, and we did not have the strength to face him.$B$BWe are fortunate to have a friend in you, $N.',
    `RequestItemsText` = 'Greetings. And welcome to the Harborage.'
WHERE `entry` = 1392;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The keyhole of this strongbox is filled with black resin.  It is impossible to open.$B$BBut Galen told you of a hidden latch on the box''s bottom...$B$B...After a quick search the latch is found.  The latch is flipped, and the strongbox opens...',
    `RequestItemsText` = ''
WHERE `entry` = 1393;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, $N. It has been a long time since you have last stepped into my home. It seems like many moons have passed since you took your first leap that set you upon your path.$B$BAnd now you return to me stronger than you once were... more enlightened. This pleases me. And you should be justly rewarded for seeing my tests to the end.',
    `RequestItemsText` = ''
WHERE `entry` = 1394;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, the powerstones!  The mages will be happy to see these!$B$BMany thanks, $N.  I know your trip from Darkshire was not an easy one.',
    `RequestItemsText` = 'Hello!  Don''t mind all the commotion, it''s just business as usual at Nethergarde Keep.$B$BYou have something for me?'
WHERE `entry` = 1395;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The sounds of animals are now faint, more distant. Thank you, $N. Now let''s hope they don''t return!',
    `RequestItemsText` = 'The swamp creatures press close, $N. Please, you must defend the camp!'
WHERE `entry` = 1396;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This wood is light, but tough. Thank you, $N. It will work nicely.',
    `RequestItemsText` = 'Did you find any driftwood, $N?'
WHERE `entry` = 1398;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Helgrum wants a report, eh? I sent an outrunner to Stonard not three days past. Did he fail his mission? If Stonard does not have my report, then it appears he did fail.$B$BLet''s hope the next runner I send has more skill, or more luck.',
    `RequestItemsText` = ''
WHERE `entry` = 1418;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That''s a nice collection of jawbones, $N. Now those coyotes won''t be tearing through our supplies for scraps.$B$BWell done. The coyotes of the Badlands aren''t easy prey. Your deed shows me that you might just survive here.',
    `RequestItemsText` = 'Do you have the jawbones?'
WHERE `entry` = 1419;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. From Neeka''s report, I see the Alliance is not without its own problems. And we may find that some enemies are shared between us.',
    `RequestItemsText` = 'You returned. You have a report?'
WHERE `entry` = 1420;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, you found them! With these, the wizards in Nethergarde may continue their work. I do not know what it is that they do, but it is linked to the Dark Portal in the Blasted Lands, and is vital to the security of the Alliance.',
    `RequestItemsText` = 'Do you have the wizard''s reagents, $N?'
WHERE `entry` = 1421;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Be silent a moment, $C. Even over the dull roar of the sea you can still hear those disgusting gurgles from the fish men.',
    `RequestItemsText` = ''
WHERE `entry` = 1422;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, thank you $N! So many supplies are lost from Darkshire to here. It''s good to see that some are recovered.',
    `RequestItemsText` = 'You have something for me?'
WHERE `entry` = 1423;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your diligence in collecting the Atal''ai artifacts is worthy of praise, $C.',
    `RequestItemsText` = 'No one knows what dark practices went on inside The Temple of Atal''Hakkar. But we do know that great and powerful forces of magic were used.$B$BWe must learn as much as we can about such magic. Perhaps the spells of the Atal''ai will prove of use to the Horde.$B$BOnce you have gathered enough Atal''ai artifacts from around the Pool of Tears, I can begin to understand what the trolls were hoping to accomplish and what went so horribly wrong.'
WHERE `entry` = 1424;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What? A package from Biggs'' caravan? We thought it, and he, were lost.$B$BThank you, $N. With luck, these supplies will carry the much needed reagent, Azoran Crystals. Our stock is running low...',
    `RequestItemsText` = 'You have business with me?'
WHERE `entry` = 1425;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The sea seems vast and relentless, but you have stained her with the blood of her own spawn. The fish men know pain. Their stupidity will force them to refortify their ranks from the devastation you''ve caused, and that is good.$B$BLet their gurgling screams overshadow the sea''s roar long into the night. I shall smile every time I hear one of them silenced.$B$BReturn to me if you wish to slay more of the fish men. I will gladly reward you again.',
    `RequestItemsText` = 'I am patient. Patient and everlasting like an old kank stone from Draenor. The fish men shall not make it past our borders--not while I still stand. If we had an army at our disposal I would cleanse this world and all others of their presence. I feel my hatred seethe just speaking about them.'
WHERE `entry` = 1426;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, $N, you''ve returned. Good. I''ve finished crafting more weapons for our fight against the murlocs. For bringing us the fresh sawtooth meat, and for bringing a small smile to Katar''s face, I offer one of them to you.',
    `RequestItemsText` = ''
WHERE `entry` = 1427;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $C. I call for more of their blood. Let all the fish men perish.',
    `RequestItemsText` = 'Not until the sea and all her children are silenced will I be pleased... especially those disgusting fish men.'
WHERE `entry` = 1428;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You bring me the summoning artifacts of the Atail''ai?$B$BI see Jammal''an the Prophet is leading the disciples of the Chamber of Blood towards their chosen fate. Has Hakkar returned to the Temple I wonder? Has their fate been met?',
    `RequestItemsText` = 'You are brave to come here. Brave or foolish...'
WHERE `entry` = 1429;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, this should be perfect. I can''t wait to taste these after they are prepared perfectly over an open fire. You should take a sample of it with you on your travels. It truly is delicious.',
    `RequestItemsText` = 'I have a cask of wine waiting for your success, $N. It''s only right I taste the goods before I have it shipped back to my customers.'
WHERE `entry` = 1430;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Putanni, noble $C. I am Keldran, student of magic... and other mystical arts.$B$BThe business Craven sent you here to speak to me about requires a touch more subtlety than you''ve previously needed, but that does not mean you can not still aid our cause.$B$BPlease, make yourself comfortable, and I shall tell you why the Warchief has need of my aid... and yours.$B$BIt starts with appearances, $N. How the Horde sees itself. How our allies see us. And most importantly, how our enemies see us.',
    `RequestItemsText` = ''
WHERE `entry` = 1431;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Greetings, $C. You bring news from Orgrimmar; that is good.$B$BThe demon infestation overwhelms this area even more than the smell of centaur dung. The horse-men claim this land as their own, but clearly there are influences out of their control that will crush them if not kept in check.$B$BIt does not please me that we aid the centaur indirectly, but it is for the good of the Horde, so I do my duty for the Warchief, even if it means helping the warlocks within the Horde.',
    `RequestItemsText` = ''
WHERE `entry` = 1432;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, yes. Aid from those loyal to the Warchief is always appreciated.$B$BMy name is Maurin. I am here at the behest of Keldran and the Warchief cub Thrall. It is my desire to aid the youngling leader against the evils that threaten his rule.$B$BCome, come closer, $C. I shall explain to you my plan for removing the festering boil that is the Burning Blade.',
    `RequestItemsText` = ''
WHERE `entry` = 1433;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, $C. You have shown honor and dedication.$B$BWhen our campaign in Desolace is done, the Warchief will know that you aided us in our actions here, and that you helped make his will manifest.$B$BI thank you.',
    `RequestItemsText` = 'I was warned by a tauren companion that the satyr are not all they appear to be. He believes there is something more to them, that their evil is a twisting of their true nature. But I have not seen such things.$B$BI see only the ruthless slaughter of the weak and the corruption of those who seek dark power.$B$BI will continue in my duty of annihilating them until the Warchief directs me otherwise. Until then, I take no pity on them.'
WHERE `entry` = 1434;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, you''ve returned successful. That is good. Give me the gems and I shall put them someplace safe....$B$BMy tasks for you are complete, $C. Speak to Takata when you are rested. He may have other tasks for you, or perhaps needs you to return to Orgrimmar to inform Keldran of our progress here in Desolace.',
    `RequestItemsText` = 'I have tried to make the magics as simple as possible. Drawing the spirit of your victim out of its injured form should be child''s play. Do not rely on the gem''s power to slay your foe completely. You must only activate the gem when they are close to death, or it will be useless.'
WHERE `entry` = 1435;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have returned from Desolace more than successful, $N. Thank you.$B$BThank you for your efforts, your time, and your understanding to my plea. Thrall understands and desires peace between the Horde and Alliance, and by taking measures to insure our appearance is acceptable, we will not provoke any further threats of unnecessary violence.$B$BI am indebted to you.',
    `RequestItemsText` = ''
WHERE `entry` = 1436;

UPDATE `quest_template` SET
    `OfferRewardText` = 'As you rummage around the remains of the wagon, it becomes obvious that it was attacked by both spells and weapons. The battle seemed one-sided and quick; there''s no blood to be found, and no remains of any bodies.$B$BWhoever attacked the wagon was efficient and swift.',
    `RequestItemsText` = ''
WHERE `entry` = 1437;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank Elune someone has finally come to help. Please, $C, I need your help. My brother Tyranis and I were captured and brought here by the Burning Blade. I think they mean to sacrifice me to their demon masters!$B$BI knew coming to Desolace was a mistake, but Tyranis has recently begun craving knowledge of all things arcane--even against the wishes of our people. He decided to make this trek even after hearing tales of this land''s demon infestation.$B$BI fear the worst for him.',
    `RequestItemsText` = ''
WHERE `entry` = 1438;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is terrible! But I suppose it was necessary. If it wasn''t by your hand, it would have surely been by that of my people''s. I suppose I should thank you--please forgive me if it doesn''t seem sincere. I mean no offense.$B$BWith the knowledge of my brother''s fate in hand, it seems the time for my escape has come. If you are still willing, I will accept your aid in escaping this horrible place.$B$BWhen you are ready, we can make our way to safety.',
    `RequestItemsText` = 'I fear Tyranis will attempt to learn the Burning Blade''s secrets and count himself among their kind if they allow it - he has always adored the power magic brings to those who are seduced by it.$B$BI''m not sure I could endure returning home to my family with news of Tyranis'' spirit flirting with such dangers. It''s a terrible enough crime among my kind to pursue such things, but to become that which we attempt to protect ourselves from, well, that''s apprehensible.'
WHERE `entry` = 1439;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. Dalinda made it safely back here to Nijel''s Point, and in much better condition than I could have asked for. The fact that she arrived here under her own power was a good sign. I hope you''re well?$B$BIt pains me to know that both Tyranis and Dalinda didn''t return, but the embarrassment of Tyranis'' decisions is hers to endure. It is something she will have to deal with when she returns to Darnassus.',
    `RequestItemsText` = ''
WHERE `entry` = 1440;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is indeed the gem Stilwell desires, but before I can allow you to bring it to him, it must be purified of corruption--the naga wenches imbue the gems with power, that much is true, but of their own, evil kind.$B$BLet Stilwell know that its power is intact, and it should work well for whatever ritual he wishes it to be part of.$B$BI hope you know what you''re doing, $C, this is no simple item you possess.',
    `RequestItemsText` = 'I would be less trustful of one not on a holy path if they came asking about a Kor gem. But I trust your kind more than some of my kin. I do not judge your entire order based on the actions of just one of your fallen kind.'
WHERE `entry` = 1442;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It has been quite some time since we spoke, $C. I hope your journey was successful.$B$BWhat knowledge did you gain from the exiled Atal''ai in the Hinterlands?',
    `RequestItemsText` = ''
WHERE `entry` = 1444;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Brave $C, you have proven yourself to be a great champion of the Horde.$B$BNow this collection of fetishes of Hakkar must be dealt with at once!',
    `RequestItemsText` = 'If the Atal''ai fetishes hold the power to summon Hakkar and fulfill Jammal''an''s prophecy they must be seized. Such powers must be understood by the Horde!'
WHERE `entry` = 1445;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Jammal''an''s reckless trust of false visions led my people to their eternal doom.$B$BI thank you, $C, for avenging my exile. I mourn for my people. I have no home to return to.',
    `RequestItemsText` = 'Once Jammal''an has been removed, I stand a chance of returning to my people.$B$BWith Jammal''an as their spiritual leader, the Atal''ai face certain destruction.'
WHERE `entry` = 1446;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, you came to me for a reason. What is it you need?',
    `RequestItemsText` = 'I didn''t mean anything by the comment ''bout you being a stupid $C. We''re friends, right? No hard feelings?'
WHERE `entry` = 1447;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Temple of Atal''Hakkar has been sunk beneath the Pool of Tears? And surrounded by the green dragonflight?$B$BAn amazing discovery, $C. But obviously something has gone terribly wrong.',
    `RequestItemsText` = 'I have traveled the world from the jungles of Azeroth to the snowy peaks of Khaz Modan.$B$BNever before have I asked for help in my adventures. But my old bones are tired.$B$BNothing would leave me feeling more satisfied than knowing that I completed my final quest for the Explorers'' League$B$BIf you''d be so kind as to help me search for the Temple of Atal''Hakkar, $C, I''d greatly appreciate it.$B$BScour the Swamp of Sorrows and report back with your findings!'
WHERE `entry` = 1448;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What do you want, laddy? Can''t you see I''ve got problems to take care of here? Who has time to stand around yapping with some $R chatterbox?$B$BThere are trolls coming out of the woodwork! Make it snappy.',
    `RequestItemsText` = ''
WHERE `entry` = 1449;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, yes. Of course I remember sending one of my gryphon riders to lend a hand to Brohann Caskbelly.$B$BAlways had a soft spot in my heart for the Explorers'' League. My father helped with the initial excavation team that discovered Uldaman as a matter of fact.$B$BI sent who I thought was my best gryphon rider at the time with Brohann. He was a chap by the name of Rhapsody Shindigger.$B$BAnd what a gryphon jockey he was! Well until...',
    `RequestItemsText` = ''
WHERE `entry` = 1450;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hiccup!$B$BI''m a-lookin'' right at you but you keep bobbing up and down. Makin'' me dizzy. Hoho!$B$BHiccup!$B$BWhoa! Did ya feel that? Ground is a-shakin'', my friend. I need a drink.$B$BHiccup!',
    `RequestItemsText` = ''
WHERE `entry` = 1451;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I see ya had no trouble at all getting me what I need! Musta been quite a stint you had over there in far-off Kalimdor.$B$BIt won''t take but a moment for me to extract what I need from these gizzards and livers. Hiccup!$B$BThen I can distill me a fierce ol'' drink and finally tell ya what ya wanna know.$B$BHiccup!$B$BGetting shivers just thinking about that ol'' swamp.$B$BHiccup!$B$BLemme whip up a drink real fast.',
    `RequestItemsText` = 'Ya ever had a Rhapsody Malt? One of my finest brews, if I do say so myself. Hiccup!$B$BBut if I''m gonna relive the horrors of that fateful flight over... hiccup... the swamp, well I''m gonna need me something a wee bit stronger. Hiccup!$B$BDon''t suppose you found me those gizzards and livers I need to add that extra kick to my Kalimdor Kocktail?$B$BHiccup!'
WHERE `entry` = 1452;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Glad to see the Reclaimers aren''t in short supply of work, or adventurers willing to help out.$B$BI''m Kreldig, $N. You''ve made a smart move helpin'' out the Reclaimers. Everyone needs something these days: they''ve lost a family heirloom, a magic item, a loved one. You never can tell. But with the Reclaimers around, there''s no reason, for the right price, everyone can''t find what they''ve lost.',
    `RequestItemsText` = ''
WHERE `entry` = 1453;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You notice the chest does not seem to have any water damage.$B$BThe second thing you notice is that the top has been forced open, and whatever magical traps were set to safeguard it have long been triggered--this much is obvious from the burn marks around its edges.',
    `RequestItemsText` = ''
WHERE `entry` = 1454;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Welcome back to Nijel''s Point, $N. So, tell me what you found.$B$BWhat!? Nothing? An empty chest ain''t gonna get us paid, I''m afraid.$B$BTell me more about these marks you saw... these slashes.',
    `RequestItemsText` = ''
WHERE `entry` = 1455;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is great, $N! You found Karnitol''s belongings!$B$BThose blasted naga, always causing trouble. I think I''d rather spend my life at war with the Horde than have to go against their kind. You''ve done a great service to the Reclaimers.',
    `RequestItemsText` = 'No offense to whoever Nijel is, but this camp ain''t the most comfortable place I''ve spent a night, if you know what I mean, $N.'
WHERE `entry` = 1456;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, the Karnitol business in Desolace. Excellent!$B$BSo, the chest was destroyed, but the items are all here, huh? Well, I''ll let him be the judge of that. One good part about this business I got going on here is that if they''re not satisfied, I can tell ''em to shove it! They''re relyin'' on us to find their stuff... not make sure it''s all pretty and in good shape when they get it back.$B$BGood work, $N. Let''s see about gettin'' you paid.',
    `RequestItemsText` = 'Business is booming, $N, and I don''t have a lot of time for questions. If you''ve got business with the Reclaimers, then let''s hear it. If not, I''m gonna have to ask you to talk to one of me underlings - they''re adept enough at taking care of things ''round here.'
WHERE `entry` = 1457;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good good, $N. Not sure if these are of any good quality, but if Leftwitch wanted a specific type, he should have specified before sending the Reclaimers out here to begin with.$B$BWhat say you to getting on with the next item on his list?',
    `RequestItemsText` = 'Despicable creatures, the satyr. Story says they''re somehow tied to the night elves, but I''m not so sure I believe it.$B$BI think they get that on account of that one elf that brought them into the war few years back. World''s never been the same since. Lot more dangerous, and a lot scarier.'
WHERE `entry` = 1458;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your help here''s a boon, $N. You''re cutting my time spent here in Desolace by half at least. I''ll be back in Ironforge warming my feet in no time with your help.$B$BWhen we get this list taken care of, and I''m back home, look me up, I''ll buy you an ale for sure.$B$BBut until then, let''s get the rest of these reagents gathered.',
    `RequestItemsText` = 'Sorry I couldn''t tell you where to find the kodo or the scorpashi. I''m not terribly familiar with the area, and I haven''t had time to explore.'
WHERE `entry` = 1459;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I give you one in good faith. You already proved yourself once, but me thinkin'' you should be more careful in the future.',
    `RequestItemsText` = ''
WHERE `entry` = 1462;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I give you one in good faith. You already proved yourself once, but me thinkin'' you should be more careful in the future.',
    `RequestItemsText` = ''
WHERE `entry` = 1463;

UPDATE `quest_template` SET
    `OfferRewardText` = 'May fire burn within your heart, $N.$B$BThe elements await you.',
    `RequestItemsText` = 'Speak to Telf Joolam for another Fire Sapta.'
WHERE `entry` = 1464;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Infuriating! This entire fiasco!$B$BThe two of them were warned about how dangerous coming here would be. Now they''re both missing... or worse.$B$BYou said you saw tracks heading to a fort nearby? That may be our best bet.$B$BFrom what the locals have said, that fortress is infested with members of the Burning Blade--orcs who have dedicated themselves to demon causes. They may not represent the majority of the Horde''s beliefs, but they are evil and will slay you on sight if you''re caught spying.',
    `RequestItemsText` = ''
WHERE `entry` = 1465;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Honestly? I wouldn''t have thought it. You''re amazing, $N. Taking on demons for a mage''s experiments, and coming back in one piece to boot. Great job!$B$BI''m personally gonna tell Roetten about you when I get back to Ironforge.',
    `RequestItemsText` = 'I didn''t even realize these demon things were in Desolace. Last I read, centaur pretty much owned the land after the night elves picked up and left years ago.$B$BI wonder why they took up here, and how.'
WHERE `entry` = 1466;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, the package for Leftwitch from Desolace. Excellent. I ''preciate the work, and your timeliness, $C. Glad to have you aboard for at least this small bit of work.$B$BI got your payment right here. Let it be known that Reclaimers Inc. always pays well for a hard week''s work.',
    `RequestItemsText` = 'Well met, $N. Business is booming, the sounds of anvils being struck rings throughout Ironforge, the bellows blow the fires hot, and me wife''s making me a pie for dessert after tonight''s dinner. Could life be any grander?'
WHERE `entry` = 1467;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Um... hi. My name is Randis, and I guess you''re looking after me? You''re an adventurer, like my mom and dad were. I''m happy to meet you.$B$BI hope we''ll have a lot of fun together. I have some things I''d like to do, and the matron says you''ll be like a big brother to me during this week. I''d like that a whole bunch, yes sir.',
    `RequestItemsText` = ''
WHERE `entry` = 1468;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Rhapsody Shindigger! That''s right... how could I forget such a name?$B$BSo he knew about the sinking of the temple all along? Well, that certainly would have saved you some leg work.$B$BBut this Atal''ai artifact! Why, it''s quite a find!',
    `RequestItemsText` = 'At long last you have returned, $N. It has been quite some time since we last spoke. I thought perhaps you had forgotten about my quest.$B$BDid you locate that wily gryphon rider? Did he have anything to report?'
WHERE `entry` = 1469;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Though you are still untested and young in your learning, you have proven that you possess sufficient ability to master the summoning and binding of an imp. Do not be deceived by an imp''s size. Though it lacks physical strength, it possesses powers and a cleverness that will serve you well.$B$BAttend me carefully, $N, for I will not repeat this lesson, and I will leave its mastery to you.',
    `RequestItemsText` = 'Your power is little now, though I suspect already you sense the possibilities.$B$BEven the dead might feel alive, with that power coursing through us.'
WHERE `entry` = 1470;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, $N. Now, I will impart to you the spell used for summoning the voidwalker.$B$BThe power that it unleashed upon you is now yours to command. Use it wisely.',
    `RequestItemsText` = 'I expect to hear of your success, $N. Not meeting my expectations will be the least of your worries, however, should you fail.'
WHERE `entry` = 1471;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You were sent by Carendin? Sithel, then.$B$BDo not think light of me because my sight is gone. I see things that lie behind now, with clarity I had never known. What I once thought a curse, is now a boon.',
    `RequestItemsText` = ''
WHERE `entry` = 1472;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, this is excellent. Like as not, Perrine was ignorant to the true power of the musty book he had stolen from us.$B$BIt will not fall out of our hands again. Observe, $N, the structure of the spell, the manner in which your power must be channeled.',
    `RequestItemsText` = 'Egalin was the teacher that taught me. With hardly a look, he was able to command the voidwalker he had summoned.$B$BWhen it came my turn to try, I was overconfident. Do not trifle with the powers that you wield, $N, they can consume even the vigilant.'
WHERE `entry` = 1473;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Again, you have done well, $N. It has been quite some time since I have seen a young $C with as much potential as you. Be assured that I will continue to watch your progress, and prepare and assist you in your future trials.$B$BFor now, let me show you the summoning spell for your newly dominated succubus.',
    `RequestItemsText` = 'Of the powers from beyond the void, the succubus is one of the most dangerous, as the weak are most easily wrapped around its fingers.$B$BRemember that now and in the future.'
WHERE `entry` = 1474;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Atal''ai Tablets! Thank you, $N!$B$BOnce I deliver these to the Explorers'' League our names shall go down in history together. You have helped an old dwarf fulfill his final obligation in life. For that I am eternally grateful.',
    `RequestItemsText` = 'As dusk slowly descends upon my career I turn to you, $N, to help me in my final quest for the Explorers'' League. If my old bones could muster the strength to brave the Swamp of Sorrows and the sunken temple I would be fighting right alongside you.$B$BPride makes it hard for me to ask for your help in collecting the Atal''ai Tablets. But old age forces the necessity.$B$BPlease help me, $N. I want to retire from the Explorers'' League having completed their final bidding.'
WHERE `entry` = 1475;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The heart of a goodly man seems much the same as any, when you see it like this, don''t you think?$B$BPerhaps we possess something of a... different... view on the subject. These will do, though. I have no doubt that a succubus would be attracted by their purity.',
    `RequestItemsText` = 'I have been pleasantly surprised by the speed of your progress so far, $N. Bring me the hearts and you will impress me once again.'
WHERE `entry` = 1476;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Andromath sent you? Very good. I have an important task for you...',
    `RequestItemsText` = ''
WHERE `entry` = 1477;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good, I see Ageron managed to find you, $N. Let us waste little time with small talk and pleasantries and focus on your training. There is still much you have to learn.',
    `RequestItemsText` = ''
WHERE `entry` = 1478;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wow, it was cooler than I even imagined - the Bough of the Eternals! I didn''t think it''d be so big, but it was! Did you see the bird on top of it too?! I wonder how they got the branches to look like that!$B$BThanks for taking me to Darnassus, $N. You''re awesome!',
    `RequestItemsText` = 'Are we there yet?'
WHERE `entry` = 1479;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmm, these runes are indeed a language, $N, an old language. They seem remotely similar to the Eredun language, but the differences are drastic. If I am not mistaken, this is a contract of some kind.... Here, yes, this symbol is the demon''s signature: Lord Azrethoc.',
    `RequestItemsText` = 'The Burning Blade begin to realize how weak they truly are. Their magics are pathetic, their strength feeble.$B$BTheir only power comes from those they serve, and not from any understanding of true power and knowledge.'
WHERE `entry` = 1480;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The shadowstalkers were unable to slay you, $C. Impressive... most impressive.$B$BThis scalp will do nicely for my spell. While you were away, I was able to gather some of the other reagents needed for the spell.$B$BI am almost ready. I only need a focus for the spell--something to project an image of the demon lord and his whereabouts.',
    `RequestItemsText` = 'Do not bring me an incorrect scalp, $C. Using the incorrect reagents could cause our deaths. The demon lord may have contingency spells on his person to slay those who would scry upon him.$B$BFate has already dealt me enough pain.'
WHERE `entry` = 1481;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A precious oracle crystal... flawless... beautiful. Indeed.$B$BWe shall begin immediately. Finding this demon lord should be our primary concern, and its slaying demands our utmost attention.$B$BTake a step back, $C, and let us see what this demon is, and where he may be found.',
    `RequestItemsText` = 'I am ready for the oracle crystal, $C. Finding and destroying this Lord Azrethoc would garner a great deal of favor with the Warchief for both of us. We would do well to work together and to do so swiftly so we may further our own ends and curry favor with the Warchief.'
WHERE `entry` = 1482;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I thought those Venture Company higher-ups were slave drivers, but then I met Sputtervalve, the cruelest of them all!$B$BHa! Though it''s better than being out of a job, I suppose... Or worse, working with that Gerenzo. If you''re here to help, I''ve got something for you to do.',
    `RequestItemsText` = ''
WHERE `entry` = 1483;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I witnessed what just occurred with Maurin and the demon lord. That creature, even as an apparition, seems to have more power than my warlock companion. I wonder if he''s up to the task of defeating the monster? It would serve the Warchief better if I go myself, but with my responsibilities here, I would disgrace my clan if I turned my back on my duties here to battle this evil for my own honor.',
    `RequestItemsText` = ''
WHERE `entry` = 1484;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Throughout your training as a $C, you will learn to call forth beings of many sorts. Some may not seem it, but all are useful tools.$B$BDo not be fooled by the imp''s small size. As you no doubt noticed, it is still a formidable adversary.',
    `RequestItemsText` = 'It is important that you can control the beings that you summon through your magic. There are few enough interested in learning the ways of the $C that I would risk throwing your life away by teaching you something before you are ready.'
WHERE `entry` = 1485;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your efforts shall not go unnoticed in gathering these hides, $N.$B$BThank you for your dedication.',
    `RequestItemsText` = 'I am very interested in examining the hides from the deviate creatures who have infested these caves. Have you had any luck in collecting some, $C?'
WHERE `entry` = 1486;

UPDATE `quest_template` SET
    `OfferRewardText` = 'As a Disciple of Naralex, I commend your bravery, $N.$B$BYour aid in ridding the caverns is the first step in our long plight to see the Barrens restored.$B$BThank you and may you prosper.',
    `RequestItemsText` = '$N, we, the Disciples of Naralex, need your help. Our numbers are dwindling with our master trapped in his twisted nightmare. We have not the forces necessary to deal with the corrupt creatures which now haunt these caverns.$B$BI beg of you, enter the caves and wage war on the deviate creatures!'
WHERE `entry` = 1487;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A mighty victory for us all, $N. Let us rejoice in your success. I trust now that our future here is not as bleak as I once thought.$B$BThe demons will be slain, the Burning Blade will fail in their efforts, and we may one day have a place we can safely call home again.',
    `RequestItemsText` = 'Glory to the Horde, and death to our enemies, $N!$B$BThe demons in Desolace pose a greater threat than ever before. My hope of returning to the Warchief dwindles as more and more of the foul creatures seem to appear.$B$BI sometimes wish it was only the centaur we had to deal with.'
WHERE `entry` = 1488;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I bid you greetings, $N.  You are welcome here, and I suggest you gather all your strength.  For the task we now set before you ... is a dire one.',
    `RequestItemsText` = ''
WHERE `entry` = 1489;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, it is true.  I know of the druids in the Wailing Caverns.  I have seen their twisted, scaled faces.  I know their crimes, and I know their plans.$B$BYou must stop them, $N.',
    `RequestItemsText` = ''
WHERE `entry` = 1490;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great, you got it!  I can''t wait to try it out.  This is going to make me a fortune, I just know it!$B$BThank you, $N.  Take this, and after I''m rich I''ll send you more, I promise!',
    `RequestItemsText` = 'Where is my wailing essence?'
WHERE `entry` = 1491;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A small enough crate. Yes, I should be able to find room for this aboard the ship. It sails with the next tide, I trust this is soon enough? Excellent. Let me just enter it into my ledger.$B$BAll taken care of! Good day to you, $C.',
    `RequestItemsText` = 'You seek passage on the next ship, or have some item you wish to send aboard it?'
WHERE `entry` = 1492;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah.  I see you have defeated the thunder lizards, which proves you are tough.  Now I will show you how tough skin and shrewd movements can combine to form an impenetrable wall of defense.$B$BLearn your lesson well, $N.  And be ready for future instruction.',
    `RequestItemsText` = 'Do you have the scales, $N?  Unless you can withstand the attacks of the thunder lizards, you will not benefit from my instruction.'
WHERE `entry` = 1498;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, $N.$B$BAlthough the vile familiars were merely pets of the darker powers within the Burning Blade, your success against them foretells greater deeds ahead.',
    `RequestItemsText` = ''
WHERE `entry` = 1499;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good. I hope you inflicted some other losses on the Burning Blade when you went to retrieve this.$B$BThey have been a source of great annoyance for the Warchief, and a great blight upon warlocks as a whole.',
    `RequestItemsText` = 'Do you have the Tablet of Verga, $N? If not, I do not wish to speak with you until you do.'
WHERE `entry` = 1501;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My eyes have long dried out from staring into the forge''s flame, but some things I can still see. I can see you want something.$B$BAnd if you found your way here, then I can guess what you desire.',
    `RequestItemsText` = ''
WHERE `entry` = 1502;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found them! And all the bars are here, which doesn''t surprise me. I didn''t think the Razormanes would know what to do with fine steel like this.$B$BThank you, $N. Here is your reward. May it serve you well.',
    `RequestItemsText` = 'Do you have my steel bars?'
WHERE `entry` = 1503;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, $N. I will show you how to summon the voidwalker similar to the one you just defeated.$B$BYou should know that we have high expectations for you, and you have, so far, matched them.$B$BDo not let it go to your head, however, as the tasks that still lie before you will make this seem as simple as waking in the morning.',
    `RequestItemsText` = 'The voidwalker is a powerful creature. I remember when it was I that was in your shoes, $N. Over the years, my own voidwalker has grown to fight me less, though I suspect that is only because it hopes I will let my guard down.$B$BRemember that, $N.'
WHERE `entry` = 1504;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hello, young one.  Here for some instruction, are you?',
    `RequestItemsText` = ''
WHERE `entry` = 1505;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good. I was afraid Ophek wouldn''t reach you.$B$BIt is time that I further your warlock training. Any business you have currently will have to wait.$B$BI trust there will not be a problem with this?',
    `RequestItemsText` = ''
WHERE `entry` = 1506;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hm... Zarm. You are still new to your path, but I sense the possibility for greatness in you.$B$BYou were born with gifts, $N. See that they do not go to waste.',
    `RequestItemsText` = ''
WHERE `entry` = 1507;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Have you come with news of Dogran? He was to have returned days ago, and I have heard nothing...',
    `RequestItemsText` = ''
WHERE `entry` = 1508;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Zankaja? That''s Dogran''s mate, right?$B$BYeah, I''ve heard from him, but it''s not the sort of news we should let get back to her...$B$BNo, he''s not dead. But he is injured and a prisoner of the quilboar.',
    `RequestItemsText` = ''
WHERE `entry` = 1509;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Another $R, eh? I hope you haven''t come for the other. He didn''t make it. Those goblins did him in good.$B$BHe said he needed a healing draught, but not much else.',
    `RequestItemsText` = ''
WHERE `entry` = 1510;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, it''s about time! Dogran has been dying out there, waiting for this.$B$BWe need to get this out to him right away, but most of the grunts stationed here are out on a foraging mission.',
    `RequestItemsText` = 'Yes, what is it?'
WHERE `entry` = 1511;

UPDATE `quest_template` SET
    `OfferRewardText` = 'If you tell me that this will suffice, then I trust you, $N. Allow me to clean it though... Pristine and shining, it may be even more enticing to a succubus.',
    `RequestItemsText` = 'You have returned. Are you ready to battle a succubus?'
WHERE `entry` = 1512;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Success! Be sure I expected nothing less from my star pupil.$B$BYou have proven your worth, and gladly will I show you the method of summoning your subdued succubus. Go now, you have much to learn, and when next I see you, I will expect you to have found true mastery over your succubus.$B$BLeave the sorrow of Dogran and Zankaja to those of us who are longer in years, but remember it, and hold it as protection against the wiles of the dark power you have learned to summon today.',
    `RequestItemsText` = 'When I look upon a succubus, my heart begins to soar... But at the same time, I can almost sense my soul''s ebb, drifting away like the tides.$B$BBe wary, my friend.'
WHERE `entry` = 1513;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You apply two Cenarion plant salves to the windblossom. It immediately begins to shed its corrupted form, blossoming into a vibrant and healthy plant.',
    `RequestItemsText` = 'You have found a sickly, corrupted version of what appears to be a windblossom plant. The berries that hang from the plant appear rotten and poisonous. It desperately needs some sort of attention if it is to be turned back to normal.'
WHERE `entry` = 1514;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Foul tasting brew...$B$BI can feel the strength in me now, enough to hobble away... But my leg, I will have lost it for the rest of my life. My arm, too.',
    `RequestItemsText` = 'Urrrghhhh...'
WHERE `entry` = 1515;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent. Your success shows that you are prepared.$B$BOf all the elements, earth represents the foundation of all things. It is your strength, your stamina, and your patience. Earth will protect you, but only if shown the proper respect. Like the other elements, even earth can be fickle. Earth is the basis for life, and by observing its laws, you will gain greater wisdom. Never forget the secrets earth shares with you.$B$BI shall make a sapta for you now, and by accepting it, you will realize your path.',
    `RequestItemsText` = 'Patience is earth''s greatest virtue. The earth witnesses the cycle of all things: the mountains becoming deserts; rivers becoming canyons. The earth is the most stubborn and wise of all the elements and it does not tolerate impatience.$B$BThe earth beckons you now because a time of conflict draws near. When you return to me successful, then you shall be that much closer to being made whole.$B$BOthers will be envious of your wisdom and hate you for their ignorance.'
WHERE `entry` = 1516;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah... $N... pleased is the earth to have you here.$B$BBound together in body and spirit, you will go forward knowing that the mountains are your strength; the plains, your patience; and the world itself your essence.$B$BStanding before the earth humbly is all that is required of you for you to pass this rite. But the others are not as passive. They may be chaotic and often violent, but such is the nature of the elements. Dual natures opposing one another, you must come to learn these things intricately.',
    `RequestItemsText` = ''
WHERE `entry` = 1517;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent!$B$BThe totem I will craft for you is more than a symbol of your status among $C--it has abilities beyond that. One use of the totem is as a focus for spells. Those spells are tied to the earth, and as you earn greater and greater wisdom, more of the earth''s abilities will be made accessible to you.$B$BThe trainers will know when you are ready for greater knowledge.$B$BBut for now, take this earth totem, and a scroll to teach you your first ability.',
    `RequestItemsText` = 'I wish to be the first to welcome you fully to the first of four paths that will forever lead you in your destiny.$B$BIf you have the stone the earth gave to you, I will give you the totem it promised.$B$BIf not, then be gone with you until you have found your way.'
WHERE `entry` = 1518;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good, $N. Your return here signifies that you are indeed prepared for the next step.$B$BOf all the elements, earth represents the foundation of all things. It is your strength, your stamina, and your patience. The Earth Mother will protect you, but only if you show her proper respect. She is the basis for life, and by observing her laws, you will gain a greater wisdom. Never forget the secrets she shares with you.$B$BI shall make your sapta for you now, and by accepting it, a new path will open before you.',
    `RequestItemsText` = 'The earth is patient, and will wait for you until you are ready because she knows in time all things erode and are reborn. It is the cycle of things. Mountains become deserts. Rivers become canyons. The earth is the most stubborn and wise of all the elements.$B$BYou must learn patience and stamina above all things. The earth calls for you now because she feels you are ready. Consider this your rebirth if you succeed. You will never be able to go back to ignorance afterwards.'
WHERE `entry` = 1519;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah... $N... pleased is the earth to have you here.$B$BBound together in body and spirit, you will go forward knowing that the mountains are your strength; the plains, your patience; and the world itself your essence.$B$BStanding before the earth humbly is all that is required of you for you to pass this rite. But the others are not as passive. They may be chaotic and often violent, but such is the nature of the elements. Dual natures opposing one another, you must come to learn these things intricately.',
    `RequestItemsText` = ''
WHERE `entry` = 1520;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Splendid.$B$BThe totem I will craft for you is more than a symbol--it has abilities beyond that. One use of the totem is a focus for spells. Those spells are tied to the earth, and as you earn greater and greater wisdom, more of the earth''s abilities will be made accessible to you. Trainers found throughout Kalimdor will know when you are ready for greater knowledge and will let you know as much when you visit them.$B$BBut for now, take this earth totem, and a scroll to teach you your first ability.',
    `RequestItemsText` = 'Greetings, $N. You would not return to me if you had not accomplished your task. May I be the first to welcome you fully to the first path of four that will forever rule your travels.$B$BIf you have the stone the earth gave to you, I will give you the totem it promised. If not, then I pity you. There is much pride to be had when you''ve fully dedicated yourself to the elements.'
WHERE `entry` = 1521;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmmm, Searn sent you to me, did he?$B$BWell then, Searn could always be trusted, so that must mean you''re ready to take part of the next sapta--the sapta of fire.$B$BI see it in your eyes already, the burning, the desire. You''ve tasted power, and now you''re ready for more of it. Patience, $N. Remember what earth taught you. Power and destruction will come easily, but you must still know when to stay your hand.',
    `RequestItemsText` = ''
WHERE `entry` = 1522;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmmm, Narm sent you to me, did he?$B$BWell then, Narm could always be trusted, so that must mean you''re ready to take part of the next sapta--the sapta of fire.$B$BI see it in your eyes already, the burning, the desire. You''ve tasted power, and now you''re ready for more of it. Patience, $N. Remember what earth taught you. Power and destruction will come easily, but you must still know when to stay your hand.',
    `RequestItemsText` = ''
WHERE `entry` = 1523;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, my mistake, $N. I apologize. I did not realize you possessed the Torch. I am pleased to make your acquaintance.$B$BMany adventurers find their way here while looking for lost treasure or the promise of mystical creatures to slay, only to be turned away from a seemingly empty shrine. But we know the truth, do we not, $N?$B$BThis shrine holds a greater secret from the mundane members of the Horde. To us, it is sacred.',
    `RequestItemsText` = 'Greetin''s, $N. You''ve found yerself at the Shrine of the Dormant Flame. Only those knowledgeable enough in the shamanistic arts will ever learn the secrets of this place and the power it holds. I''m sorry you made the trip all this way, only to be turned back now--the journey up here is far from safe after all--but I am the keeper of the shrine, and I cannot allow just anyone to wander around here.'
WHERE `entry` = 1524;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These will do nicely, $N.$B$BFire is more than chaos and destruction--do well to remember that. It is also about life, and creation. All things are tied together in such a way. Forces oppose one another, but at the same time, one cannot exist without the other. Both extinguish one another, but also give one another meaning. Always remember this.$B$BUsing different types of magic in conjunction with one another will show not only true skill, but great wisdom.',
    `RequestItemsText` = 'I have enough ingredients for a sapta of fire if you can find the reagent pouch and some fire tar. The Burning Blade fanatics carry the proper components for most of their spells in those pouches, and usually have enough of the items I need that we will not have to search much farther for anything else.$B$BThe saptas are always made from ingredients that are closely tied to their respective elements. It makes our work easier because of the warlocks'' ties to fire.'
WHERE `entry` = 1525;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A white hot flame ignites within the bowl as you place the ember within. You can feel the magical effects of the sapta coursing through your body and the fire dances rhythmically before you.$B$BYou place the top of the torch within the basin, and it immediately catches on fire.',
    `RequestItemsText` = 'The brazier stands about a third your height, and looks normal, save for the inscriptions along its smooth metal rails. The metal shows no signs of wear from the weather, and the bowl seated at the top of it feels cool to the touch.'
WHERE `entry` = 1526;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your spirit burns brighter than any torch I''ve ever seen, $N, and for that, you should be proud.$B$BIf you continue down this path, the elements will be yours to command, and our brethren will look to you for guidance and wisdom. Let me be the first to congratulate you and present to you your newest totem.',
    `RequestItemsText` = 'Yes, $N? What do you have there?'
WHERE `entry` = 1527;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The wind approaches you quickly from the horizon; the earth is steady beneath your feet; and your spirit is already warmed by fire--I would say it is time for you to learn about the purity of water.$B$BYour path has led you this far, and your spirit will give you the strength to carry on even further. But the first step is yours to take.',
    `RequestItemsText` = ''
WHERE `entry` = 1528;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The wind approaches you quickly from the horizon; the earth is steady beneath your feet; and your spirit is already warmed by fire--I would say it is time for you to learn about the purity of water.$B$BYour path has led you this far, and your spirit will give you the strength to carry on even further. But the first step is yours to take.',
    `RequestItemsText` = ''
WHERE `entry` = 1529;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes?$B$BMmm. I have a feeling I know what you''re going to ask me: what would possess someone to live out here in the deepest part of the Barrens, the threat of quilboar all around, and no protection? Well, we all have our reasons to justify why we act the way we do. The real question is, what brings a lowly $R to the deepest reaches of the Barrens to speak to a woman who obviously has no concern for her own well-being?$B$BI''m willing to bet we both know the answer to that.',
    `RequestItemsText` = ''
WHERE `entry` = 1530;

UPDATE `quest_template` SET
    `OfferRewardText` = 'For the time being. I shall give you what you need to focus your spells and to call upon the spirits of air. Take this totem, and when you are ready, train with me some more.',
    `RequestItemsText` = ''
WHERE `entry` = 1531;

UPDATE `quest_template` SET
    `OfferRewardText` = 'For the time being, I shall give you what you need to focus your spells and to call upon the spirits of air. Take this totem, and when you are ready, train with me some more.',
    `RequestItemsText` = ''
WHERE `entry` = 1532;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wonderful, $N. With all three samples gathered, I can create for you a vial of the purest water any living creature will find. It will be used in the next steps of your rite of passage.$B$BI am pleased to count you among our kind, $N. You do all $C proud, and I look forward to hearing about your exploits in the future.',
    `RequestItemsText` = 'Do you have the water yet, $N? Tales say the ruins were protected by large creatures of nature that do not care for visitors, but those could be myths to scare off the enemies of the night elves.$B$BRegardless, be careful.'
WHERE `entry` = 1534;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I thought some bloodshed might ensue if you tried to take water from the pool. It is a pity the quilboar do not realize that all living things are tied together; that their greed only perpetuates the pain and suffering of their people. How much could they accomplish if they were to put their differences aside and their clans came together.$B$BAgain, a pity, but more than likely a boon for the other races of the Barrens.',
    `RequestItemsText` = 'I am just about prepared to send you on your other tasks. Have you filled the skin yet?$B$BI know how protective the quilboar can be. Even such a small water source is a vast hoard of wealth to them. They have great feasts when even the slightest rain comes to the Barrens. Water is sacred to their kind because it is so scarce. Do you understand?'
WHERE `entry` = 1535;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is good, $N. You''re dedicated to the task at hand and have the ability to seek out that which is needed.$B$BOne more sample is all I need to create the reagent needed for your sapta. Islen will be pleased as well.',
    `RequestItemsText` = 'The well remaining pure within the town reminds me of stories told to me when I was younger, $N. Even in times of great pain and sorrow one can find a sliver of hope, a small symbol to rally around. The orc people see Thrall this way. He survived against great odds and rose up to lead our people through his strength and example.$B$BI''m not sure any orc has suffered as much as he has, but at the same time, I''m not sure any orc is as strong as he is either.'
WHERE `entry` = 1536;

UPDATE `quest_template` SET
    `OfferRewardText` = 'WOW - the dam was WAY bigger than I thought! I could barely hear myself talk from the sound of all the rushing water! Hey, do you think it would ever run out of water? Man, what would happen if that dam ever broke! WOW, that would be scary!$B$BThanks for taking me to see the dam. That was very kind of you. I told you I wouldn''t lean over too far!',
    `RequestItemsText` = ''
WHERE `entry` = 1558;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So you''re an engineer, eh? Well, for your help in getting me those pearls, here''s the recipe for flash bombs.$B$BGood luck, and try not to blind yourself!',
    `RequestItemsText` = ''
WHERE `entry` = 1559;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So he couldn''t find his way back on his own? Figures.$B$BWell, I guess you deserve something for your troubles....',
    `RequestItemsText` = 'Where is Tooga?'
WHERE `entry` = 1560;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, apologies! I didn''t realize you were here to help resupply our troops. The stuff you made will be a big help!$B$BHere are plans for some armor. I hope you find them useful.',
    `RequestItemsText` = 'I have no time to chat. Do you have business with me?'
WHERE `entry` = 1578;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I can''t believe you found them! You must be the luckiest $R in Kalimdor!',
    `RequestItemsText` = 'Did you find my gaffer jacks, $N? Without my gaffer jacks I can''t tune my stintle pegs!'
WHERE `entry` = 1579;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I can''t believe it! You found them! You are the best fisherman I''ve ever seen!$B$BThank you, $N. And here, take these. Although you''re so good and you probably don''t need them, they will help you with your fishing.',
    `RequestItemsText` = 'Did you find any electropellers? I''ll need them if I''m to continue my research on duck decoys...'
WHERE `entry` = 1580;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These are nicely mixed. You take great care in your trade, $N, and that is important for an alchemist.$B$BHere are your herbs, freshly gathered. May you use them well.',
    `RequestItemsText` = 'Hello, $N. Do you have the elixirs to trade?'
WHERE `entry` = 1581;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, these are good pieces. You have a skilled hand and an eye for detail. Your future as a leatherworker is promising.$B$BHere, $N. Let me show you the pattern to make the Moonglow Vest.',
    `RequestItemsText` = 'Greetings, $N.'
WHERE `entry` = 1582;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent... I was never able to gain access to this text, it was held in a protected wing of the library that would have looked suspicious for me to be loitering around.$B$BWell, you did a good job in getting this, and I''m convinced that you can probably handle your own imp, so there''s no reason for me not to show you how to summon one.',
    `RequestItemsText` = 'It was too conspicuous for me to steal the book myself. What luck one of their own patsies did the dirty work for me.'
WHERE `entry` = 1598;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good, very good! You''ve done well, $N. Perhaps the interest that is being shown in you is deserved, after all.$B$BThat''ll be for the others to decide--assuming your imp doesn''t overpower you and nip your career in the bud. For now, I''m satisfied that you''ll probably survive your first few months as a $C.$B$BA word about the imp, $N. As a $R knows, don''t let its size fool you, its magic can be very dangerous.',
    `RequestItemsText` = 'Those feather charms the novices carry have some sort of magical power to them. It will be interesting to research them. I wouldn''t have expected it from the trolls.'
WHERE `entry` = 1599;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. This will help me out tremendously. With the Blackrock orcs attacking from Stonewatch Keep and the Redridge gnolls lurking in the foothills to the north, I''m always fixing armor and making new weapons for our troops.$B$BThe supplies you brought will give me a moment''s peace. I will have enough time to teach you something...',
    `RequestItemsText` = 'I hope you''re here with good news from Ironforge. Because I''m at my wit''s end!'
WHERE `entry` = 1618;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh ho! Have a drink with me, $N. You look tough on the outside, but let''s see if your gut can handle a few mugs of the Pig and Whistle''s strongest!!$B$BOr... were you here for a lesson?',
    `RequestItemsText` = ''
WHERE `entry` = 1638;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hello, fancy boy! What''s a prissy thing like you doing in the Pig and Whistle? Be careful, or you might break a nail...',
    `RequestItemsText` = ''
WHERE `entry` = 1639;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''re a lot tougher than you look!',
    `RequestItemsText` = ''
WHERE `entry` = 1640;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here in Stormwind, I am responsible for putting paladins on the path to greater virtue as they devote themselves to the Light and defend Azeroth from the Scourge and other threats.$B$BThe time has come for you to take your first step towards being truly virtuous. If you accept it, I will give you a Book of Divinity. In studying it, you shall learn some about the Light, and what is expected of you. If you understand it, and are capable, then you will succeed in attaining greater abilities.',
    `RequestItemsText` = ''
WHERE `entry` = 1641;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hello again, $N. How goes your studies of the Tome of Divinity?$B$BThen you should be prepared to have yourself tested. There are always tasks to be done throughout the city and our lands; acts of compassion and understanding; people who need help; creatures to slay.$B$BBy proving you have the patience to help others, especially those who are less fortunate, you prove that you are a servant of the Light and of sound mind.',
    `RequestItemsText` = ''
WHERE `entry` = 1642;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, hello, luv. How go your adventures? Oh, I''m so glad to hear you''re doing well.$B$BOh, me? Thank you for asking--I''m doing well, all things considered.$B$BThe increase in tradesmen has kind of put a damper on the amount of leather and cloth people are willing to part with these days, so it''s been tougher to make clothing for the children at the orphanage, but we''ll manage. By "we" I mean my husband and I. He''s up in Ironforge trying to seek help from the citizens there.',
    `RequestItemsText` = ''
WHERE `entry` = 1643;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N, thank you so much!$B$BThe children will be so pleased, and you''ve saved me so much time. I''ll now be able to focus on the children''s other needs, and hopefully my John will be able to return home sooner than we thought.$B$BThank you again, $N. I knew I could rely on the charity of others. The Light be with you.',
    `RequestItemsText` = 'I hope my John is having better luck in Ironforge. He so dislikes his trips there because it leaves the kids and me alone, but he knows it must be done. He''s so kind-hearted.$B$BSome years have been easier than others, but this one''s been rougher by far. It''s almost as though something in the air is signaling a huge change. Who knows though?'
WHERE `entry` = 1644;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here in Ironforge, I am responsible for putting paladins on the path to greater virtue as they devote themselves to the Light and defend Azeroth from the Scourge and other threats.$B$BThe time has come for you to take your first step towards being truly virtuous. If you accept it, I will give you a Book of Divinity. In studying it, you shall learn some about the Light, and what is expected of you. If you understand it, and are capable, then you will succeed in attaining greater abilities.',
    `RequestItemsText` = ''
WHERE `entry` = 1645;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Welcome back, $N. You''ve spent time reading the book, I hope?$B$BThen you should be prepared to have yourself tested. There are always tasks to be done throughout the city and our lands; acts of compassion and understanding; people who need help; creatures to slay.$B$BBy proving you have the patience to help others, especially those who are less fortunate, you prove that you are a servant of the Light and of sound mind.',
    `RequestItemsText` = ''
WHERE `entry` = 1646;

UPDATE `quest_template` SET
    `OfferRewardText` = 'THE ORPHANAGE OF STOR... oh, sorry, didn''t mean to shout at you, sir.$B$BMy name is John Turner. How are you?$B$BGood, good, glad to hear things go well for you. I''ve had a long day of work already, and I miss my wife terribly, but that''s the price you have to pay when there are mouths to feed and backs to clothe.',
    `RequestItemsText` = ''
WHERE `entry` = 1647;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is so wonderful of you, $N. Thank you again.$B$BYou''re a noble man for doing this for me. It''s no wonder you''ve chosen to follow the Light. I wish there was some way I could repay you for all you''ve done... what''s that? It''s the least you could do? See? That''s what I''m talking about, $N, noble to the end.$B$BBe safe, and may the Light protect you in your travels.',
    `RequestItemsText` = 'What with the influx of tradesmen here and throughout Azeroth, there''s a smaller supply of items we use to make clothes for the children of our orphanage. Helping me collect linen so my wife can make new clothes for them is very noble of you, $N. Thank you.$B$BHopefully, I''ll be able to return home to my wife soon.'
WHERE `entry` = 1648;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, you wish to petition me for a test of valor. Splendid.$B$BThere are many tasks throughout the city and surrounding lands that hold much challenge, and they could use a  man with your skills.$B$BThis test should not be taken lightly, $N. This, like many things along our path, could take our lives. The Church always wishes to bolster its ranks, but it understands the sacrifices needed to ensure the paladins serving it are worthy.$B$BAre you prepared?',
    `RequestItemsText` = ''
WHERE `entry` = 1649;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hello, $N. I''m assuming by all that armor and weapon of yours, you''re either here to try and take my land, or the Church finally sent someone to help protect me while my Jordan''s gone.$B$BWell, let me introduce myself: I''m Daphne Stilwell. It''s a pleasure.$B$BNow, you''re not too late... I''ve only killed a half dozen of the scum since last sun up. They''ve been a little slow getting ''round the bend up there, but they probably saw you coming, which means they''ll probably be here any minute.',
    `RequestItemsText` = ''
WHERE `entry` = 1650;

UPDATE `quest_template` SET
    `OfferRewardText` = 'We''ve done it, $N! Thank you for your help. You were truly amazing out there. I never thought a $C could handle so many enemies at once.$B$BYou''ve truly shown bravery in the face of overwhelming odds.',
    `RequestItemsText` = 'We''ll make our stand at the house!'
WHERE `entry` = 1651;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, we meet again, $N, and you are in high spirits, I see.$B$BThe Stilwell home will be safe for another day, and from your story I see that there was no shortage of danger to be found. Well done.$B$BDaphne and Jordan have helped the Church greatly, and having you protect their property--and their very lives--was the least we could do for them.$B$BFor your valor, you will be rewarded.',
    `RequestItemsText` = ''
WHERE `entry` = 1652;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good day, $N. The Light is with you, I trust?$B$BWhat''s that? You were sent by Duthorian!? My wife, how is she? I knew there was going to be trouble if I left. Please tell me she''s... oh, thank goodness. I''m so glad that she''s safe. The Defias were a threat long before these attacks, but now the King''s advisors cannot deny it.$B$BWhat else did Duthorian have to say?$B$BYou''re the one that was sent to protect my wife? Then I thank you again, $N. I couldn''t think of a better test of valor than that.',
    `RequestItemsText` = ''
WHERE `entry` = 1653;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is wonderful! You''ve gotten all the items.$B$BI should have no problem forging you a grand weapon with these. I''ve actually had the plans for doing this for some time. I just never had the opportunity to gather the goods. Thank you, $N.$B$BIt feels good to have my father''s hammer again...and a Kor gem. I never thought I''d see one of these myself.',
    `RequestItemsText` = 'The items you''re seeking will be difficult to acquire, but I can assure you, the weapon I will craft for you will be worth the effort.$B$BIt will be my finest work to date, and only a small payment for the service you''ve done me.'
WHERE `entry` = 1654;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yup yup, this is it. Ha! If I''d known you were really gonna head out there and fight some o'' them ogres, I woulda given you a list of things to get instead of just this one thing. But, you''re not here doin'' business for me, are ya?.$B$BA deal''s a deal; Jordan wanted a shipment of me alloy, that''s what he''s gonna get.$B$BTell ''em hello fer me, and be safe, $C.',
    `RequestItemsText` = 'So, any luck yet? Haha, those ogres didn''t get the best of ya yet, did they?'
WHERE `entry` = 1655;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, the furs I was expecting. Thank you.$B$BThese came faster than I had expected. They will make good blankets for anyone who wishes to stay here.$B$BPlease feel free to stay as long as you like. My inn is always open and all of our people are welcome here. And don''t underestimate a good night''s rest, it can make a great difference while you''re out traveling.',
    `RequestItemsText` = 'Yes, young one? What can Kauth do for you?$B$BThe journey here from the Mesa can be a tremendous burden for some, but a welcome sight for others. Which is it for you, I wonder?'
WHERE `entry` = 1656;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, well done!  I hope the Alliance chokes on the foul gift we''ve given them, much like we were forced to choke on the yoke of enslavement to the Scourge!$B$BYou''ve kept the ideas of Hallow''s End true, $N, and for that I salute you.  As an extra bonus, let me share some of these Hallow''s End treats I have with you.  I think you might find them to be quite the enjoyable diversion!',
    `RequestItemsText` = 'Have you delivered our "gift" to the people of Southshore?$B$B<Darkcaller Yanka laughs wickedly.>'
WHERE `entry` = 1657;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N.  The Wickerman Festival will continue to be trouble so long as the abominable Forsaken are allowed to haunt the remnants of Lordaeron.  It is NOT a fitting tribute to that once proud kingdom, let me tell you...$B$BHere''s some coin for any repairs you might need, and in the spirit of the season I''ve also included some treats you might like.  Happy Hallow''s End - let''s keep it as safe as possible here in Southshore.',
    `RequestItemsText` = 'Have you gone up to Tirisfal Glade and checked things out?  They usually hold the festival close to the Undercity...'
WHERE `entry` = 1658;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Congratulations, and may the Light protect you.',
    `RequestItemsText` = ''
WHERE `entry` = 1661;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There it is! He sure didn''t want to part with it, but you were persuasive. Well done.$B$BNow for your lesson...',
    `RequestItemsText` = 'I saw your fight with Bartleby. Nicely done! Did you get his mug?'
WHERE `entry` = 1665;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Who''s that?$B$BBurlguard, is that you?$B$BYou''ll have to step a little closer. My eyes aren''t what they used to be.$B$BWalking up like that, I thought you were a gnoll!',
    `RequestItemsText` = ''
WHERE `entry` = 1666;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great, you found it! I feared it was gone forever, used by the Defias to impersonate a Stormwind official. Well that won''t happen now, thanks to you.$B$BHere are some weapons I used when I was a Marshal. I kept them in great shape--take your pick!',
    `RequestItemsText` = 'Do you have my badge? I don''t want to think of the mischief Dead-tooth Jack could cause with it.'
WHERE `entry` = 1667;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Vejrek sure was an ugly one, eh? Nicely done, $N! You have what it takes, now let''s start your lesson...$B$BYou may not know it, but a strong defense is very important to a $C. It keeps him standing against foes that''d fell others, and that''s what your allies need.',
    `RequestItemsText` = 'Have you been to Vejrek''s hut, $N? Is that $R stink I smell on you?'
WHERE `entry` = 1678;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, $N. I heard the warriors of Dun Morogh bouncing your name around. I hope you haven''t spent all your time in the breweries!',
    `RequestItemsText` = 'Did you make the switch?'
WHERE `entry` = 1679;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Muren sent you, did he? Yes, I can make you a nice weapon... but before I do that, I have a favor to ask of you.$B$BDon''t worry. It''s plenty dangerous and could mean your death; it''s exactly the sort of job a $C wants.',
    `RequestItemsText` = ''
WHERE `entry` = 1680;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found it! Well done!$B$BI hope you killed a host of Dark Iron dwarves while searching. I fear that Ironband''s compound won''t be the last place we see them.$B$BBut thank you for the ore, $N. I''m eager to work it and find its properties.',
    `RequestItemsText` = 'Have you entered Ironband''s Compound? Did you find the umbral ore?'
WHERE `entry` = 1681;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here are some weapons, hot off the anvil and made with the new umbral ore you brought me!$B$BPlease, $N, take your pick!',
    `RequestItemsText` = ''
WHERE `entry` = 1682;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N. It is good to know Vorlus is defeated and our moonwell cleansed, and it is good to see young warriors eager to keep our beloved Teldrassil free of corruption.$B$BNow let us begin your training...',
    `RequestItemsText` = 'Do you have the horn, $N? Is our moonwell free of the fiend Vorlus?'
WHERE `entry` = 1683;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I bid you greetings, $N. Your name rings loudly in Darnassus, for you show promise. But we shall soon see if you possess the strength of will to follow the path of the $C.',
    `RequestItemsText` = ''
WHERE `entry` = 1684;

UPDATE `quest_template` SET
    `OfferRewardText` = 'About time you showed up. Though, perhaps I should have sent someone more capable than Remen to find you.$B$BNo matter.$B$BYou''ve gone too long without training, and a warlock without training isn''t like to keep his head on his shoulders for long.',
    `RequestItemsText` = ''
WHERE `entry` = 1685;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Bravely done, $N.$B$BYou have given the Shade of Elura much deserved peace, and we will use the gathered elunite to make a fine weapon for you.',
    `RequestItemsText` = 'Have you defeated the Shade of Elura, $N? And do you have the lost elunite ore?'
WHERE `entry` = 1686;

UPDATE `quest_template` SET
    `OfferRewardText` = 'WOW, that was a real life ghost! That was so awesome - I can''t wait to tell everyone back at the orphanage. Captain Grayson... he even looked like a pirate! When I grow up I wanna be a ghost pirate too!$B$BThanks for taking me to Westfall, $N. I know there are scary things out there in the wilds of Westfall, and I hope I wasn''t too much of a pain. You''re awesome!',
    `RequestItemsText` = ''
WHERE `entry` = 1687;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Surena was talented, but not enough so to gain mastery of $C magic on her own. It''s a shame to see talent wasted, but sometimes it is necessary.$B$BI hope my investment in you will bear different results.',
    `RequestItemsText` = 'Even the older and wiser can be unmanned by the wiles of youth and beauty, $N. A piece of advice you would do well to remember throughout your life.'
WHERE `entry` = 1688;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You did better than I expected, $N, but as well as I''d hoped. Now, you can learn to command your subjugated voidwalker, an ally you will find valuable in the trials that are sure to stand before you.$B$BI have nothing more to teach you at the present, but I am far from done with you, $N.',
    `RequestItemsText` = 'I cannot show you how to control a voidwalker until you have overtaken one.'
WHERE `entry` = 1689;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now that''s what I call efficiency!  You''ve helped thin out the nomad''s numbers enough now that we can start to think about how we can win back those water wells.$B$BThe Gadgetzan Water Company thanks you for your help, but we''re far from done in dealing with those foul nomads.  Listen close - here''s what we need next...',
    `RequestItemsText` = 'Back so soon? I hope you were able to bring some goblin-style justice to those Wastewander Bandits and Thieves like I asked you to!'
WHERE `entry` = 1690;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Top notch work, $N... top notch!  You''ve thinned down the nomad population to a point where we can actually take the fight to them!$B$BIf you haven''t already, talk to Spigot Operator Luglunket here; he gives a bounty on any of the Wastewander water pouches you may have run across while bringing those nomads to justice!',
    `RequestItemsText` = 'Well, were you able to take out those nomads like I asked? The Gadgetzan Water Company is developing plans based on your success here! Don''t let us down, now...'
WHERE `entry` = 1691;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, elunite ore. This is a fine metal to work with, for it is blessed by the goddess Elune herself. It would be an honor to craft weapons with it.$B$BPlease wait while I work...',
    `RequestItemsText` = 'Greetings, young $C. How might my skills serve you?'
WHERE `entry` = 1692;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N, I have crafted these weapons with the elunite you brought to me. Please, take whichever most suits you.$B$BAnd I must thank you. Working with elunite is both an honor and a pleasure.',
    `RequestItemsText` = ''
WHERE `entry` = 1693;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hah! So you heard of my challenge, did you?$B$BWell sit down and listen. Have a drink, and savor it... because it might be your last.',
    `RequestItemsText` = ''
WHERE `entry` = 1698;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You made it! Well done! Three cheers for $N!',
    `RequestItemsText` = ''
WHERE `entry` = 1699;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Furen wrote this? How dare he! Why, I taught him everything he knows! To think he could teach me something is outrageous! Outrageous!$B$BHm... but there is something in his notes that I''d like to try...',
    `RequestItemsText` = 'Hello, and well met. How might I be of service to you?'
WHERE `entry` = 1700;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You got it all? Amazing! I was afraid those chimaeras would eat you up for sure!$B$BWell let''s get started on that armor...',
    `RequestItemsText` = 'How goes the scavenger hunt, $N? Do you have the materials?'
WHERE `entry` = 1701;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, Barleybrew Scalder. Great stuff! So you''ve been to see Yorus, eh?$B$BI can get you a shield, yes sir! You won''t find a better one, and that''s no lying!',
    `RequestItemsText` = 'Hello! Dry times, don''t you think?'
WHERE `entry` = 1702;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These are interesting, very interesting indeed. My dwarven colleague Furen has made quite a grand discovery!$B$BThank you, $N. It will be an honor to apply his new techniques to my own craftings.',
    `RequestItemsText` = 'I bid you greetings, $C.'
WHERE `entry` = 1703;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh my! These notes are amazing! And what''s more... they''re incredible and they''re stupendous and they make my knees go all a-wobbly!$B$BFuren had a breakthrough! A real breakthrough! I can''t wait to try out his new technique!',
    `RequestItemsText` = 'Good day, or morning or evening. I can''t tell from way down here. So do you have business for me?'
WHERE `entry` = 1704;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Nice work! Now if you''ll excuse me, I have some work to do myself...',
    `RequestItemsText` = '$N, do you have the burning blood and rock? I''ll need them to complete the armor.'
WHERE `entry` = 1705;

UPDATE `quest_template` SET
    `OfferRewardText` = '',
    `RequestItemsText` = ''
WHERE `entry` = 1706;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent - the more water pouches we are able to reclaim, the further away from disaster we''ll all be!  Keep ''em coming, and I will be sure to reward you for every five water pouches you bring me.',
    `RequestItemsText` = 'Got the five Wastewander water pouches we need?  If you do, then the Gadgetzan Water Company Care Package, Model 103-XB, will be yours!'
WHERE `entry` = 1707;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That''s the stuff! Well done! Now let me get this smelted and hammered so I can apply Furen''s technique with my own and then we can see what happens!$B$BOh my, oh my! I just know the armor will be very very very tough!',
    `RequestItemsText` = 'Hello hello, $N! Do you have the searing coral? I can''t wait to get to work!'
WHERE `entry` = 1708;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here''s your armor, $N. Furen''s process worked brilliantly! Perfectly! Marvelously, truly!$B$BYou could run this armor over with a siege engine and it would spring right back into shape!',
    `RequestItemsText` = ''
WHERE `entry` = 1709;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, thank you. These will work splendidly!$B$BI will begin fashioning the armor immediately...',
    `RequestItemsText` = 'Do you have the shells, $N? They are quite strong, and can be rendered into a lacquer I will use to coat the links of my new mail armor.'
WHERE `entry` = 1710;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I have finished with your piece of armor, and I am quite pleased. Furen''s new techniques meshed perfectly with my own and I am sure this armor will prove to be quite resilient.$B$BThank you, $N. And may this serve you well in future battles.',
    `RequestItemsText` = ''
WHERE `entry` = 1711;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have gathered the items for my spell, and have shown me your strength and cunning. But the next stage of our quest is even more perilous.$B$BLet us hope your strength does not falter.',
    `RequestItemsText` = 'Do you have the items, $N?  Gathering them is the proof I need that you have the strength to face Cyclonian.'
WHERE `entry` = 1712;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You did it! You defeated Cyclonian and gained the Whirlwind Heart!',
    `RequestItemsText` = '$N, I must have the whirlwind heart!'
WHERE `entry` = 1713;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The charms sink slowly into the cauldron''s depths...$B$BA large bubble rises to the surface of the liquid and breaks...$B$B...And a churning lump of molten rock is revealed.',
    `RequestItemsText` = 'The cauldron bubbles. Its vapors beckon...'
WHERE `entry` = 1714;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Sent by Blackwrench, were you? Damn warlocks in Ironforge need to get things sorted out. There''s only so much room and so many teachers in Stormwind. With all the increased traffic, we''re sure to attract attention sooner or later.',
    `RequestItemsText` = ''
WHERE `entry` = 1715;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Was your crossing difficult, $N? You have come a long way to speak with me. But fear not, I know why Gakin has sent you, and he was wise to, for I can help you in your search.',
    `RequestItemsText` = ''
WHERE `entry` = 1716;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I''m glad someone was able to get a hold of you, $N. I was beginning to fear the worst. It would be a shame to lose you, after the time we''ve invested in you.$B$BWe can talk later, though. Your training is the only important thing now.',
    `RequestItemsText` = ''
WHERE `entry` = 1717;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hello, warrior.  It''s good to see you made it to Fray Island.  I hope you find it to your liking...',
    `RequestItemsText` = ''
WHERE `entry` = 1718;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N.  You have passed The Affray!$B$BYou are a worthy warrior, and I am honored to teach you...',
    `RequestItemsText` = ''
WHERE `entry` = 1719;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, I can tell this will do nicely, let me just work with it for a moment...$B$BTakar is a resourceful fellow to have around, isn''t he? If only I could persuade him to move back to civilization.',
    `RequestItemsText` = 'Was your search a success, $N?'
WHERE `entry` = 1738;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, well done, $N. I see we''ve done right in deciding to train you. Your performance certainly does not disappoint.$B$BI''ve no qualms in showing you the way to control your newly bound succubus. Observe carefully.',
    `RequestItemsText` = 'Sometimes I wonder if Surena was not a succubus in disguise, sent to warp and twist my mind... Ha! I give her too much credit, I think.'
WHERE `entry` = 1739;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes... The orb was not greatly fragmented, and almost all of the pieces are here. It is a simple thing to recreate them, to make Soran''ruk whole again.$B$BI have dedicated my life to the study of the Burning Legion''s orbs and their recreation. You have done me a favor collecting these pieces to study, and I will give you them back - fully reconstructed - in a form of your choosing.',
    `RequestItemsText` = 'It took me many years to collect the pieces of the orb of Zargain, but it has served me well, as I am sure the orb of Soran''ruk will serve you.'
WHERE `entry` = 1740;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Tome of Cabal? Hmm...sounds familiar. I have never seen it here before, though--and believe me, I remember every book I read.$B$BHmm... Ah, yes!$B$BI have seen reference to it in library cataloging books.',
    `RequestItemsText` = ''
WHERE `entry` = 1758;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, you''ve returned so quickly, huh? And what pray tell have you accomplished in your time away from here?$B$BWere you able to help a noble cause? Perhaps you''ve learned the value of charity or some more about your obligations to the citizens of Azeroth. Tell me, who have you helped and how.... Impressive, $N, those are surely the actions of one who follows the Light.$B$BSuch sacrifice will always be rewarded in time.',
    `RequestItemsText` = ''
WHERE `entry` = 1778;

UPDATE `quest_template` SET
    `OfferRewardText` = '*cough*$B$BGood day to ya, $C. Don''t mind me wounds, the good priest ''ere''ll take care of ol'' Muiredon in time. Not needin'' the power of that Symbol of Life ya got there quite yet.$B$BSo, me wife sent ya o''er to speak to me, huh? Fair ''nough. I''ll take the time to talk to ya-I''ll tell ya exactly wut happened to Muiredon and his best friend Narm, a $C jus'' like yerself.',
    `RequestItemsText` = ''
WHERE `entry` = 1779;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve returned so quickly, $N. And what have you accomplished in your time away from the Cathedral?$B$BHave you helped a noble cause? Perhaps you''ve learned the value of charity or some more about your obligations to the citizens of Azeroth. Tell me, who have you helped and how... Well, I''m impressed, $N, those are surely the actions of one who follows the Light and values others above oneself.$B$BSuch sacrifice will always be rewarded in time.',
    `RequestItemsText` = ''
WHERE `entry` = 1780;

UPDATE `quest_template` SET
    `OfferRewardText` = '*cough*$B$BPleasure to meet you, $R. Don''t mind my wounds, the good priest here can take care of ol'' Gazin this time. I won''t be needing the power of that Symbol of Life you''ve got there... not yet anyway.$B$BSo, Duthorian sent you to speak to me, huh? Fair enough. I''ll tell you exactly what befell me and my friend Henze. And with any luck, and some skill on your part, perhaps you can still help us all.',
    `RequestItemsText` = ''
WHERE `entry` = 1781;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here''s your armor, $N. This will stand up to the strongest assaults or my name isn''t Furen Longbeard!$B$BAnd I have to thank you. I learned a lot while working with the materials$B$Byou brought me. I think I''ll have another breakthrough one day!$B$BI''m going to send what I learned to other$B$Bblacksmiths of the Alliance.$B$BI''ll tell them you were a big help, and maybe they''ll want to return the favor.',
    `RequestItemsText` = ''
WHERE `entry` = 1782;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I can''t thank you enough, brother.$B$BI can only assume that Tiza and Muiredon sent you here to aid me if you carry the Symbol of Life.$B$BIt''s true, I fell to the Dark Iron while trying to attain one of the scripts: I was able to hold on long enough to allow Muiredon to escape, but the Light had almost embraced me fully when you came along. The fact that you were powerful enough to use the Symbol means great things for you, but there''s time to speak of that later.',
    `RequestItemsText` = ''
WHERE `entry` = 1783;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Haha! You''ve done it! Ya saved Narm, and ya found the proof me wife needs to take to the council. Yer a blessin'' o'' the Light if I ever saw one... not includin'' me wife o'' course.$B$BThank ya again, $N.',
    `RequestItemsText` = 'Yer back! I''m glad to see it, $N. My wounds are healed and I''m about ready to return to Helm''s Bed lake as soon as I c''n convince me wife that I''ll be fine.'
WHERE `entry` = 1784;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done all of Ironforge a great favor today, $N. I''m proud to count you among us, and if you feel you''re ready, I would like to bless you with this scroll. The Symbol of Life would only have worked when used by a $C who was ready for one of the Light''s greatest blessings-the power to restore the dead back to life.$B$BI will teach you the ability to resurrect your companions. Use it wisely, $N, and thank you, on behalf of myself, my husband, and Ironforge.',
    `RequestItemsText` = ''
WHERE `entry` = 1785;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, brother.$B$BSeeing you wield the Symbol of Life, may I assume Duthorian or Gazin sent you?$B$BI fell to the Defias spell casters while Gazin and I tried to get their plans from them: I was able to hold on long enough to allow Gazin to escape, but in the end, their magics overwhelmed me.$B$BBut you were able to bring me back: the ability to use the Symbol doesn''t come to just anyone, $N. It bodes well for you that you were able to empower it with your own faith.',
    `RequestItemsText` = ''
WHERE `entry` = 1786;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wonderful! You made it, and saved Henze. The Light is with you for sure, $N!',
    `RequestItemsText` = 'Is Henze safe, $N? Were you successful?$B$BBetween your skill with a weapon, and the power of the Light, I''d imagine Heroes'' Vigil is safe from any Defias threat, but that''s for the King and his advisors to say.'
WHERE `entry` = 1787;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done well this day, $N. You should take some pride in what you''ve accomplished.$B$BEven more so, you should be proud of your abilities. Not everyone can use the power of the Symbol of Life. Calling upon the Light to bring back the dead means you''re prepared for one of the $C''s greatest honors: the power of resurrection.$B$BYou shall have the power to bring back fallen companions much like you did for Henze.$B$BBe well, $N. The Light shines upon you and you should welcome it wholly.',
    `RequestItemsText` = ''
WHERE `entry` = 1788;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Make haste, $N, more than one life hangs in the balance if you fail.$B$BIf for some reason you fail to help Muiredon and Narm, then return to me and I will give you another Symbol of Life for your travels.$B$BDon''t mistake my aid as simple charity, you must prove yourself worthy like any other $C and continual failure may reflect upon you later.',
    `RequestItemsText` = ''
WHERE `entry` = 1789;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Make haste, $N, more than one life hangs in the balance if you fail.$B$BIf for some reason you fail to help Gazin and Henze, then return to me and I will give you another Symbol of Life for your travels.$B$BDon''t mistake my aid as simple charity, you must prove yourself worthy like any other $C and continual failure may reflect upon you later.',
    `RequestItemsText` = ''
WHERE `entry` = 1790;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have traveled far, young warrior.  I see fire in your eyes.  You seek a weapon of great power, yes?$B$BI can help you with your quest.  And you can help me with mine.',
    `RequestItemsText` = ''
WHERE `entry` = 1791;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I have the whirlwind heart, and am ready to place it within your vessel of choice.$B$BChoose your weapon, $N, and know that its power is the power of Cyclonian.',
    `RequestItemsText` = ''
WHERE `entry` = 1792;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It has been proven that the Light is with you, $N, but as times grow more dangerous, it becomes important to know what strength lies beneath the flesh. When demons, dragons, or any other evil set foot in your lands, your mettle will be tested. Will you be strong enough?$B$BBravery, regardless of the situation, is as much a part of paladinhood as the Light, your armor, and your weapon. Protecting the weak, and not losing faith are two more lessons you must master while you study in the Cathedral of Light.',
    `RequestItemsText` = ''
WHERE `entry` = 1793;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It has been proven that the Light is with you, $N, but as times grow more dangerous, it becomes important to know what strength lies beneath the flesh. When demons, dragons, or any other evil set foot in your lands, your mettle will be tested. Will you be strong enough?$B$BBravery, regardless of the situation, is as much a part of paladinhood as the Light, your armor, and your weapon. Protecting the weak, and not losing faith are two more lessons you must master while you study in the Cathedral of Light.',
    `RequestItemsText` = ''
WHERE `entry` = 1794;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I must say I''m impressed, $N. When I faced down my felhunter, I barely escaped with my life. I sense that you have the potential to become one of the most powerful warlocks of this era.',
    `RequestItemsText` = 'Every $C should have a felhunter at his command. Though it be difficult to tame, the powers it brings to its master far outweigh the cost.'
WHERE `entry` = 1795;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This will do nicely, $N.$B$BAll magical items must begin with an item of high quality. The more effort and skill put into an item, the greater the magics it can hold. Rare and more expensive components hold the magic better. You will not regret having the robes fashioned into the ones we will make for you later on.',
    `RequestItemsText` = 'How goes your search for the robes, $N? Have you created them yourself? Such personal touches I find make the imbuing of magic that much sweeter. It gives you a greater sense of accomplishment. But I understand if you choose the quicker path and have it made for you - there''s something to be said for such... ambition.'
WHERE `entry` = 1796;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N? Ah, of course. Our latest prodigy. The real thing can not live up to the legend, I am afraid.$B$BNo matter, you have come here to learn, not to hear me make jokes to myself.',
    `RequestItemsText` = ''
WHERE `entry` = 1798;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, so Menara sent you. Fair enough... I suppose you may stay as my guest for the time being. But you must be on some pressing business - perhaps you''re here seeking lost power? Maybe I''m mistaken. Maybe corruption isn''t too far away from you after all.',
    `RequestItemsText` = 'And obviously not being a mage, I wonder if I can trust you at all. I can smell the power of the arcane on you, but you seem to have eluded the stank of corruption that comes so willingly with your kind.$B$BYes, a $C... a $C has come to ask for my help.$B$BWell, what is it I can do for you, $N?'
WHERE `entry` = 1799;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That throne room was scary, $N!  Even though it was empty, it felt like a great evil had happened there.  I felt mad... but I also felt sad too.  I understand why the matrons tell us such stories; I will never betray my people like that!$B$BThank you for taking me to the throne room, $N.  I learned a lot.',
    `RequestItemsText` = 'Are we there yet?'
WHERE `entry` = 1800;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Map making! Pictures, estimations of reality. I have no use for such things.$B$BIn books, narrative, description! That is where truth lies. I would trade all the maps in this store for one book on the rise of necromancy, or a tale of the Dark Lady''s triumph.',
    `RequestItemsText` = ''
WHERE `entry` = 1801;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Fantastic! Now I may join the ranks of the few that have spied its contents.$B$BI can''t wait to further peruse this text. This is a great day, $N! If you will just allow me to glance at it before you leave. I''m sure that Strahad will be willing to send me a copy.',
    `RequestItemsText` = 'Did the rumors prove true, $N?'
WHERE `entry` = 1802;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well well well! What do we have here?$B$BThis is impressive, $N. I wouldn''t have thought it possible, but here it is in my very hands, the complete Tome of the Cabal.$B$BAllow me to leaf through its pages for just a moment before you are off again.',
    `RequestItemsText` = 'It may be that you are chasing after fairy tales, $N, but truth can be found at the center of even the wildest rumors.'
WHERE `entry` = 1803;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done! The Tome of the Cabal and three pristine--slightly scratched, I suppose--rods of channeling.$B$BThis will be interesting. It''s been some time since a young $C took on a felhunter to make his own.',
    `RequestItemsText` = 'Haven''t seen you around these parts for a while. Have you found the tome and the rods?'
WHERE `entry` = 1804;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done! The Tome of the Cabal and three pristine--slightly scratched, I suppose--rods of channeling.$B$BThis will be interesting. It''s been some time since a young $C took on a felhunter to make his own.',
    `RequestItemsText` = 'Yes, $N? Of what service can I be to you?'
WHERE `entry` = 1805;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here it is, $N. A weapon worthy of a champion of the Light such as yourself. I''ve named it after a great dwarven paladin who was a friend of mine. His name was Verigan... Bosch Verigan.$B$BPlease take it on behalf of myself and my wife. We owe you a great debt, and the world will be a safer place with one of your skill traveling the land.',
    `RequestItemsText` = ''
WHERE `entry` = 1806;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''re here for a mission? Good. I have an important one, and one that will test your skill in combat... and your resolve in the defense of the Forsaken.',
    `RequestItemsText` = ''
WHERE `entry` = 1818;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N. Ulag was no minor agent of the Scourge. You have shown the Deathguards, and hence the Dark Lady, that you are a $C of skill and resolve, and are worthy of further instruction.',
    `RequestItemsText` = 'Your task is yet undone, $N. It is not wise for a $C to show fear...'
WHERE `entry` = 1819;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, it is true. I have need for your skills in combat. My means are small, but my task aids both me and the Forsaken''s cause. Do it, and your reward will be twofold.',
    `RequestItemsText` = ''
WHERE `entry` = 1820;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah! You retrieved them! Now the last semblance of honor and memory is stripped from the cursed Agamand lands. The family truly is no more!',
    `RequestItemsText` = 'Do you have the heirlooms, $N?'
WHERE `entry` = 1821;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I will keep three of the weapons you returned to me, as mementos of my pain and loss. But please, $N, choose your favorite of the heirlooms and keep it for yourself.$B$BMay it serve you greater than it served its cursed, former owners.',
    `RequestItemsText` = ''
WHERE `entry` = 1822;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You are here for my trial, $N?',
    `RequestItemsText` = ''
WHERE `entry` = 1823;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Nicely done, $N! In passing the trial at the Field of Giants, you take one more step down the $C''s path.',
    `RequestItemsText` = 'Do you have the antennae? If so then give them to me quickly, for twitching antennae do not twitch forever...'
WHERE `entry` = 1824;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, you have come. This is good, for we have much to discuss, you and I.',
    `RequestItemsText` = ''
WHERE `entry` = 1825;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You brought all that I asked. Now, I will do my part...',
    `RequestItemsText` = 'Do you have the items on my scroll, $N?'
WHERE `entry` = 1838;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Greetings, $N. Old Thun''grim sent word to me of your coming, but had he kept silent your presence here would not have surprised me.$B$BThe spirits follow your progress, young $C, and they tell me that many foes have fallen before you.',
    `RequestItemsText` = ''
WHERE `entry` = 1839;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Greetings, $C. I am Orm, and Thun''grim tells me you wish a helm made?',
    `RequestItemsText` = ''
WHERE `entry` = 1840;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You are here for leg armor? Great!$B$BUm... am I making the armor for you, or are you making it for me?$B$BThat was joke. Was it funny? I can''t tell... I lost my sense of humor the same time I lost my sense of smell. Which was about the same time I stopped breathing.',
    `RequestItemsText` = ''
WHERE `entry` = 1841;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, you have them! Now, just as the Satyrs leeched the strength of Ashenvale, I will leech the power held within these hooves and harness it into my crafting...',
    `RequestItemsText` = 'Do you have the hooves, $N? The magic within them is strong.'
WHERE `entry` = 1842;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. These gauntlets are my best work. Take them. In wearing them, you bring honor to me and my ancestors.',
    `RequestItemsText` = ''
WHERE `entry` = 1843;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have completed your task, $N, and shown me your worth and resolve. The helm will be yours...',
    `RequestItemsText` = 'Do you have the horn? Is the matriarch free of pain?'
WHERE `entry` = 1844;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I give this helm to you.$B$BGreat deeds brought you to me, $N, and Earthmother willing... even greater deeds lie before you.',
    `RequestItemsText` = ''
WHERE `entry` = 1845;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done! These all look strong. I think they''ll do quite nicely. How did those orcs mind you taking their shins, $N? Complain much?$B$BThat was another joke. You''re not laughing.$B$BI''m not very funny these days, am I...',
    `RequestItemsText` = 'I''m waiting for those shinbones, $N. They''ll make a nice frame for your leg guards.'
WHERE `entry` = 1846;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here are your legguards, $N. Let me know how they fit or if you need any modifications. I aim to please! At least I used to.$B$BThese days I don''t care much for my craft. But it beats being a mindless minion of the Scourge!$B$BI guess.',
    `RequestItemsText` = ''
WHERE `entry` = 1847;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I am sure you endured much hardship and shed much blood on my task, $N. Here is the product of your toil.$B$BMay you wear it well, and may you one day return here with stories of its service to you.',
    `RequestItemsText` = ''
WHERE `entry` = 1848;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmmm, now this is interesting. You''ve more than proved your worth with this, Weir. I am quite impressed. Consider yourself the newest member of the Shattered Hand. And take this, it will be a great help to you in the future, I think.',
    `RequestItemsText` = 'Is it not vexing to have the subject of your desire within your grasp, but to have no way of getting to it?'
WHERE `entry` = 1858;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good, I''m glad Kaplak was able to get a hold of you.$B$BWe have some things to speak of, not the least of which is your future with the Hand.',
    `RequestItemsText` = ''
WHERE `entry` = 1859;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have been sent to aid me in my task, $N?  Good.  It is heartening to see young mages eager to help in our cause...$B$BWhat cause, you ask?  In time, young one.  You shall know... in time.',
    `RequestItemsText` = ''
WHERE `entry` = 1860;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. I will test this water for magical properties. Let us hope that it contains none, or we may find that those who drink from Mirror Lake for too long will be adversely affected.$B$BHere, $N. Take this orb or staff as a token of your service. May it serve you well.',
    `RequestItemsText` = 'Do you have the sample, $N? The flow of magic in Stormwind and Elwynn has been altered, and I must know if it is seeping into the water.'
WHERE `entry` = 1861;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent - the more water pouches we are able to reclaim, the further away from disaster we''ll all be!  Keep ''em coming, and I will be sure to reward you for every five water pouches you bring me.',
    `RequestItemsText` = 'Back again, $N?  If you have five more Wastewander water pouches, then I have a care package with your name on it!'
WHERE `entry` = 1878;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, I can see you have promise, yes you do! But it takes more than promise to be a good mage.  And if you''re not a good mage, then you''re a bad mage.  And bad mages are part of the problem, yes they are!$B$BOops, I''m getting ahead of things.  Let''s begin at the start!',
    `RequestItemsText` = ''
WHERE `entry` = 1879;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, splendid day! When I made the gizmonitor I never realized how dependent on it I would become. Now I can begin my studies anew!$B$BThank you, $N! And here - these were my first tools as a $C. They''re a little scratched but they''re well tested. Take your pick - I''m sure you''ll find either of them useful.',
    `RequestItemsText` = 'Did you find the gizmonitor? I must have it before its energy supply runs out!'
WHERE `entry` = 1880;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Greetings, $N.  You were wise to answer my call, and wiser still if you heed what I next say...',
    `RequestItemsText` = ''
WHERE `entry` = 1881;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, a fine specimen this is.  I will send it to be studied by our apothecaries to determine the extent of the Plagueland''s taint.$B$BWell done, $N.  For your services, I present to you this choice: an orb or staff.  Whichever you choose, you will find it quite useful.',
    `RequestItemsText` = 'Do you have the snapdragons?  That breed of flower is highly receptive to magic energies, and studying the snapdragons so close to the Plaguelands can tell us if the plague has entered Tirisfal Glades.'
WHERE `entry` = 1882;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hail, $N.  Praise to you, for my call for aid is now answered.  Let us hope you are up to the task...',
    `RequestItemsText` = ''
WHERE `entry` = 1883;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I sense that Zalazane''s ju-ju heaps were destroyed, and with time, and luck, the flow of magic in Durotar will return to normal.$B$BA great deed you have done for your people, $N. And you have shown your worth to us, the mages of the Horde.',
    `RequestItemsText` = 'You must hurry, $N. Destroy the ju-ju heaps!'
WHERE `entry` = 1884;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hm. No doubt you made your way here at first mention of my summons, yes? Of course. I would expect no less from a prospective Deathstalker.',
    `RequestItemsText` = ''
WHERE `entry` = 1885;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N. You''ve passed the first part of this test. Hopefully Andron will not have caught wind of your activities, and we will be able to convince him that you are, in fact, the messenger he is expecting.',
    `RequestItemsText` = 'Success to report?'
WHERE `entry` = 1886;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, yes, I''ve been expecting you. I have no doubt our mutual acquaintances are pleased with the information that I have provided so far?$B$BI suppose there''s no point in asking you, I doubt they would burden you with this knowledge. Why place so much trust in the messenger, hm?',
    `RequestItemsText` = 'Hello. Something I can do for you?'
WHERE `entry` = 1898;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, this is certainly more information than I suspected to get out of Andron. Give me a moment to peruse it, before I set you to your next task.',
    `RequestItemsText` = 'Success, $N?'
WHERE `entry` = 1899;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You find a nasty ball of water and decide to bring it to me?  Who am I, the Earthen Ring or something?$B$BActually, that does give me an idea... perhaps you do need the Earthen Ring for this.  I mean, if it helps clear up the situation at the lake for good, then I''m all for it.$B$BYou know who the Earthen Ring are, $N?',
    `RequestItemsText` = 'Yeah, what do you need?'
WHERE `entry` = 1918;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N, I have a mission for you, here in the $C district. Listen closely, for there is no time to waste.',
    `RequestItemsText` = ''
WHERE `entry` = 1919;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very well done!  I will study these creatures and, with diligence and luck, determine how they slipped into our world.$B$BYour value to the society of mages grows, $N.',
    `RequestItemsText` = 'Have you captured the creatures, $N?  They must be studied in order to determine the reason behind their arrival.'
WHERE `entry` = 1920;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, these are great pieces of linen.  I can make a fine robe with them.  And after I weave the rift gems into it, we''ll have a garment fit for a $C!',
    `RequestItemsText` = 'Hello, $N.  Jennea told me you would come.  Do you have something for me?'
WHERE `entry` = 1921;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I feared that Morganth had hidden the book elsewhere, or that he had found a way to open it and read its contents.$B$BIt is good to see that he did not, and that the seals we placed on Ur''s Treatise on Shadow Magic still hold.',
    `RequestItemsText` = 'Do you have the book, $N? Its secrets are not meant for the untrained, and plumbing its depths can lead to doom and ruin.'
WHERE `entry` = 1938;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Greetings, $N. I am pleased to see you, and hope you have time to listen to an old man''s words...',
    `RequestItemsText` = ''
WHERE `entry` = 1939;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Nice specimens, these. I''ll get right to work!',
    `RequestItemsText` = 'Ah, yes. The mages of the Wizard''s Sanctum said you''d speak with me. Do you have the required silk?'
WHERE `entry` = 1940;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here is your robe.  It''s one of my best made yet!  Wear it with pride, and when people ask... tell them you got it at the Larson Clothiers!',
    `RequestItemsText` = ''
WHERE `entry` = 1941;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your garment is ready!  And that silk you gathered was so nice... you don''t mind if I made it a little short so that I''d have some silk left over for me, do you?$B$BI''m only joking.  It''ll fit you great, and will be perfect for both adventure and formal dining.  Enjoy!',
    `RequestItemsText` = ''
WHERE `entry` = 1942;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good, you have come.  My task is not an easy one, but vital to the society of mages.  If you aid me, I am sure you will find it worthwhile.',
    `RequestItemsText` = ''
WHERE `entry` = 1943;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, very good. I trust the satyrs of Xavian gave you little trouble?$B$BThank you, $N. I will study this sample of Xavian water immediately.',
    `RequestItemsText` = 'I am pleased you have returned with your skin intact, $N. Do you have the water sample? I am eager to study its properties.'
WHERE `entry` = 1944;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, this hair will weave into a fine robe, $N. It is a pity the laughing sisters had to die to part with it, though I do doubt they would ever give it willingly.$B$BA pity, but only a small one.',
    `RequestItemsText` = 'Greetings, $N. Deino said you would come, and would bring the laughing sisters'' hair. Do you have it?'
WHERE `entry` = 1945;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here is your nether-lace, $N.  It is both comfortable and durable, and holds the magic of the laughing sisters'' hair.$B$BEnjoy, and if you find it amenable, please mention so to Deino.  She is a mage on whose good side I wish to stay...',
    `RequestItemsText` = ''
WHERE `entry` = 1946;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Quiet! I''m in a delicate juncture and mustn''t be disturbed!',
    `RequestItemsText` = ''
WHERE `entry` = 1947;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Aha! You got the jade and made the bramble! Well done!$B$BIs that smoke I see rising from your ears? You might have gotten too close when the lightning struck the totem sticks, but don''t worry. Being hit by lightning is good luck!',
    `RequestItemsText` = 'Hello, $N.  Do you have the items I require?'
WHERE `entry` = 1948;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What?  Speak up!  These old ears aren''t as sharp as they used to be.$B$BWell, I hope you''re here with a fresh mug of ale or some hot tips on the next race!  If not, then you best keep walking... because I have a polymorph wand with your name on it!',
    `RequestItemsText` = ''
WHERE `entry` = 1949;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, now I remember...$B$BI had forgotten about that little curse I put on Johnson.  I can''t remember why I did it but I''m sure it served him right, the little ingrate!',
    `RequestItemsText` = 'What are you waiting for? I need my magic phrase!'
WHERE `entry` = 1950;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That''s it!  It''s just what I need to prepare for the ritual to create your wand!  I hope it wasn''t too much trouble to find...',
    `RequestItemsText` = 'Greetings, $N.  Did you find the book, Rituals of Power?'
WHERE `entry` = 1951;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here are the wands I made.  Take your pick!',
    `RequestItemsText` = ''
WHERE `entry` = 1952;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, yes.  You are here for an orb or a staff, $N?  Very well.  I will aid you in its construction.',
    `RequestItemsText` = ''
WHERE `entry` = 1953;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, that''s a nice one!  No, I don''t mean it''s "nice" like cool juice is nice on a hot day.$B$BIn fact, it''s very NOT nice now that I think about it.  Not the juice.  The orb!$B$BFocus, $N!  We''ll need you focused if we''re ever to finish our task!',
    `RequestItemsText` = 'Do you have an infernal orb, $N?'
WHERE `entry` = 1954;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Nicely done, $N! You gave that demon a lesson he won''t soon forget.$B$BHe''ll think twice before he sticks his ugly head back in this world, looking for the stupid mortal who beat him. Probably with friends this time. Big, scaly friends who''d want nothing more than to tear you into little $R pieces.$B$BI didn''t scare you, did I...$N?',
    `RequestItemsText` = 'You''ll have to kill that demon to remove its taint from the orb, $N.'
WHERE `entry` = 1955;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You did it?  Well done!$B$BI was chatting with some of my colleagues and when your name came up they said, "You know that $N sure works well under stress!"$B$BBut when I told them I sent you to Uldaman against the obsidian sentinel, they said I was crazy!  They said, "Tabetha, you''re crazy!  There''s no way $N could take on that sentinel!"$B$BAnd I said, "We''ll see," and then they said "Yeah, we''ll see..."$B$BWell we sure showed them, didn''t we!',
    `RequestItemsText` = 'Have you been to Uldaman, $N?  Did you defeat the obsidian sentinel?'
WHERE `entry` = 1956;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You did it!  I never doubted you for a second!  Ok, maybe for just a second, or two... but basically I didn''t have much doubt.$B$BHonest.',
    `RequestItemsText` = 'You have not killed the required amount of mana surges, $N.'
WHERE `entry` = 1957;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You should be proud of yourself, $N.  Many mages have fallen to the creatures you faced.$B$BThe Celestial Orb is ready.  Or if you''d like I can mount it atop a staff.  It''s up to you.  I''d prefer the orb, but who am I to judge?',
    `RequestItemsText` = ''
WHERE `entry` = 1958;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is true.  A magical disturbance has been detected in our city.  We are not yet sure of its origin, or whether it is malign or benign.  We must first gather more information...$B$BAnd that, $N, brings us to your task.',
    `RequestItemsText` = ''
WHERE `entry` = 1959;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good, $N.  The creatures within these containment coffers will be studied by our finest minds, and the reason behind their presence in the Undercity will be determined.$B$BIf their appearance is caused by a rift in the natural flow of magic, then we must determine if the rift was random.  If it was not random, but instead an attack by some magical force, then we must prepare for future, more serious disturbances.',
    `RequestItemsText` = 'Have you investigated the disturbance, $N?  Have you captured the creatures?'
WHERE `entry` = 1960;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is very good material, and although I lack the talent to gauge the quality of these mana gems, we''ll soon know if they possess the power needed to create spellfire robes...',
    `RequestItemsText` = 'Anastasia said you would come to me, and I am prepared to fashion your robes.  Do you have the gems and the linen?'
WHERE `entry` = 1961;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here are your robes, $N.  Wear them well.',
    `RequestItemsText` = ''
WHERE `entry` = 1962;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hm, while I am glad to hear that Tazan is no longer with us, a locked satchel does us no good. We need the information kept within.$B$BThis should prove a worthy second challenge for one who wishes to join the Shattered Hand.',
    `RequestItemsText` = 'It is a fool who believes a charge with axe drawn is more dangerous than a knife in the dark.'
WHERE `entry` = 1963;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmm, this is interesting. The Deathstalkers have performed their duties admirably in ferreting this out.$B$BFrom what I understand, you also deserve commendation for your performance. I hope that this will become routine for you, $N, my Deathstalkers always have use of a good man.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 1978;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done well, $N. It occurs to me that you have performed many services for the Deathstalkers, proving your worth, and that perhaps it is time that we furthered your training in the shadow arts.',
    `RequestItemsText` = 'I have placed the utmost faith in you to perform this service for Lord Varimathras.'
WHERE `entry` = 1998;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good, $N! You have learned the fine art of lockpicking well, and faster than I could have possibly expected.$B$BI see that I was right to place my trust in you. Believe me, boy, I foresee that you will go far in this line of work.',
    `RequestItemsText` = 'Have you located the documents, $N?'
WHERE `entry` = 1999;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done the movement a great service, $N. The troggs and leper gnomes infesting Gnomeregan will soon feel the brunt of a gnomish air assault!',
    `RequestItemsText` = '$N! Where are my things?!'
WHERE `entry` = 2038;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So Gnoarn doesn''t trust my reconnaissance abilities? I wonder why...$B$BNevermind that, I need your assistance! Nay! The movement needs your assistance!',
    `RequestItemsText` = ''
WHERE `entry` = 2039;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N. Thanks to you, Gnomeregan is one step closer to its day of liberation!',
    `RequestItemsText` = 'Have you found the Gnoam Sprecklesprocket, $N?'
WHERE `entry` = 2040;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Do you bring word from central command?',
    `RequestItemsText` = ''
WHERE `entry` = 2041;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yarrr... Ye be provin'' yerself to be more than a yella sea dog, landlubber.$B$BThe Cap''n may promote ye to poop deck swabby if ye be keepin'' this up...',
    `RequestItemsText` = 'Where be me first mate, $N? Shackles n'' sharks fer ye soon if ye don''t hurry!'
WHERE `entry` = 2078;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Avast ye scurvy sea dog! Ye did it! Soon me first mate be back in workin'' order and them beasties won''t know what hit em!$B$BHrm, have ye seen me first mate?',
    `RequestItemsText` = 'Have ye found me broke down key, landlubber?'
WHERE `entry` = 2098;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Our work has only just begun, $N. Are you prepared for your next task?',
    `RequestItemsText` = 'Have you brought me the sick animal, $N?$B$BShould you fail to spring the trap, do not fret - Tharnariun''s Hope is eternal. If you require another trap, abandon your task and report back to me.'
WHERE `entry` = 2118;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done Auberdine a great service, $N, but your task is not yet complete.',
    `RequestItemsText` = 'Is your task complete?'
WHERE `entry` = 2138;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have fought for Auberdine with bravery and honor, $N. In our war torn lands, death and despair are common. Many will not rise to meet the challenge of life in our new home, choosing instead to hide in their homes or escape to the more fortified lands of the Alliance.$B$BThank you, $N. Perhaps someday soon we shall fight along side as comrades versus another foe.',
    `RequestItemsText` = 'With the infected Den Mother slain, the population of Rabid Thistle Bears entering our land is lessened. Waste no time, $N.'
WHERE `entry` = 2139;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Rest and relaxation for the tired and cold -- that''s our motto! Please, take a seat by the fire and rest your weary bones.$B$BWould you like to try a sampling of some of our fine food and drink?',
    `RequestItemsText` = ''
WHERE `entry` = 2158;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah yes, the delivery of herbs from Shadowglen. It is a shame Porthannius could not bring it himself, for we have much to discuss, he and I. But I am glad to get the herbs nonetheless, and I am glad you came.$B$BWhile you are here, please, rest yourself. Heroes must keep their strength and spirits high, and must find rest and solace whenever they may. For to neglect one''s peace of body and mind is a sure path to failure.$B$BSo... rest.',
    `RequestItemsText` = 'How might I be of service to you, young one? Are you here to rest in the inn? Do you require a hearthstone?'
WHERE `entry` = 2159;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, at last, the supplies from Hands! I was beginning to worry, we''ve had scarce word from Anvilmar ever since the troggs overran the pass.$B$BThanks for bring this to me, $N. And please, make yourself comfortable. You must be tired after your journey.',
    `RequestItemsText` = 'Hi there! Come in, take a seat by the fire and warm yourself with a flagon of ale.'
WHERE `entry` = 2160;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, this is the food Ukor brought to the Valley of Trials. Did they not need it? Well, I guess they like to starve you heroes in training. Builds spirit, they say!$B$BThank you for returning the food. I''ll stick it back on the shelves... but here, let me offer you some refreshment first!$B$BAnd don''t forget to rest here in the inn. You may be a brave $C ready to take on the world, but if your energy is sapped you won''t be doing yourself, or the Horde, much good.',
    `RequestItemsText` = 'Welcome to Razor Hill!'
WHERE `entry` = 2161;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Fantastic! Try it and tell me what you think, $N!',
    `RequestItemsText` = 'The pot is empty and I''m hungry! What''s taking you so long?'
WHERE `entry` = 2178;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes... I am the jeweler who made this necklace. I also am not in the business of handing out information as though it were free. Information is never free, friend. If I am going to help you out, you need to help ME out first.',
    `RequestItemsText` = 'You''ve got the wrong gnome, pal! I was never there! You can''t prove anything!$B$BWait a second... who are you? What the... where did you find this necklace at?'
WHERE `entry` = 2198;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''re all right in my book; I don''t care what everyone else has been saying... I kid, I kid!  Seriously, thank you my friend.$B$BNow, the necklace you have is one of my finest creations, but it is missing three gems that help bind magic power to it.  I crafted it for a paladin some time ago.  He was on a self-appointed quest to clear out the "evil taint" present at an excavation site in the Badlands called Uldaman.$B$BWell... that paladin died in Uldaman, and that was just the beginning of my woes.',
    `RequestItemsText` = 'Have you got the five silver bars I asked for?  I will share my sad tale of woe with you concerning the necklace you now possess... but only after I get those bars!  Please, help a gnome out, won''t ya?'
WHERE `entry` = 2199;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Remains of a paladin: Reading the journal reveals that after much effort, the paladin had identified the location of all three missing gems:$B$BThe Shadowforge dwarves hid the ruby in their barricaded area as they battled the Troggs for control of Uldaman.$B$BThe troggs stashed the topaz in an urn located near some unusual inhabitants of Uldaman - Alliance dwarves!$B$BFinally, the trogg elder himself took the sapphire as his own.',
    `RequestItemsText` = ''
WHERE `entry` = 2200;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yep, those indeed are the three gems.  Good job!  Unfortunately, your work isn''t quite over just yet.$B$BNo, I''m not trying to pull a fast one here, silly $C.  This is about making magic jewelry - Talvash del Kissel quality-level jewelry!  You need a strong power source to give it some oomph.  Well, that necklace has no more oomph to give.',
    `RequestItemsText` = 'Talvash''s image comes into focus from the waters of the scrying bowl.$B$B"Wow, you''re still alive! Did you manage to find the gems? Are you truly the savior of my reputation I have hoped for? Please tell me you didn''t waste a charge on the phial just to chat; those things are NOT cheap, and I''m already in dire financial straits.'
WHERE `entry` = 2201;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done $N, you''ve proven your worth once again! The caps will be an interesting study, you betcha.$B$BAnd now, as promised, enjoy a taste of one of my more potent restorative brews from my personal stock...$B$BIf you are a skilled alchemist, then perhaps we might have some additional business to conduct. Regardless, I thank you for your assistance!',
    `RequestItemsText` = 'Have you obtained the magenta fungus caps I need for my alchemical work? No caps - no reward!'
WHERE `entry` = 2202;

UPDATE `quest_template` SET
    `OfferRewardText` = 'From one alchemist to another, I salute you.  Here, take this recipe and commit it to your knowledge.  May it bring you the success and rewards that it has brought me over the years.',
    `RequestItemsText` = 'Have you used the vessels to get me the scorched guardian dragon blood I need?  Yes, I know it is a dangerous task... but the recipe for my restorative brew awaits your success.  Risk and reward, my friend... risk and reward...'
WHERE `entry` = 2203;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well I''ll be - I sure am glad to see you and this power source in one piece.  It will take me a moment to magically fuse the power source with the necklace now that the gems have been reunited with it.  Once it is done, however, the necklace will be yours!$B$BYou''re excited, aren''t you?  All tingly with anticipation?  Now where did I put that spell focus at...',
    `RequestItemsText` = 'You didn''t even stop to tidy yourself up after leaving Uldaman, did you.  You just came straight here, lingering dungeon odors be damned.  Well, let''s hope this visit is merely an odiferous one, and not a useless one to boot.$B$BDo you have the power source for the necklace?'
WHERE `entry` = 2204;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found me - and by looking at you, I''d say the run and subsequent search may have been a great strain on your system, both mentally and physically.$B$BWould you like Renzik to show you the way to an inn or are you ready for some work?',
    `RequestItemsText` = 'Can I help you, $C?'
WHERE `entry` = 2205;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I am astonished... Astonished that Keryn finally found a recruit that could possibly have the makings of a proper $C. Take this blade, $N. A day will come when you will be called upon again to serve the SI:7. Hone your skills, keep your eyes open and that blade sharp.$B$BYou won''t see us coming but you''ll feel it when we get there...',
    `RequestItemsText` = 'Your mortality wanes with every moment you waste loitering in the barracks, $C.'
WHERE `entry` = 2206;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So ye think yer a right scoundrel? Destined to be one o'' Blackbeard''s chosen few - an officer o'' the Hidden Circle?$B$BOnly a good fer nothin'' scallywag would think so highly o'' hisself.$B$BThat''s exactly what we be lookin'' fer! Welcome aboard, $N!',
    `RequestItemsText` = ''
WHERE `entry` = 2218;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Shhhh! Keep it down you daft fool. They''ll hear us.',
    `RequestItemsText` = ''
WHERE `entry` = 2238;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Long route? In the name o'' me own beard!$B$BYe done good, $N. Take this dagger and be gone with ye. The Circle will call upon ye again when step three be ready to be set into motion.$B$BWhat''s step three? It comes right after step two - me putting me boot up yer backside.$B$BInterested?',
    `RequestItemsText` = 'Did ye enjoy the stench of leper gnome? I only ask because ye got a crazy smile on yer face.$B$BWhat news do ye bring from Onin?'
WHERE `entry` = 2239;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have seen the Chamber of Khaz''mul? Amazing! Baelog was sure it existed, but I must admit that I had my doubts.$B$BThank you, $N. With luck your finding will incite our leaders to renew their efforts to retake Uldaman. And if it is ever again under Ironforge control, then the secrets of the Chamber of Khaz''mul will be ours!',
    `RequestItemsText` = 'Do you have something to report?'
WHERE `entry` = 2240;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Had I saved every flower that dolt, Jannok, had sent me, I would have had the means to open a shop. Regardless, it seems as if Jannok''s latest courier may prove to be useful.Interested in some work, $C?',
    `RequestItemsText` = 'Oh, isn''t this wonderful. You''ve brought flowers for your own funeral.'
WHERE `entry` = 2241;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is grim news, $N. It would seem that the sickness which has gripped the forests and rivers of Darkshore has begun to taint our home.$B$BYou have served us well, but there is nothing more you can do here. Take this blade as a reward for your service to Teldrassil.',
    `RequestItemsText` = 'Have you anything to report from Sethir the Ancient, $N?'
WHERE `entry` = 2242;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, well done! These should last me for a little while, at least. Here is your pay as promised.$B$BIf you''re interested, I have some more reagents I could use. These, however, are only found in the depths of the Uldaman excavation. They will not be easy to get, but I will make it worth your while if you are interested in helping me again.$B$BPerhaps something more than some shiny coins, yes?',
    `RequestItemsText` = 'Have you gotten the things I need yet? You won''t get paid unless you bring me those reagents.'
WHERE `entry` = 2258;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is time to branch out, $R - the world awaits.',
    `RequestItemsText` = ''
WHERE `entry` = 2259;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have answered SI:7''s calling, $N and journeyed from distant shores to join our ranks, however, there is much for you to learn.',
    `RequestItemsText` = ''
WHERE `entry` = 2260;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Following the instructions of the stone watcher, you once again access the Discs of Norgannon now that you have learned about the history of the Earthen, the troggs, and the dwarves. A faint, brief hum is heard from within the discs. The stone watcher then speaks:$B$B"The discs have now been synthesized. Access the Discs of Norgannon once more to receive your personal copy."',
    `RequestItemsText` = 'The voice of the stone watcher seems to resonate within your very inner being:$B$B"You must first satisfy the data assimilation prerequisite of Discs of Norgannon; once you fulfill this requirement, you will then be permitted to obtain a portable version of the stored data. Please be sure you have fully explored the information within this repository first."'
WHERE `entry` = 2278;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What do you have there... oh my.  You found this where?$B$BNo, really?$B$BYou spoke to whom about what?$B$BNO, REALLY?!$B$BMy fine $C, you may have just made the archaeological find of the year!  By the Gods who am I kidding, the find of the century!  If these discs are what I think them to be, then this could be the very key we have been looking for!  This may well prove outright once and for all the legitimacy of the Dwarves'' enchanted creation!',
    `RequestItemsText` = 'Yes, may I help you with something?  I assure you I am a very busy right now.  If it is grave importance to the Explorers'' League, however, then I am all ears!'
WHERE `entry` = 2279;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What are these here then?$B$BImpressive, young one! These discs, in them I sense secrets that the earth has held on to tightly for many years. You were very wise to bring them here to me.',
    `RequestItemsText` = 'Yes young one, I see you marching into my tent with intensity in your stride... with determination in your purpose. You seek my counsel is some matter of grave importance to the Horde? Perhaps you wish a mystery of the universe revealed to you?'
WHERE `entry` = 2280;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, so your fingers are a little fat, eh? Don''t worry, $N, I''ve turned more useless thieves than you into accomplished rogues.',
    `RequestItemsText` = ''
WHERE `entry` = 2281;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Cracked it open, did you? Nice work, $N.$B$BIf you die now, we can rest easy knowing it was due to your own stupidity and not inexperience.',
    `RequestItemsText` = 'Did I forget to mention the orcs?$B$BI hear they have been nosing around up by the mill.'
WHERE `entry` = 2282;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Mmmm salvage!  I can smell the necklace from here.  Now let''s look at that beauty...$B$BHey, what do you think you''re trying to do here?  This necklace is missing the gems!  You think we wouldn''t notice?  Even Malton could see that the gems are gone.$B$BWell, maybe you didn''t steal them... but this necklace is worthless without those gems!  Your job isn''t done here yet, not by a long shot!',
    `RequestItemsText` = 'Well, do you have the necklace?  You won''t see a copper from us if you don''t have that necklace!'
WHERE `entry` = 2283;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You seem to have found the remains of the paladin that Dran had mentioned from before. Searching the remains uncovers what would appear to be his journal. The book is in poor condition, as dried blood has stained most of the text in the book. What you can read, however, is gibberish; it is written in the native tongue of the humans, to the best of your knowledge.$B$BYou will need the book translated if you are to glean any knowledge from it.',
    `RequestItemsText` = ''
WHERE `entry` = 2284;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It''s always good to have one of Hulfdan''s rogues among our ranks!',
    `RequestItemsText` = ''
WHERE `entry` = 2298;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Keep yer voice down, $N, the guards may hear ye.',
    `RequestItemsText` = ''
WHERE `entry` = 2299;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Are you ready to get to work or do you need to take a nap before we get started?',
    `RequestItemsText` = ''
WHERE `entry` = 2300;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Mighty $C, I know what you are doing out here in the Badlands. I know you seek my gift of tongues. You''re after the parts to that necklace you found in Uldaman.$B$BSurprised? Don''t be - it''s my job to know such things. Instead, let''s discuss what you''re going to do for a translated journal. Trust me - I''m the only one you''ll find that can translate it.$B$BBetter still, let me make you a better offer than Dran Droffers is, and it''ll let you still complete your deal with them. Interested now, yes?',
    `RequestItemsText` = ''
WHERE `entry` = 2318;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You know a good deal when you see one - I knew I could count on you.$B$BIt will be just a moment while I cast a spell to quickly translate the human tongue into a form you will understand. I am a troll of my word; ask anyone in the Horde about Jarkal Mossmeld. Now, let''s get this started...',
    `RequestItemsText` = 'You''ve thought about it, yes? You''re a smart $C if you take this deal - you and I will get what we both want, and Droffers and Son Salvage will think they''re getting what they want.'
WHERE `entry` = 2338;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very well done, $C.  Now the fruits of our redirection will pay themselves out handsomely.  I''m finished with the necklace itself, and I am confident I can duplicate the construction process consistently.$B$BBut first, I will use a specially prepared incantation to quickly analyze those gems before you take them and the necklace back to Orgrimmar.  This will take just a brief moment to do.',
    `RequestItemsText` = 'You''ve got another trip into the depths of Uldaman in store for yourself if you don''t have the gems and a power source capable of channeling magical power back into the necklace.$B$BYou''ll be getting the gems back to deliver to the goons in Orgrimmar; I will be keeping the power source, since it will be the thing that will make the necklace work in the first place...'
WHERE `entry` = 2339;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yep, it''s all here. Say, mind if we keep the bag too? No? Thanks, appreciate it! Har!$B$BThis necklace will be our greatest haul yet! Don''t feel too bad though; I''m sure the necklace wouldn''t fit you anyway. Har again!$B$BA deal is a deal, so here''s your fee for the salvage. Our business is done here for now; check back later to see if we have more work. Until then, beat it!',
    `RequestItemsText` = 'Well, look who it is! Took your sweet time getting here, I see. Let''s hope this isn''t a waste of my time! You''ll not get paid unless you have everything I asked for. And trust me on this - we''ll be double and triple checking everything!'
WHERE `entry` = 2340;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The power source you gave me exceeded every expectation I had for it. I was able to make both you and me a necklace, and I have enough left over to make at least three more. They will fetch quite the fee, with Droffers and Son Salvage none the wiser.$B$BHere you go, my friend. I give you my thanks on a splendid job... and something quite special for your trouble.',
    `RequestItemsText` = ''
WHERE `entry` = 2341;

UPDATE `quest_template` SET
    `OfferRewardText` = 'At last - a broom worthy of a Garrett.  You''re bloody well worth every silver I spent on you, I say!$B$BDo you hear me, foul bats?  I now wield the Garrett family weapon of choice!  Tremble, bats, tremble!!',
    `RequestItemsText` = 'The sweeping never ends... these bats are prolific in their mockery of me and my broom.  Please tell me you''ve reclaimed my family''s treasure!  I''ve offered you my silver - is that not enough?!'
WHERE `entry` = 2342;

UPDATE `quest_template` SET
    `OfferRewardText` = 'To deny Ravenholdt the artifact, would be to deny one''s own existence. Well done, rogue. You may yet walk among the assassins of Ravenholdt.$B$BAs a young rogue adventuring in Darkshore, I discovered a tea that replenishes energy in combat. It has served me well throughout the years and now I pass on a taste of the thistle tea to you. Drink of it when you tire, $N, and fight with vigor once more!',
    `RequestItemsText` = 'Do you have the demon prince''s horns?'
WHERE `entry` = 2358;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This would explain the Defias drones you and Kearnen saw outside of the tower, $N. It would also explain the Venture Company''s involvement with the Defias and the strange shipments out of Duskwood.$B$BAccording to this book, the Zanzil trolls in Stranglethorn have discovered a way to raise the dead through potions... or to be more specific: poison.$B$BYou''ll be of no use to SI:7 without a firm understanding of poisons, $N -- especially with the recipe to create undeath at our fingertips.',
    `RequestItemsText` = 'Any news from Agent Kearnen?'
WHERE `entry` = 2359;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Mathias finally sent another agent to back me up, eh? Well I hope he''s ready to hear some bad news.',
    `RequestItemsText` = ''
WHERE `entry` = 2360;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I gladly give you this necklace, mighty $C.  You have done me an invaluable service, and for that I thank you.  Wear it with pride, and make sure you mention loudly and repeatedly who made it for you!$B$BAlso, if you could toss in the fact that it really isn''t cursed, that would be great.',
    `RequestItemsText` = ''
WHERE `entry` = 2361;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, you are what our mighty allies have sent Shenthul? How uninspiring....',
    `RequestItemsText` = ''
WHERE `entry` = 2378;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Perhaps Zando''zan was wrong. Zando''zan apologizes.',
    `RequestItemsText` = ''
WHERE `entry` = 2379;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is important that the Shattered Hand remains vigilant in the face of the changes Thrall wishes to bring about to the Horde. Our numbers alone will not be enough to overcome his rule - stealth and deception must be mastered.',
    `RequestItemsText` = ''
WHERE `entry` = 2380;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Incredible! Improbable! Simply amazing! You''ve got talent, $N. Either that or you''re the luckiest man alive!$B$BHere''s your cut of the action. I''m sure you would make better use of this stuff than I could.',
    `RequestItemsText` = 'Well, at least you still have all of your body parts. Did you find the treasure?'
WHERE `entry` = 2381;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Another one? The last five that crazy troll sent me ended up as shark food. Let''s hope you fare a little better, eh?',
    `RequestItemsText` = ''
WHERE `entry` = 2382;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, that''s my parchment. I heard you''d be coming to the Valley, $N. I''m glad to see you made it--let''s hope you survive the trials ahead. Like I said, as you gain in power, come to me--I will do what I can to train you in the ways of the $C.$B$BGood luck, $N, and return to me whenever you feel ready.',
    `RequestItemsText` = 'What''s that you have there? A parchment? You''re not a scholar, I hope...'
WHERE `entry` = 2383;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It''s about time you showed up! I was in danger of losing a bet with Olaf!$B$BHe wagered that his beard would grow to his knees before he saw another living $R. Well here you are, and as you can see Olaf''s beard has a few more inches to go.$B$BThanks, $N. I''ll split the winnings with you.',
    `RequestItemsText` = ''
WHERE `entry` = 2398;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The fronds Denalan planted within his garden have sprouted and grown.  They tremble, eager to be picked....',
    `RequestItemsText` = ''
WHERE `entry` = 2399;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That''s great, you found some!  Thanks a lot, $N.  You''re the most dependable $R I''ve met!$B$BI can''t wait to try these on some devices I''ve been tinkering with.  I bet that, under the right circumstances, devices powered with these stones will keep going, and going, and going...',
    `RequestItemsText` = 'Do you have the power stones, $N?  I have a robotic rodent that needs a power supply...'
WHERE `entry` = 2418;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My emerald dreamcatcher is of great importance to me. It is a gift only given to few. Thank you for returning it, $N.',
    `RequestItemsText` = 'Please move swiftly. I can only hope that my emerald dreamcatcher has been unharmed by the furbolg.$B$BHave you recovered it yet, $N?'
WHERE `entry` = 2438;

UPDATE `quest_template` SET
    `OfferRewardText` = 'As yes, a voucher from the Explorers'' League... and quite the valuable one, might I add.$B$BThe Explorers'' League lends me the authority to offer you a choice in your compensation directly from their vault.  You are to receive this item, and you may choose between five superior healing potions or five greater mana potions as your reward.',
    `RequestItemsText` = 'Welcome to the Vault of Ironforge, $N.  What may I do for you today?'
WHERE `entry` = 2439;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well $N, you must have pleased Sage Truthseeker greatly for him to give you this item. You are also to be granted a gift from his cache of potions; you may choose between 5 superior healing potions or 5 greater mana potions as your reward.',
    `RequestItemsText` = 'Greetings, $C! Are you here for alchemy training, or perhaps something else?'
WHERE `entry` = 2440;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It''s good to see another agent of the Shattered Hand in these parts, however, the flare may have been a little too much!$B$BNext time you need to speak with me, blow into this whistle twice and I''ll know you are an ally.',
    `RequestItemsText` = ''
WHERE `entry` = 2458;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now I can repair my dreamcatcher. Thank you, $N.',
    `RequestItemsText` = 'Ferocitas and the Gnarlpine Mystics must return what is mine. Please retrieve the emerald so that I may repair my emerald dreamcatcher.'
WHERE `entry` = 2459;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N. You are now ready to proceed.',
    `RequestItemsText` = 'Practice!'
WHERE `entry` = 2460;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Poor Fizzule, he was a good agent -- one of our best. Alas, it is the price we pay, $N. Being a field agent of the Shattered Hand is dangerous work.$B$BYou have performed your duty well, $C. It would be a shame if you did not live to serve us again.',
    `RequestItemsText` = 'What have you to report, $N?'
WHERE `entry` = 2478;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You look deliciously pale, $C. And what is that foul aroma you are giving off? I must know!',
    `RequestItemsText` = 'What''s this???'
WHERE `entry` = 2479;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The cure is ready! Drink this anti-toxin and the creeping madness will stop, however, I will not be able to do anything about the smell.',
    `RequestItemsText` = ''
WHERE `entry` = 2480;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, so Rellian sent you to aid me. I am glad you arrived here so soon.$B$BI have discovered something quite disturbing!',
    `RequestItemsText` = ''
WHERE `entry` = 2498;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I knew you were more than capable of ridding the lake of that horrible beast.$B$BIt is a distressing situation; Oakenscowl was once a grand leader amongst his kind... but corruption does not discriminate between the lowly and the noble.$B$BThe size of this tumor is quite disturbing, but I must study it to learn more about the disease that upsets the timberling population.$B$BThank you, $N.',
    `RequestItemsText` = 'Have you located Oakenscowl yet, $R?'
WHERE `entry` = 2499;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, well done $N.  These should last me for a little while at least.  Here is your pay, as promised.$B$BIf you''re interested, I have some more reagents I could use.  These, however, are only found in the depths of the Uldaman excavation.  They will not be easy to get, but I will make it worth your while if you are interested in helping me again.$B$BPerhaps something more than some shiny coins, yes?',
    `RequestItemsText` = 'Have you gotten the things I need yet?  You won''t get paid unless you bring me those reagents.'
WHERE `entry` = 2500;

UPDATE `quest_template` SET
    `OfferRewardText` = 'From one alchemist to another, I salute you.  Here, take this recipe and commit it to your knowledge.  May it bring you the success and rewards that it has brought me over the years!',
    `RequestItemsText` = 'Have you used the vessels to get me the scorched guardian dragon blood I need?  Yes, I know it is a dangerous task... but the recipe for my restorative brew awaits your success.  Risk and reward, my friend... risk and reward...'
WHERE `entry` = 2501;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The forest mourns for Lady Sathrah, but it was something that had to be done.$B$BThank you, $N.',
    `RequestItemsText` = 'I regret the task that I have asked you to carry out; but Lady Sathrah is beyond hope.$B$BIt is our hope to offer the sacrifice of the spinnerets to Elune. With this sacrifice, Elune will bless Sathrah so that she might be reborn, and at peace.'
WHERE `entry` = 2518;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, Sister Aquinne sent you?',
    `RequestItemsText` = ''
WHERE `entry` = 2519;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The loss of Lady Sathrah is distressing, but in this way only may she be reborn with a renewed spirit.$B$BMay Elune willingly accept the sacrifice that you have offered her.',
    `RequestItemsText` = 'Have you placed the sacrifice at the fountain, $N?'
WHERE `entry` = 2520;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Do my eyes deceive me? Impossible! Where did you... How...$B$BPerhaps now a rift can be opened, returning us to our homeland.',
    `RequestItemsText` = 'I have dedicated my life to the search of flawless draenethyst spheres. A lifetime, $R!'
WHERE `entry` = 2521;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Simply amazing. I had doubted that you could find another sphere, yet here it is, pulsating in my hands.$B$BWell done, $N!$B$BShould you find anymore--and I believe this to be an impossibility--return them to me and I shall reward you again.',
    `RequestItemsText` = 'Have you found another flawless draenethyst sphere?'
WHERE `entry` = 2522;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You apply some Cenarion plant salve to the songflower. It immediately begins to shed its corrupted form, blossoming into a vibrant and healthy plant.',
    `RequestItemsText` = 'You have found a sickly, corrupted version of what appears to be a songflower plant. A pungent, unhealthy odor emanates from the plant. It desperately needs some sort of attention if it is to be turned back to normal.'
WHERE `entry` = 2523;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N.$B$BWhat an odd trinket this is... I can sense the vile aura emanating from it; this is a very powerful enchantment.',
    `RequestItemsText` = 'If I can examine the charm, I may be able to figure out how to break the enchantment. Have you found one?'
WHERE `entry` = 2541;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I am finally free of the control of the Gnarlpine. Thank you, $N.$B$BMy spirit may now rest peacefully forever in the Emerald Dream.$B$BPerhaps one day we may meet again, young $C. But, for now, please accept this reward as a symbol of my gratitude.',
    `RequestItemsText` = '$N, be wary when approaching my physical form; the enchantment it is under is quite powerful.'
WHERE `entry` = 2561;

UPDATE `quest_template` SET
    `OfferRewardText` = 'How do you feel, $N? You radiate with the aura of the snickerfang--your strength, unmatched by mortals!$B$BUnfortunately, with the components you brought to me, I could only make enough of the assay for one tablet. I will require more components, should you require another tablet.',
    `RequestItemsText` = 'You smell foul, $N. Have you been traipsing in sulfur fields? And where are my components?!'
WHERE `entry` = 2581;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There you go! Remember, use it sparingly. If you require another, come see me after you finish the one you currently have in your possession.',
    `RequestItemsText` = 'Do you have the beast organs?'
WHERE `entry` = 2582;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The spirit of the boar illuminates your being, $N! I wonder, do you believe yourself to be as invulnerable as these beasts?',
    `RequestItemsText` = 'Where are the organs, $N!?'
WHERE `entry` = 2583;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I must warn you, $N, do not attempt to mix the formulas I have created. The chemical properties of the formula you most recently ingested will always take precedence over former enchantments; thus, rendering the other formulation null.',
    `RequestItemsText` = 'Where are the organs, $N!?'
WHERE `entry` = 2584;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Fascinating. This has been the most difficult of all assays to analyze.$B$BTake a pinch of this residual salt and place it under your tongue. You should experience a slight feeling of euphoria followed by a state of unprecedented agility and quickness.',
    `RequestItemsText` = 'Where are the organs, $N!?'
WHERE `entry` = 2585;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Fine work, $N. Here is one sample of the assay for you and the remaining nine will be used in my research.$B$BAnytime you require more of the ground scorpok assay, return to me and we shall work out a deal.',
    `RequestItemsText` = 'Where are the organs, $N!?'
WHERE `entry` = 2586;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is wondrous, $N! My offering to you is a taste of the inner workings of the redstone basilisk.$B$BShould the compound be to your liking, more can always be made... for a price.',
    `RequestItemsText` = 'Have you returned with the requested organs?'
WHERE `entry` = 2601;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, yes, give me a moment and more of the compound will be ready for your consumption, $N.$B$BTake it... and $N, do not attempt to consume these experimental concoctions in rapid succession. The results could be disastrous.',
    `RequestItemsText` = 'Have you returned with the requested organs?'
WHERE `entry` = 2602;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Most excellent! I shall get to work immediately. Perhaps a cure for many of the ailments of the world is to be found!$B$BAh yes, your reward - of course, should you require more of the gum, return to me and another task you shall be given.',
    `RequestItemsText` = 'Do not waste my time, $N. We have nothing to discuss, unless you have recovered the items I have requested.'
WHERE `entry` = 2603;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Perhaps one day I shall be able to isolate the active enzymes of this assay and produce a much more efficient resultant. Unfortunately, you will have to settle for what I am currently able to produce. Return to me should you require more gizzard gum.',
    `RequestItemsText` = 'Do not waste my time, $N. We have nothing to discuss, unless you have recovered the items I have requested.'
WHERE `entry` = 2604;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, wonderful! Give it here -- let me drink it!',
    `RequestItemsText` = 'Please, tell me you found the dew collectors?'
WHERE `entry` = 2605;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Marin''s a good guy, don''t get me wrong -- just a little... eccentric, I''d say.$B$BAnd of course he needs my help, yet again.',
    `RequestItemsText` = 'So old Marin''s up to it again, eh? What''s this concoction made from?'
WHERE `entry` = 2606;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It''s about time! Just put the cheese on the table and skedaddle. Osborne will pay you on the way out.',
