WHERE `entry` = 2608;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What am I doing? What does it look like I''m doing? I''m devising a cure for your ''itis!'' Don''t get indignant with me now, $N!$B$BJust a few more seconds. There! Just spray this, um, fantastic smelling medicine on yourself and you''ll be as good as new.',
    `RequestItemsText` = 'If you want the ''itis'' cured, you''re going to have to try harder than that, $N. Where are the reagents for the cure?'
WHERE `entry` = 2609;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thrall''s Grasp... The story is still fresh in my mind.$B$B<Commander Ruag shakes his head>$B$BTerrible thing that happened to that regiment. The horde lost some of its best soldiers when that battalion was destroyed.',
    `RequestItemsText` = ''
WHERE `entry` = 2621;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Swamp tal... talk.. talker...',
    `RequestItemsText` = ''
WHERE `entry` = 2622;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is worse than I imagined. Nineteen of my men could have been spared from the agony which they faced. If only I had not acted so irrationally.$B$BYou must help them, $N! I am powerless to act.',
    `RequestItemsText` = 'Awaiting orders.'
