UPDATE `quest_template` SET
    `OfferRewardText` = 'That''s the stuff, $N!$B$BIt looks so good, I might just...  Haha, gotcha!',
    `RequestItemsText` = 'Under the waters of that lake -- it''s the only place where the Violet Tragan can be found.  Hope you''re good at holding your breath!'
