UPDATE `quest_template` SET
    `OfferRewardText` = 'Drink this! It''s absolutely wonderful!!!$B$BI knew I had it in me... Oh thanks again, $N for your help, but please, stand a little to the side, will you? You''re blocking my business! I''m going to make millions on the fabulous Noggenfogger Elixir, millions!$B$BWhat''s that? Sprinkle says I owe her a favor? Oh, that Sprinkle, such a kidder!',
    `RequestItemsText` = ''
WHERE `entry` = 2662;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done it, $N! The poor, tortured souls can finally rest.$B$BOur work is not yet over, $N. We have much to discuss and much more to accomplish.',
