UPDATE `quest_template` SET
    `OfferRewardText` = 'You place the hippogryph egg into the machine. A series of beeps follows along with some strange mechanical sounds.$B$BIt appears that the Eggometer has weighed, measured, and packaged your egg. Now that''s speedy service!',
    `RequestItemsText` = 'The Super Egg-O-Matic is the latest of Curgle Cranklehop''s inventions. It is quite an impressive piece of machinery.$B$BThe Super Egg-O-Matic sputters wildly as you approach the control panel.'
WHERE `entry` = 2741;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This troll tablet must be the "secret" that Rin''ji was talking about.$B$BCovered with strange markings, you can not decipher what the tablet says.$B$BOran Snakewrithe sent you to this area in the first place... Perhaps he might be able to tell you more about it.',
    `RequestItemsText` = 'Rin''ji is scared!'
WHERE `entry` = 2742;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The demon lord displays a cunning almost as calculated as his brutality, $N.',
    `RequestItemsText` = ''
WHERE `entry` = 2743;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I will help you. Although, I do not think you fully understand what you are up against.',
    `RequestItemsText` = 'What are you doing here?'
WHERE `entry` = 2744;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What the...?! Don''t sneak up on me like that! And keep your voice down! What in the name of the Shadow are doing sneakin'' up on me for? Can''t you see I''m busy, you daft fool?$B$BWhat do you mean, what am I doing? I''m waiting for the next Dark Portal to open, what the heck do you think I''m doing? Speak your peace and be off with you... ''fore the guards notice the two of us hiding in the bushes together. I have a reputation to maintain.',
    `RequestItemsText` = ''
WHERE `entry` = 2745;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These will do nicely, $N. Great job.$B$BI have the rest of the gear I''ll need in my pack... thank the Light I just got a tailor friend of mine to make me a silk bag. I was running out of room carrying all my gear around.$B$BBefore Spybot heads in, let''s get the details set so you know what you have to do.',
    `RequestItemsText` = 'I''ve been watching Lescovar for a couple weeks now. Trias has never trusted him, but we didn''t suspect he was involved in anything to do with the Defias Brotherhood. We were following leads that tied him to the Twilight''s Hammer. Either way, he''s become more dangerous than this city can deal with, and that''s where we come in.$B$BGet me those items and we can put my plan into effect.'
WHERE `entry` = 2746;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well now, you have one--amazing!$B$BI hope you always remember the good you have done today.',
    `RequestItemsText` = 'I have seen very few eggs retrieved from Feralas in extraordinary condition. These are eggs of the rarest sort...'
WHERE `entry` = 2747;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good, $N. I will be sending this egg to Darnassus where I hope it will soon hatch!$B$BPlease accept this as a symbol of my gratitude.',
    `RequestItemsText` = 'A fine egg is one that will, in ideal conditions, hatch free of the evil effects of the Gordunni ogres'' incantations.'
WHERE `entry` = 2748;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, you have found an ordinary egg, $N? Please give it to me... And we can only hope for the best.$B$BI don''t have much, but please accept this reward. If you ever find yourself in Feralas again, know that I am always here to take the eggs you find there.',
    `RequestItemsText` = 'Ordinary hippogryph eggs hatch about half the time. We do our best to nurture them and with a little luck, they will hatch.'
WHERE `entry` = 2749;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I am afraid I have bad news for you, $N. This egg is too far gone. I can take it from you so that it may be disposed of properly.$B$BPlease don''t be discouraged; we cannot save them all. If you find yourself in Feralas again, please try again. Bring another egg for the Super Egg-O-Matic!',
    `RequestItemsText` = 'These are the eggs that cannot be saved -- they will never hatch.'
WHERE `entry` = 2750;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The bloodline will fade but perhaps the legend of Omosh will continue!$B$BYou have proven that you are a blacksmith, $N. For the blacksmith the reward is the satisfaction of seeing their weapons and armors coated in the blood of their enemies!$B$BMay the breastplates you create for the generations ahead be drenched in the blood of your enemies!',
    `RequestItemsText` = 'Bronze, $N! More bronze!!'
WHERE `entry` = 2751;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You do Orokk proud, $N. Read, learn of iron shoulders!',
    `RequestItemsText` = 'Show me your dedication, $R.'
WHERE `entry` = 2752;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You remind Orokk of his grandfather, Chief Gorokk of Omosh! Read, learn of the iron boot.',
    `RequestItemsText` = 'Their skulls will crack under the pressure of your boots!'
WHERE `entry` = 2753;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Astounding! You have learned the way of the Omosh, $N!',
    `RequestItemsText` = 'Show the iron who is in charge, $N!'
WHERE `entry` = 2754;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Orokk pants.>$B$BIt has been a very long time since Orokk has done the Omosh dance of joy. Learn now, $N!',
