WHERE `entry` = 2755;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It seems you are but another complacent lemming of the Warchief, $N. How disappointing.$B$BHow I long for a glorious death upon the battlefield. Instead, I am stuck here, by order of Thrall, to teach infants how to craft! Watch and learn, child!',
    `RequestItemsText` = 'Aturk, like time, waits for no one! Hurry up fool!'
WHERE `entry` = 2756;

UPDATE `quest_template` SET
    `OfferRewardText` = 'By Blackhoof''s back hair -- finally, one worthy of the Mithril Order!',
    `RequestItemsText` = 'A rare breed your kind be, matey. Let me see that insignia.'
WHERE `entry` = 2757;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good, $N! Listen and learn.$B$BBlacksmithing never comes from here! <Hank points to his hammer.>$B$BBlacksmithing never comes from here! <Hank points to the anvil.>$B$BBlacksmithing only comes from here! <Hank points to his heart.>$B$BAnd now you know the origin of blacksmithing.',
    `RequestItemsText` = 'Could you be the next Galvan protege?'
WHERE `entry` = 2758;

UPDATE `quest_template` SET
    `OfferRewardText` = 'By Blackhoof''s back hair -- finally, one worthy of the Mithril Order!',
    `RequestItemsText` = 'A rare breed your kind be, matey. Let me see that insignia.'
WHERE `entry` = 2759;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, many years it has been since one has been worthy of the Mithril Order''s initiation. We will start now!',
    `RequestItemsText` = 'Hail! Come closer; show Galvan what you have.'
WHERE `entry` = 2760;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your work ethic is impeccable, $N! You are starting to understand the ways of Galvan mineralogy! Take this and learn from it all that you can.',
    `RequestItemsText` = 'After such mining, your muscles bulge and your body aches!'
WHERE `entry` = 2761;

UPDATE `quest_template` SET
    `OfferRewardText` = 'She''s a cruel mistress, is she not, $N? I''m speaking of truesilver, naturally. Aye, Galvan spent over a decade in the mountains of Alterac learning this lesson. Take this and learn from it all that you can!',
    `RequestItemsText` = 'After such mining, your muscles bulge and your body aches!'
WHERE `entry` = 2762;

UPDATE `quest_template` SET
    `OfferRewardText` = 'One can barely keep their eyes from leaving its splendor, $N. Aye, citrine is a glorious gem.$B$BPay attention and learn what such a discovery may teach us!',
    `RequestItemsText` = 'After such mining, your muscles bulge and your body aches!'
WHERE `entry` = 2763;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Galvan the Ancient sent you??$B$B<Trenton bows.>$B$BIt is a great honor to meet another of the master''s pupils!',
    `RequestItemsText` = ''
WHERE `entry` = 2764;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is only fitting that you receive a trinket of far greater power than the one you sacrificed to get here. Use it in good health, $N.',
    `RequestItemsText` = ''
WHERE `entry` = 2765;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You place the egg... distress beacon... inside the chicken... homing robot.$B$BHums and whirs are heard from inside the robot as it struggles to stand up. After the robot comes to life, Oglethorpe''s voice is heard once more, but now from inside the robot:$B$B"OOX-22/FE is working at least, but it needs major repairs! It is much too heavy for you to carry it... but I think I have an idea. Are you up for watching over it some more?"',
    `RequestItemsText` = 'You appear to have uncovered the wreckage of... a robotic chicken? The voice from within the egg crackles to life again:$B$B"Yes, excellent work! This is indeed my homing robot, though my sensors indicate that it needs a jump start before it can fly back to Booty Bay for repairs. Go ahead and place the beacon inside the rover - the beacon will take care of the rest!"'
WHERE `entry` = 2766;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, YOU''RE the great savior of OOX-22/FE!  I cannot even begin to express my thanks for your assistance!  My homing robot series needs more development, but your recovery has saved me countless hours of extra rebuilding time, as well as many gold pieces in manufacture costs!$B$BPlease, take your choice of any of these items I have.  Thank you again for your generous assistance $N, my robots and I are in your debt!',
    `RequestItemsText` = 'Yes, I''m Oglethorpe Obnoticus, master inventor at your service! Now, is there something I could assist you with?'
WHERE `entry` = 2767;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found it! Well done, $N! Did you have to fight Bly for it? I hope you knocked him and his band down good and hard!',
    `RequestItemsText` = 'Did you find Sergeant Bly?  Did you get my divino-matic rod?'
WHERE `entry` = 2768;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, you want to help me?  Great!$B$BThere''s a part I want for an experiment I''m working on, and I need a brave $C like you to help me get it!',
    `RequestItemsText` = ''
WHERE `entry` = 2769;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wow, you got the scale!  Thanks, $N.  I can''t wait to get to work on this thing!$B$BSo you saw Gahz''rilla?  Was he as big as they say??',
    `RequestItemsText` = 'Do you have the scale?  I can''t wait to try different ways to harness its energy!'
WHERE `entry` = 2770;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent! A fair tradeoff, if I do say so myself. Watch and learn, $N!',
    `RequestItemsText` = 'Have you completed the crafting of the items, $N?'
WHERE `entry` = 2771;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The world will be at your feet, $N! Let them all come at your legs, for you are now unsweepable!',
    `RequestItemsText` = 'Have you completed the crafting of the items, $N?'
WHERE `entry` = 2772;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you for all that you have taught me, $N. The master and commander of the ornate mithril set will soon be in your possession.$B$BBehold!',
    `RequestItemsText` = 'Have you completed the crafting of the items, $N?'
WHERE `entry` = 2773;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Finally - justice is served!  You have struck a mighty blow against those vile nomads!  With Scorpidsting''s demise, this might be just the thing to finally push those squatters off of Gadgetzan''s water wells!$B$BBy the authority of the Gadgetzan Water Company, I gladly award you with this bounty.  You''ve done a great service for us all.',
    `RequestItemsText` = 'Yes $C, I am an official of the Gadgetzan Water Company.  What can I assist you with?'
WHERE `entry` = 2781;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This tablet... Quite unusual... Where did you find this, $N?',
    `RequestItemsText` = 'Well, now, what is this?'
WHERE `entry` = 2782;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Alliance wishes to assist?$B$BI thought to never see this day again. A day in which the Alliance fights side by side with the Horde against a common enemy.$B$BIt shall be... we will unite.',
    `RequestItemsText` = ''
WHERE `entry` = 2783;

UPDATE `quest_template` SET
    `OfferRewardText` = 'As a spirit, I am powerless, $N. Assist me. Allow me to regain my honor.',
    `RequestItemsText` = 'Listen to what I have to say.'
