UPDATE `quest_template` SET
    `OfferRewardText` = 'You apply some Cenarion plant salve to the songflower. It immediately begins to shed its corrupted form, blossoming into a vibrant and healthy plant.',
    `RequestItemsText` = 'You have found a sickly, corrupted version of what appears to be a songflower plant.  A pungent, unhealthy odor emanates from the plant.  It desperately needs some sort of attention if it is to be turned back to normal.'
WHERE `entry` = 4113;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You apply some Cenarion plant salve to the songflower. It immediately begins to shed its corrupted form, blossoming into a vibrant and healthy plant.',
    `RequestItemsText` = 'You have found a sickly, corrupted version of what appears to be a songflower plant. A pungent, unhealthy odor emanates from the plant. It desperately needs some sort of attention if it is to be turned back to normal.'
WHERE `entry` = 4114;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You apply two Cenarion plant salves to the windblossom. It immediately begins to shed its corrupted form, blossoming into a vibrant and healthy plant.',
    `RequestItemsText` = 'You have found a sickly, corrupted version of what appears to be a windblossom plant.  The berries that hang from the plant appear rotten and poisonous.  It desperately needs some sort of attention if it is to be turned back to normal.'
WHERE `entry` = 4115;

