UPDATE `quest_template` SET
    `OfferRewardText` = 'Ridding Felwood of Xavathras is only the first step in a long process. It will take much work to repair the damage that has been done here.$B$BI sense that there is something much larger than just the satyrs at work here, but we will only know the truth with time...',
