UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, this is great! Nice feel to it too!$B$BWhat? Oh, yeah... geologists. Got ''em good, did ya? I can''t thank ya enough, $N. That''ll give me some time to finish up in here... I mean, it''ll let me not have to worry about them comin'' back for me anytime soon. Thanks again.',
    `RequestItemsText` = 'I ain''t got all day! Get me those pieces of silk cloth! I mean geologists. Get those geologists! They deserve to feel my, well... your wrath.'
WHERE `entry` = 4449;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, you''ve seen fit to do some of the work I requested. Excellent. And here I thought you were going to ask me to craft you something.$B$BThese are all perfect... and everything''s here. Thank you, $C.$B$BMaybe it wouldn''t hurt to reward you some... hmm, what would you find useful.',
    `RequestItemsText` = 'Yes, yes? What can I do for you, $R? I''m awfully busy and have many patrons requesting my services. Perhaps you can speed things up. I don''t mean to be rude, but I just don''t have the time if I''m to catch up on all my work.'
WHERE `entry` = 4450;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, I''ll be! How in tarnation!? You found the key! I knew them blasted Dark Irons were hiding it after they locked me in here! Thank ya so much, $N. You''re the greatest! Now, just turn the key and let ol'' Locheed outta here!',
    `RequestItemsText` = '*cough*$B$BWho is it? Can''t ya see I''m busy?'
WHERE `entry` = 4451;

