UPDATE `quest_template` SET
    `OfferRewardText` = 'It is disgrace to his memory... a mortal, such as yourself, finishing his life''s work.$B$BTake your amalgamation and be gone!',
    `RequestItemsText` = 'There is a price to pay for all things in this world. The price for the specific item that you seek is thirty gold pieces.$B$BNaturally, I shall retain the majority of the components which you collected. But worry not, you shall have your trinket.'
WHERE `entry` = 4481;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It took Kariel what would amount to several of your lifetimes to complete the libram that you now hold, $R. All for what? So that his disciple could stand in the Burning Steppes and bastardize his research in order to satiate a never ending arcane craving... Curse this foul addiction.$B$BI am disgusted with your lack of compassion and insatiable greed. Be gone!',
    `RequestItemsText` = 'Thirty gold, $R. Thirty gold and the required components.'
WHERE `entry` = 4482;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Other librams are lost in this world. Lost in places you would not dare enter. Places you would pray did not exist.$B$BI will drink in the energies of these components. You shall be given the residual waste...',
    `RequestItemsText` = 'If it is resilience you desire, thirty gold I require.'
WHERE `entry` = 4483;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My head throbs... The energies of the vast expanses that makes up our universe... ARGGH!$B$BTake what you desire and leave!',
    `RequestItemsText` = 'Do not waste my time, $R. Give me what I require. Thirty gold and the components.'
WHERE `entry` = 4484;

