UPDATE `quest_template` SET
    `OfferRewardText` = 'Ringo''s not in the best shape, $N, but I am glad to have him back in one piece!$B$BThank you for finding him.',
    `RequestItemsText` = 'I''ve been so worried about Ringo...'
WHERE `entry` = 4491;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh... I''m so glad someone found me...',
    `RequestItemsText` = 'Wha... What?'
WHERE `entry` = 4492;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, I gathered that Gracina sent you to me.  Your experience in fighting these beasties is priceless; no one to my knowledge has ever dealt with their kind before.  As for Gracina''s idea that Un''Goro Crater is their heart... perhaps it is.  Un''Goro is a mysterious and dangerous jungle to the west of here.  Perhaps it is also one step closer to figuring out what the silithid are all about.',
    `RequestItemsText` = ''
WHERE `entry` = 4493;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, I gathered that Zilzibin sent you to me. Your experience in fighting these beasties is priceless; no one to my knowledge has ever dealt with their kind before. As for Zil''s idea that Un''Goro Crater is their heart... perhaps it is. Un''Goro is a mysterious and dangerous jungle to the west of here. Perhaps it is also one step closer to figuring out what the silithid are all about.',
    `RequestItemsText` = ''
WHERE `entry` = 4494;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I''m so glad you found me, $N. How did you know I was here?',
    `RequestItemsText` = ''
WHERE `entry` = 4495;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The scent gland, ah yes.  The membrane appears intact - excellent.  The soil, yes, this should work out perfectly.  With my special additions, I should be able to grind all this up into the perfect lure.$B$BGive me a moment to make the lure, $N.  Once it''s ready, we''ll be able to enact the next step that may hopefully stop the silithid before they overrun Gadgetzan... and the rest of Kalimdor.',
    `RequestItemsText` = 'Finding a suitable scent gland might take a bit - the gland can''t be damaged, but the process of getting one certainly doesn''t lend itself to it.  As for the soil, I''d assume it should be easy enough to find.$B$BAnyway, do you have the items I need to make the lure?'
WHERE `entry` = 4496;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I am absolutely terrified of the pterrordax here! Thank you for decreasing their numbers, $N. Now I might feel safe enough to venture out of Marshal''s Refuge.',
    `RequestItemsText` = 'To tell you the truth, I really wasn''t that worried about the strange creatures... Until the day that I saw it written on the side of a large stone.$B$BBEWARE OF PTERRORDAX$B$BWho could have written it? I don''t know, but it''s too creepy to just ignore!'
WHERE `entry` = 4501;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These samples will be perfect for my studies! Thank you, $N! I promise, you''ll be the first one I will tell about my findings.',
    `RequestItemsText` = 'Is it true that the volcano in Un''Goro is active? I''m sure I could learn a lot with some ash from the volcano, $N.'
WHERE `entry` = 4502;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, these scales are perfect. I should be able to get this flyer off the ground with these scales for sure!$B$BThanks!',
    `RequestItemsText` = 'Every great vehicle needs a name... I was thinking I''d call it... Pwned!'
WHERE `entry` = 4503;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, this tar is just the stuff...$B$BHey, wait a minute, my hands... I can''t seem to get them apart...$B$BMaybe this wasn''t such a good idea. Oh, but wait! Super sticky tar remover! That''s where the real money is!',
    `RequestItemsText` = 'Tran''rek''s done it again -- this super sticky glue will be all the rage!'
WHERE `entry` = 4504;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very well. We must find a way to use this corruption against our enemies...',
    `RequestItemsText` = 'This is of utmost importance. Be on your way, now.'
WHERE `entry` = 4505;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent!$B$BThe forsaken will resort to any means necessary to crush the alliance! The use of the corrupted water will surely prove useful in our future efforts...',
    `RequestItemsText` = 'Don''t tell me that you can''t go back there! Get going!'
WHERE `entry` = 4506;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Fantastic, $N!  We''ve won quite the victory here today.  It will take some time for us to fully understand what we have here; we''ll put it to good use though, don''t you worry about that.$B$BAs for the silithid, I genuinely doubt that this was the full extent of their presence.  This is much too clean of a resolution, I''m sorry to say.',
    `RequestItemsText` = 'Acquiring the queen''s brain for our research is absolutely imperative.  From what we have learned, we believe that these silithid are quite possibly being controlled by a malign intelligence.  I shudder to think what could control something as insidious as the silithid, $N.'
WHERE `entry` = 4507;

UPDATE `quest_template` SET
    `OfferRewardText` = 'While I genuinely appreciate this, I am not sure what good it will do us.  The Alliance ignores threats from any source other than the Horde, and even our own leaders here in Darnassus cannot agree on what exactly this threat is.  Fools like Fandral Staghelm theorize that the silithid are nothing like the threat from the ancient past I claim them to be.  His ignorance is only surpassed by his arrogance.$B$BYou have seen the threat yourself, $N.  We must remain committed to defeating the silithid!',
    `RequestItemsText` = 'They are fools, $N!  They cannot even think to look around them for a greater threat; their irrational hatred of the Horde will be the end of us all.  I do not know how much more proof I can give them of the silithid threat short of dropping them in one of the hives so they can see for themselves!$B$BI''m sorry, you bring news for my attention?'
WHERE `entry` = 4508;

UPDATE `quest_template` SET
    `OfferRewardText` = 'While I genuinely appreciate this, I am not sure what good it will do us.  The Horde ignores threats from any source other than the Alliance.  While Thrall himself might take action were the facts presented to him, he is beset on all sides by conflicting advice.  These fools would have us chase our own imaginary tails were they to think it might catch the Alliance unawares!$B$BYou have seen the threat yourself, $N.  We must remain committed to defeating the silithid!',
    `RequestItemsText` = 'They are fools, $N!  They cannot even think to look around them for a greater threat; their irrational hatred of the Alliance will be our undoing.  I do not know how much more proof I can give them of the silithid threat short of dropping them in one of the hives so they can see for themselves!$B$BI''m sorry, you bring news for my attention?'
WHERE `entry` = 4509;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This bank voucher authorizes me to withdraw an item from Gracina Spiritmight''s account with us and present it to you.  Congratulations would seem to be in order!',
    `RequestItemsText` = 'Elune''adore, $C.  What may I do for you today?'
WHERE `entry` = 4510;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This bank voucher authorizes me to withdraw an item from Zilzibin Drumlore''s account with us and present it to you.  Congratulations would seem to be in order!',
    `RequestItemsText` = 'Zug zug!  What may I help you with today, $C?'
WHERE `entry` = 4511;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Amazing results, $N! You got close enough to take a sample of the corrupted things, and managed to look no worse for wear! Thank you. Oh, these samples will be perfect. I can''t wait to start testing on them.$B$BIf I''m right, I could be one of the Explorers'' Leagues greatest scientists!$B$BThat''ll prove to all the dwarves that it wasn''t a mistake to allow us gnomes into Ironforge  after the Gnomeregan incident.',
    `RequestItemsText` = 'Some of the experiments I''ve done are fascinating. I think with a little more work, I''ll be able to figure out the nature of these creatures and how they play into how life developed on Azeroth... if they even have anything to do with it to begin with.$B$BOne of my biggest theories that isn''t well liked is the idea that oozes and slimes are tied to the creation of this planet... almost like they''re a secretion of it.$B$BBut I can''t prove or disprove it until I get more samples.'
WHERE `entry` = 4512;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve found it? $N, you are a treasure unto yourself. Your dedication and aid has been magnificent and I could not possibly thank you enough.$B$BPlease, take this for your troubles. I have some work to do, but I''m sure, if you come back at a later time, I''ll have need of your services again.$B$BThank you. Thank you so much.',
    `RequestItemsText` = 'So many things to consider. But what does it mean? And how does it affect the lives of the people of Azeroth?'
WHERE `entry` = 4513;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is excellent news, $N. With these beasts out of the way, we can begin to adventure further into Winterspring. Are you ready for more?',
    `RequestItemsText` = 'Report back to me after you have completed the task I gave you.'
WHERE `entry` = 4521;

UPDATE `quest_template` SET
    `OfferRewardText` = 'More bad news! These centaurs have gone too far! They raided one of my supply caravans and slaughtered the whole party. This is an outrage, and it will not go unpunished!',
    `RequestItemsText` = 'What do you want, $C? An urgent message - for me?'
WHERE `entry` = 4542;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You pick up the petri dish with the slime sample in it. The only way to discern if the samples is pure enough is to open it and examine the contents yourself. Ideally you''ll find a sample that fits Chemist Fuely''s criteria.',
    `RequestItemsText` = 'You take a sample of slime from Un''Goro Crater and place some of it into the various tubes and beakers on the table. As things begin to boil and spurt, the slime changes colors. When the process slows down and the liquids calm, you see a small petri dish with your purified Un''Goro slime samples in it along with some other remnants.'
WHERE `entry` = 4561;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, Shindrell''s report!  Many thanks, $N.  Shindrell is a fine sentinel, brave and keen.  I must read this for clues of a wickedness I fear is moving through Ashenvale.',
    `RequestItemsText` = 'Do you have something for me?'
WHERE `entry` = 4581;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You insert the grime-encrusted item and three silver coins into the Sparklematic 5200. The machine surges to live in an almost frenzied attempt to purge the grime from the unknown item. Loud, violent churning sounds beat from the heart of the machine. The metal frame of the beast creaks and groans as it lurches from side to side...',
    `RequestItemsText` = 'It would seem that the device needs some sort of grime-encrusted object to clean and three silver coins to get the contraption working. So long as both are present, the Sparklematic 5200 should work...'
WHERE `entry` = 4601;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You insert the grime-encrusted item and three silver coins into the Sparklematic 5200. The machine surges to life in a frenzied attempt to purge the grime from the unknown item. Loud, violent churning sounds beat from the heart of the machine. The metal frame of the beast creaks and groans as it lurches from side to side...',
    `RequestItemsText` = 'It would seem that the device needs some sort of grime-encrusted object to clean and three silver coins to get the contraption working. So long as both are present, the Sparklematic 5200 should work...'
WHERE `entry` = 4602;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Sparklematic 5200 comes to life, lurching to and fro. Inside, the helpless grime that has encrusted the object placed within it is being pulverized by the machine''s gnomish cleaning agent.$B$BThe Sparklematic 5200 comes to a halt, heralded by a familiar "ding!" The item receptacle of the machine spirals open, revealing a neatly wrapped box.',
    `RequestItemsText` = 'The Sparklematic 5200 is empty, awaiting a grime-encrusted object to clean and three silver coins to start!'
WHERE `entry` = 4603;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Sparklematic 5200 comes to life, lurching to and fro. Inside, the helpless grime that has encrusted the object placed within it is being pulverized by the machine''s gnomish cleaning agent.$B$BThe Sparklematic 5200 comes to a halt, heralded by a familiar "ding!" The item receptacle of the machine spirals open, revealing a neatly wrapped box.',
    `RequestItemsText` = 'The Sparklematic 5200 is empty, awaiting a grime-encrusted object to clean and three silver coins to start!'
WHERE `entry` = 4604;

UPDATE `quest_template` SET
    `OfferRewardText` = 'As quickly as it started, the Sparklematic 5200 comes to an abrupt halt. A simple "ding" is heard from the machine, and the mouth of the machine spirals upward. Inside the Sparklematic 5200 is a small box wrapped in a little bow. The machine would appear to wrap an object up after eliminating its grime-encrusted status. Even if the machine didn''t work, at least the item is now wrapped in a pretty box.$B$BWell, there is one way to find out if it cleaned the item or not...',
    `RequestItemsText` = ''
WHERE `entry` = 4605;

UPDATE `quest_template` SET
    `OfferRewardText` = 'As quickly as it started, the Sparklematic 5200 comes to an abrupt halt. A simple "ding" is heard from the machine, and the mouth of the machine spirals upward. Inside the Sparklematic 5200 is a small box wrapped in a little bow. The machine would appear to wrap an object up after eliminating its grime-encrusted status. Even if the machine didn''t work, at least the item is now wrapped in a pretty box.$B$BWell, there is one way to find out if it cleaned the item or not...',
    `RequestItemsText` = ''
WHERE `entry` = 4606;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Avast ye... Admiral $N!  Yer a pirate of pirates, lass!$B$BIt warms the cackles of me heart to give ye this hat.  Ye will ne''er find one like it anywheres, and all that gazes upon ye will see that yer an Admiral of the Bloodsail Navy!',
    `RequestItemsText` = 'Yer back already, ya blasted tar! Haves ye done as I''ve ordered? Fail us, and ye will be walkin'' the plank.$B$BArrrrr...'
WHERE `entry` = 4621;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Another one of Kaltunk''s recruits, hm?$B$BA sorry state of affairs we find ourselves in if this is the best the Horde can produce. No matter. By the time we think you''re ready to leave the Valley, you''ll be a proud $C of the Horde.',
    `RequestItemsText` = ''
WHERE `entry` = 4641;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, most excellent, $N. This is most excellent.$B$BSuch a tale. Who would have thought the two would interact with one another in such a way... I will have to spend more time looking at the environmental issues that cause changes in these creatures.$B$BI will continue my research for now. Perhaps we will speak again soon. Until then, I wish you well.',
    `RequestItemsText` = 'How goes the experiment, $N? I will continue to study the samples you''ve recovered for me--I am starting to see why Lady Sylvanas is so interested in these creatures. If they are truly part of the Old Gods, then who knows how it can be used to our benefit.'
WHERE `entry` = 4642;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You pick up the petri dish with the slime sample in it. The only way to discern if the samples is pure enough is to open it and examine the contents yourself. Ideally you''ll find a sample that fits Chemist Fuely''s criteria.',
    `RequestItemsText` = 'You take a sample of slime from Felwood and place some of it into the various tubes and beakers on the table. As things begin to boil and spurt, the slime changes colors. When the process slows down and the liquids calm, you see a small petri dish with your altered Felwood slime samples in it along with some other remnants.'
WHERE `entry` = 4661;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve been a tremendous help here today; we now have a solid chance at unlocking the mystery of why these creatures choose to beach themselves on the coast of Darkshore. The idea that they might be fleeing the area around Teldrassil is disturbing. Should you come across others in your travels, please let me know. Our research here is but in its infancy.$B$BOn behalf of the Temple of the Moon, please accept this as thanks for the effort you have given. Thank you, $N',
    `RequestItemsText` = 'Once you have investigated the creature''s remains in the water to the west of here, I should be able to file a proper report with the Temple of the Moon in Darnassus. Perhaps then we will be closer to discovering the reason why these unfortunate creatures choose to end their lives beached on the coast of Darkshore.'
WHERE `entry` = 4681;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Do not dwell upon her suffering, $N. The beast was corrupt - a product of dark magic. You have done the Alliance a great service and you shall be rewarded.',
    `RequestItemsText` = 'Have you discovered and dealt with the source of the worg menace?'
WHERE `entry` = 4701;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hard work is something I have great respect for, $N. Now we can move forward with our plans for Winterspring.',
    `RequestItemsText` = 'You know your orders, $N.'
WHERE `entry` = 4721;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Another discovery for us to research - well done $N!  These remains will be properly studied once they get to Darnassus.  Please accept this small honorarium in exchange for the remains you have provided for our study.',
    `RequestItemsText` = 'Hello $N - do you have any discoveries of creatures that have washed ashore to report on?'
WHERE `entry` = 4722;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The bones you have are from gentle sea mammals that are known to inhabit the waters surrounding the base of Teldrassil. They had never been known to violently beach themselves like the threshers had been known to. Why would these creatures do this, I wonder? Well, perhaps the study of their remains will bear the fruits of knowledge that we seek.$B$BAgain, thank you for your aid. Please accept this honorarium from the Temple of the Moon.',
    `RequestItemsText` = 'Hello again, $N! Are you here to report on another discovery?'
WHERE `entry` = 4723;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Rabid pups? Gizrul the Slavener? And you live to tell the tale?! Incredible! A tribute well earned!',
    `RequestItemsText` = 'With the pack mistress slain, we can begin to thin out the worg sentries of the Spire and eventually make some headway into the city.'
WHERE `entry` = 4724;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I have heard of the kinds of carriages found on the back of the turtle you found. Those I do believe are naga carriages, used both in battle and in transportation of their supplies on to land. The markings on the box you found are of the naga; this would explain their invasive presence in far-northern Darkshore.$B$BI will send this box to Darnassus along with the rest of your discoveries. This is for you - thank you again for your assistance.',
    `RequestItemsText` = 'It is a pleasure to see you again, $N. We are making great strives in uncovering the mystery of why majestic sea creatures beach themselves on the Darkshore coastline, but with every question answered, two more are raised it seems.$B$BAre you here to offer us more aid in our research?'
WHERE `entry` = 4725;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It worked!  You got the essence!  Well done, $N!  Well done!$B$BThis essence will be invaluable in my research.  I hope to one day learn how to capture living dragons whelps, or perhaps capture their eggs.  If I could find a way to do that, then I would be the envy of dragon scholars around the world!$B$BMy employer would also be happy, and as I said before, he''s someone you want to keep happy...',
    `RequestItemsText` = 'Do you have the broodling essence, $N?  I can''t wait to study it.$B$BAnd besides that... my patron is not the type of person you want to disappoint.'
WHERE `entry` = 4726;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The bones you have are from gentle sea mammals that are known to inhabit the waters surrounding the base of Teldrassil. They had never been known to violently beach themselves like the threshers had been known to. Why would these creatures do this, I wonder? Well, perhaps the study of their remains will bear the fruits of knowledge that we seek.',
    `RequestItemsText` = 'Hello again, $N! Are you here to report on another discovery?'
WHERE `entry` = 4727;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, I believe you discovered one that was originally being examined by the Explorer''s League.  They have a presence here in Darkshore, and they had mentioned that they were studying one of the beached creatures until they were chased out by the murlocs.  You appear to have succeeded where we both have not.  Please - accept this honorarium on behalf of the Temple of the Moon.',
    `RequestItemsText` = 'Greetings once again, $N!  What brings you back to Auberdine?  Are you here to report on another discovery, perhaps?'
WHERE `entry` = 4728;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You got ''em at the perfect time, $N. Any later and they''d be untrainable! Gimmie a minute and I''ll have the little fella ready for you to take home.',
    `RequestItemsText` = '<Kibler is busy arguing with Opus.>'
WHERE `entry` = 4729;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The bones you have are from gentle sea mammals that are known to inhabit the waters surrounding the base of Teldrassil.  They had never been known to violently beach themselves like the threshers had been known to.  Why would these creatures do this, I wonder?  Well, perhaps the study of their remains will bear the fruits of knowledge that we seek.',
    `RequestItemsText` = 'Hello again, $N!  Are you here to report on another discovery?'
WHERE `entry` = 4730;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I have heard of the kinds of carriages found on the back of that turtle.  Those I do believe are naga carriages, used both in battle and in transportation of their supplies on to land.  The markings on the box you found are of the naga; perhaps the creature you discovered was killed as it was heading further south... to Ashenvale maybe?$B$BI will be sure to send this box to Darnassus with the rest of your discoveries.  This is for you - thank you again for your assistance.',
    `RequestItemsText` = 'Hello again, $N.  The work you have done on behalf of the Temple of the Moon has been outstanding.  Are we to be blessed with more of your effort on our behalf?'
WHERE `entry` = 4731;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve found even more beached creatures, $N?  Sea turtles were commonly found frolicking along the base of Nordrassil before it was destroyed.  With the birth of Teldrassil, however, these creatures have been seen in ever decreasing numbers.  Some, as we have discovered, end their lives here for some unknown reason.',
    `RequestItemsText` = 'Greetings once again $N - do you have any more discoveries to report to the Temple of the Moon?'
WHERE `entry` = 4732;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The dimensions of the thresher you mention are mind-boggling.  Even the eldest of the threshers in this region grow to only a fraction of that size.  While some larger ones were known to be close to Teldrassil, their numbers have declined steadily.  I cannot help but wonder if these creatures beaching themselves here are somehow related to this.$B$BWhile we analyze the bones you have brought us, please accept this on behalf of the Temple of the Moon.  Thank you, $N.',
    `RequestItemsText` = 'Thanks be to Elune - I am glad to see you again, dear $N.  The Temple of the Moon''s work on the strange beaching phenomena continues here in Darkshore.  Might you have anything additional to offer us?'
WHERE `entry` = 4733;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It worked? Splendid! I knew it would!$B$BWhile you were gone I was working on a new version of the eggscilloscope. This one has a much longer range.$B$BHere, you can have one in case you go back to Blackrock Spire.',
    `RequestItemsText` = '$N, did you test the eggscilloscope?'
WHERE `entry` = 4734;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wow, you got them! The collectronic module worked! I''m a genius!$B$BThank you, $N. My patron will be very pleased to get these eggs...',
    `RequestItemsText` = 'Do you have the eggs, $N?  My patron heard you were collecting them for me, and is very eager to get his hands on them!'
WHERE `entry` = 4735;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, Briarthorn sent you. Good. Then word does reach far enough to find future students. This pleases me.$B$BIt is typical of our kind, $N, to band together, regardless of race. It is especially important since those we deal with most do not discriminate in their malice if we fail to appease them or control them properly.$B$BI feel you''ve learned a great many things, and if you are willing, I would help you create tools to compliment your skills.',
    `RequestItemsText` = ''
WHERE `entry` = 4736;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, Zevrost sent you. Good. Then word does reach far enough to find future students. This pleases me.$B$BIt is typical of our kind, $N, to band together, regardless of race. It is especially important since those we deal with most do not discriminate in their malice if we fail to appease them or control them properly.$B$BI feel you''ve learned a great many things, and if you are willing, I would help you create tools to compliment your skills.',
    `RequestItemsText` = ''
WHERE `entry` = 4737;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, Demisette sent you. Good. Then word does reach far enough to find future students. This pleases me.$B$BIt is typical of our kind, $N, to band together, regardless of race. It is especially important since those we deal with most do not discriminate in their malice if we fail to appease them or control them properly.$B$BI feel you''ve learned a great many things, and if you are willing, I would help you create tools to compliment your skills.',
    `RequestItemsText` = ''
WHERE `entry` = 4738;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, Kaal sent you. Good. Then word does reach far enough to find future students. This pleases me.$B$BIt is typical of our kind, $N, to band together, regardless of race. It is especially important since those we deal with most do not discriminate in their malice if we fail to appease them or control them properly.$B$BI feel you''ve learned a great many things, and if you are willing, I would help you create tools to compliment your skills.',
    `RequestItemsText` = ''
WHERE `entry` = 4739;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, looks like you''re here to more than just inquire! The citizens will be delighted to know that tonight they will sleep a little bit more soundly and safer.$B$BYou''ve acted as the executioner of justice for the people of Auberdine today, $N. For that, I would like to offer you this as a suitable reward... for a true hero of the Auberdine people.',
    `RequestItemsText` = 'Greetings $C - what may the Sentinels assist you with today? Perhaps you are here to inquire about the bounty on Murkdeep?'
WHERE `entry` = 4740;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I sense that you are enjoying your work. And I believe that we are onto something here.',
    `RequestItemsText` = 'Don''t tell me that you''re too scared! Get going!'
WHERE `entry` = 4741;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Vaelan''s image blurs for a moment.>$B$B<The pieces that you had collected have disappeared.>$B$BThe Unforged Seal of Ascension is now ready. It is time for the final step.',
    `RequestItemsText` = 'Courage and patience above all else, $N!'
WHERE `entry` = 4742;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Stand steady while I cast the final invocation of protection.$B$B<Vaelan''s eyes turn to twin orbs of flame.>$B$BThe Seal of Ascension is complete...$B$BKnow this, I have imbued the artifact with some powerful protective wards. In your darkest hour, when all appears to be lost, the might of the red flight will be at your disposal.',
    `RequestItemsText` = 'Waste no time, $N. Nefarian works feverishly to unleash his evil upon our world.'
WHERE `entry` = 4743;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well met, $C.  Your scouting of the furbolg situation comes at a fortuitous time for us in Auberdine.  For some time we have dealt with not only forest dwellers who are now openly hostile to our presence, but also the outright corruption of the forest itself.  Hopefully you might be able to lend Auberdine aid during these troubling times.',
    `RequestItemsText` = ''
WHERE `entry` = 4761;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It''s no surprise how tainted this water is, but just look at how putrid it is becoming! It would seem that action is needed sooner than later, eh $N?$B$BTo our east is Felwood; it is the real source of this corruption, one that I have seen in times past. I predict this sample will confirm this. We might be able to enact a cure for it here, but in order to even try we will need assistance. When that time comes $N, I hope you will be able to give the aid we need.',
    `RequestItemsText` = 'The pollution of the Cliffspring River is but the start of an alarming trend here in Darkshore.  The sample you provide will help us formalize a plan... a plan of attack, I am starting to suspect.'
WHERE `entry` = 4762;

UPDATE `quest_template` SET
    `OfferRewardText` = 'We have just begun this war to reclaim our forest from the forces of corruption, but a battle this day has been won! $N, the people of Auberdine owe you a debt of gratitude that will never be easily repaid. Please accept this along with our thanks. What we have learned here today may one day free our furbolg friends from the shackles of torment permanently.',
    `RequestItemsText` = 'The Talisman of Corruption is a sinister device that only serves to pervert the balance of nature. When you obtain this item from whatever satyr is tormenting the furbolgs and bring it to me for disposal, we will have won a great victory this day!'
WHERE `entry` = 4763;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found it! So the rumors were true!$B$BThank you, $N. My patron, Count Remington Ridgewell, will be quite pleased to see this addition to this collection.',
    `RequestItemsText` = 'Do you have the clasp, $N?  My patron will pay very handsomely for it.'
WHERE `entry` = 4764;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, so you are he! You have my thanks, $N. And... if you didn''t already know... the gratitude of a noble in the house of Ridgewell is nigh worth a king''s ransom.',
    `RequestItemsText` = 'I was told a messenger would come. One with a gift from Blackrock Spire.$B$BAre you he?'
WHERE `entry` = 4765;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You came from Stormwind? Wonderful -- I know of an object of art that Remington would kill to have in his museum, but extracting it won''t be easy.$B$BThat''s where you come in.',
    `RequestItemsText` = ''
WHERE `entry` = 4766;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Perfect! With these eggs I hope to take the next step to become a wind rider. Here is a token of my appreciation; may good hunting always shine upon you, $C.',
    `RequestItemsText` = '$N, have you retrieved the wyvern eggs that I seek? I''m really anxious to start my wind rider training!'
WHERE `entry` = 4767;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent. The formulae etched into this tablet will consume days of research, but I am confident such research will bear sweet fruit.$B$BThank you, $N. You have been invaluable to us.',
    `RequestItemsText` = 'Have you found the Tablet, $N?  I yearn to delve into its secrets.'
WHERE `entry` = 4768;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is true. I believe there is a tablet held within Blackrock Spire, a tablet that contains old alchemical recipes. I am glad you are here, for I need help in retrieving the tablet.$B$BMake yourself comfortable, and I will explain further.',
    `RequestItemsText` = ''
WHERE `entry` = 4769;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What!? If I knew that Pao''ka Swiftmountain was going to snoop around Highperch, I would have chained him to a totem! His father was reluctant allowing him to come with me to Thousand Needles. We came here to study the different creatures that inhabit these beautiful lands.$B$BI appreciate the help you have shown Pao''ka. I hope this covers any misfortunes this deed has cost you.',
    `RequestItemsText` = ''
WHERE `entry` = 4770;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You did it! Vectus is defeated! And Dawn''s Gambit... did it work?$B$BHm... maybe my device wasn''t the success I had hoped, but I''m glad you were able to handle things anyway. Well done, $N!$B$BThe Argent Dawn, and the good people of Azeroth, are in your debt.',
    `RequestItemsText` = 'Remember, $N - we must be tolerant yet rigid in our beliefs!'
WHERE `entry` = 4771;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Perfect, $N. I''m glad you could find a miner to help you out so quickly. Or did you do this work yourself? Either way, you''ve done well. This will be perfect for the thread.$B$BIt will take some time to create the stuff, so you''ll have to come back--I actually send it off to some princess who we have locked in a tower who''s only job is to spin gold thread... no, seriously. I mean it... okay, not really.',
    `RequestItemsText` = 'Gold bars, yes... yes. Bring me one and we''ll see what we can do about spinning some thread for you. Until then, I would suggest you focus your efforts on becoming more powerful. Your toughest trials are still ahead. And trust me... you''ll wish you were more prepared, regardless of how powerful you think you might be.'
WHERE `entry` = 4781;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good, you''ve returned, $N. And where is the thread?$B$BAh, I understand. That is acceptable. The goblin and his brother have not failed us yet--I suppose it is understandable that he did not have it prepared right then. So be it... we have other things we can attend to in the meantime.$B$BAre you prepared for the next step?',
    `RequestItemsText` = ''
WHERE `entry` = 4782;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent, $N. These will do nicely. I will prepare them now while you move on to your last two components. Are you ready?',
    `RequestItemsText` = 'Desolace is not a kind area: naga, giants, satyr, the Burning Legion... all of those and warring centaur clans all make the land dangerous if you''re not careful.$B$BLike I said before, it will not only test your strength and cunning, but also your patience. Be wary in those lands, $N.'
WHERE `entry` = 4783;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent, $N! The components are gathered and we are ready.$B$BI trust you will be pleased.',
    `RequestItemsText` = 'Soon, $N. I promise you. The robe will be more than adequate for your needs and certainly give you an edge over your opponents.'
WHERE `entry` = 4784;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here you go, $N. And please tell Menara we say hello.$B$BWe expect great things of you. Perhaps when the Legion falls to its knees, your name will be spoken aloud and in praise of your power. I can''t wait!',
    `RequestItemsText` = ''
WHERE `entry` = 4785;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is done, $N. Here you are. Wear it with pride.$B$BYou''ve worked hard and I see great things in your future. Remember, to defy the corruption that comes with our path takes great will and fortitude. As long as your will is your own, then you shall have great success.',
    `RequestItemsText` = 'A moment, $N...'
WHERE `entry` = 4786;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, you have the egg! I bow to you, $N. Your strength and bravery will be long remembered.',
    `RequestItemsText` = 'Do you have the ancient egg? I sense great forces stirring, and I fear that time grows short.'
WHERE `entry` = 4787;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Unbelievable!  You found them!  You truly are a hero, $N!$B$BThat''s a good thing, because I''ve been reading the tablets you brought me before, and from what I gathered... we''re going to need a hero to stop what''s coming...',
    `RequestItemsText` = 'Have you been to the spire, $N? Do you have the fifth and sixth tables?'
WHERE `entry` = 4788;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Mau''ari can derive da juju for $N... Use da Cache of Mau''ari to cast dis upon yourself or your allies.',
    `RequestItemsText` = 'In Winterspring, you will fight great cats called frostsabers. These beasts possess incredible speed an'' cunning. If you wish ta gain the speed a'' da frostsaber, bring me da E''ko you find from dem.$B$BRememba, you must have the Cache of Mau''ari in your inventory if you want ta hunt for E''ko.'
WHERE `entry` = 4801;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Mau''ari can derive da juju for $N... Use da Cache of Mau''ari to cast dis upon yourself or your allies.',
    `RequestItemsText` = 'In Winterspring, you will fight misguided creatures known as da Winterfall furbolg. Through the wishes of their leader, dey have gained incredible strength. If you wish ta gain the power a'' da Winterfall, bring me da E''ko you find from dem.$B$BRememba, you must have the Cache of Mau''ari in your inventory if you want ta hunt for E''ko.'
WHERE `entry` = 4802;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Mau''ari can derive da juju for $N... Use da Cache of Mau''ari to cast dis upon yourself or your allies.',
    `RequestItemsText` = 'In Winterspring, you will find large bears wit extremely thick hides. These Shardtooth bears gain much protection from what dey can withstand. If you wish ta gain the resistance against fire, bring me da E''ko you find from da Shardtooth.$B$BRememba, you must have the Cache of Mau''ari in your inventory if you want ta hunt for E''ko.'
WHERE `entry` = 4803;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Mau''ari can derive da juju for $N... Use da Cache of Mau''ari to cast dis upon yourself or your allies.',
    `RequestItemsText` = 'In Winterspring, you will fight great flying creatures called da Chillwind. These beasts possess da power ta wield frost magics. If you wish ta gain resistance ta frost, bring me da E''ko you find from da Chillwind.$B$BRememba, you must have the Cache of Mau''ari in your inventory if you want ta hunt for E''ko.'
WHERE `entry` = 4804;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Mau''ari can derive da juju for $N... Use da Cache of Mau''ari to cast dis upon yourself or your allies.',
    `RequestItemsText` = 'In Winterspring, you will fight great creatures called da ice thistle yeti. These beasts move slowly, but dey are able to evade many blows from da protection their thick fur provides dem. If you wish ta gain da ability to dodge attacks, bring me da E''ko you find from dem.$B$BRememba, you must have the Cache of Mau''ari in your inventory if you want ta hunt for E''ko.'
WHERE `entry` = 4805;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Mau''ari can derive da juju for $N... Use da Cache of Mau''ari to cast dis upon yourself or your allies.',
    `RequestItemsText` = 'In Winterspring, you have fought da large ice giants called frostmaul. Sheer power and force is at their disposal. If you wish ta gain da force of da frostmaul, bring me da E''ko you find from dem.$B$BRememba, you must have the Cache of Mau''ari in your inventory if you want ta hunt for E''ko.'
WHERE `entry` = 4806;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Mau''ari can derive da juju for $N... Use da Cache of Mau''ari to cast dis upon yourself or your allies.',
    `RequestItemsText` = 'In Winterspring, you will fight creatures of might dat seem to possess an innate magic ability. These wildkin can use strong magics. If you wish ta gain an increase in your intellect bring me da E''ko you find from any a'' da owlbeasts you find der.$B$BRememba, you must have the Cache of Mau''ari in your inventory if you want ta hunt for E''ko.'
WHERE `entry` = 4807;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That''s no blanket! But what have we here? I letter from Tinkee? I wonder what she has to say...$B$BAh, she''s studying in the Burning Steppes. That makes sense--that''s a good source for dragonkin. Oh, but look! It says here that she needs some parts for a device she wants to build. I guess that''s where I come in, eh?',
    `RequestItemsText` = 'It''s cold up here!  I hope you brought me a blanket!'
WHERE `entry` = 4808;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These are good specimens. They''re packed with cold! Let me get some gloves on, then pack them along with the other things Tinkee needs...',
    `RequestItemsText` = 'Do you have the chillwind horns, $N?'
WHERE `entry` = 4809;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You brought them! Great! I''ll get to work right away! Thanks a ton, $N!$B$BYou''ve been so helpful to me, I might need you for even more important tasks later...',
    `RequestItemsText` = '$N! Did you talk to Felnok? Did you bring the components I need?'
WHERE `entry` = 4810;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So the crystal exists, $N? Fascinating... anyway, your task has been well executed; good work!$B$BWhat exactly is this crystal? This is but a single question in a sea of questions. Another question that comes to mind is why the moonkin would be drawn to this object? Is the crystal benign in nature, or does it hold a more sinister purpose?$B$BI have many more questions, but we''re going to need to examine that crystal closely to get some answers.',
    `RequestItemsText` = 'What do you have to report on that red crystal? Does it even really exist?'
WHERE `entry` = 4811;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have made it once more to the mysterious crystal. Removing the stopper on the tube of moonwell water, you gingerly pour the contents out over the top of the crystal. As the water cascades down its lattices, you see the opaque surface turn transparent...',
    `RequestItemsText` = 'The crystal looks very alien against the wooded scenery of Darkshore. You think you hear a very slight humming coming from deep within it.'
WHERE `entry` = 4812;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, it would seem that even though we know more about this crystal, more unanswered questions are the result!$B$BI''ll take the information you''ve uncovered to the council here in Auberdine. Perhaps they''ll know a course of action to follow on this crystal. Well, that is if there is one to be taken; for now, the threat remains far enough to our east to be out of harm''s way.$B$BAs for you, please have this. Consider it a reward for a job well done, $N.',
    `RequestItemsText` = ''
WHERE `entry` = 4813;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, finally... the mysterious egg has finally been delivered to me. Now, let me take a closer look at this... What..! What is this..?',
    `RequestItemsText` = 'I must know more about this mysterious egg, who knows what will hatch from it.'
WHERE `entry` = 4821;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Mmmmmmmmm! I love their strawberry ice cream! If there''s one thing Tigule and Foror know to do, it''s make ice cream!$B$BThank you very much $N - this is the best treat ever!',
    `RequestItemsText` = 'I wish they''d make more flavors of ice cream other than strawberry, but I guess I''m lucky that strawberry is my favorite!'
WHERE `entry` = 4822;

UPDATE `quest_template` SET
    `OfferRewardText` = 'For my gratitude, this is for you, $N.',
    `RequestItemsText` = 'Come now $N, I know you haven''t killed your share yet. Hunt them down, and I shall give you a reward for my gratitude.'
WHERE `entry` = 4841;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, the demons there in Darkwhisper Gorge; I believe it is their presence that is affecting the land in this way. I am going to continue observing the hot springs here and see if I learn anything more.$B$BI''d wait until you are a bit stronger if you have plans of heading farther into Darkwhisper Gorge.',
    `RequestItemsText` = 'The water in the springs seems to have some very odd properties... I am still unsure of what it means...'
WHERE `entry` = 4842;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A severely damaged crate stands out among the rest of the destroyed belongings at the camp...',
    `RequestItemsText` = ''
WHERE `entry` = 4861;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What a load! I mean, look at all those eggs! These should bring in a right few gold.$B$BAs promised, here''s your own little critter. Don''t get bitten!',
    `RequestItemsText` = 'Are those spider eggs in your pack or are you just happy to see me?'
WHERE `entry` = 4862;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Approaching the wagon, it doesn''t appear that there is much more here for Jaron. But, looking on the ground, you notice some crates that look undamaged, despite being half-buried in the snow.',
    `RequestItemsText` = ''
WHERE `entry` = 4863;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, I expected to hear as much, lad. I figured that the crazed beasts destroyed all of my belongings...$B$BBut you did find my tools, and most importantly, the amulet! I wonder why the wildkin so fiercely defended this item... In any case, I''ll think twice before heading their way again!',
    `RequestItemsText` = 'Aye... Tell me the news.'
WHERE `entry` = 4864;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Vengeance! So, the legend of Arikara is true. Indeed, this is a problem that must be resolved immediately.',
    `RequestItemsText` = ''
WHERE `entry` = 4865;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is gonna make the best ale yet!$B$BEh, what did you think I was gonna use this for? Poison or something??$B$BCrazy kids...',
    `RequestItemsText` = '<Ragged John pinches you.>'
WHERE `entry` = 4866;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Aha!  I can already feel my powers returning to me.  And my mind is no longer wracked by Urok''s curse.$B$BThank you, $N!  Humility is below me, but I must acknowledge your aid.$B$BAnd I bid you fortune in your journeys through Blackrock Spire.  You are a fool to think you could make your way to the top, but your bravery is without question.',
    `RequestItemsText` = 'Ah!  Do you have my mojo?'
WHERE `entry` = 4867;

UPDATE `quest_template` SET
    `OfferRewardText` = 'They come to kill me?  I will show them how a Tauren fights!',
    `RequestItemsText` = ''
WHERE `entry` = 4881;

UPDATE `quest_template` SET
    `OfferRewardText` = 'An important discovery?',
    `RequestItemsText` = 'Reporting for another assignment?'
WHERE `entry` = 4882;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The energy of this necklace, $N. I believe that it has only one source.$B$B<Nara closes her eyes and is quiet for a moment.>$B$BThe wildkin, now misguided and confused, were once not so. They once had a purpose, and were guided to serve. The night elf goddess Elune created these creatures to guard her most sacred areas.$B$BWhile this fact may seem like it holds little value; I urge you to look deeper.$B$BYou will learn, in time. Thank you for bringing this to me, $N.',
    `RequestItemsText` = 'How may I help you, $N?'
WHERE `entry` = 4883;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Did you meet up with Ranshalla?',
    `RequestItemsText` = ''
WHERE `entry` = 4901;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Do not hesitate; tell me why you have come.$B$BOh, yes? Hmm. Well.$B$BThank you for bringing this straight to me; it is always best to go right to the top... But... Yes. The druids of the Cenarion Circle have known of the Wildkin for some time. That they are pets of Elune, and were chosen to guard the most sacred of places.$B$BSo while this isn''t news, I definitely compliment you on your effort. Here, take this -- it is something that seems suitable for such a deed.',
    `RequestItemsText` = ''
WHERE `entry` = 4902;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Warlord Goretooth''s dull green skin turns a pasty white for a brief moment.>',
    `RequestItemsText` = '<Warlord Goretooth salutes.>'
WHERE `entry` = 4903;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. Deep in my bones I knew that she would find her way back to me. She told me of your bravery and how you helped her escape. These items belonged to her brother. I know she would want you to have them.',
    `RequestItemsText` = 'Thalia Amberhide:'
WHERE `entry` = 4904;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you for all you have done, $N. May Elune protect you and guide you on the path ahead.',
    `RequestItemsText` = 'Please, put and end to the suffering of Felwood''s creatures.'
WHERE `entry` = 4906;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Felnok was right! I do need your help again, and this time... it''s going to be really dangerous.$B$BAre you ready??',
    `RequestItemsText` = ''
WHERE `entry` = 4907;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I understand. Thank you, $C.',
    `RequestItemsText` = 'Have you found any sign of her at all? The pain in my chest tells me that the worst has happened, but I have hope you will find her safe and sound.'
WHERE `entry` = 4921;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Thrall appears dismayed by the news you bring.>',
    `RequestItemsText` = 'Can you not see that I must not be interrupted?'
WHERE `entry` = 4941;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Nicely done, $N!  You gave that demon a lesson he won''t soon forget. You''ve shown great power and skill. Now I suppose it''s time you return to Menara with your cleansed orb so you can put it to good use.$B$BGood luck, $C. Perhaps our paths will cross again.',
    `RequestItemsText` = 'You''ll have to kill that demon to remove its presence permanently from the orb, $N.'
WHERE `entry` = 4961;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, the spirit of a felhound. Well done, $N.$B$BWhen I have both the spirit and the cleansed orb, I will merge the two for you, but not until then.',
    `RequestItemsText` = 'Yes, $N? Have you chosen? Infernal or felhound?$B$BEach choice is personal and should reflect your strengths and weaknesses. It is not unheard of for a $C to enhance themselves further instead of making up in areas they lack. Sometimes overpowering an enemy is just as strong a tactic than becoming a more balanced spell caster.'
WHERE `entry` = 4962;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, the spirit of an infernal. Well done, $N.$B$BWhen I have both the spirit and the cleansed orb, I will merge the two for you, but not until then.',
    `RequestItemsText` = 'Yes, $N? Have you chosen? Infernal or felhound?$B$BEach choice is personal and should reflect your strengths and weaknesses. It is not unheard of for a $C to enhance themselves further instead of making up in areas they lack. Sometimes overpowering an enemy is just as strong a tactic than becoming a more balanced spell caster.'
WHERE `entry` = 4963;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is done, $N. Simply tell me which you''d prefer: a staff that would require you to use both hands, or an orb so you may use a dagger or sword as your weapon.$B$BTackling a felhound was a great feat on your part. I am sure your item will serve you well in the future. Continue to work hard in the arts, $N. I will be awaiting details of your exploits.',
    `RequestItemsText` = ''
WHERE `entry` = 4964;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, you do seek something more... substantial. That I can help you if you truly are prepared.$B$BIt''s a welcome change to see one of our kind seeking more power in forms other than just knowledge.$B$BSo, do you feel you''re ready, $N?',
    `RequestItemsText` = ''
WHERE `entry` = 4965;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you for your help, $N. I couldn''t have held them off without you.',
    `RequestItemsText` = ''
WHERE `entry` = 4966;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, you do seek something more... substantial. That I can help you if you truly are prepared.$B$BIt''s a welcome change to see one of our kind seeking more power in forms other than just knowledge.$B$BSo, do you feel you''re ready, $N?',
    `RequestItemsText` = ''
WHERE `entry` = 4967;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, you do seek something more... substantial. That I can help you if you truly are prepared.$B$BIt''s a welcome change to see one of our kind seeking more power in forms other than just knowledge.$B$BSo, do you feel you''re ready, $N?',
    `RequestItemsText` = ''
WHERE `entry` = 4968;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, you do seek something more... substantial. I can help you if you truly are prepared.$B$BIt''s a welcome change to see one of our kind seeking more power in forms other than just knowledge.$B$BSo, do you feel you''re ready, $N?',
    `RequestItemsText` = ''
WHERE `entry` = 4969;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you for assisting me, $N. My opinion of you grows as time passes.',
    `RequestItemsText` = 'Discipline and determination are your goals. I may ask you to do a simple task many times; you must perform to the best of your ability each time.'
WHERE `entry` = 4970;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Time feels easier to mend now, thank you $N.  While you might not understand fully the consequences of a fractured timeline, I appreciate that you understand the urgency of countering what I suspect more and more to be a Scourge-driven malfeasance.$B$BI see no harm in rewarding you for your assistance, mortal.  Your greatest feats are to come, and the awarding of a bauble will certainly not alter your future destiny.  Your continued aid, however, is something that I and the dragonflight could use...',
    `RequestItemsText` = 'Temporal parasites are a common malady present wherever the flow of time has been tampered with.  I sense that many are present, and this is disturbing.$B$BRooting out whatever ones you can find will help me be able to take a better hold on the deteriorating temporal situation here.  I will be able to sense when this has been achieved.'
WHERE `entry` = 4971;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These are exactly what I need, $N.  Thank you.$B$BAllow me to suitably reward you with this.  You may not understand what you would need with such a device.  You might not even know quite what it really is.  Alas, I cannot tell you when you will find it most useful; just know that at some point in the future, you may find this item to have extreme utility and function when consumed.  Whether or not you choose to hold on to it until then... this, my friend, is up to you.',
    `RequestItemsText` = 'The time trinkets I seek are simple devices.  They are watches mainly, and their hands are trapped forever when the plague first ravaged Andorhal.$B$BTime is never ending, and the watches you bring to me will invariably find themselves counted out back to their homes... that is, so long as the disturbances continue here.'
WHERE `entry` = 4972;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Again, I thank you for your assistance.  Please accept this gift.  While you still may not know when to use such an item, perhaps in the future the path of time will reveal its true intentions to you.  You could say that I''ve seen as such happening to you, $N.',
    `RequestItemsText` = 'The watches of Andorhal, much like the large clock on the ruins of the town hall, all are frozen in time at three o''clock.  This was when the full effects of the plague first spread out over the city, choking the life out of it.$B$BAs much as we all may regret what happened that day, it has shaped the flow of time as you mortals perceive it.  The bronze dragonflight must persevere in protecting the timeline!'
WHERE `entry` = 4973;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have dealt a crippling blow to the forces of Blackrock, $N. With their Warchief slain, the Blackrock legion is once again thrown into the maw of chaos.$B$BIn honor of your heroics, the people of Kalimdor shall be rewarded!',
    `RequestItemsText` = '<Thrall grunts.>'
WHERE `entry` = 4974;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is done, $N. Simply tell me which you''d prefer: a staff that would require you to use both hands, or an orb so you may use a dagger or sword as your weapon.$B$BTackling the infernal was a great feat on your part and this reward will fit you nicely. I wish you further success in the arts, $N.',
    `RequestItemsText` = ''
WHERE `entry` = 4975;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N. This will do nicely.$B$BThe only thing left for you to do is to decide on which demon you want me to imprison within the cleansed orb. Do that, and you will have a magnificent new item to wield.',
    `RequestItemsText` = 'How goes your search for Tabetha and the orb, $N?$B$BTabetha has been more than useful when it comes to matters of the arcane. I''m sure she would have no problem aiding you if you''re able to find her.'
WHERE `entry` = 4976;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I won''t lie to you, $R. I needed the money! Kibler pays very, very well - much better than the K.E.F. ever could.$B$BBut don''t doubt my loyalties! Why do you think I''m down here? To get that crazy goblin some exotic animal eggs or something equally inane? No, only someone truly daft would come to Blackrock Spire to collect pets. Yep, I don''t reckon too many people like that exist in this world.$B$B<Bijou laughs.>$B$BThe last thing we need are those kinds of people breeding.',
    `RequestItemsText` = ''
WHERE `entry` = 4981;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done it! Once Lexlort has these plans, he''ll forget all about the nasty things he wanted to do to me.$B$B$N, you''re my hero!',
    `RequestItemsText` = 'Any luck?'
WHERE `entry` = 4982;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I''ve got to hand it to her; she''s managed to weasel her way out of another sticky situation! These reports will prove to be invaluable in our dealings with the Blackrock orcs.$B$BOf course, you will be rewarded for your hard work.',
    `RequestItemsText` = 'Where''s the goblin???'
WHERE `entry` = 4983;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I... I sense that the souls of those wolves you have put down now have rest.  They - and I - thank you for a merciful release.$B$BThe wolves are not alone in their suffering within this damnable place, $N.  Please, I have need of you once more.',
    `RequestItemsText` = 'The wolves that are infected with the plague must be put down, $N.  The disease they carry cannot be cured.  I tried... I tried until I succumbed to the plague myself.'
WHERE `entry` = 4984;

UPDATE `quest_template` SET
    `OfferRewardText` = '"I know that the grizzles have been put down, their torment at an end.  I... I have one more thing for you.  I wrote it down on... on this branch, sensing that my time in this realm had come to an end.$B$BIndeed... I am at that end.  Thank you again friend... the creatures of this accursed land may rest... and now shall I."$B$BWith that, a heavy sigh is uttered by the druid, followed by what sounds like a death rattle.  His body lies motionless on the cottage floor.',
    `RequestItemsText` = 'I hear your footsteps, $N.  My vision has faded from me, but I still am able to sense things around me.  Have you ended the misery of the disease-ridden grizzlies?'
WHERE `entry` = 4985;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This... this is quite strange.  This druid - this tauren druid no less - entrusted you with a great deal of valuable information on the extent of the Scourge''s plague.  I am surprised a tauren would give a $R such information, and freely at that if what you say is true.  We will make good use of this, I promise you.  Perhaps the tauren have not fallen as far from Cenarius as Fandral would believe...$B$BErm, anyway, please - accept this as a token of thanks from the Cenarion Circle.',
    `RequestItemsText` = 'On behalf of the Cenarion Circle, I bid you welcome to this enclave, $C.  What business do you have with us?'
WHERE `entry` = 4986;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is from Mulgris, you say? We had heard he sought to minister to the creatures suffering in the Plaguelands, but this is most unexpected... and most saddening. Mulgris is... was a good friend. I will mourn his passing deeply.$B$BHis efforts have not gone in vain, thanks to your diligence. In this branch, much lore is stored about the plague the Scourge propagates upon the land. We will study it diligently. As for you, please accept this. It is the least we can do for your noble efforts.',
    `RequestItemsText` = 'On behalf of the Cenarion Circle, I bid you welcome to this enclave, $C. What business do you have with us?'
WHERE `entry` = 4987;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well I''ll be! Where were they??',
    `RequestItemsText` = 'Any luck?'
WHERE `entry` = 5001;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This coincides with much of what we already knew. Regardless, it is interesting and rather unfortunate information.$B$BThe markings on this map will prove valuable in thinning the Blackrock menace.',
    `RequestItemsText` = 'Ah, $N. It has been a long time.'
WHERE `entry` = 5002;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A package in the barn that you might have otherwise overlooked now stands out amongst the decay and ruin.  Perhaps this is the one that the ghost of Janice Felstone was clamoring about...',
    `RequestItemsText` = ''
WHERE `entry` = 5021;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A package for an Emma Felstone, you say?  Last known address was Stormwind, four years ago?  Well let me see here...$B$BAccording to what we know, there was an Emma Felstone in the city about four years ago.  Well, I should say possibly - this census I refer to is from five years ago, and I don''t have a report of her vacating the city.  This doesn''t mean that she is still here though.$B$BWait a second... this package couldn''t be for Ol'' Emma, could it?',
    `RequestItemsText` = 'Welcome to the office of the Stormwind census.  If you are in need of information on our populace, then I can assist you.'
WHERE `entry` = 5022;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A package for a Jeremiah Felstone, with his last known address as Lordaeron... I should be able to assist you.$B$BJeremiah Felstone was in the city before the plague. Well, I should say the former Jeremiah Felstone - some of the Forsaken have changed their last names to rid themselves of their former countenance. This case is no exception; the former Jeremiah Felstone is now known as Jeremiah Payson.$B$BWait a minute... isn''t he the cockroach vendor?',
    `RequestItemsText` = 'Are you here to seek the assistance of the Undercity census, or just to ask me if someone you knew is dead? I get asked that a lot.'
WHERE `entry` = 5023;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Haha! Thank you, $N! This will help us greatly. You''re a boon to the Crossroads and to the Horde. If there is anything I can do for you, please, let me know.',
    `RequestItemsText` = 'How goes your search for the supplies, $N? I trust the quilboar fall under your strength easily.'
WHERE `entry` = 5041;

UPDATE `quest_template` SET
    `OfferRewardText` = 'If only Mangletooth were free to see you decimate those who betrayed him! <snort>$B$BI thank you for destroying more of the Bristleback by gathering these shards. Please, continue to do so, and I will continue to aid you. <snort>',
    `RequestItemsText` = 'I will need 4 blood shards if you wish Agamaggan''s strength, $R.$B$BYour foes will cower before your strength were you to be given this blessing. <snort>$B$BThe Razormane''s greatest warriors are infused with such power!'
WHERE `entry` = 5042;

UPDATE `quest_template` SET
    `OfferRewardText` = 'May your aim be unerring, and the mark of your weapon be true, $R.$B$BAgamaggan''s spirit is with you. Return <snort> to me if you wish. Mangletooth will bless you again if the great boar god deems me worthy. <snort>',
    `RequestItemsText` = 'My tribes greatest scouts are said to be unrivaled in their accuracy, and no rogue <snort> could measure up to their quickness in battle.$B$BBring me 4 blood shards and I will make you even more agile than any quilboar born.'
WHERE `entry` = 5043;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your enemies should fear you even more, $R. <snort>$B$BTell Mangletooth tales of your cunning in battle when next we meet--be it in this life, or the next. <snort>',
    `RequestItemsText` = 'The shaman and geomancers of the quilboar tribes <snort> call upon the strength of Agamaggan to help them in battle and in their rituals, $R.$B$BIf you too wish the added power of Agamaggan''s blessing with your spells, then bring me 4 blood shards and Mangletooth will aid you. <snort>'
WHERE `entry` = 5044;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Our greatest warriors, and our greatest <snort> shamans would envy your will, $R.$B$BDefeat more of the Bristlebacks knowing that they cannot stop you! <snort>',
    `RequestItemsText` = 'Warriors of all types <snort> have need of a strong spirit. It drives you to greater feats when all hope has been lost. This is not unknown to the <snort> Razormane. We are a spiritual tribe--we are more proud of our connection to Agamaggan than our prowess <snort> in battle.$B$BBring me 4 blood shards and I will bless your spirit for battle. <snort>'
WHERE `entry` = 5045;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Go to war, $R.',
    `RequestItemsText` = 'All those who <snort> enter battle have need of protection. Their bones must be strong. Their skin tough. <snort> My tribe knows this as well, and to add to the natural protection our quills and hide give us, <snort> we often call upon Agamaggan to protect us from harm before we go to war.$B$BBring me 4 blood shards <snort> and I will grant you the same protection.'
WHERE `entry` = 5046;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Alive? Suit worked? And what do we have here?',
    `RequestItemsText` = 'Yea?'
WHERE `entry` = 5047;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My name is indeed Emma Felstone - you''re the first person in years to call me that.  Who... who are you?$B$BYou say you knew... my sister?!  Is she still alive?  Who am I kidding, of course she isn''t.  When the plague broke out in Lordaeron, I had come to expect the worst.  So many of my family died... or worse.  Here I am now, crazy Ol'' Emma, all alone.  What are you, a grave-robber or something?  Looking for your next target?$B$BWhat... you have a package for me from my sister?',
    `RequestItemsText` = 'I would tell you to get off my lawn, but as you can see I don''t have one.'
WHERE `entry` = 5048;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I haven''t used that name in years... but yes, at one point in my life - before this glorious unlife - that was my last name.$B$BYou claim to have known my sister... or rather, have recently spoken to my sister.$B$BWho''s been dead.$B$BFor four years.$B$BYou know, if my bones weren''t already brittle enough, I''d be tempted to break my foot off on your posterior. You''re quite the vulture, aren''t you?$B$BWhat... you have a package for me from my sister?',
    `RequestItemsText` = 'Every time someone steps on a cockroach, I cry. Please don''t make me cry.'
WHERE `entry` = 5049;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You give the half-charm back to the apparition.  She looks at it, then at you expectantly.$B$B"Honey, where did you put your half of the charm?  We can''t be together unless we have both halves.  Honey... can you see me?"',
    `RequestItemsText` = 'John, sweetheart... is that you?  I''m so cold all the sudden...'
WHERE `entry` = 5050;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You hand the reassembled good luck charm to Janice Felstone''s ghost.  As soon as she grasps it, you observe an almost immediate change in her.  Her ethereal form shimmers, and she looks upon you with clear yet sad eyes.$B$B"You''ve freed me... I no longer will need this charm.  Please, take it and perhaps it will give you the solace it has given me."',
    `RequestItemsText` = 'John, don''t let the ghouls get you... don''t let the ghouls get me... nasty ghouls... our charm will keep us safe.'
WHERE `entry` = 5051;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, you do understand. <snort> My words were not lost on your ears, $R. Mangletooth may be caged, but no cage can stop Agamaggan''s power! <snort>$B$BThe touch of the shard, the feel of it... it has been a long time, $R.$B$BDo you know what it is like? To have your power severed from you?$B$BBut, that is a tale for another time. I promised you information. I promised you Agamaggan''s power. My people turned their backs on Mangletooth. Now, I lose you upon them. <snort>',
    `RequestItemsText` = 'Our tribes flock to the thorny areas throughout the Barrens <snort> because they are holy places, but none as holy as Razorfen. Agamaggan''s body makes up the entirety of the Razorfen, <snort> but the Downs are especially protected because the entrance is made from his great maw! <snort> It will swallow whole those not loyal to him, and spit out their bodies after he''s chewed them up! <snort>$B$BAgamaggan has left his body behind to protect us, and he gives of his spirit so we may protect him. <snort>'
WHERE `entry` = 5052;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This was no easy task, yet you have excelled. But do not be too quick to think you have impressed me, $N.',
    `RequestItemsText` = 'Go now, $C. Seek out Ursius.'
WHERE `entry` = 5054;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes. You have returned. I believe now that you are a true $C by nature. You have faced the most ferocious of creatures and have returned, surpassing my expectations.$B$BYou are now ready for my final request.',
    `RequestItemsText` = 'Brumeran calls out to you, $N.'
WHERE `entry` = 5055;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have proven both your strength and your determination. Many more challenges await you, but I have already shown you as much as I am able.$B$BGood luck, $N.',
    `RequestItemsText` = 'Shy-Rotam is bold and unforgiving; she will defend her kind with fervent enthusiasm.'
WHERE `entry` = 5056;

UPDATE `quest_template` SET
    `OfferRewardText` = 'We learn from our life experiences, $N. I am sure that you have only become stronger and wiser as a result of yours. You have grown much since we first spoke.$B$BTake this in remembrance of the difficult tasks you have accomplished as a $R $C, and know that you will always have my respect and admiration.',
    `RequestItemsText` = ''
WHERE `entry` = 5057;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A diary with yellowing pages lies open to the last entry:$B$B"I don''t know what''s going to happen now that Harold''s turned.  It took everything out of me to drag him into the only place I could find that''d lock him up tight and hold him.  I hid the key on me, and I pray it works...$B$BI hope I can get out of here, but I need money to do that.  Our stuff''s all in the cabinet I think... and now that I think about it, doesn''t Harold keep the key on him?$B$BI''ll rest on it, I''m dead tired now."',
    `RequestItemsText` = ''
WHERE `entry` = 5058;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Using the key found on the skeleton of the former Mrs. Dalson, you unlock the door to the outhouse.  A bloodthirsty ghoul leaps from the outhouse, having been trapped inside for who knows how long.$B$BIt is clear by the bloodcurdling scream of the ghoul at your presence that the former Farmer Dalson is now beyond saving.',
    `RequestItemsText` = 'The door to the outhouse has begun to splinter at the edges of the frame as though it has been repeatedly and incessantly tried to be forced open.  It is currently locked up tight from the outside of the outhouse.$B$BAs you rattle the door, you hear a guttural moaning come from inside!  Whatever is inside there, it certainly does not sound friendly.'
WHERE `entry` = 5059;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The key taken from Farmer Dalson''s ghoulish remains fits the lock perfectly.  The doors of the cabinet swing open, revealing several items that remain intact and appear quite valuable.',
    `RequestItemsText` = 'An extremely sturdy cabinet stands before you, securely fastened shut by a built-in lock.  The front of the cabinet is deeply scratched and marked.  This could be surmised as being from numerous and violent failed attempts to reveal whatever secrets the cabinet currently obfuscates from view.$B$BIf you are going to open this cabinet, you will need to find the key.'
WHERE `entry` = 5060;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very impressive, $N. You are ready to learn your aquatic form, and it is my pleasure to teach it to you.$B$BAlso, in recognition of your achievement during the two trials, I give you this item. I hope you''ll find it to be a welcome addition to your gear as a protector of nature and a keeper of the balance.',
    `RequestItemsText` = 'Your return to Darnassus is not without heralding, though I will need proof of your lessons learned in Moonglade before I will teach you your aquatic form.$B$BDo you have the Pendant of the Sea Lion?'
WHERE `entry` = 5061;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good, you have gathered the essential amount of Incendia agave. This rare herb found only in Thousand Needles will help light the dormant sacred fire of life.$B$B<Magatha begins to enchant the Incendia agave.>',
    `RequestItemsText` = 'So, Motega Firemain sends word of Arikara...well now that is grave news.$B$B<Magatha looks around.>$B$BArikara is a deadly creature born only to seek vengeance against those who have committed heinous acts.$B$B<Magatha smiles.>'
WHERE `entry` = 5062;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Astounding! It must have taken weeks to gather those components... and how did you find a pristine hide?!?$B$BEnjoy the cap, $N!',
    `RequestItemsText` = 'Unless you''ve got everything I need, you''re wasting my time.'
WHERE `entry` = 5063;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great Spirit Totem! This is dire news indeed. I must begin to plan for whatever may come.$B$B$N, as promised, here is your reward for your brave service.',
    `RequestItemsText` = 'Have you discovered what the Grimtotem are up to?'
WHERE `entry` = 5064;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found them!  Great!$B$BThank you, $N.  I will pour over these texts and decipher their meaning.$B$BYou, however, have another task...',
    `RequestItemsText` = 'Do you have the tablets?  I fear their texts will reveal a great threat to our world.'
WHERE `entry` = 5065;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Welcome to the Plaguelands, hero. This is one of most dangerous frontiers in Azeroth, especially with the looming threat of the Scourge to our north and northeast. I am glad to hear that the clarion call of duty and service to the greater good did not fall on deaf ears with you!$B$BIf you are ready to get your hands dirty, then there is plenty for willing and able heroes to do here on the edge of the Plaguelands.',
    `RequestItemsText` = ''
WHERE `entry` = 5066;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Few more improbable tasks I have seen completed by mortals. Bask in the glory of my handiwork! Reap its rewards!',
    `RequestItemsText` = 'Unless you''ve got everything I need, you''re wasting my time.'
WHERE `entry` = 5067;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I thought I would be dead and buried before I ever saw this day.$B$BAn accomplishment of this magnitude can only be overshadowed by the reward.',
    `RequestItemsText` = 'Unless you''ve got everything I need, you''re wasting my time.'
WHERE `entry` = 5068;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent work, $N. At the very least, you have bought us more time - precious, precious time.',
    `RequestItemsText` = 'Status?'
WHERE `entry` = 5081;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thanks so much, $N! Now I can get back to work here.$B$BDid you find anything of interest at the Winterfall camp?',
    `RequestItemsText` = 'I appreciate your help!'
WHERE `entry` = 5082;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You got this from the Winterfall?',
    `RequestItemsText` = 'What is that you have found?'
WHERE `entry` = 5083;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Inside the cauldron bubbles a rotting, repulsive-smelling substance...',
    `RequestItemsText` = ''
WHERE `entry` = 5084;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You are very resourceful, $N. Do you think that the Winterfall furbolgs have been to the Deadwood camp?',
    `RequestItemsText` = 'I hope you found something, $N. The Winterfall are becoming increasingly aggressive!'
WHERE `entry` = 5085;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I have to compare this to the substance you found in the cauldron, and then I''m sure we''ll know more.',
    `RequestItemsText` = 'I think we are beginning to uncover what is happening here, $N.'
WHERE `entry` = 5086;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Donova examines the contents of the crate.>$B$BI wonder if consuming this substance makes the furbolg more aggressive. They do seem much larger...',
    `RequestItemsText` = 'We''ll see what happens when the Winterfall don''t get their firewater!'
WHERE `entry` = 5087;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This does not make sense. Why would Arikara be after Cairne Bloodhoof? Magatha could not be wrong, she is our most powerful shaman.$B$B<Motega shakes his head.>$B$BRegardless, your great deed to the Horde shall not go unnoticed - please, choose one of these as a reward for your aid.',
    `RequestItemsText` = 'Have you slain the vicious serpent Arikara, $N?'
WHERE `entry` = 5088;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The plot thickens...',
    `RequestItemsText` = 'What have you got there, $N?'
WHERE `entry` = 5089;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Welcome to the Plaguelands, hero. This is one of most dangerous frontiers in Azeroth, especially with the looming threat of the Scourge to our north and northeast. I am glad to hear that the clarion call of duty and service to the greater good did not fall on deaf ears with you!$B$BIf you are ready to get your hands dirty, then there is plenty for willing and able heroes to do here on the edge of the Plaguelands.',
    `RequestItemsText` = ''
WHERE `entry` = 5090;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Welcome to the Plaguelands, hero.  This is one of the most dangerous frontiers in Azeroth, especially with the looming threat of the Scourge to our north and northeast.  I am glad to hear that the clarion call of duty and service to the greater good did not fall on deaf ears with you!$B$BIf you are ready to get your hands dirty, then there is plenty for willing and able heroes to do here on the edge of the Plaguelands.',
    `RequestItemsText` = ''
WHERE `entry` = 5091;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Mission accomplished, $N!  Well played, well played.$B$BAllow me to reward your work thus far with some coin from the Stormwind coffers.  I''d recommend spending it on materiel that will aid you in your next mission... one that will take you into the ruins of Andorhal itself.$B$BBe ready!  Be vigilant!',
    `RequestItemsText` = 'I want you to prepare for the worst, $N - dig deep.  The task in front of us will not be easy.  As we rally our forces here to eventually strike out against the Scourge, you will be part of our advance effort that takes the fight to them!  Your assigned mission in Sorrow Hill will begin our path to victory!'
WHERE `entry` = 5092;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Welcome to the Plaguelands, hero.  This is one of the most dangerous frontiers in Azeroth, with the looming threat of the Scourge to our east, and then even further still eastward from there.  I am glad to hear that the call of duty and service to the Horde did not fall on deaf ears with you!$B$BIf you are ready to get your hands dirty, then there is plenty for willing and able heroes to do here on the edge of the Plaguelands.',
    `RequestItemsText` = ''
WHERE `entry` = 5093;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Welcome to the Plaguelands, hero. This is one of most dangerous frontiers in Azeroth, with the looming threat of the Scourge to our east, and then even further still eastward from there. I am glad to hear that the call of duty and service to the Horde did not fall on deaf ears with you!$B$BIf you are ready to get your hands dirty, then there is plenty for willing and able heroes to do here on the edge of the Plaguelands.',
    `RequestItemsText` = ''
WHERE `entry` = 5094;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Welcome to the Plaguelands, hero. This is one of the most dangerous frontiers in Azeroth, with the looming threat of the Scourge to our east, and then even further still eastward from there. I am glad to hear that the call of duty and service to the Horde did not fall on deaf ears with you!$B$BIf you are ready to get your hands dirty, then there is plenty for willing and able heroes to do here on the edge of the Plaguelands.',
    `RequestItemsText` = ''
WHERE `entry` = 5095;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Finely executed, $N. Your attack on the Scarlet Crusade will buy us time. I have sent one of my best scouts out to watch over the camp and make sure that the Crusade forces that come to reinforce the position will take the bait.$B$BWith the pressure on us lessened, we should now finally be able to risk a mission into Andorhal itself, and an important one at that. I''d very much like it if you''d perform this one as well, based on your success to date.',
    `RequestItemsText` = ''
WHERE `entry` = 5096;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My priests are reporting that our beacon trackers are picking up extremely strong signals on all four towers!  Dare I say it, but I believe you''ve executed another mission with complete and total success!  Well played once again, $N!$B$BWith the towers marked, our preparations for the attack are now in place.  The time has come to take the fight to the Scourge!',
    `RequestItemsText` = 'Once the towers are marked, they''ll become top priority targets for our attack on Andorhal.  I suspect that once we neutralize the towers, the main threat of Andorhal will emerge.  From that point on, we''ll have a straight-up fight for control of the city!$B$BYou''re back to report success, yes?  Don''t forget the beacon torch as well; we must maintain control of our materiel.'
WHERE `entry` = 5097;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My warlocks are reporting that our beacon trackers are picking up extremely strong signals on all four towers!  You''ve executed my orders with the skill and precision of a seasoned veteran.  Your service to the Horde is duly noted once more, $N!$B$BWith the towers marked, our preparations for the attack are now in place.  The time has come to take the fight to the Scourge!',
    `RequestItemsText` = 'Once the towers are marked, they''ll become top priority targets for our attack on Andorhal. I suspect that once we neutralize the towers, the main threat of Andorhal will emerge. From that point on, we''ll have a straight-up fight for control of the city!$B$BYou''re back to report success, yes? Don''t forget the beacon torch as well; we must maintain control of our materiel.'
WHERE `entry` = 5098;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Surely, we will strike against their dragon lords next. Well done, brave soldier of the Alliance! Well done, indeed.',
    `RequestItemsText` = 'Is it done?'
WHERE `entry` = 5102;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What the...',
    `RequestItemsText` = ''
WHERE `entry` = 5103;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you so much, $N. I hope to get back to my studies without worry that I will be ambushed. Please accept this as a reward.',
    `RequestItemsText` = 'Maybe you will find out more in Winterfall Village, $N.'
WHERE `entry` = 5121;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You retrieved the medallion! Now I will be able to leave the chapel and perform my duty.$B$BThat duty is to kill the beast who helped corrupt me and so many of my brothers and sisters, Baron Rivendare!',
    `RequestItemsText` = 'The power of this chapel gives me the strength to resist the corruption in my heart.  If I leave it, I will become a death knight.   But there is a medallion, the medallion of faith, that will give me the strength I need to leave.$B$BPlease, $N, retrieve the medallion.  It is guarded by Malor the Zealous, a crazed member of the Scarlet Brotherhood who resides deep in the Scarlet Bastion in western Stratholme.'
WHERE `entry` = 5122;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I wonder what all of this means... I can''t make anything out...',
    `RequestItemsText` = 'Now, what''s this, $N?'
WHERE `entry` = 5123;

UPDATE `quest_template` SET
    `OfferRewardText` = 'As promised, $N, here''s your recipe! I''m also going to throw in a little something extra for all of your hard work and dedication. What am I going to do with these anyway???',
    `RequestItemsText` = 'Time is money, $N and I don''t have much of either.'
WHERE `entry` = 5124;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N, I am dying... but my soul is saved.  For that, I owe you more than words can say.  Please, take this... and fight on, brave $C!',
    `RequestItemsText` = ''
WHERE `entry` = 5125;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Lorax laughs.>',
    `RequestItemsText` = '...'
WHERE `entry` = 5126;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Our pact you did not break. The soul I did take. The reward I shall make.',
    `RequestItemsText` = 'Tempt not...'
WHERE `entry` = 5127;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, if you let me examine this for a while, I might be able to translate it for you.$B$B<Kelek flips through the pages.>$B$BWhen I am able to look over this fully, I will send word to you.$B$BThank you for sharing this with me, $N. Very little is known about the Winterfall furbolg.',
    `RequestItemsText` = 'The Emerald Circle is friendly to all, $R. What can I do for you?'
WHERE `entry` = 5128;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I''ll hand it to you - it takes a strong will to make a permanent decision like you''ve just done. I assure you, dragonscale leatherworking will prove to be a profitable and rewarding path for you to follow.$B$BTo train in the art for the future, simply speak to me and I will make available any knowledge that you have yet to commit as yours.',
    `RequestItemsText` = 'If you''re ready to commit to a permanent decision by becoming a dragonscale leatherworker, then I''m ready to take you on as a student. Just bring to me the things I asked for, and we''ll begin your education.'
WHERE `entry` = 5141;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hello.  I''m Pamela, what''s your name?',
    `RequestItemsText` = ''
WHERE `entry` = 5142;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve given your finest offerings, and nature will soon permit you to bend her to your will. Once I have finished my tutelage, your work will be a force of nature unto itself.$B$BTo train in the art for the future, simply speak to me and I will make available any knowledge that you have yet to commit as yours.',
    `RequestItemsText` = 'Nature is a force that must be appeased before you hope to learn how to bend its will into your leather garments. Bring me your offering to this force, and I will make sure you are heard.'
WHERE `entry` = 5143;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve cast your lot, and the elements accept you. Once I have finished my tutelage, you shall command the will to craft the finest of leather garbs.$B$BTo train in the art for the future, simply speak to me and I will make available any knowledge that you have yet to commit as yours.',
    `RequestItemsText` = 'Making this kind of leather-based armor requires patience and dedication. Once you have cast your lot with the elements, there is no turning your back on them. Bring me proof of your worthiness, and we''ll get started.'
WHERE `entry` = 5144;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I''ll hand it to you - it takes a strong will to make a permanent decision like you''ve just done. I assure you, dragonscale leatherworking will prove to be a profitable and rewarding path for you to follow.$B$BTo train in the art for the future, simply speak to me and I will make available any knowledge that you have yet to commit as yours.',
    `RequestItemsText` = 'If you''re ready to commit to a permanent decision by becoming a dragonscale leatherworker, then I''m ready to take you on as a student. Just bring to me the things I asked for, and we''ll begin your education.'
WHERE `entry` = 5145;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve cast your lot, and the elements accept you. Once I have finished my tutelage, you shall command the will to craft the finest of leather garbs.$B$BTo train in the art for the future, simply speak to me and I will make available any knowledge that you have yet to commit as yours.',
    `RequestItemsText` = 'Making this kind of leather-based armor requires patience and dedication. Once you have cast your lot with the elements, there is no turning your back on them. Bring me proof of your worthiness, and we''ll get started.'
WHERE `entry` = 5146;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hah! Well, this is excellent news! I was starting to think that he would never be brought to justice!$B$BHere you are, $N... and thanks. News of Arnak''s foul deeds boiled my blood!',
    `RequestItemsText` = 'Have you any news of that murderous Arnak Grimtotem?'
WHERE `entry` = 5147;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve given your finest offerings, and nature will soon permit you to bend her to your will. Once I have finished my tutelage, your work will be a force of nature unto itself.$B$BTo train in the art for the future, simply speak to me and I will make available any knowledge that you have yet to commit as yours.',
    `RequestItemsText` = 'Nature is a force that must be appeased before you hope to learn how to bend its will into your leather garments. Bring me your offering to this force, and I will make sure you are heard.'
WHERE `entry` = 5148;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found it!  You found my doll!  Oh, thank you!',
    `RequestItemsText` = 'Did you find my doll?'
WHERE `entry` = 5149;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Placing the sprouts in front of her, Dadanga seems pleased.$B$BShe nudges a small brown-wrapped package towards you, in exchange for the treat!',
    `RequestItemsText` = 'Dadanga looks up at you as you approach her. She seems to be hoping for something...$B$BShe''s probably hungry!$B$BThere''s got to be something growing in the crater that would be just the perfect snack for a large herbivore. Dadanga''s a big girl; whatever you bring her, there would need to be a lot of it!'
WHERE `entry` = 5150;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My hypercapacitor! This will keep me busy for a while until I can figure out what it does...',
    `RequestItemsText` = 'Do you have my hypercapacitor?'
WHERE `entry` = 5151;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You saw Pamela?  How is she?  Is she alive??  Oh, no!  Poor Pamela!  She was so young, and such a happy child...$B$BShe doesn''t know what happened to her father, does she?  My brother, Joseph?$B$BNo... she couldn''t understand what happened to Joseph.  And even if she could, I don''t have the heart to tell her...',
    `RequestItemsText` = ''
WHERE `entry` = 5152;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What is this?  A wedding ring?  Let me see...$B$BAh!  This ring was once on the hand of a great man, but there is much tragedy in that man''s past.$B$BAre you here to help him?  It''s far too late for him now... but perhaps we can help him in the past!',
    `RequestItemsText` = 'There is something timely about your visit.  You''re not from the future, are you?'
WHERE `entry` = 5153;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, you found it!$B$BDid you read it?  Is Joseph Redpath mentioned?  If he is, then perhaps we can save him!$B$BAh.  The Annals of Darrowshire tell a very unsettling tale.  It says that during the battle, Joseph Redpath was corrupted and joined the ranks of the Scourge!  He then betrayed the defenders of Darrowshire.$B$BThat is an ill fate.  If we can, we should try to change that fate, don''t you think?',
    `RequestItemsText` = 'Did you find the book, $N?'
WHERE `entry` = 5154;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good, $N! With their numbers weakening, we can further press them.$B$BHow was your first taste of their power? Were they as strong as you thought they would be? Stronger? Or perhaps they were no challenge for you at all. Wouldn''t that be something?$B$BWe can discuss the details of your exploits later. There are other things we must focus on now.',
    `RequestItemsText` = 'How goes your fight, $N? I know the shedding of blood as proof of honor can be disgusting to some, but you must understand that it serves two goals: you make my task easier by hurting their numbers, and we gain a respect for each other that will only make us stronger in times to come.$B$BI hope you understand.'
WHERE `entry` = 5155;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good that you''re alive, $N. Bad that the water still exists. I was hoping to find at least one pure source of water here in Felwood. It looks like my search has failed. The process of healing the land could have been made much easier with its existence.$B$BI will have to concern myself with saving what forest creatures I can while destroying those that have become so corrupt that they endanger themselves as much as travelers through this once-mighty forest.',
    `RequestItemsText` = 'I hope your search goes well, $N. I haven''t started heading that far north, but I will admit, the thought of crossing the path of an infernal at any point scares me just a little. The creatures are brainless, but still quite intimidating.'
WHERE `entry` = 5156;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This will do nicely, $N.$B$BNow all we have to do besides apply the waters to the braziers is to have it purified. That should not be difficult--it should only require a little travel.$B$BHopefully we can do this quickly.',
    `RequestItemsText` = 'Once we have the waters from the Moon Well, we will purify it and use it to extinguish the braziers of protection within Shadow Hold. That should allow me ample time to see into the chambers even deeper and discern who actually leads this... cult.$B$BI pray the Earthmother is with us.'
WHERE `entry` = 5157;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, you need the water from this Moon Well cleansed. Stopping this force of malice in Felwood seems noble enough, but it is not for me to decide if the water will be purified. I will ask the spirits of water--it will be up to them to decide if the cause is just.$B$BGive me a moment and I will tell them of your plea. I hope they are as sympathetic as I am to your cause.',
    `RequestItemsText` = 'I sense you are not just a simple traveler looking for the path to Ratchet. Come, sit and rest at our camp. Speak to me when you''re ready.'
WHERE `entry` = 5158;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This should be more than enough water for our purposes.$B$BI''m glad to hear that Islen was able to help us. Her strength with the water spirits has always been a strong one. She is also wise, and rare is it that the spirits do not agree with her purpose. The fact that both of them have blessed our task gives me hope that we are on the right path.',
    `RequestItemsText` = 'Ah, I see you''ve returned, $N. Good. Did you find Islen in the Barrens? Or do we have to find another way to accomplish our goals?'
WHERE `entry` = 5159;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Aspects insist that we stay out of the affairs of mortals. In this world, however, such a thing is not always possible - especially when one of our own contemptuously disregards such edicts.',
    `RequestItemsText` = 'It is good to see you, $N.'
WHERE `entry` = 5160;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So it shall be...',
    `RequestItemsText` = ''
WHERE `entry` = 5161;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I am Jeziba, known to many as the Sculptor. What I sculpt, however, are not statues, but heroes.',
    `RequestItemsText` = ''
WHERE `entry` = 5162;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hah! They''ll think twice before making fun of my ideas again!$B$BThanks for your help, $N. I couldn''t have had so much fun without you!',
    `RequestItemsText` = 'I can''t wait to hear how my friends react!$B$BThey''ll never expect it!'
WHERE `entry` = 5163;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hundreds upon hundreds of pages filled with garbled text and symbols make up the brunt of this book.',
    `RequestItemsText` = ''
WHERE `entry` = 5164;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I was able to see you with my spells as soon as the last brazier''s flames died. Well done, $N.$B$BI learned a few things before the Shadow Council''s warlocks were able to recast their spells. Hopefully it will be enough.$B$BFor now, rest. I will tell you what I''ve learned in a moment.',
    `RequestItemsText` = 'The braziers must be extinguished if we are to have any hope of being prepared for a much greater battle. Going in to the dragon''s lair without any knowledge is a fool''s errand. And this is much worse than a dragon. The Shadow Council are solely responsible for a great number of crimes and atrocities. We''ll have to work quickly if we''re to stop them.'
WHERE `entry` = 5165;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Do you not yet understand? The journey was the destination. Can you not feel the battle scars? The pain you underwent?$B$BHaving survived the ordeal, you are a more powerful being. Much more powerful. This breastplate is merely a reflection of your own innate abilities.',
    `RequestItemsText` = 'You have chosen wisely, $R.'
WHERE `entry` = 5166;

UPDATE `quest_template` SET
    `OfferRewardText` = 'They will smell their kin as you enter their halls, $N. Crush them with their own fear!',
    `RequestItemsText` = 'Such an item has never been crafted!'
WHERE `entry` = 5167;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have the libram and the shield!$B$BTheir history is entwined with the history of Darrowshire, and somehow, I know that fate will bring them together again.',
    `RequestItemsText` = 'Do you have the relics, $N?'
WHERE `entry` = 5168;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found them! Well done, $N! These relics hold a power I do not fully understand, a power you will one day harness.$B$BThey also bring dark memories to my mind, memories death and treachery, and of the last night of Darrowshire...',
    `RequestItemsText` = 'Did you find the skull and the sword, $N?'
WHERE `entry` = 5181;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I am relieved to hear that for a short moment, we will not have to worry about the Winterfall intrusion.$B$BYou are beginning to show your perseverance, $N.',
    `RequestItemsText` = 'The furbolgs seem to suffer from such paranoia...'
WHERE `entry` = 5201;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The key, you''ve found it! Please, give it to me and I can finally escape!',
    `RequestItemsText` = 'I begin to wonder if I''ll ever escape this cage.$B$BIt''s only a matter of time before they sacrifice me to whatever demons they worship. The monsters!'
WHERE `entry` = 5202;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You were the one who helped Arko escape? I''m so glad you found me. She passed by here not too long ago on her way to Darnassus. She had Lightforge in tow and wouldn''t even take time to speak to the druids to be healed. She said it was far too urgent.$B$BBut she did tell me about your encounter with Trey''s spirit. What a terrible fate for a Knight of the Silver Hand. She didn''t show it, but I know it''s tearing her up inside, the thought of losing one of her closest friends.',
    `RequestItemsText` = 'You look winded, $N. Are you all right, or is something wrong?'
WHERE `entry` = 5203;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You gather the paladin''s remains as carefully as you can, recalling that at least his spirit has been released from any pain or suffering that might have been forced upon him.',
    `RequestItemsText` = 'You inspect the body, and there is no doubt that these are the remains of the Knight of the Silver Hand, Trey Lightforge. For a moment you think of Arko''narin and question if anyone in your life meant as much to you as this man meant to the Night elf captive you recently helped escape Shadow Hold.$B$BAfter taking another moment to gather your thoughts, you know that you cannot take the paladin''s remains back to Jessir without killing his torturer first.'
WHERE `entry` = 5204;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found them! Wonderful!$B$BAlthough I don''t fully understand how they can help us, I feel their power and I know in my bones that they are linked to my home village of Darrowshire.',
    `RequestItemsText` = 'Do you have the skulls? Chromie said they will be critical for her spell, and that spell will give us the chance to save Darrowshire.'
WHERE `entry` = 5206;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What is this book?  The Annals of Darrowshire?  That was my home before the war... my home before the battle that destroyed it!  Why did you bring me this book?$B$BBut look here!  At the end there are pages that tell tales of the days beyond the battle!  Here is a passage about me!  And one about my brother Joseph!  Is this book true?$B$BWe must discover the truth!',
    `RequestItemsText` = 'You''ve come from the west?  How fare the rest of Lordaeron?  I know that Andorhal is lost, but has the Scourge yet reached fair Tirisfal?'
WHERE `entry` = 5210;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is good to hear you found the tortured souls of my brethren and freed them.  My heart will weep less, knowing at least some of the defenders of Darrowshire no longer wallow in the vile subservience of the Scourge.',
    `RequestItemsText` = 'The poor defenders of Darrowshire cry out to me in my dreams, $N.  You must free them!'
WHERE `entry` = 5211;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There is something that has changed in the chemical structure of the plague''s active agents. More data is required.',
    `RequestItemsText` = 'Some say I worry too much - to them I say, ''You don''t worry enough!'''
WHERE `entry` = 5212;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Astonishing! This will take months to dissect and analyze. The Argent Dawn thanks you for your efforts, $N.$B$BWith our blessing, take your pick between either this Seal of the Dawn or this Rune of the Dawn.  You can use either of them instead of a standard Argent Dawn Commission to collect scourgestones on our behalf.  Should you lose yours, speak with me and I''ll get you a replacement.',
    `RequestItemsText` = 'We are on the verge of discovering what this new active plague agent may be!'
WHERE `entry` = 5213;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh sweet, sweet stogie, how I have missed you...',
    `RequestItemsText` = 'I can''t take it, $N! You gotta help me! I''m dying!'
WHERE `entry` = 5214;

UPDATE `quest_template` SET
    `OfferRewardText` = 'May the power of the Light shine upon you in these dark times, $C.  I am pleased to serve as your coordinator for our plan to sabotage the Scourge''s cauldrons.$B$BOur goal will be to change the composition of the plague that the cauldrons create into something that negatively affects the Scourge.  In order to affect this change, you will need to secure access to each of the four cauldrons present in the Western Plaguelands.$B$BStand ready hero, for a glorious battle against the vile Scourge awaits you!',
    `RequestItemsText` = ''
WHERE `entry` = 5215;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The key taken from Cauldron Lord Bilemaw is a perfect fit in unlocking the access panel.  A foul stench emanates from the opened panel as an unknown mix of concentrated substances swirl inside the cauldron.$B$BThere is a small spigot that the bottle fits well enough under, allowing you to draw a sample for High Priestess MacDonnell back at Chillwind Point.',
    `RequestItemsText` = 'An access panel to the cauldron remains securely fastened.  In order to open it, you will need to find the key.'
WHERE `entry` = 5216;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done $N - it should take Alchemist Arbington no time at all to analyze this and devise a counter agent to introduce into the cauldron.  If we are able to pump out enough of it into the air, we might be able to weaken all the Scourge present here.$B$BThis will no doubt be an ongoing ordeal; we will need to continually hit these cauldrons and introduce our reagents into their mix.  Still, if we can keep it up, we will have a huge advantage over Scourge when the time comes for battle!',
    `RequestItemsText` = 'Welcome back to the relative safety of Chillwind Camp, $N.  What progress on the cauldrons do you have to report?'
WHERE `entry` = 5217;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Adding the reagents to the cauldron''s mix begins to change the color and texture of the cloud it spews forth.  Scourge that are even remotely near the cauldron appear to recoil at the introduction of the new components into the environment.',
    `RequestItemsText` = 'The Scourge''s plague cauldron stands before you, spewing vast amounts of toxins into the air.  A small, non-descript access panel lies in the base of the cauldron''s vast platform.$B$BHaving already defeated the cauldron lord and acquired its key, you are free to add the appropriate reagents to the cauldron to make a counter agent to the plague.'
WHERE `entry` = 5218;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The macabre key found on the cauldron lord easily slides into a keyhole and then disappears, allowing you permanent access to it.  Crude, viscous ichors pulsate through twisted tubes within the cauldrons underpinnings.$B$BThere is a small spigot that the bottle fits well enough under, allowing you to draw a sample for High Priestess MacDonnell back at Chillwind Point.',
    `RequestItemsText` = 'An access panel to the cauldron remains securely fastened.  In order to open it, you will need to find the key.'
WHERE `entry` = 5219;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, there is plenty in here for study.  Well done, $N!$B$BFor now, the next step is in our hands.  We''ll need to produce a list of reagents that, when combined with what is already in the cauldron, will act as its counter.$B$BThe only way we will be able to introduce this is by placing the reagents into the cauldron directly.  Alchemist Arbington will have more information on that, so be sure to speak with him at your earliest convenience.',
    `RequestItemsText` = 'We know that each cauldron employs a different mix of reagents to generate its plague-inducing toxin; likewise, we know that we will need to develop a counter agent that is unique for each cauldron.  Your sample from Dalson''s Tears will be the key to figure out that cauldron''s distinct reagent requirement.'
WHERE `entry` = 5220;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Adding the reagents to the cauldron''s mix begins to change the color and texture of the cloud it spews forth. Scourge that are even remotely near the cauldron appear to recoil at the introduction of the new components into the environment.',
    `RequestItemsText` = 'The Scourge''s plague cauldron stands before you, spewing vast amounts of toxins into the air.  A small, non-descript access panel lies in the base of the cauldron''s vast platform.$B$BHaving already defeated the cauldron lord and acquired its key, you are free to add the appropriate reagents to the cauldron to make a counter agent to the plague.'
WHERE `entry` = 5221;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The cauldron lord''s key unlocks the access panel to this cauldron and then disappears, much like the other keys have for the previous two cauldrons you''ve dealt of.  A putrid smelling substance churns violently beneath the platform of the cauldron.$B$BThere is a small spigot that the bottle fits well enough under, allowing you to draw a sample for High Priestess MacDonnell back at Chillwind Point.',
    `RequestItemsText` = 'An access panel to the cauldron remains securely fastened.  In order to open it, you will need to find the key.'
WHERE `entry` = 5222;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Another finely executed mission, $N!  This makes three cauldrons available to us to turn against the Scourge.  If Kel''Thuzad''s necromantic dominance over these lands wasn''t as strong as it currently is, I''d dare say you''d shut them down completely!$B$BAlchemist Arbington will have a report on what this cauldron - as well as the other cauldrons subverted - will require to deliver our counter agent to the plague.  With that, the time has come to bring the last cauldron of the west under our influence!',
    `RequestItemsText` = 'Once we successfully analyze the sample drawn from the Writhing Haunt''s cauldron, it will provide us with a third avenue to deliver a devastating counter agent onto the Scourge!'
WHERE `entry` = 5223;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Adding the reagents to the cauldron''s mix begins to change the color and texture of the cloud it spews forth. Scourge that are even remotely near the cauldron appear to recoil at the introduction of the new components into the environment.',
    `RequestItemsText` = 'The Scourge''s plague cauldron stands before you, spewing vast amounts of toxins into the air.  A small, non-descript access panel lies in the base of the cauldron''s vast platform.$B$BHaving already defeated the cauldron lord and acquired its key, you are free to add the appropriate reagents to the cauldron to make a counter agent to the plague.'
WHERE `entry` = 5224;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Cauldron Lord Soulwrath''s key disintegrates as it touches the lock on the access panel at the base of the cauldron''s platform.  A slight clanking noise is heard within, and the access panel swings open to reveal more viscous toxins within the cauldron''s framework.$B$BThere is a small spigot that the bottle fits well enough under, allowing you to draw a sample for High Priestess MacDonnell back at Chillwind Point.',
    `RequestItemsText` = 'An access panel to the cauldron remains securely fastened.  In order to open it, you will need to find the key.'
WHERE `entry` = 5225;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Congratulations $N, you''ve unlocked the last cauldron for us!  Alchemist Arbington will soon know what this cauldron requires as far as reagents needed for the mix.$B$BAs for you, I am sure that Commander Valorfist will want to thank you personally for the assistance you''ve given us.  Without you, our struggle against the Scourge would have been nearly insurmountable.  Thank you, hero!',
    `RequestItemsText` = 'Gahrron''s Withering houses the last cauldron here in the west that we need access to.  Once we have a sample of the plague it spews forth, we will be able to introduce our reagents into the environment through four separate vessels!  The Scourge will be hard pressed to keep us out of all four, even with the power of Kel''Thuzad behind them.'
WHERE `entry` = 5226;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Adding the reagents to the cauldron''s mix begins to change the color and texture of the cloud it spews forth. Scourge that are even remotely near the cauldron appear to recoil at the introduction of the new components into the environment.',
    `RequestItemsText` = 'The Scourge''s plague cauldron stands before you, spewing vast amounts of toxins into the air.  A small, non-descript access panel lies in the base of the cauldron''s vast platform.$B$BHaving already defeated the cauldron lord and acquired its key, you are free to add the appropriate reagents to the cauldron to make a counter agent to the plague.'
WHERE `entry` = 5227;

UPDATE `quest_template` SET
    `OfferRewardText` = 'From the shadows, brother $R, I bid you greetings. I am to serve as your coordinator for our plan to sabotage the Scourge''s cauldrons.$B$BOur goal will be to change the composition of the plague that the cauldrons create into something that negatively affects the Scourge. In order to affect this change, you will need to secure access to each of the four cauldrons here in the Western Plaguelands.$B$BThe time has come for you to lead the charge against the Scourge, hero.',
    `RequestItemsText` = ''
WHERE `entry` = 5228;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The key taken from Cauldron Lord Bilemaw is a perfect fit in unlocking the access panel, though it disappears after you use it.  Still, you think you can open the panel now without a key.  A foul stench emanates from the opened panel as an unknown mix of concentrated substances swirl inside the cauldron.$B$BThere is a small spigot that the bottle fits well enough under, allowing you to draw a sample for Shadow Priestess Vandis back at the Bulwark.',
    `RequestItemsText` = 'An access panel to the cauldron remains securely fastened.  In order to open it, you will need to find the key.'
WHERE `entry` = 5229;

