UPDATE `quest_template` SET
    `OfferRewardText` = 'Congratulations $N, you''ve unlocked the last cauldron for us! Apothecary Dithers will soon know what this cauldron requires as far as reagents needed for the mix.$B$BAs for you, I am sure that High Executor Derrington will want to thank you personally for the assistance you''ve given us. Without you, our struggle against the Scourge would have been nearly insurmountable. I thank you, mighty $C.',
    `RequestItemsText` = 'Gahrron''s Withering houses the last cauldron that we need to acquire access to here in the west. Once we have a sample of the plague from that cauldron, we will be able to introduce our reagents into the environment through four separate vessels! The Scourge will be hard pressed to keep us out of all four, even with the power of Kel''Thuzad behind them.'
WHERE `entry` = 5236;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N, your successful re-engineering of the cauldrons is a tremendous victory for us!$B$B<The commander clears his throat and begins to bellow loudly.>$B$BLet all within my presence hear: for service to the Kingdom of Stormwind and to the Alliance above and beyond the call of duty - in the face of overwhelming odds and incredible danger, might I add - I give $N this, and I extend upon his our undying gratitude as a true hero of the Alliance. Cheers, I say!',
    `RequestItemsText` = ''
WHERE `entry` = 5237;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N, your successful re-engineering of the cauldrons is a tremendous victory for us!$B$BLet all within my presence hear: for service to the Forsaken and to the Horde as a whole above and beyond what was expected - in the face of overwhelming odds and incredible danger, might I add - I give $N this, and I extend upon him our undying gratitude as a true hero of the Horde.$B$BHuzzah!',
    `RequestItemsText` = ''
WHERE `entry` = 5238;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve seen Pamela?  She''s alive?$B$BShe''s dead?  No!  Oh, Pamela!  Why does your spirit still suffer in this world.  Why are you perished, while fortune keeps me alive?  In an instant I would switch places with you and wander dead Darrowshire, a ghost and alone!$B$BAh, but this news cannot change fate.  Thank you, $N.  Now my duty, my duty to revenge, burns hot as ever.',
    `RequestItemsText` = ''
WHERE `entry` = 5241;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Earthmother be praised, $N! Thank you! This is a great day, indeed!$B$BThe Shadow Council will be hard pressed to scale to the same levels of power they once held with this blow to their hierarchy. You have done a great thing this day!',
    `RequestItemsText` = 'Without Fel''dan, the Shadow Council will hopefully lose focus and start infighting. They will struggle with one another for control and hoard assets for future plans. That will be an opportune time to devastate them and their demon slaves.'
WHERE `entry` = 5242;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $R. You have proven that while you are tolerant of others, you will stop at nothing to destroy the minions of Kel''Thuzad.',
    `RequestItemsText` = 'Be wary, not all supply crates will have survived the destruction of the city. The Scourge dare not touch the water but surely the holy water will not prevent vermin infestations.'
WHERE `entry` = 5243;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, sure, I can tell you more about Kel''Theril. Mind you now, I''m no historian, but I can tell ya about what I saw there...',
    `RequestItemsText` = ''
WHERE `entry` = 5244;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The past of the high elves is something that I do not wish to discuss, $N. Please, it pains me to think of all that has happened... And that there is no way to make things right.',
    `RequestItemsText` = 'Why have you come here?'
WHERE `entry` = 5245;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The pages have gone untouched for many many years...',
    `RequestItemsText` = 'It is only in the pages of the sacred writings that I will be able to discern whether or not I can help you...'
WHERE `entry` = 5246;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Using these elements, I can fuse the fragments together... to hopefully what they once were.',
    `RequestItemsText` = 'The relic must be placed in the hands of only the most trustworthy. It can not be stolen again...'
WHERE `entry` = 5247;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Pleeease, leeeave meeeeee...',
    `RequestItemsText` = 'Currrrrsed... Forevvvverrrr...'
WHERE `entry` = 5248;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A friend of Ivy Leafrunner? Nice to meet you, $N.',
    `RequestItemsText` = ''
WHERE `entry` = 5249;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A student of Daryn Lightwind? Nice to meet you, $N.',
    `RequestItemsText` = ''
WHERE `entry` = 5250;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Outstanding, $N! Years of intelligence, lost! The Scarlet Crusade will surely feel this blow in the coming weeks.',
    `RequestItemsText` = 'Remember, $N - we must be tolerant yet rigid in our beliefs!'
WHERE `entry` = 5251;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Is that... what I think it is?',
    `RequestItemsText` = 'It has been some time since you left, $N. How have you fared?'
WHERE `entry` = 5252;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I have heard of the Crystal of Zin-Malor; the user of the crystal becomes capable of incredible arcane power, but only if truly worthy. I am impressed that you not only recovered the crystal, but you also realize your own limits, and did not attempt to use the crystal yourself.$B$BThank you for bringing it to me, $N. We will keep it safe, and may the cursed sprits that once guarded the shattered crystal finally be at peace.',
    `RequestItemsText` = 'Yes, $R?'
WHERE `entry` = 5253;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That''s true.  I''m looking for someone to hunt me some wolves!  Are you that person?',
    `RequestItemsText` = ''
WHERE `entry` = 5261;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What will this mean to the Crusade? Could it be possible that they have been under the control of this demon? Unwittingly serving as the pawns to a greater evil?',
    `RequestItemsText` = 'What have you got there, $N?'
WHERE `entry` = 5262;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It has been many years since I have ushered a champion into our ranks. You are the first to be granted audience with Lord Maxwell in years.',
    `RequestItemsText` = 'The Baron has slain more people than you have most likely seen in your lifetime.'
WHERE `entry` = 5263;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You are a worthy ally, $N. You shall reap the rewards of your stalwart dedication.',
    `RequestItemsText` = ''
