UPDATE `quest_template` SET
    `OfferRewardText` = '<Egan wipes a tear from his eye.>$B$BDid you see my mother, $N? Did you free her?$B$BYou are a shining example of decency. For your troubles...',
    `RequestItemsText` = 'Compassion is what separates us from the animals, $N. Remember that...'
WHERE `entry` = 5282;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This be it, $N. After this, there ain''t no way to turn back. It''s not too late to become a toy maker, er, weaponsmith.$B$BI trust ye''ll make the right decision.',
    `RequestItemsText` = 'Ah, ain''t nothing like a good forge tan. Ye can tell who''s got the really good tans by their apron lines.'
