UPDATE `quest_template` SET
    `OfferRewardText` = 'About time! I''ve got customers waiting.$B$BGive those here and pay attention. You''re going to take the first step in your career as a weaponsmith.',
    `RequestItemsText` = '<Ironus is busy stacking gold coins into neat little piles.>'
WHERE `entry` = 5284;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is the final step before you begin your new career as an armorsmith, $N. Should you choose to back out, now would be your last chance. Otherwise, prepare yourself for a lifetime of glory.',
    `RequestItemsText` = 'I will pound the steel until the breath itself has been taken from me.'
WHERE `entry` = 5301;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is the final step before you begin your new career as a weaponsmith, $N. Should you choose to back out, now would be your last chance. Otherwise, prepare to be consumed by knowledge!',
    `RequestItemsText` = 'For the glory of the Horde!'
