UPDATE `quest_template` SET
    `OfferRewardText` = 'Knowledge is power!',
    `RequestItemsText` = 'Legend states that one use of Vosh''gajin''s snakestone will keep an axe razor sharp for a 1000 years!'
WHERE `entry` = 5306;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It should be obvious that a sword is always the best choice.',
    `RequestItemsText` = 'Have you forgotten what it is that you were tasked with, $N?'
WHERE `entry` = 5307;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, I am so happy Kerlonian made it! And I''m sure I''ll find him sleeping somewhere around here, won''t I?$B$BThank you for showing him the way, $N.',
    `RequestItemsText` = 'Has Kerlonian arrived?'
WHERE `entry` = 5321;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent work, $R. Now to secure my inheritance...',
    `RequestItemsText` = 'Bow your head in my presence, $R. I am a noble, after all, and you are a copperless peasant.'
WHERE `entry` = 5341;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wonderful! Now only I hold the power and fortune of house Barov!$B$B<Alexi throws a large bag at you.>$B$BAnd keep the change, you filthy animal.',
    `RequestItemsText` = 'Secure my fortune and share in the spoils.'
WHERE `entry` = 5342;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There is but one more task that I must ask of you, $N.',
    `RequestItemsText` = 'Ensure my future and I shall ensure yours.'
WHERE `entry` = 5343;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A glorious day it is! Finally, the pockmark of house Barov eliminated and my fortune secure!$B$BTake this and leave my sight, peasant.',
    `RequestItemsText` = 'You do want payment, do you not?'
WHERE `entry` = 5344;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I know not what connection you have with my brother but it would seem he has trust with you, $C.$B$BI am Nataka Longhorn and would like to welcome you to Ghost Walker Post, we have many needs of a $C! Talk with others, perhaps there is need of you here.',
    `RequestItemsText` = 'What news have you, $C!  Ah - a message from my brother you say?  Well then, hand over the report!'
WHERE `entry` = 5361;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, the Demon Box. Give it to me, $C, and I shall open... and thus reveal to you the Hand of Iruxos.',
    `RequestItemsText` = '$N, do you have the Demon Box?'
WHERE `entry` = 5381;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I can feel my spirit healing, $N. You have done my husband and I a great service, but I am certain there is more to be done.',
    `RequestItemsText` = 'The Butcher must be stopped!'
WHERE `entry` = 5382;

UPDATE `quest_template` SET
    `OfferRewardText` = 'With the death of Kirtonos, a chapter in the horrible tale of Scholomance comes to a close. There is, however, more to be done. Others here are now aware of your brave acts. Take this, $N. It is a piece of our own essence. It will allow you to communicate with the other lost souls of Caer Darrow.',
    `RequestItemsText` = 'Be wary, Kirtonos is a seasoned fighter.'
WHERE `entry` = 5384;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done it! Praise be to Elune and whichever powers you worship, $N. You have done an honorable and noble thing this day. I am certain Arko''narin will be pleased that you not only took the time to save her, but to also slay the creature who tortured one of her best friends.$B$BI wish I could do more for you, but please, take this.',
    `RequestItemsText` = 'How did things go in Jaedenar, $N?'
WHERE `entry` = 5385;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You are a savior, $N! These Bloodbelly fish look almost good enough to eat raw.$B$B<Nataka starts salivating.>$B$BHere you go - choose one of these items as a payment for these fish.',
    `RequestItemsText` = 'My hoof tingles and my mouth starts to water when I think of fried Bloodbelly fish... You have any on you?'
WHERE `entry` = 5386;

UPDATE `quest_template` SET
    `OfferRewardText` = 'All who fight evil on behalf of the Argent Dawn must don our commission.  Wearing such will earn your right to claim rewards our quartermasters have to offer.$B$BWhile under commission, you''ll be able to acquire Scourgestones from slain Scourge; these are marks of insignia that they sometimes possess.  Procure these insignia and bring them to me.  For each set you turn in, you will receive our marker of heroism - the Argent Dawn Valor Token.$B$BAchieve your destiny, $C - join the fight today!',
    `RequestItemsText` = ''
WHERE `entry` = 5401;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Congratulations, $N - I am pleased to award you with an Argent Dawn valor token!$B$BThe tokens serve two purposes.  One - they can be used to further your standing within the Argent Dawn; to do so may avail you options and rewards that are reserved for our honored and revered allies.  Two - they can be given to our quartermasters, along with coin, as payment for some of the Dawn''s more prized items.$B$BWhatever you decide, know that you are earning your commission.  Well done!',
    `RequestItemsText` = 'A Minion''s Scourgestone is the insignia of the Scourge rank and file.  These are sometimes found on the weaker of their troops positioned in the Plaguelands, though the term "weaker" is certainly to be considered in context.  The Scourge, no matter where they are, should never be underestimated.$B$BThe Argent Dawn currently offers a valor token in exchange for twenty of these insignia - an exchange I''m happy to do, provided you have earned enough scourgestones!'
WHERE `entry` = 5402;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Congratulations, $N - I am pleased to award you with an Argent Dawn valor token!$B$BEach valor token handed out to worthy recipients is a sign of the tide turning against the Scourge. With more and more heroes fighting the Scourge in their own lands, the Argent Dawn will assuredly be at the forefront when the time comes to wage war on the ultimate evil of the Scourge. I hope that the valor you''ve shown what it took to acquiring your token will carry the day then as well!',
    `RequestItemsText` = 'An Invader''s Scourgestone is the insignia of the Scourge''s elite troops.  These are sometimes found on the stronger of the troops positioned in the Plaguelands.  Slaying such a creature is indeed a challenge, but one that should be relished with a commission to vanquish evil.$B$BThe Argent Dawn currently offers a valor token in exchange for ten of these insignia.  Bring them to me here, and I will make sure you receive your just reward.'
WHERE `entry` = 5403;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Congratulations, $N - I am pleased to award you with an Argent Dawn valor token!$B$BTo acquire a valor token in such a manner indicates that you are a true hero in the cause of good. We value all effort brought to bear against the Scourge, but to take down one of their leaders is to truly deliver onto them a crushing defeat!$B$BFor the Dawn, my brother!',
    `RequestItemsText` = 'A Corruptor''s Scourgestone is the insignia of the Scourge''s overlords.  A powerful being that holds a position of authority over the Scourge will always possess one.  To slay such a malevolent creature would surely advance the cause of the Argent Dawn, and all good causes!$B$BOn behalf of the Argent Dawn, I will give you a valor token in exchange for just a single one these insignia.  Use caution in acquiring one, $N - such powerful beings are not to be trifled with.'
WHERE `entry` = 5404;

UPDATE `quest_template` SET
    `OfferRewardText` = 'All who fight evil on behalf of the Argent Dawn must don our commission. Wearing such will earn your right to claim rewards our quartermasters have to offer.$B$BWhile under commission, you''ll be able to acquire Scourgestones from slain Scourge; these are marks of insignia that they sometimes possess. Procure these insignia and bring them to me. For each set you turn in, you will receive our marker of heroism - the Argent Dawn Valor Token.$B$BAchieve your destiny, $C join the fight today!',
    `RequestItemsText` = ''
WHERE `entry` = 5405;

