WHERE `entry` = 5408;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Sweet mon, nothing beats work being done, especially if it''s someone else doing the work... eh?',
    `RequestItemsText` = 'I''ll reward anyone who makes my life a bit easier... I enjoy doing as little as possible, mon!$B$BBelow the docks here in Shadowprey Village, I''ve many shellfish traps.  If you''re kind enough to do my work and collect me my shellfish, then I''ll reward you with something you want... get my drift mon?  For every five shellfish you bring me I will give you a fine Bloodbelly fish!'
WHERE `entry` = 5421;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good, good. Maybe they''ll think twice before slacking next time!$B$BThanks for the help!',
    `RequestItemsText` = 'No good lazy...$B$BEh? Do you have my blackjack? Did you catch any peons sleeping on the job?!'
WHERE `entry` = 5441;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I had doubted the possibility of such an item existing. This certainly opens up an incredible opportunity - one we must not squander.$B$BPrepare yourself, $N, for what I am about to ask of you will take you into the depths of hell.',
    `RequestItemsText` = 'A keepsake of remembrance is a rare find, $N.'
WHERE `entry` = 5461;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Leonid looks over the keepsake.>$B$BYour quandary stirs up memories that I had hoped would never resurface.',
    `RequestItemsText` = 'Do not ask questions of which you do not want answers.'
WHERE `entry` = 5462;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You place the keepsake on the tainted soil.',
    `RequestItemsText` = 'The area around Menethil''s Gift is exceptionally cold.'
WHERE `entry` = 5463;

UPDATE `quest_template` SET
    `OfferRewardText` = 'As the soul clung to the keepsake, so shall it cling to the physical form of Ras Frostwhisper.',
    `RequestItemsText` = '<Leonid shudders.>'
WHERE `entry` = 5464;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I was certain that you would be joining me as another hapless spirit.',
    `RequestItemsText` = 'Have you done the impossible?'
WHERE `entry` = 5465;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ten thousand souls cry out in unison, $N! You have struck a mortal blow to the Scourge and their masters.',
    `RequestItemsText` = 'You carry the burden of ten thousand restless souls, $N.'
WHERE `entry` = 5466;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What''s this? Gloom weed?! I''ve no need for gloom weed! That mindless mass of flesh is out there picking daisies and convincing the Lady knows how many dupes like you into doing the same. No offense.$B$BVery well, you''re here now and that''s all that matters. Since I''m not going to bother to try to explain things to that abomination how about you collect what I really need... doom weed!',
    `RequestItemsText` = 'Where''s that useless abomination? Either you have what I need or you''d best get out there and find it.'
WHERE `entry` = 5481;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, my doom weed. Excellent!$B$B<Junior Apothecary Holland rubs his hands together greedily.>$B$BThese will come in quite handy. You''ve done me, uh, the Lady, a fine service today, $N. As promised here is the reward that you deserve.',
    `RequestItemsText` = 'This had better be good. I trust you have all of the doom weed that I require?'
WHERE `entry` = 5482;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, goodie!  My bones!$B$BI can''t wait till the chaps at home see my face on the front cover of Goblin''preneur.  I''ll be the richest goblin in the world... and my physical education teacher said I would never amount to anything.',
    `RequestItemsText` = 'Do you have the bones?  The caravan will be here any moment.  I need just ten more kodo bones to reach a career high.  A career high, I tell you!'
WHERE `entry` = 5501;

UPDATE `quest_template` SET
    `OfferRewardText` = 'May the spirits bless you, $N.  You''ve done more for Grunth than most would ever think of doing for him.  Thank you - you''re the epitome of what it means to be a hero of the Horde.$B$BPlease - if you can spare the time, come back and visit us.  I know that Grunth would like that, as would I.$B$BGrunth had so much fun with you, $N.  He wanted to give you one of his favorite pets to remember him by.',
    `RequestItemsText` = 'It is a pleasure to see you again, $N.  Have you attended to the duties you''ve volunteered for during Children''s Week?'
WHERE `entry` = 5502;

UPDATE `quest_template` SET
    `OfferRewardText` = 'All who fight evil on behalf of the Argent Dawn must don our commission. Wearing such will earn your right to claim rewards our quartermasters have to offer.$B$BWhile under commission, you''ll be able to acquire Scourgestones from slain Scourge; these are marks of insignia that they sometimes possess. Procure these insignia and bring them to me. For each set you turn in, you will receive our marker of heroism - the Argent Dawn Valor Token.$B$BAchieve your destiny, $C join the fight today!',
    `RequestItemsText` = ''
WHERE `entry` = 5503;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Outstanding - your tribute to the Dawn is duly noted, $N. With this accomplished, I am delighted to make our mantles available to you for purchase. So long as you maintain your current status with us, these mantles will be purchasable from any authorized quartermaster of the Argent Dawn.$B$BFor the Dawn, my brother!',
    `RequestItemsText` = 'Ah, noble $C! Have you brought the valor tokens requested of you? Once you hand them to me, I will make our various mantles available to you for purchase.'
WHERE `entry` = 5504;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good luck, mighty hero. May your victories continue to bring you fame and power as you lay waste to Scholomance!',
    `RequestItemsText` = 'Well, here you are, $N - the completed Skeleton Key. I am certain as I can be that this key will allow you within the confines of the Scholomance. There''s only one way to be absolutely sure it works, though. Waste no time in trying it out, I say.'
WHERE `entry` = 5505;

