UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done the Light a great service by becoming a shining example to those who travel in these dangerous lands and beyond. Please, accept this lesson as a thanks for all you''ve done.',
    `RequestItemsText` = ''
WHERE `entry` = 5634;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I''m glad you''ve arrived, $N. There are many things we will have to discuss, but more importantly is your training in the ways of the Light.$B$BThere are lessons all servants of the Light must learn. If you are ready, we''ll begin discussing some of those now.',
