UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve got the makings of a great $C, $N. Keep up the good work!$B$BYou''ve already shown you''re ready for battle. Perhaps it''s time we taught ya a little somethin'' more.',
    `RequestItemsText` = ''
WHERE `entry` = 5641;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your rites will come soon enough. For now, I teach you a spell that will be of great use to you when you do battle with your enemies.',
