UPDATE `quest_template` SET
    `OfferRewardText` = 'I would teach you Devouring Plague if you feel you are prepared, $N. A spell of no small power, it will aid you in your coming battles. Practice with it--there will be tests later.',
    `RequestItemsText` = ''
WHERE `entry` = 5644;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is good you''ve come, $N. Our race is proud and strong, and it is time you learn to not only be so yourself, but to invoke such emotion and confidence in others. You prepared, lad?',
    `RequestItemsText` = ''
WHERE `entry` = 5645;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good, you''ve returned, and not a moment too late. We have great things to discuss, $N. Your abilities are growing stronger, and we must make sure you are ready.',
    `RequestItemsText` = ''
WHERE `entry` = 5646;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve got the makings of a great $C, $N. Keep up the good work!$B$B$NYou''ve already shown you''re ready for battle. Perhaps it''s time we taught ya a little somethin'' more.',
    `RequestItemsText` = ''
WHERE `entry` = 5647;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good, then Kor''ja lives and goes off to defend our town from those malicious humans. I often wish to remember days of battle; where power was shown in combat and it was the wise who often destroyed those who relied on just their strength.$B$BYou done good by me, $N. You take this robe now. Maybe it help, maybe you not care, but you earned it and I''m proud to call you brother.',
    `RequestItemsText` = 'Most think it logical that healin'' magics be powerful, but not many understand how powerful. You can keep many alive when instead they should be meetin'' their own ancestors. This healin'' magic mixed with the ability of Fortitude are a very powerful combination of spells. You remember this. It helpful to all manner of people: warriors, mages and everything in between.'
WHERE `entry` = 5648;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh... so you finally come to Tai''jin. This be good.$B$BYou already know that we are not da same tribe that once joined with the Horde. We be much stronger now. We stronger ''cause we adapt--the Horde teach us that much. We no longer defeat our enemies and gain strength from them; now we gain strength, and then defeat our enemies.$B$BThe difference be subtle, but you will learn. You will see. The tribe count on you to learn such things.',
    `RequestItemsText` = ''
WHERE `entry` = 5649;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have passed my test with ease. Good.$B$BSoon, you will be ready to take on more responsibility and that road will lead to darker powers--powers that no $C of another race has.$B$BTake this robe as a symbol of your station. You have earned it. If you do not wish to wear it, then so be it, you may do with it as you will. I and others like us will always acknowledge you for what you''ve achieved in our ranks.',
    `RequestItemsText` = 'Our powers make us ideal for so many situations, $N. You''ll find that no matter what though, our ability to mend wounds and increase the amount of damage our companions can take will always be the most desired talents we have access to. Do not let that dissuade you from pursuing other paths as a $C--you can be effective in many ways. But... if you truly wish to destroy your enemies with magical energy, perhaps the arcane is more to your liking.'
WHERE `entry` = 5650;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Finally, you''ve arrived. Your faith alone will not allow you to pass the trials before you, young one. A sense of urgency and some ambition will help too.',
    `RequestItemsText` = ''
WHERE `entry` = 5651;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You would do well to pay heed to this lesson, young one. The Hex of Weakness will be a great boon to you in battle. Later I will have tests for you to further yourself and prove your worth to the tribe.',
    `RequestItemsText` = ''
WHERE `entry` = 5652;

