    `OfferRewardText` = 'Ah, young $C, I am glad you have returned here. I would teach you a lesson you would do well to not forget. Are you prepared?',
    `RequestItemsText` = ''
WHERE `entry` = 5658;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, good, another has arrived. Time may not matter to me, but to you it is of the essence. There is much for you to learn and there is much I wish to teach you. You simply must prove your worth. Do that, and you shall be greatly rewarded.',
    `RequestItemsText` = ''
