UPDATE `quest_template` SET
    `OfferRewardText` = 'By devoting yourself to Elune and our people, you have attained a state that not all of us can achieve. It is tradition that you then be taught even greater abilities for your devotion. Do you accept?',
    `RequestItemsText` = ''
WHERE `entry` = 5672;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Elune bless you for returning so quickly to us. This is an important time in your training, and a time that all of our order take very seriously. When you''ve rested from your journey here, please, let me know. We can then discuss the continuation of your training and where your path will lead you next.',
    `RequestItemsText` = ''
