UPDATE `quest_template` SET
    `OfferRewardText` = 'We were forced to learn some magics to protect us from what is commonly called our greatest enemy: the arcane.$B$BI would teach you a spell to help you defend yourself and your companions from those who would wield such power.',
    `RequestItemsText` = ''
WHERE `entry` = 5676;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, you have wonderful timing, $N. I was beginning to wonder if all of my messengers had been successful. I''m glad to see they were, otherwise I would wager you''d still be out in the world learning more about all the threats that exist against our people.$B$BAre you ready? Ready for more training I mean. You''re growing in power more quickly, and I feel you are ready to learn more about our faith.',
