UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done! I''ll put these supplies to good use! Thanks, $N!',
    `RequestItemsText` = 'Do you have the supplies, $N? We can never have enough!'
WHERE `entry` = 5892;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, you got them. Good work, $N! These supplies are a little musty from sitting in that dark mine for so long, but we''ll make use of them nonetheless.$B$BThank you, $N. Your deeds are vital to the maintenance of our fighting forces.',
    `RequestItemsText` = 'Have you been to the Coldtooth mine, $N? Do you have the supplies I asked for?'
WHERE `entry` = 5893;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These will do nicely, $N. Thank you.$B$BIf you''re ready, we can get on with the next step.',
    `RequestItemsText` = 'Do you have the termites yet, $N? I am sure it is obvious to a smart $C like yourself.$B$BOnce we have enough of them, we''ll make sure no one can use the lumber mill ever again!'
WHERE `entry` = 5901;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The termites are obviously getting restless as you place the barrel on top of the crate.',
    `RequestItemsText` = ''
WHERE `entry` = 5902;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These will do nicely, $N. Thank you. Just look at them... so many of them all huddled up. I almost feel bad for the Crusade, but then again, it was never their mill to take, now, was it?',
    `RequestItemsText` = 'Did you find the termite mounds, $N? I''ve heard they are all over Plaguewood.'
WHERE `entry` = 5903;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The termites are obviously getting restless as you place the barrel on top of the crate.',
    `RequestItemsText` = ''
WHERE `entry` = 5904;

UPDATE `quest_template` SET
    `OfferRewardText` = '"And so it begins. Father Cenarius. And so it begins."$B$BDendrite makes a quick, invisible gesture in the air above him. A slight aura of power falls over him.$B$B"The first perspective of nature you must adapt to is that of the bear. I will put you on the path to understanding this aspect of druidic life, but it is you that must embrace it and propagate it - now and forever!"',
    `RequestItemsText` = ''
WHERE `entry` = 5921;

