UPDATE `quest_template` SET
    `OfferRewardText` = 'I am glad you found your way here today. young $C. The time has come for you to take a large step into a much larger world.$B$BInside each of Cenarius'' children is the call to serve nature. Animals and plants are our friends as well as our charges. We choose to devote our lives as preservers of balance for their sakes as well as our own. Your first step into this world will be to learn of the ways of the bear, and to learn strength of body and heart.$B$BReady yourself!',
    `RequestItemsText` = ''
WHERE `entry` = 5923;

