UPDATE `quest_template` SET
    `OfferRewardText` = 'Dendrite makes another invisible gesture in the air above him as you approach. Another aura of power comes over him. and he smiles ever so slightly.$B$B"I sense wisdom in you, young one, that was not present when we first met. You gaze upon me with strength and knowing intent, though this intent is yet not focused. You will now learn to focus your strength and adopt the nature of the bear into your work."',
    `RequestItemsText` = 'Return only when the Great Bear Spirit has released you back unto me.  Your training cannot continue without its blessing.'
WHERE `entry` = 5929;

