UPDATE `quest_template` SET
    `OfferRewardText` = 'Welcome back, $N. I sense that your first meeting with the Great Bear Spirit is the same as it is with all druids when they first start down the path of the Claw... a little bewildering, but very intense. I know it was that way with me.$B$BThe Great Bear Spirit has been a part of Azeroth as long as Azeroth has existed in the heavens. We have come to rely on its wisdom and its power to fuel our purpose. Now, the time has now come for your first test of this purpose. Listen closely...',
    `RequestItemsText` = ''
WHERE `entry` = 5931;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Welcome back, $N. I sense that your first meeting with the Great Bear Spirit is the same as it is with all druids when they first start down the path of the Claw... a little bewildering, but very intense. I know it was that way with me.$B$BThe Great Bear Spirit has been a part of Azeroth as long as Azeroth has existed in the heavens. We tauren listen closely to such spirits, and we all prosper from its purpose. Now, the time has now come for your first test of this purpose. Listen closely...',
    `RequestItemsText` = ''
WHERE `entry` = 5932;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah yes, there they are. Together they weave a powerful spell, one that will raise the spirits of Darrowshire.$B$BWith that spell, and with a little luck, we can save Joseph Redpath!',
    `RequestItemsText` = 'I have been in contact with your friend Carlin. He feels great pain for the doom of his village, but he speaks very highly of you and knows that you can set things right.$B$BOh, but I''m drifting from the subject at hand... $N, do you have the relics I asked for?'
WHERE `entry` = 5941;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The key fits the lock, and the chest opens...',
    `RequestItemsText` = 'This chest is old and covered in grime.'
WHERE `entry` = 5942;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Not sure it''s a prosperous proposition to be paying so much money to protect the Gizelton Caravan. Cork and Rigger only make one gold piece a week, but as long as they keep paying for my kodos I can care less how they run their business.',
    `RequestItemsText` = 'You know, if that caravan were to ever disappear I would be ruined! You''re not the bearer of bad news about the caravan, are you?$B$B<Smeed wipes his brow.>$B$BThank the goddess of greed!'
WHERE `entry` = 5943;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The death of my son at the hands of these monsters will not pass without incident. Take solace in knowing that the Order is reborn.$B$BI now take my place as Highlord of the new Order of the Silver Hand.$B$BThese possessions of my past - they are all that I have to offer for all that you have done. Please, take these as a symbol of my gratitude; all have served me well over the years.$B$BMay we meet again, in better times, and reminisce of days long past... battles hard fought... dreams redeemed.',
    `RequestItemsText` = '<Tirion regains his composure.>'
WHERE `entry` = 5944;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Surely the Dark Lady does not believe you worthy to meet her champion. You are here to feed my hounds, yes? There could be no other reason for this interruption.',
    `RequestItemsText` = ''
WHERE `entry` = 5961;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent, $N. Your determination has been duly noted.',
    `RequestItemsText` = 'You must continue to prove yourself, $N.'
WHERE `entry` = 5981;

UPDATE `quest_template` SET
    `OfferRewardText` = '',
    `RequestItemsText` = ''
WHERE `entry` = 6000;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have finally taken your large step into a much larger world, $N. I sense the teaching of the Great Bear Spirit within you, and I sense that you have received the strength that Lunaclaw possessed.$B$BThere are no further obstacles in your way... let me now teach you what it means to be a $C of the Claw!',
    `RequestItemsText` = 'When you have faced the challenge that lies before you, your understanding of strength of body and strength of heart will be fully realized.  Until that time, I cannot help you further.'
WHERE `entry` = 6001;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have finally taken your large step into a much larger world, $N. I sense the teaching of the Great Bear Spirit within you, and I sense that you have received the strength that Lunaclaw possessed.$B$BThere are no further obstacles in your way... let me now teach you what it means to be a $C of the Claw!',
    `RequestItemsText` = 'When you have faced the challenge that lies before you, your understanding of strength of body and strength of heart will be fully realized.  Until that time, I cannot help you further.'
WHERE `entry` = 6002;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N. I''m amazed you dealt with them so quickly. Thank you.$B$BI have yet to meet anyone that approves of the Scarlet Crusade and their methods. I believe in the Light as much as anyone else in Stormwind, but they''ve demonstrated that they only want to kill anyone not loyal to their movement... even innocents.',
    `RequestItemsText` = 'How is it going, $N? Are they stronger than you thought? I hope not. If I''m going to follow through here, then it''s going to require a heck of a lot more strength than what I''ve already asked you to do.'
WHERE `entry` = 6004;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great, you got him!  And I hope you taught his gang a lesson too!',
    `RequestItemsText` = 'Did you find the hideout, $N?  Did you take care of Zaeldarr?'
WHERE `entry` = 6021;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Disappointing. I was hoping that I''d be feeding you to my hounds, instead.$B$B<Nathanos sighs.>$B$BWell, at least you they''ll have something to eat.',
    `RequestItemsText` = 'Are you crying? If this is too ''tedious'' for you, ''hero,'' I recommend that you head back to the Dark Lady and inform her of the horrible mistreatment you received at my farmstead.$B$BNow get out of my sight!'
WHERE `entry` = 6022;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. You''ve been more help than I could have hoped for. The air here just seems to suck my will. I feel tired, and I can tell I''m not getting any better the longer I''m here.$B$BI''m not really sure how I''m going to infiltrate Hearthglen itself and report on how strong the Scarlet Crusade''s presence is.$B$BBut that''s another matter, before you leave, here, take this... as payment for your help. Thank you again.',
    `RequestItemsText` = 'Have you found them yet, $N? With the two of them taken care of, I can proceed to enter Hearthglen to take a closer look at their setup. I can''t do it without your help. Please, find Radley and Durgen for me.'
WHERE `entry` = 6023;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hameya''s chest is opened!!',
    `RequestItemsText` = 'This chest buried here is securely locked.'
WHERE `entry` = 6024;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done it, $N! Thank you!$B$BI''ll return to Elling... I mean Stormwind as soon as I can. Here, take this coin, it''s the least I can do for you. You''re a credit to your people, $N. Thank you and good luck.',
    `RequestItemsText` = 'It''s a dangerous task, $N. I envy your courage.'
WHERE `entry` = 6025;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I can pay you half up front and half when the job is done.',
    `RequestItemsText` = 'Trust ol'' Smokey, $R. The reward will be worth it. These Argent Dawn folk don''t mess around when it comes to payment.'
WHERE `entry` = 6026;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The long lost Book of the Ancients!  I will ensure this book is passed on to the high council.  You''ve done well today, and for that you are to be thanked... as a hero should be thanked!',
    `RequestItemsText` = 'Ah, $N!  It''s good to see you again.  Do you have the Book of the Ancients?'
WHERE `entry` = 6027;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very resourceful, Gregor is.  He''s been dealing with the Steamwheedle Cartel for some time now, and has become an expert on the "art" of goblin negotiations.  Though it''s true that the goblins'' primary loyalties lie with those who have the largest coin purses, they also know and respect the value of diplomacy.  If anything, it provides them with repeat customers...$B$BAt any rate, the Argent Dawn acknowledges you for your effort.  Please have this, with our thanks.',
    `RequestItemsText` = 'Greetings, $C.  On behalf of the Argent Dawn, I offer you safety and shelter while you are here at Chillwind Camp.  I might also have some work for you...'
WHERE `entry` = 6028;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Resourceful for a human, Gregor is.  He''s been dealing with the Steamwheedle Cartel for some time now, and has become an expert on the "art" of goblin negotiations.  Though it''s true that the goblins'' primary loyalties lie with those who have the largest coin purses, they also know and respect the value of diplomacy.  If anything, it provides them with repeat customers...$B$BAt any rate, the Argent Dawn acknowledges you for your effort.  Please have this, with our thanks.',
    `RequestItemsText` = 'Greetings, $C.  On behalf of the Argent Dawn, I offer you safety and shelter while you are here at Bulwark.  I might also offer you the chance to fight for a cause that''s worth fighting for!'
WHERE `entry` = 6029;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This... this is a very special book you have brought me.  I''d like to tell you that "special" in this case means "unique and quite possibly illuminating", but that remains to be seen.$B$B"Ooooooo?"  Who in their right mind thinks this up?$B$BWell now, I''ve heard of this Umbranse that Gregor spoke of, so this isn''t without merit.  I''ll do my best to decipher it.  As for you... please, have this - courtesy of the Argent Dawn.  While you are here, perhaps there are some other things you can aid us with.',
    `RequestItemsText` = 'May the Light guide you in these troubling times, $C.  What brings you here to this beacon of hope in the middle of darkness and despair?'
WHERE `entry` = 6030;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, you brought the cloth.  Such fine material it is!$B$BThank you, $N.  You are a true friend.  Please accept this in exchange.',
    `RequestItemsText` = 'Do you have the runecloth?  My people are eager for more items of runecloth!'
WHERE `entry` = 6031;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, very good. This mooncloth will be used for garments sacred to our people. Thank you, $N. Now I will train you.',
    `RequestItemsText` = 'Have you brought the mooncloth, $N?'
WHERE `entry` = 6032;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''re much darker than I remember. You got that look going for you; the look that says, ''I''ve been charred by a high explosive bomb.''$B$B<Smokey laughs.>$B$BAnyhow! Here''s your cut of the loot. I''ve thrown in a little something extra to help soothe the burns.',
    `RequestItemsText` = 'I got supplies left over to make a few more sticks of the special compound. Just let ol'' Smokey know if you need more.'
WHERE `entry` = 6041;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It''s incredible what a little anger and rage can get accomplished.',
    `RequestItemsText` = 'It could have been worse. I could have had you collecting bat guano.$B$B<Nathanos stares at you in contemplation.>$B$BHrm... Hey! Wait a minute. Where are you going?'
WHERE `entry` = 6042;

