UPDATE `quest_template` SET
    `OfferRewardText` = 'You have learned all I can teach you, $N. It is time for you to take what you have learned here and choose a pet of your own.$B$BHere you are, $N. I will now give you the power to tame a beast, as well as call it and dismiss it as you see fit. Use your new skills with pride; you have earned them.',
