UPDATE `quest_template` SET
    `OfferRewardText` = 'A new recruit, eh? You''re on your way to becoming a great $C, I see.$B$BYes, I can bestow you with the skills you need to train and guide your pet. Not only will you be able to teach your pet new abilities, you will now be able to feed your pet, as well as revive it, should it fall in battle.$B$BRemember that the key to getting the most from your new pet is to respect it and treat it well. In turn, your pet will be your most loyal friend.',
    `RequestItemsText` = ''
WHERE `entry` = 6086;

