UPDATE `quest_template` SET
    `OfferRewardText` = 'There it is!  Looks like you got some of it on you too.  Kinda slimey, eh?$B$BWell, thanks a lot for all the trouble, $N.  This stuff will be worth a fortune... if I can convince the centaurs what it is!',
    `RequestItemsText` = 'Where''s my ghost-o-plasm, $N?'
WHERE `entry` = 6134;

