UPDATE `quest_template` SET
    `OfferRewardText` = 'I received word of aid arriving from the east.  Are you the source of these rumors?  Have you come here to help the Scarlet Brother in its crusade?$B$BIf so, then listen close...',
    `RequestItemsText` = ''
WHERE `entry` = 6141;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Perfect mon, this is just what the witch doctor told me to do for my headache. He says, "Mai''Lahii - go fish. It''ll make you feel better"$B$BWell, I feel better already, thanks mon!',
    `RequestItemsText` = 'I can''t wait to go fishing with some fresh soft-shelled clam meat; did you bring me the 10 pieces of it I need?'
WHERE `entry` = 6142;

UPDATE `quest_template` SET
    `OfferRewardText` = 'As sweet as it is hearing the news that the naga have been vanquished, my heart still feels empty. For the rest of my life I will be dedicated to having them all killed.$B$BHere mon, your reward as I promised. It''s small in comparison to the gratification of knowing the naga fried for their hated act upon my crew.',
    `RequestItemsText` = 'I still hear their voices crying for help when the naga unleashed their chaos over us. If I didn''t have this bad knee, I''d go and help you kill those blasted naga!$B$BYou can usually guarantee to find them deep in the coral reefs below the surface... lurking... scheming...'
WHERE `entry` = 6143;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Grand Crusader sits safely in the Scarlet Bastion while his forces pour into your lands, desecrate your structures and monuments and murder your people.$B$BThe Dark Lady has commanded that I deal with this insect once and for all. You will become the instrument of the Forsaken''s reckoning.',
    `RequestItemsText` = ''
WHERE `entry` = 6144;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Nathanos laughs.>$B$BExcellent! Finally! An opportunity to destroy the Scarlet Oracle!',
    `RequestItemsText` = 'Succeed now and you will have almost earned my respect, $C.'
WHERE `entry` = 6145;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Where have you been? We had thought the Scourge had captured you.',
    `RequestItemsText` = 'This is unacceptable, soldier!'
WHERE `entry` = 6146;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The fools! My deception went unnoticed! Prepare yourself, $C. We must strike with cold cunning!',
    `RequestItemsText` = ''
WHERE `entry` = 6147;

UPDATE `quest_template` SET
    `OfferRewardText` = 'They will be reeling from this blow for years! Well done, $N! You have earned not only my respect but also this reward.',
    `RequestItemsText` = 'What is your status, $N?'
WHERE `entry` = 6148;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Chest opens to reveal Rackmore''s treasure!',
    `RequestItemsText` = 'This chest is securely locked.'
WHERE `entry` = 6161;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You bring honor to me for following through with your word. My husband died in battle--he would have been proud of that. But I could not rest until I knew that the creature that has forced me to live my life alone paid for what it had done.$B$BThank you again, $N.',
    `RequestItemsText` = 'Do you have the beasts head yet, $N? It will pay for its crimes. I don''t care if it''s corrupt or just angry for living in such a dismal forest. No furbolg will live for long committing such crimes against my family!'
WHERE `entry` = 6162;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I wonder... did it beg for mercy? Could it know what mercy is?$B$B<Nathanos spits.>$B$BI will hang this beast''s head upon my wall.$B$BYou have earned a spot amongst one of my champions, $N.$B$B<Nathanos salutes.>',
    `RequestItemsText` = 'After Sylvanas freed me, I hunted the beast across these wastes for months. It fled to the safety of Stratholme. The bastard...'
WHERE `entry` = 6163;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There it is!  And oh my!  I forgot how full it was!$B$BThis is a glorious day, $N!  Stupendous!  Insanely good, I say!',
    `RequestItemsText` = 'Do you have my receipt book?  I can''t wait to get back to business!'
WHERE `entry` = 6164;

UPDATE `quest_template` SET
    `OfferRewardText` = '',
    `RequestItemsText` = ''
WHERE `entry` = 6165;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have to get this note to Stormwind?  That''s not a problem, you can take one of my gryphons!',
    `RequestItemsText` = 'You look like you''re in a hurry.  Well, then you came to the right place!'
WHERE `entry` = 6181;

UPDATE `quest_template` SET
    `OfferRewardText` = 'After some reports of unusual Forsaken activity in the Eastern Plaguelands, SI:7 agents were dispatched to investigate. The results of that investigation are unsettling.',
    `RequestItemsText` = ''
WHERE `entry` = 6182;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Mathias nods.>$B$BI had faith that Bolvar would send me men and women of honor - the most dedicated soldiers of the Alliance.',
    `RequestItemsText` = ''
WHERE `entry` = 6183;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The first mission will be straight up, $N. You go in, you come out. Recon...',
    `RequestItemsText` = ''
WHERE `entry` = 6184;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Rutger. Fredo. Turyen. All... dead...$B$B<Flint clutches the insignias tightly.>$B$BWhere were they? Did you discover any more information about this bastard, the Blightcaller?',
    `RequestItemsText` = 'An... Any luck??'
WHERE `entry` = 6185;

UPDATE `quest_template` SET
    `OfferRewardText` = 'No. It... NO! How? An agent of the Forsaken? The CHAMPION of the Banshee Queen???$B$B<Highlord Bolvar Fordragon slumps in defeat.>',
    `RequestItemsText` = ''
WHERE `entry` = 6186;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is a tragedy. I think... I believe that our kind is cursed, $N. We are cursed to lose our greatest warriors; our most noble heroes; our most gifted scholars.$B$BWe are indebted to you and I assure you, $N, wherever Nathanos Marris is now, he smiles down upon you.',
    `RequestItemsText` = '<Highlord Bolvar Fordragon is lost in thought.>'
WHERE `entry` = 6187;

UPDATE `quest_template` SET
    `OfferRewardText` = '',
    `RequestItemsText` = ''
WHERE `entry` = 6221;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you for what you have done. Please continue to help us, $N. We have very few allies on which to call upon.',
    `RequestItemsText` = 'We very much appreciate what you have done for the Timbermaw, $N. Your continued efforts will surely earn my tribe''s trust and respect.'
WHERE `entry` = 6241;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A crate for Westfall, eh?  Have you been to Westfall before?  If so, then it''s no problem, my friend.  I have plenty of gryphons trained to fly that route!',
    `RequestItemsText` = 'Is that sweat on your brow, lad?  You''ve been running too much.  Next time, take a gryphon!'
WHERE `entry` = 6261;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, a note from Quartermaster Lewis?  I''m not surprised he needs more gear.  Sentinel Hill is far away, in a land Stormwind has all but forgotten.$B$BWell thank you, $N.  Here''s some money to cover your travel costs.',
    `RequestItemsText` = 'You''ve been traveling, eh?  Have you been anywhere interesting?'
WHERE `entry` = 6281;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is most excellent news! Tell me again how you cast fear into the cold hearts of those vile harpies. The Bloodfuries have been dealt a serious blow!',
    `RequestItemsText` = 'Do not be weary of Charred Vale; many evil creatures reside in those hills. Stay strong $N, and you shall prevail over this threat to our people. Go now and strike hard - our children shall never know of the evil of what was.'
WHERE `entry` = 6282;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Bloodfury Ripper is a nasty creature! You will have success finding her along the western hill line in the Charred Vale.$B$BThe bloodfuries will be helpless without their leader... surely we can vanquish them forever!',
    `RequestItemsText` = 'Already I feel the anger leave me. What will I do with my time? Knowing evil moves near my land kept my thoughts moving, though now they are silent. Perhaps this is a good thing... maybe now I can focus on the good, as all Tauren should.$B$BPlease accept this as a reward for your troubles.'
WHERE `entry` = 6283;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good hunting, $N! Besseleth is an old predator in these parts... I will miss her not. Take this reward as a token for being the forest champion.$B$B<Maggran rubs the wound caused by Besseleth.>$B$BPerhaps now many more will travel to Sun Rock Retreat without fearing what lurks in the dark.',
    `RequestItemsText` = 'Besseleth is a ruthless predator... I fear for those that travel Webwinder Path at night. It''s then that she and her children prey upon innocent travelers. I myself fell prey to her two-foot fang of death, but luckily I was able to fend her off and get to safety. I would give anything to see that monster destroyed.'
WHERE `entry` = 6284;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great, you brought the armor!  We''ll get this divvied to those who need it immediately.$B$BThank you, $N.  Your efforts have been a great help to us.  And now that you''re no stranger to gryphons, I hope you''ll come and lend your aid to Sentinel Hill often!',
    `RequestItemsText` = 'You''re back from Stormwind?  Did Osric send the armor?'
WHERE `entry` = 6285;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, $N, you have the Gaea seeds. Watch and see how the blessing of the Earthmother can cause even these small kernels of life to bloom and flourish.$B$B<Tammra begins to chant.>',
    `RequestItemsText` = 'The continuous destruction caused by war and those that seek a profit from lumber pains me deeply. To aid the cycle of rebirth and replenish the lands, I need Gaea seeds. Do you have them, $C?'
WHERE `entry` = 6301;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, an order for supplies.  You will want to take this to the Undercity, no doubt.  And quickly, for the Sepulcher must not be left under stocked.',
    `RequestItemsText` = 'You appear to be on official business...'
WHERE `entry` = 6321;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This crate must reach the Sepulcher in Silverpine?  That is easily done; our bats fly there daily.',
    `RequestItemsText` = 'If you must travel a long distance, then a bat is your best option.'
WHERE `entry` = 6322;

UPDATE `quest_template` SET
    `OfferRewardText` = 'An order from the Sepulcher?  Very well.  It is an honor to serve those who serve our Dark Lady.',
    `RequestItemsText` = 'I keep my weapons in top condition.  They are cleaned and ready for use.'
WHERE `entry` = 6323;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good work, $N.  These weapons will ensure our Deathguards don''t get caught unprepared.$B$BYou have done a valuable service for our Dark Lady.',
    `RequestItemsText` = '$N, you return.  Do you have our supplies from the Undercity?'
WHERE `entry` = 6324;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, you wish to get this to Auberdine? Very well...',
    `RequestItemsText` = 'How may I help you? Are you in need of transport?'
WHERE `entry` = 6341;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A package from Nessa? Thank you, $N! She told me she would send me samples of the fish caught near Rut''theran village. She thinks they may be very different from the fish caught here...$B$BMy! This jawbone is nearly twice the size of the same fish found here. And these scales are as big as a closed fist! Amazing!',
    `RequestItemsText` = 'Have you come from Teldrassil? Tell me, how is the fishing there?'
WHERE `entry` = 6342;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is very interesting. The fish here are large, but I didn''t think the difference in bounties between here and the mainland was so great. There must be a reason for this...$B$BWell thank you, $N. I will discuss with the villagers the news you brought. Perhaps, one day, we will find the root of this oddity. But until then, we shall reap its benefits!',
    `RequestItemsText` = '$N, you''re back from Auberdine? Did you speak with Laird?'
WHERE `entry` = 6343;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, I have need of a courier who will take a package to Darkshore. Will you help me?',
    `RequestItemsText` = ''
WHERE `entry` = 6344;

UPDATE `quest_template` SET
    `OfferRewardText` = 'If you must take these hides to Thunder Bluff, then you are speaking to the right orc!',
    `RequestItemsText` = 'Are you here for a wind rider? You have something to transport?'
WHERE `entry` = 6361;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, a new bundle of hides. I will get to work on these immediately!$B$BThank you, brother. You have done me a great service. Here are some coins to pay for your time and travel costs.',
    `RequestItemsText` = 'There is dust on your shoulders that must be from the Barrens. You have spoken with my friend Jahan?'
WHERE `entry` = 6362;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You need to take this to the Crossroads, eh? That''s not a problem. If you''ve already been there and spoken to Devrak, then you can take one of my wind riders back to him.',
    `RequestItemsText` = 'Greetings, $C. What can I do for you?'
WHERE `entry` = 6363;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahanu sent me finished products? Very good. There are many hunters and adventurers in the Crossroads now and business is lively. I am sure I''ll sell these goods very soon.$B$BThank you for all your efforts, $N. I am in your debt.',
    `RequestItemsText` = '$N, you are back from Thunder Bluff? Did you deliver the hides to Ahanu?'
WHERE `entry` = 6364;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have to get this meat to Orgrimmar? That is no problem. For a small fee, my wind rider can take you there.',
    `RequestItemsText` = 'You need to get somewhere fast? Then you''re talking to the right orc!'
WHERE `entry` = 6365;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is great victory for the land. In time, other things will come to pass: the Venture Co. will pack up their buzz saws and axes, the angry fire spirits will calm, and the harpies will be pushed out by the land.$B$BOnly then $N, will Stonetalon be truly at peace.$B$BYou have done well $C; take one of these items as thanks for the new life you have created here today.',
    `RequestItemsText` = 'These seeds you plant are strong, resisting corruption, and making a foothold for other life. They will grow and grow, first preventing corruption and healing the scarred land, and then one day, restoring Stonetalon to a lush forest, once again.$B$BHave you planted all of the Gaea seeds?'
WHERE `entry` = 6381;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Welcome to the new frontier, $N.  Ashenvale is a land of opportunity, one where a young $C like yourself is able to find boundless chances to prove their mettle.  Look around the outpost here, and be sure to travel out to the Zoram Strand, as the Horde has another outpost there as well.$B$BYour presence here tells me that you''ve come to learn more about the hunt.  Listen close, and I will gladly share with you what you need to know.',
    `RequestItemsText` = ''
WHERE `entry` = 6382;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There are three legendary creatures that make up the Ashenvale Hunt; you may seek them and test yourself against their cunning and might.  In the process, you will hopefully learn something about yourself.  The creatures are: the bear Ursangous, the nightsaber cat Shadumbra, and the hippogryph Sharptalon.$B$BThe creatures of the Ashenvale Hunt are powerful, and you may find that you''ll need aid in bringing them down.  If you should best them, bring me proof of your deed.',
    `RequestItemsText` = ''
WHERE `entry` = 6383;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, wonderful! Those are fine cuts! These are from Zargh, are they? That orc sure knows his way into a lady''s heart...$B$BOh, I can''t wait to cook it. But not too much! Meat is best served rare, don''t you think?',
    `RequestItemsText` = 'Something smells good! You don''t have raw meat on you, do you?'
WHERE `entry` = 6384;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have to get this to the Crossroads in the Barrens? Yes, I can get you there...',
    `RequestItemsText` = 'Do you need one of my wind riders?'
WHERE `entry` = 6385;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hah! I guess she liked it! Nothing brings red to a lady''s cheeks like a big, juicy steak!$B$BThank you, $N. You''ve done me a great service. Here is some money for your trouble, and don''t be surprised if I invite you to my wedding!',
    `RequestItemsText` = 'Have you returned from Orgrimmar? Did Gryshka like the meat I sent her?'
WHERE `entry` = 6386;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have to get this to Ironforge, eh? For a small fee I can put you on the back of one of my gryphons, and it''ll take you there. How does that sound?',
    `RequestItemsText` = 'Have you had your fill of Thelsamar so soon? Are you ready to leave for another city?'
WHERE `entry` = 6387;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have to get these to Thelsamar, eh? That won''t be a problem. As long as you''ve already been to Thelsamar and spoken to Thorgrum Borrelson, then you can take one of my gryphons back to him.',
    `RequestItemsText` = 'You look like you have somewhere to go. Need one of my gryphons?'
WHERE `entry` = 6388;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Haha! Thank you, $N! You''ve done it! My father''s spirit can now rest and I can live in peace.$B$BThank you again. If there is anything I can do for you, please, just ask.',
    `RequestItemsText` = 'Have you done it, $N? Have you released the termites? The Light help us if the Scarlet Crusade were able to hold onto both the mill and Hearthglen. They should have neither. They''re just capitalizing on the victims of the last war and should be put down like rabid animals!'
WHERE `entry` = 6389;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. Here, take this coin. I''m sorry it''s not more, but try to take some joy in helping destroy the Scarlet Crusade''s efforts!',
    `RequestItemsText` = 'Have you done it, $N? Have you released the termites in the lumber mill?$B$BIt was bad enough that my family lost their jobs and lives, but then to see the place where my childhood was spent taken over by those disgusting so-called holy men... pfah!!'
WHERE `entry` = 6390;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, the lastest list of Brock''s best pupils. I have a batch of honorary picks ready to go. I just need to chisel in the names of the students...',
    `RequestItemsText` = 'What can I do for you, sir?'
WHERE `entry` = 6391;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You brought the picks. Great! I''ll get these to my mining students. I''m sure they''re eager to use them on the ore deposits of Loch Modan.$B$BThank you for your help, $N. I am in your debt, but I hope this money will at least cover your travel costs.',
    `RequestItemsText` = 'Ah, $N. Have you returned from Ironforge?'
WHERE `entry` = 6392;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The water spirits within me bubble with the excitement. $N, you have given me a glorious victory to report to the Tribunal of the Tides.',
    `RequestItemsText` = 'The Tribunal of the Tides grows impatient. They seek to end this war that has raged across all dimensions for eons. My brethren are anxious to hear news of the glorious victory over the hated fire elementals. Have you the Incendrites that I require?'
WHERE `entry` = 6393;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great, you got it! Thanks a lot, $N. This is my favorite pick! Now if my peons ever finish chopping down these trees, maybe we can find a nice cave to mine!',
    `RequestItemsText` = 'Have you entered the Burning Blade Coven, $N? Did you find my pick?'
WHERE `entry` = 6394;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done a good deed today, $N.  Although our struggle against the Scourge continues, let us hope that Marla and Samuel will find peace together in their final resting place.',
    `RequestItemsText` = 'We must respect our dead, $N. It is one of the ways in which we differ from the Scourge...'
WHERE `entry` = 6395;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My goodness, my niece Kaya is alive! That is good news indeed. Thank you, $N.',
    `RequestItemsText` = ''
WHERE `entry` = 6401;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Before we begin, I ask that you first gather an army. We face a dragon, after all!',
    `RequestItemsText` = ''
WHERE `entry` = 6402;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Bolvar holds the shattered medallion.>$B$BThe magic held within must be reignited. The dragon''s eye must be attuned.$B$BWindsor''s sacrifice has freed our Kingdom, but the threat of Onyxia and her kin is ever looming.$B$BThis medallion is what held my mind and body captive. It is also what gave me access to Onyxia''s own mind - to her secrets. Albeit the visions are muddled now, some things I do remember.',
    `RequestItemsText` = 'I... I... I was powerless.'
WHERE `entry` = 6403;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah... Yes! That''s it; the Resonite crystals have a trace of Earthen magic. The kobolds must have dug deep uncovering an Earthen.$B$BLegend states that the Earthen are creatures created by the Titans.  They were used to create the land our feet walk on. This most definitely is a threat that cannot be ignored.$B$B<Mor''rogal shakes his head.>$B$BPerhaps I can enchant these ore samples to use against this kobold plot.',
    `RequestItemsText` = 'What news have you discovered from Boulderslide Ravine? I recall some legend that deals with Resonite... I just cannot place my hoof on it. Perhaps knowing what lies at the bottom of the cave will illuminate their devious intentions.'
WHERE `entry` = 6421;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These are perfect, $N! Thanks for helping me out!$B$BOh, and this is for your time...',
    `RequestItemsText` = 'I hope you can be quick about getting those horns, $N. I''m heading back to Ratchet soon!'
WHERE `entry` = 6441;

UPDATE `quest_template` SET
    `OfferRewardText` = 'We could use more of your kind around here, $N. Thank you for your help.',
    `RequestItemsText` = 'The naga increase in numbers, $N. Please complete this task for me.'
WHERE `entry` = 6442;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Sweet, mon! Good news, perhaps we will have fewer unwanted dinner guests tonight.$B$BMany thanks, $N.  We are forever in your debt.',
    `RequestItemsText` = 'Hey mon, have you slain the hairy blood feeders? I fear none here in Stonetalon but I don''t go walking around here at night... if you know what I mean mon!$B$BAs long as I stay off their dinner plate then all is well.$B$BGood luck to you, $C!'
WHERE `entry` = 6461;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found them!  Thank you!  Thank you, $N!  You do not know how great a thing you have done for me.$B$BA troll without his charm is like an orc without his battle scars...$B$BWorthless.',
    `RequestItemsText` = 'Did you find the charms, $N?  Every moment the furbolgs possess those sacred items, my blood boils with rage!'
WHERE `entry` = 6462;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You bear good news, $C! I fear the possibilities of what an Earthen would mean to Kalimdor.$B$BSlaying Goggeroc was a task for no one less then a hero. You have done well; all of Stonetalon and Kalimdor are indebted to you, noble $C.$B$BAccept this as your reward most honored one.',
    `RequestItemsText` = 'I fear if we do not dispose of this threat immediately, all of Stonetalon will be lost. The might of an Earthen can not be matched by any means. When awakened, Goggeroc will be weak from his long slumber, this will be the opportunity that you must take advantage of... go now $N!'
WHERE `entry` = 6481;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found my brother!  He was captured by the Thistlefurs?  That is terrible news to hear, for although many Furbolgs are noble creatures, the Thistlefurs are corrupt.$B$BThank you for rescuing my brother, $N.  I do not want to think of how they treated poor Ruul.  He will likely sleep long after this ordeal...',
    `RequestItemsText` = 'Have you seen my brother Ruul? He walked into the forest days ago and has not returned...'
WHERE `entry` = 6482;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I should have known - a piece of the black dragon brood mother, Onyxia. How revolting...',
    `RequestItemsText` = 'I sense an aura of evil radiating from you, $R. What could you hold that emits such an aura?'
WHERE `entry` = 6501;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This amulet will grant you the access that you seek. The lair of Onyxia can be found in Dustwallow Marsh. As long as you hold the amulet, her wards cannot prevent you from entering.$B$BThe Blue Flight wishes you luck, $N.',
    `RequestItemsText` = 'The flow of time does not stop or slow, $R. While my life is eternal, yours is not. Waste not the time that you have...'
WHERE `entry` = 6502;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good, $N.  Your hunting skills are impressive...$B$BThe loss of those outrunners helps blind the Alliance, and when they lack intelligence they are less likely to launch attacks.',
    `RequestItemsText` = 'I await reports of your outrunner kills, $N.'
WHERE `entry` = 6503;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Reading isn''t my strong point... but now I''ll be able to get back to work! Thanks, $N!',
    `RequestItemsText` = 'I hope you find the pages soon, $N! I really need to get back to work!'
WHERE `entry` = 6504;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good. Well done, $C.$B$BNow that Malcin is dead, we can at least know that the Scourge''s advances will be halted. The Dark Lady thanks you for your efforts and wishes to reward you with a gift.$B$BAlthough we do not know the extent of the Scourge''s influence within the Downs, I am sure we will discover their plots soon enough.',
    `RequestItemsText` = 'Have you found the Ambassador, $N? Is he dead?$B$BWe cannot afford to allow the Scourge to take a foothold on Kalimdor. They are enough of a threat to our own borders to have to deal with them on two fronts.$B$BThe only optimistic sign from the events you''ve told me about is that the crone seemed uncorrupted. She must know deep in her spirit that the Scourge may bring great power, but that the Barrens would not truly be hers if she were to agree to their deal.'
WHERE `entry` = 6521;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I recognize the insignia on this scroll, $N. You found this on that crone who reigns over Razorfen Kraul? Interesting.$B$BThe Scourge aren''t content with one continent it seems. This Ambassador Malcin--the one who wrote the note--is one of the Scourge''s plagued servants, a human diplomat to the kingdom of Lordaeron before things... changed.$B$BIf the Scourge are trying to gain a foothold in Kalimdor, then it is up to us to act.',
    `RequestItemsText` = 'What business is it you wish to speak of, $N? You must feel it is important if you continue to pester me.'
WHERE `entry` = 6522;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Kaya is alive! $N, I have you to thank for rescuing her.',
    `RequestItemsText` = ''
WHERE `entry` = 6523;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ashenvale is a divided land, but our most recent efforts have been very successful. We not only have an outpost at the Zoram Strand, but another just north of here called Splintertree.',
    `RequestItemsText` = ''
WHERE `entry` = 6541;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ashenvale is a divided land, but our most recent efforts have been very successful. We not only have an outpost at the Zoram Strand, but another just north of here called Splintertree.',
    `RequestItemsText` = ''
WHERE `entry` = 6542;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I can see that you are one that can be counted on. These updates are crucial to our plans to further our presence in Ashenvale. We can now plan our next move.',
    `RequestItemsText` = 'Hurry, $N. They must receive their reports; it is urgent.'
WHERE `entry` = 6543;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So Torek''s attack was successful!  Well done, $N.  Night elves are decent foes.  A little skinny, but strong and fierce!  I''m sure the battle was something to see...$B$BAnd I hope you gained a scar or two!',
    `RequestItemsText` = 'Torek was sent on a mission against Silverwing Outpost. Was the attack successful?'
WHERE `entry` = 6544;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, my update will explain all of this to Kadrak. You must return this to him as quickly as possible.',
    `RequestItemsText` = 'So you''re here with my orders? Always good to see a new recruit with an exuberant nature and a strong will.$B$BYou''d best learn fast if you expect to keep up here. The threat of the naga grows, $N. I have observed and have taken up defenses against several attacks on this outpost since I arrived here.$B$BBut if you''d like to pitch in with that effort, speak with one of the others here at the outpost.'
WHERE `entry` = 6545;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Take my update to Kadrak. Swiftly, $N.',
    `RequestItemsText` = 'Much danger lies along this path, $N. You''d do best to remember this while traveling in these lands. The threat of the alliance is quite near.$B$BWe are faced by enemies on all fronts. The satyr are a formidable and prevalent force in eastern Ashenvale. I have also discovered that the naga have taken over a large area of the land of Azshara.$B$BIt''s good to see that we are still bolstering our numbers -- be ready for what lies ahead, $N.'
WHERE `entry` = 6546;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Let Kadrak know of the success we have had here holding off the night elves. Our plans are going well.',
    `RequestItemsText` = 'Keep an eye out, $R. The elves are often hiding in the shadows...$B$BWe must always be watching. We have worked very hard to claim this land, and the elves are looking for a chance to take it from us.$B$BI assume you have my next orders from Kadrak?'
WHERE `entry` = 6547;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N, I thank you... but I will never forget what the Grimtotem have done to my village.',
    `RequestItemsText` = 'Have you killed them yet?'
WHERE `entry` = 6548;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Kelris has eluded the Argent Dawn for some time.$B$BFor some time they considered him dead or missing.$B$BBy ending his reign you have spared the lives of many innocent people, $N.$B$BEarthmother be praised! To sacrifice another to a servant of an Old God for personal gain is beyond disgusting!$B$BYou have done a great thing this day. Kelris was a creature of evil and sought to bring the world back to a time of chaos by worshipping such creatures as the Old Gods. Thank you, $N.',
    `RequestItemsText` = 'May the Earthmother be with you, $N.$B$BPeace between the earth and all her people should be our goal. She has a grand plan for nature, and we all have a role to play in that plan.'
WHERE `entry` = 6561;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Tsunaman sent you? Excellent. Then we have matters to discuss.',
    `RequestItemsText` = ''
WHERE `entry` = 6562;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N. These are the crystals I spoke of. Intriguings...$B$BI can feel the power within them. The spirits of water cling to them. Whatever the naga were going to use these for... well, let us be glad they are no longer in their hands.',
    `RequestItemsText` = 'How goes your search for the crystals, $N? Have you witnessed the naga harvesting them? I pray to my ancestors we find the reason they are collecting such things.'
WHERE `entry` = 6563;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is interesting indeed. I am glad you have brought it to my attention.$B$BNow we have a name for our troubles... Lorgus Jett.',
    `RequestItemsText` = 'Yes, $N? What is it you need? There is still much I must learn about the crystals the naga are gathering.'
WHERE `entry` = 6564;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good!! Thank you, $N. We may not have stopped the Twilight''s Hammer completely, but at least you have staved off another of their plans to return the Old Gods to power.$B$BWho knows what other plans they have manifesting, but we can rest easy for now.',
    `RequestItemsText` = 'Have you found him yet, $N? Lorgus must be stopped!'
WHERE `entry` = 6565;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Are you prepared to take on this task?',
    `RequestItemsText` = 'Patience, $N. Pay attention!'
WHERE `entry` = 6566;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There is but one way into the dragon''s lair, $R.$B$BYou see, only the strongest of the Black Dragonflight are allowed entry into the lair of the brood mother. Many trials must be passed and the key to enter ceremoniously enchanted by General Drakkisath himself!$B$BSince you are not of black dragonkin, you may have some difficulty in obtaining passage.$B$B<Rexxar grins.>',
    `RequestItemsText` = ''
WHERE `entry` = 6567;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Myranda holds the note, pauses, then smiles.>$B$BHow is he? Rexxar, I mean. Oh, come now, do not look so confused. The letter was left intentionally blank. It carried with it the intentions and thoughts of its creator. Judging from its contents, it is no wonder Rexxar left it as such. Imagine if you were captured or slain and this information discovered!$B$BOh, nevermind! Myranda will help you, $R. I owe the Warchief a favor or two.$B$B<Myranda smiles.>',
    `RequestItemsText` = 'It is not often I see one of the Horde in these parts of Lordaeron. What is it that you have for Myranda?'
WHERE `entry` = 6568;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Let Myranda have a look, $R.$B$BOh yes, these will do nicely.$B$BWith these reagents, Myranda will create for you a medallion that will grant an illusion capable of fooling the black dragonflight''s gatekeeper.',
    `RequestItemsText` = 'The eyes of that which we wish to mimic are the most important ingredient of any illusion, $N.$B$B<Myranda points to a bag almost overflowing with eyeballs labeled ''Scarlet Crusade.''>$B$B<Myranda laughs.>'
WHERE `entry` = 6569;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Have we run so low on able soldiers that Nefarian is sending me whelps? You will never pass my tests, broodling.',
    `RequestItemsText` = ''
WHERE `entry` = 6570;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent, $N. You''ve saved me a lot of work!$B$BBut don''t think that I''m not grateful!',
    `RequestItemsText` = 'I hope you can come through with the supplies! I''m in big trouble if I don''t deliver them soon!'
WHERE `entry` = 6571;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is perfect -- just the thing! Well, here''s the shipment.',
    `RequestItemsText` = 'Direct from Ratchet, the Warsong saw blades! Yep, I have them right here.$B$B..But what sort of payment do you have for me? You can''t just take them, you know! My time isn''t cheap!$B$BWhat I really need is a good gun to carry with me on my travels. A girl''s gotta protect herself, you know? There''s a gun I really like that I''m sure an engineer would have no problem making.$B$BSo, if you bring me a deadly blunderbuss, I''ll give you the saw blade shipment. Do we have a deal?'
WHERE `entry` = 6581;

UPDATE `quest_template` SET
    `OfferRewardText` = 'One of ssseveral complete...',
    `RequestItemsText` = '<Emberstrife hisses.>'
WHERE `entry` = 6582;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Another complete...',
    `RequestItemsText` = 'Do not return here until you have bathed in the blood of our enemies and drank in their suffering.'
WHERE `entry` = 6583;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The most hated remainsss...',
    `RequestItemsText` = 'Ironically, whelp, time is of the essencccce.'
WHERE `entry` = 6584;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I had doubted your dedication, whelp. You persisted, dominating our enemies, bringing honor to our flight.$B$BI must now prepare the skulls for your ascension.',
    `RequestItemsText` = 'Changesss... I sense them taking place in you, whelp. Pass this test and only ceremony remains.'
WHERE `entry` = 6585;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is merely dragon-talk, $N - more hot air than actual substantive information. Pompous, aggressive behavior is to be expected from their kind.',
    `RequestItemsText` = 'Do not panic, $N!'
WHERE `entry` = 6601;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A victory that will be remembered for many years, $N. The Drakefire Amulet will open Onyxia''s lair. Gather your allies and bring victory to the Horde.',
    `RequestItemsText` = 'I don''t think I need to tell you that Drakkisath is not to be taken lightly.$B$BI let the thousands dead by his hand do the talking.'
WHERE `entry` = 6602;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, hi there! So Meggi told you of the trouble I have found here?',
    `RequestItemsText` = ''
WHERE `entry` = 6603;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Aye, what can I do for you?',
    `RequestItemsText` = ''
WHERE `entry` = 6604;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, $C. I see that there is hope yet. Are you here to assist me?',
    `RequestItemsText` = ''
WHERE `entry` = 6605;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, so Harlo be sendin'' you? Well, den, who might you be? I s''pose you be wantin'' my help?',
    `RequestItemsText` = ''
WHERE `entry` = 6606;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now that''s a fine catch!$B$BCome over here, lemme show you how to set a few lines.',
    `RequestItemsText` = 'Anything bitin'' today?'
WHERE `entry` = 6607;

UPDATE `quest_template` SET
    `OfferRewardText` = '''Course, you must be a friend of Lumak''s.$B$BFishin''? I can tell you all ''bout fishin''.',
    `RequestItemsText` = ''
WHERE `entry` = 6608;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I''ve always got room on my island for visitors... I reckon...',
    `RequestItemsText` = ''
WHERE `entry` = 6609;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You are in for a special treat, $N. Watch and learn!$B$B<Dirge begins to prepare clamlette surprise.>',
    `RequestItemsText` = 'My cravings are going to be the end of me! Hurry, $N - before I dip into my own supply.'
WHERE `entry` = 6610;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Dirge spits out some leather sandal bits.>$B$BPfftooey...$B$B<Dirge hacks loudly.>$B$BWhat? I''ll have you know that leather is surprisingly high in protein and low in carbohydrates.',
    `RequestItemsText` = ''
WHERE `entry` = 6611;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Dirge spits out leather.>$B$BPfftey...$B$B<Dirge hacks loudly.>$B$BWhat? I''ll have you know that leather is surprisingly high in protein and low in carbohydrates, $R.',
    `RequestItemsText` = ''
WHERE `entry` = 6612;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good work, $N. Issuing that challenge to the Foulwealds and defeating their leader sends them a strong message:$B$BThe Horde is not to be trifled with.$B$BI don''t believe that tribe will giving us much trouble for a long time.',
    `RequestItemsText` = 'Did you defeat Chief Murgut, $N? Did you retrieve his Foulweald Totem?'
WHERE `entry` = 6621;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Doctor $N, welcome to Horde Trauma.',
    `RequestItemsText` = 'Miraculous work, doctor. Simply miraculous.'
WHERE `entry` = 6622;

