UPDATE `quest_template` SET
    `OfferRewardText` = 'Doctor $N, welcome to Alliance Trauma.',
    `RequestItemsText` = 'Miraculous work, doctor. Simply miraculous.'
WHERE `entry` = 6624;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wonderful. Put on your scrubs, we are to start at once!',
    `RequestItemsText` = ''
WHERE `entry` = 6625;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N! The work you''ve done will be a great help, I''m sure.$B$BI will continue my study of this diplomat and the rest of the quilboar here. If you seek greater adventure, I''d find a few friends and head into the cave that looks like a great boar maw just over there. I''m sure once you''re inside you''ll find greater challenges to face.',
    `RequestItemsText` = 'How goes the hunt, $N? Seeing just this small sample of this diplomat''s power here removes any doubt I had that the Scourge are one of the greatest threats this world has ever seen.'
WHERE `entry` = 6626;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $C. You have studied the text I asked you to, and now you have passed another of our tests.',
    `RequestItemsText` = 'Life is full of questions, $C. You will never be able to answer all of them, but with some time and study, perhaps you will become a little more knowledgeable.'
WHERE `entry` = 6627;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N. I had my doubts if you studied the text I asked you to get, but you''ve answered correctly.',
    `RequestItemsText` = 'There is only one rule I feel you must know if you wish to survive in this world: the more you know, the more you''ll see.$B$BIf you study, if you observe, then you will begin to see things in the world that no other $R will see.'
WHERE `entry` = 6628;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Grundig Darkcloud is dead! $N, I will always be grateful for what you''ve done here today.',
    `RequestItemsText` = 'Have you killed Grundig Darkcloud and his personal band of Brutes?'
WHERE `entry` = 6629;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I have witnessed many naga attacks since I arrived here. It puts my mind at ease that Vorsha will no longer roam freely.$B$BWe are in your debt, $N.',
    `RequestItemsText` = ''
WHERE `entry` = 6641;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your offering has been accepted. Favor you have gained. Continue and you shall be allowed access to the ancient trades.',
    `RequestItemsText` = 'Dark Iron, while plentiful in the Depths, is still a valued commodity amongst the Brotherhood. The sacred arms and armaments of Ragnaros favor Dark Iron.$B$BFor every 10 pieces of Dark Iron Ore you offer, favor amongst the Brotherhood you will gain.'
WHERE `entry` = 6642;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your offering has been accepted. Favor you have gained. Continue and you shall be allowed access to the ancient trades.',
    `RequestItemsText` = 'Woe unto those that tempt fate inside the Molten Core. Death comes swiftly - the punishment dealt without mercy.$B$BMany of the Brotherhood have been lost in their search for Fiery Cores.$B$BOffer 1 Fiery Core and you shall be granted favor amongst the Brotherhood.'
WHERE `entry` = 6643;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your offering has been accepted. Favor you have gained. Continue and you shall be allowed access to the ancient trades.',
    `RequestItemsText` = 'The Thorium Brotherhood sympathizes with your plight, $R. This is why Lokthos has been empowered to bargain.$B$BOffer 1 Lava Core and you shall be granted favor amongst the Brotherhood.'
WHERE `entry` = 6644;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your offering has been accepted. Favor you have gained. Continue and you shall be allowed access to the ancient trades.',
    `RequestItemsText` = 'Many of the sacred recipes require the skin from Ragnaros'' chosen pets.$B$BOffer 2 Core Leather, skinned from the smoldering corpses of the Core Hounds of the Molten Core and you shall be granted favor amongst the Brotherhood.'
WHERE `entry` = 6645;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your offering has been accepted. Favor you have gained. Continue and you shall be allowed access to the ancient trades.',
    `RequestItemsText` = 'The tears of the Fire Lord are a rare find indeed.$B$BOffer 1 Blood of the Mountain and you shall be granted favor amongst the Brotherhood.'
WHERE `entry` = 6646;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These''ll werk nicely, matey. Me brother needs em still tickin'' and kickin,'' else they go sour... Ye don''t want to taste no sour rat kabob.',
    `RequestItemsText` = 'Yarrr... Swabby, what be takin'' ye so long?'
WHERE `entry` = 6661;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Poor Monty. Ever since the Gnomeregan incident, he hasn''t been the same. That boy has never seen an ocean in his life, let alone being some kind of pirate.$B$B<Nipsy sighs.>$B$BAt least he keeps the flow of twitching critters coming.',
    `RequestItemsText` = 'Alive and kicking... and just in time!'
WHERE `entry` = 6662;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Most excellent, young thief.$B$BYou look a bit beaten down, but no worse for the wear.$B$BA long journey awaits you - long and rewarding. Are you prepared to finally embrace your destiny among the masters of Ravenholdt?$B$BSpeak with the guards outside. They will get you started.',
    `RequestItemsText` = 'Did you meet Milton?<Fahrad laughs.>'
WHERE `entry` = 6681;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hey, nice work! Keep this up and the other rogues might stop spitting on you.',
    `RequestItemsText` = 'We have been entrenched in a battle with the Syndicate for years. What they lack in skill they make up for in numbers. It''s impossible to kill them off fast enough to have any noticeable impact on their population!$B$BWe''ve found that the best way to deal with their size is to pilfer their emblems. Once an emblem is stolen the shamed member is ''dealt'' with internally.$B$BPick their pockets clean and turn the emblems in to me or one of the other guards.$B$BStart at Durnholde, south of here.'
WHERE `entry` = 6701;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, it is time, $C.',
    `RequestItemsText` = ''
WHERE `entry` = 6721;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, it is time to train you...',
    `RequestItemsText` = ''
WHERE `entry` = 6722;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thanks again, $N. You do the Horde proud...',
    `RequestItemsText` = 'I need more armor scraps, $N! Do you have any?'
WHERE `entry` = 6741;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes $C, thank you for coming.  I apologize about the misunderstanding... the air is thick with mistrust between the Arch Druid here and Keeper Remulos in Moonglade.  Each suspect the other of chicanery, and the fact that strange corruptions of Teldrassil continue unabated are still an issue here.  It does little to quell mistrust.$B$BRegardless, our duty to the Cenarion Circle remains... even if those who lead it may disagree with one another.',
    `RequestItemsText` = ''
WHERE `entry` = 6761;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I am Rabine Saturna, and on behalf of Keeper Remulos and all of the denizens of this sacred glade I bid you welcome.$B$BI appreciate your interest and eagerness to assist the Cenarion Circle.  I also know that Arch Druid of Darnassus expressed his displeasure to you in your lending us aid.  Rest assured that it is for the greater good, and that you will be safe from any ill-conceived repercussions you may be the target of.$B$BYou are among friends here, $N.',
    `RequestItemsText` = ''
WHERE `entry` = 6762;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These are some good pieces, $N. I can use them to fashion new equipment for our troops.$B$BIf my supply level gets high enough, then maybe our seasoned fighting units will enter the field!',
    `RequestItemsText` = '$N, we need more armor scraps to supply our troops!'
WHERE `entry` = 6781;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The blood of our enemies has been shed. I shall mix this blood with the rest that has been gathered. Once the offering is complete, the Ice Lord shall show these Stormpike dogs the full wrath of the Frostwolf Clan!',
    `RequestItemsText` = 'I come from Thunder Bluff, $R. Cairne himself has seen to it that I assist the Frostwolf Clan in these dire times.$B$BBut let us not waste any more time. You must strike down our enemies and bring to me their blood. Once enough blood has been gathered, the ritual of summoning may begin.$B$BVictory will be assured when the elemental lord is loosed upon the Stormpike army.'
WHERE `entry` = 6801;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, $C. The corrupted elementals you cured were an outrage to all bodies of water. Our strength lies in our purity and if we are to win our war with the others, we must remain strong.',
    `RequestItemsText` = 'Do you have the bracers?'
WHERE `entry` = 6804;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your bravery is proven, as is your worth to us.  Perhaps I may have future tasks for you, tasks more befitting a valued ally of the Waterlords.',
    `RequestItemsText` = 'Cowardice is not a thing we hold in regard, $C.  Go to Silithus and prove your bravery.'
WHERE `entry` = 6805;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, so you do have the strength.  And you have the cunning as well, for Blackrock Spire is more than a match for brute strength alone.$B$BIndeed $N, you may yet prove a valued ally to us...',
    `RequestItemsText` = 'Do you have the Eye, $C?  Do you have the strength to enter Blackrock Spire?'
WHERE `entry` = 6821;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done what most of your kind would think impossible.  You have faced the beings of the Molten Core, and triumphed!$B$BFor so small a creature, you have displayed great resource.$B$BSome day, perhaps we might strike a true allegiance between your kind and the Waterlords.',
    `RequestItemsText` = 'Your success in the Molten Core awaits, $N.'
WHERE `entry` = 6822;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your exploits against our enemies ring through the chambers of the Waterlords, $N.  It was thought by some that your form is too small and fragile to fight in our war, but you have made great gains.  You have earned respect among us, an unbelievable feat.',
    `RequestItemsText` = 'Your campaign is not yet done, $N.  Go out and defeat our enemies, the servants of air and earth and fire, and one day perhaps you will earn a place in the hall of the Waterlords.'
WHERE `entry` = 6823;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have the hands!  You defeated the fire captains!  I would not have thought it possible, had I not known you and what you are capable of.$B$B$N, your exploits are without number, but word of this last feat will send waves among the Waterlords.  Your name may one day be legend to us.$B$BSpeak with me again, $N.  I may have yet another task...',
    `RequestItemsText` = 'Have you defeated Lucifron and the others, $N?  Do you have the hands of the enemy?'
WHERE `entry` = 6824;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The fleet feeds on their flesh. It consumes the enemy.$B$BFlight is imminent!',
    `RequestItemsText` = 'We must prepare the new fleet of War Riders, $R! My riders are set to make a strike on the central battlefield; but first, I must wet their appetites - preparing them for the assault.$B$BI need enough Stormpike Soldier Flesh to feed a fleet! Hundreds of pounds! Surely you can handle that, yes? Get going!'
WHERE `entry` = 6825;

UPDATE `quest_template` SET
    `OfferRewardText` = 'More! More! Bring more for they are soon to be ready!',
    `RequestItemsText` = 'You''ve worked hard, $N, but we have only just begun!$B$BMy War Riders must taste in the flesh of their targets. This will ensure a surgical strike against our enemies!$B$BMy fleet is the second most powerful in our air command. Thusly, they will strike at the more powerful of our adversaries. For this, then, they need the flesh of the Stormpike Lieutenants.$B$BMake haste, soldier!'
WHERE `entry` = 6826;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Not enough! I would expect this level of work from an initiate, but you, $N? Come on, soldier! HUSTLE! More flesh is needed!',
    `RequestItemsText` = 'I was locked up in a dwarven hellhole for days. You better believe I want revenge!$B$BWe must plan carefully.$B$BFirst, my war riders need targets to gun for - high priority targets. I''m going to need to feed them the flesh of Stormpike Commanders. Unfortunately, those little buggers are entrenched deep behind enemy lines! You''ve definitely got your work cut out for you.'
WHERE `entry` = 6827;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well great monkey toads! What have you got here? It''s sort of book shaped, I guess... I''ll try crack this shell on it.$B$BLayo sent you to me from Silithus? I''ve only heard very hushed rumblings - which I guess aren''t all that hushed when you think about it - about the horrors that are going on out there. Couple that with my lack of pleasure for anything bug-like, and you''ve got the recipe for me needing to stay here with the books!',
    `RequestItemsText` = 'Why, hello there! Hrmm...$B$BLet me be a little honest with you, friend... you smell a bit ripe. Whiffy, one might say. Now I''m not making a personal assailment of your being. I''m just saying... in the future, you may want to freshen up a little after coming in from the field. It will make those first impressions a little more positively impressionable!$B$BAnyhoo... what can I do for you?'
WHERE `entry` = 6844;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, $N - I had hoped you would stop by. I am glad to see you well.$B$BI received notice you would be coming in from the field, and I wanted to personally express the Cenarion Circle''s gratitude for the assistance you''ve given us thus far. No doubt there are more secrets to uncover from Silithus; your delivery to Umber should prove most interesting once uncovered. Please, accept this as a token of our continued appreciation for your aid.$B$BThank you, generous $C.',
    `RequestItemsText` = ''
WHERE `entry` = 6845;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, the orders! They say I''m to assault at will, and my will says... now!',
    `RequestItemsText` = 'My troops are supplied and ready to assault.  We just need orders from Noreg Stormpike and I''ll send them into the fray!'
WHERE `entry` = 6846;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Master Ryson examines the Eye.>$B$BNow you shall be witness to the awesome power of the All Seeing Eye!',
    `RequestItemsText` = 'The Eye, fool. Do you have the Eye?'
WHERE `entry` = 6847;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Master Ryson examines the Eye.>$B$BNow you shall be witness to the awesome power of the All Seeing Eye!',
    `RequestItemsText` = 'The Eye, fool. Do you have the Eye?'
WHERE `entry` = 6848;

UPDATE `quest_template` SET
    `OfferRewardText` = '',
    `RequestItemsText` = 'I''m as anxious as you are to try out my portable shredder unit, $R, but before I can make the kit, I''m going to need materials - lots of materials!$B$BTo be exact, I''m going to need a mountain of thorium, mithril, and iron. I will also need one steamsaw per unit. You''ll have to get those at the lumber mill.$B$BWhen I was nosing around in here (before my capture) I noticed a pile of steamsaws at the Stormpike lumber camp.$B$BMaster Engineer Zinfizzlex wants you to bring him the following:'
WHERE `entry` = 6861;

UPDATE `quest_template` SET
    `OfferRewardText` = '',
    `RequestItemsText` = 'I''m as anxious as you are to try out my portable shredder unit, $R, but before I can make the kit, I''m going to need materials - lots of materials!$B$BTo be exact, I''m going to need a mountain of thorium, mithril, and iron. I will also need one steamsaw per unit. You''ll have to get those at the lumber mill.$B$BWhen I was nosing around in here (before my capture) I noticed a pile of steamsaws at the Stormpike lumber camp.$B$BMaster Engineer Zinfizzlex wants you to bring him the following:'
WHERE `entry` = 6862;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N. I will use the power of this charm to augment the magic that has already been gathered. When enough power has been amassed, I shall focus the collected energies and call upon the Forest Lord to aid our cause.',
    `RequestItemsText` = 'The Frostwolf Clan is protected by a taint of elemental energy. Their shaman meddle in powers that will surely destroy us all if left unchecked.$B$BThe damage has grown too great for the Circle to control! Ivus must be called to our aid.$B$BThe Frostwolf soldiers carry elemental charms called storm crystals. We can use the charms to conjure Ivus. Venture forth and claim the crystals, $N!'
WHERE `entry` = 6881;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It''s about time! Now we can show the Alliance their folly in coming to Alterac Valley!',
    `RequestItemsText` = 'My troops are supplied and ready to assault.  We just need orders from Frostwolf Quartermaster and I''ll send them into the fray!'
WHERE `entry` = 6901;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is exactly what I need! A fathom core is an incredible well of information that we will be able to draw much good from. Whatever the Twilight''s Hammer is up to in there - and believe me when I say it is no good - my comrades and I will now uncover.$B$BYou''ve done well here today; the Earthen Ring looks upon you warmly for assisting us. You''ve also helped the Horde as a whole, and for that you should be proud.',
    `RequestItemsText` = 'Have you been successful in locating the fathom core?  Without it we''ll have no idea what the Twilight''s Hammer is exactly up to down there.'
WHERE `entry` = 6921;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This... this is quite the find, $N.$B$BYou acquired this from Baron Aquanis in Blackfathom, you say?  Baron Aquanis has long been thought of as a corrupted elemental power; this globe will prove what exactly had corrupted him.  While it would be no surprise if it turned out to be the Twilight''s Hammer, our studies will also show how they did it as well.$B$BYou did well in bringing this to me.  Please - take this, along with the Earthen Ring''s warmest regards.',
    `RequestItemsText` = 'Ah, hello again $N.  I was just reading the waves the sea, much like I always do.  What brings you to the outpost?'
WHERE `entry` = 6922;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The flight will be ready soon. Continue your efforts!',
    `RequestItemsText` = 'The elite Frostwolf units that guard the lines must be dealt with, soldier! I''m tasking you with thinning out that herd of savages. Return to me with medals from their lieutenants and legionnaires. When I feel that enough of the riff-raff has been dealt with, I''ll deploy the air strike.'
WHERE `entry` = 6941;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Keep em coming, soldier! The Aerie gryphons will be ready to strike in no time at all!',
    `RequestItemsText` = 'My gryphons are poised to strike at the front lines but cannot make the attack until the lines are thinned out.$B$BThe Frostwolf warriors charged with holding the front lines wear medals of service proudly upon their chests. Rip those medals off their rotten corpses and bring them back here.$B$BOnce the front line is sufficiently thinned out, I will make the call to air! Death from above!'
WHERE `entry` = 6942;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Can you see it? Look at them, soldier! They''re coming around... Soon, Ichman''s flight will once again strike at the heart of the valley! Stormpike will rule the skies!',
    `RequestItemsText` = 'Their spirits are low, soldier. After our last failed air strike against the Horde, they refuse to fly! It is up to you to bolster their morale.$B$BReturn to the battlefield and strike at the heart of the Frostwolf''s command. Take down their commanders and guardians. Return to me with as many of their medals as you can stuff in your pack! I promise you, when my gryphons see the bounty and smell the blood of our enemies, they will fly again! Go now!'
WHERE `entry` = 6943;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ho ho hello.  I am Greatfather Winter, and I - courtesy of the fine folks of Smokywood Pastures... "Fresh from our farm to your plate, it''s Smokywood Pastures wholesome goodness" - would like to wish you a fantastic Feast of Winter Veil.$B$BIf you''ve been good this year, maybe you will receive treats from Smokywood Pastures as your treat for the Feast of Winter Veil.  Huzzah.',
    `RequestItemsText` = ''
WHERE `entry` = 6961;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''re quite the helper to ol'' Greatfather Winter there, $N.  Have a great Feast of Winter Veil.$B$BHere''s a little something... you know, for the effort.',
    `RequestItemsText` = 'All this talk of treats has given me a hankering for some myself.  Mmmm... gingerbread cookies and milk...'
WHERE `entry` = 6962;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Y-y-you can h-h-hear me!  Thank the b-b-bottom line!$B$BI''m not really a s-s-snowman - my n-n-name is Sacks, and I w-w-work for the Orgrimmar b-b-branch of Smokywood Pastures... I g-g-got sent out here to look for a m-m-missing package, when I was attacked by a c-c-creature I have never seen b-b-before!$B$BSo v-v-very cold...',
    `RequestItemsText` = ''
WHERE `entry` = 6963;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Feast of Winter Veil, you say?  Alas, in times past it held a more substantial meaning to us tauren.  Nowadays, it seems as though others have turned the legend of this season of renewal into something that helps to sell candies and presents.$B$BIt''s no surprise that Furmund is bitter about that sort of change.  He and other tauren like him cling to our past like a banner of war.  While I think a little celebration is always good, it is important to remember the origins of the Feast.',
    `RequestItemsText` = ''
WHERE `entry` = 6964;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh... I have never seen anything like this...',
    `RequestItemsText` = 'Hello, $R. What can I do for you?'
WHERE `entry` = 6981;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, you got them. Good work, $N! These supplies are a little musty from sitting in that dark mine for so long, but we''ll make use of them nonetheless.$B$BThank you, $N. Your deeds are vital to the maintenance of our fighting forces.',
    `RequestItemsText` = 'Have you been to the Coldtooth mine, $N? Do you have the supplies I asked for?'
WHERE `entry` = 6982;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found it!  You''ve saved Smokywood Pasture''s Feast of Winter Veil!$B$BPoor Sacks... we''ll be sure to send a team out there and figure out a way to unfreeze him.  Hopefully, he''ll be back in time for the day of the Feast; he''ll need to make up missed time working though.  Still, this wouldn''t even be possible if it weren''t for you!',
    `RequestItemsText` = '$N - our Feast of Winter Veil will be ruined without those treats to restock!  Graccu himself will miss out on sharing his delicious meat pies with all the good boys and girls this season...'
WHERE `entry` = 6983;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ho ho hello, adventurer!$B$BThe goblins told me that you have earned a special gift this holiday season, and I am pleased to give it to you.  Here you go - have a wondrous Feast of Winter Veil this and every season in the future.',
    `RequestItemsText` = ''
WHERE `entry` = 6984;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You got them! Nicely done, $N! And I hope you saw a few dwarves during your raid, and shed their blood for the Frostwolves!',
    `RequestItemsText` = 'Did you enter the Irondeep mine, $N? Did you raid its supplies?'
WHERE `entry` = 6985;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I can only hope that those charged with collecting ram hides are as determined as you, $N.$B$BAt this rate, we will have the stables full in a matter of hours!',
    `RequestItemsText` = 'Without your help, the Frostwolf Wolf Riders would not have mounts to ride into battle. You do us a great service!'
WHERE `entry` = 7001;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, soldier. I will notify you when I have stockpiled enough of the hides.$B$BCarry on!',
    `RequestItemsText` = 'Slay them and return to me with their hides. The same rams that the Stormpike cavalry uses as mounts!'
WHERE `entry` = 7002;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Splendifimous!  Not only am I glad to see that you''ve returned with the residue, but also with all your major appendages intact!  That is, well, there was never any danger in using the Ultra-Shrinker, now was there!$B$BI do appreciate your effort on my behalf, $N.  Truly, you are a friend to goblins everywhere.  Accept this as a token of my appreciation!',
    `RequestItemsText` = 'Miniaturization residue, I assure you, is a valuable commodity when it comes to engineering!  Well, it is valuable in that it helps me make sure the zapper won''t do something as disappointing as explode on the user.$B$BOh, I mean for the zappers other than the one I gave you.  Absolutely!'
WHERE `entry` = 7003;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ho ho hello. I am Greatfather Winter, and I - courtesy of the fine folks of Smokywood Pastures... "Fresh from our farm to your plate, it''s Smokywood Pastures wholesome goodness" - would like to wish you a fantastic Feast of Winter Veil.$B$BIf you''ve been good this year, maybe you will receive treats from Smokywood Pastures as your treat for the Feast of Winter Veil. Huzzah.',
