    `OfferRewardText` = 'You''re quite the helper to ol'' Greatfather Winter there, $N.  Have a great Feast of Winter Veil.$B$BHere''s a little something... you know, for the effort.',
    `RequestItemsText` = 'All this talk of treats has given me a hankering for some myself.  Mmmm... gingerbread cookies and milk...'
WHERE `entry` = 7025;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, soldier. I will notify you when I have stockpiled enough of the hides.$B$BCarry on!',
    `RequestItemsText` = 'The Stormpike Brigade cannot charge into battle bareback! We require harnesses for our mounts, after all, we are not savages.$B$BWhile we could easily slay the rams that roam near our base for the leather required to fashion a harness, doing so would be idiotic. We need those rams for mounts.$B$BYou must strike at our enemy''s base, slaying the frostwolves they use as mounts and taking their hides. Return their hides to me so that harnesses may be made for the cavalry. Go!$B$BSlaying the frostwolves they use as mounts and return their hides to me.'
WHERE `entry` = 7026;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The stables will be full in no time at all. Keep up the good work!',
    `RequestItemsText` = 'Without your help, the Stormpike Ram Riders would not have mounts to ride into battle. You do us a great service!'
WHERE `entry` = 7027;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ha ha ha! I knew you''d be back.$B$B<Willow mutters>$B$B...So easy to convince.$B$B...Will do anything for the right price. Heh heh heh...',
    `RequestItemsText` = 'Don''t ask questions!$B$BYou have my request.'
WHERE `entry` = 7028;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you for returning this, $N. With the remaining liquid you brought me, I can continue my studies.$B$BWhile there is still much to do, you have helped to heal some of the corruption that Vyletongue spread through Maraudon. Please take this with my gratitude.',
    `RequestItemsText` = 'If you are able to heal the plant, it will again begin to grow. We must do what we can, $N...'
WHERE `entry` = 7029;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you for returning this, $N. With the remaining liquid you brought me, I can continue my studies.$B$BWhile there is still much to do, you have helped to heal some of the corruption that Vyletongue spread through Maraudon. Please take this with my gratitude.',
    `RequestItemsText` = 'If you are able to heal the plant, it will again begin to grow. We must do what we can, $N...'
WHERE `entry` = 7041;

