    `OfferRewardText` = 'Let''s get to work!',
    `RequestItemsText` = ''
WHERE `entry` = 7261;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your heroics will not go unnoticed, $N.$B$BI must waste no time if he is to be saved. Sylvanas must be contacted!',
    `RequestItemsText` = 'How it must pain him to remain as one of the living while his beloved brother has ascended to perfection.'
WHERE `entry` = 7281;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You did remember to burn the corpse, didn''t you?',
    `RequestItemsText` = 'It is with heavy heart that I give such an order, soldier.'
WHERE `entry` = 7282;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Unbelievable! You did free them, right? Right??? Well at the very least we know where they were held.',
    `RequestItemsText` = 'Anything I would care to hear?'
WHERE `entry` = 7301;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done! The information you recovered will be invaluable to our cause.',
    `RequestItemsText` = 'Status of the hunt, soldier?'
WHERE `entry` = 7302;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My soothing turtle bisque will keep you warm on a cold night... if you care about that kind of thing.',
    `RequestItemsText` = 'Any luck finding the ingredients?  I''ll tell you, the alliance maggots are far too numerous in this area now... In my opinion, they have come far too close already...'
WHERE `entry` = 7321;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent! I am a Tauren of my word, $R. The arrows are yours.',
    `RequestItemsText` = 'Greetings, $R. I am Kolark, Bounty Hunter from Thunderbluff. Much of the world I have traveled and much I have seen.$B$BMy journeys across the South Seas led to the discovery of these wonderous thorium headed arrows. Alas, I have an endless supply of the arrows but have exhausted my supply of shells. Bah, no self respecting Tauren would ever be caught dead using a flimsy bow. The arrows are useless!$B$BI will offer a trade: An even exchange of thorium shells for my thorium headed arrows. Deal?'
WHERE `entry` = 7341;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A done deal if I ever saw one! The arrows are yours.',
    `RequestItemsText` = 'Can you believe this rubbish?! The last shipment of ammunition from Kharanos was botched! All we have for ammo now are these flimsy, good for nothing arrows! What in the world am I going to do with 500,000 thorium headed arrows?$B$BI''ll tell you what, kid. If you can bring me thorium shells, I''ll trade you thorium headed arrows - straight up! Deal?'
WHERE `entry` = 7342;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N, it is but one of thousands. A job well done nonetheless.',
    `RequestItemsText` = 'They seek to exterminate us? It is they who shall be exterminated.'
WHERE `entry` = 7361;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Aye, this is definitely gnome. Well done, $R, but there is more work to be done.',
    `RequestItemsText` = 'I don''t care where the hair comes from, $R.'
