UPDATE `quest_template` SET
    `OfferRewardText` = 'It would be easier if they just accepted their illness and gave in to your healing touch. It would also probably be less fun. Carry on! We''ll cure them, one way or another.',
    `RequestItemsText` = 'Yes, it is true. My brother is a human. Shameful... A stain upon my nearly immaculate record.'
WHERE `entry` = 7363;

