UPDATE `quest_template` SET
    `OfferRewardText` = 'To be in the presence of the Oracle Tree... it is almost to feel wisdom take form. Let me continue the telling...$B$BWith Teldrassil grown, the Arch Druid approached the dragons for their blessings, as the dragons had placed upon Nordrassil in ancient times. But Nozdormu, Lord of Time, refused to give his blessing, chiding the druid for his arrogance. In agreement with Nozdormu, Alexstrasza also refused Staghelm, and without her blessing, Teldrassil''s growth has been flawed and unpredictable...',
    `RequestItemsText` = 'Along with the druids, the Oracle Tree and the Arch Druid have been carefully monitoring the growth of Teldrassil. But though we have a new home, our immortal lives have not been restored.'
WHERE `entry` = 7383;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The blood of our enemies has been shed. I shall mix this blood with the rest that has been gathered. Once the offering is complete, the Ice Lord shall show these Stormpike dogs the full wrath of the Frostwolf Clan!',
    `RequestItemsText` = 'You must strike down our enemies and bring to me their blood.'
