UPDATE `quest_template` SET
    `OfferRewardText` = 'You retrieved the web!  Well done, $N!  Lethtendris, like many elves of her ilk, are blind to the dangers the abuse of magic can cause to our world.  They believe they are masters of magic; they do not realize that they are slaves to their own addiction.  Her death saddens me, but it was necessary.$B$BThank you, $N.  I will have the energies within the web released safely over a wide area, and then I''ll destroy it to prevent future magical exploits.',
    `RequestItemsText` = 'Do you have the web, $N?  Its concentrated magical energy must be dissipated!'
WHERE `entry` = 7488;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, $N. This web holds within it vast stores of the magic of Dire Maul, and I fear what damage may be unleashed if those energies were harnessed by one so irresponsible as Lethtendris. I am saddened by her death, but I know that she could never part with her web while alive.$B$BThank you, $N. I will send the web to students of magic more responsible than Lethtendris. They will be the new wardens of its power.',
    `RequestItemsText` = '$N, do you have Lethtendris''s Web?'
WHERE `entry` = 7489;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is a great victory for the Horde, $N. So many times you have honored your Warchief. It is time for the Warchief to honor you.',
    `RequestItemsText` = '<Thrall''s stoic demeanor changes for a split second when he sees the enormous head of Onyxia. The mighty Doomhammer was nearly unsheathed.>'
