UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent work, $R. Should you find any more tomes, do not hesitate to return them to us.$B$BAs time passes, we tend to change around and even add new rewards for the return of missing tomes.',
    `RequestItemsText` = 'You have recovered a tome!'
WHERE `entry` = 7504;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent work, $R. Should you find any more tomes, do not hesitate to return them to us.$B$BAs time passes, we tend to change around and even add new rewards for the return of missing tomes.',
    `RequestItemsText` = 'You have recovered a tome!'
WHERE `entry` = 7505;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent work, $R. Should you find any more tomes, do not hesitate to return them to us.$B$BAs time passes, we tend to change around and even add new rewards for the return of missing tomes.',
    `RequestItemsText` = 'You have recovered a tome!'
WHERE `entry` = 7506;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You could have gotten quite a lot of gold for this book on the black market, $N. Especially since the protective seal has been broken, leaving the secrets of dragon slaying viewable to any with the requisite intellect to consume the knowledge held within the sacred pages.$B$BPerhaps a grand reward is in order... Well, a reward that will require enormous effort to obtain.$B$B<Lydros grins.>',
    `RequestItemsText` = 'Ah, one of our greatest compilations. This one has been missing for ages.'
WHERE `entry` = 7507;

UPDATE `quest_template` SET
    `OfferRewardText` = 'If you manage to enter the lair of the dragon, heat the blade under her fiery breath, and ultimately temper it in her blood, I shall bind the blade for your use.',
    `RequestItemsText` = 'Excellent, let us begin...'
WHERE `entry` = 7508;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Lydros murmurs something unintelligible.>$B$BAs promised, $C, the blade of Quel''Serrar.',
    `RequestItemsText` = 'Perhaps one day, another will wield the prismatic blade.'
WHERE `entry` = 7509;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Even in dreams I did not dare foresee this day.$B$BBehold, mortal.$B$BBEHOLD HE WHO IS OLDER THAN EXISTENCE!$B$BBEHOLD HE WHO HAS FACED TITAN AND GOD ALIKE!$B$BRISE MY MASTER! BREAK FROM YOUR BONDS!',
    `RequestItemsText` = 'Bring the world to its knees if you must!'
WHERE `entry` = 7521;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It will take time for our scholars to study the pendant you brought us.  But for your service to the Horde I would like to offer you a small token.$B$BThank you, $N.  Your acts bring honor to you, and to us.',
    `RequestItemsText` = ''
WHERE `entry` = 7541;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Greetings, $N, and welcome.  Are you here to study near the Altar of Storms as I am, perhaps to harness its energy for some hidden purpose...$B$BOr... are you here to speak with me?  Yes, I believe you are.$B$BYou want to master a dreadsteed?  Such is no easy task.  It will cost you no small amounts of blood, sweat... and of course gold.  But a dreadsteed of Xoroth is a prize well worth winning so if interested, listen on...',
    `RequestItemsText` = ''
WHERE `entry` = 7562;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, very good. I will have this blood distilled into an ink and use it for the parchment I promised you. And perhaps I will save just a little for myself, as I hear its taste is quite euphoric...',
    `RequestItemsText` = 'Have you seen the raging owl beasts, $N? The magic of those creatures is strong, and it concentrates in the blood that flows through their torturted forms.'
WHERE `entry` = 7563;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, it''s blood. It must be from master Mor''zul then. He is so enamored with the stuff, and loves to see it spilled. I, however, prefer it coursing through the veins of a small rodent. It stays warm that way... until you want it.$B$BThis is powerful blood. Mor''zul must be making another parchment to summon a dreadsteed! How exciting!$B$BIf that''s true, and you''re going to perform the ritual, then... you''re going to need a lot more than blood, my friend.',
    `RequestItemsText` = 'You have something for me?  It''s not a big, juicy spider, is it?  Or maybe a roach?  I hope it''s still alive... I so love chewing on them when they''re still alive...'
WHERE `entry` = 7564;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, a most excellent recovery. The blood will suppress the Doomguard''s magical defenses.',
    `RequestItemsText` = 'Only the blood of Wildspawn satyr will suffice.'
WHERE `entry` = 7581;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I merely need to combine the blood of the Wildspawn with these crystals and the prison shall be ready for use.',
    `RequestItemsText` = 'The Hederine will not give up their precious gems without a fight, $N.'
WHERE `entry` = 7582;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done as I have asked. You are ready to be given the knowledge to conjure and control the beast.',
    `RequestItemsText` = 'Hrm? Well?'
WHERE `entry` = 7583;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh boy, here we go again.',
    `RequestItemsText` = ''
WHERE `entry` = 7601;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Give me a minute and I''ll combine the essences into Fel fire.',
    `RequestItemsText` = 'Don''t tell anyone this but Niby is daft.'
WHERE `entry` = 7602;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A deal is a deal! Quickly, take this and write this down. I don''t have time! My greatest conjuration is upon us!',
    `RequestItemsText` = 'Did you get lost?'
WHERE `entry` = 7603;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It has been a pleasure doing business with you, $N!$B$BOn behalf of TB Ltd., I wish you luck in your search for Sulfuras!',
    `RequestItemsText` = 'Do we have a deal?'
WHERE `entry` = 7604;

UPDATE `quest_template` SET
    `OfferRewardText` = '$G Priest:Priestess;, you are about to undergo a rigorous series of events which shall test all of your abilities.$B$BI suggest that you listen to the story that I have to tell.$B$BBe warned, you must complete this task alone. It is recommended that your allies remain at a distance. Interference by outside agents will result in a most severe punishment.$B$BDestiny has led you and you alone here. Battle with honor. Harness the Light.',
    `RequestItemsText` = ''
WHERE `entry` = 7621;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your tenacity and courage are astounding, priestess. You have earned the right to hold the Splinter of Nordrassil. Only one task remains: The Eye of Shadow must be recovered. Scour the world.',
    `RequestItemsText` = ''
WHERE `entry` = 7622;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My patience spans the millenia, $C.  But do not think that allows you more than an instant of my time...',
    `RequestItemsText` = ''
WHERE `entry` = 7623;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, how splendid! After rotting a week, this heart will prove a succulent treat! Perhaps I will send for Ulathek''s head and place it before me as I eat...$B$BYou have done me a service, $C, and so my patience for you has grown. Marginally.',
    `RequestItemsText` = 'I can already taste the heart of Ulathek on my lips. So sweet is the flesh of a traitor...'
WHERE `entry` = 7624;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There it is! I can hardly believe you got it! You must have struck a big deal with that Dreadlord or else paid a large sum, or both!$B$BMor''zul will have his ink very soon and then he can finally make the glyph parchment, so you can open a portal to Xoroth and pull through it one of the famed dreadsteeds!',
    `RequestItemsText` = 'Have you been to Jaedenar, $N? Did you get the stardust from Lord Banehollow?'
WHERE `entry` = 7625;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good! I hope these elixirs weren''t too hard to get. Sometimes alchemists can be so miserly with their creations...$B$BI''ll make the bell and keep it until you''re ready for your ritual.',
    `RequestItemsText` = 'You have those elixirs, $N? Mor''zul told me you need a Bell of Dethmoora, and making one of those takes a lot of shadow power!'
WHERE `entry` = 7626;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There they are! I hear that dark iron ore is only found in the depths of Blackrock, and I''m sure these shards weren''t easy to find either. I am often awed at the dedication you warlocks have. If you instead bent all that energy into the art of bug catching, oh... such a feast you would enjoy!$B$BSorry, a small digression. I''ll create the wheel and keep it for you until you''re ready for your ritual.',
    `RequestItemsText` = 'The Wheel of the Black March isn''t easy to make, and takes a lot of materials. Have you gathered them yet?'
WHERE `entry` = 7627;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, very good. I''ll need these to contain the fires of the candle. Now that I have the scales, I''ll make the candle and hold onto it until you''re ready to begin your ritual for the Circle of Greater Summoning.',
    `RequestItemsText` = 'Did you bring the dragonscales, $N? I don''t want to start on the candle until I have them... or I might blow up the whole camp!'
WHERE `entry` = 7628;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, good. J''eevee created the parchment. How was the Scholomance? Charming, don''t you think? And the bugs there... I hear they''re delicious!$B$BWell done, $N, and thank you for returning my jar. I''ve had it for a long time... and it''s not for sale!',
    `RequestItemsText` = 'Have you been to the Scholomance, $N? Has the imp yet infused the parchment with the stardust?'
WHERE `entry` = 7629;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You got it! Nicely done! Now I can create the lodestone. When you''re finally ready for your ritual to create the Circle of Greater Summoning, you''ll want a lodestone to make sure the ritual doesn''t fizzle out!',
    `RequestItemsText` = 'Do you have the arcanite, $N? Once I have it I can make you the black lodestone.'
WHERE `entry` = 7630;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Xorothian Dreadsteed''s spirit is beaten.  Although rage pulses through its ghostly flanks, you know that the beast''s soul is yours...$B$BIt whispers dark magic into your mind and instills within you the knowledge to summon a dreadsteed.',
    `RequestItemsText` = ''
WHERE `entry` = 7631;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Of course I recognize my own leaves. Look at that! It''s in perfect condition.$B$BHow good of you to return it, $C.$B$BPerhaps you could be of service to us and we to you.',
    `RequestItemsText` = '<Vartrus groans.>'
WHERE `entry` = 7632;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your diligence and integrity has been noted, $C.$B$BWe are Ancients: Protectors of this once great forest. Our physical forms were destroyed 10,000 years ago when Archimonde and the Burning Legion marched upon Hyjal. Our spirits, however, remain intact.$B$BThere are tasks that we can offer. Tasks that if completed will open up the secrets of the Ancients to you.$B$BKnow this, should you complete these tasks, merely return to this rock and we shall answer the calling.',
    `RequestItemsText` = ''
WHERE `entry` = 7633;

UPDATE `quest_template` SET
    `OfferRewardText` = 'May my leaves provide your arrows protection from harm. May your arrows strike true. May the enemies of our world be smitten.',
    `RequestItemsText` = 'Welcome back, young $C.'
WHERE `entry` = 7634;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A most foul dragon this one was. The sinew reeks of evil.$B$BGive me a moment to cleanse the filth from this flesh and apply the proper enchantments.',
    `RequestItemsText` = 'I am certain that you will have little difficulty in finding and slaying a black dragon, $N. Do not waste my time with idle chatter.'
WHERE `entry` = 7635;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have served us well, $N! Take this stave and combine it with the bow string that Stoma is able to create. Together, they form a most formidable weapon.',
    `RequestItemsText` = 'Do not be fooled by their disguises!'
WHERE `entry` = 7636;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Blessings onto you, friend $C! Your donation goes far beyond what was needed. Your sacrifice will not only help us recover what we have lost, but also help us to help those most in need here in Ironforge.$B$BNow, let me make sure I''ve suitably prepared this censer for your future needs...',
    `RequestItemsText` = 'Greetings, noble $C! I have prepared my trusted censer with the freshest of incense and blessed it thrice for your use. Your donation will help us in Ironforge not only create a new censer, but also to bolster sagging reserves of food for our needy.'
WHERE `entry` = 7637;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I am glad to see you $N. I know that you have awaited word as to how to acquire your charger, and now that time has come.$B$BYou will be surely tested in many different ways, but most importantly in your willingness to rise above numerous obstacles thrust before you. These are not done as a learning exercise - your stature is beyond simple educational tests. You must save your future companion from the clutches of the evil you have spent your life fighting.$B$BTake heed, your time has come!',
    `RequestItemsText` = ''
WHERE `entry` = 7638;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, this will do. You will be called upon more than once during this process to make acts of sacrifice; I am glad to see that you are willing to do just that. Sacrifice is a key component in what it takes to uphold the duties of being a Paladin... but I don''t have to lecture you on that.$B$BNow $N, you will need to show due judgment in your actions. To that end, this censer will act as your vessel to dispense such judgment on tortured spirits of lands lost to us.',
    `RequestItemsText` = 'Welcome back, $N. Have you acquired the exorcism censer?'
WHERE `entry` = 7639;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N. To render the judgment of the Light on those that dwell in darkness is a task we must approach with vim and zeal; you have done just that with your sacrifice in Ironforge and your judgments of the spirits in Terrordale.$B$BYour next steps will call on both sacrifice and judgment again as you now strive to reclaim the spirit of a fallen charger who now serves a Death Knight known as Darkreaver.',
    `RequestItemsText` = 'It is good to see you again $N. Is your work done in Terrordale?'
WHERE `entry` = 7640;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hello there - Lord Shadowbreaker sent me word ahead of time that you''d be coming around this way to see me. I''m willing to make the barding you need, but it won''t be either cheap or easy; let''s get that out in the open first and foremost.$B$BI will say this much, and Grayson will back me up when I make this claim... you''ll not find better barding made anywhere in all of Azeroth than right here.',
    `RequestItemsText` = ''
WHERE `entry` = 7641;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This... well, this is exactly what I needed.  You''re quite the resourceful $C, aren''t you?$B$BAll right then, let''s get this barding finished up for you!',
    `RequestItemsText` = 'Ah, $C. I won''t be able to finish your barding without the things I mentioned. Have you gotten everything together?'
WHERE `entry` = 7642;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Ancient Equine Spirit accepts the offering of the Manna-Enriched Horse Feed, nuzzling the container as it helps itself to the special oats and grains. After it has eaten a little, it looks at the barding you possess and positions itself as though it wants you to place it upon its back...',
    `RequestItemsText` = 'The Ancient Equine Spirit looks at you expectantly, as though it wants something from you.'
WHERE `entry` = 7643;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve come far, my friend. Your barding is now suitably prepared for the last task at hand.$B$BYou will be using this barding to harness your charger once the task of redemption is complete. Before that, however, you will have a monumental struggle to overcome. Your time draws near - huzzah!$B$BThere is one last item that needs to be made before we begin this, $N. Hopefully your resourcefulness has not departed you since you had your barding made...',
    `RequestItemsText` = '$N, you''re back! Were you able to successfully deal with Merideth Carlson and Tendris Warpwood?  Honestly, I''m not sure which one is a greater threat at times...'
WHERE `entry` = 7644;

UPDATE `quest_template` SET
    `OfferRewardText` = 'YES, NOW WHO - wait - you''re giving me the gold too? You weren''t the one who called me mad (actually they called me a fruitcake nut-job)... still, you''re willing to show sacrifice even for wrongs you''ve not committed?$B$BI... I misjudged you, $N.  Should you need more horse feed, come see me. I will give it to you free of charge. Thank you... noble $C.$B$BI am going to keep the money though - I''m not that much of a nut-job as to give up a fortune.',
    `RequestItemsText` = 'Yes, I''ve proved you wrong now, haven''t I? I''ve proved them all wrong! I WAS RIGHT ALL ALONG!!!'
WHERE `entry` = 7645;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These are fine specimens, $N - the final pieces are now in place. At long last, your time has come!$B$BIn the depths of the Great Ossuary of Scholomance are the skeletal remains of many beings. Amongst them is a once-noble charger. The hollowed soul of this charger now serves as the steed for Death Knight Darkreaver. It is he whom you will face, and it is this steed that you will pass judgment upon. Only you, $N, can redeem its soul and save it from the torment of its servitude.',
    `RequestItemsText` = 'You have come so very far, $N. Your final act of worldly-item sacrifice will be the genesis for one of your greatest accomplishments. I can feel it in the very fiber of my being!'
WHERE `entry` = 7646;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A glimmer of life - long vacant from the poor beast - shines in its eyes as you hand its judged soul back to it. You feel a holy rush of power surge around you as you place the barding on its back, having judged the charger redeemed. The charger nuzzles your hand as the burdens of the past are lifted from the beast. You now feel as though you could call upon this beast to serve as your steed, should the need arise.$B$BYou have claimed your epic charger, $C! Congratulations!',
    `RequestItemsText` = 'The spirit of the fallen charger looks upon you with a mournful gaze. Sad, almost hollow eyes look at you as though all hope was lost to it.'
WHERE `entry` = 7647;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is most impressive work. It seems that as Grimand gets older, his craftsmanship continues to improve. That''s quite the feat when his work was already some of the finest you''d find anywhere when he made my barding back in the day.$B$BWhile this barding would be a fine addition to any normal steed, we are not dealing with such a mundane beast. You''ll need this barding blessed by an appropriate source for it to be worthy of resting on a $C''s charger. I''ll hold onto it for you until then.',
    `RequestItemsText` = 'You''re progressing along nicely, $N. Once you have made your barding, you''ll be well on your way to the next task.'
WHERE `entry` = 7648;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, my boy.$B$B<Lorekeeper Lydros tears out a page from the book.>$B$BI am sure you can make use of this recipe.',
    `RequestItemsText` = 'You have recovered a tome!'
WHERE `entry` = 7649;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, my boy.$B$B<Lorekeeper Lydros tears out a page from the book.>$B$BI am sure you can make use of this recipe.',
    `RequestItemsText` = 'You have recovered a tome!'
WHERE `entry` = 7650;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, my boy.$B$B<Lorekeeper Lydros tears out a page from the book.>$B$BI am sure you can make use of this recipe.',
    `RequestItemsText` = 'You have recovered a tome!'
WHERE `entry` = 7651;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Aright, mister, I got a hot deal for ya.$B$BI''m lookin'' to offload some of these here Imperial plate armor recipes and need someone willing to take on the burden. All I want in exchange is some thorium bars. Sound good?',
    `RequestItemsText` = ''
WHERE `entry` = 7652;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A pleasure doin'' business with ya.$B$BAnd $N, wipe that look of disgust off yer face.',
    `RequestItemsText` = 'For the belt plans, I''ll be needin'' 20 thorium bars.'
WHERE `entry` = 7653;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A pleasure doin'' business with ya.$B$BAnd $N, wipe that look of disgust off yer face.',
    `RequestItemsText` = 'For the boot plans, I''ll be needin'' 40 thorium bars. Yep, 40. Are you gonna cry? Would you like a hanky?$B$B<Derotain laughs.>'
WHERE `entry` = 7654;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A pleasure doin'' business with ya.$B$BAnd $N, wipe that look of disgust off yer face.',
    `RequestItemsText` = 'For the bracer plans, I''ll be needin'' 20 thorium bars.$B$BAre you alright, sonny? Yer getting'' all red.'
WHERE `entry` = 7655;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A pleasure doin'' business with ya.$B$BAnd $N, wipe that look of disgust off yer face.',
    `RequestItemsText` = 'For the chest piece plans, I''ll be needin'' 60 thorium bars.$B$BOh boy, there you go again. Are you gonna be runnin'' to yer blue Gods, askin'' why they have forsaken you?!? Toughen up, Nancy! Nobody ever said life''s fair.'
WHERE `entry` = 7656;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A pleasure doin'' business with ya.$B$BAnd $N, wipe that look of disgust off yer face.',
    `RequestItemsText` = 'Just hand over 50 thorium bars and the helm plans are yers.'
WHERE `entry` = 7657;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A pleasure doin'' business with ya.$B$BAnd $N, wipe that look of disgust off yer face.',
    `RequestItemsText` = 'Just hand over 60 thorium bars and the leg plans are yers.$B$BI know, I''m driving you into bankruptcy! I''ve heard it all before so you can save your sob story, weakling.'
WHERE `entry` = 7658;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A pleasure doin'' business with ya.$B$BAnd $N, wipe that look of disgust off yer face.',
    `RequestItemsText` = 'For the shoulder plans, I''ll be needin'' 20 thorium bars.'
WHERE `entry` = 7659;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Are you headed back into the Scholomance, $N? You''ve already paid such a great price for the use of the Divination Scryer - perhaps you''d like to take another one with you. With it, you''d be able to face the perils of the Great Ossuary once more.$B$BBy all means, have it. You''ve certainly earned it.',
    `RequestItemsText` = ''
WHERE `entry` = 7666;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your generosity is unrivaled, $N. I thank you for your kindness.$B$BI will be able to finish my divination scryer now, and I should be able to fashion more without further need of diamonds... perhaps you would be interested in helping me in its use? It is for a most important task, I assure you... one that left unchecked could spell unmitigated disaster for the spirit realm!',
    `RequestItemsText` = 'I feel awkward asking for material assistance, but my divination scryer - the device I hope to finish - requires one of each. If you cannot help me, I''d certainly understand.'
WHERE `entry` = 7667;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is a victory to savor, $N! The demise of Darkreaver should restore the fragile fetters that anchor the spirit realm.$B$BYou have far exceeded what was asked of you, even when you had no notion of reward or compensation. You are truly a $C of worth, my friend.$B$BI know that acting to preserve the spirit realm should be thanks enough, but please - accept this simple gift with my thanks.',
    `RequestItemsText` = 'Time is critical, $N - have you succeeded in stopping Death Knight Darkreaver''s threat?'
WHERE `entry` = 7668;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I never thunk I''d be lookin'' at thish ugly mug again!$B$BHe acshually looksh better without the resht o'' him attached.$B$BHere''s yer reward *hic*, $R.',
    `RequestItemsText` = 'Can''t ya shee I''m bushy? What *hic* ish it ya be wantin? *hic*'
WHERE `entry` = 7701;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wow... you ARE da true king! I never think I see this gauntlet in my life! It look like it got no mojo left anymore... maybe that creepy elf try and ruin gauntlet. Well, I say HAR HAR to him!$B$BLook - this mark on da gauntlet an old old OLD timey magic mark, older than da Gordok they say. Well, as Captain of da Gordok, we all learn one thing over and over - how to make mark come to life and give power back to gauntlet!$B$BI do it for you, king! Here, take da gauntlet and rule FOREVER!',
    `RequestItemsText` = 'Hah, you no find it, do you boss? Maybe old timey story a bad story... hard to believe that creepy elf can steal from Gordok king!'
WHERE `entry` = 7703;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Scrumdillyriffic!  These cores will keep me working for some time.  Add to that the benefit of there now being fewer elementals along the coast, and I might no longer cry myself to sleep at the prospect of having set up shop in perhaps the worst place imaginable!$B$BThank you, $N, for your efforts on my behalf.  While it certainly straps me financially to do this, allow me to show you some gratitude you may understand and appreciate... loot!',
    `RequestItemsText` = 'While I could bore you with the technical details of the utility behind elemental cores, I will instead tempt you to completion of this important task by offering valuable coin and prizes for doing so.  Yon verily, are you finished?'
WHERE `entry` = 7721;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I hope you kicked his teeth in too, $N. Ragnaros knows, he deserved it.$B$BNow we can get down to business.',
    `RequestItemsText` = 'Did you find the plans?'
WHERE `entry` = 7722;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ye''re a good lad, ye are. I got ye a lil'' present fer yer troubles.',
    `RequestItemsText` = 'Did ye pound ''em?'
WHERE `entry` = 7723;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Hansel sneezes.>$B$BI think I''m gettin'' a cold. Damn this frigid climate!',
    `RequestItemsText` = 'Was he right? Does it come out their rumps?'
WHERE `entry` = 7724;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Inconceivably fantastical, $N!  You''ve come through for me again, and for that I thank you.$B$BThank you!$B$BWhile you may find this coin to be a little less than you''re accustomed to, rest assured your great deeds on the field of goblindom are echoing through the halls of power in the Steamwheedle Cartel.  Should you need something else to do, then by all means talk to me!',
    `RequestItemsText` = 'Ah, the fruits of research and utilization in the form of sweet, sweet residue.  Well, that is to say, I don''t taste it or anything when I study it.$B$BMuch.'
WHERE `entry` = 7725;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Top notch, $N, top notch!  While the coin I give you might not be the most you''ll ever receive for such work, rest assured my comrades in the Steamwheedle Cartel will hear about your efforts!$B$BIf you are looking for anything else to do, then let me know.  I can always use more elemental cores and such.',
    `RequestItemsText` = 'Have you managed to find the elemental cores I need?'
WHERE `entry` = 7726;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh me achin'' feets.$B$BI figured since ye didn''t have a luffa...',
    `RequestItemsText` = '<Hansel is busily rubbing his bunions.>$B$BDon''t just stand there, grab some oil and a luffa and get to scrubbin'' these bunions.$B$BYe don''t have a luffa? Well then! Perhaps it''s time I sent you out to find a luffa?%$B$BHey, where are ye goin''?'
WHERE `entry` = 7727;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Fantastic work! Now for your reward.',
    `RequestItemsText` = 'If you''re here for the reward, you''re gonna have to give me the stolen goods.'
WHERE `entry` = 7728;

UPDATE `quest_template` SET
    `OfferRewardText` = '15.9 pounds! That may be a new record for blood and gut weight on apparel! Congratulations, $C!',
    `RequestItemsText` = 'We''re gonna need to weigh you with and without clothes to be sure.'
WHERE `entry` = 7729;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $C.  Though the extensiveness of the Zukk''ash presence will not be thwarted with anything less than a full-scale invasion, you have bought us some time so we can devise a proper strategy.$B$BI will be sure to have these carapaces analyzed; we''ll need to learn everything about them before we deal with what has unfortunately turned into a much larger issue than we had anticipated.',
    `RequestItemsText` = 'How goes the hunt, $N?  Are you here to report your success?'
WHERE `entry` = 7730;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Impressive, $C... most impressive!  If Stinglasher is indeed one of their strongest creatures, the study of the beast will prove to be quite valuable in time.  It''s now my charge to make sure we defend ourselves long enough to take advantage of it.$B$BPlease accept this coin bounty as a token of the entire camp''s thanks, $N.  Well done.',
    `RequestItemsText` = 'Have you managed to bring down Stinglasher yet?'
WHERE `entry` = 7731;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, I''ve been expecting this.  These creatures you faced... they are an ancient threat that the Horde continues to choose to ignore.  Hadoken was wise to bring this - and you - to me.$B$BThe Zukk''ash are nothing more than creatures called the silithid.  Some would think that they are a mindless nuisance, but let me assure you - they are a far, far worse threat than anything the Alliance could muster.$B$BIf you''re willing and strong enough, I could use your aid in bringing this threat to light.',
    `RequestItemsText` = 'Greetings friend... you look as though you are on urgent business.  Is there something I can help you with?'
WHERE `entry` = 7732;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent, excellent!  These are going to work out incredibly well - I can already tell that they''re going to be much harder when properly cured.$B$BThanks again for your help $N.  Here - please take one of my latest creations.',
    `RequestItemsText` = 'If these Rage Scar yeti hides are anything like the quality displayed by their Feral Scar counterparts, they could very well be as resilient as thorium!$B$BImagine that!'
WHERE `entry` = 7733;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent, excellent!  These are going to work out incredibly well - I can already tell that they''re going to be much harder when properly cured.$B$BThanks again for your aid, $N.  Here - please take one of my latest creations.',
    `RequestItemsText` = 'If these Rage Scar yeti hides are anything like the quality displayed by their Feral Scar counterparts, they could very well be as resilient as thorium!$B$BImagine that!'
WHERE `entry` = 7734;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Incredible!  You may have found the granddaddy of all yeti hides with this!$B$BYou better believe I''ll pay you for it.  I normally don''t pay that much for a single hide, but I''m pretty sure I can make something special from it.  Thanks for thinking of me on this, $N!',
    `RequestItemsText` = 'What''s this, $N - you''ve got something special for me?'
WHERE `entry` = 7735;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There''s always room for more fiery flux, junior. Keep it comin''... unless I tell you to stop.',
    `RequestItemsText` = 'Let''s not waste more of my precious time with jibber jabber, $R. It''s time to focus on replenishing our dwindling fiery flux supply.$B$BWhat I''m gonna need from you is the following:$B$B*Incendosaur scales.$B$B*Kingsblood.$B$B*Coal.$B$BI''ll take all that you can offer!$B$BAnd you''ll do it fast if you wanna get in good with the Brotherhood.'
WHERE `entry` = 7736;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Keep the residue pouring in!',
    `RequestItemsText` = 'You''ve worked your way up through the Brotherhood''s corporate hierarchy, $R. We have begun to look favorably upon you. Quite an accomplishment!$B$BIf you''re interested in more work and earning more respect amongst us, listen up.$B$BWe can refine the fiery flux by adding a simple Dark Iron residue to the mix. The Dark Iron residue can be found in Blackrock Depths.'
WHERE `entry` = 7737;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is an incredible find! I believe this is the finest yeti hide specimen I have ever seen!$B$BIndeed, this is certainly worthy of an appropriate bounty. I normally don''t pay that much for a single hide, but I''m confident I can make something special from it. Thanks for thinking of me on this, $N!',
    `RequestItemsText` = 'What''s this, $N - you''ve got something special for me?'
WHERE `entry` = 7738;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You don''t even flinch as the smoldering brand is pressed into your flesh. You are so tough!$B$BYou now hold the Mark of Drakkisath. Have fun storming the castle.',
    `RequestItemsText` = ''
WHERE `entry` = 7761;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You need not be told the meaning of what you have done, $N. This day will be recorded in the annals of history. A victory the likes of which has not been known to the Alliance for years - if ever!',
    `RequestItemsText` = 'Inconceivable!'
WHERE `entry` = 7781;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Field Marshal Afrasiabi bows.>$B$BChoose your reward, let the celebration begin!',
    `RequestItemsText` = ''
WHERE `entry` = 7782;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have honored the Horde once more, $N. The son of Deathwing lays dead. Surely, the evil one stirs.',
    `RequestItemsText` = 'I wish that I could have been there to see the look on the face of the beast as you struck the killing blow, $N.'
WHERE `entry` = 7783;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Choose your reward so that I may mount the head of the beast for all to see.',
    `RequestItemsText` = ''
WHERE `entry` = 7784;

UPDATE `quest_template` SET
    `OfferRewardText` = 'May you be protected in your crusade. May the Master bless your efforts.',
    `RequestItemsText` = 'Will you release him from his eternal prison?'
WHERE `entry` = 7785;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Even in dreams I did not dare foresee this day.$B$BBehold, mortal.$B$BBEHOLD HE WHO IS OLDER THAN EXISTENCE!$B$BBEHOLD HE WHO HAS FACED TITAN AND GOD ALIKE!$B$BRISE MY MASTER! BREAK FROM YOUR BONDS!',
    `RequestItemsText` = 'Bring the world to its knees if you must!'
WHERE `entry` = 7786;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Please do not harm me! Take it! Take the blade! Leave Demitrian to reshape his pathetic life!',
    `RequestItemsText` = '<Demitrian cowers in your presence.>'
WHERE `entry` = 7787;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have proven your value to our efforts in Warsong Gulch. Continue to aid the cause and bring me more Marks of Honor. Do this, and you will earn even more of our trust.',
    `RequestItemsText` = 'Have you fought in Warsong Gulch and defended Silverwing Hold?'
WHERE `entry` = 7788;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Captain Shatterskull roars in triumph>$B$BHow much more can they withstand? How many more Alliance filth must perish at the hands of the Horde for them to retreat? Only time will tell, $R...',
    `RequestItemsText` = 'The blood of our enemies is a mark of honor. Do you have such a mark?'
WHERE `entry` = 7789;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wonderful! We thank you for your generous donation, $N!',
    `RequestItemsText` = 'We are currently accepting donations for wool cloth.  A donation of sixty pieces of wool cloth will net you full recognition by Stormwind for your generous actions.  Our stores are such on wool that we would only need sixty pieces from you total; we should be able to acquire enough from others in the realm to support our drive.$B$BIf you have the sixty pieces of wool cloth on you and are ready to donate them, I''m able to take them from you now.'
WHERE `entry` = 7791;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wonderful! We thank you for your generous donation, $N!',
    `RequestItemsText` = 'We are currently accepting donations for wool cloth. A donation of sixty pieces of wool cloth will net you full recognition by Darnassus for your generous actions. Our stores are such on wool that we would only need sixty pieces from you total; we should be able to acquire enough from others in the realm to support our drive.$B$BIf you have the sixty pieces of wool cloth on you and are ready to donate them, I''m able to take them from you now.'
WHERE `entry` = 7792;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wonderful! We thank you for your generous donation, $N!',
    `RequestItemsText` = 'As with most other fabrics, our stocks of silk are at an all-time low.  Our stores are such that we''d only need sixty pieces of silk from you total; we should be able to reach our goal with the support of others.$B$BA benevolent gift such as silk, might I add, would certainly increase your local standing in the community!  If you have the sixty pieces of silk cloth on you and are ready to donate them, I''m able to take them from you now.'
WHERE `entry` = 7793;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wonderful! We thank you for your generous donation, $N!',
    `RequestItemsText` = 'Mageweave is running low, and we could use your help to replenish our stocks!  By counting on the community as a whole, we would only need a donation of 60 pieces of mageweave cloth from you to enable us to reach our goal.  Such generosity would not go unnoticed by Stormwind, I assure you!$B$BIf you have the sixty pieces of mageweave cloth on you and are ready to donate them, I''m able to take them from you now.'
WHERE `entry` = 7794;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Fantastic - these will go right to use, I assure you. Thank you again for your assistance! We''d certainly be lost without you.$B$BWith all the donations you''ve made, I would certainly process any additional runecloth donations you care to make in the future. Just be sure to check in with me, and I''ll personally make sure that your good deeds won''t go unrecognized!',
    `RequestItemsText` = '$N, you''ve been a tremendous contributor to our cloth drive. As we work hard to replenish our reserves, one form of cloth remains critically low - runecloth. We are in absolutely dire need of it, and we hope that you will be able to help us as you have in the past!$B$BIf you are willing, please bring me what runecloth you can spare. We''ll initially accept a single donation of sixty, and then we''ll go from there.'
WHERE `entry` = 7795;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N - without heroes like you working on behalf of the tribe, we''d surely suffer. Thank you for your continued efforts!',
    `RequestItemsText` = 'Whenever you are ready to hand in the stack of runecloth, I''ll accept it.'
WHERE `entry` = 7796;

