UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. Your exploits in Warsong Gulch ring throughout Ashenvale Forest.',
    `RequestItemsText` = ''
WHERE `entry` = 7888;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great! These will work great! They''re not too heavy, but not too light either. They''re perfect for building muscle mass!$B$BThanks much, $N. Here''s your Darkmoon Faire ticket!',
    `RequestItemsText` = 'It takes a lot of work to be the strongest woman alive!  My weight set is getting too light and if I''m too stay fit then I''ll need more weights!$B$BDo you think you could bring me some weight stones?  If you do, then I''ll give you a Darkmoon Faire ticket.'
WHERE `entry` = 7889;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You brought the stones! And they''re heavy! I can already feel my muscles getting bigger. Thanks $N!$B$BHere, take these tickets, and be sure not to eat too many sweets while your at the faire. A big strong $C like you needs to keep himself in fighting shape!',
    `RequestItemsText` = 'To help with my workout, I like to fit a staff between heavy grinding stones, then lift the staff over my head. It isn''t easy, but being the strongest woman in the world, like I am, can''t be earned sitting down!$B$BCan you help me? I need more grinding stones - bring me some and I''ll trade Darkmoon Faire tickets for them.'
WHERE `entry` = 7890;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thanks much, $N. Here''s your Darkmoon Faire tickets!',
    `RequestItemsText` = 'I''m working on a new costume, for when I have my own booth as the strongest woman alive! Right now I''m looking for some bracers I can wear. They can''t cover much because people want to see my muscles, but I still want to flash a little color, you know?$B$BHow about green iron bracers, $N? Can you make me green iron bracers? If you can, then I have a whole bunch of Darkmoon Faire tickets for you.'
WHERE `entry` = 7891;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thanks much, $N. Here''s your Darkmoon Faire tickets!',
    `RequestItemsText` = 'For my act as the strongest woman alive, I plan to accept items from the audience and smash them with a big, black mace!$B$BCan you make me a big black mace, $N?'
WHERE `entry` = 7892;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thanks much, $N. Here''s your Darkmoon Faire tickets!',
    `RequestItemsText` = '$N, in my quest to become the strongest woman alive, I have traveled the world and learned muscle building secrets from distant weight masters, strength gurus, and ancient manuals. I now know forbidden exercises that would kill the weak and cripple the uninitiated!$B$BThese feats of strength and conditioning require training with the densest of grinding stones. $N, can you find or make some grinding stones and bring them to me? I''ll give you tickets if you do...'
WHERE `entry` = 7893;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Aha! The modulators! Superb!$B$BI can''t tell you exactly what we''re building, but these will be invaluable for its construction. I am in your debt, Grimling, but please, take this Darkmoon Faire ticket as a token of my appreciation.',
    `RequestItemsText` = 'Yebb is developing a new attraction for the Zoo Bizarre, one that will drive people crazy with wonder, and delight! But it will take a lot of work, and a lot of materials...$B$BThat includes copper modulators. We need lots of modulators for the mechanical parts of the attraction. Bring me copper modulators and I''ll trade for them with a Darkmoon Faire ticket.'
WHERE `entry` = 7894;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You brought the gizmos! Wonderful! Even now I can hear their buzzing, whirring chorus in my mind! Oh, when this booth is ready it will be the wonder of the world, mark me!$B$BHere are your tickets, $N. And please enjoy your stay at the Faire!',
    `RequestItemsText` = 'My new booth will be a sight to see, yes sir! A sight to see, and... for a lucky few, to touch!$B$BI can already hear the whirring bronze gizmos singing their song of mechanical rapture as patrons step to my booth and test their skill!$B$BAh... now I need the gizmos themselves to bring my dream closer to fruition. Please, $N, bring me whirring bronze gizmos... and Darkmoon Faire tickets will be yours!'
WHERE `entry` = 7895;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You brought the fireworks. Wonderful work, $N! I can''t wait to light these and tell the world that my booth is ready to go! I must still wait, quite a long time I''m afraid, but... I''ll be ready when I''m ready, yes?$B$BHere are the tickets, $N. Enjoy yourself!',
    `RequestItemsText` = 'When I finally get this booth up and running, I''ll want to advertise! And what better way is there to advertise than with fireworks?$B$BWell, some might think that the smell of a cauldron, churning with the boiling heads of your foes is better for drawing crowds, but... we''re in mixed company. So fireworks it will have to be!$B$BBring me green fireworks, $N, and I have a big fistful of Darkmoon Faire tickets for you.'
WHERE `entry` = 7896;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you! Now I can get to fixing things.$B$BIt''s going to take a lot of repair kits and a lot of late nights to get everything in working order. Sometimes I think it''d be better to get back to my roots and restart my career as a headhunter, but... the Faire has been good to me.$B$BTake these tickets, $N, and have fun!',
    `RequestItemsText` = 'The biggest reason I can''t open up my booth is that... everything''s broken! I need mechanical repair kits to fix all this stuff!$B$BCan you bring me those kits, $N? I''ll trade you... kits for Darkmoon Faire tickets. What do you say?'
WHERE `entry` = 7897;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, thank you, $N! Yebb will enjoy these widgets. I don''t know what he has planned for them, but Yebb''s a clever little gnome. He''s clever, and maybe a little devious....$B$BIf only he liked the taste of humanoid flesh... he''d make a great troll!$B$BHere, $N. A deal''s a deal, and these tickets are yours.',
    `RequestItemsText` = 'Yebb Nebblegear, like me, is working on a future attraction. So amazing is this attraction, says Nebb, that it will draw folks from across the world... and it will make us all very, very rich!$B$BHe says he needs thorium widgets for its construction, and wants me to collect them for him. So what do you say, $N? Do you know where to get Thorium widgets? If you''re an engineer, can you make them? Do you want to trade them for Darkmoon Faire tickets?'
WHERE `entry` = 7898;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great, you got them! We can use these to make toys and baubles, and those will attract more people to the Faire!$B$BHere''s your ticket, $N. You earned it!',
    `RequestItemsText` = 'The first lesson in drawing a crowd is: lure them with gadgets and trinkets! Can you help me?$B$BI need small furry paws to use for prizes. You can find those on the cats of the Barrens or Darkshore....$B$BBring me some paws and I''ll trade you a Darkmoon Faire ticket for them.'
WHERE `entry` = 7899;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Nice pelts, $N! I''ll get someone to sew these into a bunch of plush toys. With a little stuffing and some paint, I think they''ll be the envy of children across Azeroth!$B$BTickets? Ah yes, your payment!$B$BHere they are!',
    `RequestItemsText` = 'Children love toys! And no matter what race, I''ve found that all children love furry, plushy toys made from torn bear pelts!$B$BYou can get those pelts from the bears of Ashenvale or Hillsbrad. Bring me a heap of them and earn yourself a heap of Darkmoon Faire tickets!'
WHERE `entry` = 7900;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N! These tails will make great prizes for our visitors, and that means happy visitors... who talk to their friends and bring more visitors!$B$BHere are your tickets! Have a good time at the Darkmoon Faire... and don''t forget to tell your friends about us!',
    `RequestItemsText` = 'It''s amazing what people value! Take, for instance, a wooden stick with a soft bushy tail attached to it. Now, you and I might think something like that isn''t all that valuable... but if you give that piece of junk a neat name like "Savage Fuzz Tail" and put it in a pretty box, then people will think it''s valuable. Trash becomes treasure!$B$BGet me soft bushy tails from the wolves of Desolace and the Badlands, and I''ll give you Darkmoon Faire tickets.'
WHERE `entry` = 7901;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, the plumes! They are amazing, don''t you think! It would be easy to spark one''s imaginations with such beauties!$B$BYou do such charitable work, $N. The smiles on our visitors'' faces when they see the show is a grand payment indeed, but please take these tickets as well.',
    `RequestItemsText` = 'A person''s imagination is an incredible thing. It can make the smallest hill seem like the largest mountain. It can make the most innocuous shadow appear cast by a horrible nightmare!$B$BWe at the Darkmoon Faire let our visitor''s imaginations blossom! But to help stretch their imaginations... sometimes we have to get tricky.$B$BI need vibrant plumes for one of my attractions. You can get them from the birds of the more dangerous areas of Azeroth. Bring me the plumes and many tickets will be yours!'
WHERE `entry` = 7902;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great!  You got the eyes!  I hope hunting those bats was frightening for you, because if it scared a brave $C like yourself, then those eyes will certainly scare our Faire visitors.$B$BTake these tickets, $N, and thank you for your service.',
    `RequestItemsText` = 'Do you ever find yourself wandering in a cave, late at night, looking for adventure? You do? Really? Well, then you''ve seen the creepy eyes of bats staring at you from high up, waiting for you to let down your guard so they can suck your blood!$B$BScary thought, don''t you think? Of course! It''s no doubt that bat eyes are scary!$B$BWill you bring me some evil bat eyes, $N? I want them for... something I''m designing. Something scary.$B$BYou can get them from the bats of the Eastern Plaguelands.'
WHERE `entry` = 7903;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Welcome to the Darkmoon Faire! This voucher is good for FIVE, yes, FIVE prize tickets!$B$BWhen you accumulate prize tickets, you''ll want to speak to me about redeeming them for valuable prizes. The more tickets you get, the more prizes you can win. Huzzah!',
    `RequestItemsText` = 'Yes friend, may I help you? Do you have a voucher that needs redeeming?'
WHERE `entry` = 7905;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well this explains a lot. If you ever find a way into Ahn''Qiraj, keep an eye out for ol'' Brann. I''m afraid that he''ll be powerless without his monkey.',
    `RequestItemsText` = 'Oh dear.'
WHERE `entry` = 7907;

