UPDATE `quest_template` SET
    `OfferRewardText` = 'So you have put together a deck of Portals. Your gesture of returning it to us will create a tie between you and the Darkmoon that will not soon be forgotten. Allow me to present you with one of the greater darkmoon cards as a small token of our appreciation.',
    `RequestItemsText` = 'I see that you have managed to complete a deck of portals! Congratulations!'
WHERE `entry` = 7927;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So you have put together a deck of Warlords.   Your gesture of returning it to us will create a tie between you and the Darkmoon that will not soon be forgotten.   Allow me to present you with one of the greater darkmoon cards as a small token of our appreciation.',
    `RequestItemsText` = 'I see that you have managed to complete a deck of warlords!   Congratulations!'
WHERE `entry` = 7928;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So you have put together a deck of Elementals. Your gesture of returning it to us will create a tie between you and the Darkmoon that will not soon be forgotten. Allow me to present you with one of the greater darkmoon cards as a small token of our appreciation.',
    `RequestItemsText` = 'I see that you have managed to complete a deck of elementals! Congratulations!'
WHERE `entry` = 7929;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here you go, here you go! A prize fit for a king! Congratulations to you, my friend!$B$BIf you have more tickets you''d like to turn in, then please let me know! For as long as the Darkmoon Faire is here, I''ll redeem your tickets.',
    `RequestItemsText` = 'Step right up, step right up! If you have tickets from the Darkmoon Faire you''d like redeemed, then just say so! You can redeem tickets in various denominations for wondrous and fantastic prizes. Don''t be shy, give it a try!'
