UPDATE `quest_template` SET
    `OfferRewardText` = 'Thanks much, $N. Here''s your Darkmoon Faire tickets!',
    `RequestItemsText` = '$N, thank you for all the help you''ve given me. I really can''t thank you enough!$B$BAlthough my need is no longer great... if you bring me more dense grinding stones, I still have more Darkmoon Faire tickets for you.'
WHERE `entry` = 7939;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here you go, here you go! A prize fit for a king! Congratulations to you, my friend!$B$BIf you have more tickets you''d like to turn in, then please let me know! For as long as the Darkmoon Faire is here, I''ll redeem your tickets.',
    `RequestItemsText` = 'Step right up, step right up!  If you have tickets from the Darkmoon Faire you''d like redeemed, then just say so!  You can redeem tickets in various denominations for wondrous and fantastic prizes.  Don''t be shy, give it a try!'
WHERE `entry` = 7940;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There you are, $N.  A fair trade.  Enjoy.',
    `RequestItemsText` = '$N, I must thank you for all your help.  I have plenty of supplies, through no small efforts on your part, but if you wish to bring me more armor kits, then I will gladly trade them for Darkmoon Faire tickets.'
WHERE `entry` = 7941;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here you are, $N. Here are Darkmoon Faire tickets for your enjoyment. Do not, as they say, spend them all in one place!',
    `RequestItemsText` = '$N, you have been so good to us, bringing me goods without tiring. You have my eternal thanks!$B$BAlthough our need for Thorium widgets is not as great as it was, you may still bring them to me and I will gladly trade them for Darkmoon Faire tickets.'
WHERE `entry` = 7942;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thanks again, $N.  Here are your tickets!',
    `RequestItemsText` = '$N, the attraction I''m designing will be the scariest event since Gnomeregan was overrun! And it''s largely thanks to you and all the baubles you''ve brought me. Many, many thanks!$B$BI don''t need much else, but... if you bring me more evil bat eyes from the bats of the Eastern Plaguelands... I might have more Darkmoon Faire tickets for you.'
WHERE `entry` = 7943;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A quick search of the chest reveals a lockbox from within it!  It would seem that you have found your fortune!',
    `RequestItemsText` = 'This chest looks like the one from your vision...'
WHERE `entry` = 7944;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A quick search of the tree stump reveals a lockbox from within it!  It would seem that you have found your fortune!',
    `RequestItemsText` = 'This tree stump looks like the one from your vision.'
WHERE `entry` = 7945;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N.  Here is your egg!  It won''t be ready to hatch for a little while, but when it does you''ll have a great pet!',
    `RequestItemsText` = 'I''m so happy Jubjub is no longer lost. She loves Dark Iron ale so much that when I ran out... she ran away to find more!$B$BNow that Jubjub''s back, I want as much ale as I can get! I won''t want her to run away again!$B$BDo you have any Dark Iron Ale? If you do, then I''ll trade you one of Jubjub''s frog eggs for a mug...'
WHERE `entry` = 7946;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here you go, here you go! A prize fit for a king! Congratulations to you, my friend!$B$BIf you have more tickets you''d like to turn in, then please let me know! For as long as the Darkmoon Faire is here, I''ll redeem your tickets.',
    `RequestItemsText` = 'Step right up, step right up! If you have tickets from the Darkmoon Faire you''d like redeemed, then just say so! You can redeem tickets in various denominations for wondrous and fantastic prizes. Don''t be shy, give it a try!'
WHERE `entry` = 7981;

UPDATE `quest_template` SET
    `OfferRewardText` = '',
    `RequestItemsText` = ''
WHERE `entry` = 8001;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hail, $C. I am Jin''rokh the Breaker, troll of Mugamba. We of the Zandalar tribe recognize your accomplishments. We salute your tenacity and strength of will.$B$BWear this talisman around your neck, $C. Let the strength of Mount Mugamba flow through your being. Be empowered as you strike down our enemies!',
    `RequestItemsText` = ''
WHERE `entry` = 8041;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Our paths will cross again, $C.',
    `RequestItemsText` = 'It is good to see you in good health, $N. The glorious battles you have undertaken affect all life on this planet. Hakkar must never leave the confines of Zul''Gurub as the world will surely collapse beneath his immense hunger.$B$BGive me your talisman and I shall amplify its strength. Use the Strength of Mugamba to punish our enemies!'
WHERE `entry` = 8042;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Use your newfound strength to destroy the Gurubashi!',
    `RequestItemsText` = 'Master $N, you return! Molthor has sent word of your deeds to the King. Your name is known even in the South Seas. Perhaps one day you will be a legendary $C - a story for the ages.$B$BGive me your talisman so that I may once more amplify its power.'
WHERE `entry` = 8043;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Zul''jin would be envious, $C. Go forth and conquer!',
    `RequestItemsText` = 'King Rastakhan sends his regards, Master $N. Such an honor has never been given to one outside the Zandalar tribe.$B$B<Jin''rokh bows.>$B$BGive me your talisman so that I may enhance it once more. Know that the Rage of Mugamba is now intrinsically connected to your very soul.'
WHERE `entry` = 8044;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Know this, heathen: A catastrophe has brought us together. Your pagan ways are neither understood nor appreciated by Zandalar but we are a fair people. Wear this brand around your neck. It shall serve as both a warning to our enemies and a symbol of your friendship to Zandalar.$B$BContinue to serve our people and I will amplify the power of the brand.',
    `RequestItemsText` = ''
WHERE `entry` = 8045;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Do what you must to defeat our enemies, $C. Even if it means channeling the Light.$B$B<Jin''rokh shudders.>',
    `RequestItemsText` = 'I may have been too hasty in my judgement, $C. It seems as if your blind faith in this Light has some value after all.$B$BGive me your brand and I shall amplify its power.'
WHERE `entry` = 8046;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Our beliefs differ but our cause is righteous. Strike down our foes, noble $C.',
    `RequestItemsText` = 'I must confess, I did not think you had the resolution to see this cause through, $C. Zandalar now considers you an invaluable ally. Well done, indeed.$B$BGive me your brand and I shall once more amplify its power.'
WHERE `entry` = 8047;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Vigilance, honor, loyalty, bravery... You embody all of these traits and so shall your brand.',
    `RequestItemsText` = 'The King has acknowledged your existence, $C. You are the first of your kind to be accepted by Rastakhan as a true ally of Zandalar.$B$BYou will be rewarded greatly for your efforts. Present your brand and I shall apply the final amplification.'
WHERE `entry` = 8048;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Accept this talisman as a token of our appreciation,  priest.$B$BThe Eye of Zuldazar will grow in power as your bond with the trolls of Zandalar strengthens. Return to me periodically and I shall imbue the jewel.',
    `RequestItemsText` = ''
WHERE `entry` = 8049;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Be resolute in your endeavors, $N. The Soulflayer will attempt to siphon your will to live.',
    `RequestItemsText` = 'Tales of your battles against the Gurubashi are whispered in the winds, priestess. Even royalty is beginning to talk of your deeds. It is rumored that King Rastakhan even mentioned you by name.$B$BThe time has come to imbue the Eye. Hand me the talisman and I shall perform the service.'
WHERE `entry` = 8050;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Continue in your battle against the Soulflayer and his minions, $N. He must never be permitted to leave the confines of Zul''Gurub.',
    `RequestItemsText` = 'Welcome $C. The Eye of Zuldazar pulses with energy. You are ready to take the next step. Hand me the talisman and I shall perform the imbue.'
WHERE `entry` = 8051;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Smite them all and let Hakkar sort them out...',
    `RequestItemsText` = 'If only we had ten-thousand more like you, $N. The armies of Hakkar would be scattered to the wind in the blink of an eye.$B$B<Al''tabim sighs.>$B$BAlas, the Eye is ready to realize its full potential. Give it to me.'
WHERE `entry` = 8052;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You do much to honor us.  Your hands drip with the blood of Hakkar''s minions.  You are a friend to the tribe.$B$BWear these bracers.  They are the freethinker''s armguards.  This is what I mean about real power.',
    `RequestItemsText` = 'You have returned?  Do you have the Paragons of Power?  Are you wasting my time?$B$BI hope not, heathen.'
WHERE `entry` = 8053;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your honor is assured in the tribe.  You claim many deaths in Zul''Gurub.  Enemies fall before your convictions.  Enemies fall before your power.$B$BThis is the freethinker''s belt.  It is a symbol of honor.  It is powerful mojo.  It is now yours.',
    `RequestItemsText` = 'Your presence means victory?  Do you have the Paragons?  Are you dripping in the remains of your enemies?'
WHERE `entry` = 8054;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done what few ever could.  You have brought the minions of Hakkar to their knees.  You have shown them what a freethinker can do.  You have shown us how a heretic could be revered in the tribe.  You have more than real power.  You ARE real power.$B$BTake the breastplate, freethinker.  Crush those who oppose you.',
    `RequestItemsText` = 'Do you have the Paragons?  They have mojo inside them.  We must have them.  You will aid us.'
WHERE `entry` = 8055;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It seems ya got a bit of the Zandalar augur in ya.  We know about the deeds you''ve been doin'' in Zul''Gurub on our behalf mon.  These Paragons of Power will go a long way to helpin'' out the Zandalar tribe - a tribe, I might add, ya can call upon as friends.  Take these bracers, $N; ya earned them and then some!',
    `RequestItemsText` = 'Got the Paragons of Power from Zul''Gurub that I need?  These bracers are well worth any effort ya be needin'' to make!'
WHERE `entry` = 8056;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, I can sense the power comin'' from these Paragons of Power, $N.  Ya proved to be someone we in the tribe can call "friend."  A deal is a deal, $N... behold the power of the haruspex''s bracers!',
    `RequestItemsText` = 'Have ya got the Paragons of Power from Zul''Gurub?  These bracers are worth the effort, $N.  Trust me mon!'
WHERE `entry` = 8057;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have wrought much vengeance today.  You have taken on the visage of the vindicator.  You have brought the Blood God''s minions to their knees.$B$BTake this.  It will fuel your vengeance for the future.  You are a friend to the Zandalar now.',
    `RequestItemsText` = 'Have you brought the Paragons of Power?  Has vengeance been claimed in the name of the Zandalar?'
WHERE `entry` = 8058;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done... no doubt they were made to pay in excruciating ways before they gave up the Paragons of Power.  Take this - the demoniac''s wraps.  Made from powerful mojo used in summoning the demoniac''s prey, it is a powerful tool in your acquisition of power.',
    `RequestItemsText` = 'Have you returned with the Paragons of Power?  By defeating the diabolic minions of the Hakkar, you will not only prove yourself to us, but also your willingness to learn the ways of the demoniac.'
WHERE `entry` = 8059;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Impressive... could you feel the mojo flowing through them?  The Paragons of Power were used as currency of sorts back when the Gurubashi Empire ruled these lands.  Now we Zandalar will use the latent mojo inside of them to fight the second rise of the Blood God Hakkar!$B$BYou''ve done well today - consider yourself to have a friend in the Zandalar.  For that, here are the illusionist''s wraps I promised!',
    `RequestItemsText` = '$N - you''ve returned already?  Were you able to get the Paragons of Power I need?'
WHERE `entry` = 8060;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Outstanding, $N!  This was no small feat bringing these to me.  No doubt you''ve acted as our tribe''s confessor today in preserving ourselves against the threat of Hakkar.  These wraps are befitting a friend of the tribe such as you!',
    `RequestItemsText` = 'Back from Zul''Gurub, are you?  Have you succeeded in retrieving the Paragons of Power from the minions of Hakkar?'
WHERE `entry` = 8061;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes... I need no vision to sense the presence of the Paragons of Power.  Your success in Zul''Gurub has impressed many among the tribe.  We not only consider you to be a friend of the Zandalar, but also consider you worthy enough to possess the predator''s bracers - powerful items, and a symbol of what it means to be a predator.  Well done, $N.',
    `RequestItemsText` = 'Hunt those in Zul''Gurub that would possess the Paragons of Power, $N.  They are your prey; they possess that which we both must have.'
WHERE `entry` = 8062;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N... your accomplishments in Zul''Gurub have earned you the right to call the Zandalar tribe as a friend.  I will see to the disposition of the Paragons; for your effort please accept this reward!',
    `RequestItemsText` = 'Seek the madness from within Zul''Gurub and overshadow it with your own, $N!  To do so means success, and success means reward!  Let not the Blood God reign supreme again!'
WHERE `entry` = 8063;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I thank you - the latent power in these items will be treasures unto themselves, you betcha.  Not only have ya done as I''ve asked of ya, but you''ve also proven to be honorable to us here in the tribe.  As promised, here is your reward!',
    `RequestItemsText` = 'Got the Paragons of Power from Zul''Gurub I need?  The haruspex''s belt will be yours if ya have them.'
WHERE `entry` = 8064;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Impressive... you''ve successfully collected the required Paragons of Power, $N.  Your accomplishments in Zul''Gurub for the Zandalar are legendary; hence forth, you''ll be revered amongst the tribe.  Here is your tunic, mighty $C!',
    `RequestItemsText` = 'Got the necessary Paragons of Power from Zul''Gurub?  The haruspex''s tunic is well worth any effort ya be needin'' to make.'
WHERE `entry` = 8065;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I sensed your arrival moments before, $N, but none too easily.  What revealed yourself to me were the Paragons of Power you brought.  I can feel the power without needing to see the trinkets; their latent mojo - raw magic, if you will - will continue to fuel our efforts of vanquishing the diabolic schemes of the Blood God Hakkar.$B$BYou are to be commended - and rewarded - for your success.  You are honored amongst the tribe, and you are worthy to wear the predator''s belt.',
    `RequestItemsText` = 'Strike at the insane minions of Hakkar in Zul''Gurub - they are the ones that hold the Paragons of Power, $N.  Prove your success to them - and to the tribe - as an aspirant to the predator.'
WHERE `entry` = 8066;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Success... you are to be revered amongst the tribe, $N.  It was no small feat acquiring the Paragons of Power needed for the mantle, but you handled it in the fashion of the deadliest of our predators.  You''ve earned your place amongst them, and you''ve certainly earned the right to wear their mantle.',
    `RequestItemsText` = 'Have your strikes into Zul''Gurub yielded success, $N?  Only when you''ve brought me what I seek - and proven yourself fully to the tribe - will you earn a mantle second to none amongst the Zandalar.'
WHERE `entry` = 8067;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Success!  You shall be honored in the tribe from here on!  Zul''Gurub has certainly tasted the might of the Zandalar today, thanks to you $N.$B$BWith the tribe''s blessing, take the Zandalar illusionist''s mantle.  May it serve you well.',
    `RequestItemsText` = 'How was your foray into Zul''Gurub?  Did you drive your enemies mad through the power of illusion?  Illusion or not, their deaths - and the Paragons of Power taken from them - will help thwart the rise of Hakkar.'
WHERE `entry` = 8068;

UPDATE `quest_template` SET
    `OfferRewardText` = 'At last, someone worthy to wear the illusionist''s robe!  Your success in Zul''Gurub has assured your reverences amongst the tribe for ages to come.  Wear it with pride, $N!',
    `RequestItemsText` = 'Have you returned with the Paragons of Power we need?  I know it will not be easy... but I have long predicted an outsider would come to aid us in our fight against Hakkar.  Let it be you, I say!'
WHERE `entry` = 8069;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Success!  These will go a long way to building up our power against the rise of Hakkar.  With your help, we''ve taken a significant step in ensuring that the Blood God will not destroy us all.$B$BYou''ve earned honor with the tribe today, $N.  Take this - the confessor''s bindings - as a symbol of our thanks.',
    `RequestItemsText` = 'The Paragons of Power... do you have them?  Only when we have them will we be able to make use of the latent power stored inside them.  It will be good to turn the tables on the minions of the Blood God...'
WHERE `entry` = 8070;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N - the minions of Hakkar have surely felt the retribution of the Zandalar today, thanks to you.  Your actions have given you a permanent place of reverence within the tribe.  With our blessing, please take this confessor''s mantle as your own!',
    `RequestItemsText` = 'Do you have the Paragons of Power from Zul''Gurub?'
WHERE `entry` = 8071;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Victory is ours this day, thanks to the madness you have sowed upon our mutual enemies!  You are to be honored amongst the Zandalar, and there is no better way of showing gratitude for your deeds than by offering you the madcap''s mantle!',
    `RequestItemsText` = 'You''ve returned - do you have the Paragons of Power I need?$B$BThe legend of Khar''vaxal the Cracked serves us today as a reminder that no foe - no matter how great a threat they may be - is impossible to overcome.  Chaos will bring everyone to their knees, that much is certain... and perhaps the most non-chaotic elements of chaos.'
WHERE `entry` = 8072;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Impressive... you have accomplished today what few thought was possible.  Your reverence in the tribe is assured for a lifetime, $N.  You have earned the right to don the madcap''s tunic - do so with our blessing.',
    `RequestItemsText` = 'Welcome back to the Isle, $N... have you returned triumphantly with the Paragons of Power in tow?'
WHERE `entry` = 8073;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I can smell the scent of vanquished evil on ya, $N.  It''s a sweet smell mon... one I think you know quite well.$B$BI know it''s no small feat to have brought me the Paragons of Power required for the belt.  Your deeds have not only honored the tribe, but also honored yourself amongst my tribe.  Here ya are - take the augur''s belt and don it as your own!',
    `RequestItemsText` = 'The Paragons of Power are what I need mon - we''ll tap the power right out of them in our fight against the evil from Zul''Gurub.  Do ya have them for me?'
WHERE `entry` = 8074;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I know what ya had to go through to bring me the Paragons of Power, $N.  It wasn''t easy, mon - defeatin'' the evil that seeps out of Zul''Gurub like a foul ooze - but now that it is all said and done, I can easily say that you''ll be revered amongst the Zandalar for ages to come!$B$BHere - take the augur''s hauberk and wear it with pride!',
    `RequestItemsText` = 'The Paragons of Power are a key source of magic power - the same kind of power that goes into makin'' the augur''s hauberk.  Bring me what I need, and I''ll be able to share the finest of vestments any Zandalar augur would be wantin'' as their own.'
WHERE `entry` = 8075;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N.  The Paragons of Power from Zul''Gurub should act as a reminder of wasted power.  The Gurubashi were strong at their height, but they allowed themselves to be consumed by it.  A demoniac knows that the game they play is much similar, but the power unleashed is often the very thing needed for survival.$B$BUse this mantle as an honored ally of the Zandalar... it will serve you well.',
    `RequestItemsText` = 'Retrieved the Paragons of Power from Zul''Gurub?  While we will take the latent power from these items and make them our own, we will give you your own reward of power should you be successful...'
WHERE `entry` = 8076;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Impressive - your victory in Zul''Gurub has assured us - nay, the world - that Hakkar will not prevail.  The time may come when you face the Blood God directly... and should this come to pass know that your reverence is assured amongst the Zandalar tribe.$B$BOh, and this simple robe should help out too I think.$B$B<Al''tabim winks knowingly at you.>',
    `RequestItemsText` = 'The Paragons of Power... you have returned with them?  Only once we have them will we share the ultimate symbol of demoniac power with you, $N.'
WHERE `entry` = 8077;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The way of the vindicator is now known to you.  You have brought honor to the tribe.  You have brought honor to yourself.  You have brought pain to our enemies.$B$BThe vindicator''s belt is yours.  You are surely becoming one with the way of the vindicator.',
    `RequestItemsText` = 'Have you brought the Paragons of Power?  Have you struck down the enemies of the tribe?  Hakkar must know the wrath of the vindicator!'
WHERE `entry` = 8078;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You are to be revered for your deeds.  The tribe rewards its heroes.  Zul''Gurub has tasted Zandalar vengeance like never before.$B$BYour deeds will herald the deeds of others to come.  They will look upon you as a sign of real power.  They will look upon you as vengeance personified!',
    `RequestItemsText` = 'Your presence means victory?  Do you have the Paragons of Power?  Tell me of the vengeance you have wrought today!'
WHERE `entry` = 8079;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You got the Mark! Great job! I''ll send the ressources to our quartermasters, who can quickly disperse them to our troops.$B$BThank you, $N. Indeed, performing successful missions like the one you achieved are how wars are truly won.',
    `RequestItemsText` = 'Do you have the Marks of Honor, $N? The League of Arathor can''t fight a decent battle without them...'
WHERE `entry` = 8080;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good. I will get these to our quartermasters immediately, and a commendation for your actions will be sent to my superiors.$B$BOnce again, thank you $N. Your contributions to our struggles are noticed by footman and field marshal alike.',
    `RequestItemsText` = '$N, the League of Arathor has a standing mission for you to reenter Arathi Basin, procure more resource crates and bring them to me.'
WHERE `entry` = 8081;

UPDATE `quest_template` SET
    `OfferRewardText` = '$R, the pebble held within the frame of this talisman comes from Mount Kajaro in the South Seas. Mount Kajaro is an area plagued by volatility - marked by violent and oftentimes magical volcanic eruptions.$B$BAs your bond with the trolls of Zandalar grows, so too shall the power of this pebble. Harness the power of the pebble to strike down our enemies. Be like the mountain: Quick, explosive, deadly...',
    `RequestItemsText` = ''
WHERE `entry` = 8101;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Be unstoppable, like the molten fronts of Kajaro.',
    `RequestItemsText` = 'Welcome back, $C. I can see that the pebble has seen much use. Many of our foes have fallen to your otherworldly abilities. Their suffering has been great. It is time that I enhance the power of the pebble. Give it to me.'
WHERE `entry` = 8102;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Continue in your decimation of the trolls of Zul''Gurub. Hakkar must see that the world will not buckle beneath his indomitable will.',
    `RequestItemsText` = 'Hakkari fear you, $N. They speak of horrors they believed that only their faceless God could perpetrate. You have burned them with the force of Kajaro. They now know fear in two places.$B$BIt is time to further strengthen the pebble. Hand me the talisman.'
WHERE `entry` = 8103;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Al''tabim shatters the pebble with a powerful unseen force.>$B$BDo you see? The pebble is what we call a geode. Inside the pebble are powerful crystals that have been soaking in the latent energies from our world. By cutting the pebble in half, I have finally allowed its full potential to be realized. Use it to lay waste to our enemies.',
    `RequestItemsText` = 'Give me the talisman, $N. I must show you something.'
WHERE `entry` = 8104;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I received reports of your exploits in Arathi Basin, $N.  Well done!  With those like you joining the struggles here, I have faith that we will one day retake our homelands.',
    `RequestItemsText` = ''
WHERE `entry` = 8105;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Accept this talisman, $C. Accept it and use its power to strike down our mutual enemies.$B$BKnow that around your neck you carry a piece of history. Kezan was once a grand territory of the Zandalar Empire. Alas, the taint of goblin trade princes would force out my proud brothers and sisters.$B$BKezan is now home to the goblin capital of the Undermine; but know that before the taint, it held greatness. Still to this day Kezan is considered sacred land to my people.',
    `RequestItemsText` = ''
WHERE `entry` = 8106;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Draw from the darkness, $C. Embrace the shadows. Let Kezan''s Taint supplement your dark meddling.',
    `RequestItemsText` = 'Honor is earned amongst the Zandalar trolls, $N. With honor comes reward - friendship, alliance...$B$BHand me the talisman so that I may enhance its power.'
WHERE `entry` = 8107;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is only through our combined efforts that we will stop the Soulflayer.',
    `RequestItemsText` = 'I am ready for you, $C. Once more I will enhance your talisman. I only ask that you continue in your destruction of Hakkar and his minions.$B$BGive me the talisman.'
WHERE `entry` = 8108;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Flay the flesh from their corpses. Watch as the shadows consume the Hakkari. Draw power from their fear, $C. Let Kezan''s Taint augment this power...',
    `RequestItemsText` = 'Call forth your demons, $C. Let them bask in the energy of Kezan''s Taint. Command them on the field of battle! Decimate the enemy!$B$BYes... The time has come to apply the final enhancement to Kezan''s Taint. Give me the talisman.'
WHERE `entry` = 8109;

UPDATE `quest_template` SET
    `OfferRewardText` = 'See this here seaweed, mon? It be from the South Seas. We just add a little mojo and a little magic and it takes on the properties most suited to its owner.$B$BYou a $C so it be easy, mon. Just wrap it around your neck and think of nature or squirrels or whatever it be that you people like.',
    `RequestItemsText` = ''
WHERE `entry` = 8110;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The neck piece not be for smokin'', mon! You got to use it to fight evil.',
    `RequestItemsText` = 'Hey mon! It be good to see you again. The tribe be talking about your killin'' of the Hakkari and all that. Molthor gave me the word to be adding more mojo to your talisman. Just give it here and Maywiki make it better.'
WHERE `entry` = 8111;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now you take the evil trolls in Zul''Gurub and show them what your nature powers can do, mon!',
    `RequestItemsText` = 'How be that talisman, mon? It look like it be time to add a little more magic and mojo to its leaves. It need a little bloom in its wilt. Give it here and Maywiki fix it right up.'
WHERE `entry` = 8112;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N mon, it been a good journey. Keep on with the killing and suppressing of Hakkar and he minions.',
    `RequestItemsText` = '$N! It been a long time since I seen you. Did you know that King Rastakhan himself be givin'' me the order to add the final bit of mojo and magic to your talisman? It be true, mon! I wouldn''t have believed it had I not seen it with me own eyes. Give it here.'
WHERE `entry` = 8113;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good work, $N!  An excited scout came to me with a report of your exploits.  We in the League of Arathor are very pleased!$B$BYou are swiftly becoming a local hero among the soldiers in the League, and today''s deed once again proves your sterling reputation.',
    `RequestItemsText` = 'You have not yet taken four bases, $N. Return to Arathi Basin and do as you have been tasked!'
WHERE `entry` = 8114;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You did it!  You took all of the bases! Well done, $N!$B$BThere were those who doubted your chances, but I knew you could do it. Thank you, and know that the League of Arathor holds you in high regard, just as the Defilers of the Forsaken must fear the very mention of your name!',
    `RequestItemsText` = 'You have not yet completed your mission, $N. It is difficult, but my faith in you is strong.'
WHERE `entry` = 8115;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You and Maywiki have something in common, mon. We both be $C! Although, Maywiki is more of a mystic and you be more of a scrub. Still, we both know what the great spirits bring.$B$BAs a gift I give to you this orb to wear around your neck. Look deep inside and see the village of Voodress in the South Seas! Let it lift your spirits!',
    `RequestItemsText` = ''
WHERE `entry` = 8116;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Beware the evil Hakkari spirits, mon. Honestly, they be spooky.',
    `RequestItemsText` = 'Good news, $N. Molthor be singin'' your praises lately. He say how you be turnin'' into a real hero of Zandalar.$B$BHe also say for Maywiki to polish your orb some more! Give it here so Maywiki can brighten the vision.'
WHERE `entry` = 8117;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Take a look at it now, $N. Voodress come in even clearer now, yea? Let the primal power flow through you, mon.',
    `RequestItemsText` = 'Sha-mon! Maywiki make a joke!$B$B<Maywiki laughs.>$B$BSo, you been using the spirits and elements against our enemies in Zul''Gurub, eh? Spirits be praised!$B$BMaywiki gonna brighten your orb. Give it here, $N.'
WHERE `entry` = 8118;

UPDATE `quest_template` SET
    `OfferRewardText` = 'One day, $N, you will be able to use this orb to communicate directly with me. Whenever this battle with Hakkar be over and Maywiki go home. Let us call to the spirits and ask them for that day to come soon.',
    `RequestItemsText` = '<Maywiki points to your talisman.>$B$BLook at it, $N! It''s come alive. The spirits dance around the orb.$B$BGive it to Maywiki so she can make one last adjustment.'
WHERE `entry` = 8119;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A Defiler scout came to me with a report of your success, $N.  Well done.$B$BAs you will learn, to win the battle for Arathi Basin, we must be ever vigilant and crush any attempts at Alliance expansion.  Do this, and our victory here is ensured.',
    `RequestItemsText` = ''
WHERE `entry` = 8120;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good work, $N! Your latest actions in Arathi Basin were quite difficult, and so their successes are quite praiseworthy. The League of Arathor must be reeling from the last skirmishes in the basin, licking their wounds and, let us hope, rethinking their choice to fight here.',
    `RequestItemsText` = 'Return to Arathi Basin, $N, and perform the task for which you were sent to do! Capture and hold four bases!'
WHERE `entry` = 8121;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The cries of the Alliance as you and your compatriots attacked them could be heard even from here, $N. I can almost pity them for the pain and fear you delivered to their ranks. Almost, but not quite.$B$BYour value to the Defilers is without question. Your deeds in Arathi Basin have been most impressive, and have echoed among the chambers of Varimathras... and the Dark Lady herself.',
    `RequestItemsText` = 'Return to Arathi Basin, $N, and perform the task for which you were sent to do! Capture and hold all five bases!'
WHERE `entry` = 8122;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Deathstalker Mortis smiles>$B$BAnother decisive blow has been dealt against our enemies, $N. Thanks to your deeds, Arathi Basin is soon to be taken hold of by the Defilers.',
    `RequestItemsText` = 'What is it, $R? Do you have the Marks of Honor? Go back to Arathi Basin, slay the Alliance vermine and take possession of its ressources for the Dark Lady!'
WHERE `entry` = 8123;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good. I will get these to our quartermasters immediately, and a commendation for your actions will be sent to my superiors.$B$BOnce again, thank you $N. Your contributions to our struggles are noticed by grunt and high warlord alike.',
    `RequestItemsText` = '$N, the Defilers has a standing mission for you to reenter Arathi Basin, procure more resource crates and bring them to me.'
WHERE `entry` = 8124;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You progress swiftly, young $C. Perhaps it is time to initiate you into the Shera Ali''kh - Zandalari for Death''s Hand. For thousands of years we have played the role of assassin for the Zandalar Empire. For too long we have sat idly, allowing the Hakkari to grow in strength. Once more we face Hakkar, but this time without the support of a united $R front. It is you and your allies who must assist in vanquishing the Blood God and his minions!$B$BWear this talisman and let it assist you in your journeys.',
    `RequestItemsText` = ''
WHERE `entry` = 8141;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There is only one enhancement left that can be placed on the talisman, $C. When the time is right, I shall apply that enhancement.',
    `RequestItemsText` = 'Impressive, $N. You have a gift for killing that I have not sensed in another in many years. Even Molthor is aware of the work that you have done for Zandalar. It is time to enhance your talisman further. Give it to me.'
WHERE `entry` = 8142;

UPDATE `quest_template` SET
    `OfferRewardText` = 'An assassin of your caliber should be given a wide berth. Your foes must learn respect! You will get just that when the enemy sees the glint of Death''s Hand - all too late...',
    `RequestItemsText` = 'I sense that you have dealt countless fatalities to the Hakkari, $N. You carry the stink of their mojo.$B$BI assume the Shadow talisman has assisted in the culling? Give it to me and allow me to enhance its power.'
WHERE `entry` = 8143;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is the last time we will speak under the auspices of Shera Ali''kh. You know all that you must. Take the talisman and continue in your slaying. Hakkar must never be allowed to leave Zul''Gurub.',
    `RequestItemsText` = 'It yearns to grow, $N. The talisman has soaked in all that you have done. The thousands of troll corpses littering Zul''Gurub have fueled its power. Hand it to me and I shall make the final enhancement.'
WHERE `entry` = 8144;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Amongst the Zandalarians, the profession of $C is revered. Our greatest hunters travel to the edge of the Maelstrom to prove their resolution.$B$BFrom the heart of the sea they pull strands of kelp known as Maelstrom Tendrils. The kelp is then woven into a talisman that is enchanted to improve their accuracy and power.$B$BI now grant you a single weaving of the Maelstrom''s Tendril. As your bond with Zandalar grows, I shall weave more power into the talisman.',
    `RequestItemsText` = ''
WHERE `entry` = 8145;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There is only one more weave that I will be able to add to your talisman, $C',
    `RequestItemsText` = 'Even from here I can hear the sound of your volleys laying waste to our enemies. Their cries echo in agony.$B$BYou have made quite a name for yourself among the trolls of Zandalar, $N. We are grateful for all that you have done.$B$BHand me your talisman so that I may add another weave.'
WHERE `entry` = 8146;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Let them seek atonement at the end of your munitions.',
    `RequestItemsText` = 'Ah, $N, it is good to smell you again.$B$B<Falthir grins.>$B$BYou''ll have to excuse my sense of humor. It can be most foul at times.$B$BI sense that you have caused great anguish to our enemies. The forces of Hakkar cry out your name in anger. This is most excellent.$B$BYou have earned another weave on your talisman. Hand it to me.'
WHERE `entry` = 8147;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your journey has only just begun, young $C. Perhaps one day you will visit the Maelstrom and glance into the heart of the world.$B$BI wish you power and fortitude!',
    `RequestItemsText` = 'Molthor delivers word from King Rastakhan, $N. The royal court is most impressed with your decimation of the Hakkari forces. I am to award you with the final weave in your talisman. Hand it to me.'
WHERE `entry` = 8148;

UPDATE `quest_template` SET
    `OfferRewardText` = 'He was a hero among heroes, Uther was.  I can''t even begin to imagine the anguish of what he felt when Arthas - his greatest student and someone whom Uther loved like his own son - betrayed all of humanity.  Still, he rose to try and stop Arthas, and for that he will be forever remembered as a true paladin.  His fight was to the end, thinking only of those he might save.$B$BThank you, $N.  You''ve paid tribute to a great hero today, honoring his spirit and the spirit of the Harvest Festival.',
    `RequestItemsText` = 'Have you made the journey to Uther''s Tomb and placed the tribute there?$B$BIt can be a dangerous trip for less experienced adventurers; a safer way of traveling there, relatively speaking, may be to travel north from the river that runs through Hillsbrad into the Plaguelands. It flows from a lake that is adjacent to Sorrow Hill; travel west up through the hills, steering clear of the adjacent tomb... one that is infested with the Scourge.'
WHERE `entry` = 8149;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Grom''s full name - Grommash - means "The Giant''s Heart"; it took that and more to stand alone against Mannoroth.  I think the Warchief said it best when the curse of the orcs began and ended with Grom.  Fitting that Grom''s sacrifice - and perhaps redemption - would be the wellspring from which the Horde flows today.$B$BThank you, $N.  You''ve paid tribute to a great hero today, honoring his spirit and the spirit of the Harvest Festival.',
    `RequestItemsText` = 'Have you made the journey to Grom''s Monument and placed his tribute there?$B$BThe site where the monument is still touched by the taint of the Burning Legion. Should you be less experienced in the ways of adventuring, be on your toes when approaching the monument.'
WHERE `entry` = 8150;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is no longer my purpose to hunt, but to teach the $C.  That is what fate has handed to me.',
    `RequestItemsText` = ''
WHERE `entry` = 8151;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You must possess keen sight and great patience to have obtained these. Well done.',
    `RequestItemsText` = 'Have you found the antlers?'
WHERE `entry` = 8153;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You got the Mark! Great job! I''ll send the ressources to our quartermasters, who can quickly disperse them to our troops.$B$BThank you, $N. Indeed, performing successful missions like the one you achieved are how wars are truly won.',
    `RequestItemsText` = 'Do you have the Marks of Honor, $N? The League of Arathor can''t fight a decent battle without them...'
WHERE `entry` = 8154;

