UPDATE `quest_template` SET
    `OfferRewardText` = 'So, you have been speaking with that old dwarf Ironboot and uncovered the lost Mosh''aru Tablets, have you?  That meddling prospector...$B$BNo matter.  It is too late to save this world.  Hakkar has been reborn, and even now grows in power... deep in the ancient troll kingdom of Zul''Gurub!  He has come!  And he will rule in blood and terror!$B$BThank you, $N.  Your help has sped the return of the Soulflayer!',
    `RequestItemsText` = ''
WHERE `entry` = 8181;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You were sent by the prospector, Ironboot?  His kind are wise, and wiser still to bring you to me, for I and the Zandalarian trolls may know a way to defeat the Soulflayer.$B$BSpeak with the trolls of this isle, heed their words, and prepare yourself, $N, for the task before you is soaked in blood.',
    `RequestItemsText` = ''
WHERE `entry` = 8182;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, the Heart of Hakkar.  So the Soulflayer has been slain!  Our world is saved!$B$B$N, your service to us cannot be overstated.  You truly are a hero of this realm!',
    `RequestItemsText` = '$N, the reek of an evil soul surrounds you.  Have you been cursed by the Soulflayer?'
WHERE `entry` = 8183;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Use it well, $C. Show the Hakkari no mercy!',
