UPDATE `quest_template` SET
    `OfferRewardText` = 'Use it well, $C. Show the Hakkari no mercy!',
    `RequestItemsText` = 'Zanza can create the ancient troll enchantments with the right components.$B$BThe first is a primal Hakkari idol that must be taken from the most powerful of the Hakkari lieutenants: Jin''do and the Bloodlord.$B$BThe second is a punctured voodoo doll. These can be found in the piles of refuse that litter this foul place. Look inside the jinxed hoodoo piles.$B$BBring me these things and I will create a powerful enchantment for you!'
WHERE `entry` = 8185;

