UPDATE `quest_template` SET
    `OfferRewardText` = 'Hurry up and turn those in if you want to be declared the Master Angler!  I have been standing around here for HOURS with nothing to eat!   Hand those suckers over!',
    `RequestItemsText` = 'Today between 2pm and 4pm we have a contest to determine who the greatest angler of them all is!   Just be the FIRST PERSON to bring me 40 Tastyfish fished from the Tastyfish schools found along the coast of Stranglethorn before anyone else does and you will be declared the Master Angler!$B$BIf you are not the first person to bring me 40 fish, my apprentice here will still reward you with money for each 5 Tastyfish you bring her.$B$BOh, and don''t delay, Tastyfish go bad quickly!'
WHERE `entry` = 8193;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This deal works for me if it works for you!',
    `RequestItemsText` = 'Even though we already have a contest winner, I will still buy your Tastyfish from you at a reasonable price.   Whadda ya say!'
WHERE `entry` = 8194;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent - this set of coins will make a fine addition to our growing collection... one that we will use in the tribe''s defense against the rise of the Blood God.  You''ve earned this Honor Token, $N, as well as the thanks of the tribe!',
    `RequestItemsText` = 'I seek the Paragons of Power known as the Coins of the Tribes.  They are the currency used by the various denizens of Zul''Gurub, and each is imbued with subtle but powerful mojo.$B$BThere are nine distinct kinds to be found.  Some are sought after by my compatriots for various armors they offer Zandalar heroes.  Should you have any extra, I will trade you one of our Honor Tokens for a set of three.  You may use the Tokens with Rin''wosho the Trader; he offers our heroes special items for them.'
WHERE `entry` = 8195;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A fair trade, my friend - please enjoy the luscious fruits of the South Seas, with the tribe''s blessing.',
    `RequestItemsText` = 'The extremely potent essence mango grows across many of the islands in the South Seas.  A single mango will refresh those who eat it, both physically and mentally.  If you''ve never had one, you do yourself a disservice!$B$BWe have enough of a supply here on the isle to offer you a handful in exchange for a Zandalar Honor Token.  Speak with Vinchaxa if you need to learn how to get tokens; otherwise, let''s get to the business at hand!'
WHERE `entry` = 8196;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You gained the heads!  You have halted the plundering of our gods'' power, and weakened Hakkar!$B$BYour actions are truly heroic, $N.  May the heads of these troll thralls plead to you for mercy long after their blood chills.',
    `RequestItemsText` = 'Do you have the collection of heads, $N?  We must stop Hakkar from gaining more power!'
WHERE `entry` = 8201;

UPDATE `quest_template` SET
    `OfferRewardText` = '*Whir*$B$BIdentification of Keefer''s Angelfish complete.$B$BYour Reward is now available.$B$B*click-click* *Bzzzz*',
    `RequestItemsText` = '*Whir* *Click*$B$BI seek rare fish for Fishmaster Bluegill to catalogue.   If you bring me a Keefer''s Angelfish, I will provide you with this fine reward.$B$B*Zzzap* *Whir*'
WHERE `entry` = 8221;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great job, $N!  Thanks a lot!  I''m going to make paint from this blood and turn all kinds of cheap junk into glowing treasure!$B$BHere are your tickets, and thanks again!',
    `RequestItemsText` = 'In all my time working the Faire, I''ve learned a lot of things about customers. Here''s one of those nuggets of wisdom: customers love stuff that glows! It doesn''t matter what it is - you could take a broken chair leg and make it glow, and every child will come from miles around to get one!$B$BSo, $N, I need glowing scorpid blood. You can find it from the scorpids of Sillithus, or the Blasted Lands, or the Burning Steppes.'
WHERE `entry` = 8222;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thanks again, $N.  Here are your tickets!',
    `RequestItemsText` = 'That scorpid blood is working out great, $N! It''s amazing how a little sparkle and shine can create a prized bauble out of an otherwise piece of junk. The patrons love the stuff, and love is what it''s all about, don''t you think...$B$BYou''ve been a big help to me, $N, and although I don''t have a great need for more glowing scorpid blood, if you bring me more then I''ll still trade you some tickets.'
WHERE `entry` = 8223;

UPDATE `quest_template` SET
    `OfferRewardText` = '*Whir*$B$BIdentification of Dezian Queenfish complete.$B$BYour Reward is now available.$B$B*click-click* *Bzzzz*',
    `RequestItemsText` = '*Whir* *Click*$B$BI seek rare fish for Fishmaster Bluegill to catalogue.   If you bring me a Dezian Queenfish, I will provide you with this fine reward.$B$B*Zzzap* *Whir*'
WHERE `entry` = 8224;

UPDATE `quest_template` SET
    `OfferRewardText` = '*Whir* Identification of Brownell''s Racer complete. Your Reward is now available. *click* *click* *Bzzzz*',
    `RequestItemsText` = '*Whir* *Click*$B$BI seek rare fish for Fishmaster Bluegill to catalogue.   If you bring me a Brownell''s Blue Striped Racer, I will provide you with this fine reward.$B$B*Zzzap* *Whir*'
WHERE `entry` = 8225;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Why, you found my favorite measuring tape! I love this tape! I measured some of the biggest fish I ever caught with it...$B$BBut, I lost this tape in Zul''Gurub... you''ve been to Zul''Gurub? Did you see the fabled Gahz''ranka?$B$BWell... do you want to catch him?',
    `RequestItemsText` = 'Hello there, laddie. You here to do some fishing?'
WHERE `entry` = 8227;

