UPDATE `quest_template` SET
    `OfferRewardText` = 'The key! I thought it lost forever. Please, take an enchanted garment from my stores -- they are reserved for rogues of exceptional skill and loyalty. It should be known that $N is not to be trifled with!$B$B<Jorach opens the bag and is bathed by a golden glow from within. His eyes widen and he stares...>',
    `RequestItemsText` = 'The bag has already arrived from Archmage Xylem, have you found the key?'
