UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent... each bijou we wrest away from the Blood God''s minions is one step closer we all are to finally defeating them once and for all.  You bring honor to the Zandalar - and yourself - through your noble actions.$B$BRemember $N, you may always destroy the bijous you find in Zul''Gurub at the altar.  For each one, you will gain recognition and an Honor Token!  Just remember to have an open space in your inventory if you don''t have one of the tokens already.',
    `RequestItemsText` = 'Have you destroyed the bijou at the Altar of Zanza?  Do so, and then you will be doubly blessed by Zanza!'
WHERE `entry` = 8240;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There''s always room for more fiery flux, junior. Keep it comin''... unless I tell you to stop.',
    `RequestItemsText` = 'Let''s not waste more of my precious time with jibber jabber, $R. It''s time to focus on replenishing our dwindling fiery flux supply.$B$BWhat I''m gonna need from you is the following:$B$B*Incendosaur scales.$B$B*Iron bars.$B$B*Coal.$B$BI''ll take all that you can offer!$B$BAnd you''ll do it fast if you wanna get in good with the Brotherhood.'
WHERE `entry` = 8241;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There''s always room for more fiery flux, junior. Keep it comin''... unless I tell you to stop.',
    `RequestItemsText` = 'Let''s not waste more of my precious time with jibber jabber, $R. It''s time to focus on replenishing our dwindling fiery flux supply.$B$BWhat I''m gonna need from you is the following:$B$B*Incendosaur scales.$B$B*Heavy Leather.$B$B*Coal.$B$BI''ll take all that you can offer!$B$BAnd you''ll do it fast if you wanna get in good with the Brotherhood.'
WHERE `entry` = 8242;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A fair trade, my friend - please enjoy the blessings of Zanza with our compliments!',
    `RequestItemsText` = 'With your increased status amongst the tribe comes access to some of our more potent potables. Behold... these brews are strong in the mojoŌĆöblessed by Zanza and fit for adventurers from all walks of life!$B$BI will allow you to choose one from the three I offer; in exchange, I require a single Zandalar Honor Token. Note that only the effects of a single one may course through your spirit at any given time.'
WHERE `entry` = 8243;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A fair trade, my friend - please accept your signet with the blessing of the tribe!',
    `RequestItemsText` = '$N - for someone as exalted among the Zandalar as you are, I have something very special for you. Direct from our home in the South Seas... the Signets of the Zandalar! These signets are used to enhance any shoulder item you may possess. Should you seek might, mojo, or serenity - I have what you need!$B$BI ask for fifteen Zandalar Honor Tokens in exchange for your choice of one signet. If you have the tokens ready, then I''m ready to make a deal!'
WHERE `entry` = 8246;

UPDATE `quest_template` SET
    `OfferRewardText` = 'May these knives find a place in someone''s heart.$B$BLiterally.',
    `RequestItemsText` = 'My rogues must sharpen their lockŌĆæpicking craft, and I need Precise Lock Cylinders ŌĆö the sort of highŌĆæprecision mechanisms Zan''s beginner parts can''t challenge.$B$BSeek out Heavy Junkboxes, crack them open, and harvest the Precise Lock Cylinders hidden inside.$B$BReturn 5 Precise Lock Cylinders to me, and I''ll reward you with some of the finest throwing knives ever forged for roguekind.'
WHERE `entry` = 8249;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Sanath sneers at you.>$B$BArch$C Xylem awaits your arrival.',
    `RequestItemsText` = ''
WHERE `entry` = 8250;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N!  It never ceases to amaze me how persuasive a volley of arcane missiles can be.',
    `RequestItemsText` = 'Have you the dust?'
WHERE `entry` = 8251;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is a superb specimen of coral, $N.  Your skills are unquestionably precise and deadly.$B$BDo not think your efforts have gone unnoticed.  Perhaps you are worthy of a true test of your skill...',
    `RequestItemsText` = 'The spitelash sirens are surprisingly adept mages.  Not as adept as you, I hope?'
WHERE `entry` = 8252;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Incredible.  The shard has grown as it absorbed the drake''s energy over the long years.$B$BThere is no more I can ask of you now.  My full ability to forge the arcane has returned with this shard.  My first creation is yours, $N, and you have but to choose...',
    `RequestItemsText` = 'Have you slain my old nemesis?'
WHERE `entry` = 8253;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your arrival has lifted a weight from my shoulders.  We have much to do.',
    `RequestItemsText` = ''
WHERE `entry` = 8254;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is good the divine path has led you to us, $N. Your beliefs do not interfere with the tasks involved in creating this salve.$B$BYou see, the courser is sacred to the Cenarion Circle, and killing them for any reason, no matter how necessary, weakens their spirit.',
    `RequestItemsText` = 'You have returned. Were you successful?'
WHERE `entry` = 8255;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I cannot say I''m pleased to receive such a wretched substance, but it is a necessary evil. Thank you, $N.',
    `RequestItemsText` = 'We must obtain the ichor quickly. Have you found it?'
WHERE `entry` = 8256;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have slain Morphaz and carried his blood to us... I can hardly believe this good news!$B$BWe will combine the ingredients at once and begin healing the trees and creatures of Felwood. It will take a lifetime to undo what has happened here, but you have given us the means to do it.',
    `RequestItemsText` = 'Do you have the blood of Morphaz?'
WHERE `entry` = 8257;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is a victory to savor, $N! The demise of Darkreaver should restore the fragile fetters that anchor the spirit realm.$B$BYou have far exceeded what was asked of you, even when you had no notion of reward or compensation. You are truly a $C of worth, my friend.$B$BI know that acting to preserve the spirit realm should be thanks enough, but please - accept this simple gift with my thanks.',
    `RequestItemsText` = 'Time is critical, $N - have you succeeded in stopping Death Knight Darkreaver''s threat?'
WHERE `entry` = 8258;

