UPDATE `quest_template` SET
    `OfferRewardText` = 'Just as I suspected.  I can decipher individual words in the tablets but they appear to be devoid of any logic or meaning.  It''s not unknown for Twilight''s Hammer sects to use a code to hide the meaning of their texts; we''ll have to go to someone who knows more about this sort of thing.',
