UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, very good. I''ve been working on the medallion - now with these last ingredients, I''ll be done in just a few moments...$B$BThere we are. Here is the medallion, $N.$B$BYou''ll need to wear this when you activate one of the Twilight''s Hammer''s wind stones. Put this on, along with the rest of the twilight trappings, and the Abyssal Council will see you as one of their cultist underlings.',
