UPDATE `quest_template` SET
    `OfferRewardText` = 'Thanks. Just one moment and I''ll have that ring ready for you...$B$BThere it is. Now you''re ready.$B$BBe sure to wear this ring, along with a medallion of station and the rest of the twilight trappings, when you activate a greater wind stone. Do that, and the Abyssal Council will think you one of their servants. Then, perhaps you can lure one into an ambush!',
