UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent, $N!  Defeating those Dukes will leave the Twilight''s Hammer reeling for a while. As promised, here''s your reward. It''s some of the better stuff Huum and I have found.',
    `RequestItemsText` = 'You''ve shown you''re more than capable of taking on an Abyssal Duke, $N. I''m always one to promote good habits. Bring me more signets and I''ll give you a reward.'
