UPDATE `quest_template` SET
    `OfferRewardText` = 'I knew you''d come through, $N! Here''s your reward.',
    `RequestItemsText` = 'You''ve truly exceeded all my expectations, $N. You''ve been taking on opponents that Huum and I would think long and hard before engaging.$B$BAt this point the best I can do is to continue rewarding your efforts in the fight against the Twilight''s Hammer and their overlords.$B$BBring me more abyssal scepters and I''ll do my best to give you a suitable reward.'
WHERE `entry` = 8364;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh you''re a darling, even if it did take you longer than I am accustomed to. This shipment should make me quite a bit of money once I''ve cleaned and personalized these hats. And seeing as I''m always willing to reward work that''s well done, here''s a little something for you. I suggest that you spend some of it on a bath sweetie.',
    `RequestItemsText` = 'Do you have all 20 hats? I don''t believe you, let me see them. They better be in pristine condition!'
WHERE `entry` = 8365;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N! You are the man!!!$B$BI''m sure that the Cartel will ease up on me now that you''ve dealt with those Southsea scum. Let''s see, what can I give you as a reward? How about a little coin and you choose from one of these for your trouble?',
    `RequestItemsText` = 'Back so soon? I hope you taught those Southsea hoodlums a lesson they won''t soon forget.'
WHERE `entry` = 8366;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your trials have not been easy, but your courage did not escape you and your strength did not fail. Part with past tokens of victory, $C. None shall need them as a reminder of your worth. Stand up straight, $N. Today you will walk with great pride for you are a hero!',
    `RequestItemsText` = 'Arathi is still wet with the blood of great warriors and the clash of steel still rings throughout Alterac.  Do not waste my time unless you bring news from the front!'
WHERE `entry` = 8367;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent!  You''ve shown your worth by defending our operations in Warsong Gulch!  May word of your honor spread far and wide across our lands.',
    `RequestItemsText` = 'Do you bear news from Warsong Gulch, $N?'
WHERE `entry` = 8368;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve shown great bravery in protecting our lands in Alterac Valley!  I will tell my superiors of your deeds.',
    `RequestItemsText` = 'What news do you bring from the lands of the Frostwolves?  How does the battle for Alterac Valley fare?'
WHERE `entry` = 8369;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Securing our resources in Arathi is an important task!  You''ve done well, $N.',
    `RequestItemsText` = 'You''ve come back with news from Arathi, $C?'
WHERE `entry` = 8370;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''re not one to disappoint, $N!  What you''ve learned goes beyond petty medals and commendations.  What you''ve learned is what can only come with experience and the hardening of one''s temper in the field of battle.$B$BYou''ve done well, $C.  You''re a true hero of the Alliance!',
    `RequestItemsText` = 'How are yer travels faring  laddie?'
