UPDATE `quest_template` SET
    `OfferRewardText` = 'This is excellent, $N.  I would say I am surprised, but I knew without question that you wouldn''t let us down.$B$BIt is my honor to bestow one of the Holy Mightstones to you.  Use it well.',
