    `OfferRewardText` = 'It is good to know the people of this land still pay homage to the olden races. I bid you well, $N, and offer you this token...',
    `RequestItemsText` = ''
WHERE `entry` = 8619;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Fantastic! I can''t believe you went through the hassle! Are you some kind of machine? If it were me, I would have probably just let the world implode.$B$BI tip my turban to you, sir. And no good deed should go unrewarded.',
    `RequestItemsText` = 'I put my pants on just like you - one leg at a time. Except when my pants are on, I make arcanite buoys. Arcanite buoys, baby!'
WHERE `entry` = 8620;

