    `OfferRewardText` = 'Well done, $N. I will be able to reform the Scepter of the Shifting Sands soon.',
    `RequestItemsText` = 'Time is running out, champion.'
WHERE `entry` = 8729;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Vaelastrasz''s soul is at ease, champion. The Aspects all watch your progress with great interest. Know that you have powerful allies.$B$BI was commanded to grant you something to aid you in this struggle. Use it well...',
    `RequestItemsText` = 'Another of our heroes lost to the spawn of Deathwing. We will be cursed with this suffering forever...'
WHERE `entry` = 8730;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I can tell that Krug has little use for paperwork. He signed this in silithid blood!$B$BVery well, $N. I''ve prepared a set of tasks that should make good use of your skills as a $C.$B$BWith the continued efforts of you and people like you, our enemy will soon be crushed!',
    `RequestItemsText` = 'You''ve completed your field duty, $N?  Captain Skullsplit can be found outside of Hive''Regal.'
WHERE `entry` = 8731;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, I suppose that little skirmish will pass as field duty nowadays. Take these back to Cenarion Hold, I''m sure they''ll have a cushy job ready for you.$B$BOff you go!',
    `RequestItemsText` = 'I take it you want those papers signed, boy?'
WHERE `entry` = 8732;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The wisp is silent except for a low humming sound. Oddly enough, it is able to communicate with you through thoughts.',
    `RequestItemsText` = ''
WHERE `entry` = 8733;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It would be impossible to pull Eranikus from the Dream should he refuse. His intentions, however, require him to enter our world. He seeks to destroy the living manifestation of Malfurion. To do this successfully would mean an end to one of the most powerful allies of the Dream. The Nightmare would wholly consume all that would remain should Malfurion fall...',
    `RequestItemsText` = ''
WHERE `entry` = 8734;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Are you prepared? Is the world prepared for what we are about to invoke? I do not know... I am bound by duty to Malfurion. Duty and honor...',
    `RequestItemsText` = '<Remulos is lost deep in thought.>'
WHERE `entry` = 8735;

UPDATE `quest_template` SET
    `OfferRewardText` = 'He is redeemed, $N. He now returns to the Dream to right what he alone has done wrong. Eranikus will be a powerful ally to Malfurion and my father.$B$BThese armaments are for you, $N; given to me by Ysera herself. You would do well to make use of them in your battles against the Qiraji.',
    `RequestItemsText` = ''
WHERE `entry` = 8736;

