UPDATE `quest_template` SET
    `OfferRewardText` = 'The Scepter of the Shifting Sands is whole once more, $N.$B$BIt must be you who uses the scepter. It must be you who heralds the next age of your people.$B$BYou must wait for the armies of the Horde and the Alliance to arrive in Silithus before you may ring the Scarab Gong.',
    `RequestItemsText` = 'A thousand years has passed and just as it was fated, one stands before me. One who shall lead their people to a new age.$B$BThe Old God trembles, $N. Oh yes, it fears your faith. Shatter the prophecy of C''Thun.$B$BIt knows you come, champion - and with you comes the might of Kalimdor. You have only to let me know when you are prepared and I shall grant you the Scepter of the Shifting Sands.'
WHERE `entry` = 8742;

UPDATE `quest_template` SET
    `OfferRewardText` = 'From the ground near the gong springs a special crystal. Perhaps favor from the Brood.',
    `RequestItemsText` = 'The Scarab Gong looms ominously before you. Steel yourself, $N; for once the Scarab Gong is rung, the gates of Ahn''Qiraj will be opened.$B$BFrom the slackened maw of the beast can only come chaos and destruction. Defend your people!'
WHERE `entry` = 8743;

