UPDATE `quest_template` SET
    `OfferRewardText` = 'Greetings, champion. I am Jonathan, keeper of the sacred gong and eternal watcher of the Bronze Flight.$B$BI have been empowered by the Timeless One himself to grant you an item of your choosing from his timeless treasure trove. May it aid you in your battles against C''Thun.',
    `RequestItemsText` = ''
WHERE `entry` = 8745;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You did it!  Huzzah!$B$BMetzen flew back into Great-father Winter''s stables - yes Metzen can really fly - just a little while ago!  The dust worked like a charm; I knew it would.  You''ve saved the Feast of Winter Veil as well as Smokywood Pastures from disaster.  Thank you, $N.$B$BListen... because of what you''ve done here, I want you to have this.  It''s something VERY special; if you have a mount, I think you''ll get a kick out of it.  Happy Winter Veil!',
    `RequestItemsText` = '$N!  Did you find him?  Were the notes in the satchel I gave you enough information to locate Metzen?  I hate to think of what those cruel thugs might do to him... but there''s no way we can afford to pay such an exorbitant ransom!'
WHERE `entry` = 8746;

