UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh the chickens I will craft from this wondrous husk! Well done, my  boy!',
    `RequestItemsText` = 'Yes? What have you got there?'
WHERE `entry` = 8857;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent. We could surely devise some incredibly powerful armor from this chitin. Here''s the riches you were promised.',
    `RequestItemsText` = 'Hmmm...'
WHERE `entry` = 8858;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent and timely! Well done,  lad.',
    `RequestItemsText` = 'You look a bit heavy in the boots, friend.'
WHERE `entry` = 8859;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, my Smokywood supplies! Splendid! I''ll need these to feed all the people in town for the celebration!$B$BThank you, $N. Please take this as payment, and don''t forget to drink and dance with the revelers outside!',
    `RequestItemsText` = 'Greetings! Are you here for the party! Or perhaps you just need to rest those weary feet of yours...'
WHERE `entry` = 8860;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, very good! These supplies will help feed all our people, here to celebrate the new year!$B$BI thank you, $N. You are in my debt. Please, take these coins... and heed my advice - drink heartily from the kegs outside, and join our revelers in a dance of celebration!',
    `RequestItemsText` = 'Good day, $C! Did you come to Thunder Bluff for our celebrations?  Or are you here to rest a weary hoof between hunts?'
WHERE `entry` = 8861;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very well then - I accept these coins of ancestry. Please take Elune''s candle with my blessing. Also, please enjoy these complimentary fireworks.',
    `RequestItemsText` = 'Elune''s candle is an artifact of great reverence to the disciples of the Lunar Festival. Stored within the candle is true moonlight, ready to be unleashed!$B$BThis light is harmless to most creatures, but you will find that Omen and his minions are burned and dazzled by it.'
WHERE `entry` = 8862;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent - please enjoy these dumplings with my compliments.  While they are but a small token of appreciation for the honor you have brought upon yourself through your actions, I think you will enjoy them all the same. Should you have any more coins of ancestry, I stand ready to offer you a wide array of items in exchange.',
    `RequestItemsText` = 'If you are hungry, then you have come to the right place my friend! Dumplings are the traditional food of the Lunar Festival; it has been served since the time of the first Lunar Festival, and I am pleased to be able to offer it at this one.$B$BIn exchange for just a single coin of ancestry, I will share with you a sampling of one of the tastiest dishes you will ever enjoy!'
WHERE `entry` = 8863;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very well then - I accept these coins of ancestry.  Please take your dress with my blessing.  Also, please enjoy these complimentary fireworks.$B$BAs you have honored your elders, you honor me with your mere presence.  Thank you, and may your Lunar Festival be joyous.',
    `RequestItemsText` = 'I have a selection of dresses that may be of interest to you.  Such dresses have been worn in times past during the Lunar Festival, and the selection I have today is perhaps the finest I have ever seen.  Each is hand-crafted with only the finest and softest of components.$B$BIn exchange for some coins of ancestry, I will let you choose one of the three styles I have to keep as your own.  Is this acceptable to you?'
WHERE `entry` = 8864;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very well then - I accept these coins of ancestry. Please take your pant suit with my blessing. Also, please enjoy these complimentary fireworks.',
    `RequestItemsText` = 'I am please to inform you that I have a fine selection of festive pant suits available for you to own... but only in trade for coins of ancestry.  If fashion is important to you, then these are what you''re looking for!  I assure you that you will not find pant suits like these anywhere else.$B$BIn exchange for some Coins of Ancestry, I will let you choose one of the three styles I have to keep as your own.  Is this acceptable to you?'
WHERE `entry` = 8865;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is good to know the people of this land still pay homage to the olden races.  I bid you well, $N, and offer you this token...',
    `RequestItemsText` = ''
WHERE `entry` = 8866;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N.$B$BNow that you''re in the spirit of things, why don''t you take this invitation to the festival in Moonglade.$B$BIt''s quite an enjoyable celebration, if you have the time to spare.  We share food, drink, stories and of course... more fireworks!$B$BOpen the invitation while standing inside the circle of greater moonlight and you''ll be transported to Moonglade.',
    `RequestItemsText` = 'Did you find the launchers, $N?'
WHERE `entry` = 8867;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very well done, $N. Defeating Omen sent his spirit back to the water of Elune''ara. Although the beast himself is blessed by Elune and so cannot die, his anger will subside for another year.',
    `RequestItemsText` = ''
WHERE `entry` = 8868;

