UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, very well. Here are your recipes, $N, and my Elune bless you.',
    `RequestItemsText` = 'I hold the secrets to creating Lunar Festival rockets, and I am happy to share my knowledge with the honored.$B$BIn exchange for coins of ancestry, I can offer you the recipe to make a small rocket...'
WHERE `entry` = 8876;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here you are, $N. Here is the schematic to create a firework launcher. Place launchers where you wish to celebrate, and then welcome your friends to join you!',
    `RequestItemsText` = 'Although rockets are a wonderful way to celebrate, in order to see their glory... they must be fired from a launcher.$B$BBring me coins of ancestry and I can offer you the knowledge to create rocket launchers like the ones you see in Moonglade.'
WHERE `entry` = 8877;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here are the patterns, $N.  I am sure you will find the product of this knowledge quite beautiful.',
    `RequestItemsText` = 'The dresses and pant suits you see are traditional clothes from many years past.  They are worn in honor of old ways and loved ones gone.$B$BIf you bring me coins of ancestry, $N, then I will give you the pattern to create traditional red dresses or suits.'
WHERE `entry` = 8878;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very well - I accept these coins of ancestry. Here are your recipes, $N. May you use them to spread Elune''s glory!',
    `RequestItemsText` = 'Large Festival rockets light up the sky brilliantly - only the cluster rockets rival their magnificence!$B$BBring me coins of ancestry, $N, and I shall share the knowledge of their creation.'
WHERE `entry` = 8879;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here you are, $N.  Take these recipes and learn their secrets.  I bid you fortune, and I look forward to seeing your magnificent creations.',
    `RequestItemsText` = 'Cluster rockets are a collection of individual rockets, and their beauty is awesome!  Bring me coins of ancestry and I will share the knowledge of their creation to you...'
WHERE `entry` = 8880;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N.  Here is the recipe for large cluster rockets.  May your products bring joy and luck to all those who gaze up them.',
    `RequestItemsText` = 'Large cluster rockets require vast resources and skill to create, but their brilliance and beauty is worth that effort!  Bring me coins of ancestry and I will grant you the knowledge of their crafting.'
WHERE `entry` = 8881;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here is your schematic.  Study it closely, and learn...',
    `RequestItemsText` = 'The most splendid fireworks shows must include cluster rockets, and those cluster rockets must be fired from cluster launchers! Is it not then logical for you to learn the secrets of making cluster launchers? Bring me coins of ancestry and I will give this knowledge to you.'
WHERE `entry` = 8882;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N, welcome to Nighthaven, host of the Lunar Festival!  Although our village is normally remote and sequestered from the peoples of Azeroth, during this time of celebration we open our arms and hearts to all.$B$BEnjoy your visit, $N, and speak with me or my sister again when ready.',
    `RequestItemsText` = ''
WHERE `entry` = 8883;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You place the hippogryph egg into the machine. A series of beeps follows along with some strange mechanical sounds.$B$BIt appears that the Eggometer has weighed, measured, and packaged your egg. Now that''s speedy service!',
    `RequestItemsText` = 'The Super Egg-O-Matic is the latest of Curgle Cranklehop''s inventions. It is quite an impressive piece of machinery.$B$BThe Super Egg-O-Matic sputters wildly as you approach the control panel.'
WHERE `entry` = 8893;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, isn''t that sweet! This is the first time he''s ever sent me something. Do you suppose he''s getting serious?$B$BColara Heldric? I suppose it has a ring to it. Oh, but I''m getting ahead of myself. Thank you.',
    `RequestItemsText` = 'Hello there, handsome. Something I can help you with?'
WHERE `entry` = 8897;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Tormek? Oh yes, I do remember him. He had quite a nice beard and smile underneath.$B$BAh, I can''t believe he remembered me!',
    `RequestItemsText` = 'Hello there, handsome. Something I can help you with?'
WHERE `entry` = 8898;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I''ve never received something like this before. How lovely!',
    `RequestItemsText` = 'Hello there, handsome. Something I can help you with?'
WHERE `entry` = 8899;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You wouldn''t expect an orc to be so eloquent. Of course, we never really had a chance to know them before now. Thank you for bringing this to me.',
    `RequestItemsText` = 'Oh, and to what do I owe this pleasure?'
WHERE `entry` = 8900;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What kind words Temma writes for me. But, as much as his words move me, I cannot consider the love of a tauren. In thoughts, body and mind we are too different.$B$BIt is good I do not have to receive these thoughts of his in person. I could not bear to break his heart.',
    `RequestItemsText` = 'Oh, and to what do I owe this pleasure?'
WHERE `entry` = 8901;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This brings back memories from a lifetime ago, $N. Elenia Tor. That was going to be my name, you know. We would have a beautiful ceremony out on the shores of the lake. When he retired, we''d find a farm to retire to.$B$BSimple dreams, then.$B$BBut if he saw me now, I doubt he''d even see Elenia in me. Only cold flesh and a dead heart...',
    `RequestItemsText` = 'Oh, and to what do I owe this pleasure?'
WHERE `entry` = 8902;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So it is true. This is unbelievable. How could this have happened? Let me think for a moment. There must be a reason behind this.',
    `RequestItemsText` = 'Was I right to worry? Are the guards afflicted with this lovesickness?'
WHERE `entry` = 8903;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So it is true. This is unbelievable. How could this have happened? Let me think for a moment. There must be a reason behind this.',
    `RequestItemsText` = 'Was I right to worry? Have our idiot guardians been overcome?'
WHERE `entry` = 8904;

