UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you for rescuing me... I feared for my life. Please accept this as a small token of my gratitude.$B$BAnthion is... no... he can''t be...',
    `RequestItemsText` = 'Tell me, is Ysida alive?'
WHERE `entry` = 8945;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That locket... you found her! I can rest in peace at long last.$B$BI shall now answer any questions you might have, $N. But make haste, my time in this world is not long.',
    `RequestItemsText` = 'Ysida... is she alive?'
WHERE `entry` = 8946;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent. I shall transmute these into something more suitable to our needs.',
    `RequestItemsText` = 'Did you obtain the materials I asked for, $N?'
WHERE `entry` = 8947;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Anthion sent you, you say? I thought he was dead. I guess I''ve heard stranger things in my life.$B$BVery well, then.  What is it you want me to do with this banner?',
    `RequestItemsText` = 'Speak up stranger, can''t you see I''m busy?'
WHERE `entry` = 8948;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmmm... strangely enough I don''t feel any better about my brother''s death at the hands of those brutes.$B$BWell, you held your end of the bargain. Let''s see what I can do for you.',
    `RequestItemsText` = 'Have you performed the favor I asked of you, $N?'
WHERE `entry` = 8949;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, these will do just fine. After I''m done, no force in the world will be able to stop your victim from accepting your challenge.',
    `RequestItemsText` = 'Have you gathered the materials I require, $N?'
WHERE `entry` = 8950;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I can''t believe our lives are all but forfeit all because of a stupid medallion! And you''re sure Anthion mentioned Bodley?$B$BWell, you''ve done your job so let''s get your reward out of the way.',
    `RequestItemsText` = 'You''re back, $N. You must tell me all about what you''ve found out. But first let us arrange for your reward.'
WHERE `entry` = 8951;

