UPDATE `quest_template` SET
    `OfferRewardText` = 'A job well done, $N. I will imbue the essence of the ashes into the brazier.$B$BNow all that is left is to get into Scholomance, to Ras Frostwhisper''s chamber, and use the brazier to summon forth the spirit of my former cohort, Kormok. The amulet piece, and Valthalak''s spirit within, has corrupted him even further, and he will not rest until you forcibly take it from him.$B$BOh, by the way, I had some leftover bloodkelp from your trip to Alcaz Isle, so I made it into some potions for you. Take your pick!',
    `RequestItemsText` = 'Have you returned already then, $C, with what I sent you out to gather?'
WHERE `entry` = 8988;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you for helping Mor Grayhoof, $N. Another spirit rests in peace, and we now have the reassembled amulet! But we still have the hardest test ahead of us.$B$BIn order for the brazier to be attuned to calling forth Lord Valthalak, there are a few more items that need to be gathered and brought back to me here.',
    `RequestItemsText` = 'Then it is done? You have retrieved the right piece of Lord Valthalak''s amulet, recombined the amulet into one whole, and finally put to rest the spirit of my old companion, Mor Grayhoof?'
WHERE `entry` = 8989;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N, for putting Isalien''s spirit to rest. Now, perhaps, she will find peace with her goddess. And, we have the reassembled amulet, as well! But we still have the hardest test ahead of us.$B$BIn order for the brazier to be attuned to calling forth Lord Valthalak, there are a few more items that need to be gathered and brought back to me here.',
    `RequestItemsText` = 'Surely you haven''t already dealt with the salvation of Isalien''s spirit and the retrieval of the right piece of Lord Valthalak''s amulet, $N? Be sure to recombine the pieces of the amulet before handing it to me.'
WHERE `entry` = 8990;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I suppose it''s for the best that the souls of those two have finally been put to rest, even if I didn''t like them while they were alive. In any case, we have what we were after, and now the amulet is reassembled! But we still have the hardest test ahead of us.$B$BIn order for the brazier to be attuned to calling forth Lord Valthalak, there are a few more items that need to be gathered and brought back to me here.',
    `RequestItemsText` = 'Does this mean then, $C, that you''ve already put the souls of those two fools to rest and recombined the pieces of Lord Valthalak''s amulet?'
WHERE `entry` = 8991;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good work, $N! Kormok wasn''t all that bad for an ogre, at least not while he was still alive, so I hope he gets the rest that he deserves. And now we have the completed amulet! But we still have the hardest test ahead of us.$B$BIn order for the brazier to be attuned to calling forth Lord Valthalak, there are a few more items that need to be gathered and brought back to me here.',
    `RequestItemsText` = 'I commend you, $N, if you have returned with the completed amulet. If not, however, please take care of that as there is no time to waste, I assure you!'
WHERE `entry` = 8992;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wonderful! Wonderful! I will add this to the pile of other gifts.$B$BI didn''t expect so many! You must truly love your leaders.$B$BNow, let me just add one more to the count...',
    `RequestItemsText` = 'Have you come to deliver a present of love and adoration to your favorite leader?'
WHERE `entry` = 8993;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That''s it then. I''ll extract the metal from the bracers and imbue the brazier with these final components. Then it will be ready for you to summon Lord Valthalak, and finally return his spirit amulet to him.$B$BYou''ve come quite a distance, $N, don''t falter now that the end is in sight!',
    `RequestItemsText` = 'We''ve come a long way, $N, and I just wanted to say that no matter what happens, thank you! You''ve put yourself in mortal danger to try to help the surviving members of our mercenary company, The Veiled Blade, and as far as I''m concerned, you''re one of us now.'
WHERE `entry` = 8994;

UPDATE `quest_template` SET
