UPDATE `quest_template` SET
    `OfferRewardText` = 'You perform a great service for us, $N. Well done!',
    `RequestItemsText` = 'Truth be told, I use the cores to create Frostfire armor. It is the armor used by the mages battling in Naxxramas. Without you and others like you, we would most definitely be losing this war.$B$BWith that said, bring me more cores and I shall grant you more insignias.'
WHERE `entry` = 9129;

