WHERE `entry` = 9137;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Alright, here''s how it works: For every valor token that you turn in, I''ll give you another writ. You complete the order on that writ and deliver the order to Packmaster Stonebruiser. Got it? Good. Now get out of here.',
    `RequestItemsText` = '<Commander Metz chews on his cigar.>$B$BWhat is it? I''m a busy man.'
