UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done well, $N. Through these incremental defeats, we shall prevail against this renewed Scourge threat.$B$BRest and recover, but then you must head out to the front again, lest we lose the ground we have gained today.$B$BTo aid you in your further battles, we will make some of our special items available to you in trade for more necrotic runes.',
