UPDATE `quest_template` SET
    `OfferRewardText` = 'Blessed bootstraps! Are those what I think they are? The troops have been complaining non-stop about the lack of storage space for all that is required while in the field. One of them even drew me a diagram - such a pansy...$B$BThese will definitely help alleviate some of the whining.',
    `RequestItemsText` = 'Filling a work order, $C?'
WHERE `entry` = 9191;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You shouldn''t have! No really, you shouldn''t have. I don''t know what Metz is thinking, but nobody is going to be wearing these robes into Naxxramas.$B$B<Packmaster Stonebruiser sighs.>$B$BBah, another pile of junk I''ll have to get transferred to the front lines and another berating I''ll have to take from Chambers.',
    `RequestItemsText` = 'Filling a work order, $C?'
WHERE `entry` = 9194;

