UPDATE `quest_template` SET
    `OfferRewardText` = 'Why are you smiling? What''s so funny? Listen, mister, a gnomish battle chicken is a very important unit and not to be taken lightly - EVER. We send these in to areas that might be heavily plagued or infested and they clean up any plagued insects or carrion maggots that might still be fluttering about. Everybody knows that robots are immune to the plague.$B$BI bet you don''t feel so smart now, do you? Big dummy...',
    `RequestItemsText` = 'Filling a work order, $C?'
WHERE `entry` = 9197;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thorium tubes? Gee, thanks.$B$B<Packmaster Stonebruiser throws the stack of thorium tubes into a large pile of assorted junk.>',
