UPDATE `quest_template` SET
    `OfferRewardText` = 'Ande''thoras-ethil. It means; ''May your troubles be diminished,'' in my native tongue.$B$BWear the band proudly and in good health, $N.',
    `RequestItemsText` = 'Fandu-dath-belore? Oh, pardon me, $N. I did not recognize you. Have you the scepter?'
WHERE `entry` = 9248;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The archmages have died.$B$BDo not mourn their passing, $N. All such things are fated. Just as you holding the staff of the Guardian was fated...',
    `RequestItemsText` = 'It was her time, mortal.'
WHERE `entry` = 9250;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There is a being within... a being not of this world.',
    `RequestItemsText` = 'In its current form, the staff is far too dangerous to be in the hands of a mortal.'
