UPDATE `quest_template` SET
    `OfferRewardText` = 'The magnitude of this accomplishment must not be understated, $N. You have done what most would have thought to be impossible. Alas, it was fated. The staff has made its choice.',
    `RequestItemsText` = 'I must not interfere, $R.'
WHERE `entry` = 9257;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Let us observe a minute of silence for our fallen mates, $N.$B$B<The Bloodsail Traitor grins at you and winks.>$B$BBeing a traitor is one thing, murdering yer own buckos... that''d be just downright despicable, aye!',
    `RequestItemsText` = 'That mangy dog, Revilgaz, has offered to pardon any former Bloodsails willing to turn on their cap''n!  That bilge sucker asked me to go an'' off me ole'' mates and to bring back their bandannas as proof.$B$BI don''t have it in me heart to do that, nor will I ask ye to.  Bring me some silk cloth and red dye and I''ll make suitable replicas.  I''ll tell the Baron you went turncoat, but be warned... the Bloodsails are not gonna like it!'
WHERE `entry` = 9259;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmm. From what you''ve told me, the voices within the circles... they must be used for communication of some kind. I shudder to think what unnatural minds are contacted through such magic. Regardless, you seem to have emerged whole and sane. The Argent Dawn appreciates your service.',
    `RequestItemsText` = 'Have you investigated the invasion yet? There''s no time for dawdling!'
WHERE `entry` = 9260;

