UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. You''re on a quick path to redeeming yourself with our fair town.',
    `RequestItemsText` = 'You must''ve done something really bad to us or our friends, $N. At any rate, I''m here to offer you a way to get our good graces back.$B$BAs you know, Winterspring is quite cold. With so many of us goblins coming from other cities, we could use a hand keeping warm. Bring me some runecloth and coal and I''ll put in the good word for ya. Be warned though, our enemies are not going to take kindly to your helping us.'
WHERE `entry` = 9266;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I''m happy you''re seeing the error of your ways, $N. Keep the supplies coming; we''re not going to forget about you so easily, mister!',
    `RequestItemsText` = 'You''d better think twice before setting foot in Ratchet, $N! Word''s been getting around of your dirty deeds.$B$BYou''re in luck though, a ship just arrived with many wounded from an encounter with the Bloodsail Buccaneers. This is your chance to prove you''re not a complete scoundrel. Lend us a hand by bringing linen cloth for bandages and empty vials for potions.'
WHERE `entry` = 9267;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Keep it coming, $N. Us goblins don''t forget that easily!',
    `RequestItemsText` = 'You seek to befriend the goblins of Tanaris once again, $N? We''re in need of materials for sails and guns to fight off our old enemies, the Bloodsail Buccaneers. Bring me mageweave and strong flux and we''ll be on our way to pardoning your trespasses.'
WHERE `entry` = 9268;

