UPDATE `quest_template` SET
    `OfferRewardText` = 'Your spirit glows with the warmth of the Kalimdor fires, friend. Is the heat not invigorating? Once the power fades from you, perhaps these will help rekindle the feeling.',
    `RequestItemsText` = 'Are the flames of Kalimdor burning brightly?'
WHERE `entry` = 9322;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, here you are. A little wearier, a bit dustier, but enlightened! The heat touches us all during this season and unites us; your very being glows with the power of the fires you touched. Ah, but these days enlightenment is taken as a rather poor reward for being sent on a task, I suppose. Take these, then, and enjoy the celebration.',
    `RequestItemsText` = 'Have you yet traveled the continent? Enlightenment awaits you.'
WHERE `entry` = 9323;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What''s this? Unless I''m mistaken, this flame has been taken from the heart of Orgrimmar itself! The fierce hearts of the orcs and trolls are reflected in its searing heat. What a fine addition to our collection--how brave you are, stealing into the enemy''s lair to retrieve the sacred flame!',
    `RequestItemsText` = 'You''re practically glowing, $R. What do you have there?'
WHERE `entry` = 9324;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Unless I miss my guess, this fire has been taken from the cliffs of Thunder Bluff! How it sings with the power of the spirits! You are quite the thief, $N. Take this as just payment for your skill. Now, if only we had the flames of all three cities...',
    `RequestItemsText` = 'You''re practically glowing, $R. What do you have there?'
WHERE `entry` = 9325;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hm... what a strange fire! It is subdued, nearly smoldering, but the heat is intense. And you received this from the Undercity, you say? Fascinating. With the flames of all three cities, who knows what we could accomplish?',
    `RequestItemsText` = 'You''re practically glowing, $R. What do you have there?'
WHERE `entry` = 9326;

UPDATE `quest_template` SET
    `OfferRewardText` = 'And this brightly-burning fire... you say it came from Stormwind? Remarkable! That must have been quite an adventure! I''ll pay you for this, of course. If you find anything else like this, be sure to speak with me again.',
    `RequestItemsText` = 'You''re practically glowing, $R. What do you have there?'
WHERE `entry` = 9330;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This hearty flame must be from the halls of Ironforge; it''s as stalwart as the dwarves themselves. A fine catch, $N. If I had the fires of the other cities... ah, but never mind. Here is your payment.',
    `RequestItemsText` = 'You''re practically glowing, $R. What do you have there?'
WHERE `entry` = 9331;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This fire aches of ancient sorrow, $N. You pulled this from the roots of Teldrassil, you say? Fascinating! Here is a reward for your skill. Return to me should you find anything else like this; I may have a use for it.',
    `RequestItemsText` = 'You''re practically glowing, $R. What do you have there?'
WHERE `entry` = 9332;

