UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahhh, so they do still burn. I am glad; it would not do for those fires to burn out before their time. You have done well, $N. Take this with my blessing.',
    `RequestItemsText` = 'The fires cannot die until the festival is done!'
