UPDATE `quest_template` SET
    `OfferRewardText` = 'So you''ve returned, and you''ve seen to the emerald flames of the continent. What do you think, mm? A rare and wonderful sight, to be certain. I am aware, however, that tangible rewards are better appreciated... so please, take this for your trouble.',
    `RequestItemsText` = 'Have you seen to your task?'
WHERE `entry` = 9389;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Alliance needs every able body they can get. The Horde has been receiving a steady supply of reinforcements from the northern part of the continent, and it''s been a struggle to keep up.$B$BLet me explain the situation to you.',
    `RequestItemsText` = ''
WHERE `entry` = 9415;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It''s good that you''re here, but there''s no time to waste making small talk. You need instructions, and then you need to get out there.$B$BListen up.',
    `RequestItemsText` = ''
WHERE `entry` = 9416;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank the Light you were successful.$B$BNow if we could only have started this sooner, our need would not be so desperate. We must keep the bounty of the desert from falling into the hands of the Horde.',
    `RequestItemsText` = 'Be careful out there, but also be quick. We have no time to lose.'
WHERE `entry` = 9419;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done well, $N. These resources will be added to our stockpiles, and every bit is to our gain and our enemy''s loss.',
    `RequestItemsText` = 'Be wary of the dangers of the desert, $N. With the Alliance lurking in the dunes, any step could be your last.'
WHERE `entry` = 9422;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good, $N. It will be important for us to hold these towers against future attacks, and for that we may need your assistance until reinforcements can be brought in to secure the area.',
    `RequestItemsText` = 'When the towers are under our control, we will soon be able to surround the Forsaken. After that, it is only a matter of time before we can crush them.'
WHERE `entry` = 9664;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is good news, $N. It will be a constant struggle here in the Plaguelands until we have fully driven back the forces of the Alliance.$B$BUntil that day, I hope that we will have your continued assistance.',
    `RequestItemsText` = 'They must be fools to think that we would allow them to establish bases so close to one of our capitals.$B$BWe will bleed their numbers until they turn tail and retreat back to the south.'
WHERE `entry` = 9665;

