UPDATE `quest_template` SET
    `OfferRewardText` = 'Very well. You seem ready.$B$BA piece of advice before you go $N. Someone like you, someone like me, we will always be forgotten. Keep this close to your heart: the people of this world will never remember your name, they will never recall your face, but they will always remember your deeds.',
