UPDATE `quest_template` SET
    `OfferRewardText` = 'You actually want to buy it?!$B$BI mean, of course you do it''s a great opportunity. Oh, and sign this paper, it''s just say that you own the machine now, and... um...$B$B<Vizlow mumbles.>$B$BThat you are aware of the risks.',
    `RequestItemsText` = 'Got the gold yet?'
WHERE `entry` = 39000;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Do tell! Were there any signs of where they came from? Any artifacts?$B$BTools they might''ve used? Anything? Wha-ŌĆ” That''s it?$B$BJust a cave?? Time wasted, then, I guess. Let me give ya some coins, though. Ya did the job well, no matter what.$B$BHere, not much, but it is a good start, kid.',
    `RequestItemsText` = 'If only we had some mages cooperating with our research here instead of fiddling with all those trinkets they seem glued to like a goblin to gold!$B$BBahŌĆ” Frustrations won''t bring us anywhere, right? SoŌĆ” be sure to have your rest once you''re done ''ere.'
WHERE `entry` = 39001;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Delightful! Such an aromatic fragranceŌĆ” This tea must be one of a kind and especially flavorful. And I cannot wait for the fireworks to light up the sky in vibrant lights once more! $C, you have my eternal gratitude. For all your meticulous work, embrace my blessing upon you. Cherish these moments and the many that are yet to come - with your friends and loved ones, together!',
    `RequestItemsText` = 'Have you acquired everything yet? I am certain your abilities will not fail you in completing this small request.'
WHERE `entry` = 39977;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What a spectacle! The light show that just unfolded in front of me was simply marvelous. You did great; an earnest thanks to you, from the bottom of my heart. You have shown that you are diligent and responsible, so accept this blessing upon you, as a token for a past and coming year of good fortune!',
    `RequestItemsText` = 'Gather your friends and enjoy the festivities!'
WHERE `entry` = 39978;

