    `RequestItemsText` = 'I told you, I can''t let the prisoner go!'
WHERE `entry` = 39983;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You must be the heroic stranger that sprung my dear friend Mr Tusk from jail?$B$BWe here at Shell Co appreciate your assistance very much, and while we don''t currently have the means to pay you back the gold you spent, we have something even better.$B$BThis is a shellcoin, the currency of the future! A means of payment free from government interference! A currency that suffers no taxation! Take it, it''s yours.',
    `RequestItemsText` = ''
WHERE `entry` = 39984;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I see your point now, $N. Perhaps Shellcoin does not need to be taxed.',
    `RequestItemsText` = 'I suppose I could change my mind, under the right circumstances.'
WHERE `entry` = 39986;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have brought those for me? Why, how did you know, I do love rum!$B$BThat''s very thoughtful of you. But let''s keep this between us, okay, $N?$B$BThe high priestess recently introduced some silly rules about avoiding temptations and not indulging in alcohol, blah blah blah.',
    `RequestItemsText` = 'Blessed be the poor, blessed by the generous. To donate to the Church of the Holy Light is to guarantee your well being in the afterlife.$B$BHave you come to make a contribution, $N?'
WHERE `entry` = 39987;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Why have you handed me this bag of gold? What is the meaning of this?$B$BExcessive taxation? You hope to bribe me to overturn the law?!',
    `RequestItemsText` = 'What is it you require, citizen?'
WHERE `entry` = 39988;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The highlord said what?! This is an economic disaster. Seems like we''ll need to relocate to some place that respects the rights of free enterprise. Stormwind is nothing but a den of misery.$B$BThank you for your help, $N. While I can''t compensate you for your expensess in gold, I can give you something far more valuable.',
    `RequestItemsText` = ''
WHERE `entry` = 39989;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N. I see you''re not only skilled but cunning.',
    `RequestItemsText` = 'What did I say about returning to me before it''s done?'
WHERE `entry` = 39991;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done more in a day than these idiots around me have done in a month. I shall make sure you''re properly compensated for your services.$B$BDo not mistake my generosity for weakness however. If you were to make a move against me, you''d be dead just as quick as that prince. I don''t want you getting any ideas.',
    `RequestItemsText` = 'What did I say about returning to me before it''s done?'
WHERE `entry` = 39992;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, you did it already? Good, good. Now find something else to do and get out of my face.',
    `RequestItemsText` = 'Well? I''m waiting...'
WHERE `entry` = 39993;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That''s right.  I did witness something suspicious.',
    `RequestItemsText` = ''
WHERE `entry` = 39994;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You did it! I am thankful for your help, $N. Now we can begin gathering the materials needed for this weapon.',
    `RequestItemsText` = 'Did you find out where the stolen plans are kept?'
