UPDATE `quest_template` SET
    `OfferRewardText` = 'At last! I have all that I need to craft the weapon. You have done a great service to the horde.',
    `RequestItemsText` = 'Did you raid the human lands and find the stone I asked you for?'
WHERE `entry` = 39998;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You are indeed worthy of this axe. Thank you for your service, champion. May it help you crush many more of our enemies.',
    `RequestItemsText` = 'Return to me once you have proven yourself worthy in battle against the Alliance.'
WHERE `entry` = 39999;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, mon, Shagu sent ya for his herbs? Mishiki wanted to send it as soon as possible, but ya see, we got a bit of a problem.',
    `RequestItemsText` = ''
WHERE `entry` = 40001;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve returned, my friend! And with the herbs no less. Here''s the payment I owe.',
    `RequestItemsText` = 'Mixed herbs give mixed feelings, friend!'
WHERE `entry` = 40002;

UPDATE `quest_template` SET
    `OfferRewardText` = 'An eye-opener, isn''t it, $N?$B$BYou now feel closer to the Earthmother than ever before.$B$BRejoice and be one with nature!',
    `RequestItemsText` = 'Come on, my friend, sit down and take a toke.$B$BIt will be well worth it.'
WHERE `entry` = 40003;

UPDATE `quest_template` SET
    `OfferRewardText` = '<The elder listens to your report...>$B$BThere be a sizable force of gnolls encamped there, and from what you tell me they are tough ones. You have proven your worth, and now I will fulfill my promise. The power of the Winterax is yours!',
    `RequestItemsText` = 'Our enemies won''t slay themselves... Go!'
WHERE `entry` = 40004;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It smells good, doesn''t it? The tribe will be well fed, thanks to you.$B$BHere, you can have some too, you''ve earned it!',
    `RequestItemsText` = 'Bring me a gnome, before i decide to make an idiot stew instead!'
WHERE `entry` = 40005;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You are real big game hunter. Taurens are among the most dangerous beasts in the world. Thanks to your expert hunting skills, the tribe will be well fed for a whole week!$B$BHere, you should have some, you''ve earned it!',
    `RequestItemsText` = 'Taurens are exceptionally strong and dangerous. Don''t attempt to kill it on your own. Just bring it here, and we''ll slay the beast together.'
WHERE `entry` = 40006;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You returned faster than I thought you would, perhaps you are a proven hunter. You fit in well with my people, but there is one more thing to do in preparation.',
    `RequestItemsText` = 'Have you gathered the venom sacs?'
WHERE `entry` = 40014;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You truly are a master hunter and a friend to the Wildtusk, $N! Take this for all of your help, thank you!',
    `RequestItemsText` = 'Has she been slain?'
WHERE `entry` = 40015;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Raaaar!',
    `RequestItemsText` = 'Have you smashed ogre for my beads?'
WHERE `entry` = 40016;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done all of Wildtusk Village a favor this day, thank you. Take this silver as payment for your help.',
    `RequestItemsText` = 'Have you gathered the war materials?'
WHERE `entry` = 40017;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done it, $C! We may rest easy tonight thanks to the work you''ve done. Take these coins as appreciation for the work you''ve done.',
    `RequestItemsText` = 'Have you cut down their numbers?'
WHERE `entry` = 40018;

UPDATE `quest_template` SET
    `OfferRewardText` = 'With the charms returned to us, we can begin to tend to the spirits once again. I can already feel the difference. Thank you for all you have done, $C!',
    `RequestItemsText` = 'Have you retrieved the charms?'
WHERE `entry` = 40019;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I cannot believe my eyes, $C. Thank you for retrieving it for me. I can now return to my duties with pride.',
    `RequestItemsText` = 'Have you found the amulet?'
WHERE `entry` = 40020;

UPDATE `quest_template` SET
    `OfferRewardText` = 'He deserved worse than this, $C. What you see here are the remnants of my people, and he will pay for his crimes even after death now that you have brought me his head.',
    `RequestItemsText` = 'Have you put an end to that traitor''s miserable life?'
WHERE `entry` = 40021;

UPDATE `quest_template` SET
    `OfferRewardText` = 'He will join Gan''to and suffer until the day I die, $C. The two of them will decorate my belt forevermore and stand as a symbol of victory over the Witherbark and newfound friendship with the Horde. You have done well, $N. Your deeds will be remembered by my people forever.',
    `RequestItemsText` = 'Are those drums of mourning?'
WHERE `entry` = 40022;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You desire to aid the realm of rock? There is much to do. Let us begin.',
    `RequestItemsText` = 'Yes, mortal being?'
WHERE `entry` = 40023;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There is something foul hereŌĆöa magic that is not native to my kind.',
    `RequestItemsText` = 'Is it done, mortal? Have you gathered the bracers?'
WHERE `entry` = 40024;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is everything. I shall do as Lord Rog instructed so that he may purify the bracers.',
    `RequestItemsText` = 'The task at hand is an important one, mon. We must be doing our best to help the elementals.'
WHERE `entry` = 40025;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done your duty well. You exemplify the values of my kind. Without you, I would be unable to continue my work. Take this signet as a symbol of gratitude, mortal. May the blessings of the Elemental Plane help you in your future battles.',
    `RequestItemsText` = ''
WHERE `entry` = 40026;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Sanv Charm means a lot to me, outsider. The Sanv were once a large tribe in Outlands. Sadly, I am the only that remains. Let me prepare the communication with the lost one.',
    `RequestItemsText` = 'The Sanv Charm must be recovered, outsider. Be quick.'
WHERE `entry` = 40027;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done it! This is the horn. I must thank you greatly. Without you, it would have been lost forever. Words alone cannot express how pleased I am to have this once more.$B$BPlease, take my ring as a symbol of my gratitude and respect.',
    `RequestItemsText` = 'Have you gotten my prized possession, outsider?'
WHERE `entry` = 40028;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It saddens me that we must slay our brethren, of those we shared so much hope in coming to this world. But their minds are warped. They are no longer friends. You have freed their souls, outsider. Thank you.',
    `RequestItemsText` = 'Has it been done yet, outsider?'
WHERE `entry` = 40029;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done it? Have you truly defeated the terrible one? This is a joyous day for the Harborage. He was a direct threat to our survival, and we did not have the strength to face him.$B$BWe are fortunate you could help, outsider! Please, as a symbol of our gratitude, take one of our artifacts from the old world. They serve no purpose to us anymore. We must look to the future and not remember the brutal past.',
    `RequestItemsText` = 'Has the feared one been defeated?'
WHERE `entry` = 40030;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, more leather to work with. My hands are eager to get started. I thank you, outsider, for  getting me this.',
    `RequestItemsText` = 'Have you procured the leather?'
WHERE `entry` = 40031;

UPDATE `quest_template` SET
    `OfferRewardText` = 'We shall begin the communication at once. Stand back, outsider. Our magic is unstable.',
    `RequestItemsText` = 'We must attempt to find Akh Z''ador, and quickly outsider.'
WHERE `entry` = 40032;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Sanv K''la sent you? I am happy to hear his name once more. I thought I would never hear from him again, nor would I think he would send someone so far to seek me.',
    `RequestItemsText` = 'I come from a far away land, and I seek no hostility. What is it you need?'
WHERE `entry` = 40033;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I see. Hashaz has sent you? If that is the case, then perhaps you may be of use. I am Tide Mistress Rashal, and this is the Rethress Sanctum. Speak with my followers here and make yourself useful.',
    `RequestItemsText` = 'Yes? What could it be that you want from me, $R?'
WHERE `entry` = 40034;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Many battles were fought for this. It is good to hear lives were not wasted for nothing. You are proving to be a good ally, interloper.',
    `RequestItemsText` = 'Have you collected what I asked for?'
WHERE `entry` = 40035;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Spitelash Myrmidon are an abomination to the great depths. They deserved death for breaking our most sacred bonds. I am pleased.',
    `RequestItemsText` = 'Have you killed the oathbreakers, $R?'
WHERE `entry` = 40036;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Even just crippling their numbers is enough to please me. My kind would never stand for such an aberration of the tide''s rules, and if I had the numbers, I would be sure to make them suffer.',
    `RequestItemsText` = 'Have the servants been dealt with, $R?'
WHERE `entry` = 40037;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Even just crippling their numbers is enough to please me. My kind would never stand for such an aberration of the tides rules, and if I had the numbers, I would be sure to make them suffer.',
    `RequestItemsText` = 'Have you got his head, interloper?'
WHERE `entry` = 40038;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have found it... Well done, land-walker. There is still one final task I must ask of you to ensure the Rethress survive.',
    `RequestItemsText` = 'Have you found the Scepter? Can you even follow instructions, $R?'
WHERE `entry` = 40039;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, someone new? We haven''t had anyone new around here in a long time, and we haven''t been told of someone new arriving. Do you want to help us out? You gotta prove to me you''re the real deal, buddy!',
    `RequestItemsText` = 'Mmm, yes?'
WHERE `entry` = 40040;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wow, you got it? I guess you are the real deal, and you really do want to help us! I''ll spread the word around that you''re A-OKAY! Let us get some work done then!',
    `RequestItemsText` = 'Have you gotten the Horn for me?'
WHERE `entry` = 40041;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, Gigno finally delivered the shipment? Well, I am pleased to receive it at all. I hadn''t expected it would arrive in some time with all of the... trouble in the area.',
    `RequestItemsText` = 'Hello there, traveler. Do you bring news from the outside world?'
WHERE `entry` = 40042;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Magus Bromley has news about the Analyzor 53G?! Hand that note over at once!$B$B<The gnome would swipe the letter and begin to read>.$B$BWhy, my Flaxwhisker!',
    `RequestItemsText` = 'You''re back. Splendid. Did he appreciate the supplies?'
WHERE `entry` = 40043;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Analyzor 53G was destroyed?... I will miss him dearly, but we shall create a better one in the future. Analyzor 54G will rise from the ashes likeŌĆöI got carried away. Thanks for getting the Analyzation Chip. You ''ve saved us months of work!',
    `RequestItemsText` = 'Have you got the Analyzation Chip? You must recover it!'
WHERE `entry` = 40044;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Flight Log Book? Oh... I''ve been so distracted that I haven''t even thought about it for a while now! The last one that had it was... Dinkle Togpipe.',
    `RequestItemsText` = 'Hello there. How can I help you, $R?'
WHERE `entry` = 40045;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Dinkle? He''s dead? Those blasted murlocs! I knew it would be trouble stationing him out there with only a rifle on that platform. Those higher-ups at Gnomeregan said the lights should be enough to scare off the creatures. Looks like they were wrong!',
    `RequestItemsText` = 'Have you gotten the Flight Logbook? ItŌĆÖs certainly taking a while!'
WHERE `entry` = 40046;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Flaxwhisker Front? They''re still alive? I''ll be honest, with all of the chaos in Gnomeregan, I had completely forgotten about the Flaxwhisker Front.',
    `RequestItemsText` = 'Is there something I can help you with?'
WHERE `entry` = 40047;

UPDATE `quest_template` SET
    `OfferRewardText` = 'GnomereganŌĆ” fallen? There are no more Tinkerspark Transponders?! We can''t go back. There''s no point in going back. Tinkertown sounds like nothing more than a ghetto compared to what Gnomeregan was! We will make Flaxwhisker Front into the new Gnomeregan. We just need time!',
    `RequestItemsText` = 'So, is Gnomeregan sending help?'
WHERE `entry` = 40048;

