UPDATE `quest_template` SET
    `OfferRewardText` = 'I''m impressed, $C, but there''s no time to lose. I will give you your next task, because you will still need to acquire a few more important components before we can proceed.$B$BSpeak to me again when you feel that you are ready for the challenge that lies ahead.',
    `RequestItemsText` = 'It was our folly... our doom that we took that last job. If only we hadn''t inadvertently stolen Lord Valthalak''s spirit, which was contained in the amulet; if only there weren''t those in our mercenary group that had been so greedy and divided it up amongst themselves. I''d be alive today, maybe tossing back a beer, or tossing one of my kids into the air.$B$B$N, don''t let the avarice of the ignoble in our old mercenary company be your doom as well.'
WHERE `entry` = 40056;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wow! You''ve gotten it, you''ve reclaimed our most valuable tool? I cannot thank you enough, outsider! We are forever in your debt, and now, the work can continue!',
    `RequestItemsText` = 'Have you done it? Have you recovered the Transponder?'
WHERE `entry` = 40057;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, it is done. It will take some time to bring all of the others into the fold, but I would not be a step closer without you. When I return to the great depths, I will have your name placed in honor. When we naga conquer the world, you will be spared to do as you please.$B$BTake this as a token of my gratitude, land-walker.',
    `RequestItemsText` = 'Have you killed him? Have you stopped this insurrection?'
WHERE `entry` = 40061;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Dragons sure can be imposing. I underŌĆö... Wait, you actually got it? Wow, that''s incredible! I''m shocked you managed to do this. Thanks again. We''ve needed this since we first came here.',
    `RequestItemsText` = 'So, have you tackled the Dragonflight yet?'
WHERE `entry` = 40062;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, wow, you did it, great job! I sure hope those murlocs didn''t give you much trouble. They sure can be nasty when you harm or scare them!',
    `RequestItemsText` = 'We need those Sprugbolts! They are an intricate part that we cannot just make.'
WHERE `entry` = 40063;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Splendid! So there really was one. The Gyronautical Compass will help a bunch around here. Thanks again for everything you''ve done. As thanks, take this. We can do without it.',
    `RequestItemsText` = 'Have you found the boat?'
WHERE `entry` = 40064;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wonderous! Oh, by my name, you''ve done a great job in getting this back! I was getting myself mentally prepared for having to work for another few months to restart everything.$B$BOh... My, it seems to have taken some damage...',
    `RequestItemsText` = 'Have you found our old work site? Did you reclaim the Turbocharged Wobble-free Fizz Disk?!'
WHERE `entry` = 40065;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My my, look at that! You''ve gotten everything I needed, and now I can get to work on putting this technology together for you!',
    `RequestItemsText` = 'I know it''s quite the list. Still, the quicker you get the items to me, the quicker I can get started!'
WHERE `entry` = 40066;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That''s it! I knew it would be on the second floor, now let''s get started!',
    `RequestItemsText` = 'Any luck? I''m still looking around, but I can''t find it.'
WHERE `entry` = 40067;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There, done! I appreciate all that you''ve done. Honestly, you''ve been a huge help to me around here. Without the Turbocharged Wobble-free Fizz Disk, I would be back in the Stone Age! Here, pick which one you like the most for all the trouble.',
    `RequestItemsText` = 'I''m working on it, not now.'
WHERE `entry` = 40068;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thanks for delivering this report. I trust Biggs can manage to get here. The Draenei of the region have become a problem that need to be dealt with.',
    `RequestItemsText` = 'Yes, may I assist?'
WHERE `entry` = 40071;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I cannot describe how pleased I am. I had generations looking down upon me with anger before, and I feel peaceful. Maybe I can return to Stormwind soon. Thanks again.',
    `RequestItemsText` = 'I don''t want to lose my father''s legacy. Have you had any luck?'
WHERE `entry` = 40072;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I cannot thank you enough. This will mean a lot in the long term, and I will put it to good use, I assure you.',
    `RequestItemsText` = 'Have you gotten them? The iron supplies I have will not last forever.'
WHERE `entry` = 40073;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, you come from Sorrowguard? It''s been about a month since I last heard from them. I assumed the worst.',
    `RequestItemsText` = 'Welcome to our blacksmithing shop. Can I help you?'
WHERE `entry` = 40074;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank the heavens. I have been worried about this order since the trouble with shipping weeks ago. At the least, we have a stock of swords available should anything bad happen, and it has freed up my iron for other things.$B$BHere. Take one as a way for me to pay you for your services.',
    `RequestItemsText` = 'You return with good news, I hope?'
WHERE `entry` = 40075;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These are quite heavy pieces of meat. They will last me a while if I ration everything out. Thanks again. You''ve kept us fed.',
    `RequestItemsText` = 'Have you had any luck?'
WHERE `entry` = 40076;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Huha! you did it, partner. Now I can finally make some coin and sell some of these off, but here. Don''t say I didn''t cut you in on the profits!',
    `RequestItemsText` = 'Any luck? The swamp is a dangerous place, so be careful!'
WHERE `entry` = 40077;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done. We are one step closer to salvation. The murlocs have been a thorn in our side for too long.',
    `RequestItemsText` = 'The murlocs, are they dealt with?'
WHERE `entry` = 40078;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done good work. For a while longer, we can remain undetected within the mountains and hopefully keep the eyes of the Horde off of us.',
    `RequestItemsText` = 'Has it been done? Have you kept our secrecy here?'
WHERE `entry` = 40079;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I have been waiting for these. It''s about time! Now I can finally get some work done.',
    `RequestItemsText` = 'Hello, can I help you?'
WHERE `entry` = 40080;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good work out there, $C. Keeping the road safe and thinning the pack of mongrels will only be for the greater good.',
    `RequestItemsText` = 'These mongrels are nothing more than a stepping stone for the Forsaken. Deal with them.'
WHERE `entry` = 40081;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Chief Rnarl, you have eluded me for so long, but no longer. Well done, $N, you did what I could not. You are a skilled fighter and worthy of praise. When Steepcliff Port gets more established, return, and we can share a corpse.',
    `RequestItemsText` = 'Have you slain the mongrels, or are you simply waiting for them to leave?'
WHERE `entry` = 40082;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent work. We have certainly put a dent in those Rogue Wizards, but I still feel there is more to be done.',
    `RequestItemsText` = 'We must act quickly, lest they begin to harness their magical power.'
WHERE `entry` = 40083;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent work. We have certainly put a dent in those Rogue Wizards, but I still feel there is more to be done.',
    `RequestItemsText` = 'Have you dealt with the wizards, $N?'
WHERE `entry` = 40084;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Another victoryŌĆöand more books to read. Thanks again, friend. Take these coins for the hard work.',
    `RequestItemsText` = 'Have you found their tomes, books and trinkets, $N?'
WHERE `entry` = 40085;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Gordon must have sent you, and on time too. He has been a steady help here at Glenshire. Without him, I would be quite out of luck working.',
    `RequestItemsText` = 'Hello, can I help you?'
WHERE `entry` = 40086;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You did it? Well, I was honestly not expecting you to return! I wish you had arrived a few days earlier, then We might have avoided this whole situation to begin with.',
    `RequestItemsText` = 'Back so soon, $C?'
WHERE `entry` = 40087;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, I can smell the blood coming from your bag. Is that the head of the mongrel? Good, very good. With the mine and tower back in our control, we are one step closer to achieving complete rule over the Tirisfal Uplands.',
    `RequestItemsText` = 'How goes the attack?'
WHERE `entry` = 40088;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So... It is done then. I hope in peace they may finally be let free from their delusions.',
    `RequestItemsText` = 'It pains me to ask, but have you gotten the badges?'
WHERE `entry` = 40089;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is a relief to know that the delusions these once wise elders spread have been halted. I hope they will find a better place in the afterlife.',
    `RequestItemsText` = 'Have they been silenced? Have the whisperings of the elders ceased?'
WHERE `entry` = 40090;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Arch Druid Staghelm will be overjoyed to hear such news! Please, on behalf of the Cenarion Circle, take one of these items.',
    `RequestItemsText` = 'Have you ventured into the grove yet?'
WHERE `entry` = 40091;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This means a lot to me. When I get back home, I will send a postcard and some coin for what you''ve done. Wish me luck when I set off!',
    `RequestItemsText` = 'Murlocs are a dreadful race of creatures, are they not?'
WHERE `entry` = 40092;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well in your task. If the Blackblood or Southsea Pirates had found this, they would have been able to raid innocent merchantmen with leisure.',
    `RequestItemsText` = 'Have you had any luck in finding the logs?'
WHERE `entry` = 40093;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Admiral Caelan''s death has been avenged, and the captain from each ship now lies in a grave. I thank you for what you''ve done. The marines will be overjoyed with such news of vengeance.',
    `RequestItemsText` = 'Have you had any luck?'
WHERE `entry` = 40094;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This... This is it. You found it. I must say, looking at this again, after all these years, is quite something.',
    `RequestItemsText` = 'I take it you have had no luck?'
WHERE `entry` = 40095;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done. With those scouts gone, they will think twice before sending an attack force on Glenshire.',
    `RequestItemsText` = 'Is it done?'
WHERE `entry` = 40096;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, yes. My greatest asset returns, successful, no less. With the sentries gone, we will have a much easier time dealing with the miserable humans.',
    `RequestItemsText` = 'Tell me, how goes the attack?'
WHERE `entry` = 40097;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmmm, you managed to impress my husband? Let''s see if you will do the same for me.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40098;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I have received news that the humans did their part precisely as planned. They have brought our little gift into their main camp. You did marvelously, my dear.',
    `RequestItemsText` = 'Back already?'
WHERE `entry` = 40099;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, I assume you are the famous $N of whom I''ve heard so much about, a pleasure to meet you. You can call me Vess.$B$BI understand that you need something from me, as it so happens, I also need something from you. So shall we talk business?',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40100;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I will assume that you and Magellas didn''t know what you got me into by sending me after those damned plates. I should have sent you to rob the royal treasury of Stormwind instead of giving you a menial task such as Bannor.$B$BBut a deal is a deal, and the Black Rose always holds up to her end of the bargain.',
    `RequestItemsText` = 'You''re still here? Don''t tell me that you are scared of a few pirates.'
WHERE `entry` = 40101;

UPDATE `quest_template` SET
    `OfferRewardText` = '<High Explorer Magellas reads the letter.>$B$BShave my beard and call me an elf, How in the world did she manage this? AhmŌĆ” I mean, this is more than good news, $N. We know the exact locations of the missing plates. And what is this mentioning of a cult?',
    `RequestItemsText` = '$N, I sure damn hope that you have good news for me because it appears that the Horde is on the move as well.'
WHERE `entry` = 40102;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''re back! And you have the first plate as well. Finally, some good news. I was starting to think that I''m cursed with bad luck.',
    `RequestItemsText` = '<Magellas doesn''t notice you as he mumbles to himself.>'
WHERE `entry` = 40103;

UPDATE `quest_template` SET
    `OfferRewardText` = 'WeŌĆ”$B$B<Grungis coughs.>$B$BWe were trying to come to an agreement with the Horde about the plates when those monsters fell upon us. They slew both our brethren and the Horde with such ease.',
    `RequestItemsText` = '$N?'
WHERE `entry` = 40104;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So that''s what happened. I should have taken Vess'' warning more seriously.$B$BBy Muradin''s beard, I hope that you killed every last one of them. But what of the plate? Tell me that Grungis'' sacrifice and the sacrifice of his men weren''t for nothing.',
    `RequestItemsText` = 'Any news?'
WHERE `entry` = 40105;

UPDATE `quest_template` SET
    `OfferRewardText` = '<I should get ready. Once I activate the pedestal, who knows what awaits inside.>',
    `RequestItemsText` = '<The Pedestal appears dormant.>'
WHERE `entry` = 40106;

UPDATE `quest_template` SET
    `OfferRewardText` = 'And the prodigy returns. In one piece, too. I''m glad to see you, $N. So, how did it go?$B$B<Magellas listens to your story with eyes wide open.>$B$BYou fought a what? And the Gate has been locked again? Marvelous. Well, not the part about Uldum getting locked again, but imagine what awaits us inside if the entrance alone was that exciting.$B$BNow we can inspect the second lock, and who knows, maybe one day make it into the Uldum itself. But don''t think for a second that I forgot about your reward. Here. I think you have more than earned this.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40107;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, Truthseeker sends his emissary? I tend to avoid meddling in the affairs of the Horde, but I owe my life to the Sage, so you have my ear, $N.',
    `RequestItemsText` = 'I was wondering when you would show up. Speak up, then.'
WHERE `entry` = 40108;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Mok''ra, $N. I''m assuming that the accursed demon is dead. Good, his ilk does not deserve anything more than death. Though my rage towards them runs deep, revenge was not my only motive.',
    `RequestItemsText` = 'How goes the hunt?'
WHERE `entry` = 40109;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The winds guided you back to me, $N. I''m glad to hear that my friend is still alive and well. A letter you say? Show me.$B$B<The Sage reads the letter, and a grin shows up on his face.>$B$BAh, words of a long-lost friend bring warmth to my heart, $C, but how did he manage to locate the exact location of the plates, and what is this talk about the danger ahead?',
    `RequestItemsText` = 'Any news, $N?'
WHERE `entry` = 40110;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''re back! And you have the plate with you as well. The sun shines upon us today.',
    `RequestItemsText` = 'Is there something you need?'
WHERE `entry` = 40111;

UPDATE `quest_template` SET
    `OfferRewardText` = 'We were trying to negotiate with the Alliance when they attacked. The madmen fought with a power that I have never seen.',
    `RequestItemsText` = 'It be you, $N.'
WHERE `entry` = 40112;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Dead? All of them? This... this is my fault for not listening to the warning of the spirits.$B$BThey will be remembered as true warriors of the Horde. But what of the plates, $N? Tell me that we did not sacrifice the lives of our friends in vain.',
    `RequestItemsText` = 'You return. What did you find?'
WHERE `entry` = 40113;

UPDATE `quest_template` SET
    `OfferRewardText` = '<I should get ready. Once I activate the pedestal, who knows what awaits inside.>',
    `RequestItemsText` = '<The pedestal appears dormant.>'
WHERE `entry` = 40114;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This only shows that there is much we need to learn. Between the gatekeeper that you have fought and the new lock on the gate, it would appear that we have our work cut out for us. I can only imagine what secrets Uldum hides inside. But, $N, that is the story for another time. You have done for us more than you can imagine, and for that, you have my eternal gratitude. I know that there will come a day when we will have to ask you for assistance again. Until then, I want you to have this for all you had to go through to help us.',
    `RequestItemsText` = 'How are you my friend?'
WHERE `entry` = 40115;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I must thank you dearly for the work you have put in. You have made it easier for us out here, but I feel you must do one more thing.',
    `RequestItemsText` = 'Have you made the forests a safer place, friend?'
WHERE `entry` = 40120;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The balance of nature in the region will be restored over time. I thank you greatly, on both behalf of myself and my wife. Take this, a family heirloom. May it serve you well.',
    `RequestItemsText` = 'The beast, Ghoststalker, have you dispatched him?'
WHERE `entry` = 40121;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, so Ansirem sent you. Good. I forwarded a letter to him quite a while ago, and it seems that this magical interference has grown ever more potent.',
    `RequestItemsText` = 'Hello, $R. It is good to see a friendly face in such a worn landscape.'
WHERE `entry` = 40122;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Splendid! Magnificent, in fact! I shall begin my testing at once.',
    `RequestItemsText` = 'Have you gathered the Ley-shards yet?'
WHERE `entry` = 40123;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It has been done? Have you dispelled the shrine? Let us see just how much of an effect this has had on our magics. Let us hope this is done once and for all.',
    `RequestItemsText` = 'Have the Naga been dealt with?'
WHERE `entry` = 40124;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Magus Bromley sent you? Well, it is good to hear from him. If he desires these shards to be examined, I will begin at once.',
    `RequestItemsText` = 'What brings you to Dalaran?'
WHERE `entry` = 40125;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Magus Bromley begins to read the letter.>$B$BOh... Well, things have gotten a whole lot more complicated if this is the case.',
    `RequestItemsText` = 'So, you return. What did Ansirem say about the Ley-shards?'
WHERE `entry` = 40126;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is done? Truly?$B$BYou have my thanks hero. Your name shall go down in the annals of Dalaran history. A defender of magic is truly one that stands for virtue. Please, take one of these artifacts. It is the least I can offer. May it serve you well.',
    `RequestItemsText` = 'Have you ended the dampening that lies upon Azshara?'
WHERE `entry` = 40127;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done. This contraption will take some time to repair. Do visit sometime in the future, and I may have news for you!',
    `RequestItemsText` = 'Did you find it?'
WHERE `entry` = 40128;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is it! Well done! Now I just have to fix this up, and we''re good to go soon! Come visit again in the future.',
    `RequestItemsText` = 'Is that a Power core in your pocket, or are you just happy to see me?'
WHERE `entry` = 40129;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hah! Perfect! Tell ya what, here''s an advance payment. I may require your aid again, so keep on keeping on! For now, do some other stuff. I got tinkering to do!',
    `RequestItemsText` = 'Did you find it? If not, get movin''! Time is money.'
WHERE `entry` = 40130;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Perfect! Yes, this will fit. Just needs a few modifications and we''ll be good to go! I knew I could count on you, partner! Here''s your share! Now leave, I got work to do. The sooner I patch this up, the sooner we''ll strike it rich! This technology will revolutionize my position within Labor Union!',
    `RequestItemsText` = 'Got the core for me? Come on, I''m countin'' on you here!'
WHERE `entry` = 40131;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Analyzer X-51 huh? The memory banks are restricted. I''ll have to figure out how to unlock them. Imagine the secrets it may possess! The secrets of the Titans! He''s very cooperative, though, so I''d say we''ve made some headway.$B$BI''ll keep working with Analyzer X-51 and see if he can help the dig site for now. I''ll call you once I have a hint regarding the memory banks. In the meantime, I have something for you. I have modified Analyzer X-51''s old depleted power core into an amulet you can wear.$B$BWhile the energies within are but a fraction of what the core once held, it can still sustain your magical energies if you use magic... If not, I bet we can sell it to someone who''d be interested.',
    `RequestItemsText` = 'Stand by... Processing.'
WHERE `entry` = 40132;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Analyzer X-48 huh? I had expected more than a robotic Gnome, but hey! It''s smart, and the analyzing ability can make me some dosh...$B$BBut more than that, there''s memory banks! I gotta find a way to dig into them. That''s where the true treasure is, partner! Schematics and knowledge belonging to the ancient Titans!$B$BWho knows what treasure it might hold! I''ll call you soon, partner! Oh wait, I made this thing for you from it''s original power core. You may find it useful or somethin''. Have a good one, partner!',
    `RequestItemsText` = 'Well well well...'
WHERE `entry` = 40133;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Look at that, a chunk of finely cut meat. Are you sure you are not some mysterious chef who is an adventurer by the day and chef by night? Anyways, thanks a lot. This will surely help. And here, I hope this is a suitable enough reward.',
    `RequestItemsText` = 'Back already?'
WHERE `entry` = 40136;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thanks, you might not have eradicated them completely, but this will surely make them think twice before attacking us again. Oh, and here is your reward.',
    `RequestItemsText` = 'Any luck?'
WHERE `entry` = 40137;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You are fast. Have you ever considered changing your profession to being a bounty hunter? Anyways, here is your share, and thanks for the job well done.',
    `RequestItemsText` = 'How goes the hunt?'
WHERE `entry` = 40138;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Finally, some good news. As promised, here is your reward.',
    `RequestItemsText` = 'Were you successful?'
WHERE `entry` = 40139;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, the necromancer is dead, this truly is reassuring news. Without you, we might have had to retreat into the Tirisfal Glades, and even worse, the Scourge would have been able to attack the Forsaken from both the west and east. You have done us a great service. I think you should have this as a just reward for your deeds.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40140;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My family has always been close knit, and I know that such a long length without hearing from me would certainly cause worry. I am simply happy to dispell such concern and let them know all is fine. Thanks again. This has meant a lot for me.',
    `RequestItemsText` = 'Have you seen my brothers yet? It will require travelling, but I would appreciate it greatly.'
WHERE `entry` = 40141;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, yeah this should be everything. A meal worthy for the Admiral! Here, have some as thanks.',
    `RequestItemsText` = 'Make sure those crawler legs are juicy!'
WHERE `entry` = 40142;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I salute you. You have made the waves a much safer place for all who travel them.',
    `RequestItemsText` = 'The Southsea Freebooters must be stopped if we are to ever leave this place.'
WHERE `entry` = 40143;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Admiral would be proud of everything you''ve done. I have no doubt it will take the Southsea many weeks before someone is their new leader, and even then, they will be very much weaker than they were before. Cheers, the dead of the fleet have been avenged.',
    `RequestItemsText` = 'Once the leaders are dead, the pirates will be sent into a state of chaos to establish new leadership.'
WHERE `entry` = 40144;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Loruk sent you. I am assuming he wishes to hear news about the Crescent Grove.',
    `RequestItemsText` = 'Yes? Is there anything you need from me?'
WHERE `entry` = 40145;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The rumors are true. There is something evil twisting the very roots of this place, and if left unchecked, could be a force unstoppable.',
    `RequestItemsText` = 'So, were my suspicions correct?'
WHERE `entry` = 40146;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is truly an accomplishment to be celebrated. For what you''ve done within the Crescent Grove, please take one of these. May they assist you well in your future endeavors.',
    `RequestItemsText` = 'We must root out evil, no matter the cost.'
WHERE `entry` = 40147;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is it! Haha! Such fine workŌĆöyou''d make one excellent swashbuckler aboard the Waterbreaker when she is repaired!',
    `RequestItemsText` = 'Any luck, matey?'
WHERE `entry` = 40148;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found this in the wreck of the pirate ship? I must say, that is some rather adventurous exploring! This logbook will help us learn quite a lot about pirates'' charts and patrol pathing and may help us locate some of their bases at sea.',
    `RequestItemsText` = 'Is there something that I can help you with?'
WHERE `entry` = 40149;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Deeptide Naga have been up to something, but that is not what we are here to investigate. Good work in dispatching the foul creatures. Let us hope they prove no further harm to the crew.',
    `RequestItemsText` = 'Has it been done? Have you traveled to Gillijim?'
WHERE `entry` = 40150;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is it! We had abandoned all serious hopes of reclaiming it, and now it is in our possession once again. A marvelous day, and it is all thanks to you.',
    `RequestItemsText` = 'The Aqua Stone is of much importance to us here, and we must recover it.'
WHERE `entry` = 40151;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is a shame what happened to the elves, but I know if we Kul Tirans were in a similar state, they would offer us the same kindness.',
    `RequestItemsText` = 'Have the crew been put to rest?.'
WHERE `entry` = 40152;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh... I had left this book upon an elvish vessel quite some time ago. Did you manage to recover it? I must say, I had considered this lost after the news of what happened. Thank you so much, my child, for returning this book.',
    `RequestItemsText` = 'Yes, child? Are you here to learn about the Light?'
WHERE `entry` = 40153;

UPDATE `quest_template` SET
    `OfferRewardText` = 'With their numbers thinned, it will take them much longer to organize an attack. Your actions have helped us greatly, but still, there is more to be done.',
    `RequestItemsText` = 'Brutality, that is all they know, and that is all they shall receive.'
WHERE `entry` = 40155;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Such a crude thing. An ugly trophy it will make. With the Tyrant King removed, the Gor''dosh will be splintered without leadership and may truly never recover. Many thanks. You have done good work this day.',
    `RequestItemsText` = 'There is no diplomacy to be had. All that is left is to kill the king.'
WHERE `entry` = 40156;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Primalist Jongi lets a small sigh escape from him and nods his head.>$B$BI know what had to be done to gather these, mon. It was necessary for my people, and eventually, the wounds may heal once more. Thanks for what you have done.',
    `RequestItemsText` = 'I would suggest bringing friends for such a task. The city will be difficult to enter.'
WHERE `entry` = 40157;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Manaz''ago takes his time to inspect the horn, slowly cracking a grin.> This be it. This be the one. Nice job, outsider. You did me good. There still be more to do, though, if you be wanting to help.',
    `RequestItemsText` = 'The Thunderhead I hear be a powerful creature. Keep your wits about you.'
WHERE `entry` = 40158;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This be it, mon. It radiates an almost unbearable heat, and, when lit, should go up in a mighty fire hotter than anything we can produce. You done me well. Thank you, mon. Your efforts here may bring back our old magics.',
    `RequestItemsText` = 'This jungle, you find it yet?'
WHERE `entry` = 40159;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I expected the Bengals be too much for you. With these fangs I will be creating the elixirs for our people. Thanks again, mon.',
    `RequestItemsText` = 'You be havin'' trouble?'
WHERE `entry` = 40160;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent work. Without the Hazu leaf, it would be much harder to make many of our recipes, and also to just simply relax, mon. Take this as a reward for my gratitude.',
    `RequestItemsText` = 'Any luck finding Hazu leaves out there, mon?'
WHERE `entry` = 40161;

UPDATE `quest_template` SET
    `OfferRewardText` = 'They had it coming for stealing all of my stuff and being so mean to me! Thanks for getting some of them back, it means a lot, here, for the hard work, one for you!',
    `RequestItemsText` = 'Any luck with getting back my Shell Necklace''s?'
WHERE `entry` = 40162;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, we are finally doing something about Lapidis. It will be a tough task, given how powerful the man is.',
    `RequestItemsText` = 'Oh, yes, has the Colonel sent you?'
WHERE `entry` = 40163;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hydromancer Lapidis, I have heard the name from before the horrific Third War. He was spoken as one of the most powerful of his kind. He refused to give us a lesson within Dalaran of his great magics, or to at the least, show us how it was done.',
    `RequestItemsText` = 'What brings you to Dalaran?'
WHERE `entry` = 40164;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent work, with this orb I can begin to work with the magic of this key to replicate some of the traces that are present.',
    `RequestItemsText` = 'Has the orb been obtained?'
WHERE `entry` = 40165;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There.. It is done, the key has had its magical properties manipulated, and should contain similar enchantment.',
    `RequestItemsText` = 'I think I''ve done it.'
WHERE `entry` = 40166;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmm. So there is still more to be done, who knew that Lapidis had such potent magic that not even Dalaran could crack it. There must be some other way.',
    `RequestItemsText` = 'Have you learned anything new about the key?'
WHERE `entry` = 40167;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, they are looking into Lapidis, it is about time. The man was always a shady figure, one who hid most of his studies and his work, and no doubt had nefarious purpose. I would suspect he is the reason we are all here.',
    `RequestItemsText` = 'Flakereef sent you? I haven''t spoken with him in quite a while now.'
WHERE `entry` = 40168;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Magus Valgon sent you, interesting, let me have a look then and I will see what I can do.',
    `RequestItemsText` = 'What do you need from me, adventurer?'
WHERE `entry` = 40169;

UPDATE `quest_template` SET
    `OfferRewardText` = '<The troll looks almost filled with glee>. You have done well, this wretch had much worse coming to him, but this shall do, especially given my current state. Fine, give me that key, I will do as you asked, my word is my bond.',
    `RequestItemsText` = 'Have you found that blackhearted mongrel yet?'
WHERE `entry` = 40170;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now that the key is attuned, and enchanted, we can begin our planning to destroy Hydromancer Lapidis.',
    `RequestItemsText` = 'How have you fared? Have you gotten any answers about the key?'
WHERE `entry` = 40171;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I''d like to say welcome aboard but ye are not ready to become a crew member yet, first ye must do us a favor.',
    `RequestItemsText` = 'Don''t waste me time mate, I be tryin'' to enjoy the sun and this here fine rum.'
WHERE `entry` = 40172;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Not so loud! You want the whole bruiser brigade on our hands? Just put that crate in and keep them coming.$B$B<After you bring each crate one by one you turn your attention towards Narkk.>$B$BFine work mate, here''s your pay. Now leave and don''t worry about it, you were never here today.',
    `RequestItemsText` = 'Aye?'
WHERE `entry` = 40173;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Aye, good job lad. This is all fer the greater good of the crew, aye?',
    `RequestItemsText` = 'Done already mate?'
WHERE `entry` = 40174;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Damn, look at this beauty, such a beautiful rock. Here, have some silver for the hard work of getting it for me. Some people should really learn not to flash their expensive rocks out in public, you never know who could be looking for them, heh.',
    `RequestItemsText` = 'It might be hard to track him down, but I''m sure you can do it.'
WHERE `entry` = 40175;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Eudokia looks toward the materials curiously.>$B$BThis should do, I will begin to prepare the spell now.',
    `RequestItemsText` = 'These materials will be the only thing to help Jang''zo. If I am correct, the dark magic could be influencing the trolls of the Razzari and driving them further into madness.'
WHERE `entry` = 40176;

UPDATE `quest_template` SET
    `OfferRewardText` = '<The Goblin takes the device and quickly inspect it.>$B$BYeah, this is it. Here, take your cash. Now scram, I gotta make sure this baby ain''t broken!',
    `RequestItemsText` = 'Look buddy, the longer we sit around here and talk, the higher the probability that thing is getting chewed up!'
WHERE `entry` = 40177;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What kind of monster am I to make ye sully such great rum, I hope one day I will be able to forgive meself.',
    `RequestItemsText` = 'Just go already, this action makes me eyes water.'
WHERE `entry` = 40178;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The rat finally lays dead. Put that bag down fer now, I''ll tell ye what ye gotta do next afore we get the deck all bloody.',
    `RequestItemsText` = 'Don''t got all day.'
WHERE `entry` = 40179;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Haha idiots! Now they know what''s gonna happen when they try to mess with us next, great job. And welcome aboard.',
    `RequestItemsText` = 'Shiver me timbers, ye actually made it. Were they mad?'
WHERE `entry` = 40180;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Their ship, the Harbinger, was sent fer some reason in Arathi Highlands. We dunno why, ''n we mighty don''t care that much either. All we care about right now be that they be dead, ''n we''ve landed once again a blow to the Blackwater Pirates.',
    `RequestItemsText` = 'Been a long road, eh?'
WHERE `entry` = 40181;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So they be thar after all. Good, some of me scallywags be trackin'' behind ye to see if they can get any kind of information while ye be wreakin'' havoc, ''n it seems we got what we needs.',
    `RequestItemsText` = 'Still as weak as they used to be?'
WHERE `entry` = 40182;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Aye, toss it on the floor over there, I''ll be mountin'' it on me wall in the room I sleep.',
    `RequestItemsText` = 'Bah, as ugly as it used to be.'
WHERE `entry` = 40183;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Thirael lays dead, you''ve fulfilled your promise to him. All that is left of him is a bag of coins you pick up.>',
    `RequestItemsText` = '<Thirael''s broken corpse lays before your eyes.>'
WHERE `entry` = 40184;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I''ll be damned, ye found something, eh? Looks like a damn normal compass to me.$B$B<Garfield frowns.>$B$BWhatever, we''ll try it some other time.',
    `RequestItemsText` = 'How goes the search fer legends ''n myths?'
WHERE `entry` = 40185;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good, somethin'' else ye''ve dealt with. I be startin'' to fear the thought of ye bein'' me enemy, mate.',
    `RequestItemsText` = 'Did it burn nicely?'
WHERE `entry` = 40186;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yo-ho-ho!',
    `RequestItemsText` = 'It be no great honour mate, this ain''t a knight''s ceremony.'
WHERE `entry` = 40187;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, Yeggle sent you? Heh, that guys a character he is, thankfully to hear he made it, some of those other gutter-rats were given a lucky way out of this world compared to what I dreamed of.',
    `RequestItemsText` = 'What, you haven''t seen a goblin before?'
WHERE `entry` = 40188;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hey, this might be it, I swear if theres a single crack on here, you''re gonna go and have to get another one, understand? Hmm... Seems spotless, good, this shall do just fine, now the final step!',
    `RequestItemsText` = 'Look pal, I can	 just tell you what I got planned or else you''ll steal my idea! Now find that Shell!'
WHERE `entry` = 40189;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now, we can unlock true riches!',
    `RequestItemsText` = 'The Gold Bar is the last ingredient for this recipe, hurry up, and get one pal!'
WHERE `entry` = 40190;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is my charm, but, something doesn''t seem right about it, too much time within the hands of a ghost may have, cursed it!',
    `RequestItemsText` = 'The Silver Strand can be a dangerous place now. Be careful when you go find my charm.'
WHERE `entry` = 40191;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Faldan takes some time mulling over the items, his gaze somber and somewhat steeled>. These items surely paint a rather dark picture. If the furbolg have been relying off the land, and the land itself has become tainted, it makes sense as to what has happened.$B$BTheir creations reflect upon their mind state, and in the past, when dealing with them, I have never come across any such ornaments or carved rocks. I must prepare a letter to Darnassus, to be delivered with haste.',
    `RequestItemsText` = 'Remember to be careful, there may still be some lurking about, or even other potential dangers.'
WHERE `entry` = 40192;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Faldan believes that I can assist in Ashenvale as far away as I am? The furbolg here have already begun to act in a similar manner, and there are much greater issues at stake then a tribe of savages out within the deep forests of Ashenvale.$B$BThis is not an issue that I can help with at the moment, my hands are tied, and I have more important things to deal with. When my current tasks are completed, I will begin to assist with the problems in Ashenvale.$B$BGood day.',
    `RequestItemsText` = 'Yes, what is it?$B$BI am busy, you must have something for me.'
WHERE `entry` = 40193;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This Mojo doesn''t look normal, it is dark, and thick, swirling with the seeds of evil deep within it. The Hazzuri tribe did the same long ago, and abandoned this past for a new fate. Now, they sent speakers and emmisaries to Zul''Razar in hopes to bring the Razzari into the fold.$B$BI had thought our leaders better then to listen to the words of madmen, to buy wares from the peddlers of evil misdeeds.',
    `RequestItemsText` = 'There be no time to waste! Each second that we remain idle and speak with one another, is another second that their minds rot away to this foreign evil.'
WHERE `entry` = 40194;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, it is done then, you have braved Zul''Razar, and killed the leaders. The skulls will be a reminder to any who betray what we really are. I hold hope that my people can see reason, and deep down will know this had to be done for the best.$B$BI must still find a way to reverse this Tainted Mojo, but until then, I thank you, your efforts have surely helped my people. Without you, who knows what would have happened to this island.',
    `RequestItemsText` = 'Chief Imaz''ul is a coward for what he has done, the chief of our tribe is to hold strong, even in the face of tempting offers.'
WHERE `entry` = 40195;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is done, you have gotten revenge for each and every one of us. I cannot thank you enough for smiting him down, if only the fates had been different, if only he acted with honor and kept his word, perhaps we would be back home.$B$BIt is not something to dwell on, but we Kalkor will find our place in the world. You have earned esteem within our community, and restored our spirits, I wish you the best in your future.',
    `RequestItemsText` = 'Have you had any success in finding Lykourgos?'
WHERE `entry` = 40196;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This a tragedy, for all of Ashenvale to have such a thing happen. The forest truly has lost a bright mind this day, withered away to a foul madness that lingers in the trees.$B$BDo not feel bad, there was no averting this fate for Old Greypaw, he was a danger to both himself, and all who were near him. I pray for his spirit to transcend to Elune, and be watched for all eternity.$B$BAs much as I hate that it ended like this, I must still give you my thanks, for Greypaw was not himself, if he were around, he would have asked for such mercy to be released from his madness.',
    `RequestItemsText` = 'He may act hostile, but I assure you, it is not within his nature, and deep down, he truly is a kind soul.'
WHERE `entry` = 40197;

UPDATE `quest_template` SET
    `OfferRewardText` = 'All this variety, you know what they say, variety is the spice of life! When we make our next journey this will all surely keep everyone in good spirits.$B$BLast time we ventured out, we barely had any ale left over, most of the barrels were destroyed, and let me tell you, Garfield would have my neck if anything like that ever happened again! Thanks for the hard work ye scurvy dog, take this money as a thanks.',
    `RequestItemsText` = 'If you want to be a real smuggler , let me tell you, you need connections, and those connections need to be trustworthy.'
WHERE `entry` = 40198;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, you actually are stronger then I first thought. So many big ogre think they are tough just because they think they are and then they get smashed. You are tough, and strong, and you prove it, maybe you are a real ogre. War must continue, it is the only way we can go forward.',
    `RequestItemsText` = 'What, you too weak to kill panthers and creepers? Do I need to send someone else?'
WHERE `entry` = 40199;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, you actually are stronger then I first thought. So many big ogres think they are tough just because they think they are and then they get smashed. You are tough, and strong, and you prove it, maybe you are a real orc. We must continue, it is the only way we can go forward.',
    `RequestItemsText` = 'Have you found Tanglemoss? It may require more then just yourself for this to be done.'
WHERE `entry` = 40200;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, Malos and I have spoken on occasion. He has been studying the corruption of nature for some time now, and has even offered his assistance in understanding and, perhaps someday, reversing the corruption of my kind.$B$BHe is a good and kind soul, and if he needs my help, then I will do whatever is in my power.',
    `RequestItemsText` = 'It is not often I have visitors. What can I assist you with?'
WHERE `entry` = 40201;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I see. So it is as I feared. Broken free of my control, gnarled and enraged, it has been twisted beyond recognition by the undercurrent of corruption that plagues Teldrassil.',
    `RequestItemsText` = 'You are back. Do you bring word from Tasala of my treant''s whereabouts?'
WHERE `entry` = 40202;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Malos contemplates the roots you hand him with great concern.>$B$BIt would appear that the roots are decayed, suggesting the treant was already deceased by the time you found it. What a horrible fate for a protector of the forests... No, for any of nature''s creatures. I cannot begin to fathom how this could have happened.$B$BThis is a disturbing revelation indeed, and I am afraid that it has only created more questions. My research continues without the breakthrough we had hoped for, it seems. Nonetheless, you have done a great service to the forests and myself.$B$BPlease take one of these items as a token of my gratitude.',
    `RequestItemsText` = 'Have you found my treant? We cannot allow it to roam freely and wreak havoc in the forests.'
WHERE `entry` = 40203;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Have you come to aid in securing the Darnassus perimeter?$B$BThat is good to hear. We are in need of all the assistance available with my forces spread so thin. Recent events have strained our resources, as we now defend not only Ashenvale and Darkshore, but must have details all across our homes here in Teldrassil.',
    `RequestItemsText` = ''
WHERE `entry` = 40204;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done a great service to the Kaldorei today, $N. Though I weep for the fate of our former allies, sorrow cannot give way to weakness. Elune guided your hand in defending our people''s lands, and for carrying out her will, you are to be rewarded.',
    `RequestItemsText` = 'Is it done, $N? We cannot afford to fail here, lest Darnassus itself be at risk.'
WHERE `entry` = 40205;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, such fine specimens these are, I will make haste at once to prepare it for the camp, and save some extra for my tinkering purposes. Thanks again for all of the work out there, I can imagine you got pestered by aggresive wildlife in your searching.',
    `RequestItemsText` = 'You must search the entirety of the swamp, Sorrowmoss can grow almost anywhere!'
WHERE `entry` = 40206;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Potent, extremely potent, it would appear that the deathstrike tarantulas have been growing more strong over the past months. I will still attempt what I can, thank you again $N, perhaps I can best such a venom one day.',
    `RequestItemsText` = 'Deathstrike Venom can be fatal if used improperly, be careful in handling it!'
WHERE `entry` = 40207;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Such a rarity this is, many in Orgrimmar wouldn''t even have the opportunity to have something as powerful as this could potentially be! I must thank you, and thank you again, I will make good use of this.',
    `RequestItemsText` = 'The power of the Green Dragonflight is not something to be underestimated, be careful in getting that scale!'
WHERE `entry` = 40208;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I never imagined the day would come so soon, Sorrowclaw always was able to elude my efforts.$B$BYou are a much greater then myself, please, be rewarded for your glory of defeating such a beast!',
    `RequestItemsText` = 'Sorrowclaw is a dangerous beast, be careful within the swamp.'
WHERE `entry` = 40209;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, now you know what is at stake, and you will help me retake these islands, if not for your own selfish whims of ''virtue'' to stop some evil.',
    `RequestItemsText` = 'Open your mind, and listen, wisdom can be found anywhere.'
WHERE `entry` = 40210;

UPDATE `quest_template` SET
    `OfferRewardText` = 'We move forward, as much as the satyr are nothing more than worthless agents of a fading order. They still had this coming, and much more should I ever have the agency to torment them.$B$BWith these horns and lotus I can begin to channel energy to locate this dark source with my own magics. Until then, there is much more to do before we can unveil the source of the evil that taints the islands.',
    `RequestItemsText` = 'There is much work to do, and little time, get out there and do my bidding.'
WHERE `entry` = 40211;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Who did you say you were sent by again?',
    `RequestItemsText` = 'Travel, and with haste. There is much to do, and little time to do it, mortal.'
WHERE `entry` = 40212;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Zul''Hazu was a breeding ground for the corrupt, and the defiled. They swept aside my magic and my teachings for a chance to indulge in greater powers. They are nothing but harlots to the highest bidder, and it is retribution to dispense justice upon them.',
    `RequestItemsText` = 'Have you dealt with those rebellious insects yet?'
WHERE `entry` = 40213;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well mortal, your help here, I must admit, has been insturmental. You have earned a place upon these islands as long as you desire to be here. As long as you understand that my rule here is now concrete.$B$BAs a token of my appreciation to enact revenge, and give me back my rightful throne, you are to be rewarded, as one should for noble deeds. May you find use for the treasure I offer, and may you prosper on whatever path you choose.',
    `RequestItemsText` = 'We must be cautious.'
WHERE `entry` = 40214;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Revenge, such a sweet thing, perhaps now, people will know not to step all over Shizwackle!$B$BI''ve learned a valueable lesson thanks to you pal, not to just trust every old sap with a bundle of gold offering riches.$B$BTake this coin for the trouble, I actually pay people for work!',
    `RequestItemsText` = 'They deserve every licking they get, don''t up and go soft on me!'
WHERE `entry` = 40216;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Blatarg was looking for me huh? I''m doing fine, I just have new company, but they''ve learned well enough to leave me alone. Perhaps you can be of assistance, I got some stuff I need worked out!',
    `RequestItemsText` = 'Yes, you need something, or just here to talk?'
WHERE `entry` = 40217;

UPDATE `quest_template` SET
    `OfferRewardText` = 'We meet again Glasseye, this is the eye that stared back at me in my dreams, and now I hold it within my fingers. I sense that I may be able to make great strides with this, and I thank you greatly. No longer will my dreams be haunted, you''ve done me a great service.',
    `RequestItemsText` = 'Glasseye may have strong, magical powers, be sure to keep your wits about you.'
WHERE `entry` = 40218;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Those stupid pirates thought that they were so smart taking over that mine, now look at them, DEAD! Puny $R has done good for me, and I reward good work, here, take this, you''re now an official mercenary for Maul''ogg!',
    `RequestItemsText` = 'While you''re talking, who knows what''s happening to my emerald, go get it!'
WHERE `entry` = 40219;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You carry that weapon well, but it is not enough to be an adequate marksman. The Dark Lady, Sylvanas Windrunner, freed you from the shackles that bound you to the will of the Lich King. You will return her gracious gift by giving of yourself for her cause.$B$BIf you cannot commit, I will see to it personally you are buried again in the hole you crawled out of. I will train you to be one of the many arrows that strike the hearts of her foes.$B$BCome to me often, that I may teach you new skills. I will be watching you carefully and gauging your growth here in Deathknell.',
    `RequestItemsText` = 'You must know why I sent for you, $N. Seeing a fallen marksman rise again is such a rare glimmer of hope in this accursed land. Lady Sylvanas will no doubt be pleased that she may one day soon have ranks of ranger under her command again.$B$BI will see to it that you are molded into a proper vessel for fulfilling that dream. Embrace now your destiny as a Dark Ranger.'
WHERE `entry` = 40220;

UPDATE `quest_template` SET
    `OfferRewardText` = 'For the Light! For Azeroth!',
    `RequestItemsText` = 'Go forth, champion!'
WHERE `entry` = 40221;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yeah, this is it, those pesky rats think they could stop me? Hah! Good work pal, you certainly got some gumption.',
    `RequestItemsText` = 'Any luck? I can''t be waiting around all day.'
WHERE `entry` = 40222;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My my, see, I told you, there are always deals being made! Profits to be made, always of course, especially if you know how to come between it, heh! Here, take this coin, if you''re interested in more work, I got it.',
    `RequestItemsText` = 'If you don''t go looking around, you wont find a thing.'
WHERE `entry` = 40223;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Let me guess, ''Slip'', huh? He always wanted to get the crew back together after we parted ways. I figured he''d just slink away to some part of the world and live it out on the gold he made!',
    `RequestItemsText` = 'Howdy, what can I do for you?'
WHERE `entry` = 40224;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, he did uphold his end of the bargain... Wally Wisecrack huh, that two faced piece of rat filth!$B$BI am going to get my revenge, and you''re going to be the weapon I unleash upon this miserable prick.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40225;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It''s done then, and good, the spirits of those that were lost because of this cold hearted goon may find peace in whatever grave they found themselves in. I can''t thank you again for all the help, and for reconnecting me with some old crew across the world.$B$BTake one of these items, as a token of my gratitude.',
    `RequestItemsText` = 'He is a dastardly fellow, don''t let him know you''re coming, or you''ll never find him.'
WHERE `entry` = 40226;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Interesting, there may be something developing between the Twilight Runners that has made them more aggresive, but it could also be due to the overpopulation and need for food, thanks again. This has dispelled some worry for me with all of the nightmares I hear about back in Teldrassil.',
    `RequestItemsText` = 'The Twilight Runners can be aggresive, so keep your wits about you.'
WHERE `entry` = 40227;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great work, Ironforge would be proud of the actions you have done this day, please, take these coins, as a token of our gratitude.$B$BPerhaps one day we may resume our work here on a more larger scale!',
    `RequestItemsText` = 'If there is to ever be peace, then we must act with swiftness.'
WHERE `entry` = 40228;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great work, Ironforge would be proud of the actions you have done this day, please, take these coins, as a token of our gratitude.$B$BPerhaps one day we may ressume our work here on a more larger scale!',
    `RequestItemsText` = 'They are incredibly stubborn, and will not give up without a fight.'
WHERE `entry` = 40229;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That book meant quite a lot to me, I never thought I would see it again, thank you.',
    `RequestItemsText` = 'That place is crawling with murloc, I would advise you steel yourself for what must be done.'
WHERE `entry` = 40230;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Watch Paladin Janathos sent you, well I know the man well. He spoke with me before his departure out to Sorrowguard. It is good to hear that he is alive. If he desires me to keep this book within the Cathedral I will do as such, perhaps the words written inside will benefit those of the faith.',
    `RequestItemsText` = 'How may I assist you?'
WHERE `entry` = 40231;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, then it is done? The Archbishop has always been a friend of mine, his convictions and word in the light has always been true.$B$BThis scroll will continue to guide our actions here, and keep us safe within Sorrowguard.',
    `RequestItemsText` = 'Have you spoken with Benedictus?'
WHERE `entry` = 40232;

UPDATE `quest_template` SET
    `OfferRewardText` = '<A smile would crest across Janathos'' face as he looks upon the orb>. My mentor would be proud of us to recover such an item. You truly are blessed of the light for your services here in this dark corner of Azeroth.$B$BPlease, take this as a token of my appreciation, and walk with swiftness upon this earth, as blessed by the light.',
    `RequestItemsText` = 'The Orb of Kaladus holds great power in the light. My mentors artifact should not be wielded by zealots.'
WHERE `entry` = 40233;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Would ye look at that! You actually managed to get your hands on one, its not like every day I go asking for someone to produce a rare weapon, and expect them to bring it to me. This is rare $N, very rare, its not every day someone gets there hands on an Untempered Runeblade.$B$BI made a promise that I would share my knowledge, and I will, perhaps we can temper the blade!',
    `RequestItemsText` = 'Have you had any luck? I would suggest you focus your attention towards the Dreadlords.'
WHERE `entry` = 40234;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I shudder to imagine traveling that deep into Corin''s Crossing for a book- one that might not even have what we''re looking for. You did good work either way, now, lets see if this book holds any knowledge that we can use!',
    `RequestItemsText` = 'I would make sure to look over both shoulders while you are there, and bring some holy water, the place is cursed I tell ye!'
WHERE `entry` = 40235;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Farsan''s brow twitches upon hearing the name ''Wilhelm''>. Him huh? Didn''t he sign up to go and join those Argent fellows?',
    `RequestItemsText` = 'Yes, are you here to learn the deeper secrets of Arcana?'
WHERE `entry` = 40236;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Upon seeing the book, Farsan would smirk from ear to ear>. Excellent, as I have said, a favor for a favor then.',
    `RequestItemsText` = 'Have you procured what I have asked?'
WHERE `entry` = 40237;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Heh... So that is why you have come, it is not often that I am intrigued by your kind, not many would be so bold as to approach me willingly, knowing what I am capable of. Very well then, perhaps you may be of use for me, and should you prove a good asset, I will grant you what you desire.',
    `RequestItemsText` = 'Yes, mortal?'
WHERE `entry` = 40238;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, incredibly well, much more then I had originally expected, If you wish to learn how to create a Tempered Runeblade, I shall grant you such knowledge.',
    `RequestItemsText` = 'Do my bidding mortal, and dispatch my enemies. It is for the greater good of this world for these magics to be taken from the hands of lesser beings.'
WHERE `entry` = 40239;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I must say, with how long you have been gone, I figured you were lost to the madness of some terrible curse! Hah! Phew, what a relief that is, knowing that you''re still alive, so, I take it you learned something valueable?',
    `RequestItemsText` = 'Welcome back friend! What have you learned, was my friend of much help to you?'
WHERE `entry` = 40240;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is all that is required, well done $N! Now, I can direct you to where it must be done, once you temper the blade, it will be bound to you and you alone!',
    `RequestItemsText` = 'It will be a lengthy process to require so many materials, but they will be required for the tempering process!'
WHERE `entry` = 40241;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Why look at these beauties! These shells could certainly be used for all sorts of things, thanks again, no wonder Gigno saw good things in you!',
    `RequestItemsText` = 'We need more methods to shield our projects, have you had any luck?'
WHERE `entry` = 40242;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I can breathe a sigh of relief. At one time I could walk the entirety of the beach, I could journey through the buried ruins of the old city, now submerged beneath the waves, but now, I am confined to this very tower. Perhaps one day I will be free to journey again.',
    `RequestItemsText` = 'Have the invasive species been dealt with?'
WHERE `entry` = 40243;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Eldara Relay-Orb is one of its kind, and incredibly rare, without this my ability to study, and communicate with the last Keeper''s of Azshara were both tampered. I cannot thank you enough for finding it.',
    `RequestItemsText` = 'Have you recovered my valueable items?'
WHERE `entry` = 40244;

UPDATE `quest_template` SET
    `OfferRewardText` = 'After many long years, it is returned. This Harmonization Gem was worthless within the hands of those naga, for they deal with magic they will never understand. You have done a great favor for us Keepers.',
    `RequestItemsText` = 'When the Gem is returned, then we can begin construction of a staff.'
WHERE `entry` = 40245;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good work in finding one, I was beginning to have my doubts. The power the Satyr wield in such a rod is but a fraction of the power we used to have in our glory. The Ley-lines flowed with a power unimaginable, it was so strong that even now, after so much time has past, the energy still lingers.$B$BAs dampened as it is now, it still holds power we must preserve, and keep secret.',
    `RequestItemsText` = 'Walk with caution, the Satyr are lackies of a much greater power.'
WHERE `entry` = 40246;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Another chapter begins, the Keepers of Azshara may not fade into memory this early.',
    `RequestItemsText` = 'I must concentrate.'
WHERE `entry` = 40247;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Most excellent. I can see this darkhound is eager to sink its fangs into the Scourge and gnaw on their bones.$B$BYou have performed... adequately.',
    `RequestItemsText` = 'Do not waste my time. The Dark Lady has no need of the weak, nor do I for that matter.'
WHERE `entry` = 40248;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This creature flies around you with a spirit of ease. It would seem that you have earned its trust.$B$BYou are improving.',
    `RequestItemsText` = 'Being undead does not make you a cripple. My expectations of you are no lower than if you were still alive.'
WHERE `entry` = 40249;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This beast no longer feels lost, your strength of will earning its trust and coaxing from it once suppressed emotions. Though we dominate, we are not incapable of affection for our new companions.$B$BNever forget that each beast has its own story. Your actions will bring to them salvation... or destruction.',
    `RequestItemsText` = 'Time and dedication this path takes. As your luck would have it, I have begun to see you possess both.'
WHERE `entry` = 40250;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Insom''ni takes his time to gaze over the necklace, his body seems invigorated, and energized by its very presence. Slowly, he would place it around his neck, and exhale a heavy breath of relief.>$B$BIt has been a long time since I have felt such energy, it is as if both halves to my soul have been reconnected after many long years. I can not even begin to explain such a feeling, too long has it been that I have been seperated from my essence.$B$B<A grin would spread across Insom''ni, his face taking on a very intense gaze>.$B$BNow, let us begin our work.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40251;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I have heard faded messages of someone helping Keeper Iselus, and now I have you before me. The Eldarath Harmonization Gem has been recovered then, good to hear.',
    `RequestItemsText` = 'Can I help you?'
WHERE `entry` = 40252;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I can feel the energy flowing once again, it will no doubt attract the attention of outside forces, or perhaps those who wish to uncover the secrets of Azshara for themselves. Our next step will be a crucial one, and will be required to keep the mysteries of this land from being uncovered.',
    `RequestItemsText` = 'When you have spoken the phrase the magic that once held the stone and made it dormant will be inactive. This spell was placed long ago to deter any outside entities from interfering, if we can act quickly, I will be able to do as I need.'
WHERE `entry` = 40253;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Us Keepers could not fulfill the lengths of our duties, and I imagine we will not last forever, one day the Tower of Eldara will lose its master, and perhaps one day I may fall as well. I know not what has happened to the others, though I still hope they are alive and well.$B$BIf we are to fulfill atleast one of our duties, then we shall dispell much of the great magics buried beneath the waves, under the sands. The last thing we intended was for something much more foul to untangle the web of secrets we created.$B$BI must thank you again $N, for everything you have done, you have assisted us in a time of great need, and perhaps now we may last many more years, especially with the energy of the Ley-Lines flowing, and old secrets dispelled. Me and Keeper Iselus have only you to thank, without you, we would have been aimless in our goals.',
    `RequestItemsText` = 'The energy used in Dire Maul is truly fascinating, I can feel it from all the way here. I believe this will be our only chance of fulfilling our oath as Keepers.'
WHERE `entry` = 40254;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Brother Kristoff asked for you to assist us, he is a kind man, and faithful to the light. We could use all the help we could get around here, this bastion is in a state of disrepair, not to mention the threats all around.',
    `RequestItemsText` = 'Hello?'
WHERE `entry` = 40255;

UPDATE `quest_template` SET
    `OfferRewardText` = 'We have dealt a blow to the Old Horde and delayed their progress. I have been ordered to pay you in gold for your duties. If you see more of our enemy, make sure to kill them.',
    `RequestItemsText` = 'Have you done as I asked?'
WHERE `entry` = 40256;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Blackrock Slayers were a truly terrifying foe, you have done good work.',
    `RequestItemsText` = 'Have they been eliminated?'
WHERE `entry` = 40257;

UPDATE `quest_template` SET
    `OfferRewardText` = '<A grin would spread from ear to ear across Emberguts face> So long it has been gone, and here it is!$B$BYou''ve done well, I never thought I would see it again and it is in my hands. Maybe now Embergut can be the strongest ogre!',
    `RequestItemsText` = 'Have you found the orb?'
WHERE `entry` = 40258;

UPDATE `quest_template` SET
    `OfferRewardText` = '<A humming, radiant energy comes from the surface of the dark metal, its energy is almost mystifying to your mind. As you stand before it, the knowledge of runes swells within your mind, and guides your hand. With the materials provided, you begin the process of tempering the Runeblade>.$B$B<After the process is complete, you feel whole, you feel complete. You can feel sheer power flowing from the blade, it is calling you, it is urging you toward destruction. Within that moment, you lose all knowledge of the processes which drove your hands to create such a weapon, it''s touch within your hands is euphoric. You were made for this very moment, you have found your purpose on this world>.',
    `RequestItemsText` = '<The Anvil''s presence is intimidating>.'
WHERE `entry` = 40259;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Morpheus sent you from Deathknell?$B$BIt''s been a while since I have seen someone wish to walk this path. You are most welcome, that is if you can keep up with the training.',
    `RequestItemsText` = 'Be quick about your business, I don''t have the leisure to be here all day.'
WHERE `entry` = 40260;

UPDATE `quest_template` SET
    `OfferRewardText` = 'And you are...?$B$BOh, yes. Morpheus and Lanissa spoke on your behalf. I suppose it is time, then, to offer you my expertise.',
    `RequestItemsText` = ''
WHERE `entry` = 40261;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, well, what have you brought me? My, what a gorgeous, fresh specimen! Allow me to assist you with that.$B$BI will teach you the incantation by which you can persuade creatures who still walk among the living to serve you faithfully.',
    `RequestItemsText` = ''
WHERE `entry` = 40262;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well.$B$BIt is a tragedy what all the Scourge took from many of us beyond our sanity. That Boltrus still clung to emotions from his past life stirs something within me. I wonder... By another fate, could I have been in his place? A barely sentient yet mindless husk?$B$B... Alas.',
    `RequestItemsText` = 'How goes your task?'
WHERE `entry` = 40263;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I see. Lord Cruk''Zogg will bring us into ruin, I must come up with a new way to convince him.',
    `RequestItemsText` = 'So, have you spoken with him?'
WHERE `entry` = 40264;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I see a great future in you, you have done well, now, let us begin.',
    `RequestItemsText` = 'Have you had the opportunity to collect what it is I asked?'
WHERE `entry` = 40265;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A bold plan he has come up with, I would not have suspected Bol''ukk to speak such words. But perhaps there is no other option, I will begin to work on an elixir.',
    `RequestItemsText` = 'Have you spoken with Seer Bol''ukk?'
WHERE `entry` = 40266;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, Haz''gorg sent you. It''s been some time, now, tell me what he desires from me, cause no doubt he needed something!',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40267;

UPDATE `quest_template` SET
    `OfferRewardText` = '<The troll looks almost filled with glee> You have done well, this wretch had much worse coming to him, but this shall do, especially given my current state. I will do as asked, and assist Haz''gorg.',
    `RequestItemsText` = 'Have you found that blackhearted mongrel yet?'
WHERE `entry` = 40268;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Insom''ni would inspect the Ligment curiously, and nod his head>. This shall do just fine.',
    `RequestItemsText` = 'Why are you here, you should be searching for a Ligment.'
WHERE `entry` = 40269;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Insom''ni would inspect the Ligment curiously, and nod his head>. This shall do just fine. This shall do just fine.',
    `RequestItemsText` = 'Have you ventured within the Sunken Temple?'
WHERE `entry` = 40270;

UPDATE `quest_template` SET
    `OfferRewardText` = '',
    `RequestItemsText` = 'I see.. Then let us finish what we have set out to do.'
WHERE `entry` = 40271;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Haz''gorg would let out a great sigh of relief> What has been done here today cannot be celebrated with great enthusiasm, we have done but a small evil for the good of the Maul''ogg. Unknowingly, my kind will be thankful for your efforts, even if they do not know anything has transpired. I ask of you to keep your silence, and for your assistance, I offer you a gift from my kind.',
    `RequestItemsText` = 'Is it done?'
WHERE `entry` = 40272;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, finally! Now I can get back to my passion. Here''s the rod I promised, take good care of it. If you don''t know how to fish, try in Orgrimmar. No doubt there''s someone there that can help.',
    `RequestItemsText` = 'Have you had any trouble? They''re practically everywhere, so be careful.'
WHERE `entry` = 40274;

UPDATE `quest_template` SET
    `OfferRewardText` = 'We are one step closer to uncovering the secrets of this place, but I feel there is moe to be done in order to secure ourselves here.',
    `RequestItemsText` = 'Have you dealt with the Naga?'
WHERE `entry` = 40275;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is done then, with their leaders killed the Naga will be uncoherent, and nothing more then a disorganized mass. Even the largest army will always lose to one more disciplined, and focused. We have truly weakened their position this day, and perhaps forever.',
    `RequestItemsText` = 'Have you had any progress with the Naga?'
WHERE `entry` = 40276;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I wish I was there to see the look on her miserable face when she realized one last time that she was never able to beat me. Neither in life nor in death, my dear sister. You have proven to be quite an ally, $C. From this day forth, consider yourself welcome to my court... when I rebuild it, of course.',
    `RequestItemsText` = 'Is it done?'
WHERE `entry` = 40277;

UPDATE `quest_template` SET
    `OfferRewardText` = 'And who might you be? The Duke sent you? On with it then, I''m a busy man.',
    `RequestItemsText` = 'I''m busy.'
WHERE `entry` = 40278;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A magical lock? Naturally. Nothing can ever just be simple.',
    `RequestItemsText` = 'What did he say?'
WHERE `entry` = 40279;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A letter for me? That ignorant son of a... Apologies, $C. That man certainly knows how to get on my nerves. I will do this for him, but this is the last time I deal with that accursed family.',
    `RequestItemsText` = 'And who might you be?'
WHERE `entry` = 40280;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You are persistent, to say at least. Let''s see what Melenas had in store for us.',
    `RequestItemsText` = 'Hmm...'
WHERE `entry` = 40281;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I already received notice from my husband that he found someone capable enough to assist our noble house with such an important task. You certainly outdid yourself with this one. Ah, so it requires my blood to open it, a good thing I still have a bit of that left.$B$BBut this spell will be tricky. Anyways, I doubt that you wish to stay here for days while I prepare the ritual. And to the matter of your reward: I will allow you to pick one of the relics from my family armory. I hope that you find this agreeable, after all the help you have provided us.',
    `RequestItemsText` = 'Speak quickly.'
WHERE `entry` = 40282;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good. They will fear us.',
    `RequestItemsText` = 'Bloodfist Point is at danger as long as the Naga slither and the Banshees wail in those forests.'
WHERE `entry` = 40283;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ha! I knew you had it! You are a strong $C, very strong. It reminds me of my youth, cutting down hordes of enemies!',
    `RequestItemsText` = 'The Legash Encampment is close to our base. I will be able to see you fighting, so don''t disappoint me. I want some fun.'
WHERE `entry` = 40284;

UPDATE `quest_template` SET
    `OfferRewardText` = 'He met with my friend? I know I should be cautious to heed the words of a stranger, but I trust him.$B$BIf he says the last place he remembers seeing him was at the Temple of Arkkoran, then that must be it.',
    `RequestItemsText` = 'I will find his Blade.'
WHERE `entry` = 40285;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It''s broken...',
    `RequestItemsText` = 'I will find his Blade.'
WHERE `entry` = 40286;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found it. This Blade will be whole again, mark my words $N.',
    `RequestItemsText` = 'There is only sorrow to be found within Azshara.'
WHERE `entry` = 40287;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Katokar Bladewind would take his time studying the fel energy before a sigh of relief would escape him>.$B$BThis should be enough, you''ve done well.',
    `RequestItemsText` = 'The Fortress of Jaedenar is the most powerful bastion of the Legion in Felwood, strike them down.'
WHERE `entry` = 40288;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is done then, and with that, he shall walk freely with those he regarded as heroes. He shall be buried with his blade, I can guarentee that, you have put my mind, and my heart at rest $N. Take my Binding as thanks for the work I could not do.$B$BIt is not often that someone comes and offers to aid in such a manner, your spirit is truly that of great heroes, bear my Binding with pride, and honor.',
    `RequestItemsText` = 'This is important to me $N.'
WHERE `entry` = 40289;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is some good game, $C. But I have more to ask from you.',
    `RequestItemsText` = 'Got the meat? No? Then get moving.'
WHERE `entry` = 40290;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You impress me. It''s not easy to impress old Nulda. Ill make sure to put the claws to good use, hope to see you around.',
    `RequestItemsText` = 'Scared already?'
WHERE `entry` = 40291;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, this is all I need. Now, let me prepare the ritual.',
    `RequestItemsText` = 'Have you found the ingredients yet?'
WHERE `entry` = 40292;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The vision gave us more questions than answers. The city must''ve been Zin-Azshari, the dying peoples must''ve been Highborne of the old. The wave represented the Sundering. It was a warning. A warning, that all of this can happen again.',
    `RequestItemsText` = 'The ritual must not be disturbed.'
WHERE `entry` = 40293;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A dragon, you say? Well, me and my friend there, Brutan, noticed something weird happening in these forests, which could be explained by the presence of the Dragonflight.',
    `RequestItemsText` = 'Waste no time.'
WHERE `entry` = 40294;

UPDATE `quest_template` SET
    `OfferRewardText` = 'How many? This is worse than we expected.',
    `RequestItemsText` = 'Have you been to Lake Mennar yet? It''s in the southern part of Azshara.'
WHERE `entry` = 40295;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, young one. Talom did well, advising you to come to me.',
    `RequestItemsText` = 'Blue Dragonflight in such numbers. This is really worrying.'
WHERE `entry` = 40296;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The elements are calmed, for now. Thank you, $C. Your help will never be forgotten. We owe you much.',
    `RequestItemsText` = 'So, have you done it?'
WHERE `entry` = 40297;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Bristelfur begins to smell your satchels with excitement and awaits the treats you''ve brought her. After eating and a short moment of enjoying her toy, she seems barely incapable of keeping from flying off while waiting for you to get in the saddle.',
    `RequestItemsText` = 'Bristlefur eyes you up and down but pays you no mind. It seems you have yet to gather the items that would forge a bond between the two of you.'
WHERE `entry` = 40298;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It truly shines as its told in the legends.$B$BAn accomplishment of this magnitude can only be overshadowed by the reward.',
    `RequestItemsText` = 'Unless you''ve got everything I need, you''re wasting my time.'
WHERE `entry` = 40299;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What is this? From a secret admirer?$B$BOh, silly Androl. He hasn''t realized that I have known for years. I wish he would be more forward about his affections. Nonetheless, I thank you, $N. Please take this coin for your troubles.',
    `RequestItemsText` = 'Elune be with you, $C. What brings you to me?'
WHERE `entry` = 40300;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Jhawna sent you? Blessed be the ancestors. I haven''t heard from her in a while!$B$BAnd she sent me a sack of her and the means to make it. Always treasure your friends, $N, not even distance stays in the way of true bonds.$B$BEnough melancholy, I got some coins for you and if you wait a while I can even offer you a loaf of bread!',
    `RequestItemsText` = 'Come and rest for a while.'
WHERE `entry` = 40301;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found it!$B$BOh my, I think it''s hatching $N! Quick what a beautiful little baby tu-- it''s not a baby?!$B$B<The turtle seemed to have gotten a growth spurt and stares at you>.$B$BI think those Nagas used their magic on this poor baby turtle, it seems to believe you are its parent, there goes my chance to have a talking turtle in the Faire.$B$BWell, enjoy your new companion friend, and visit us from time to time, I really wonder if it will ever speak.',
    `RequestItemsText` = 'Do you have it?'
WHERE `entry` = 40302;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This... This is the head of Lapidis! It is done, his horror has ceased?!$B$BWhat you have done here is truly heroic, truly worthy of legend. You have assured our survival upon this island, and triumphed over a great evil, a great evil that would have surely been our downfall. Kul Tiras and the Anchor have been given justice, for all of the crimes this man has caused against our people.$B$BPlease, as a token of our gratitude, and in Caelan''s name, have a just reward.',
    `RequestItemsText` = 'Hello again $N, what can I do for you?'
WHERE `entry` = 40303;

UPDATE `quest_template` SET
    `OfferRewardText` = '<A smirk would press to Kor''gan as he looks upon the Pendant>.$B$BThis is it, you''ve done well, I''ve always had some suspicions about Var''zhog and his power, with this, we can continue.',
    `RequestItemsText` = 'The Pendant of Ardan will be required if we wish to proceed, find it.'
WHERE `entry` = 40304;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmm.. It would appear that the Substance you have brought me is extremely potent, and quite magically powerful. Whatever being is at work here stirring these forces is quite certainly strong.',
    `RequestItemsText` = 'Have you had any success in dealing with the ethereal?'
WHERE `entry` = 40305;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes? What is it that you want with me? I can sense a powerful magic about you.$B$BFrom Karazhan, well, let me have a look then.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40306;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, my suspicions were correct, the power that has begun to rise is coming from below Deadwind Pass. Well, then we must make haste, unless a great evil comes to threaten the Horde.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40307;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, the stories were correct, the items have been obtained, with the Pendant of Ardan, the Mark of Karazhan, and the key itself, I can begin to work my magic.',
    `RequestItemsText` = 'Be dedicated in your searching, if we are to destroy this evil, then we must act fast.'
WHERE `entry` = 40308;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, the stories were correct, the items have been obtained, with the Pendant of Ardan, the Mark of Karazhan, and the key itself, I can begin to work my magic.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40309;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Do you feel it? A great fog has been lifted over the area, and the foul blackness of magic is beginning to subside. You have done the work of great heroes, and have acted with a decisiveness I have not seen! You bring honor to your ancestors, please, take one of these items as a tribute of my thanks in helping me.',
    `RequestItemsText` = 'Do not fear the darkness $N, stride with a great determination and you may still find glory.'
WHERE `entry` = 40310;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Magus Ariden Dusktower would take his time inspecting the pendant, before letting out a bright smile>.$B$BThis would appear to be it, you''ve done well, my suspicions were correct. It is not every day some ogre learns to manipulate magical energy after all.',
    `RequestItemsText` = 'The Pendant of Ardan will be required to proceed $N, collect it, and with haste.'
WHERE `entry` = 40311;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is it, interesting, the substance is much more potent then I had originally imagined, even just from looking at them this close I can feel an intensity lingering upon it.',
    `RequestItemsText` = 'A foul magic stains the air, our actions must be dedicated and swift, find the ghosts around Karazhan, and free them from torment.'
WHERE `entry` = 40312;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Why hello there, you bring word from Magus Ariden? Why, he set out for Karazhan weeks ago, this must be of importance if he has sent you.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40313;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, Ansirem believes the energy is also coming from the Karazhan Crypts? Then that settles it, we must reforge the key, and enter forcefully.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40314;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Magus Ariden Dusktower would look over the items, and let out a breath of relief>.$B$BPerhaps there is a hope after all, you have done well, now, let us begin.',
    `RequestItemsText` = 'If we are to enter the Karazhan Crypt, then we must take action, I suggest you find some friends to help, for our foes may be quite strong.'
WHERE `entry` = 40315;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The key has been reforged with the magic that once created it, now with it in our grasp we can strike hard at the evil that lurks within that long forgotten crypt.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40316;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A great evil has been vanquished this day, it is on the shoulders of heroes like yourself that this world remains uncorrupted by darkness!$B$BThe powers that once drew me here have begun to settle, I must thank you greatly for all of the work you have done in uncovering this mystery. Please, on behalf of the Kirin Tor, take one of these items as a thanks.',
    `RequestItemsText` = 'It is unknown how deep the Crypts may burrow within Azeroth, so tread carefully once you are inside.'
WHERE `entry` = 40317;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What''s this? This letter bears the crest of Lordaeron. I must say, it has been quite some time since I received a letter marked with this sigil.',
    `RequestItemsText` = 'How can I help you?'
WHERE `entry` = 40318;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, there is no help coming? It seems we must look to ourselves to keep the last torch within these lands alight.$B$BThank you for delivering the letter. You are dismissed.',
    `RequestItemsText` = 'Any good news?'
WHERE `entry` = 40319;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, fine pieces, and they don''t seem touched by the taint of the plague. They will do nicely, thanks again, it means a lot.',
    `RequestItemsText` = 'Have you gotten them yet?'
WHERE `entry` = 40320;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, that took a bit, I told you I knew the way through. Welcome to Kaneq''nuun!',
    `RequestItemsText` = 'So, I take it you must be ready to go, yes?'
WHERE `entry` = 40321;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, hello there, so it was Inunquaq who brought you here? I must say, I worried for him when he did not return from his journey to the southlands, but I am pleased that he has returned.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40322;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My, these look tasty, they will go well with the food that we already have. You''ve done a kindness for us in bringing this offering before my people, I welcome you to Kaneq''nuun as family outsider.',
    `RequestItemsText` = 'You''re back, have you gotten the claws, or are you just seeking shelter from the cold?'
WHERE `entry` = 40323;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done it? Well, I do hope I made the correct decision, perhaps now he will watch over us favorably from wherever he is. For everything you''ve done, I offer you this, as a thanks for my people, for freeing a most beloved spirit.',
    `RequestItemsText` = 'Tarqsiku should not be underestimated, be cautious.'
WHERE `entry` = 40324;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I must say, a southlander like yourself certainly is quite resourceful. These pelts you have gathered will be put to use, thanks again for keeping us safe.',
    `RequestItemsText` = 'They are a ferocious beast, be careful when you are out there!'
WHERE `entry` = 40325;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is it, I didn''t expect it would still be there. You have my thanks, with this mallet I will create a new home, and find somewhere new to settle.',
    `RequestItemsText` = 'Crescent Grove is a dangerous place, I would advise that you bring help if you are to go there.'
WHERE `entry` = 40326;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Look at all this stuff! Spanners, Flaxpipes, Togwig Gears! This will last the Bloodsail quite a while, and give me a whole bunch of opportunity to tinker! Thanks again $N, this is a haul!',
    `RequestItemsText` = 'Make sure you keep yours eyes open out there!'
WHERE `entry` = 40327;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, excellent, the less of them swimming about, the better for all of us. You''ve done well, here, keep one, it might serve you well.',
    `RequestItemsText` = 'The Naga can be a fearsome foe, battle hard, and put them down.'
WHERE `entry` = 40328;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Willy would take his time inspecting the pelt for imperfections>. This might just be the one $N , nice job out there, this will certainly bring us some gold.$B$BHere, take your cut for the good work.',
    `RequestItemsText` = 'Any luck yet? Remember, it needs to be immaculate.'
WHERE `entry` = 40329;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, McCoy sent you did he? Well, I can understand why, we''ve hit some problems, and haven''t been able to send out the goods that have been requested, perhaps you can help.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40330;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Heh, we''ve butted heads with the Skullsplitter a few times, they should know not to mess around now. Nice job in getting back the booty.',
    `RequestItemsText` = 'Those trolls can be some mean sons of bitches, make sure you are cautious out there.'
WHERE `entry` = 40331;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hey there, looking for anything specific?$B$BOh, that''s why you''re here huh, heh.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40332;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Welcome back, this is it huh?$B$BNot bad, nice work in getting it, now you know where we get some of our poisons, so keep it hush.',
    `RequestItemsText` = 'Any news?'
WHERE `entry` = 40333;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, I take it everything is back in order huh? Well, from what I read you''ve done a good job. You''ve solved our supply issue, and for that you should be commended, take one of these items from the hoard, you''ve earned it matey.',
    `RequestItemsText` = 'Any news?'
WHERE `entry` = 40334;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Monkeys, all of them, serve them right. Let me help you out with those!$B$BI hope you found some coins for your pockets because I''m afraid I don''t carry anything with me.',
    `RequestItemsText` = 'Hurry Cap''n, there be much to do.'
WHERE `entry` = 40335;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Jeesie''s eyes sparkle at the treasure>.$B$BOh Cap''n, it''s beautiful, come put it on my neck, the sight will be the most treasured reward you''d ever get!',
    `RequestItemsText` = 'Oh Cap''n you''re a tease and a half, quite the charmer I may say.'
WHERE `entry` = 40336;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Aye! Now let''s try it.$B$BThis be strong and fine rum, here ye go Cap''n yer share.',
    `RequestItemsText` = 'Can''t wait to test it or taste it.'
WHERE `entry` = 40337;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now you understand the sheer importance of the order.',
    `RequestItemsText` = 'So, have you come to listen?'
WHERE `entry` = 40338;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I am impressed, it seems we have another who is willing to join. Your bravery has been noted, and your excellence with magic is evident in completing this task. We dwarven mages do not shy from assisting the kingdom.$B$BAs a reward for your bravery, please, take this, as a token of joining The Azurestone Order.',
    `RequestItemsText` = 'Have you braved the Gol''Bolar Quarry?'
WHERE `entry` = 40339;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is a fine sample, $N. If you should acquire more, bring it to me for purification.',
    `RequestItemsText` = 'The Infinite Dragonflight has begun their assault upon the timeline in every conceivable way, splintering timelines with their relentless assaults. It is from these shattered timelines that Corrupted Sand manifests.$B$BThis Corrupted Sand can be purified by members of the Bronze Dragonflight here in the Caverns of Time, that we may repair the damage caused. If you so happen to acquire any Corrupted Sand, bring it to me without delay.'
WHERE `entry` = 40340;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, $N. This sample of Corrupted Sand shall make our purification easier. We are always in need of more, should you find it, and ready to accept your contributions.',
    `RequestItemsText` = 'The purification of Corrupted Sand is a lengthy and complex process, which is why it is best to gather large quantities to be purified at one time. If you should obtain 10 samples of Corrupted Sand, our work to purify them and repair the damage to the timeline would be that much more efficient.$B$BThe broken timelines beyond these portals should be abundant in Corrupted Sand. Only a brave soul need venture in to obtain it. Be on guard in the Caverns of Time, for it is a perilous place for the uninitiated.'
WHERE `entry` = 40341;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A part of my heart is put to ease, but even having his trecherous head does not repair the damage his betrayal caused me. I thank you greatly for putting this to rest, here, take this, as a token of my gratitude.',
    `RequestItemsText` = 'Chronar is the most foul of traitors, hunt him.'
WHERE `entry` = 40342;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I am happy to see that my messages have been received from Orgrimmar, welcome to Spirit Rise, it is time for you to undergo an age old tradition.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40343;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, you have been sent here by Beram Skychaser you say. You must be another who is looking to learn the ways of old, come, sit around, there is much to learn.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40344;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A dedicated mind, it takes true perseverance to find such a rare plant, you have done well.',
    `RequestItemsText` = 'You must be dedicated in your path if you wish to learn the ways of the spiritwalker.'
WHERE `entry` = 40345;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is done, the spirits have communicated with me.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40346;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I have been expecting you.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40347;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Do you understand the burdens of a Spiritwalker? It is to understand the lessons of the past, and to live in harmony with the spirit world. To pass this information on to those in the mortal realm, and to make sure these values never fade.$B$BYou have impressed us $N, you have done much for this world, and for the good of others and for that we are greatful.',
    `RequestItemsText` = 'Have you spoken with everyone?'
WHERE `entry` = 40348;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, you be a new one, I can feel it within your spirit mon. Let us not waste time.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40349;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Such fine samples, yes... This shall do nicely!',
    `RequestItemsText` = 'You be gettin that mojo mon?'
WHERE `entry` = 40350;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Heh, it took quite a lot of concentration, but here we are mon!',
    `RequestItemsText` = 'Yes Mon?'
WHERE `entry` = 40351;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, that is why you are here, you seek my wisdom, and my knowledge as your ancestors before you have, very well.',
    `RequestItemsText` = '<N''ribbi stares at you>.'
WHERE `entry` = 40352;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done it, I am impressed. You are worthy of my power, and I bestow upon you the energies that many of your ancestors have used.$B$BMay your travels be plentiful, there is a future ahead of you shaman.',
    `RequestItemsText` = '<N''ribbi stares at you>.'
WHERE `entry` = 40353;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hm, not something I would''ve gone with. Alas, it be yer ship ''afore all.',
    `RequestItemsText` = 'Any idea yet mate?'
WHERE `entry` = 40354;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This pleases me greatly, $N!$B$BYou''ve begun your way towards my respect, thank you.',
    `RequestItemsText` = 'Is the fool dead?'
WHERE `entry` = 40355;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The language is unreadable to you and you bet it''d be unreadable for the rest of your crewmates back at the retreat, it is by now you realize you should''ve probably recruited a historian.',
    `RequestItemsText` = 'The notes appear to be torn and dirty.'
WHERE `entry` = 40356;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Told ya Vil''doŌĆÖs got a nose for dis things! But look at ya figurin'' out where to go and what we be huntin''!',
    `RequestItemsText` = 'Got anythin'' boss mon?'
WHERE `entry` = 40357;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You stare at the huge statue and can''t believe your eyes, it''s made of pure gold! You dare question whether it''s still there when you realize you will not be able to move it one inch.$B$BSeveral curses come out of your mind when you remember Vil''do''s words. Not only did you come this far, but you can''t even grab them!',
    `RequestItemsText` = 'Comparing the drawing from the journal it seems you''re in the right place and this is the right statue.'
WHERE `entry` = 40358;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Okay bub, stand back while I assemble this thing, yeah?',
    `RequestItemsText` = 'Got them yet?'
WHERE `entry` = 40359;

UPDATE `quest_template` SET
    `OfferRewardText` = 'As you push the button the shrink ray activates! Mumbling all sorts of sounds at first you start cursing the corpse of the goblin who built this, not only was he a double-crosser but he was no engineer! Or so you''d think, sooner than later the statue began to shrink, no weighing less, and could easily be placed in your backpack.',
    `RequestItemsText` = 'You stare at the statue with the engraved name once more and get ready to pull the trigger.'
WHERE `entry` = 40360;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Dis be great mon, very great, and ya be sayin'' ya can make dem big too? Ah dis be da greatest haul we got in a while now, great job mon, great job. Here be some coin for da troubles, I be takin'' dem statues and dat ray now.',
    `RequestItemsText` = 'Aye boss mon, ya be back!'
WHERE `entry` = 40361;

UPDATE `quest_template` SET
    `OfferRewardText` = 'And so you have it $N, or is it Captain $N? I guess I''m a crewmate from now on, well, one only YOU can see.',
    `RequestItemsText` = 'Am I dead?'
WHERE `entry` = 40362;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your kindness surprises me, $C. With the Galak''s raid crippled, the tauren will be free to continue their peaceful lives.$B$BThere is still yet work to do if I am to earn their favor.',
    `RequestItemsText` = 'Is it done, $C? As an exile, this is my only chance to find acceptance in amongst others.'
WHERE `entry` = 40363;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I have never heard such a strange tale and I struggle to believe it to be true. We have never known the centaur to be anything but beasts seeking our extinction. If she is yet true to her word, perhaps I can assist.',
    `RequestItemsText` = 'I see that you have something on your mind. Speak freely.'
WHERE `entry` = 40364;

UPDATE `quest_template` SET
    `OfferRewardText` = 'She had you retrieve the pelts of prairie wolves and did not tell you what I would need to do with them to earn their favor.$B$BAlthough I am not the most gifted in the ways of magic, I believe I have just the idea to solve their trial.',
    `RequestItemsText` = 'You''ve returned and yet it seems as if there is more for us to work toward.'
WHERE `entry` = 40365;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These pelts are of even finer quality than I expected, $N. The enchantment is almost as if it is naturally woven into the fabric itself and will serve to protect newborns through the harsh change of the seasons.$B$BWe will not deny Kherra the opportunity to prove herself further to us. We understand there is more to her than the average centaur. It will take time for her to be welcome in Bloodhoof Village, but I have to wonder... are there more like her?',
    `RequestItemsText` = 'You''ve returned. Was she sincere in her words?'
WHERE `entry` = 40366;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done. I hope this helps put my kin to rest while ensuring the safety of the survivors. Don''t worry, their sacrifice was not in vein. Now we can continue the excavation and learn more about the Titans and this site.',
    `RequestItemsText` = 'Is it done $R? These constructs killed some of my best diggers. I want them turned to rubble!'
WHERE `entry` = 40367;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $R. Four years ago my commanding officer ordered me to escort a caravan of villagers out of Lordaeron. I remained with them as they settled here and built Hawk''s Vigil. Arthas himself had returned to Lordaeron to lead the genocide of his own people.$B$BMany perished to give us a chance to escape, Jennalla among them. With the incense produced from the Auriblooms, we honor their memory.',
    `RequestItemsText` = 'Is it done, $R? The Auribloom should not be too difficult to find.'
WHERE `entry` = 40368;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, what a lovely haul this is! Look at these samples! Fascinating! Wait... What''s this? Ah, it seems you have found yourself a small companion! Perhaps you should study its behaviour before you decide on your favourite seasoning.',
    `RequestItemsText` = 'As scary as those pinchy crawlers may look, they tend to run away from you faster than you can catch a fish. Have you gathered any parts we could study further?'
WHERE `entry` = 40369;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found it! Thank you, thank you, thank you! Woooah, it really looks like a sun! You''re my new best friend!$B$BThere aren''t many children here besides me, so I feel lonely sometimes. But with this necklace, I can be brave like my mom and dad.$B$BThey were sailors and one day I''ll be a marine just like mama Eliza!',
    `RequestItemsText` = 'I like stargazing at night. I know my mom is looking at me and I don''t want her to think I''ve forgotten her.$B$BDid you find her necklace?'
WHERE `entry` = 40370;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The stories about Tyrande Whisperwind were true after all.$B$BIn her letter, she writes she was not only honored to stand with Prince Kael''thas, but once fought beside Dath''remar Sunstrider himself, the founder of our great kingdom!$B$BBut it seems not all Kaldorei think as she does. We shall soon work to prove ourselves in their eyes as well.$B$BFor now, with the approval of most of the Alliance''s leaders, our future grows more secure.$B$BI hope we can count on you again, should such need arise. And $N, thank you for all you have done.',
    `RequestItemsText` = 'Have you met them yet?'
WHERE `entry` = 40371;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I have no objections. During the Second War, the High Elves were instrumental in defeating the Orcish Horde. And I cannot deny that the refugees have done a lot for the Alliance.$B$BIt would be remiss of me to reject their aid. Even Lady Prestor has taken a personal interest in this matter and petitioned to send the military abroad to help.$B$BWith that said, please give my response to Alah''thalas.',
    `RequestItemsText` = 'What is it, $R?'
WHERE `entry` = 40372;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There is a saying among the Wildhammer dwarves of the north: "You can sooner count on a High Elf than on the hair of your own beard."$B$BThe Senate will need to discuss this matter in detail, but know that I am keen to believe the Wildhammers, as I have been supportive of the Quel''dorei''s accession to the Alliance for a while now. Especially after all the refugees have done to help secure Loch Modan.$B$BNot to mention the aid we received from them during the Second War, without their help and that of the Alliance, who knows how the war would have turned out for us.$B$BAs I see it, now is our turn to return the favor. Deliver my reply, and I wish you safe travels.',
    `RequestItemsText` = 'What is it, $R?'
WHERE `entry` = 40373;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmm, an expected proposal. Even if we ignore the deeds that the High Elves have done in the past, one cannot deny that having another powerful ally on our side could prove beneficial.$B$BYes, you may let our friends at Alah''Thalas know that they indeed have the support of our brilliant people.',
    `RequestItemsText` = 'What is it, $R?'
WHERE `entry` = 40374;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The plight of the Quel''dorei is one that grieves me deeply. Their noble Prince Kael has been in my prayers since the day our paths crossed in Lordaeron.$B$BI would gladly welcome Silvermoon into the Alliance, yet there are those among my people who believe they are beneath Elune''s boundless compassion, those who see the High Elves and can only forebode the repetition of the darkest chapter of our ancient history.$B$BI shall help you dispel these doubts. You may go, with my answer and my blessing.',
    `RequestItemsText` = 'What is it, $R?'
WHERE `entry` = 40375;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You see, when the Scourge ravaged our lands, we were left beaten and broken. So I gathered those I could find and set out to reclaim this outpost. It was not an easy task, but now we have a place to call home.$B$BI only wish Prince Kael''thas could have seen all of this. But, now is not the time to mourn. We have to hold our heads high and look forward.',
    `RequestItemsText` = 'So you are the one that everyone has been talking about. It''s a pleasure to meet you, $N.$B$BMy name is Vereesa Windrunner, and I wanted to personally thank you for your efforts in bringing our people closer to the Alliance.$B$BAlthough it is unfortunate that some Kaldorei still doubt our intentions, we will prove we are not what they would fear us to be.'
WHERE `entry` = 40376;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found and slew Dra''lox Felstar?$B$BI knew the High Priestess was right in her judgement of the Quel''dorei.$B$BNow allow me to return the favor.',
    `RequestItemsText` = 'What can I do for you?'
WHERE `entry` = 40377;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I know the message you bear. Word of Felstar''s demise has been spreading swiftly.$B$BMay the Night Warrior ever bear steel with you, $N. May such be the fate of all those who dare threaten us.$B$B<She lets out a long sigh.>$B$BYou might have begun to glimpse the rift that divides Darnassus. Many of Fandral''s druids have rescinded their former protests about the accession of the Quel''dorei, but the Archdruid himself remains unyielding.$B$BYet with his support on the matter ebbing, nothing more ties my hands in granting Silvermoon my full support.',
    `RequestItemsText` = 'What news do you bring?'
WHERE `entry` = 40378;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What wonderful news! With Darnassus'' Endorsement, the Alliance has unanimously agreed that the Quel''dorei of Alah''thalas will officially join the Alliance. Let us discuss further steps, my friend.',
    `RequestItemsText` = 'What brings you here?'
WHERE `entry` = 40379;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Ashylah Starcaller blinks as you make your request.>$B$BYou have to understand, $N, our moonwells are not like the Well of Eternity of old. Their waters have been cleansed, and sanctified by the Great Mother.$B$BThey can replenish health, mana and even stave off hunger. But we hold them as hallowed shrines, we cannot grant them to others so easily.',
    `RequestItemsText` = 'I take it the Quel''dorei sent you. What can I do for you?'
WHERE `entry` = 40380;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What you ask is difficult, but not impossible.$B$BIf you render me aid, I will do what I can to help.',
    `RequestItemsText` = 'What brings you here?'
WHERE `entry` = 40381;

UPDATE `quest_template` SET
    `OfferRewardText` = 'An exhilarating experience. Let us agree to avoid these perilous ventures from now on, yes? Jests aside, you have my gratitude. And as promised, I will do my best to help you with your case.',
    `RequestItemsText` = 'May Elune guide us.'
WHERE `entry` = 40382;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hail to you again, $N. What tidings do you bear?$B$B<Tyrande opens and reads the missive>$B$BI see. The ancestral sickness that once plagued even Dath''remar Sunstrider still assails the hearts of the Quel''dorei. That is a heavy burden to endure.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40383;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Elune will soon lay her divine hand upon these lands. Stand back and watch as her silver light blesses this sacred ritual.',
    `RequestItemsText` = 'The preparations for the moonwell are ready.'
WHERE `entry` = 40384;

UPDATE `quest_template` SET
    `OfferRewardText` = 'We have been waiting for you. We are ready to depart, on your word, but make sure you bring all the necessary equipment. There is no telling what awaits us there.',
    `RequestItemsText` = 'How may I help?'
WHERE `entry` = 40385;

UPDATE `quest_template` SET
    `OfferRewardText` = 'With the beach secured and our fortifications up, we have finally made a first step in reclaiming these lands. But we need to be careful. Their commander mentioned someone named Lord Dar''Khan.$B$BCould he be their leader? And why does that name feel so familiar? Anyways, we won''t get much from overthinking. Let us wait for the rest of the reinforcements before continuing our campaign in Quel''thalas.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40386;

UPDATE `quest_template` SET
    `OfferRewardText` = 'With the beach secured and our fortifications up, we have finally made a first step in reclaiming these lands. But we need to be careful. Their commander mentioned someone named Lord Dar''Khan.$B$BCould he be their leader? And why does that name feel so familiar? Anyways, we won''t get much from overthinking. Let us wait for the rest of the reinforcements before continuing our campaign in Quel''thalas.',
    `RequestItemsText` = 'Welcome back, $N. I hope that you bring good news.'
WHERE `entry` = 40387;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My suspicions confirmed, they are far more cunning than I gave them credit for. This does not seem to be over, $N. Thank you for getting this information to me. I''ll send a runner to Orgrimmar and Far Watch Post right away to make sure they hear of this Death''s Head.',
    `RequestItemsText` = 'You look troubled, $N. Tell me what bothers you.'
WHERE `entry` = 40388;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The head of Zalazane? No, it could never be that easy.$B$B<As you and the great chieftain observe the witchdoctor''s head, it slowly loses its form and resembles that of another troll, perhaps a mindslave>.$B$BIt will not be so easy to reclaim the Echo Isles from Zalazane and his army of slaves, but at least we have contained the threat for now.$B$BThere are those who will not understand my decision to keep Thrall from reclaiming the isles for my tribe, but we are indebted once to the Warchief and his people and now we will prove that their faith was not misplaced. When the time comes, $N, I hope to see you on the battlefield beside my tribe.',
    `RequestItemsText` = 'I do not have long to speak, $C. What is it you bring to me?'
WHERE `entry` = 40389;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Kolkar have proven a long-standing threat to our people since settling on these shores, but it appears they will trouble us no further. Your victory over the centaur today is just one step closer to securing Durotar from local threats.',
    `RequestItemsText` = 'What do you have there, $C?'
WHERE `entry` = 40390;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The wretched Kolkar dwindle in their presence throughout Kalimdor under the watchful presence of the Horde. We are blessed for our alliance and may begin focusing on larger threats lurking just out of sight.$B$BThe very land we depend on cries out for help, $N, and we must figure out how best to answer her plea quickly. Your victory brings me joy and solace to the many tauren that suffered under Kolkanis'' cruel raids before the Horde''s arrival.$B$BGo with the Earthmother''s blessing on your journey.',
    `RequestItemsText` = 'You carry the presence of a victorious hunt, $C? Come closer, show me what you carry.'
WHERE `entry` = 40391;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you for coming. I will get straight to the point.',
    `RequestItemsText` = 'Hello.'
WHERE `entry` = 40392;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you for coming $N. As you can surmise this is not a visit of convenience. I need your help.',
    `RequestItemsText` = 'Oh, hello there!'
WHERE `entry` = 40393;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you for coming my friend. I may need your help as a dangerous situation is unfolding.',
    `RequestItemsText` = 'Hello.'
WHERE `entry` = 40394;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A book of mine? Hah, I am no reader...$B$BCould it be?',
    `RequestItemsText` = 'I am forever restless.'
WHERE `entry` = 40395;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I can''t believe he didn''t toss this away.$B$BIn my anger I might''ve mistaken CookieŌĆÖs actions, he was always a scared catfish. He must''ve panicked.$B$B<Grayson sighs for a moment>.$B$BDrying the book, keeping this necklace...$B$BOh $N, what have I done.',
    `RequestItemsText` = 'Is he done with?'
WHERE `entry` = 40396;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have removed the taint of demonic influence from this world. Their vile schemes will not come to fruition, take heart in that.',
    `RequestItemsText` = 'I grow impatient, have you dispatched the mongrels?'
WHERE `entry` = 40397;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This has been a long time coming, I would have never imagined this monster would be removed from this world so soon.$B$BYou may have the potential to follow in my footsteps, given your prowess in tracking demons.',
    `RequestItemsText` = 'Each day we must stay vigilant to combat the growing darkness.'
WHERE `entry` = 40398;

UPDATE `quest_template` SET
    `OfferRewardText` = '<A smirk creeps across Niremius'' face as he glances upward and nods his head..>$B$BAt long last, I have the gemstone. I thank you greatly.',
    `RequestItemsText` = 'Have you removed this deceitful orc from the world, have you recovered my Gemstone?'
WHERE `entry` = 40399;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Heart of Hazzas. You are more resourceful than I anticipated, $R. Now, as promised, let''s forge your weapon.',
    `RequestItemsText` = 'There is taint all across Azeroth, can you feel the world itself calling for aid?'
WHERE `entry` = 40400;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My work is done, as I have promised, a Glaive worthy of my namesake. Use it well, and keep Azeroth safe.',
    `RequestItemsText` = 'This will take time.'
WHERE `entry` = 40401;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Claws perfect, Tharg thanks new friend.',
    `RequestItemsText` = 'Tharg friend angry with Tharg.'
WHERE `entry` = 40402;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Pretty gift! Me still angry at Tharg but less angry now. Thanks new friend for bringing Bourok gift, marsh dangerous!$B$BDrink some grog, grog of friendship!',
    `RequestItemsText` = 'What you want?'
WHERE `entry` = 40403;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Tharg friend sent him meat? Tharg love meat! Tharg love old friend, new friend too.$B$BHere, Tharg had gift for new friend for help.$B$BTharg loves new friend.',
    `RequestItemsText` = 'Big sack!'
WHERE `entry` = 40404;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, yes. Good meat, enough too, me make us sausage.',
    `RequestItemsText` = 'Meat?'
WHERE `entry` = 40405;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Perfect mon.$B$BThis will make for great poison, Balai makes the poison and dips darts in it. Balai uses this small wooden thing to shoot darts at the enemy, with poison!$B$BSmall little things can kill you, the marsh teaches, think about the mosquitos. And here''s your reward, it will help you one day.',
    `RequestItemsText` = 'You back already, mon?'
WHERE `entry` = 40406;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The power coming from this sigil is quite strong, and will prove useful for study, thanks again for everything you have done $C, I will make sure it is put to good use in defense of the realm.',
    `RequestItemsText` = 'Have you found a sigil?'
WHERE `entry` = 40407;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Why look at this here, you out done yourself, truly! I haven''t seen some dang-nab spider legs this juicy in a few years now, they''ve been getting extra fat down there!$B$BNow we can have a real good meal!',
    `RequestItemsText` = 'Ye wrangle up them spider legs? Remember to get the extra juicy ones.'
WHERE `entry` = 40408;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, I cannot thank you enough for what you''ve done, with less murloc around it means I can do my job in peace without having to constantly watch the waterline.',
    `RequestItemsText` = 'I advise you to be careful when you''re fighting them, they tend to stick together.'
WHERE `entry` = 40409;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, this is it, and it''s still sealed, I would have expected those dumb creatures to pry it open, or use the oil to make a big fire or something, it seems they couldn''t figure it out, or hadn''t gotten around to it yet.$B$BThanks again for the help, you may have saved my hide here!',
    `RequestItemsText` = 'Every minute that burns away is a minute less that we have.'
WHERE `entry` = 40410;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Privateer Groy practically snatches it from your hands, a wide grin upon his face.>$B$BAhh, its been a while... a long while. I suppose you want something in return for running all that way. Here, some coin to cover the trip. If I ever need more I''ll let you know, heh.',
    `RequestItemsText` = 'I''ve been waiting patiently, have you gotten it yet?'
WHERE `entry` = 40411;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What''s this? For me?$B$BI''ve been waiting a few weeks for this, didn''t think it was even coming anymore! I don''t go to Theramore much, but that yokel Lorman almost made me march down there I been waitin'' so long.',
    `RequestItemsText` = 'Can I help you?'
WHERE `entry` = 40412;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, about time, I hate having to ferry to Theramore for a meal!',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40413;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This may not be the end of the murloc threat, but this will no doubt slow them down. Thanks again, as promised.',
    `RequestItemsText` = 'Have you slain the foul monster?'
WHERE `entry` = 40414;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, thanks for gathering these reports, its good to hear news from the frontier, even if some of it is bad, take this coin as thanks for the work.',
    `RequestItemsText` = 'Have you gotten those reports yet?'
WHERE `entry` = 40415;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, I must say, this is the last thing I had expected to come into my shop, I haven''t heard from Wallace in some time, not seeing family certainly makes you miss old times.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40416;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, you have delivered the letter then? How did he like it?$B$BWait, he sent this? Truly this could have fetched a noble''s wage in gold, I must thank you for not being a brigand and making off with it, I shall use it with great honor.$B$BThanks again, for all you''ve done. $N, take this coin for all the traveling you have done.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40417;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now that those raptors have been culled we may be able to make more supply trips out in the swamp without worrying so much.$B$BI took it upon myself to gather a payment for you on behalf of Theramore, it may not be much, but all help should be rewarded.',
    `RequestItemsText` = 'Have you had any luck?'
WHERE `entry` = 40418;

UPDATE `quest_template` SET
    `OfferRewardText` = 'We have our hands full of work. I wasn''t able to spare any of my men to send the report back to Stonard.$B$BBut since you are here now, you might be able to help us with the matters at hand.',
    `RequestItemsText` = 'Ruag sent you? I didn''t expect him to hire a search party that soon.'
WHERE `entry` = 40419;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A mine of extraordinary size, you say?$B$BGood, I will write about it in the report. We still have other issues to worry about before I send this off, speak with Jaiymu and Bagaroh for more tasks.',
    `RequestItemsText` = 'Any success?'
WHERE `entry` = 40420;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good job, $C. I wish I could''ve seen them dying.',
    `RequestItemsText` = 'How many have you killed?'
WHERE `entry` = 40421;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hah, good job again.$B$BThank you, friend. Thank you for all you do for the Horde.',
    `RequestItemsText` = 'Have you found the Altar of Storms?'
WHERE `entry` = 40422;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Twenty heads. I rarely smile, but you earned it.$B$B<Bagaroh grins>$B$BTime to get back to work.',
    `RequestItemsText` = 'Got the heads?'
WHERE `entry` = 40423;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Ruag glances over the report>.$B$BGreat work, soldier. I am relieved to hear that the expedition is safe. I am also impressed. You did a lot of work, good work. Please, pick some equipment from our armory. Whatever you like.$B$BStay safe, soldier.',
    `RequestItemsText` = 'It''s you! What happened to the expedition?'
WHERE `entry` = 40424;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My my... This is it, the rare volume! I never thought I would lay my eyes upon it!$B$BYou''ve done us a great favor in getting this, and favors should always be repaid.$B$BOn behalf of the Academy of Arcane Arts and Sciences, I present you with this.',
    `RequestItemsText` = 'Have you delved within the depths of that accursed Vault, and recovered the rare tome? Or is it still collecting dust with chance of desecration?'
WHERE `entry` = 40425;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, here we are! This is them, thanks again, this means a lot, here, just as I promised.',
    `RequestItemsText` = 'Be careful, the Runic Constructs are quite powerful, an overchage of magical energy gone rampant!'
WHERE `entry` = 40426;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is done, truly?$B$BWhy, thank you $N, you''ve saved us a massive headache, and countless lives of this city. We have requisitioned a reward worthy of such feats from the treasury itself.$B$BPlease, take one, it is the least we can do.',
    `RequestItemsText` = 'The longer Arc''Tiras remains active, the more danger Stormwind lays within, we cannot have rumors spreading, this must be dealt with.'
WHERE `entry` = 40427;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The dead will not be forgotten, but at the least we have avenged their deaths. Thanks again for everything that you have done.$B$BTake this coin, it is from all of us.',
    `RequestItemsText` = 'Has the infestation been cleansed?'
WHERE `entry` = 40428;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Foreman Tanoth lets out a heavy sigh of relief.>$B$BWell, that gives me some breathing room. It seems like you got to the Caches before the troggs mindlessly trampled over them, thanks for the hard work, I''m sure it wasn''t an easy task.',
    `RequestItemsText` = 'Have you recovered the Caches?'
WHERE `entry` = 40429;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, someone of action I see, you remind me of a young Harguf, bashin'' skulls and the like, here, as I promised.',
    `RequestItemsText` = 'You got them skulls I asked for?'
WHERE `entry` = 40430;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, look at that, you do some good work, well, as I promised, here you are.',
    `RequestItemsText` = 'Any luck on collecting them pendants?'
WHERE `entry` = 40431;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done Nethergarde a great service, I must thank you for the hard work. Without you, who knows how long we would have had to wait until we could flush them out.',
    `RequestItemsText` = 'Have you avenged the dead, has the mine been reclaimed?'
WHERE `entry` = 40432;

UPDATE `quest_template` SET
    `OfferRewardText` = '<The Commander would take some time to look over the situation report.>$B$BI see, well thanks again for your work, I don''t have all day to look for everyone, take some silver for the trouble.',
    `RequestItemsText` = 'Have you found Sergeant Burnside yet?'
WHERE `entry` = 40433;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I must commend you for your work, I am sure many of those here are relieved to have one less threat be waiting at the doorstep.$B$BI have gathered a suitable reward for the work you have put in, may it help you on your journey.',
    `RequestItemsText` = 'The defense of Nethergarde requires us to be steadfast.'
WHERE `entry` = 40434;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, this is a fine specimen, take long to find?',
    `RequestItemsText` = 'Twenty eight, carry the seven, account for arcane disturbances... Oh- it''s you, have you had any luck?'
WHERE `entry` = 40435;

UPDATE `quest_template` SET
    `OfferRewardText` = '<The Corpse of the soldier remains lifeless, battered and bruised it would appear that the body was beaten mercilessly. An abrasion can be seen upon the neck, where a medallion or necklace was torn off.>',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40436;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Sergeant Burnside would let out a quiet sigh>$B$BI feared it would have come to this, it always hurts to lose someone, especially those under your command. I will forever wonder if there is more I could have done to save a life.$B$BThank you $C, for risking your own safety to let us know the truth.$B$BTake this amulet, I am sure Holson would respect it being in your hands after delivering this news.',
    `RequestItemsText` = 'Have you found anything, or any clues?'
WHERE `entry` = 40437;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So that is why you are here, this is the report from Wigglestip yes?$B$B<Mahar Ba would take the report, beginning to read it with caution.>$B$BInteresting...',
    `RequestItemsText` = 'Yes, can I help you?'
WHERE `entry` = 40438;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh yes, I sensed that you would be coming, I can practically feel the energy from the letter you carry.$B$B<Upon taking the report, Ansirem Runeweaver would read with caution.>$B$BI see.$B$BSo it is going as predicted, it would appear we may need to be more hands on to manage the growing instability within the Blasted Lands, let us hope there is no outside interferance that is causing the increased magical irregularities.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40439;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is as I feared, the magical energies are that of fel.',
    `RequestItemsText` = 'Have you travelled to Dalaran, and spoken with Ansirem Runeweaver?'
WHERE `entry` = 40440;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good work, now, let us see what mysteries these may contain.',
    `RequestItemsText` = 'Have the items been recovered yet $C?'
WHERE `entry` = 40441;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So.. Mahar Ba sent you, did he?',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40442;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A Dreadlord Heart, oh how I desired, and needed one. You''ve done me a real favor, I shall answer your question.',
    `RequestItemsText` = 'Yes yes yes, do you have my heart?'
WHERE `entry` = 40443;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Watcher Mahar Ba would look on with a slightly concerned look.>$B$BWe must begin to prepare, and keep the magical energies stable, you have given us a great deal of information, and without you we would have been unable to figure out these clues and unearth the answers we need for our future.$B$BThe Kirin Tor thanks you greatly for what you''ve done, please, take one of these rewards, it is the -least- we can for how much trouble you have saved us.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40444;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your actions have eased this troubled mind. We can now be more free with the wyvern and let them truly grow within this world, and for that, I must thank you.$B$BTake this, as a symbol of my thanks young one.',
    `RequestItemsText` = 'Have you had any luck, child?'
WHERE `entry` = 40445;

UPDATE `quest_template` SET
    `OfferRewardText` = 'With your assistance Suntail Pass is made much safer for travel.$B$BPerhaps now the Quillboar will have learned a lesson, and the Spirit Walker''s can resume their tasks in peace.',
    `RequestItemsText` = 'The Bristleback hold incredible disregard for nature, have the Quillboar been dealt with?'
WHERE `entry` = 40446;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I have been expecting you, it seems that you were sent to aid us at a time of dire need. The spirits have sent you to aid me, and now I must aid you for your help.$B$BTake this, on behalf of the Spirit Walker''s for allowing us to conduct what must be done.$B$BGo now, and walk softly friend.',
    `RequestItemsText` = 'Without the proper instruments, we cannot conduct our ancient rites and passages.'
WHERE `entry` = 40447;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, hello there, this is from mom? I miss her quite a bit, but it''s nice seeing family! The city is kind of fascinating too.',
    `RequestItemsText` = 'Yes, can I help you?'
WHERE `entry` = 40448;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, well my my, you''ve really outdone yourself for us. Perhaps now we can finally get a plentiful harvest in for the season, here, take this, as a token of my thanks, its a spare.',
    `RequestItemsText` = 'Have you had any luck just yet?'
WHERE `entry` = 40449;

UPDATE `quest_template` SET
    `OfferRewardText` = '<After inserting the Gold Power Core it takes a moment for Chaser to power up once again, the machine whirrs to life, beeping happily.>',
    `RequestItemsText` = 'Beeeeep!'
WHERE `entry` = 40450;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You make Stromgarde proud, the less trolls, the better for our ultimate survival.',
    `RequestItemsText` = 'Has the deed been done $C?'
WHERE `entry` = 40451;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, much better than I would have expected. Take this, as a thanks.',
    `RequestItemsText` = 'It may be hard to find the pass, but I am sure you will do what is neccesary.'
WHERE `entry` = 40452;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Ogres are a mighty foe, and although you''ve done excellent work, I fear it will not be enough. Here, as I promised.',
    `RequestItemsText` = 'Has the work been done?'
WHERE `entry` = 40453;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Do I know you, is there something that I can help you with?',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40454;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Old Farwell has done a lot for us. Thank you for delivering this ring, it should be just what we needed.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40455;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Enjoy, enjoy! I will record your name in our super duper subscriber log!',
    `RequestItemsText` = 'Well? Cool, right?'
WHERE `entry` = 40456;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wise purchase, pleasure doin'' business with ya. Your name has been recorded in our subscriber logs.',
    `RequestItemsText` = 'You''re interested, I can tell!'
WHERE `entry` = 40457;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This... green liquid is what they''re brewing there? <Overseer opens the flask and takes a sniff.> Och, its quite acidic! This is certainly very concerning, if it the mere smells burns your nose hairs I shudder at the thought what it does to flesh. I will warn the others about this, you''ve proven yourself to be capable to the brotherhood.',
    `RequestItemsText` = 'All attempts to sneak in have failed, their hounds can smell everything.'
WHERE `entry` = 40458;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmm, so you''re the real deal huh, no way you''re working with Shadowforge anyway.$B$BYou never can be certain, they have an alignment with the Twilight Hammer afterall.',
    `RequestItemsText` = 'What is it you want $R?'
WHERE `entry` = 40459;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Does it all make sense now? Orvak Sternrock has a vengeance, one that needs to be unleashed.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40460;

UPDATE `quest_template` SET
    `OfferRewardText` = 'With this our future is secure, but I will not leave until I taste the sweet sensation of revenge.$B$BI will let the others know that you are to be trusted, speak with them, they should have tasks for you.',
    `RequestItemsText` = 'Have you recovered my lost items?'
WHERE `entry` = 40461;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It feels good knowing that there are less of those scum on this world, but there is still more to be done.',
    `RequestItemsText` = 'We are on the road to justice, can you can feel it?'
WHERE `entry` = 40462;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Also, take this key, I do not intend to return to the mountain. It should open a chest within the Black Vault, if they haven''t already taken it away.',
    `RequestItemsText` = 'Have you culled that wretch from this world yet?'
WHERE `entry` = 40463;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Orvak would let out a small chuckle of enjoyment.>$B$BThe hatred instilled deep within me has begun to cool, the fire that once raged on has eased.$B$BIt fills me with vigor to know they met their end.$B$BI know deepdown that Shadowforge can never be saved, regardless, I thank you.$B$BI will not be needing this any longer, for I do not intend to return, perhaps you may find some use for it.',
    `RequestItemsText` = 'Has the deed been done, has the senate been removed?'
WHERE `entry` = 40464;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Radgan would take his time inspecting the cores.>$B$BFlaws, cracks, hmm.. These are some second rate power cores, not the type of stuff I am looking for.',
    `RequestItemsText` = 'Any luck in obtaining those Golem Cores?'
WHERE `entry` = 40465;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hey look, it means a lot for you to travel all that distance for me, I made it worth your while in coin, now lets see...',
    `RequestItemsText` = 'Have you spoken with Jabbey?'
WHERE `entry` = 40466;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Look at the sheer power within this thing, it is much more advanced than what we used to work on in the Mold Foundry, this is intense.$B$BYou''ve done me a great favor, and now perhaps I may actually have something to work on when we get out of here.$B$BI reconfigured one of the Golem Cores you got me from the War Reavers, hopefully you''ll get some use from it!',
    `RequestItemsText` = 'Have you ventured deep into the Blackrock Depths?'
WHERE `entry` = 40467;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well by me, and truly made them bleed. Justice has been served, and their work has been slowed tremendously. I would like to offer you a reward for all of your hard work, take it, as a herald of justice, you deserve it.',
    `RequestItemsText` = 'Justice grows ever closer, you can practically feel it.'
WHERE `entry` = 40468;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is about time Vilegrip got what was coming to him, even if he deserved torture. I prepared a reward for you incase you returned, and here you are, take it.',
    `RequestItemsText` = 'Has that worm been trampled $C?'
WHERE `entry` = 40469;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What a fine specimen! A little cracked, but this should work just fine. My client is trying to get to the bottom of what caused these golems to go haywire, and he needs all the samples he can get.$B$BI have another task for you, and I''m willing to spare some coin for your trouble if you''re interested.',
    `RequestItemsText` = 'Have you recovered one?'
WHERE `entry` = 40470;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good job! And all of them are of extraordinary quality, too! I didn''t think that you could do it, to be fair. The last adventurer helping me... let''s just say, he got harvested, if you know what I mean. It''s great to finally have someone who knows what they''re doing.$B$BSo, would you want to help me once more? I need something else to be done, and I cannot leave Sentinel Hill for now. You know, I''m waiting for a shipment of supplies from Redridge and it could arrive any moment.',
    `RequestItemsText` = 'Have you collected the runes already?'
WHERE `entry` = 40471;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hewen sent you? This son of a trogg couldn''t even visit me himself? Preposterous! I got his blueprint, but if you knew how much hassle it cost me! If you only knew! Tell Hewen that next time he orders something from me, he pays double!',
    `RequestItemsText` = 'What is it? Don''t you see, $R, that I am kind of busy?'
WHERE `entry` = 40472;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Harvester Blueprints...$B$B<Christopher Hewen looks into the blueprints and makes a disgruntled face.>$B$BTo be frank, my hard-working friend, I don''t understand any of it! But it doesn''t matter, as I am only the messenger, a humble servant. Those papers are for my employer, who, if you are willing, you will meet soon!$B$BI would deliver them myself, but, believe me or not, those damned supplies have still not arrived! Also, traveling through these beautiful, golden plains became so dangerous lately. I am certain that you can handle it, though. Care to help me for one last time, friend?',
    `RequestItemsText` = 'Ahhh, $N already! You got the paper?'
WHERE `entry` = 40473;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Blueprints from Hewen, finally. He couldn''t be any slower with it. Let me see what is written inside...',
    `RequestItemsText` = 'Who are you? What do you want from me?'
WHERE `entry` = 40474;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Engineering tools. And they are all still intact. Unexpected, but a welcome surprise. Now I have all we need.',
    `RequestItemsText` = 'Have you found the equipment?'
WHERE `entry` = 40475;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So the person who may manufacture the runes lives close to Darkshire. We need to hurry then; there is no time to waste. Tales of your exploits have probably reached him already.',
    `RequestItemsText` = 'The golem needs to remain intact for this to work.'
WHERE `entry` = 40476;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found the note attached to one of the crates? But it''s all written in gibberish? Don''t worry, we will figure it out.$B$BFor now, we need to handle another problem.',
    `RequestItemsText` = 'Have you retrieved the Rune Shipments?'
WHERE `entry` = 40477;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Deadmines... Interesting. I''m glad that you made it out alive. With their leader dead, I can focus on rewiring the remaining golems.$B$BThat, and finding the person responsible for all of this.',
    `RequestItemsText` = 'Have you found the Defias hideout?'
WHERE `entry` = 40478;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great job with these golems, stopping the Defias and whatnot. You and Maltimor did more for these lands than the People''s Militia has ever done, and no one will know about your exploitsŌĆ”$B$BSuch are the whims of history, pal. But you didn''t come here for a friendly talk, ay?',
    `RequestItemsText` = 'It''s you, $N! I missed you! How''s it going?'
WHERE `entry` = 40479;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What? Give me that.$B$B<Franklin Hamar looks on the note.>$B$BYes, I can read it. But everything has a price.',
    `RequestItemsText` = 'I offer only the finest goods.'
WHERE `entry` = 40480;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Extraordinary. These are good enough.',
    `RequestItemsText` = 'Got the silk? I haven''t got all day.'
WHERE `entry` = 40481;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Extraordinary. Great work. Those needles will serve me well. So thin, so durable. But I''m getting ahead of myself.$B$BI made a promise. Let me decipher this message.',
    `RequestItemsText` = 'Less talking, more doing.'
WHERE `entry` = 40482;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So the person who may manufacture the runes lives close to Darkshire. We need to hurry then; there is no time to waste. Tales of your exploits have probably reached him already.',
    `RequestItemsText` = 'Finally, it''s you. Were you able to decipher the note?'
WHERE `entry` = 40483;

UPDATE `quest_template` SET
    `OfferRewardText` = 'F.W.? I know of no-one by those initials, but I have a hunch of who it could be, if what you told me is true.',
    `RequestItemsText` = 'The Night Watch stands firm against the darkness that surrounds us.'
WHERE `entry` = 40484;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The people of Westfall are safe. Thank you, $N. These lands will heal in time.',
    `RequestItemsText` = 'Have you found him?'
WHERE `entry` = 40485;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmm, so there is something going on up there.$B$BHold on just a minute, I got to write a report of my findings and send it to the highest authority.',
    `RequestItemsText` = 'So, have you ventured up the ridge?'
WHERE `entry` = 40486;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What brings you to Ironforge, how can you assist the Bronzebeard?',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40487;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, how did things go in the capital?',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40488;

UPDATE `quest_template` SET
    `OfferRewardText` = '<King Magni Bronzebeard would nod his head stoutly.>$B$BThe defence of the kingdom requires us to be steadfast in all manners, I have no doubt you have really shaken things up for our enemy, and put a stop to their plans.$B$BOn behalf of my people I reward you with an item from our armory, may it serve you well.',
    `RequestItemsText` = 'Is there anything I can help you with?'
WHERE `entry` = 40489;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, would you look at all this huh?!$B$BThose crafty bastards sure were keeping their secrets, I''ll make sure to send this back to Ironforge when I get the chance, and they can look everything over, nice job eh?$B$BI got some extra Thunder Ale for you, oh and me ol'' gloves, they should treat you nicely, I got a new pair.',
    `RequestItemsText` = 'You get a whiff of what''s goin on in there yet?'
WHERE `entry` = 40490;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That''s quite a haul, I''m impressed. Joining this new horde might not be so bad after all. You''ve scavenged so much I even have surplus to forge you an equipment of your choice. I believe you will wear it well.',
    `RequestItemsText` = 'Hard times call for desperate measures, knowing how to make do with what you have draws the line between life and death.'
WHERE `entry` = 40491;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These shall do nicely, now. Let us see what power they truly hold.',
    `RequestItemsText` = 'The Blood Fury burns within us, and needs to be strengthened.'
WHERE `entry` = 40492;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This heart belonged to a powerful Felguard, one that desired to serve its masters tirelessly.$B$B<Darkseer Geshtol would examine it carefully.>$B$BIt would appear there are no large flaws, this should work nicely. You''ve done well out there and have done well for us, I have gathered something you might find useful for all of the hard work.$B$BNow... Lets see what this is capable of...',
    `RequestItemsText` = 'I will not wait forever, have you done as I asked whelp?'
WHERE `entry` = 40493;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The stench of ogre blood bathes you $C. You might not be useless after all.',
    `RequestItemsText` = 'Hmph. Pathetic fool.'
WHERE `entry` = 40494;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The arrogant fool lays dead. Ah to be alive $R. I tell you, hearing the demise of those you hate while you''re still well enough to eat, drink and kill feels like the embrace of a cold and grim fate. But we hold it into our arms with pride and we would never let go. Such is life living under the Horde''s name, we greet death with open arms and weapons ready.',
    `RequestItemsText` = 'Hmph, War Master.'
WHERE `entry` = 40495;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good. I feel better now. Yet, there is still much to do.',
    `RequestItemsText` = 'Have you exacted revenge in my name?'
WHERE `entry` = 40496;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This one will do. I will get to training them as soon I can.',
    `RequestItemsText` = 'I have trained many worgs in my life. My first one, years ago, on Draenor...'
WHERE `entry` = 40497;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I knew you had it. You severely weakened the Blackrock Clan with your feat. Without the alpha, it will take years to rebuild their worg population.$B$BSoon, I will once again ride to battle. Thank you, $C. Take this, a gift from myself.',
    `RequestItemsText` = 'Revenge is close.'
WHERE `entry` = 40498;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It seems you endured their stings and lived to tell the tale. Many lives will be saved thanks to your work. Please accept what little I have as payment.',
    `RequestItemsText` = 'Can never be too prepared in these hostile lands.'
WHERE `entry` = 40499;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, you''ve done as I asked. Let''s see what''s in those documents.$B$B<Molk takes the documents from you, and stares intently for a few seconds.>$B$BWell, this will surely put a hamper on their plans, the information here must have taken them a while to acquire, and without it they have no leads.$B$BYou are more useful then you look, whelpling.$B$BTake this gold, as a thank you from myself.',
    `RequestItemsText` = 'I don''t have time to chat when there are things to be done, so get moving.'
WHERE `entry` = 40500;

UPDATE `quest_template` SET
    `OfferRewardText` = 'How can I help you $R?$B$B<Thrall takes the missive, reading it over.>$B$BKarfang, this name is not familiar to me.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40501;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmm, Karfang you say?',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40502;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Karfang looks out at the Warchief''s Response, beginning to read with caution.>$B$BSo it appears the Warchief is asking us for a test of loyalty, he shall receive his demands.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40503;

UPDATE `quest_template` SET
    `OfferRewardText` = 'On behalf of everyone here, you have done us a great service in securing our future, entrance within the Horde means we may get out of this ashen wasteland eventually.$B$BI have seen much in my time on Outland, and in the Blackrock Mountain, but I look forward in what is to come, and for that you have my gratitude.',
    `RequestItemsText` = 'Has it been done?'
WHERE `entry` = 40504;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The runts of our group will now be invisible to the Blackrock Clan, vanished from thin air with no trace of where they have gone.$B$BThere is still work to do.',
    `RequestItemsText` = 'Have you destroyed the documents $R?'
WHERE `entry` = 40505;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You will need to be prepared for what is to come outsider.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40506;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Picked through the bones have you?$B$B<Karfang lets out a small laugh.>$B$BThis would be what we were looking for, an excellent job outsider, Molk was expecting shoddy work from one of your kin, but you did well.',
    `RequestItemsText` = 'If I were you I would suggest bringing backup.'
WHERE `entry` = 40507;

UPDATE `quest_template` SET
    `OfferRewardText` = '<A deep and heavy sigh escapes Karfang, his face full of emotion.>$B$BI was always impressed with this sword and the way in which he wielded it, he fought with tenacity, and strength, he shall be remembered for it.',
    `RequestItemsText` = 'We do what we must.'
WHERE `entry` = 40508;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Karfang''s old features begin to crack a smile.>$B$BI cannot express my thanks, for this, and everything done.$B$B<Karfang would remove a ring from his finger.>$B$BThis ring was taken upon my entrance to this world, from some noble human lord in battle.$B$BThis keepsake is now yours, thank you.',
    `RequestItemsText` = 'Have you braved the Blackrock Mountain?'
WHERE `entry` = 40509;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wow, this is complicated stuff!$B$B<Masey looks baffled by the sheer complexity of the parts!>$B$BThis was truly a piece of art, no wonder those black dragons were fooled.$B$BI''m gonna take some time to figure out how this stuff works, thanks again.',
    `RequestItemsText` = 'You found any of them fake whelps?'
WHERE `entry` = 40510;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A magical grain you say? Its been a long time since I''ve heard about it.',
    `RequestItemsText` = 'Hello, welcome to Refuge Point. How can I help you?'
WHERE `entry` = 40511;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You found it! Her recovery will be slow but I believe she''ll back on the road hunting trolls with our cavalrymen in no time. This is all I have in my pockets, even if not much you made this old handler happy today. Thank you.',
    `RequestItemsText` = 'I don''t know how much longer she can last.'
WHERE `entry` = 40512;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hurry, smash the ring, it contains the magic that has kept me enslaved!',
    `RequestItemsText` = 'Hurry, I cannot stand another second of this! Baaaa!'
WHERE `entry` = 40513;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, you bring news from Lady Meldralis. Much appreciated, friend. I am glad to know the diplomatic representative has made it that far through the mountains. I am more than sure she will strengthen the bond.',
    `RequestItemsText` = 'Bal''a dash.'
WHERE `entry` = 40514;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hello, hello!$B$BWelcome to Tinker Town. Got anything that needs fixing?',
    `RequestItemsText` = 'Yes? You may speak.'
WHERE `entry` = 40515;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great, great news $N. I haven''t seen these in quite a while now!',
    `RequestItemsText` = 'Did you find them?'
WHERE `entry` = 40516;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You return with the notes! Much appreciated, friend.$B$BNow I can finally start working on this this again. I''m glad Masey would like to help me. I''m intending this as a gift for Princess Moira: her own personal bodyguard!$B$BHere, this is for you.',
    `RequestItemsText` = 'Hard at work.'
WHERE `entry` = 40517;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Excitement perks across Ansela''s face!>$B$BOh, oh thank you! I cannot express my excitement, I never thought I''d get this back.$B$BI thought I''d have to go get a stern talking to in Little Silvermoon about my failure. Here, take this, as thanks for helping me out.',
    `RequestItemsText` = 'Yes, have you had any luck?'
WHERE `entry` = 40518;

UPDATE `quest_template` SET
    `OfferRewardText` = '<With the remains close to the spirit, the howling tone becomes more clear.>$B$BI can feel the end. It is in sight. My vision is no longer blurred and faded mon. You have shown me the way. That cursed Zum''rah and his magic brought me back from my rest, and left me to wander aimlessly. But I got no grudges mon, for I am free now.$B$BI will find the way, thanks to you.$B$B<The spirit drops a chained necklace onto the sand below, leaving it as a reward as he collects his remains.>',
    `RequestItemsText` = '<The wind howls across the sand.>'
WHERE `entry` = 40519;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank ya, mon. These supplies won''t be lasting for long, but they will allow us to live for a few more days at least. Here, take this as a reward mon.',
    `RequestItemsText` = 'Do ya have da food and skins?'
WHERE `entry` = 40520;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Da ogres will fear da might of our gods. Their vengeance be scary, no mercy be shown. Curse de ogres. Theey will learn not to mess with da Sandmoon.',
    `RequestItemsText` = 'Our mad brethren in Zul''Farrak no longer revere our gods as dey should. Only we can stop the ogres.'
WHERE `entry` = 40521;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Sandfury have changed and want to cooperate? What do they have to sell then? I guess nothing! My friend, you know, Gadgetzan has its reputation. I cannot just let in some filthy sand trolls here.$B$BUnless they pay.$B$BA lot.',
    `RequestItemsText` = 'What''s up, pal?'
WHERE `entry` = 40522;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Dey be no less insane than our brothers in Zul''Farrak, mon. Sandmoon be not paying dem, never. If dey want us enemies, so be it.$B$BMy mission still stands.',
    `RequestItemsText` = 'Have ya speak to da goblins?'
WHERE `entry` = 40523;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I require your assistance in helping Sandmoon Village, brave $C.',
    `RequestItemsText` = 'I speak for the Darkspear.'
WHERE `entry` = 40524;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That be good. I think. We Sandfury be never open to da outsiders. But these be different times now. As Maz''ek be sayin'': we have to change or face extinction. I wish I could speak to Vol''jin myself about our... cooperation. I cannot leave my people yet though. I be needed here. I be needed here as long as Chief Ukorz lives and my people are in danger.',
    `RequestItemsText` = 'So ya be the new one among us. Maz''ek told me he sent you to negotiate with Vol''jin. Were you successful?'
WHERE `entry` = 40525;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It does not bring me joy to hear about de death of my kin. It be necesarry, sadly. It is de only way for Sandfury to survive.',
    `RequestItemsText` = 'Have you finished your... grim task?'
WHERE `entry` = 40526;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So it is done, I Thank you.$B$BUkorz Sandscalp was not always so brutal and cold, his mind be warped from the magic he and his lackeys dabbled within''. It almost be sad to think of what a promisin'' future he brought when he first became chief, for it all to drift away like sand on de dunes.$B$BPerhaps we find a new future now, all thanks to you mon.',
    `RequestItemsText` = 'Is Ukorz dead?'
WHERE `entry` = 40527;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good, turtle meat for Viceclaw! Ya be useful outsider. Ya can stay, Ekka be likin'' ya.',
    `RequestItemsText` = 'You can find da turtles on the shore, next to da port.'
WHERE `entry` = 40528;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I bid you farewell, $N. Thank you for understanding. And once again, thank you for all you did. You truly are a hero.',
    `RequestItemsText` = 'What is it, friend? Oh, by the Light...'
WHERE `entry` = 40529;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I have been expecting you.$B$BIt is about time you have arrived. I have heard many tales of your prowess, but now I shall see if such tales are true.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40530;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Margok Hatewind would inspect the tooth for some time.> Well, this would appear to be what I was looking for, you have displayed great patience, and great ability to hunt.',
    `RequestItemsText` = 'Exert cunning, for the wolves of Feralas can be a rather intimidating foe.'
WHERE `entry` = 40531;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Another comes to speak with me, you wish to prove yourself, do you think you''re strong enough? These are all questions one must ask themselves before they approach me, for I am not one that you should dissappoint.',
    `RequestItemsText` = '<The Wolf Spirit seems to not notice your presence.>'
WHERE `entry` = 40532;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Another comes to speak with me, you wish to prove yourself, do you think you''re strong enough? These are all questions one must ask themselves before they approach me, for I am not one that you should dissappoint.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40533;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well orc, you are stronger then I had anticipated, and carry all the traits of the wolf, I am honored to bless you with my power. May it bring you great power in the hunt, and strike terror into your enemies.',
    `RequestItemsText` = 'Do you truly think you are ready?'
WHERE `entry` = 40534;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You return, and with the meat. By which means you''ve decided to obtain it, I will not question.$B$BNow, onto the real task.',
    `RequestItemsText` = 'If you fail to feed your wyvern, it will one day feast upon you.'
WHERE `entry` = 40535;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, blessed be the ancestors, you truly have potential.$B$BI haven''t seen old Sunchaser pushed back like that for a long long time, you have my blessing, and his.$B$BOne final task remains.',
    `RequestItemsText` = 'All who seek to become windriders must first challenge an alpha.'
WHERE `entry` = 40536;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Gorgeous, just gorgeous.$B$BThe Earthmother truly had blessed this harpy with beautiful feathers, a pity her life ended. Yet, as the cycle of life and death continues one must always remember that our actions always lead to a greater purpose.$B$B<Tokala ties the feather in the wyvern cub''s hair. The cub eagerly makes its way into your backpack, ready to face the world together with you.>',
    `RequestItemsText` = 'Domination over the sky, my hooves are shaking.'
WHERE `entry` = 40537;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So they were not real whelps? But constructs made of metal by someone that bothered to put their name on each and every one of them? Convenient for us, we now know who to kill.',
    `RequestItemsText` = 'What have you found out?'
WHERE `entry` = 40538;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Dark Irons have a new quarry? What were they even digging? Not that it matters since you''ve put an end to it, I must however report to Karfang.$B$BI''ve managed to collect a few things from the willing clan members that''d see you rewarded for your efforts, but you can only pick one. Such is the way of the Blackrock Clan.',
    `RequestItemsText` = 'Did you end him?'
WHERE `entry` = 40539;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You pass the meat to the murloc. Let''s see if it really was that hungry.',
    `RequestItemsText` = '<The murloc tadpole gurgles.>'
WHERE `entry` = 40540;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Poor little murloc. The search yielded no results. Maybe the locals would know what happened to the murloc family?',
    `RequestItemsText` = 'Gurglglgl!'
WHERE `entry` = 40541;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Weird question, $R. But to my knowledge, none of my gryphon riders reported murloc presence on the shore. Revantusk, yes, but no murlocs. Are you sure your information is correct?',
    `RequestItemsText` = 'The Aerie Peak welcomes you, outsider.'
WHERE `entry` = 40542;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Kattom be not seein'' any murlocs around here, mon. Da turtles ate dem all. Murlocs be good snack, taste like fish, but betta''.',
    `RequestItemsText` = 'Katoom be fishin'', mon. Be quiet.'
WHERE `entry` = 40543;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Murlocs... I have spent months amongst them, trying to learn their fishing techniques. During this time, I learned a lot about their customs and behavior.$B$BSometimes, I feel like I can understand their language. It creeps me out.$B$BRegardless, when it comes to your little friend, I don''t have good news...',
    `RequestItemsText` = 'I am Nat Pagle, master fisherman. What can I help you with?'
WHERE `entry` = 40544;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Murlocs... I have spent months amongst them, trying to learn their fishing techniques. During this time, I learned a lot about their customs and behavior.$B$BSometimes, I feel like I can understand their language. It creeps me out.$B$BRegardless, when it comes to your little friend, I don''t have good news...',
    `RequestItemsText` = 'I am Nat Pagle, master fisherman. What can I help you with?'
WHERE `entry` = 40545;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The tadpole is waiting for you. You are the only one who can save him now. You will become his new family, his new friend.$B$BBut wait, it needs a name. Gurky! Gurky is perfect.$B$B<Gurky hops into your pocket.>$B$BOh, the adventures you will have together!',
    `RequestItemsText` = 'Grmrglgl!'
WHERE `entry` = 40546;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The tadpole is waiting for you. You are the only one who can save him now. You will become his new family, his new friend.$B$BBut wait, it needs a name. Gurky! Gurky is perfect.$B$B<Gurky hops into your pocket.>$B$BOh, the adventures you will have together!',
    `RequestItemsText` = 'Grmrglgl!'
WHERE `entry` = 40547;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I followed the footprints and I found our suspect. I couldn''t do much more. I''m just a scout.$B$BThat''s why you are here.',
    `RequestItemsText` = '$N, right? Thanks for coming so fast.'
WHERE `entry` = 40548;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You say that their chieftain had this tablet with drawings resembling the burned inn... curious. We will need someone able to read the quillboar scripture.',
    `RequestItemsText` = 'Back so soon? The camp is west of here.'
WHERE `entry` = 40549;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah yes, quillboar writing. Very hard to learn, very hard. I can read it, though. Did some business with them a long time ago. Nasty bunch, I tell you.$B$BHowever, you know how it is here. Everything has a price.',
    `RequestItemsText` = 'New customer?'
WHERE `entry` = 40550;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hah, good job. I hope you didn''t have to dispose of too many Venture Co. workers... And I hope their insurance covers this!$B$B<Sputtervalve laughs.>$B$BLet''s get to translating this thing.',
    `RequestItemsText` = 'Got it?'
WHERE `entry` = 40551;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So it wasn''t them... Unless the quillboars are the masters of deception, we reached a dead end.',
    `RequestItemsText` = 'Were you able to translate the tablet?'
WHERE `entry` = 40552;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Damn it. If it was the quillboars, it would make it so easy. Shame, but at least we ruled out one of the suspects.$B$BNevertheless, good work. Finally we got at least a step closer to solving this mystery. Please, take this gold as a reward from lady Jaina herself.',
    `RequestItemsText` = 'Welcome back, $N. What did you discover?'
WHERE `entry` = 40553;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So this is all we have. Well, it is a lead as good as any other. But what can we do with this information?',
    `RequestItemsText` = 'Were our scouts of any use?'
WHERE `entry` = 40554;

UPDATE `quest_template` SET
    `OfferRewardText` = 'In the grave, you find skeletal remains of a tauren. He must''ve died at least a few years ago.$B$BThe grave, however, has been recently dug up and hastily buried with earth. The dirt is still loose, it must''ve been no longer than a few weeks.$B$BSome equipment is buried with the tauren too. Leather straps, metal coins and pauldrons, and a beautiful, one handed axe.',
    `RequestItemsText` = 'This grave is big enough to fit a tauren for sure. It''s worth investigating.'
WHERE `entry` = 40555;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A dug-up grave of a tauren warrior... Another mystery, another question.$B$BLet me gather my thoughts on this.$B$BSo, $N, you say that he died a long time ago. It is no coincidence. The shield must''ve been taken from his grave. But... why?$B$BWhy would anyone do this? This doesn''t make any sense. If someone wanted us to blame the Horde, they could''ve found a better way to do it for sure...',
    `RequestItemsText` = 'Have you found anything?'
WHERE `entry` = 40556;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I suspect they might know something...',
    `RequestItemsText` = '$N! Nice to see you.'
WHERE `entry` = 40557;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You met with the Horde unauthorized? This could''ve provoked a major diplomatic incident!$B$BAt least you learned important information.',
    `RequestItemsText` = 'Back already? What did you learn?'
WHERE `entry` = 40558;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is embarrassing. Especially for me, as a Captain.',
    `RequestItemsText` = 'Have you found their rooms? They should be downstairs.'
WHERE `entry` = 40559;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Ritual of Divination. Yes, I am able to perform it. But be wary, $R. It is extremely dangerous for the spirit, and for the caster.',
    `RequestItemsText` = 'I studied the Arcane Arts for decades. Yet I always craved... Something more.'
WHERE `entry` = 40560;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, the Arcane Resonator. I thought this technology to be lost when Archimonde crushed Dalaran. Fortunately, Kirin Tor is tougher than I expected.$B$BShall we begin?',
    `RequestItemsText` = 'Back from Dalaran already?'
WHERE `entry` = 40561;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So it was the deserters. Very well, I suspected it, to be honest. These people have no honor. We shall send our best men to deal with them. But before this, I think the Horde should also get an explanation and... an apology.$B$BAnd when it comes to this Mariner, let me consult with some of my advisors. I think I may have heard of this man before.',
    `RequestItemsText` = 'I heard terrible noises coming from the Mage Tower. What happened?'
WHERE `entry` = 40562;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The deserters. I knew they were vile people, but to burn innocents alive... Light, save the souls of these poor people.$B$BSo be it. Kagoro is already around here, we should meet him at once.',
    `RequestItemsText` = 'Did our people really betray us?'
WHERE `entry` = 40563;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What did you learn, soldier?',
    `RequestItemsText` = 'The Horde have been honest about their investigations, it makes me happy that we disclosed our own information.'
WHERE `entry` = 40564;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Without you, we would still be in the dark. Who knows? Maybe you stopped another war between the Horde and the Alliance.$B$BYou are a hero of Theramore, for all of the work you have done to ease these tensions and solve this mystery. For this, I would like you to take one of these weapons from my personal armory.$B$BConcerning the Vengeful Mariner: Sailors coming to Theramore have reported seeing a shadowy figure stalking the coast. A question does remain: why was this figure so important to the deserters?$B$BI would not lose sleep. This is not a mystery for us to worry about, or another investigation to be launched. Let them keep their mariner in whatever grave he occupies.',
    `RequestItemsText` = 'Have you found Sellick Voss?'
WHERE `entry` = 40565;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh perfect, thank you! This should teach him a lesson. here''s your silver, now shoo!',
    `RequestItemsText` = 'Have you got what I need, or are you just being nosy?'
WHERE `entry` = 40566;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Poison? Wow, this complicates things greatly. We may need to take a more direct approach.',
    `RequestItemsText` = 'Can I help you?'
WHERE `entry` = 40567;

UPDATE `quest_template` SET
    `OfferRewardText` = 'From Hawk''s Vigil? What a juicy predicament indeed!$B$B<He trails off into a quiet, throaty laughter.>',
    `RequestItemsText` = 'Hmm?'
WHERE `entry` = 40568;

UPDATE `quest_template` SET
