UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh baby, its still intact, look at this thing, a bit of heat damage, and some sand where it shouldn''t be, but its not broken.$B$BYou saved us a heaping pile of gold recovering this thing, and that''s like giving it to me yourself!$B$BHere, this should make up for the work you did.',
