UPDATE `quest_template` SET
    `OfferRewardText` = 'You have brought justice to the Eastons, and have removed a dangerous criminal from our lands, for that we cannot be more grateful.$B$BWith these deeds there is hope we may resettle the land once the Defias threat is removed. Let us hope such a future comes soon, $N.$B$BFor your efforts I have prepared some items, they should serve you well.',
    `RequestItemsText` = 'Has he been brought to justice, $N?'
