UPDATE `quest_template` SET
    `OfferRewardText` = '<Brother Neals reads the letter, his face easing, and an expression of relief washes over him.>$B$BIt feels good to know justice has been met out to that ruffian, for all the misery he has caused.$B$BI am just happy that my information was able to assist and bring justice to that lawless land.$B$B<Brother Neals takes the Westfall Church Key, tucking it into a pocket of his robe carefully.>',
    `RequestItemsText` = 'So, what news comes from Westfall?'
WHERE `entry` = 40603;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Why, you managed to thin their numbers aye?$B$BImpressive work, more then I expected even. Now I can get to work with gathering my report.',
