WHERE `entry` = 40604;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Why, this is the Archive from our digsite in the Badlands, is it not?$B$B<Torwyn lets out a small chuckle of approval.>$B$BBy my beard, we''ve been looking for this, a chance to log it within our shelves, you''ve done good work recovering it, you have our gratitude.',
    `RequestItemsText` = 'Can I help you with anything $C?'
WHERE `entry` = 40605;

UPDATE `quest_template` SET
    `OfferRewardText` = '"Ritual secrets", is that the line that mangy dwarf fed you?$B$BOn the other hand, he''s been generous with his wares, and I suppose he isn''t too terribly looking, either. Perhaps just a little bit of information couldn''t hurt.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40606;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Up a pyramid, you say? Never would''ve guessed!$B$BYou''ve done good, but these trolls might as well be doctors for how readable their handwriting is! I''m not even sure if this recipe calls for fresh cherries, or if grenadine will do... heck, we''ll just have to try it out both ways!$B$BAt any rate, have one on the house!',
    `RequestItemsText` = 'I knew plying those elves with some ale would pay off one day! Where did Loania say to get the recipe?'
