WHERE `entry` = 40659;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmm, well, that is not all bad, some fighting will certainly need to be discussed with the Admiral, but otherwise I expected much worse...$B$BHere, take this silver, as trouble for running around the city.',
    `RequestItemsText` = 'Any luck finding them all?'
WHERE `entry` = 40660;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A rose? Why, isn''t this something else..$B$BFrom the Sailor Borus?$B$B<The woman would let out a soft snicker, smirking openly.>$B$BI remember the name, and that Kul Tiran man well, I never assumed him such a romantic.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40661;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Sailor Borus would let out a loud, and heavy sigh of relief.>$B$BI can''t thank you enough for this, so much time spent worrying, at the least I was able to finally do something!$B$BHere, for the cost of the rose, I forgot, and some bit extra for doing this on my behalf.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40662;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, this is the good stuff.$B$BWell, from one sailor to, whatever you are mainlander, thanks a bunch.',
    `RequestItemsText` = 'So, you find the port...?$B$BLike the ale.'
WHERE `entry` = 40663;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done well, your work will certainly go a long way in halting their aggresion and lowering the chances of any potential hostile run-ins. The Wildhammer thank you for the effort.',
    `RequestItemsText` = 'Any luck in your hunting $N?'
WHERE `entry` = 40664;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, but do not yet sing for victory: Our foe is as vicious as it is relentless.',
    `RequestItemsText` = 'Throw them back into the waves. Let the sea churn red with their blood.'
WHERE `entry` = 40665;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Proudmoore thought us ill-made mongrels, unthinking and mad with bloodlust.$B$BBut true warfare requires strategic acuity as much as it requires a sharp edge and strong guts.$B$BYou have done well, $N. We have defeated the Kul Tirans once, we shall defeat them again.',
    `RequestItemsText` = 'Have you taken their provisions, $C?'
WHERE `entry` = 40666;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I see you carry Dar''nakk''s commendation. I''ve never known him to grant such accolades freely.$B$BYou did well in defending our coasts, and for that the Horde owes you its gratitude.',
    `RequestItemsText` = 'Lok-regar no''gal, $R. I bid you welcome.'
WHERE `entry` = 40667;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, he sent you?$B$BI see.',
    `RequestItemsText` = 'What can I do for you?'
WHERE `entry` = 40668;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Mally O''Flor would take careful time analyzing the blood.>$B$BYou honor your word, and so I shall honor mine.',
    `RequestItemsText` = 'Have you had any progress?'
WHERE `entry` = 40669;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is always useful to have information, it helps one not step on their own feet.$B$BDo not forget that $N.$B$BYou''ve done well, and now we can act without worry.',
    `RequestItemsText` = 'Have you had any progress?'
WHERE `entry` = 40670;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I advised the Warchief against the sending of envoys. It was no use with a man like Alverold.$B$BOur men were cowardly assailed under the flag of peace. Those treacherous Kul Tirans tied them to stakes, soaked them in tar and burned them alive on the shore.$B$BNow we hold nothing back, now we put an end to them!',
    `RequestItemsText` = 'You return, and not a moment too soon.'
WHERE `entry` = 40671;

UPDATE `quest_template` SET
    `OfferRewardText` = 'If my duties did not keep me here, I would have gladly joined you in the thrill of battle.$B$BYou have delivered the Warchief''s reckoning to our enemies. For that, the whole Horde shall sing your praise.',
    `RequestItemsText` = 'Have they been overcome, have they been destroyed?!'
WHERE `entry` = 40672;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is done, then. With their chain of command gone, it might take months for their expedition to re-organize.$B$BWe shall not give them such a luxury.',
    `RequestItemsText` = 'It must be done, their leaders must die. They, more than the luckless footsoldiers they throw at us, are at fault for the persecution of our people.$B$BDo not forget it.'
WHERE `entry` = 40673;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Dar''nakk holds the head of Alverold aloft.>$B$BHere you are, pinkskin. Burn in your hell, knowing it was the Horde who vanquished you.$B$BWe orcs are here to stay, you make sure you remember that when you bring my regards to Daelin!$B$B<Dar''nakk looks back to you.>$B$BNow, you and I shall have a talk.',
    `RequestItemsText` = 'I have not forgotten Alverold''s heinous pyres. Give him and the last of his expedition what they deserve!'
WHERE `entry` = 40674;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I feel sorrow in having to be forced to violence a second time in so few years.$B$BBut I feel no shame in ordering the deaths of our enemies when our sovereignty is infringed. A war in the defense of our people is a just war.$B$BTake pride in your bravery, $N! For I now name you Champion of the Horde and give you this mighty signet as recognition of your triumphs! Bear it with honor!',
    `RequestItemsText` = 'Here you are. Hail, $N!'
WHERE `entry` = 40675;

UPDATE `quest_template` SET
    `OfferRewardText` = '<She swishes her fawn tail and small flowers drop from her hair in her visible excitement>$B$BOh, fantastic, simply fantastic!',
    `RequestItemsText` = 'Hi! How goes it?'
WHERE `entry` = 40676;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Fantastic! Oh, I could kiss you! You probablyŌĆ” wouldn''t like that though, right? Right. Oh, Thank you so much! I will report this immediately to the Circle.',
    `RequestItemsText` = 'Yes? Yes? Do you have it?'
WHERE `entry` = 40677;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, I watched you killin'' them from the pier!',
    `RequestItemsText` = 'Have you made the seas safer for me, mon?'
WHERE `entry` = 40678;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Gowlfang is rightful leader, Gowlfang strong, you help Gowlfang!',
    `RequestItemsText` = 'You get armband yes-yes?'
WHERE `entry` = 40679;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Gowlfang is one true alpha, Gowlfang lead-lead soon!',
    `RequestItemsText` = 'They killed-killed? You slay alpha for Gowlfang?'
WHERE `entry` = 40680;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Gowlfang happy, you kill enemy, Gowlfang now able to lead!',
    `RequestItemsText` = 'You find Sagepaw, you kill!'
WHERE `entry` = 40681;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Razormaw no match for $N, you strong-strong, and quick-quick, one day Dagdag be like you.',
    `RequestItemsText` = 'Razormaw strong, they kill-kill quick, you must be quick-quick too!'
WHERE `entry` = 40682;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Bogpaw Truthsay thank you for work-work, less dragon means more good spot for herb!',
    `RequestItemsText` = 'You deal with dragon?'
WHERE `entry` = 40683;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hail to you friend, I am Chen Stomstout, Brewmaster from Pandaria, and perhaps you can aid me with a little something in return for a jolly time!',
    `RequestItemsText` = 'Oho, what have we here?'
WHERE `entry` = 40684;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hail to you friend, I am Chen Stomstout, Brewmaster from Pandaria, and perhaps you can aid me with a little something in return for a jolly time!',
    `RequestItemsText` = 'Oho, what have we here?'
WHERE `entry` = 40685;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, Wonderful! I shall then prepare something really special for you. These were the final ingredients I needed for the Stormstout Surprise! Go ahead and enjoy it to your heart''s content.$B$BAh this has brought back some good memories of my homeland where many of my people would be competing and collaborating to make the brew of the year. I believe I will go a step further with the festivities here next year and organize something grand, yes? It shall be Pandemonium!',
    `RequestItemsText` = 'Did you get the ingredients? Yes?'
WHERE `entry` = 40686;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, their actions could have cause chaos for us should their plots and ploys come to fruition. Take these coins, as thanks for us here in Theramore.',
    `RequestItemsText` = 'Have you find the hideout, and dispatched the turncoats?'
WHERE `entry` = 40687;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, their actions could have sown chaos in the region. Here, take these coins as thanks from us here in Theramore.',
    `RequestItemsText` = 'Each day the Blackhorn are left to their devices is another day more of our patrols may be ambushed.'
WHERE `entry` = 40688;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You fight well and kill better, $N. With you at our side, who knows, we might even conquer Theramore a second time over!',
    `RequestItemsText` = 'Have the wretches been dealt with, $C?'
WHERE `entry` = 40689;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You ease the blood that boils in my veins, it is good to know such a craven has been removed from the world.$B$BYou have my gratitude $R.',
    `RequestItemsText` = 'The Grimtotem must be checked, and trampled.'
WHERE `entry` = 40690;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now you see why it is I traveled so far?$B$BI will reclaim my families glory.',
    `RequestItemsText` = 'There is a reason for me being here, beyond all else.'
WHERE `entry` = 40691;

UPDATE `quest_template` SET
    `OfferRewardText` = '<The sight of the axe nearly brings a tear to Grumnir''s eyes.>$B$BI cannot believe it, after all of these years, and finally before me again.$B$BYou have honored our family beyond belief, and given me justice, and relief.$B$BI will not forget this moment $N.',
    `RequestItemsText` = 'Each second that orc breaths is longer that my family remains dishonored.'
WHERE `entry` = 40692;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Flinthammer''s goggles begin to fog up.>$B$BOh by sweet Ironforge!$B$BThat is it, it really is it! I can''t believe you went and recovered the thing, good and honest work you did for me.$B$BHere, take these, and some coin on top. Maybe I can find a new place to look for rare crystals now.$B$BAll thanks to you of course.',
    `RequestItemsText` = 'Windshear Gemstone....Oh, what a beauty that''d be aye?'
WHERE `entry` = 40693;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, now lets see...$B$B<Harlek takes his time, inspecting the part over.>$B$BBlasted, it would appear the part took even more damage during my retreat from the assaulting birds... I will need some specialized equipment if I am to have a chance at getting my turbo-charge beauty back in the sky.$B$BOh, about that ale, I had one, sorry about that, a troubled mind is a thirsty mind, as they say.',
    `RequestItemsText` = 'Grounded, unable to soar the sky! I lament at such dark times.'
WHERE `entry` = 40694;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Harlek sent you?$B$B<Tansi lets out a sigh.>$B$BThis is the fourth time in the past few weeks he has asked for my assistance with parts, that flying machine of his keeps breaking down.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40695;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Harlek Vaultshield visibly lights up.>$B$BHaha! I am free to fly again, a savant of the skies to soar once more!$B$BThanks to you and Tansi I am no longer land locked.$B$BGood work $C.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40696;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Why, I must say, you have certainly gone above and beyond what I have asked, this is quite a perfect specimen, and will help me with my work.',
    `RequestItemsText` = 'There is no doubt in my mind that nature is being disturbed.'
WHERE `entry` = 40697;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I am once again left with more questions...$B$B<Maloran clutches his jaw, musing to himself in thought.>$B$BMore work will be needed to uncover a solution to the problem.',
    `RequestItemsText` = 'Have you heard news?'
WHERE `entry` = 40698;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You honor your word, and so I will honor mine.',
    `RequestItemsText` = 'My hands are eager for some practice, have you had any luck?'
WHERE `entry` = 40699;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It eases my mind to know that we may just be a little more safe in our, somewhat isolated position, I thank ye for that.',
    `RequestItemsText` = 'Have you dealt with the dead $R?'
WHERE `entry` = 40700;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You certainly have eased a troubled mind. Many a stronger dwarf than me fell at the hands of Gorras, and I hoped not to be another.$B$BI thank you for everything youŌĆÖve done for us. Take this, as a token of my thanks.',
    `RequestItemsText` = 'Gorras Thorncrusher will not cease, and must be dealt with.'
WHERE `entry` = 40701;

UPDATE `quest_template` SET
    `OfferRewardText` = 'By my beard, I must say, this is astounding work.$B$BHopefully they will get the memo and leave Windshear Crag for good.',
    `RequestItemsText` = 'Have the Venture Company been removed as a threat?'
WHERE `entry` = 40702;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I feel it now, severed from this dreadful link. I am at peace, and for that I thank you.',
    `RequestItemsText` = 'I can not rest, while this evil still lurks.'
WHERE `entry` = 40703;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Immaculate condition, not really sure what they''re worth, but, it''ll be something. Thanks for the trouble $C.',
    `RequestItemsText` = 'So, you get those cuffs?'
WHERE `entry` = 40704;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh finally! A chance to pack up and get back on the road, here, take some silver for the effort, you may have saved my job.',
    `RequestItemsText` = 'Had any luck yet?'
WHERE `entry` = 40705;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your efforts are truly spectacular, without your help, I am not sure how we would have been able to put an end to the Venture Co. within the Blacksand Oil Fields.$B$BI must thank you, and from the bottom of my heart, perhaps we may bring balance to Stonetalon after all.',
    `RequestItemsText` = 'Has it been done $C?'
WHERE `entry` = 40706;

UPDATE `quest_template` SET
    `OfferRewardText` = 'They will think twice when placing their hands upon sacred land, we will not stand aside any longer.',
    `RequestItemsText` = 'If we do not act decisively, the world will continue to be devastated and exploited for the Venture Company''s profits.'
WHERE `entry` = 40707;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done! I''ll let you in on a little secret. We''re working on a way to replicate this, the one you got us will be the template.$B$BI will let the Kirin Tor know of your service to the nation. Stay safe, friend.',
    `RequestItemsText` = 'Do you have it?'
WHERE `entry` = 40708;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Any donation is appreciated, no matter how small.',
    `RequestItemsText` = 'Greetings. The Council of Dalaran is currently accepting donations of the magical kind from outside sources. Even though weaker magical essences are more plentiful than other more powerful fonts they are still appreciated. For 3 Greater Mystic Essences I''ll put in a good word of your efforts within Dalaran.'
WHERE `entry` = 40709;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Nicely done, I''ll make sure this is known.',
    `RequestItemsText` = 'Greetings. The Council of Dalaran is currently accepting donations of the magical kind from outside sources. Small Radiant Shards are a quite potent font of power used for many tasks within Dalaran and are always needed. For a Small Radiant Shard I''ll put in a good word of your efforts within Dalaran, more than donations of weaker magical essences.'
WHERE `entry` = 40710;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I''ll personally make sure this is known, Dalaran thanks you for your donation.',
    `RequestItemsText` = 'Greetings. The Council of Dalaran is currently accepting donations of the magical kind from outside sources. The innate power of Large Brilliant Shards are only rivaled by the enigmatic Nexus Shards, only found on locations of major interest and acquired from artifacts of great power. For a Large Brilliant Shard I''ll put in a good word of your efforts within Dalaran, the most you can get from a single donation.'
WHERE `entry` = 40711;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It may seem cruel of me to ask you to put them to rest, my own people. But fear not stranger, as the sun comes up on the morrow, they too shall rise again.',
    `RequestItemsText` = 'Do not pity them.'
WHERE `entry` = 40712;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The cycle has begone, no doubt you have seen an echo of the past before your eyes, the last king, crowned before the temple.$B$BAn honor to witness one last time.',
    `RequestItemsText` = 'It is only a matter of time now.'
WHERE `entry` = 40713;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Perhaps now you understand it all.',
    `RequestItemsText` = '<The Forgotten Keeper stares at you.>'
WHERE `entry` = 40714;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Keeper sends our promised salvation. It seems the time has finally come for our curse to be undone.',
    `RequestItemsText` = 'Hail.'
WHERE `entry` = 40715;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I do not know what came to be of the newest generations, but the Keeper once told me that the written word is history''s greatest triumph and I wish to be remembered.',
    `RequestItemsText` = '<Corthan stares at the parchment you have in your hand.>'
WHERE `entry` = 40716;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The witch is dead, and the curse uplifted. It was by sheer will that I''ve yet remained to thank you.$B$BI bestow upon you, my crown and blade, may they both serve you well. I will now become an everlasting flame in the lands beyond.',
    `RequestItemsText` = 'This day has come.'
WHERE `entry` = 40717;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Kagoro? What does he want now? I''m not making him another of those super spyglasses again, just so you know!',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40718;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Perfect bub, let''s do some investigatin''.',
    `RequestItemsText` = 'You got the goods?'
WHERE `entry` = 40719;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, is that true?$B$BIt clears up one more lead for us, we should bring our evidence forward to the Alliance.',
    `RequestItemsText` = 'You got what you need?'
WHERE `entry` = 40720;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It seems we know our next course of action.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40721;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I wish I could have joined you on the battlefield. It must''ve been a glorious sight.$B$BI am proud of you, and of Kagoro. You really proved yourselves for the Horde this day. The justice was served, deserters will no longer steal our supplies and war with the Alliance was avoided. It feels like there are only winners.$B$BWell, maybe except the Hyals. Poor family.$B$BAs a reward, please, take any one of these weapons. They are sacred to Brackenwall, and deserving of one such as yourself.',
    `RequestItemsText` = 'Have you had any luck $N?'
WHERE `entry` = 40722;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is..$B$BI...$B$B<Falgran Hastil clears his throat, and nods his head.>$B$BThe Alliance thanks you for this action, friend.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40723;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, would you look at that, perhaps you''re as good as killing apes as O''ggon!',
    `RequestItemsText` = 'The apes can be a savage bunch, I would be careful out in the wild.'
WHERE `entry` = 40724;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well would you look at that, you got the claws. As much as I hate to see money go away, it needs to be done, here.',
    `RequestItemsText` = 'Any luck with those murlocs?'
WHERE `entry` = 40725;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Would you look at that, perfect size too. Thanks a bunch!',
    `RequestItemsText` = 'Had any luck finding the damn thing?'
WHERE `entry` = 40726;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Why, this is it! I''ll be honest with you, I thought the apes would tear you apart when you trundled out of here, but to actually have it in my hands...$B$BHere, take this ring. I''m trying to save gold just in case this Tel Co. thing goes even more pear-shaped.',
    `RequestItemsText` = 'You find my tools yet, kid?'
WHERE `entry` = 40727;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Maybe we stand a chance after all! You really took the fight to them, you might of even made O''ggon jealous.$B$BNice work out there, here, as a thanks from us here at Tel Co.',
    `RequestItemsText` = 'What are you waiting for, we don''t give bonus around here kid.'
WHERE `entry` = 40728;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These should do. You have aided my experiments.',
    `RequestItemsText` = 'The longer you stand around, the longer my work will take, go on now, quick quick!'
WHERE `entry` = 40729;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, here we go... Maybe it really is this simple.',
    `RequestItemsText` = 'So, you end up finding that Elixir?'
WHERE `entry` = 40730;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Tazzo sent you huh? He''s finally coming back crawling for that information. He made such a point about being able to figure it out all on his own, and here he is, sending a mule to do his dirty work.$B$B<Leezza begins to laugh.>$B$BThat is almost as insulting as his stupidly big head wandering here and asking himself.$B$BLook $C, you want that info, it''ll cost you, lets make it one gold, fifty silver, and a favor afterwards while you''re here.',
    `RequestItemsText` = 'Tazzo sent you huh? He''s finally coming back crawling for that information. He made such a point about being able to figure it out all on his own, and here he is, sending a mule to do his dirty work.$B$B<Leezza begins to laugh.>$B$BThat is almost as insulting as his stupidly big head wandering here and asking himself.$B$BLook $C, you want that info, it''ll cost you.'
WHERE `entry` = 40731;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, about time.',
    `RequestItemsText` = 'So, mule, you get those sacs yet?'
WHERE `entry` = 40732;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, her rumors -were- true!$B$BThe secrets of the Gargantuan Banana were real!',
    `RequestItemsText` = 'So, you hear anything?'
WHERE `entry` = 40733;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It''s... It''s...$B$B<Tazzo is lost for words, his face a mix of wonder, and amazement as he takes his time to study the banana. Placing a single hand upon the skin, the gnome would gently pat it.>$B$BBeautiful.',
    `RequestItemsText` = 'So, do you got it?!'
WHERE `entry` = 40734;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My my, you are resourceful!$B$BI could probably tell you to go and get me the head of Illidan, and you''d be back in a couple days!$B$BNow now, lets get to it..',
    `RequestItemsText` = 'You get those materials yet?'
WHERE `entry` = 40735;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Brilliant, I will make sure to put them to good use.',
    `RequestItemsText` = 'You get a chance to find everything I need?'
WHERE `entry` = 40736;

UPDATE `quest_template` SET
    `OfferRewardText` = 'We did it $N, with my powers, and your handiness we figured out the secret to the Gargantuan Banana. I never thought I would see the day where I could pull something off like this!$B$BI have you to thank for this, without you, I''d still be here fiddling with bananas and putting giant elixirs on them if I was lucky.$B$BFrom now on, if you ever need another Gargantuan Tel''abim Banana, you come here, and I''ll make one, should you have the materials of course!',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40737;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What is this thing, it''s massive! Such a unique texture, this is one of those gargantuan bananas that Tazzo has been going on about, he finally did it?$B$B<The goblin smirks from ear to ear.>$B$BWith this thing I could become a legend back at Kezan. Say, why don''t you help me develop some recipes? You help me, and I''ll even share. With my name on them of course.',
    `RequestItemsText` = 'Yes? What is it?'
WHERE `entry` = 40738;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Within a matter of seconds, the gnome processes the bananas and procures a Gargantuan Bananas before your eyes.>$B$BThere you have it, one transmuted Gargantuan Banana. If you ever want more bananas, stop by any time!',
    `RequestItemsText` = '<Within a matter of seconds, the gnome processes the bananas and procures three Gargantuan Bananas before your eyes.>$B$BThere you have it, one transmuted Gargantuan Banana. If you ever want more bananas, stop by any time!>'
WHERE `entry` = 40739;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Within a matter of seconds, the gnome processes the bananas and procures five Gargantuan Bananas before your eyes.>$B$BSee? It''s all refined now! If you ever want more bananas, stop by any time!',
    `RequestItemsText` = '<Within a matter of seconds, the gnome processes the bananas and procures fifteen Gargantuan Bananas before your eyes.>$B$BSee? It''s all refined now! If you ever want more bananas, stop by any time!>'
WHERE `entry` = 40740;

UPDATE `quest_template` SET
    `OfferRewardText` = '<A massive sigh of relief escapes from Baron Telraz>$B$BOh my, you just saved my day, and my company at that! I was seriously -FREAKING OUT- here, and you went and got this all done for me.$B$BHere, I pay those that help and save my hide. You can take this gold coin from me-a gesture of good will.',
    `RequestItemsText` = 'So, you get those bananas?$B$B<Baron Telraz appears to be on edge.>'
WHERE `entry` = 40741;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Heh, those pesky Brushtails never bothered me any, maybe the workers will be able to finally get back to work with less danger out there.$B$BThanks for the work, here, as a reward, we have a bunch of extra stuff laying around these days.',
    `RequestItemsText` = 'Those snakes been dealt with?'
WHERE `entry` = 40742;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Chieftain Icepaw looks on with astonishment.>$B$BYou really are a festive individual, I prepared some things for you upon the fire, a tray of our famous cookies here in Icepaw Village, I hope you enjoy them, they are fresh and right off the pan!$B$BI will share these goods with the others in the village!',
    `RequestItemsText` = 'I sure am hungry, you find an assortment of food?'
WHERE `entry` = 40743;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, the young ones will be pleased. I may be old, but celebrating the holiday is always the highlight of my year, and to wrap gifts for others is always a favorite past time.$B$BHere, take this, as a thanks from myself.',
    `RequestItemsText` = 'So, have you got any wrapping paper for us?'
WHERE `entry` = 40744;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I cannot thank you enough for recovering this, those Winter Grell surely got the best of me this year, but thanks to you, all is better now, here, as a token of my thanks, have some ale on me.',
    `RequestItemsText` = 'Have you found it yet?'
WHERE `entry` = 40745;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent work out there, another season of celebrations will go with less tomfoolery.',
    `RequestItemsText` = 'It is a never ending conflict with these Winter Grell..'
WHERE `entry` = 40746;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, here you are, and here are your pair of Programmer Socks.$B$BThey are extremely comfortable and increase your skill by a considerable margain.$B$BI better not catch you without them.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40747;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Bomarn beams with excitement.>$B$BOh, this is it, the mystical keg of Winter Veil Brew! I haven''t had a drink in ages past.$B$B<Bomarn quickly drinks from the barrel with an eagerness.>$B$BOh, where has me manners gone, here, like I promised, take a couple tankards, only the best for a brave adventurer like yerself.',
    `RequestItemsText` = 'You had any luck finding the barrel down there?'
WHERE `entry` = 40748;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, so you need someone to translate this for you? Let me see it.',
    `RequestItemsText` = 'Yes? What do you have there? It appears to be written in my language.'
WHERE `entry` = 40749;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here it is, a magical delicacy for fresh minds!$B$BI present Danonzo''s Tel''Abim Surprise, just like its name implies, a sheer treat to the tongue. A mix of both chewy and sweet textures served warm with a sheer lovely taste. Thanks to the garnish of Heart of the Wild.$B$BAs I promised, here is the recipe. Don''t forget to tell people who figured this all out now, ya''hear?',
    `RequestItemsText` = 'You gather everything yet? I''m dying for the opportunity to cook wonderous dishes here!'
WHERE `entry` = 40752;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here it is, a magical delicacy for fresh minds!$B$BI present Danonzo''s Tel''Abim Delight, just like its name implies, a sheer treat to the tongue, a mix of bow chewy and sweet textures served warm with a sheer lovely taste thanks to the garnish of Mountain Silversage.$B$BAs I promised, here is the recipe, don''t forget to tell people who figured this all out now, ya''hear?',
    `RequestItemsText` = 'My destiny is ahead of me, what''s taking you so long to collect everything?'
WHERE `entry` = 40753;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is complete, Danonzo''s Tel''Abim Medley!$B$BServed cold, this banana cake is filled with a airy banana cream, incredibly sweet, with a crumbly outer layer! With this, I shall dominate Kezan, and potentially even other markets!$B$BI did promise to share this recipe, and I am an honest goblin, perhaps rare for my kind.$B$BJust remember where you got it huh, I don''t want anyone stealing my ideas now, you know?',
    `RequestItemsText` = 'I can wait no longer to start, hurry up with gathering what I need!'
WHERE `entry` = 40754;

UPDATE `quest_template` SET
    `OfferRewardText` = 'By my ears, this is it! Well done, this has saved me an extraordinary amount of time, and as you know, time is money, especially in this case.',
    `RequestItemsText` = 'So, you have any luck yet $C?'
WHERE `entry` = 40755;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Huh, what is it you want, you here for something special?$B$BOh, Bixxle sent you huh, that idiot? He spent a good five years making some banana sorter, what does he need?',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40756;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Jabbey looks on the small pile of snuff with displeasure.>$B$BWell this certainly is a disappointment.',
    `RequestItemsText` = 'You find that good for nothing thief, and give him justice yet?$B$BBetter yet, you recover my stuff?'
WHERE `entry` = 40757;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, I didn''t expect you to actually return, that''s a bummer. Oh well, a goblins word means something in this world, to some people anyway.',
    `RequestItemsText` = 'Careful holding that Blighted Essence when you bring it around here, last thing I want is some super disease in Steamwheedle.'
WHERE `entry` = 40758;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, they were that hard to get, huh? Hope it wasn''t too much of a fuss getting them for me. Here, take some coin for all the trouble.',
    `RequestItemsText` = 'So, what did Jabbey say?'
WHERE `entry` = 40759;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Bixxle let''s out a sigh of relief, smirking from ear to ear.>$B$BYou''ve really helped me out here, working from Tel''Abim complicates everything, especially with how remote the location is.$B$BYou came in clutch friend, and for that I should reward you with something, and I know just the thing.$B$BLook, if you ever need anything else, let me know, you''ve saved me more gold than I would''ve made in years, and almost as much time even!',
    `RequestItemsText` = 'You get all those things yet?'
WHERE `entry` = 40760;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I assume he complained huh?$B$B<Bixxle laughs.>$B$BYeah, this is quite secretive and a prototype build of Dark Iron Engineers, that''s why we''re going to master it.$B$BYou wouldn''t imagine it but I am quite a reknowned Engineer, and have had many run ins with these ''Dark Irons'', heck I was even contracted for some stuff in their vaunted city.',
    `RequestItemsText` = 'So, you speak with him yet?'
WHERE `entry` = 40761;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Behold, a creation of great magnitude, the ideas of wicked dwarven design, crafted by yours truly.$B$BI hope this serves you well, and does what damage you need to deal on those that may be your enemy.$B$BWe are even now, this surely is worth quite a bit of gold after all, maybe not as much as my Screwfuse 1000, but close enough.$B$BBest of luck out there $N, I hope we cross paths again.',
    `RequestItemsText` = 'Have any luck recovering the materials yes $N?'
WHERE `entry` = 40762;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is a nice haul and the ghosts are gone, yeah? I will order the crew to start diggin'' once we make sure there''s no further complications. Now let''s see about these texts... Hmm, very fascinating! $R I may need your assistance again.',
    `RequestItemsText` = 'Well, how did it go?'
WHERE `entry` = 40763;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hoo mama! This is what I''m talkin'' about! This haul will earn us lots of prestige and accolades. This is both Azotha, Troll, and  gold from other civilizations they must have buried here! You deserve your share for sure! We may work again in the future, you''ve certainly been useful!',
    `RequestItemsText` = 'Well? Don''t keep me in suspense, did ya do it?'
WHERE `entry` = 40764;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Huh, Telraz sent you? I was wondering when he would check in. I guess everything has gotten quite crazy around here after all!',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40765;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A report from Bixxle himself? Give me that!$B$B<Baron Telraz frantically reads the letter with utmost curiosity, letting out a sigh of relief.>$B$BMy, that certainly is a relief! Without Bixxle, I would have no idea how to manage things up there. Thanks for the work kid. Here, take some coins for the hassle of running around.',
    `RequestItemsText` = 'So, have you heard news from Bixxle''s Storehouse?'
WHERE `entry` = 40766;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My my, you sure are resourceful, I didn''t expect you to get it done so quick.$B$BHere, take this, we have a bunch of spare ones laying around now that the enforcers took off and left south.',
    `RequestItemsText` = 'You got rid of those critters yet?'
WHERE `entry` = 40767;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Not bad, good work out there, making the jungle just a little bit easier to handle is always noble work for us here.$B$BHere, as thanks.',
    `RequestItemsText` = 'Yeah, you get those scales yet kid?'
WHERE `entry` = 40768;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, this certainly is a rarity, while you were gone I thought of a few ideas that could work to incorporate the horn into armor, and I believe I have come up with the perfect idea.$B$BTake this, as a thanks for the assistance!',
    `RequestItemsText` = 'You had any luck yet, or you here looking for a coat to brave the cold weather?'
WHERE `entry` = 40769;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You help Ebu!$B$BMonkeys thank you, we thank you yes yes!',
    `RequestItemsText` = 'You hurt murloc, beat murloc?'
WHERE `entry` = 40770;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ebu thank you, ebu give you biggest gift of all.$B$BFrom us here, we thank you for everything!',
    `RequestItemsText` = 'You find Nibu, you save Nibu?'
WHERE `entry` = 40771;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent work! You might have saved the holiday season! Now many of us can sleep easy knowing that there is less evil lurking about, and for that, I want to thank you, personally.$B$BTake this, may it help you in the coldest of places.',
    `RequestItemsText` = 'I warn you friend, to bring help, they are strong, and tough opponants.'
WHERE `entry` = 40772;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, you have proved yourself, maybe now they will leave Felwood, and not return.',
    `RequestItemsText` = 'So, has the deed been done $R?'
WHERE `entry` = 40773;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My, these sure are fascinating, full of quite toxic material.$B$BMy benefactors back in Undercity will be pleased, and here, as promised, take these coins.',
    `RequestItemsText` = 'Have you acquired my samples yet?'
WHERE `entry` = 40774;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You did well.$B$BYou can go now. You are not needed anymore.',
    `RequestItemsText` = 'Don''t waste any more time. Get it done, and make sure it''s done right.'
WHERE `entry` = 40775;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is quite satisfying to witness the downfall of those who boast about their faith in the Betrayer. They''ve made a mockery of their legacy by dying at the hands of a paid mercenary.',
    `RequestItemsText` = 'They deserve no sympathy.'
WHERE `entry` = 40776;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Zoki is the Horde''s strongest warrior!',
    `RequestItemsText` = 'Hello.'
WHERE `entry` = 40777;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Zoki is still not on the naughty list, even if his words are harsh at times, he didn''t steal anything. A gift, because you humored the children!',
    `RequestItemsText` = 'Merry Winter Veil!'
WHERE `entry` = 40778;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, thank you! Now the celebrations can go as planned. Here, you can pick something from here as your own special gift from me!',
    `RequestItemsText` = 'Do you have them yet?'
WHERE `entry` = 40779;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done! This is a start, the legends all seem to share the characteristic of a character that arrives during the winter and brings succor and protection from the cold. Let us continue...',
    `RequestItemsText` = 'You return, how did it go?'
WHERE `entry` = 40780;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, very interesting! The Ice trolls call it The Spirit of Winter, perhaps it could be an elemental of some sort. The Goblin one is pretty obvious and I doubt it even counts as a legend and the Dwarven one... Well I am well familiar with it. But enough about that, now comes the good part, ohoho yes!',
    `RequestItemsText` = 'Did you speak with them yet?'
WHERE `entry` = 40781;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve had some sightings? I uh... see that''s unexpected, well I''ll note it down. Once look into all of them, we may further inquire into the situation.',
    `RequestItemsText` = 'Yo?'
WHERE `entry` = 40782;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve had some sightings? R-Really? Uhm... Give me a moment as I note this stuff down. Well once we have all six I suppose we''ll move on to the next stage of this.',
    `RequestItemsText` = 'You''re back?'
WHERE `entry` = 40783;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Eh? You got a voucher for a Reindeer? Blast! It''s been a long time since I''ve seen one of those, kid! They were a special promotion years back... You say you got tricked by Mulin? Hah, old coot is officially here to research legends, but in actuality he just wants to drink and feast. I bet his employees won''t approve if they found out he used his research funding on feasting so that''s why he cooked up this whole scheme. Well that''s none of my business now is it? Well the Vouchers do not expire, so a deal is a deal, enjoy your new Reindeer!',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40784;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My my, that is one MASSIVE monkeys foot, this wouldn''t be Morogo Thunderfoot''s rear paw now, would it?$B$B<Sneel Fizzwack blinks at you blankly.>$B$BI never expected anyone to actually claim a reward when we put that bounty board up, nor did I expect anyone to be crazy enough to go through with it!$B$BLook, I can find something, here.',
    `RequestItemsText` = 'So, whatcha need bub?'
WHERE `entry` = 40785;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The samples are peculiar as they do not exhibit any signs of being twisted by foreign interference or the hands of foul magic. Instead, they appear to be deformed due to primalistic rage.$B$BThere may be a link here that I am not seeing, but I doubt that these samples are connected to what is happening here in Felwood.$B$BRegardless, I appreciate your efforts in ruling out such a possibility.',
    `RequestItemsText` = 'Has your journey made progress yet?'
WHERE `entry` = 40786;

UPDATE `quest_template` SET
    `OfferRewardText` = 'For many long years, I have been without the star by my side, but thanks to your efforts, it is now where it rightfully belongs.$B$B<Niremius Darkwind seems lost in the power of the Darkwind Star, his eyes glowing with deep energy.>$B$BYou have performed admirably, young one, and as such, I have prepared a reward for your assistance - one that is truly worthy of your efforts.',
    `RequestItemsText` = 'With every passing moment, the traitor Faladar comes closer to achieving his vile schemes.'
WHERE `entry` = 40787;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Would you look at that! Pristine too, nice work, excellent work even. My client was going to get a bit tight and upset with me if I didn''t pull through, so you came in clutch.$B$BHere, as I promised.',
    `RequestItemsText` = 'Hey there outrider! You make that trip to Tel''Abim yet?'
WHERE `entry` = 40788;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A Kul Tiran paladin gave you this book?$B$BIn Kul Tiras, the Holy Light is not as widespread as it is in Stormwind and Lordaeron; places where the tradition of the faith has long been established.$B$BYet I am gladdened to see that our church has touched the heart of such a worthy man. I will make sure all its contents are kept safe in our archives.$B$BThank you, and may the Light ever be with you, $N.',
    `RequestItemsText` = 'Light''s blessings, $N. Have you come to join our service?'
WHERE `entry` = 40789;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, look at that, not even part of the Old Alliance, and still making yourself useful as a $R. Perhaps you do have it cut out to be part of the navy after all.',
    `RequestItemsText` = 'You get that food yet maggot?!'
WHERE `entry` = 40790;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, I was right to trust my hands in you. Perhaps not all is so bad in this ''New Alliance'' afterall, or so I was believed to think you were all just too lazy to work on behalf of this war.$B$BYou''ve done well, and for your hard work, you''ve earned this commendation, wear it with pride soldier.',
    `RequestItemsText` = 'So, you had any luck yet?'
WHERE `entry` = 40791;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Aqua Core, and even more potent than I had hoped!$B$BIn this arid land of beasts, mongrels and demi-humans, I dared not hold faith in assistance from anyone. But now, my control of the tidal elements is secured.$B$BYou have my thanks, $C.',
    `RequestItemsText` = 'Has the Aqua Core been recovered?$B$BI know it might take you some time to find, but it is imperative it comes into my possession.'
WHERE `entry` = 40792;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The souls of our honored dead sing of your name, $C.$B$BBut there shall be no peace for me, not until all of Lord Daelin''s murderers are dead and their accursed nations gone with them.',
    `RequestItemsText` = 'If it were within my power, I would nail their entire race to stakes and watch the life burn out of them. The way my people burned. The way my father died.'
WHERE `entry` = 40793;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Alverold lives?! Tides be thanked!$B$BWith the fall of Lord Daelin, we thought the western cause lost. Indeed, many in Kul Tiras have elected to divert our attention north.$B$BIt will not be easy to persuade them to support the Kalimdor Expedition again; it is far more likely that they will demand Alverold''s return for his assistance in the northern realms instead.$B$BStill, I will do what I can and send word to Alverold once I have news.$B$BYou have Kul Tiras'' gratitude, $N.',
    `RequestItemsText` = 'What is it? Can I help you?'
WHERE `entry` = 40794;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Exceptional. I hope you sustained no injuries during your battles? You have aided more in one skirmish than those childish sentinels have done since they arrived.',
    `RequestItemsText` = 'Blights on the land can be hidden with ease, but healed with difficulty. Remember this.'
WHERE `entry` = 40796;

UPDATE `quest_template` SET
    `OfferRewardText` = '<He peaks his ears and snatches the effigy away. He is silent for several seconds, before mewling quietly.>$B$BThis was given to me when I was a mere cub, by my parents. We bless them to protect us, always. They are deeply personal, you only ever get one in life. I sensed something I was barely able to see snatch it away as I came to Forest Song for refuge! I have no idea what they were doing to it, or why. Sometimes it is best not to ask.$B$B<Picking out the thorns, he hugs it to his chest and nods.>$B$BYou cannot know how much this means to me. I have very little, but I would have given everything away to keep this. So please, take... take.',
    `RequestItemsText` = '<The Furbolg watches you curiously as you approach.>'
WHERE `entry` = 40797;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you kindly for your efforts, $N.$B$BDid you carry all of these in your backpack? The smell must be... Nevermind.',
    `RequestItemsText` = 'Welcome back. Have you brought the hippogryph food?'
WHERE `entry` = 40798;

UPDATE `quest_template` SET
    `OfferRewardText` = '<She listens in quiet contemplation as you relate the masters'' advice, meditating on the words for minutes.>$B$BWait... Teloren said what??$B$B<Her face flushes with embarrassment.>',
    `RequestItemsText` = 'I hope you come bearing word from the masters, $N.'
WHERE `entry` = 40799;

UPDATE `quest_template` SET
    `OfferRewardText` = 'He bowed his head? By Elune, that is amazing news! I understand. I shall spend more time with the fledglings in Sharptalon''s presence, and with hard work and some fortune, I will make my family proud. The Moonfeathers will have yet another Hippogryph Master in their lineage!$B$BIt seems this little one doesn''t want to leave your side. I suppose if you promise to care for and look after this child, there should be no issue in allowing it to follow you, right?$B$BThis is the least I can offer after everything you have done on my behalf. Elune smiles upon us both this day, $N.',
    `RequestItemsText` = 'Hello, $N. Did you find Sharptalon?'
WHERE `entry` = 40800;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Impressive to see one with an ounce of sensibility around here. Thank you, $N.',
    `RequestItemsText` = 'I suppose you are going to be as unhelpful as the sentinels then?'
WHERE `entry` = 40801;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done. You have already proven more useful than the sentinels, though admittedly, it is not a high bar.',
    `RequestItemsText` = 'How has the hunt been so far? Anything to report?'
WHERE `entry` = 40802;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I knew I could count on you, from the moment we began to talk. Truly you have earned Elune''s favor this day, and I will make sure the word is spread of your deeds. My thanks, $N.',
    `RequestItemsText` = 'I pray you return with good news, $N?'
WHERE `entry` = 40803;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, the nasty business in Southern Ashenvale has come to an end, has it? Let me see what Brolthan Ironglade has achieved.',
    `RequestItemsText` = 'Speak swiftly, I have numerous other burdens upon my shoulders, if you are going to add to them, I demand you at least do so and leave quickly.'
WHERE `entry` = 40804;

UPDATE `quest_template` SET
    `OfferRewardText` = 'We must rest and meditate at some point, you and I. I would very much like to... what is this? A letter from The Arch Druid?',
    `RequestItemsText` = 'Ah, $N! I hear we have you to thank for bringing this conflict to an end!'
WHERE `entry` = 40805;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here, take one of these as a token of our appreciation for your efforts.',
    `RequestItemsText` = 'You returned for your reward, I take it? Yes, I thought as much.'
WHERE `entry` = 40806;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now that''s what I like to hear! Grab your weaponry, $N.',
    `RequestItemsText` = 'So? Interested in turning the tide?'
WHERE `entry` = 40807;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You positively reek of blood, sweat and dirt. Have you driven them back?',
    `RequestItemsText` = 'You return already?'
WHERE `entry` = 40808;

UPDATE `quest_template` SET
    `OfferRewardText` = '<She bares her teeth and gives a wide grin.>$B$BFantastic. The sentinels shall be recalled, finally, and we shall celebrate tonight. Elun''adore, $N!',
    `RequestItemsText` = 'Is it done? Are the southern forests free of the Horde, at last?'
WHERE `entry` = 40809;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, so our southern forests are finally free of the Horde? This is music to my ears.',
    `RequestItemsText` = 'Greetings, $C. What brings you to our Temple?'
WHERE `entry` = 40810;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A message from Tyrande directly? To me? Curious.',
    `RequestItemsText` = 'Ah, the hero of the hour. Speak quickly, $N, I rather wish to be left alone currently. The drunken singing of the sentinels is making it rather hard to meditate.'
WHERE `entry` = 40811;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That is... harsh, though not unfair to the druids. I think the tension would have forced them away sooner or later anyway. And of course, feel free to choose a newly crafted weapon for your troubles.',
    `RequestItemsText` = '$N! Drink?'
WHERE `entry` = 40812;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent work, the harmonization process does not take me long, especially with all this practice, if you find any more, come and let me know.',
    `RequestItemsText` = 'We must all do our part here in Hyjal, and my part is to harmonize Small Dream Shards into Bright Dream Shards. The harmonization process makes the shards much more potent in regards to their magical properties. If you have any work that you need me to do, bring me three Small Dream Shards, they can be found around Hyjal, or no doubt earned by those in town for tasks in maintaining Nordrassil.'
WHERE `entry` = 40813;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmm, everything seems to be in order here, your assistance to our efforts is well appreciated, here, take this.',
    `RequestItemsText` = 'Druidic magic requires concentration, skill, the blessing of nature, and a touch of Enchanted Leather.$B$BWe go through our stocks fairly quickly here at Nordrassil when the needs arise and it is my duty to keep us ready.$B$BIf you are willing to assist, I can trade two Bright Dream Shards in exchange for ten Enchanted Leather at any time.'
WHERE `entry` = 40814;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I am sure our blacksmith will be eager to work with this new material, thanks again $C!',
    `RequestItemsText` = 'Our enemies on Hyjal continue to grow, day after day. I may not know how to craft a weapon, but I do know our druidic weapons require quite a lot of Enchanted Thorium, and it is my duty to make sure we are prepared.$B$BIf you are willing to help us here in Nordanaar, I can trade a Bright Dream Shard in exchange for ten Enchanted Thorium at any time.'
WHERE `entry` = 40815;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Mooncloth, so divine, and majestic. I can feel the grace of Elune radiating from it.$B$BThank you $C, take this as thanks for helping us.',
    `RequestItemsText` = 'The beautiful fabric of Mooncloth has often eluded us with its rarity and is in quite high demand for all sorts of purpose. If you could get your hands on a single piece, it would go quite a long way for us in Nordanaar.$B$BI could even exchange you with two Bright Dream Shards to make it worth your while. If you end up finding one, let me know!'
WHERE `entry` = 40816;

UPDATE `quest_template` SET
    `OfferRewardText` = 'After years spent wandering these halls as a phantom, I have come to accept the weight of my actions and the consequences that have befallen me. I do not seek absolution or forgiveness from you, for that is not within your power to grant.$B$BInstead, I ask that you consider that which I have revealed to you. Reflect upon my story and the lessons that can be learned from it. Perhaps you too have had a hunger for power or knowledge that has clouded your judgment in the past. Or maybe you have made mistakes that you regret and wish to make amends for.$B$BAs for the next course of action, that too is for you to decide. Will you seek out the key to the Upper Chambers of Karazhan and uncover its secrets? Or will you leave this accursed place behind and seek your fortunes elsewhere? Only you can decide the path that lies before you.',
    `RequestItemsText` = 'Let my story be a reminder to all that seek power beyond their comprehension.'
WHERE `entry` = 40817;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The key... now lies broken and useless, its magical essence lost to time and it is no longer of any use to us in its current state. It appears that even in death, Medivh has one final trick up his sleeve to guard his secrets from the prying eyes of the living.$B$BHowever, we must not lose hope. There must be a way to restore the key to its former glory and unlock the gates to the Upper Chambers. We cannot let the secrets of Karazhan be lost forever. There must be those who still possess the knowledge and ability to revive the key, to mend what was once broken.$B$BI wish I could offer you more assistance, but this is where my part in this quest ends. I can only hope that your journey to restore the key is a successful one, and that the secrets of Karazhan may be unveiled to those who seek them.',
    `RequestItemsText` = 'Have you found Moroes and the key?'
WHERE `entry` = 40818;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmmm, Vandol, you say?',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40819;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Vandol? Let me check the records.',
    `RequestItemsText` = 'Welcome to Theramore. Is there anything I could help you with?'
WHERE `entry` = 40820;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I sense that you have come seeking me, and that you know who I really am. It seems that my past has finally caught up with me, and I must admit that I am not surprised.$B$BTake a moment to consider the gravity of what you are about to say. For you see, I have lived a long life filled with both triumphs and tragedies. I have seen the fall of great kingdoms, and I have witnessed the atrocities that people are capable of committing in the name of power.$B$BIf you are here to confront me about the sins of my past, and the many mistakes that I have made, then I will not fight back. I will accept whatever consequences may come.',
    `RequestItemsText` = 'What brings you to my secluded house?'
WHERE `entry` = 40821;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So you''re looking for Vandol? Very well.',
    `RequestItemsText` = 'You better have a damn good reason for interrupting me.'
WHERE `entry` = 40822;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Vandol?',
    `RequestItemsText` = 'Throm-ka. Is there anything I can help you with, $R?'
WHERE `entry` = 40823;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I sense that you have come seeking me, and that you know who I really am. It seems that my past has finally caught up with me, and I must admit that I am not surprised.$B$BTake a moment to consider the gravity of what you are about to say. For you see, I have lived a long life filled with both triumphs and tragedies. I have seen the fall of great kingdoms, and I have witnessed the atrocities that people are capable of committing in the name of power.$B$BIf you are here to confront me about the sins of my past, and the many mistakes that I have made, then I will not fight back. I will accept whatever consequences may come.',
    `RequestItemsText` = 'What brings you to my secluded house?'
WHERE `entry` = 40824;

UPDATE `quest_template` SET
    `OfferRewardText` = 'In life, Medivh was known to be an extremely cautious and paranoid individual, and he took great measures to ensure that only he and his most trusted allies could access the key to his chambers. Even I, as his friend, was forbidden from doing so.$B$BBut there may be a glimmer of hope yet - if we can locate Echoes of Medivh''s presence, they may be powerful enough to fuel the key. Those with great magical abilities often leave traces of their presence in the fabric of the leylines, causing disruptions that can still be felt long after they are gone.$B$BThese echoes tend to linger in places of great significance to the person''s story, so we must scour the land for any clues or signs that may lead us to the echoes of Medivh. It won''t be an easy task, but it is our only hope of gaining access to Karazhan''s chambers and preventing the dark forces that threaten to consume us all.',
    `RequestItemsText` = 'I have warned you, but I see that you are still determined.'
WHERE `entry` = 40825;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Congratulations on locating Medivh''s Echoes. You have successfully completed the task, but unfortunately, the key remains broken and unusable. It appears that merely fueling it with Medivh''s Echoes was not enough to restore it to its former state. In retrospect, I should have realized this earlier. Please show me the key so that I can inspect it more closely.',
    `RequestItemsText` = 'I am aware of one location where Medivh had been in the past, and that is the throne room of Lordaeron. Although the place now lies in ruins due to the events of the Third War, it is possible that some remnants of the past still exist there. Perhaps, there are traces of his presence that you can uncover in the form of residual energy or forgotten relics.'
WHERE `entry` = 40826;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Once again, you have succeeded where others have failed, and I must say, I am thoroughly impressed by your skills and perseverance. Your unwavering determination to see this task through to the end is truly admirable.$B$BNow, if you would kindly hand over the gems you retrieved from the demon Immol''thar, I shall proceed to reforging the key.',
    `RequestItemsText` = 'Dire Maul lies to the West, in the wild lands of Feralas.'
WHERE `entry` = 40827;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I don''t believe it. "Treatise on Magical Locks and KeysŌĆØ, written by the venerable Aegwynn herself. In my own hands, after all this time.$B$BAllow me to peruse the pages of this ancient text. I am certain that the knowledge contained within its worn and weathered pages was utilized by Medivh in the forging of this key. By studying the techniques and methods outlined in the tome, we should be able to replicate the process and repair it.',
    `RequestItemsText` = 'It is believed that Lord Victor Nefarius dwells within Blackrock Mountain, where he exerts authority over his armies of Blackrock orcs, as well as other terrifying and repulsive creatures.'
WHERE `entry` = 40828;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The task is complete. The Key to the Upper Chambers is now in your hands. The secrets and wonders of the legendary Karazhan await your arrival, and the mysteries of this ancient place shall be uncovered once again.$B$BBut heed my warning. A shadow, cloaked in flame and brimstone, lies in wait. The Burning Shadow, its presence ominous and foreboding, seeks to consume all in its path.$B$BMy role here ends, and I entrust you and your party to take care of it. The fate of Azeroth lies in your hands.',
    `RequestItemsText` = 'Finally.'
WHERE `entry` = 40829;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Father Oblen seems pleased gazing upon his old work.>$B$BAhh, I never thought I would look upon these scripts again, lucky they are to have survived all of the misery that befell that place.$B$BI thank you greatly for your efforts, $C. Please, take this as a sign of my gratitude.',
    `RequestItemsText` = 'It may seem like a perilous task, but remember: Keep your faith in the Light and you are bound to find yourself on the right path.'
WHERE `entry` = 40830;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Are these it? I haven''t had the opportunity to read these plans in quite some years.$B$BAdaman was an exceptionally talented blacksmith and I grieve deeply for his passing. I will make sure his findings are properly recorded here and in Ironforge, so that his name may earn the recognition he always deserved.$B$BThank you, $N. I have prepared something for you as well, as compensation for the immense trouble you put yourself through.',
    `RequestItemsText` = 'Have you had any luck with the plans?$B$BI know it is nothing easy I asked of you, but those plans were a man''s life''s work, it would be a tragedy if they were lost.'
WHERE `entry` = 40841;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The trees, the beasts, the wind; all of nature rejoices. In its song, it is you who are owed thanks, $N.$B$BYour bravery and tenacity in cleansing Demon Fall Canyon have bought us precious time to prepare for the final confrontation. Your actions have not gone unnoticed, and I am proud to call you a comrade in our holy war to protect these lands.',
    `RequestItemsText` = 'Our war with the Legion has been waged across many millennia, through countless battlefields.$B$BWe are the guardians of this world and we will not suffer them to taint it.'
WHERE `entry` = 40842;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It brings great comfort to me to know that I can always rely on your dedication and courage. The satyr Varaxxius was a powerful and dangerous foe, but you have proven yourself to be an expert in combat. Your actions have saved our sacred groves from the vile ambitions of those who seek to exploit the weapon of Mannoroth for their own dark purposes.$B$BBy ending the satyr and preventing any further attempts to repair the weapon, you have struck a heavy blow to our enemies and secured a significant victory for the Kaldorei. May you ever be honored for your service to us.',
    `RequestItemsText` = 'They say the orcs have left a monument to Grommash in the canyon.$B$BI hope you have spat on it.'
WHERE `entry` = 40843;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The boss wants you to help me? I hope you''re a capable $C and not some diplomatic noodle.$B$BWhat you''re about to do will take some guts.',
    `RequestItemsText` = 'Well, hello there.'
WHERE `entry` = 40844;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well I''ll be damned. You actually went and pulled it off! The boss will ensure this Mithril gets where it''s most needed. I''d say you''ve proven your worth, kid. Here''s your cut.',
    `RequestItemsText` = 'Did you get the ore?'
WHERE `entry` = 40845;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Listen up kid: I never wanted to set eyes nor foot upon the land of fancy pantsy Gilneans, not even to rob it. You want to earn my appreciation? Then help me complete this task from the boss so we can finish down here and leave this wretched place.',
    `RequestItemsText` = 'Ah, it''s you.'
WHERE `entry` = 40846;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Gilneas appears to be in open rebellion. One side is led by Prince Liam Greymane and a certain Ravenwood, while the other side is led by corrupt Gilnean nobles. The boss will want to hear about this. You have done well. This task couldn''t have been easy, but as a member of the Horde, you have proven yourself capable with this flawless execution.',
    `RequestItemsText` = 'You return. You had better have that report in hand.'
WHERE `entry` = 40847;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well.$B$BFollowing the victory of the Forsaken, those who possessed a body during the conflict were sent out as the Dark Lady''s eyes and ears. My group is usually sent to spy upon the Alliance as we are suited for blending in among humans.$B$BI have come to grow fond of my comrades in this group. They lacked discipline and purpose once, but are now skilled infiltrators and spies.',
    `RequestItemsText` = 'Shall we continue the tale?'
WHERE `entry` = 40848;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wonderful! You have proven yourself a capable agent of the Dark Lady.$B$BThough your tale of what happened in the city troubles me... If Genn Greymane was truly behind the rebellion, we may have inadvertently aided our enemies. That, however, is neither your fault nor your concern.$B$BWe will take it from here. You are dismissed.',
    `RequestItemsText` = 'The King of Gilneas was once a force to be reckoned with. Though his power and grip over the kingdom has diminished, he will be no easy prey.'
WHERE `entry` = 40849;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I see that the Dark Lady has sent someone to assist us. I may look human, but do not let appearances deceive you.$B$BI am fully committed to the Horde, as my loyalty lies with the Banshee Queen. If you are here to assist, I shall put you to work.$B$BHelp my subordinates, then I will have further instructions for you.',
    `RequestItemsText` = 'And you are?'
WHERE `entry` = 40850;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I am surprised to learn that there exists other like us in this land. It is no surprise they were unaware of our presence, as we came here of our own accord.$B$BNonetheless, if you have come all this way, then surely you intend to assist us.',
    `RequestItemsText` = 'A wandering soul comes to our flock.'
WHERE `entry` = 40851;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Eighteen, nineteen, tw... hmm. That one is really badly damaged, whatever did you do to him? Regardless, you did well. Here is your payment.',
    `RequestItemsText` = 'You seem not to be a dead mercenary. Does that then make you a successful mercenary, or simply a lazy mercenary?'
WHERE `entry` = 40852;

UPDATE `quest_template` SET
    `OfferRewardText` = 'He must not have been such a threat after all, to see you bringing back this trophy so quickly. Though I shall not change the pay now, a reward is a reward. Take it.',
    `RequestItemsText` = 'No further work, your current tasks need to be done.'
WHERE `entry` = 40853;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Glorious, simply glorious. Ah, the sweet taste of it, knowing a debt has been repaid twenty-fold.',
    `RequestItemsText` = 'Be swift, vengeance is a desire best sated immediately.'
WHERE `entry` = 40854;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, delightful. Such brutish craftsmanship, their work often looks quite pathetic, doesn''t it? Ah don''t mind me, your reward, your reward at once.',
    `RequestItemsText` = 'Yes, $N? Have you brought death to their mounds?'
WHERE `entry` = 40855;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Adventurer! I am pleased to inform you that the Alpha Channel and Reserve Pump Channel are performing exceptionally well, operating at approximately 87% efficiency. No, wait, 88%! Given the devastation of Gnomeregan, this is indeed a welcome surprise.$B$BI cannot express enough gratitude for the invaluable assistance you have provided in helping us restore this facility. Without your efforts, we would not have made nearly as much progress as we have.$B$BAs a token of our appreciation, please accept this humble offering from all of us here at the Reclamation Facility. May it aid you with your future endeavors.',
    `RequestItemsText` = 'Our success is critical on the activation of these backup systems. I would advise you to recruit some backup in this task, for Gnomeregan is filled with all manner of terrible things.'
WHERE `entry` = 40856;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Impressive work, $C. You have slain Neevan Gubblewire and scattered his leper ruffians, making our work safer and more secure. Your bravery and determination are admirable, and you have served our cause well. I will be sure to pass along your name with everyone I am sure to run into.$B$BTake one of these as a token of my appreciation, and best of luck out there.',
    `RequestItemsText` = 'Have you found that ruffian that calls himself leader?'
WHERE `entry` = 40857;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Can''t you see that I am busy here? I am trying to get this access terminal operational with subpar tools and inadequate materials! It''s proving to be quite a challenge, even for a gnome of my skill.$B$BSay, you wouldn''t mind helping me out, would you?',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40858;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Technician Stormlight lets out an exhausted sigh of relief.>$B$BI was getting ready to start preparing the copper tubes and bronze frameworks as a backup! You have certainly saved a colossal headache by finding this blasted thing. Now I can get started on some real fixing. Thanks again, $C.',
    `RequestItemsText` = 'Have you had any success in finding my modulator?'
WHERE `entry` = 40859;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Master Technician Wirespanner gazes upon the ore, an expression of giddy joy washes across his face.>$B$BThese dull, repressed glints, I remember them fondly. Excellent work $C, with this ore we will be able to produce enough conductors to fix what is needed in the facility.',
    `RequestItemsText` = 'We have been going through Copper Couplers faster than I can wrap my head around! If we are to keep up with all of the repair work required in this facility we need something that can last.'
WHERE `entry` = 40860;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmm, this is much more complicated than I remember, but with a little bit of elbow grease and some studious applications of gnomish engineering, it shouldn''t be too hard to create a proper replica. It will take some time to test its efficiency before we put it into practice, but this has saved us a lot of time in designing a new prototype.$B$BThanks again $C. Here, take this, a Low Energy Regulator as thanks for your help.',
    `RequestItemsText` = 'Damned spanner, always..$B$BOh, you startled me, you wouldn''t happen to have recovered the schematic would you?'
WHERE `entry` = 40861;

UPDATE `quest_template` SET
    `OfferRewardText` = '<A heavy sigh of relief escapes Cassie Copperlight.>$B$BPhew.$B$BWell, that is one crisis averted. It shouldn''t be long until the other malfunctioning Servitor''s are all destroyed. I got some spare silver for what you''ve done. Hope to see you around!',
    `RequestItemsText` = 'I would be careful dealing with those Servitors. They may be primarily built to help with tasks, but they can be quite dangerous!'
WHERE `entry` = 40862;

UPDATE `quest_template` SET
    `OfferRewardText` = 'By all that is divine, the tome is recovered...$B$BThe weight has been lifted, and my soul is free. You have done me a great service in recovering this text, and for it I must thank you dearly.$B$BPlease, take this robe, as a gesture of my good will.',
    `RequestItemsText` = 'It is imperative that you recover The Mercy of Humility before it is too late.'
WHERE `entry` = 40863;

UPDATE `quest_template` SET
    `OfferRewardText` = 'By Mekkatorque''s word, you''ve done a good job in cleaning up that chemical backup.$B$BThere is still some work to be done, but we will surely finish the job soon.$B$BHere, take this as payment for your help.',
    `RequestItemsText` = 'I''m trying to think of a more scientific solution to this problem, just in case your smashing solution does not pan out.'
WHERE `entry` = 40864;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done it!$B$BThe Chemical Processing Membrane has been recovered. I cannot express how thankful I am to see this! I was already dreading the sheer amount of work we would have to do to make a new one.$B$BNow, we can begin work on the XV-82 with the Tinkers and make it much more sound to deal with chemical issues and resilient to arcane interference.$B$BHere, take this as a token of appreciation. Without you, I would still be scratching my head to think of a solution!',
    `RequestItemsText` = 'The chemists here at the Reclamation Facility are relying on you, $N!'
WHERE `entry` = 40865;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is it, huh? To be honest, I expected more, but perhaps this is only because they are so far from their home.$B$BOh well, I will still go ahead and study this in more depth. At the least you were able to kill some of those rather brutish Dark Iron.$B$BHere, take this coin as thanks.',
    `RequestItemsText` = 'So, have you made it to Ironband''s Compound yet?'
WHERE `entry` = 40866;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Master Chemist Volterwhite takes his time studying the sample with utmost care.>$B$BHmm, this may prove to be a vital piece in the complex puzzle I am working on. I need to test a few things first...',
    `RequestItemsText` = 'The sample I have tasked you with gathering is of extreme importance. Do not delay in this matter.'
WHERE `entry` = 40867;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The grounded nature of the Gol''Bolar Ore and the controlled energy of the Snowvale Root should do well in controlling the extreme fluctuations of the aqua sample you brought me earlier.',
    `RequestItemsText` = 'You''re disturbing my work. That is, unless, you have those materials I asked you to acquire?'
WHERE `entry` = 40868;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Master Chemist Volterwhite looks upon the Volatile Aqua with a look of determination, beginning the synthesizing process at once.>$B$BStep back, this should only take a moment.$B$B<A smirk spreads across the gnome''s face.>$B$BIt would appear that my theorizing has been succesful, for I have been able to replicate my design and expunge the radiation from the nominal air in my samples!$B$BWith your help my theory has been put to the test, and without that I am unsure where we would be. Now the real work can begin.$B$BFor your help, I have prepared a gift. Pick one, and may it serve you well.',
    `RequestItemsText` = 'My work is almost complete, we are on the precipice of a great breakthrough here.'
WHERE `entry` = 40869;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done it. With this Hyjalroot I will be able to bring Paranus back from the edge, and guide him away from the dream. I must thank you $C. Without you, I would have been lost in grief.$B$BTake this Small Dream Shard, as thanks for everything you''ve done.',
    `RequestItemsText` = 'Paranus has a strong will, but it is only a matter of time before his strength is eroded.'
WHERE `entry` = 40870;

UPDATE `quest_template` SET
    `OfferRewardText` = 'More for my stockpile! Thank you again for your efforts $C. Please, once again, take this Small Dream Shard as a token of my thanks.',
    `RequestItemsText` = 'Have you returned with the Hyjalroot?'
WHERE `entry` = 40871;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is said to be lucky to have gained the confidence of the wildlife around the World Tree.',
    `RequestItemsText` = 'So, have you made your choice?'
WHERE `entry` = 40872;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I must warn you, use this recipe wisely. A misuse of the materials can create the counter opposite of the Dreamshard Elixir.$B$BI suggest you follow this recipe closely.',
    `RequestItemsText` = 'So, have you made your choice?'
WHERE `entry` = 40873;

UPDATE `quest_template` SET
    `OfferRewardText` = 'One sip, and you will remain awake, even from some powerful forces that draw you to slumber.$B$BI advise you not to overuse the Lucidity Potion, a known few have been known to go mad from the lack of sleep.',
    `RequestItemsText` = 'So, have you made your choice?'
WHERE `entry` = 40874;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A wise decision $C. I would recommend using these smelling salts with care. They are extremely strong and should not be used for any sort of practical joking.',
    `RequestItemsText` = 'So, have you made your choice?'
WHERE `entry` = 40875;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The creation of the Horn of Binding shall finally begin, in no small part thanks to your courageous and selfless efforts, $N. It will no doubt take me many days, or even weeks, to read through this old book and remember the steps necessary to finish this ordeal.$B$BI must thank you for what you have done for me. Please, take these items. They are tokens of my time spent in Hyjal, many long years ago... May they serve you better than collecting dust here with me at Starfall Village.',
    `RequestItemsText` = 'These materials will be dangerous to obtain, so I implore you to use caution when searching for them.'
WHERE `entry` = 40876;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What? That mindless rotbrain thinks I got lost?$B$B<Orvan chuckles darkly>$B$BHow amusing. One less pathetic cur to deal with. As you can see, I am perfectly capable of taking care of myself. But it seems fate has brought you here, and I must admit, I have a need for a servant. And you, my dear, look like a perfect specimen for the job.',
    `RequestItemsText` = 'What?'
WHERE `entry` = 40877;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, excellent. You have brought me what I needed.$B$B<Orvan takes the vials, inspects them with a sinister smile and abruptly tosses them behind him.>$B$BThese will be invaluable, truly invaluable.',
    `RequestItemsText` = 'Have you collected the blood already? I need ten full vials.'
WHERE `entry` = 40878;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It seems that not all of the Scourge forces were eradicated, but I must commend you for your work nonetheless. Your efforts have weakened their hold on this land and that will have to be enough for now. We cannot afford to underestimate our enemies, especially not the Scourge. They are a relentless force, serving their vile Lich King until the end.$B$BSpeaking of which, what became of the commander of the Scourge invasion here, I wonder? Was he defeated, or is he in hiding, waiting for the Lich King''s command to resume his invasion of Gilneas?',
    `RequestItemsText` = 'What are you waiting for? Root them out, destroy them utterly. Their presence here is an affront to the Forsaken and a threat to our operations.'
WHERE `entry` = 40879;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now that is impressive. Let us see how this blood will react with my concoction. If my calculations are correct...',
    `RequestItemsText` = 'Be quick about it, my servant.'
WHERE `entry` = 40880;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, finally! After all the obstacles and setbacks, I have obtained Ur''s masterpiece. The secrets of blood magic, and the power to control the very essence of life itself! With this book, I will be unstoppable, and the enemies of the Forsaken will tremble before me.$B$B<The Forsaken flips through the pages, cackling with excitement.>$B$BIt is clear that Ur was a master of his craft. But even he did not fully comprehend the true potential of blood magic. With the knowledge contained in this tome, I will surpass him and become the greatest bloodmage the world has ever known.$B$B<The Forsaken looks up with a wicked grin.>$B$BYou have served me well, my faithful minion. And for that, I will grant you a small taste of the power we will soon wield.',
    `RequestItemsText` = 'Has everything I''ve done been in vain?'
WHERE `entry` = 40881;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So Orvan was successful after all. Great. You have done a great favor to the Forsaken and to the Horde this day, so you shall be rewarded. Take this vial, my friend. It contains a potent concoction that will enhance your strength simply by breathing in its fumes. Of course, there may be some minor side effects, such as headaches, vomiting, madness, or even death, but I''m sure you''ll be fine. After all, what is a little risk compared to the power it can provide?',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40882;

UPDATE `quest_template` SET
    `OfferRewardText` = 'May this enchantment be a boon to you and your allies. Its power may just turn the tide in a difficult conflict.',
    `RequestItemsText` = 'So, have you made your choice?'
WHERE `entry` = 40883;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The properties of deflection are well known to us here. I am certain you will make good use it.',
    `RequestItemsText` = 'So, have you made your choice?'
WHERE `entry` = 40884;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The effects of this mixture are intense, pace yourself.',
    `RequestItemsText` = 'I am afraid I cannot offer you our Dreamtonic recipe to be crafted independently. It was discovered by one that is no longer with us, and I do not have their permission to share such secrets to outsiders.$B$BI can however, offer Dreamtonic that was created by myself in exchange for your efforts here in Hyjal. Bring me a single Small Dream Shard in exchange for a single Dreamtonic. That should be a fair trade.'
WHERE `entry` = 40885;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now then, this is the book that should teach you all that you need to know. Study it carefully, and apply the techniques as written in the text.',
    `RequestItemsText` = 'Have you brought the Dream Shards adventurer?'
WHERE `entry` = 40886;

