    `OfferRewardText` = 'I remember the day I first learned to craft and create Dreamsteel, it was a most rewarding experience.$B$BMay this recipe serve you well, $N.',
    `RequestItemsText` = 'Have you brought the Dream Shards adventurer?'
WHERE `entry` = 40888;

