    `OfferRewardText` = 'I remember the day I first learned to craft and create Dreamsteel, it was a most rewarding experience.$B$BMay this recipe serve you well, $N.',
    `RequestItemsText` = 'Have you brought the Dream Shards adventurer?'
WHERE `entry` = 40890;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I can feel a weight leaving my shoulders knowing justice has been brought after so much horror. I have no doubt in my mind his most loyal allies fought and died alongside him.$B$BWords enough cannot express my thanks to you. Please, take these items as a token of appreciation from myself.',
    `RequestItemsText` = 'I would advise caution, Barkskin Village is a place of great hostility and skilled ursa.'
WHERE `entry` = 40891;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It eases an old mind to know such murderers have met their end, and paid for their actions. I wish I could have seen it myself.$B$BFor your efforts, I offer you one Bright Dream Shard, once highly valued amongst my kind. May you find some use for it.',
    `RequestItemsText` = 'The ursa should not be taken easily $C. Take your time, and prepare for the coming battle with diligence.'
WHERE `entry` = 40892;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Nargg is pleased, Nargg is happy.$B$BA fire still burns deep within, anger not sated. Take this, as thanks from Nargg.',
    `RequestItemsText` = 'You do what Nargg ask, you bring death to evil Barkskin?'
WHERE `entry` = 40893;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Nargg is pleased, Nargg is happy.$B$BA fire still burns deep within, anger not sated. Take this, as thanks from Nargg.',
    `RequestItemsText` = 'Nargg still seeks vengeance upon the Barkskin for what they have done. Barkskin slayed many friends of Nargg, and must pay!$B$BTribe no longer what it was, it angry, and it evil. Nargg ask you to do what Nargg cannot do. Slay Barkskin and reclaim Barkskin Pendants, they can be found on any Barkskin Furbolg.'
WHERE `entry` = 40894;

