UPDATE `quest_template` SET
    `OfferRewardText` = 'I remember the day I first learned to craft and create Dreamthread, it was a most rewarding experience.$B$BMay this recipe serve you well, $N.',
    `RequestItemsText` = 'Have you brought the Dream Shards adventurer?'
WHERE `entry` = 40904;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I have not seen such an intact Dream Essence in such a long time. I had once thought all traces of it on Azeroth had been expunged, but I am proven wrong.$B$BCorruption is deep within this sample, though withering. It would not be hard to purify it.',
    `RequestItemsText` = 'What is this you have brought me?'
WHERE `entry` = 40905;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is done, the Dream Essence is purified and awaiting your embrace.$B$BNot all druids ever get the opportunity to wield such magic. Use it sparingly, and with great care, young one.',
    `RequestItemsText` = 'Have the materials been collected fellow druid?'
WHERE `entry` = 40906;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It has been many a moon since I heard the Widows take such a damning interest in a young man like this. A fate I do not envy. We, the Pellars, faithfully serve the good folk of this land. I will lend my knowledge if you will only listen.',
    `RequestItemsText` = 'I see discouragement and concern on your face, $N. What ails you so?'
WHERE `entry` = 40907;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I... I haven''t felt the chill of death in over an hour... I... I think it worked. By all that is holy, I think it worked! Thank you so much! My life is my own once more.',
    `RequestItemsText` = 'H...have you... succeeded?'
WHERE `entry` = 40908;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I am impressed, you have returned from the depths of Barkskin Village and done as I asked.$B$BHere, as thanks, please take this Bright Dream Shard, as well as this armor.',
    `RequestItemsText` = 'Have you killed my corrupt brethren?'
WHERE `entry` = 40909;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Vaenar looks upon the Dream Shards, lost for a moment.>$B$BYou''ve done well, I am true to my word. Take this Sigil, and may its power prove useful to you.',
    `RequestItemsText` = 'Have you brought the Dream Shards adventurer?'
WHERE `entry` = 40910;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Vaenar looks upon the Dream Shards, lost for a moment.>$B$BYou''ve done well, I am true to my word. Take this Sigil, and may its power prove useful to you.',
    `RequestItemsText` = 'Have you brought the Dream Shards adventurer?'
WHERE `entry` = 40911;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Vaenar looks upon the Dream Shards, lost for a moment.>$B$BYou''ve done well, I am true to my word. Take this Sigil, and may its power prove useful to you.',
    `RequestItemsText` = 'Have you brought the Dream Shards adventurer?'
WHERE `entry` = 40912;

UPDATE `quest_template` SET
    `OfferRewardText` = 'As I have promised, here is the expertise I have learned over the years.$B$BTake time to study and practice. Dedication requires patience after all.',
    `RequestItemsText` = 'Have you brought the Dream Shards adventurer?'
WHERE `entry` = 40913;

UPDATE `quest_template` SET
    `OfferRewardText` = '<A familiar voice penetrates your mind.>$B$BGood, you have made it. The sender of this letter has already failed me. Perhaps you will not.',
    `RequestItemsText` = '<Silence.>'
WHERE `entry` = 40914;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good...',
    `RequestItemsText` = 'You return.'
WHERE `entry` = 40917;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This potion will preserve and reawaken the power of the eye. It seems you have not doomed this quest after all.',
    `RequestItemsText` = 'You return.'
WHERE `entry` = 40918;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now this is a surprise, indeed. Good.',
    `RequestItemsText` = 'You return.'
WHERE `entry` = 40919;

UPDATE `quest_template` SET
    `OfferRewardText` = 'With these, I can amend the focus. Soon, the crystal shall brim with the raw power it once did...',
    `RequestItemsText` = 'You return.'
WHERE `entry` = 40920;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It seems the time has come, then? The crystal is complete...',
    `RequestItemsText` = 'You return for the last time, yes?'
WHERE `entry` = 40921;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You actually impress me, $N. Very well. From this day forth, you will walk this land as a mortal.',
    `RequestItemsText` = 'What is your decision? Think carefully, this cannot be undone.'
WHERE `entry` = 40922;

UPDATE `quest_template` SET
    `OfferRewardText` = '<The mailbox opens. A rather magnificent pendant falls forth, before the mailbox shuts with a deathly clatter.>$B$BMay this help with your fated future journey. Leave now. I have things to do and places to be.$B$B<Your connection with the mailbox is severed... permanently.>',
    `RequestItemsText` = 'A rare kindness.'
WHERE `entry` = 40923;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Baron Caliban Silverlaine looks at the signet with a smile gracing his features. Without a second word, the ring is slid upon his finger.>$B$BYou have done well, it is untarnished. It feels good to know this officer had his life claimed for such a crime.$B$BI have prepared a reward for you, thanks again adventurer.',
    `RequestItemsText` = 'Do not take your task lightly $C, Dryrock Pit is one of their most vital operations in the region and it will be under heavy guard.'
WHERE `entry` = 40924;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My, would you look at this. Such an intricate and complex silk.$B$BIt will surely be worth its cost when the creation of my new garments are complete.$B$BOh, yes I was to pay you, wasn''t I? Take this silver, and move along, would you.',
    `RequestItemsText` = 'I am not paying you to waste time you know.'
WHERE `entry` = 40925;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your efforts will better the realm in time. The less worgen that stalk our forests, the faster we can return to a state of peace.',
    `RequestItemsText` = 'Have the worgen been culled?'
WHERE `entry` = 40926;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well $N. It will only be a matter of time before the Bloodclaw tears itself apart as they struggle to establish new chains of command.$B$BYour duty to the people of Gilneas will not go unrewarded. Please, take one of these items as a thanks for everything you have done.',
    `RequestItemsText` = 'Be prepared for the task ahead.$B$BI would advise to bring some assistance. Assaulting a worgen den is no easy task.'
WHERE `entry` = 40927;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Fewer gnolls that prowl the countryside is better for any that call Gilneas home.$B$BThank you for your hard work $C.',
    `RequestItemsText` = 'Have you completed your task $C?'
WHERE `entry` = 40928;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oil to Gilneas? Hasn''t that place been sealed shut for years now?',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40929;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmm, it has been some time since I last laid eyes on this drum, but I think this is it.',
    `RequestItemsText` = 'Have you recovered the oil?'
WHERE `entry` = 40930;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Relief. I can say with certainty that I now feel an emotion besides fear.$B$BI was cursed long ago to forever tend to this fire. Should the flame ever extinguish, I would vanish forever from this world. I cannot properly describe the fear I feel about what would happen should the flame go out. Whilst I am bound to this spiritual form, I dare not think what comes after; it is the unknown that I truly dread.$B$BI would give anything to suffer as I am now than to drift away forever, forgotten for all time.',
    `RequestItemsText` = 'So, this is the oil from Theramore?'
WHERE `entry` = 40931;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, this is splendid, now I will be able to make pace to Shademore Tavern!',
    `RequestItemsText` = 'Have you gotten my spare wheel?'
WHERE `entry` = 40932;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Donald sent you?$B$B<A wave of relief washes over the woman, who sighs out a deep exhale.>$B$BThese words have brought me extreme relief. I was prepared for the worst. I told him to come with me, but he was stubborn to look after that plantation until things got unbearable.$B$BThanks for this news stranger, please, take this.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40933;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, it would appear that you are indeed not corrupted by the shadow.',
    `RequestItemsText` = 'Have you dealt holy retribution?'
WHERE `entry` = 40934;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I cannot believe the words that I am hearing, such practices among the leaders of my people? Me and others have long been wary of such allegations, but to know it to be true...$B$BI will have to convene with the others to decide our future. I thank you greatly. Please, take this, as thanks from myself and those that I represent.',
    `RequestItemsText` = 'So, what is it you have uncovered within my homeland?'
WHERE `entry` = 40935;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Gethenor takes his time, going through the missing supplies.>$B$BThat is a relief, it is all here. I was afraid our rare medical supplies and tinctures would have been destroyed in the rough transit to the camp.$B$BI must thank you greatly for your work. We have been heavily reliant on these supplies. Please, take this, as thanks from us here.',
    `RequestItemsText` = 'It is only a matter of time until our supplies are spoiled by the vile hands of the worgen who ran off with them.'
WHERE `entry` = 40936;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These shackles hold some sort of power channeled only by the worgen.$B$BYou have done well in thinning their numbers, but there is still more than we can combat.',
    `RequestItemsText` = 'Each moment wasted is another moment the Nighthowl bide their strength.'
WHERE `entry` = 40937;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have scattered the Nighthowl with this move. I suspect their attacks on us will cease as infighting begins to establish new leaders for their tribe.$B$BYou have done us a good favor $C, and for that you shall be rewarded.',
    `RequestItemsText` = 'The Alpha are a cunning foe, plot your moves and prepare for a challenge.'
WHERE `entry` = 40938;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, I am impressed. These fresh cuts of meat will surely go a long way in easing the rumbling of stomachs. I will make sure this gets to our most desperate first.$B$BThanks again for what you''ve done, take this, as a token for keeping us alive just a bit longer.',
    `RequestItemsText` = 'Have you had any luck finding food for us adventurer?'
WHERE `entry` = 40939;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Every time I interact with draconic magic, I am awed by the sheer power it possesses.$B$BTruly, we mortals cannot hope to compare to the power of our draconic rivals.',
    `RequestItemsText` = 'Has the Font been recovered?'
WHERE `entry` = 40940;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now then, let us see what the Font of Arcana can expose as truth.',
    `RequestItemsText` = 'The Arcane Font pocesses great power that cannot be wielded by magic alone.'
WHERE `entry` = 40941;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Magus Orelius takes a moment, channeling the energy of the Potent Draconic Jewel with the Font of Arcana. Within time, he would let out a loud and heavy sigh.>$B$BIt''s as I had feared, my theories are proven correct. Lord Prestor may perhaps have been a dragon in disguise all along. I am certain those who have come to replace him are aswell.$B$BThe Harlow''s are a noble family which rose to prominence around the time Prestor had arrived in Gilneas, and it is that same group that lords over the city itself. Lady Celia and Lord Mortimer are Regents of King Greymane, and act on his behalf.$B$BThe grip of the Black Dragonflight is deep within Gilneas, and it would appear they have long been working to bring this feud about. The death of innocents, and the corruption of this land is all on their hands. They must be stopped.',
    `RequestItemsText` = 'Once this Draconic Jewel is recovered, I can ascertain the true magic.'
WHERE `entry` = 40942;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The people will not know of your work here today, but their suffering will end. The draconic influence over Gilneas has been put to rest.$B$BIt is only a matter of time until the land is restored to what it was some years ago, and this is in part thanks to your efforts here today. I have convened with the other members of the Kirin Tor, and your work to banish the foul draconic magic will not go unrewarded.$B$BPlease, take one of these items, as a gesture of our appreciation.',
    `RequestItemsText` = 'Has their work been undone?'
WHERE `entry` = 40943;

UPDATE `quest_template` SET
    `OfferRewardText` = 'An outsider has come? It would appear the opening of the Greymane Wall has indeed brought new allies.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40944;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I was expecting to feel some sort of relief, but in truth I don''t feel much of anything. You have done me a great service, and for that I am in your thanks.$B$BPerhaps soon I will find solace from the dark days ahead. Please, take this, I shall not be needing it any longer.',
    `RequestItemsText` = '<Maxwell is lost in thought.>'
WHERE `entry` = 40945;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, you do have a backbone, do ye? You may have thinned their ranks, but there is still more to do.',
    `RequestItemsText` = 'You better not be bothering me.'
WHERE `entry` = 40946;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Huh, you''ve done it? Well why didn''t you say that $C! You''ve done and gone real heroes work out here, and in Gilneas that is a rarity.$B$BHere, as a token of my thanks and from all of us that work down here, take this. It might serve you better than it would myself.',
    `RequestItemsText` = 'You better not be bothering me.'
WHERE `entry` = 40947;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I have not been forgotten, it seems.$B$BTo you I say: well met, one from beyond the wall. I have imagined this encounter several times in my head only to be at a loss for words now. You are here to free me, no?',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40948;

UPDATE `quest_template` SET
    `OfferRewardText` = 'He did not deserve the mercy of a quick death.$B$B<Liam chuckles.>$B$BPerhaps the weeks spent in this hole are making me question my integrity as a follower of the Light. I have brought shame to my teacher.',
    `RequestItemsText` = 'I wish we had the time to spare a few more words but we really must hurry.'
WHERE `entry` = 40949;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A foreigner, here of all places. Liam sent you? Ah, then my brother is safe. We were just about to go save him.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40950;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My little sister... a gift from the Light.$B$B<Liam chuckles and nods.>$B$BMay we find wisdom in our own actions then?',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40951;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, it was the prince that visited us on his way to Ravenshire? I didn''t take him for royalty.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40952;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I was skeptical of your aid, but it seems that I have doubted you for naught. Well done.',
    `RequestItemsText` = 'You cannot even begin to understand how much power resides in the blood.'
WHERE `entry` = 40953;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Darius is a strongheaded man. He will understand the necessity of this alliance.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40954;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your actions have severely weakened the abilities of the Greymane in the eastern parts of the region. I must give my thanks for your work.$B$BNow we can focus our attentions on the final matters.',
    `RequestItemsText` = 'Has the operation been complete?'
WHERE `entry` = 40955;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The end of an era is upon us. A darkness has been lifted on this day, and with it, a new hope emerges from the clouds. A ray of light for all to see. Liam Greymane shall be named king and his reign shall bring prosperity to the people who have suffered for so long!$B$B<His eyes shine with hope, for perhaps the first time in a generation.>',
    `RequestItemsText` = 'Be brave adventurer, the city itself has struggled through civil strife as we have.'
WHERE `entry` = 40956;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So now you know. Solnius must be stopped.',
    `RequestItemsText` = 'The Emerald Dream is in danger.'
WHERE `entry` = 40957;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You bear the effigies in your hands, yet I see no signs of corruption within you.$B$B<Ralathius exhales, relieved.>$B$BI see the enemy in every shadow, and it''s taking a toll on me. I am sorry for my initial distrust, but I have to take these steps. Now, please, hand these effigies to me.',
    `RequestItemsText` = 'While it is with a heavy heart that I bear this burden of caution and mistrust, the threat of the enemy lurks in every shadow, ready to exploit any weakness or vulnerability.'
WHERE `entry` = 40958;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What do you want, mortal? What brought you to this forsaken place?$B$BWait... I sense an aura of the Dream from you.',
    `RequestItemsText` = 'What is it?'
WHERE `entry` = 40959;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have my deepest gratitude for gathering the materials I''ve asked you for. With the collected items and Itharius''s benevolent blessing, we are now ready to peer into the realm of the Dream and attune you to its potent energies.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40960;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Lady Ysera... we will not fail you. We will not fail the Emerald Dream.',
    `RequestItemsText` = 'The Emerald Dream is in danger.'
WHERE `entry` = 40961;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Larannikus has met his demise, and you have successfully retrieved the Charge of Ysera. With this significant accomplishment, you are now prepared to undergo the attunement process to the Emerald Dream. Remain still, mortal, as I bestow upon you the Gift of Ysera.',
    `RequestItemsText` = 'Is Larannikus dead?'
WHERE `entry` = 40962;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done it. The Awakening has been stopped.$B$BI will contact Ysera now. She must know.$B$BPlease, take this item as a token of gratitude from the Green Dragonflight.',
    `RequestItemsText` = 'What is it, mortal? You return from the Dream?'
WHERE `entry` = 40963;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, so Danmere has sent you our way, eh? Well, as you can clearly observe, the situation here is far from ideal. We are in dire need of assistance, and any help you can offer will be greatly appreciated. Welcome to the frontlines of the struggle.$B$BIn order to get properly acquainted with our operations, I suggest introducing yourself to two key figures in our ranks. Darius Ravenwood and Caliban Silverlaine are the stalwart leaders orchestrating our resistance against the Harlow forces. You will typically find them at the town hall, tirelessly strategizing and planning our next moves. Waste no time in seeking them out and informing them of your arrival. They will undoubtedly appreciate your presence and may have specific tasks or assignments to entrust you with.',
    `RequestItemsText` = 'A new face. Welcome to Gilneas.'
WHERE `entry` = 40964;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, ain''t you a sight for sore eyes, stranger! You''ve done some mighty fine work for our cause, and I reckon we owe you a debt of gratitude.',
    `RequestItemsText` = 'Ah, the thrill of the hunt.'
WHERE `entry` = 40965;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I commend your stellar work. With the Deed once again safely back in my possession, any troublemakers who dare challenge my rule shall be forced to reconsider their actions. The return of this document serves as a powerful deterrent, casting doubt upon the audacity of those who would question our authority.$B$BThough the path ahead may be arduous, we shall not waver in our commitment to rebuilding Gilneas. We have a long and challenging journey before us, but with each passing day, we will labor tirelessly to restore our beloved homeland to its rightful place of glory and splendor.',
    `RequestItemsText` = 'The Deed to Ravenshire must be reclaimed.'
WHERE `entry` = 40966;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Darius Ravenwood sighs with relief.>$B$BThe knowledge that my soldiers and servants no longer wander this world, tormented by the dark magic of the Harlows, brings me great peace. In their name, I express my deepest gratitude. Please, accept this token as a symbol of my appreciation as well as theirs.',
    `RequestItemsText` = 'Ravenwood Keep... my home.'
WHERE `entry` = 40967;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So the promised aid finally arrives.$B$BGenn Greymane''s profound lack of trust in the Alliance was undoubtedly one of his gravest misjudgments. Though I can appreciate his reasoning behind such a decision, I could never fully endorse it. However, that is all in the past now, and dwelling on it serves no purpose.$B$BI extend my warmest welcome to you and the formidable might of the Alliance. Ravenshire may be a modest town, but it holds the flame of resilience and hope that will ignite the rekindling of our beloved Gilneas. In due time, we shall extend our hospitality and invite you to partake in a grand feast within the walls of Gilneas City itself. But before we can revel in such festivities, there is much work to be done.',
    `RequestItemsText` = 'I haven''t seen you here before.'
WHERE `entry` = 40968;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So the rumors are true. Gilneas is once again open for business.',
    `RequestItemsText` = 'What do you want?'
WHERE `entry` = 40969;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Whoa there, pal! I gotta say, I didn''t expect you to make it outta there in one piece. You''re a real survivor, I''ll give ya that! So, you''re tellin'' me the mine''s clear of them nasty basilisks? Well, ain''t that splendid news! I''ll have a mining team dispatched there pronto!$B$BNow, about that ore you managed to snag, I''ll need ya to hand it over. Don''t worry, I''ll package it all up real nice and attach a fancy note for Todd. Long time no see, right? I''m sure he''ll be thrilled to get a package from me.',
    `RequestItemsText` = 'Well, I told you already. You need to clear the mine.'
WHERE `entry` = 40970;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I can hardly believe my own eyes! Crystalvein ore, just as I remembered it. This is a treasure indeed. I can already envision the magnificent weapons I''ll forge from this exquisite batch.$B$BLarry! Fire up the forge, lad! It''s time to showcase the true artistry that can be achieved with these precious ores. We shall create masterpieces that will leave tongues wagging in awe and envy.$B$BOh, where are my manners? I apologize. Allow me to express my profound gratitude for your efforts. Here, accept this piece as a token of my appreciation. It''s one of my finest works, crafted with the utmost care and skill. May it serve you well, my friend, as a testament to our collaboration.$B$BNow, let''s get to work, shall we?',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40971;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So now you know. I left many details out, but there''s no time for chatting. We must act now, with the newfound strength of our allies.',
    `RequestItemsText` = 'The situation in Gilneas is dire.'
WHERE `entry` = 40972;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent work, the harmonization process does not take me long, especially with all this practice, if you find any more, come and let me know.',
    `RequestItemsText` = 'We must all do our part here in Hyjal, and my part is to harmonize Small Dream Shards into Bright Dream Shards. The harmonization process makes the shards much more potent in regards to their magical properties. If you require a large amount of Bright Dream Shards, simply let me know.$B$BI will require fifteen in order to create five Bright Dream Shards.'
WHERE `entry` = 40973;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Dominic Larson has a smirk resting upon his face.>$B$BWell done. I must commend you for your efforts. You''ve defeated the beast that has cursed me with eternal undeath. Take one of these, as a token of my gratitude.',
    `RequestItemsText` = 'Has the deed been done $C?'
WHERE `entry` = 40974;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, I am at peace, once and for all.$B$BI can feel the nether claiming the lingering essence of my spirit. It is my time to go, and rest.$B$BI have left an item for you, as thanks for everything you have done.$B$B<The phantom begins to fade.>',
    `RequestItemsText` = '<A silence hangs on the ethereal wind.>'
WHERE `entry` = 40975;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, with the alphas scattered there will be struggles for dominance. Whatever comes of that is not our concern, however. We have already removed the head of the beast.$B$BYour efforts to serve the Dark Lady will not go unnoticed. Take this as a commendation for your work.',
    `RequestItemsText` = 'I advise you to carry yourself with caution.$B$BYour foe is not as weak as you may think.'
WHERE `entry` = 40976;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I feel like I can breathe again. These blasted vermin roam the forests in droves, at least now there are less of them about.',
    `RequestItemsText` = 'So, has the work been done?'
WHERE `entry` = 40977;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The worgen, defeated?$B$B<A wiry smirk crosses his features.>$B$BYou have done well, outsider.',
    `RequestItemsText` = 'Watch yourself during the night. Dark things are always lingering.'
WHERE `entry` = 40978;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve brought me peace, something I have been longing to have.$B$BWith this deed I can continue as I always have. I have prepared some rewards for you as thanks for returning my property.',
    `RequestItemsText` = 'So, what news do you have?'
WHERE `entry` = 40979;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, is this what revenge feels like?$B$BI must admit, I only feel an emptiness. The true killer is still out there, and must be found.',
    `RequestItemsText` = 'So, you''ve returned, have you dealt justice to those that murdered my brother?'
WHERE `entry` = 40980;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Harrison Blackheart takes the jewelry with soft hands, taking a moment to admire the beauty.>$B$BI must thank you for recovering this. It certainly does mean a lot to me.',
    `RequestItemsText` = 'Have you found the necklace?'
WHERE `entry` = 40981;

UPDATE `quest_template` SET
    `OfferRewardText` = '<With a nod of approval Harrison seems content.>$B$BYou''ve done a lot for me, and I am certainly grateful. I am sure Franklin is as well.$B$B<A heavy chuckle escapes Harrison.>$B$BTake one of these, as tribute from us.',
    `RequestItemsText` = 'Hmm, yes?'
WHERE `entry` = 40982;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmm, so the demonic presence at Darkwhisper Gorge is as I feared. It may only be a matter of time until they figure out a way past our barriers.',
    `RequestItemsText` = 'How may I assist you outsider?'
WHERE `entry` = 40983;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, I have already begun to prepare for the ritual.',
    `RequestItemsText` = 'Have the materials been acquired $C?'
WHERE `entry` = 40984;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I have uncovered the source of this magic. Satyrs have tainted the Runestone, and placed a curse upon it.$B$B<Buthok Cloudhorn lets out a sigh.>$B$BThis will take some considerable effort to fix.',
    `RequestItemsText` = '<Buthok Cloudhorn seems lost in the ritual.>'
WHERE `entry` = 40985;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Buthok Cloudhorn lets out a sigh of relief.>$B$BI feared that you would not return. I am happy my worries have not come true.',
    `RequestItemsText` = 'So, have you recovered what is required?'
WHERE `entry` = 40986;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This Imbued Stone holds considerable power, despite looking like an ordinary rock.',
    `RequestItemsText` = 'Has the work been completed $C?'
WHERE `entry` = 40987;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Buthok Cloudhorn inserts the Runestone Chunk back into place.>$B$BYou have done well, better than I ever had expected.',
    `RequestItemsText` = 'Have you tracked Xalthix?'
WHERE `entry` = 40988;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Glanthas the Ancient offers a long, and silent stare.>$B$BThe Runestone?',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40989;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Glanthas the Ancient lets out a creaking exhale of approval.>$B$BYou have done well in finding this. It eases my mind to know you have brought peace to Enthelar. He suffered great hardships, and I am sure he was relieved by your actions.$B$BAs I promised, you can now access the Runestones of Hyjal, offering transport between them. Use this power wisely, $C.$B$BFor your considerable efforts in restoring the Runestones I have prepared a suitable commendation.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 40990;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Unfathomable. Azothan artifact, now resting in my grasp.$B$B<Dark Bishop chuckles ominously>$B$BHow amusing it is to consider the reactions of our ancestors, witnessing their cherished relic held by a creature as abhorrent as I. Surely, they twist and turn in their eternal slumber, aghast at the sight.',
    `RequestItemsText` = 'Journey to Badlands is long. Get going.'
WHERE `entry` = 40991;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ha! Thanks to your unwavering efforts, our communication lines with the capital have been fortified, ensuring the safety of our operations in Gilneas. Your dedication to the cause of the Forsaken is commendable.$B$BAs a token of my gratitude, I offer you this. Though it may not be extravagant, it will undoubtedly prove useful in navigating the treacherous lands that lie before us.',
    `RequestItemsText` = 'Huge packs of Foulhide gnolls can be found in the Southmire Orchard. Their raiding parties have been spotted in Silverpine already. They must be stopped.'
WHERE `entry` = 40992;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Eye... Ah, yes. Its malevolent aura was unmistakable as you drew near.$B$BDraw nearer still. Through tireless research and countless tomes, I have unearthed a revelation of great intrigue. It appears that during the fabled Battle of Stillward, the first Greymane wielded an unfathomable darkness.$B$BNow, with the Eye of Xythos firmly in my grasp, I shall delve into the depths of time itself. I seek to unveil the true nature of this formidable power that we now confront.',
    `RequestItemsText` = 'Eye of Xythos is rumored to be in the possession of the Shadow Council in Desolace. I have caught wind of dark whispers that speak the name... Shadowbreak.'
WHERE `entry` = 40993;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, so you have found it after all.$B$BThe ravages of time have taken their toll upon the scepter, diminishing its former might. Yet, even in its weakened state, its aura pulsates with an undeniable darkness, a lingering remnant of forbidden magic.',
    `RequestItemsText` = 'Such power... It must be ours.'
WHERE `entry` = 40994;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your unwavering dedication continues to impress me, $C.$B$BYet, during your absence, I delved once more into the past, and it became clear that there is yet another task I must entrust to you.$B$BThe Scepter is still incomplete, lacking a crucial component I have missed earlier.',
    `RequestItemsText` = 'Act quickly, $C. For with each passing moment, his dark powers surge and his influence expands.'
WHERE `entry` = 40995;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, indeed! Behold, the Shard of Midnight, at last in my possession.$B$B<Dark Bishop meticulously adjusts the scepter, delicately affixing the crystal atop its pinnacle.>$B$BThe task is accomplished. The unholy forces once wielded by Garalon Greymane can be harnessed anew, but only by those who possess the fortitude to withstand their malevolence.$B$BThis endeavor is far above you and me. We have fulfilled our mission, and now we must deliver the Scepter to our superiors.',
    `RequestItemsText` = 'Gather a strong party before you venture forth.'
WHERE `entry` = 40996;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, behold, the Scepter in your grasp, delivered as expected.$B$B<Varimathras gazes at you with his piercing, demonic eyes>$B$BTruly, the latent darkness contained within shall prove indispensable to our grand cause. While it may take time for our adept warlocks to fully harness its potential, the rewards shall be manifold.$B$BIt amuses me greatly to witness the irony that the very forces that once shaped the foundation of Gilneas are now scorned and reviled by the feeble humans. It appears that wisdom has waned in their fledgling race over time.$B$BBut enough about them. I have not forgotten your contributions. Our meticulous Apothecaries have prepared a reward for your endeavors. Choose from this assortment, and claim your well-deserved prize.',
    `RequestItemsText` = 'I speak for the Dark Lady.'
WHERE `entry` = 40997;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Cooking notes. Well, I must admit I have had my fair share of meals here in Karazhan. I also spent much of my youth learning how to cook.$B$BYou certainly have come to the correct place.',
    `RequestItemsText` = 'Can I help you?'
WHERE `entry` = 40998;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, such a marvelous piece of work... I had forgotten just how extravagant it was.',
    `RequestItemsText` = 'Have you recovered my bracelet? It was a gift from my wife.'
WHERE `entry` = 40999;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Stratholme, destroyed? My family home burned?$B$B<Duke Rothlen lets out an exhale of disbelief.>$B$BSuch news brings emotions to my soul. I must thank you deeply for recovering this, for it is truly the final memento of my family.',
    `RequestItemsText` = 'Has the Rothlen Family Brooch been recovered?'
WHERE `entry` = 41000;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Le Fishe Au Chocolat, huh?',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 41001;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Welcome to Karazhan, what is it that I can assist you with?',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 41002;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your contributions have been recorded within my notebook. I would like to thank you for your continued support. As I have promised, I have prepared a Charge of Karazhan on your behalf.',
    `RequestItemsText` = 'Have the materials for your donation to the tower been acquired?'
WHERE `entry` = 41003;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very well, this Charge gives me authority to dispense with the information you request. I have prepared the recipe for you, and wrote down the instructions. May you find good use of this rare delicacy.',
    `RequestItemsText` = 'You have returned, have you had any luck?'
WHERE `entry` = 41004;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The effects of the tea are quite calming, be at ease with a few sips.',
    `RequestItemsText` = 'If you are looking for something a bit more relaxing, I have spent quite a few years mastering my recipe for herbal tea.$B$BI could brew you some for your efforts here in Hyjal. Bring me a single Small Dream Shard and I shall reward you with my famous tea.'
WHERE `entry` = 41005;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A taste of draconic magic can be intense for those not adept at it. Be careful in your use of this illusion.',
    `RequestItemsText` = 'Have you acquired the magical shards?'
WHERE `entry` = 41006;

UPDATE `quest_template` SET
    `OfferRewardText` = 'As I have promised, these Small Dream Shards contain a powerful magic, use them wisely.',
    `RequestItemsText` = 'My husband Vaenar and I have been looking to assist with the growing concerns in Hyjal. The rare material Fading Dream Fragment is becoming ever harder to come across, and before long there may be none of them left. If you bring me a Fading Dream Fragment I will be sure to reward you handsomely for your efforts.'
WHERE `entry` = 41007;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have proved yourself to Hyjal, and your reward is immense. Treat the stag of Nordrassil as you would a most loyal companion and they will show you the strength of nature.',
    `RequestItemsText` = 'So, have you made your choice?'
WHERE `entry` = 41008;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Danthar Oakmantle is a loyal friend to Moonglade, and one who has been tasked to guide you to us. Something stirs within the Emerald Dream, and it is now that we must unite together to defeat it.$B$BYou have done well, continue to do so, and perhaps we may finally have peace. Take this glyph, and let my powers flow through you.',
    `RequestItemsText` = '<The sharp gaze of the Great Cat Spirit is intimidating.>$B$BDo not be afraid, we are both on the same side.'
WHERE `entry` = 41009;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have made the journey to the top of Hyjal, and succeeded in your journey.$B$BSuch a road is full of danger, and your bravery is commendable. Something dark lingers within the Emerald Dream, even I can feel it, drawing at my will. We are all united in our efforts to support Hyjal, and as such, I have something that will reward your support.$B$BTake this glyph, and be transformed into one loyal to the Emerald Dream.',
    `RequestItemsText` = 'Danthar Oakmantle was tasked with guiding druids in Nordanaar to me. I can sense you are one such druid. Do you have proof of your deeds in Hyjal?'
WHERE `entry` = 41010;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Immense power contained in such a small token, draconic magic is certainly fascinating!',
    `RequestItemsText` = 'I have not had this much excitement in some time. Have you recovered the Dragonkin Charge?'
WHERE `entry` = 41011;

UPDATE `quest_template` SET
    `OfferRewardText` = 'We have only just begun, do not get excited.',
    `RequestItemsText` = 'Have the elements been acquired?'
WHERE `entry` = 41012;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Parnabus looks shocked by the power before him.>$B$BSo, it was true.',
    `RequestItemsText` = 'I can only imagine the power that is being expelled around Dire Maul.'
WHERE `entry` = 41013;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is done, the ritual is complete. This binding once came from near the tower of Karazhan. I have no doubt it once served a more grand cause, or was apart of an object with considerable power.$B$BI have no purpose for this binding any longer, and I offer it to you for whatever purpose you see fit. I wish you the best of luck in your cause $C.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 41014;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The upper and lower halves both. I would never have expected to see them together.$B$B<Hanvar takes a moment to gather himself.>$B$BThe bindings have been brought together, and now they are rejoined. I am cursed to forever protect these items, but it appears that you would have a better chance to carry out my charge.$B$BWatch over the binding, and make sure it does not fall into the hands of evil.',
    `RequestItemsText` = 'Once the binding is restored I will be brought peace.$B$BIt is up to you to recover both halves.'
WHERE `entry` = 41015;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I could never imagine such a betrayal, it struck me so deep that I do not even wish to recall the memories.$B$BI thank you for putting this traitor to death. Without your interferance I fear what Alzzin may have accomplished. Please, take this, as a gesture of my extreme thanks.',
    `RequestItemsText` = 'Has that foul beast been brought to justice?'
WHERE `entry` = 41016;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, such a task will not be forgotten. For each satyr that has fallen there shall be one less for when the time truly comes.$B$BThis battle for Hyjal is dependant on such heroic actions. Take this Bright Dream Shard, as thanks from us.',
    `RequestItemsText` = 'The satyr were once much like us, and now they stalk from the shadows and undermine our efforts.'
WHERE `entry` = 41017;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Dark magic lingers deep in these shards, it is good that you have recovered them before it was too late.$B$BTake this, as thanks for recovering these from the brink of destruction. If you find any more, bring them to me.',
    `RequestItemsText` = 'Dream Shards are a resonation of magical energy from the Emerald Dream made manifest here in Hyjal. They contain a very powerful energy that, when manipulated, can be used for darker purposes. The Burning Legion have been collecting them and corrupting them for their nefarious purposes.$B$BHunt down the demons still present in Hyjal, and collect these Corrupt Dream Shards, bring them to me so that they can be restored.'
WHERE `entry` = 41018;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well. Such actions ensure our safety here in Nordanaar. Nordrassil Glade must be kept as a safe haven, not threatened by the evil whims of maddened trolls.$B$BTake this Small Dream Shard, as thanks from us here.',
    `RequestItemsText` = 'The Shadeflayer trolls have taken a stance of hostility towards us in Hyjal. They were once called the Shadowtooth Tribe, and valiantly fought alongside us against the Burning Legion.$B$BSuch times are now long gone, as corruption has taken hold of even those we held as allies. I task you to travel to Zul''Hatha where they call home to the west, slay them, and procure 10 Shadeflayer Tribal Bracelets. Bring these bracelets to me and you will be rewarded.'
WHERE `entry` = 41019;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Heart of Xanvarak, such foul power can be felt emitting from his life-blood. Your efforts in defending Hyjal have been paramount. With Xanvarak destroyed, it will be some time before the demons can rally behind a new leader.$B$BYou have brought us peace, for however long that may last. Such an achievement is worthy of a reward most sacred.',
    `RequestItemsText` = 'The power of the Burning Legion should not be taken lightly. Bring your own host of would-be adventurers, or mercenaries to challenge Xanvarak''s strength.'
WHERE `entry` = 41020;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Such grim tasks are required for the betterment of nature in Hyjal. If we do not act, the animals in Hyjal will be reduced to aggressive and hostile beasts, perhaps even slaves to the legion.$B$BTake this Dream Shard, as thanks on my behalf.',
    `RequestItemsText` = 'The effects of the Third War are still present in Hyjal. Demonic corruption lingers upon the land and has touched the wildlife of the region, driving it to madness. There is still hope, however. If we can preserve the younger generations and remove the corruption of their kind, there is still a chance for the majestic animals native here to thrive.$B$BWe must act as conservationists for the sake of nature''s creatures. Bring me ten Great Beaks from the Greathorn Owls, and ten Misthoof Hide from the Misthoof Stags. For your efforts, I will reward you a Bright Dream Shard.'
WHERE `entry` = 41021;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, the lands are safer thanks to your efforts. Though I still have many questions about where these creatures have come from.',
    `RequestItemsText` = 'Be careful, these monstrosities have no value for life.'
WHERE `entry` = 41022;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Farana Leafblade has sent you? Such a fine warrior, she is as dedicated to this land as I am.$B$B<Glanthas takes the sample, studying it carefully.>$B$BSuch a foul material, contaminated with magical energies.',
    `RequestItemsText` = 'Yes, can I help you?'
WHERE `entry` = 41023;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Glanthas has sent you to find me?$B$B<Canos takes a moment, looking over the sludge.>$B$BIt would appear some sort of magical properties remain in this sludge, but I take it Glanthas has already gleamed this information.',
    `RequestItemsText` = 'Can I assist you?'
WHERE `entry` = 41024;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A trace of magic.$B$B<A sigh escapes Canos.>$B$BI was beginning to doubt myself.',
    `RequestItemsText` = 'I have been searching for quite some time to find a magical linking. Maybe you will have better luck than I.'
WHERE `entry` = 41025;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My, Canos has put in an impressive amount of work in his research. It is not conclusive, but I am sure he is on the right footing. A magical feedback, or remnant certainly is an interesting theory, and one that will need to be looked into further.$B$BYour assistance in this matter has been emphasized by Glanthas himself, one I hold with the deepest of respects. Take this, as a token of our thanks here in Hyjal.',
    `RequestItemsText` = 'Can I help you?'
WHERE `entry` = 41026;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Fang of Loresh, returned to me, but it is worse than I had feared. Dark magic has already festered deep within the relic. There is no wonder why the Loresh''s spirit has gone mad.',
    `RequestItemsText` = 'Fabricate a plan, and put it in motion. Use cunning and skill to achieve your goals $C.'
WHERE `entry` = 41027;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You are resourceful.$B$BThere is one final thing we must do before I can begin to purify the spirit of Loresh.',
    `RequestItemsText` = '<The Great Cat Spirit stares with intensity.>'
WHERE `entry` = 41028;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Loresh''s spirit is one step closer to freedom. The foul magic that entrapped him was no match for your speed and skill.',
    `RequestItemsText` = 'Be vigilant, and direct with your approach. Do not let the dark magic cow you into submission.'
WHERE `entry` = 41029;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is done, Loresh has been freed from dark magic. You have succeeded in what was asked, and for that, you shall be rewarded.$B$BTake this Gift of Ferocity, and use it for the greater good of all nature.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 41030;

UPDATE `quest_template` SET
    `OfferRewardText` = 'As I have promised, The Gift of Ferocity.$B$BUse it wisely, and your enemies will tremble before your might!',
    `RequestItemsText` = 'Have the shards been acquired?'
WHERE `entry` = 41031;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So you return! With the venom in hand! Greeted by the snarl of an old woman--I mean a smile of course.$B$BTake this coin, as thanks for the work.',
    `RequestItemsText` = 'The transformation is often a difficult process for some. There is a point of immense pain as the old skin tears away, and the worgen form is forced underneath. You must understand how painful that can be, and how some people do not have the inner strength to complete it.'
WHERE `entry` = 41032;

UPDATE `quest_template` SET
    `OfferRewardText` = 'With enough research, we may be able to uncover the properties of blood itself. This could be very important to Moranna, if our suspicions are correct.',
    `RequestItemsText` = 'Blood is quite intriguing indeed. It holds immense power, you know. Some of Ur''s research suggests that demons can be poisoned with a dead man''s blood. Fascinating, is it not?'
WHERE `entry` = 41033;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Look at that, an outlander with some mettle. We say that a man is not made until he has won his first hunt, but I can see this wasn''t your first.$B$BI can tolerate your foreign mug a little more. Now scurry.',
    `RequestItemsText` = 'The sacrament of the hunt is crucial in the order of nature. Death feeds life, which feeds death, which feeds life.$B$BThe circle is unbroken.'
WHERE `entry` = 41034;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A thousand and thousand thanks I lay upon you.$B$BMy family, my own blood, thought me sick with plague, thought me not worth the yoke. Now I am free to be Beckett no more.',
    `RequestItemsText` = 'Is it over, is it done? Is my nightmare gone?'
WHERE `entry` = 41035;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Once we are ready, I will place these items in a circle of salt, and light an incense of black roses to call the spirits forth.$B$BThough that day has not come, and will not for some time. You have done well, as I know you would have.',
    `RequestItemsText` = 'These tokens hold vestiges of who these revenants once were, what they once valued.$B$BWedding rings, a family sword, a lost one''s handkerchief could all become a tether from the realm of the dead to ours.'
WHERE `entry` = 41036;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ugly, crude, cheap. What else can you expect of gnoll-make?$B$BBut metal is metal, ''tis better in my hands than theirs. You have me thanks, this copper will make proper rods.',
    `RequestItemsText` = 'Won''t be much silver in the trinkets the gnolls use, but copper they seem to like just enough.'
WHERE `entry` = 41037;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Claw of Erennius.$B$BIt pains me to see the fall of a once noble hero to our cause. It would seem even the great Erennius was not safe from the lure and draw of the awakening. I take it the corruption sank deep into his heart, and turned him into an agent of evil.$B$BErennius is put to rest now, free from torment. I must thank you for what you''ve done. Take one of these relics, as a tribute for your heroism.',
    `RequestItemsText` = 'Can I help you?'
WHERE `entry` = 41038;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These meats will be crucial for our survival in this wilderness. Thank you, $C.',
    `RequestItemsText` = 'One shot, one kill.'
WHERE `entry` = 41039;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Swift and decisive, you have accomplished the task with remarkable efficiency. Your prowess in action speaks volumes, outsider.$B$BYour discernment in recognizing the importance of swift action and your aversion to idle chit-chat sets you apart. It is a trait we value greatly among our ranks. There are those, like Shandris, who may hesitate until the eleventh hour, and then... But let us not dwell on such matters for now.',
    `RequestItemsText` = 'This makes me wonder... have the gnolls always been there?'
WHERE `entry` = 41040;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Interesting. So, you''re telling me that their leader held possession of this artifact? Its aura carries the unmistakable taint of the Scourge. We must promptly inform someone of higher wisdom and authority to determine the appropriate course of action.',
    `RequestItemsText` = 'In bygone eras, when the Night Elves and Tauren were steadfast allies, the Grimtotem tribe was known for their penchant for trouble. They continuously sought independence from the Kaldorei, often at the expense of their own prosperity.$B$BNevertheless, I cannot deny my admiration for their combat prowess. Among the Tauren, they stood resolute against the Centaur onslaught and maintained a presence in remote mountain outposts, defying the odds. Their resilience and tenacity in the face of adversity is commendable.'
WHERE `entry` = 41041;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, the Scourge''s tainted weapon found among the Grimtotem? Not surprising at all. They have developed a peculiar fascination with undeath, even stooping so low as to collaborate with the Forsaken. But why the artifact ended up with those pathetic Grimtotem fools shouldn''t bother you. It''s just another testament to what the Horde truly stands for: death and destruction.$B$BThe world fractures further, the Second Sundering looms. Your involvement in this matter, however insignificant, is duly noted.$B$BConsider yourself dismissed.Here, take this token of appreciation for your feeble efforts.',
    `RequestItemsText` = 'What is it? You better have a good reason to interrupt me.'
WHERE `entry` = 41042;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very well, your assistance in retrieving the Tear of Zalmos is greatly appreciated. However, acquiring it is only the first step in a greater endeavor. Are you prepared to lend your aid once more?',
    `RequestItemsText` = 'Have you found it, $C?'
WHERE `entry` = 41043;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, so you seek the sacred artifact known as  Fang of Zalmos, do you? Indeed, we Pellars hold such relics within our grasp, for we have been entrusted with the guardianship of these ancient artifacts. For the Wolf-Serpent''s maws were many, each bite imbued with the strength of a thousand wolves.$B$BI must admit, the curiosity within me stirs at the thought of what a Druid from the western lands would desire with such a relic. However, I am but a humble servant of the ancient ways, and who am I to question the authority of one who predates me by millennia? If you aid me in a task, I shall grant you one of the revered  Fang of Zalmos.',
    `RequestItemsText` = 'What brings you here, my child?'
WHERE `entry` = 41044;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Splendid. With these supplies, we will be able to help those in need.',
    `RequestItemsText` = 'Wolf-Serpent watch over you.'
WHERE `entry` = 41045;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Interesting indeed. It is heartening to see that the humans have not forgotten the ancient powers that once resided in their lands. Your success in retrieving the Fang of Zalmos is commendable. However, our quest is not yet complete.$B$BThere is one more piece missing, one more relic that we must acquire.',
    `RequestItemsText` = 'You''re finally back. Have you managed to reclaim the Fang of Zalmos?'
WHERE `entry` = 41046;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, you seek my wisdom, do you? Few dare to venture into my domain, let alone seek an audience with me. Speak your purpose, but be mindful of your words, for I have little patience for idle chatter.$B$B<Cenerron''s gaze intensifies, his primal instincts ready to pounce at the slightest hint of deception or disrespect. His pack, hidden in the shadows, stirs restlessly, their feral energy palpable in the air.>$B$BRemember, mortal, the bond between man and nature is a delicate one. One misstep, and my pack will not hesitate to unleash their fury upon you. Now, state your intentions.',
    `RequestItemsText` = '<Cenerron, the feralkin, gazes at you with ancient eyes, his wild form blending seamlessly with the surrounding wilderness. The silence hangs heavy in the air as he carefully considers your presence.>'
WHERE `entry` = 41047;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The essence of the Wolf-Serpent before my eyes... Remarkable.$B$BI have tarried here long enough. The time has come to make my way back to Teldrassil, bearing the treasures you have procured. Fandral will be eager to learn of these developments, and I can already anticipate the satisfaction in his eyes.$B$BThank you, $N. You have played a part in something bigger than you can imagine.',
    `RequestItemsText` = 'Have you found the feralkin?'
WHERE `entry` = 41048;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excuse me for the state of this place. Our work has just begun.',
    `RequestItemsText` = 'I didn''t expect company. Welcome.'
WHERE `entry` = 41049;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, my gratitude, young one. These weary bones of mine have seen many moons, and my aging eyes no longer possess the keenness they once held. Your presence here is a timely boon, for the moment of anticipation is upon us.$B$BBehold those precious eggs before us, nestled within the protective embrace of the roost. They shimmer with the promise of new life, their shells trembling in anticipation of the imminent hatching. A magnificent sight to behold, indeed.$B$BStay vigilant, for any moment now, the fragile shell shall yield to the strength within, and new chimaera hatchlings shall grace this world with their presence.',
    `RequestItemsText` = 'Beware their venomous breath. One mistake can be fatal.'
WHERE `entry` = 41050;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, you have returned, just in time! The anticipation is building, and I can sense that the hatching of the chimaeras is imminent. In just a few days, these majestic creatures will emerge from their eggs and grace our roost with their presence. Your timely presence ensures that we are prepared for their arrival.',
    `RequestItemsText` = 'While killing a hippogryph is not something that we, night elves do lightly, it is unfortunately necessary for the chimaeras to grow healthy.'
WHERE `entry` = 41051;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Velos clutches the retrieved harness tightly, his weathered face softening with emotion. Tears well up in his eyes as he accepts the artifact from your hands, his voice trembling with gratitude.>$B$BFriend, you have performed a noble deed, one that rekindles the flame of hope within my heart. With this long-lost relic restored, I can now dare to dream of a future where I can train and nurture a new generation of chimaeras. Your selfless actions have granted me a sense of closure and a renewed purpose. I am forever indebted to you.$B$BIn recognition of your unwavering dedication and unwavering support, I offer you this token of my appreciation. May it serve you well on your future endeavors.',
    `RequestItemsText` = 'Have you recovered it yet?'
WHERE `entry` = 41052;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have retrieved the message. Good work. Now show me that.$B$B<Commander Anashya takes the message from you and carefully reads it, her eyes scanning the words with a furrowed brow>$B$BInteresting... They are preparing to attack the tauren.',
    `RequestItemsText` = 'Do not disappoint me.'
WHERE `entry` = 41053;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your efforts have yielded crucial time for the tauren, and our diplomat has returned from their meeting. The tauren expressed deep gratitude for the information provided, and their appreciation resonates within our hearts.$B$BNever again shall shame befall us.',
    `RequestItemsText` = 'Centaurs can be found mostly in the northern parts of Thousand Needles. Waste no time.'
WHERE `entry` = 41054;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmm, everything seems to be in order here, your assistance to our efforts is well appreciated, here, take this.',
    `RequestItemsText` = 'Dreamscale is a rare and difficult material for us to get our hands on. Even since the paths to Emerald Sanctum have been sealed it has been ever difficult to obtain.$B$BIf you are willing to assist, I can trade two Bright Dream Shards in exchange for five Dreamscales at any time.'
WHERE `entry` = 41055;

UPDATE `quest_template` SET
    `OfferRewardText` = 'May this relic from our armory serve you well, and assist you in whatever battles may yet come.',
    `RequestItemsText` = 'Have you brought the Dream Shards adventurer?'
WHERE `entry` = 41056;

UPDATE `quest_template` SET
    `OfferRewardText` = 'May this relic from our armory serve you well, and assist you in whatever battles may yet come.',
    `RequestItemsText` = 'Have you brought the Dream Shards adventurer?'
WHERE `entry` = 41057;

