    `OfferRewardText` = 'May this invocation grant you the power necessary to defeat evil.',
    `RequestItemsText` = 'Have you gathered the ley energy?'
WHERE `entry` = 41082;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, at last. Something to put my head down at night. I can''t remember the last time I had a good night sleep... I cannot even remember the last time I did fall asleep oddly enough.',
    `RequestItemsText` = 'What, can you not see how serious of a matter this is? If you do not hurry up, I will tell your boss just how horrendous of a job you''re doing.$B$BNow get on with it!'
WHERE `entry` = 41083;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''re looking for wine?$B$B<The Cook lets out a small chuckle of laughter.>$B$BSome of the spirits do not realise the predicament they are in. In fact, many still believe they are alive, walking through these halls as they did on the night before their fate was met.',
    `RequestItemsText` = 'Can I help you?'
WHERE `entry` = 41084;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I never once thought I would be using this formula, but here I am.',
    `RequestItemsText` = 'You got it all?'
WHERE `entry` = 41085;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Councilman Kyleson takes a drink from the Spectral Wine, and looks lost as he savors it for a few, brief moments.>$B$BI must say, this is certainly exquisite. Nothing has parched my intense thirst for what seems like years. Truly, this is the most fascinating wine I have tasted in quite a long time. You have gone above and beyond to ensure I have been treated well here in Karazhan.$B$BSuch a fine servant, you will go a long way here in Karazhan, and you deserve a worthy tip.$B$B<Kyleson places a single coin in your pocket.>$B$BDo not spend such wealth all in one place. If you need anything at all, just ask me.',
    `RequestItemsText` = 'So, have you fetched that wine that I asked for?'
WHERE `entry` = 41086;

UPDATE `quest_template` SET
    `OfferRewardText` = 'To witness the life''s work of Ur unfold before our very eyes is an extraordinary gift. Though the book bears the scars of time, its essence remains mostly intact, a precious treasure of forgotten knowledge.$B$BLet us delve into its ancient pages, embracing the wisdom held within its weathered embrace. The secrets of Vorgendor, the mysteries of the worgen, and the truths of realms beyond our own may be unveiled before us. And most importantly, the secrets of the Scythe.',
    `RequestItemsText` = 'The Tower of Karazhan looms over the Deadwind Pass.'
WHERE `entry` = 41087;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you! Let''s seeŌĆ”Oh no! Some of these plants are fel tainted, but the taint comes from the root!$B$BThis is bad, I hope I can count on your help! Here, take these shinies. I will get you more if you help!',
    `RequestItemsText` = 'Well? Did you succeed? Please! It is important.'
WHERE `entry` = 41088;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done! I knew something was up. How did they receive this? It''s in the demon language, so we will need help to translate this. But for now you have done well!',
    `RequestItemsText` = 'Did you find it?'
WHERE `entry` = 41090;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There are demons in Hyjal? Let me see that Missive!$B$B<He briefly skims the text and then shakes his head>$B$BThis is encoded, we will need a cipher.',
    `RequestItemsText` = 'What do you want with me?'
WHERE `entry` = 41091;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, now I will use this cipher with the letter and we will know more. <Niremius takes his time inspecting the letter.>$B$BThis is troubling news indeed. I have a task for you $C.',
    `RequestItemsText` = 'Did you find the cipher? Don''t bother returning without it.'
WHERE `entry` = 41092;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Niremius sent you? I have no love for his kind, but as long as he kills the demons, I will tolerate his presence in spite of his transgressions. If he sent you to me, then he must have had a very good reason. What is that note?',
    `RequestItemsText` = 'What do you want?'
WHERE `entry` = 41093;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done. Every demon we defeat here, means one less demon for their attack.',
    `RequestItemsText` = 'Is it done?'
WHERE `entry` = 41094;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Trak''nal takes the Mojo from you and crushes it with his blade.>$B$BI will not give up on my people. Hopefully, without the corrupting influence of this thing, their minds will be their own again in time. I be in your debt, friend. Thank you.',
    `RequestItemsText` = 'Did ya find it?'
WHERE `entry` = 41095;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That''s horrible news! I know what cave you speak of, it is connected to the Barrow Deeps below Hyjal. I believe I can cast a ward that will prevent them from breaking through for a while.',
    `RequestItemsText` = 'You are back?'
WHERE `entry` = 41096;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This is ill news you bring me. You have done well in assisting my daughter. The Greens are currently dealing with an emergency here and cannot spare the forces to deal with the demons in the Barrows right this moment.$B$BRest assured, however, we will most certainly keep them at bay.$B$BTake this as a gift for your efforts. You will find these to be of use here in Nordanaar. Now, if you will excuse me, I have much work to do in order to suppress the demon threat.',
    `RequestItemsText` = 'Yes child, can I help you?'
WHERE `entry` = 41097;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh wait! I think I know you.',
    `RequestItemsText` = 'Salutations?'
WHERE `entry` = 41098;

