    `OfferRewardText` = 'Fel in the soil?! I knew those brutes were up to something. They have been acting a bit too organized recently. I need your help!',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 41106;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Our ancestors will cry out your name! May the word of your glory spread to all in the Horde.',
    `RequestItemsText` = 'How has the arena treated you, $N?'
WHERE `entry` = 41107;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The might of the Alliance is shown this day!',
    `RequestItemsText` = 'How has the arena treated you, $N?'
WHERE `entry` = 41108;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Bask in the glory, and let the victory wash over you!',
    `RequestItemsText` = 'Does your heart burn with a yearning for battle? The best of the best compete in the Blood Ring. Heed the call, and fight against the strongest competitors in Azeroth! Bring me proof of your triumphs, and you shall be showered in the spoils of war.'
WHERE `entry` = 41109;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Was your victory thrilling? You have earned it through blood and sweat.',
    `RequestItemsText` = 'How has the arena treated you, $N?'
WHERE `entry` = 41110;

UPDATE `quest_template` SET
    `OfferRewardText` = 'May these plans be a powerful asset for you and your allies in the fight against evil.',
    `RequestItemsText` = 'So, have you made your choice?'
WHERE `entry` = 41111;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Volume Two? I have no idea how this ended up in Gilneas, but I don''t even care. I need to bring this back to Moranna as soon as possible. Just grab your reward from my table; it may not be much, but it''s all I have.',
    `RequestItemsText` = 'I sure wish this is real.'
WHERE `entry` = 41112;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So it was a portrait of her as a child? Well, it might not be worth much, but that doesn''t matter. A job well done gets paid - honor amongst thieves and such.',
    `RequestItemsText` = 'Is this your first heist job?'
WHERE `entry` = 41113;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Recovered, at last.$B$B<Magus Hallister lets out a breath of relief.>$B$BOur secrets are returned to safe hands. You have proven yourself a valuable asset, and as a fellow mage I am certain you understand the power of the arcane in the right hands.$B$BTake this, as thanks from us here in the city.',
    `RequestItemsText` = 'This is a matter most dire. Have you recovered the manuscript?'
WHERE `entry` = 41114;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, you got that coin?',
    `RequestItemsText` = '<He bites the gold coins one at a time, before storing them behind the counter. He says not one word more, but gives a terse nod and marks something down in his ledger.>'
WHERE `entry` = 41115;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The magic flowing from this tablet is intense! I would never have expected such energy from the trolls.$B$BYou have done me a solid favor, and for your help I offer you this tome. It should give you the knowledge to teleport to Stonard. May my magic serve you well!',
    `RequestItemsText` = 'Have you found this mysterious Kazkaz yet?'
WHERE `entry` = 41117;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Pleasure doing business with you, champion.',
    `RequestItemsText` = 'You there! Are you looking to cash out those Arena Marks of Honor you''ve got lying around? Well, if you''re looking for rewards from our coffers, I could take some of those marks off your hands in exchange for a Token of Blood. Think of it as the local currency around here.'
WHERE `entry` = 41118;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Such power now rests in your hands. It is only fitting after the blood you have spilled within the Arena.',
    `RequestItemsText` = 'So, made your mind up?'
WHERE `entry` = 41119;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Aye, the ore, just as I expected! You''ve done me proud, lad! Now, let me gather up these precious rocks and get ''em ready for a journey to Undermine. Ah, the thought of the profits fills me with joy!$B$BYou''ve earned yourself a reward, as promised. Here, take this with ye, if ye must.',
    `RequestItemsText` = 'I wonder if the mine is still intact...'
WHERE `entry` = 41120;

UPDATE `quest_template` SET
    `OfferRewardText` = '<As Ivar peruses the dossier, a palpable sense of disappointment fills his eyes.>$B$BSo, it appears that Isiden has departed from Gilneas. Should he indeed have sought refuge in Tol Barad, we must resign ourselves to the grim possibility of his demise, for naught can withstand the harsh and unforgiving conditions of that island.',
    `RequestItemsText` = 'Isiden Perenolde, the nephew of King Aiden Perenolde, found himself in a precarious situation after Alteraci betrayal of the Alliance. In response to this dire circumstance, Isiden sought refuge in Gilneas.$B$BAs the delicate issue of Alteraci succession gained momentum, Isiden Perenolde''s quest for backing led him to the attention of Genn Greymane. Recognizing the importance of this matter, King Greymane extended his support to Isiden, adding another layer of complexity to the unfolding events.$B$BUltimately, Alterac was annexed by Strom and Lordaeron, but Isiden remained in Gilneas even after the closure of the Greymane Wall.'
WHERE `entry` = 41121;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good, good.$B$BOur shipments to Undercity and Tarren Mill are much safer now, thanks to your actions.',
    `RequestItemsText` = 'Every moment you linger is another ship lost to this madman!'
WHERE `entry` = 41122;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Pleasure doing business with you, champion.',
    `RequestItemsText` = 'You there, champion!$B$BLooking to make a name for yourself with us? Well, we are currently taking donations. Tokens of Blood are what we''re looking for. If you don''t think you will be using yours, return them to us, and I will put in a good word with the bosses on your behalf.'
WHERE `entry` = 41123;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your offering has been accepted. Favor you have gained. Continue and you shall be allowed access to the ancient trades.',
    `RequestItemsText` = 'Dark Iron, while plentiful in the Depths, is still a valued commodity amongst the Brotherhood. The sacred arms and armaments of Ragnaros favor Dark Iron. Besides the ore, we also accept Dark Iron in bar form, should you possess the skill to smelt it.$B$BFor every Dark Iron Bar you offer, favor amongst the Brotherhood you will gain.'
WHERE `entry` = 41126;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Aye, so Delgren sent ya, did he? Ha, that lad''s a good one, fought by me side in the Third War, he did, under the command of Lady Jaina, bless her heart.$B$BBut enough of me ramblin'' about the past like an old dwarf. There be plenty of work to be done, and we best get to it, sharpish! No time to waste, laddie!',
    `RequestItemsText` = 'Aye? I did not expect a visitor today.'
WHERE `entry` = 41127;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent work, the harmonization process does not take me long, especially with all this practice. If you find any more, come and let me know.',
    `RequestItemsText` = 'The transmutation process of Bright Dream Shards can always be undone, reverting the much more powerful material into its weaker components. If you desire me to undo any harmonization, speak with me, and I shall make it so.'
WHERE `entry` = 41128;

UPDATE `quest_template` SET
    `OfferRewardText` = 'May this belt buckle serve you well. Use it wisely, and it can be the difference between life and death.',
    `RequestItemsText` = 'So, made your mind up?'
WHERE `entry` = 41129;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That is but the first lesson, kid. I did not expect to see such natural talent when it comes to your survivability, but regardless, you should go make yourself useful. As time passes and you gain more insight into the land and your own capabilities, return to me and I will teach you some more.',
    `RequestItemsText` = 'Hah! No respect for the elderly, I see. Made me wait a painfully long time, you brat.'
WHERE `entry` = 41130;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Congratulations! You''ve managed to forge your first bond! Your tenacity is admirable, my friend.',
    `RequestItemsText` = 'Remember to greet Grandma Stonefield while you''re at it. That is if you haven''t traded your manners for those of an ogre.'
WHERE `entry` = 41131;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great job! You are ready for your next and final task.',
    `RequestItemsText` = 'Sometimes, being assertive with Prowlers is the only way to go. If you think there is no other way to convince it otherwise, just jump itŌĆöbite its ear and show it who the alpha is!'
WHERE `entry` = 41132;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here we are. Your final task is complete, and my, what a terrific job you''ve done. You''ve learned the just how to manage animals here in Elwynn.',
    `RequestItemsText` = 'I heard bears love honey. People even say that if one eats too much of it, they turn golden yellowŌĆöbut my grandfather says that''s just a silly myth.'
WHERE `entry` = 41133;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, the newest Quiver. AJ mentioned that I should expect you sooner or later. Judging by your recent success, I can only assume that Daisy did a phenomenal job at teaching you the basics. Nevertheless, here we go, lesson number two. Let''s see how you fare.',
    `RequestItemsText` = ''
WHERE `entry` = 41134;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You don''t have to join any orcish coven mon, but you should use them to your advantage. This orc here, this Nartok, he be talking too much. He doesn''t really know how to twist the demons to his advantage, he is just speaking big words like he be some chosen one. Never think that mon, by summoning the demons from the Twisting Nether, you''ve chosen to live your life away from the Loa. And one day that will catch up to you.$B$BAnyway, if you bring me an offering, me be glad to teach you. Perhaps one day you will be as strong as the Zandalari Demoniacs!',
    `RequestItemsText` = 'Hey mon. I be Zin''jashi, and I welcome you.$B$BI be of the Revantusk Tribe, and I be here to teach young trolls the ways of the Twisting Nether. The demons are powerful subjects mon, but they be very treacherous - so be very careful!'
WHERE `entry` = 41135;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Vandol? Let me check the records.',
    `RequestItemsText` = 'Welcome to Theramore. Is there anything I could help you with?'
WHERE `entry` = 41136;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I sense that you have come seeking me, and that you know who I really am. It seems that my past has finally caught up with me, and I must admit that I am not surprised.$B$BTake a moment to consider the gravity of what you are about to say. For you see, I have lived a long life filled with both triumphs and tragedies. I have seen the fall of great kingdoms, and I have witnessed the atrocities that people are capable of committing in the name of power.$B$BIf you are here to confront me about the sins of my past, and the many mistakes that I have made, then I will not fight back. I will accept whatever consequences may come.',
    `RequestItemsText` = 'What brings you to my secluded house?'
WHERE `entry` = 41137;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, here we are! This is them, thanks again, this means a lot, here, just as I promised.',
    `RequestItemsText` = 'Be careful, the Runic Constructs are quite powerful, an overchage of magical energy gone rampant!'
WHERE `entry` = 41138;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is done, truly?$B$BWhy, thank you $N, you''ve saved us a massive headache, and countless lives of this city. We have requisitioned a reward worthy of such feats from the treasury itself.$B$BPlease, take one, it is the least we can do.',
    `RequestItemsText` = 'The longer Arc''Tiras remains active, the more danger Stormwind lays within, we cannot have rumors spreading, this must be dealt with.'
WHERE `entry` = 41139;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oho! These shards are great. Come on, give ''em to me!$B$B<Brok almost rips the mithril shards out of your hand and throws them into the forge.>$B$BAhaha! This will be grand, mate, I''m tellin'' ye! Just you wait, Sindri, ye''ll be bawlin'' your eyes out like ye''ll always do!',
    `RequestItemsText` = 'Seein'' his dumb face when mother scoffs at his work gives a feelin'' in my belly like nothin'' else.'
WHERE `entry` = 41140;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That''s marvelous, just look at all the energy emanating from it! Haha, I can''t lose with this at my disposal!$B$B<Sindri is gazing into the chunks of stone and quickly forgets about you.>',
    `RequestItemsText` = 'Brok is so full of himself. The pout he''s showing when proven wrong is priceless, I''m telling you!'
WHERE `entry` = 41141;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Incredible materials, both of ''em. Ye did great work. Here, have some coin for your troubles.$B$BBrok and Sindri have expertise, they''re me sons after all! They have te get past their differences one day and reflect on what the other does and they themselves don''t.$B$BBrok is te emotional in his work, if he gets a sudden idea, he rushes off te try it out only te see it could''ve never had worked te begin with. Sindri is too strict on himself - doesn''t trust his skills - that''s why he always follows anythin'' he does by the book. And that in turn shortens his horizon.$B$BEnough sentimental chatter, let''s put them in their place!',
    `RequestItemsText` = 'Let''s bring me boys back down to earth.'
WHERE `entry` = 41142;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That didn''t go as bad as I thought. Guess it''s finally time for both of ''em to grow up and become real blacksmiths. Don''t get me wrong, they still got lots of improvin'' te do, but there''s no need te walk the path of blacksmithing alone. They got me, they got themselves. I love me boys with all me heart, so don''t ye think I''ll be lettin'' em do this on their own. Besides, me forge wouldn''t stand long if I left ''em alone!$B$B<Frig''s hearty laughter fills the forge.>$B$BSince ye did most of the work, ye can keep the weapon I made, a true Thunderforge masterpiece!',
    `RequestItemsText` = 'Just say the word.'
WHERE `entry` = 41143;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Doran''s voice sounds a bit shaky, the old dwarf takes the feathers with utmost caution.>$B$BThese are magnificent, thank ye very much fer your interest in our traditions, me friend. Now that we have the feathers, we need a framin'' to put them in.',
    `RequestItemsText` = 'If a fledgling is about to leave the nest, what better way to help it fly than givin'' it some feathers, eh?'
WHERE `entry` = 41144;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Aye, welcome to Aerie Peak! Anythin'' I can help ye with?',
    `RequestItemsText` = 'Beautiful day, isn''t it?'
WHERE `entry` = 41145;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Not bad, not bad. Fer an amateur, this ain''t too shabby. Thank ye for the help and thank ye fer doin'' this fer Doran. Ye might not realize how important this is fer ''im.',
    `RequestItemsText` = 'How''s the hunt? Don''t let ole Doran wait too long!'
WHERE `entry` = 41146;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Doran takes the framing from you, slowly and with shaking hands. He again has trouble finding words.>$B$BThank ye, kind friend. We''re almost done.',
    `RequestItemsText` = 'Yer back, did Drakk remember my favor?'
WHERE `entry` = 41147;

UPDATE `quest_template` SET
    `OfferRewardText` = '<You place the headdress on the tombstone. Its inscription says: "Dulin Steelwing - Beloved son of Doran and Sigrun. May your gryphon take you to the greatest heights.">',
    `RequestItemsText` = 'This must be the gravestone Doran told you about.'
WHERE `entry` = 41148;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I am sorry fer not speakin'' the whole truth. Ye see, today would''ve been my son Dulin''s sixteenth birthday, the age at which Wildhammers become men of the skies.',
    `RequestItemsText` = 'Aye?'
WHERE `entry` = 41149;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Balnack takes a moment to inspect the mainframes, letting out a loud and annoyed sigh.>$B$BBad copper wiring, transmitters blown out...$B$BSuch shoddy craftsmanship, I probably shouldn''t have chosen the lowest bidder for these. Thanks again for your work, It''ll take some work to figure this problem out.',
    `RequestItemsText` = 'Unless you have those mainframes, consider me busy!'
WHERE `entry` = 41150;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmm, with a new copper modulator I should be able to make a new replacement for the Battlechicken with an even better attack capacity and control backups.$B$BOh, you''re back, I take it you''ve cleared out those rogue chickens? Here, take some coin as thanks for the help.',
    `RequestItemsText` = 'Did you finish clearing out those haywire models?'
WHERE `entry` = 41151;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, at last. This thing cost me an arm and a leg, and I don''t have the money to replace it. You really did me a solid.$B$BHere, take one of these. Perhaps it can help you out.',
    `RequestItemsText` = 'So, have you found DV-500?'
WHERE `entry` = 41152;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Finally, some good news! Now, take one of these and get out of my way would you?',
    `RequestItemsText` = 'What?'
WHERE `entry` = 41153;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''re a fast one, aren''t ya? What a blessing to not have a completely useless buffoon in front of me.',
    `RequestItemsText` = 'If your hands are still green, you''re not working hard enough!'
WHERE `entry` = 41154;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Of course I''m yelling at the top of my lungs because I am surrounded by IDIOTS who never in their life held a Gyrospanner!',
    `RequestItemsText` = 'Hm? What?'
WHERE `entry` = 41155;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I have my hands full with all these good-for-nothing workers AND feathered annoyances. If you''re not here to get rid of one of those two problems, then you can sod off right away!',
    `RequestItemsText` = 'What do you want?'
WHERE `entry` = 41156;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Kizzcrack is the least of my worries right now. There are things on this wreckage I need as soon as possible and these oversized lobsters are keeping me from getting them back!',
    `RequestItemsText` = 'Oh, this is just horrible!'
WHERE `entry` = 41157;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good riddance to them. This will teach them not to mess with a member of the Hangmans Plunder.',
    `RequestItemsText` = 'Nobody at Sparkwater Port told me these waters are infested with makrura and murlocs. Still, it''s not like I could not have expected this, to be honest.'
WHERE `entry` = 41158;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh! My beloved logbook! This is heavenly news! Now that I have it back, can I ask you to keep this ordeal for yourself? Don''t worry, I have a... plausible excuse for Kizzcrack ready. Here, take this and... keep it under wraps, ok? No need to... uhm... overcomplicate this, yes? Please?',
    `RequestItemsText` = 'If the info inside it ever reaches Kizzcrack or even Rustgate, I will end up in one of the holes at Sparkwater Port!'
WHERE `entry` = 41159;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Wide eyes and an extreme expression of bewilderment can be seen on Ranala''s face.>$B$BI can''t believe my eyes! My gold pouch, it''s... it''s here! But... it seems to have lost some coins through this hole here. Regardless, most of it is still here. $N, thank you so much. Here, this is for your troubles. When we get back, we''ll tell the superiors of what you did here.',
    `RequestItemsText` = 'With the ship broken and our crew gone, this stash of gold is all I have left.'
WHERE `entry` = 41160;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What? Your coworkers attacked you? Have they gone mad? You need to report this to Rustgate immediately!$B$BNevertheless, I thank you for recovering the remote. I''ll have Gazzik take a look at its insides. Though in the end it''s probably going to be me who''s gonna do that.$B$B<Fanzo lets out another deep sigh.>',
    `RequestItemsText` = 'Seriously, this thing moves really, REALLY slowly. How can one crash it into mud?!'
WHERE `entry` = 41161;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, all this work gets to my head. It is good to finally have some reliable work forces.',
    `RequestItemsText` = 'Are you done yet? The sooner you are, the quicker I can get back to worrying about other problems.'
WHERE `entry` = 41162;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good work kid, it''s nice having someone reliable for a change, with Taxxlo you don''t know if you''re going to actually get what you''re asking for.',
    `RequestItemsText` = 'So, you break those faulty bots?'
WHERE `entry` = 41163;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hm, the weather didn''t do them any good. But nothing the workers can''t repair. Good job out there. Keep this up and soon we may have normalcy back on this island again.',
    `RequestItemsText` = 'We''re not getting new supplies from Sparkwater as often as we''d like, so we have to salvage as much as we can.'
WHERE `entry` = 41164;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The water shipment? Yes, I know about that one, if you look up the cliff behind you, you can see where it ended up.',
    `RequestItemsText` = 'You''re far from Rustgate, pal.'
WHERE `entry` = 41165;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, there they are. I will have them be delivered to Copperlight once another worker shows his mug around here. Thank you, $N, I will mention this on your monthly resume.',
    `RequestItemsText` = 'The longer you take, the more work piles on for you.'
WHERE `entry` = 41166;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Not half bad, runt. This gives me some more freetime to whip your slacking coworkers back into the pits. Much appreciated.',
    `RequestItemsText` = '<Rakklan is threatening you by impatiently placing his bludgeon unto his hand again and again.>'
WHERE `entry` = 41167;

UPDATE `quest_template` SET
    `OfferRewardText` = 'While I''m personally more of a meat guy, I acknowledge the charm that maritime food offers. Making these into a stomach filling gumbo should be no issue, however. Grab something to write, and watch closely! I don''t want Rustgate to wait any longer.',
    `RequestItemsText` = 'Crawlers skitter around on the beaches east of here, makrura have been seen at the wrecks to the west.'
WHERE `entry` = 41168;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Blastentom reads the report, rivers of sweat run down his increasingly more red face.>$B$BWhat in all that is profitable is HAPPENING on that island?!',
    `RequestItemsText` = 'My, you''re covered in ash and coal. What''s up, fellow goblin?'
WHERE `entry` = 41169;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Blastentom is not happy with what''s going on here? Color me surprised. For both of our sakes, get out of my tower and start cleaning this chaos up!',
    `RequestItemsText` = 'Wait, I know your ugly mug.'
WHERE `entry` = 41170;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now this is what I like to see. Took us only twelve attempts. Having these lists will make Maxlo more than joyous.',
    `RequestItemsText` = 'The clock''s ticking.'
WHERE `entry` = 41171;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent. Swift, merciless, efficient. Keep this up and you''ll make it big, trust me. Before you run off - we''re not done here just yet.',
    `RequestItemsText` = 'I didn''t become Supreme Overseer for picking flowers and warbling songs on a meadow. No, my iron grip on maintaining order is what got me this position. And I will not have my authority undermined.'
WHERE `entry` = 41172;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Taxxlo grabs the heads by the ears and lets out a laugh audible in all of Rustgate Ridge.>$B$BLook at this, $N. This is what awaits those who betray not only the Durotar Labor Union, but also ME. Nobody on this island will question my authority and proficiency ever again! Your future is promising, young worker. Goblins like you will be the key to get this machine back on track.$B$BTo reward you for your hard work, take one of these and tell everyone what those in my favor can expect.',
    `RequestItemsText` = '<Taxxlo eyes you with a stern look.>'
WHERE `entry` = 41173;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Finally some good news! Now I can get off this gold-forsaken rock and get back to what I was meant to.$B$BYou''ve really helped me out here. Take these. They should help you navigate this horrid place.',
    `RequestItemsText` = 'If Taxxlo and his goons had given me proper materials, this wouldn''t even be an issue in the first place!'
WHERE `entry` = 41174;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Bizzlo lets out a loud laugh of relief.>$B$BOh why look at all this, you went and saved my career kid. I was sure to be demoted to a miner or even worse had I lost all of this equipment. Take this coin as a token of my thanks.',
    `RequestItemsText` = 'So, have you had any luck yet? Or will I need to find another, more brave soul to do the work.'
WHERE `entry` = 41175;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, the maritime fortune, washed ashore just to be picked up like grapes from a vine! If we ever get off this goldforsaken island, we''re gonna be rich! RICH I SAY!$B$B<Schera begins to cackle like a hyena.>',
    `RequestItemsText` = 'I can taste the beautiful, beautiful gold coins already! Haha!'
WHERE `entry` = 41176;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent work. You have proven to be a capable ranger...',
    `RequestItemsText` = 'You will learn, $N, and one day you will be a great $C.'
WHERE `entry` = 41177;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your commitment is unwavering, $C.',
    `RequestItemsText` = 'I am proud of your accomplishments, $N. Have you finished the last task I gave you?'
WHERE `entry` = 41178;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Congratulations. You''ve demonstrated your worthiness to master the art of beast taming, and I take pride in your accomplishments. I am confident that you will bring honor not only to yourself but to all of us.$B$BAllow me to share a piece of advice: Exercise discretion when selecting your first companion. Will it be a creature of the land, a denizen of the water, or a creature soaring in the skies? Whichever you choose, remember that your chosen companion shall be by your side for a considerable journey. Choose wisely, and may your bond with your pet be enduring and fruitful.',
    `RequestItemsText` = 'Understanding the balance between nature and magic is a way of life for every $N.'
WHERE `entry` = 41179;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, a fledgling ranger stands before me. Come, friend.$B$BEmbarking on the path of a ranger seems like a distant memory now, a life I can scarcely recall from the era before the fall of our homeland. Yet, it is the vitality and spirit of young hunters like yourself that kindle the flames of hope for the reclamation of our ancestral lands.$B$BAllow me to impart the knowledge of training and guiding your newfound companion. Henceforth, you shall not only instruct your pet in acquiring new abilities but also nourish and revive it should it face the perils of battle. This marks the beginning of a crucial chapter in your journey as a ranger. May you wield this knowledge with skill and purpose.$B$BI hope we will speak again soon.',
    `RequestItemsText` = 'What is it?'
WHERE `entry` = 41180;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ew, I see they''re taking their name too literally. Hang on to them for now - while you got your hands dirty, I found out how to help Galvax with his aquatic anomalies.',
    `RequestItemsText` = 'I doubt they possess great magical power, so let us be safe and collect more than usually necessary.'
WHERE `entry` = 41181;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You did it? Oh, and what are these? I''d reckon proof of your deeds. Did you know elemental shackles fetch for a good price on the black market? Ofcourse you didn''t, why else would you give them to me? Nuh-uh, too late, you can''t take back a gift, no? Brings bad fortune after all!$B$BBut don''t be mad, because of your help we won''t die of thirst, and we''re grateful for that! Take one of these as appreciation, I will probably not use them anytime soon.$B$B$N, I have to say: It has been a joy to work with you! Whether we will see eachother again or not, best of fortune to you, my friend!',
    `RequestItemsText` = 'I will be with you in spirit!'
WHERE `entry` = 41182;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These are serviceable, not perfect, but that''s fine. Much appreciated, buddy. Here, take this for your effort. You''re a good goblin, one of the few.',
    `RequestItemsText` = 'With a bit more payment on Rustgate''s side, I wouldn''t be complaining that much. But how things stand now, I definitely need to complain.'
WHERE `entry` = 41183;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So the fools from the slums are really behind the ambushes. We''d suspected the gnolls to be behind it, you know, how gnolls tend to act. But to be honest, it seemed too coordinated. Anyway, good job recovering the shipment, I will report this to Taxxlo. Something needs to be done about these rebels.',
    `RequestItemsText` = 'Hey, you! What took you so long?'
WHERE `entry` = 41184;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I do wonder, what purpose do these serve? Some kind of tribal colour? Or maybe even more? Whatever, it doesn''t really matter to me. Thank you, pal. These will be very useful in the outhouse.',
    `RequestItemsText` = 'I''ve been watching them ever since I was assigned this post here. Some of them are acting even more unreasonably than those squeaky gnomes.'
WHERE `entry` = 41185;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Haha! Wonderful, this will be a perfect gift for my darling Zanny. You are in my favour, $N, I''ll tell the other bruisers to not hit you as hard from now on.',
    `RequestItemsText` = 'Murlocs, gnolls, makrura. Honestly, I have no clue which ones are more irritating, but if it were up to me, I''d drive them all off of Durotar Labor Union property.'
WHERE `entry` = 41186;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Aerthand''s judgment has proven sound in sending you my way. You bear the mark of capability, unmistakable in your presence, $C. There''s no doubt we could use your skills in this tumultuous time.$B$BThere''s much to be done, and with every caravan that arrives, our needs grow. Are you ready to lend your hand to our cause?',
    `RequestItemsText` = 'Ah, it warms my heart to witness more of our kin finding their way to this newfound sanctuary. Isn''t it a sight to behold? There''s a certain magnificence in the familiarity of these surroundings, reminiscent of the outskirts of Silvermoon City.'
WHERE `entry` = 41187;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $C. Your willingness to contribute is like a small beacon of hope in the vast sea of our needs. It may seem like a mere drop amidst the ocean of challenges we face, but with each kind gesture, we inch closer to the restoration of our former glory.',
    `RequestItemsText` = 'You can find boars all over this valley.'
WHERE `entry` = 41188;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, a welcome relief to know that the burgeoning threat of the lynx population has been curbed. Your actions bring a sense of solace, and I can rest easier knowing that you''ve shouldered this responsibility for our community, young $C.',
    `RequestItemsText` = 'Remember, it''s the young ones you are after.'
WHERE `entry` = 41189;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, finally! A bounty of good, fresh ingredients to work with. Thank you a thousand times over! It''s about time we bring some flavor to this place, don''t you think?',
    `RequestItemsText` = 'How''s it going, friend?'
WHERE `entry` = 41190;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You must be jesting.$B$BTo think these flowers could sway anyone, let alone win the favor of someone as fair as she isŌĆöit''s a futile endeavor. Worthless, utterly worthless. Winning her heart seems like an insurmountable task. I''ll likely wither away in solitude here, far from the homeland that once held the promise of connection.$B$BJust leave me be, so I can indulge in my melodrama in peace.$B$B<Avenant dismissively throws away the flowers with a touch of contempt.>',
    `RequestItemsText` = 'Jolie will be mine.'
WHERE `entry` = 41191;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The common folk yet again take matters into their own hands, endeavoring to mend the fallout left by those who consider themselves above such concerns. Thank you, $C. You have saved many.',
    `RequestItemsText` = 'Every moment you linger means less arcane crystals for those in need.'
WHERE `entry` = 41192;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The news of our former kin''s demise brings me no pleasure; it is a somber reminder of the conflicts that have arisen among those who were once united. Their aggression left us with no recourse but to defend our newfound home.$B$BMay their spirits find solace in the embrace of the Eternal Sun, despite the shadows that clouded their hearts.',
    `RequestItemsText` = 'Have you found the blood elf camp?'
WHERE `entry` = 41193;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, this missive was recovered from the commander''s remains?$B$BThe contents are disquieting, and it is imperative that this letter reaches the Regency Council in Alah''Thalas without delay. The mention of spies infiltrating our ranks within the city is a matter of grave concern.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 41194;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Vereesa gracefully accepts the letter from your hand, her keen eyes perusing its contents with a measured intensity.>$B$BThank you, $C, for your diligence in bringing this matter to my attention. The urgency of the situation is apparent, further corroborating my apprehensions. It appears that the once understandable discontent has evolved into blatant mutiny.$B$B<She pauses, her demeanor reflecting a mix of concern and determination.>$B$BNot all within our midst remain loyal to our shared cause. We must swiftly identify these agents still aligned with Kael''thas and promptly expel them from our city.',
    `RequestItemsText` = 'Another one of our kin finds a way into Alah''Thalas. Welcome.'
WHERE `entry` = 41195;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh! Oh you got it! Oh blessed-$B$B<Ranathir quickly lowers his voice, clutching the crystal to his chest and looking around at the other Withered.>$B$BThank you. Thank you. Today is going to be all right. Today will be great. This is great. This is...$B$B<His grasp on the crystal tightens, his hands beginning to shake. His voice suddenly drops to a trembling whisper.>$B$BNever enough...',
    `RequestItemsText` = 'Some days I''m so worried that I''m going to die...but some days I''m terrified that I won''t.'
WHERE `entry` = 41196;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, it''s from Solenia? My dear girl is truly sweet. I appreciate your kindness in delivering it, stranger. If you happen to cross paths with her again, convey my gratitude and tell her she must come to visit me. There are matters of great importance that we need to... discuss.',
    `RequestItemsText` = 'Welcome to my inn, traveler. We are out of beds for now, but you can always sleep on the floor, right?'
WHERE `entry` = 41197;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This silence. I''d never thought it would be so exhilarating. Finally, after all these years of horror and agony, I feel the burden of my death being lifted off me. My eternal gratitude upon you, kindest of strangers!',
    `RequestItemsText` = 'Please, the voices...! There are too many of them!'
WHERE `entry` = 41198;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Leonid takes the derelict mace and gazes upon it almost sentimentally.>$B$BI remember that day... and the horrors it bore. Without the supervision of the Silver Hand, the summit turned slowly into a nest of sinistry and soon sunk into the clutches of darkness. The Cult of the Damned infiltrated the refugees of Stratholme seeking shelter in the mountains and overthrew Arthas'' old stronghold after Uther left.$B$BAs a devout disciple of the Light I did all I could to protect the innocent. Foolish, perhaps, but anything else would''ve been shameful to me. With life fading my ravaged body, the last sounds I heard were the screams of fear and agony coming from the people I failed to save.$B$BThank you for bringing this to me, traveler. It was a choice reminder of the terrors the Scourge inflicts upon the world, one neither you nor I should easily forget.',
    `RequestItemsText` = 'What is it, $R? What can the Argent Dawn do for a traveler like you?'
WHERE `entry` = 41199;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Light shines brighter today. Through your conviction, evil has been held back for now. Do not foolishly think this to be the end of it. Darkness is rarely ever extinguished fully. Stay vigilant, adventurer, and may the Light shine upon you.',
    `RequestItemsText` = 'The Brotherhood of Light will not stand idly by while villainy is free to set its course. Righteousness will prevail.'
WHERE `entry` = 41200;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A goblin? Your kind has been scurrying through the city more often lately. But I don''t mind, anyone seeking to widen their horizon in pursuit of power is welcome.',
    `RequestItemsText` = 'What brings you to the Cleft of Shadow?'
WHERE `entry` = 41201;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Would you look at that, you came back. Hammers in hand, -AND- alive! It would seem all those things I heard about you were true after all.$B$BI may not have told you, but you did me a real solid here, I was supposed to be the one to clean up some of those Mudpaw, and you did it for me!$B$B<Grizzie lets out a heavy chuckle of laughter.>$B$BI suppose I ought to pay you for such a good job, here take one of my old beatin'' tools.',
    `RequestItemsText` = 'So there big shot, you enforce goblin supremacy yet?'
WHERE `entry` = 41202;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good to have you here. To be frank, I saw your physique when you came through here on your arrival - and watching you work in the pits showed me how durable you really are. If you need some tips and tricks on how to make life here easier, toss me a few coins. Will be worth your money, I''ll assure you.',
    `RequestItemsText` = 'Hey, buddy! Still slogging through the coal pits?'
WHERE `entry` = 41203;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Some say mastering the arcane takes years and years of disciplined studies. Nay I say! The simple tricks are the ones that bring you the most money. Shimmy over with some silver and soon you can get your own steady income by selling conjured water to poor fools that need it!',
    `RequestItemsText` = 'Well, hello! Fancy seeing you here.'
WHERE `entry` = 41204;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I see you share my love for guns. They''re beautiful, aren''t they? Incredible tool for all sorts of fun activities - besides punching holes in your enemies. I''m willing to share some nifty shots and such if you are willing to share some of your coin. Giving and taking around here, you know?',
    `RequestItemsText` = 'Oh! That''s a nice boomstick you got there.'
WHERE `entry` = 41205;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What''s one main goal in life? Helping the innocent? Achieving peace and ending tragedies? Pah, ridiculous! One''s life goal should be prosperity! Riches! Cold hard gold! Pass some of that money over and you''ll learn how to alleviate the rich in no time.',
    `RequestItemsText` = 'Psst, no need to make unnecessary noise.'
WHERE `entry` = 41206;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I see the gleam in your eyes, eager for some more powerful spells? Ofcourse you are, the powerful are automatically the most rich around here. Just look at Rustgate and his tower. Living proof! Toss me some coin and I will help you on your journey to whatever you wish to be.',
    `RequestItemsText` = 'Hehehe, hello, fellow initiate!'
WHERE `entry` = 41207;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oho! You can literally feel and hear their energy. $N, I am keeping my promise. Listen well, and execute properly. Even summoning an imp can be difficult at first. You''ll get the hang of it in no time, I am sure.',
    `RequestItemsText` = 'Be quick, they don''t beat for long!'
WHERE `entry` = 41208;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmm...$B$B<Dalanas takes his time looking over the document>$B$BIt would appear most of their efforts have been focused at the Blacksand Oil Fields, but there are potential plans for future developments. You have done well in recovering this from that worksite. Take these coins, as a contribution from us here at Stonetalon Peak.',
    `RequestItemsText` = 'So, have you found anything of value?'
WHERE `entry` = 41209;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Why, look at this. It seems they did find something after all. It''s a good thing we snatched it right out from under them.$B$BGood work with the mission mercenary, take some coin as payment for the good work. We Durotar Labor Union members pay for a job well done.',
    `RequestItemsText` = 'So, you have any luck finding anythin''?'
WHERE `entry` = 41210;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I see you returned, and visibly strengthened by your venture. I take it the mine is cleared? You''ve done a commendable service to the Horde today. News will be sent to Orgrimmar of your deeds - with resources dwindling more and more, the Warchief will acknowledge your ambitious nature, I am certain of it.',
    `RequestItemsText` = 'The Deepmoss spiders are a menace to the Stonetalon Mountains. Too often have they ambushed innocent travelers making their way through these treacherous cliffs.'
WHERE `entry` = 41211;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is as I feared. The same faint breath of foul magic permeates these brains. Yet it may be even stronger within the spiders of the Broken Cliff Mine. I wonder, what may be the reason? Perhaps them living underground is one of the key factors here. I need to convene with Faldan about this and my findings, we have much to discuss.$B$BNevertheless, you helped me greatly in my research. Still, there is much to do to get behind this conundrum, and for the sake of Kalimdor, we have to solve it as quickly as possible.',
    `RequestItemsText` = '$N, how does your search for samples fare?'
WHERE `entry` = 41212;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Our war with the Venture Co. is one step closer to victory. No thanks to your actions of course. Here, take this, as a thanks from myself.',
    `RequestItemsText` = 'Our security depends on your actions, get to it!'
WHERE `entry` = 41213;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I hope these pesky guards weren''t much of an issue. Thank you, $C. This will be invaluable in my research.',
    `RequestItemsText` = 'Behold the statue before us, a testament to the cherished ideal of a dancing pair. An ancient legend among our people narrates the ethereal dance of the moon and the sun, forever close yet never touching. This concept extends to Quel''dorei dancing as well, where two partners gracefully draw near to one another, maintaining a captivating proximity without physical contact.'
WHERE `entry` = 41214;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Exquisite! With those two hearts now in my possession, the veiled secrets of these lands shall unfold before me like a delicate tapestry.',
    `RequestItemsText` = 'Legend has it that those who linger too long on the isle lose their grasp on the passage of time. While they find solace in the eternal autumn, seasons and even years may slip away on the mainland without their awareness. So be wary, traveler.'
WHERE `entry` = 41215;

UPDATE `quest_template` SET
    `OfferRewardText` = 'One, two, three... and a score of ten! Remarkable work. With such diligence, the hills will soon be secure for our laborers to resume their work without fear.',
    `RequestItemsText` = 'Be careful, these creatures are more savage than you think.'
WHERE `entry` = 41216;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Indeed, this fang unequivocally belonged to the ferocious beast that tormented me. With the creature now vanquished, my workers can hasten their return to the hills. There''s a profound sense of satisfaction in knowing that the creature which inflicted a life-altering scar upon me is no longer among the living.',
    `RequestItemsText` = 'Be wary of its bite.'
WHERE `entry` = 41217;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, by the Sunwell, thank you! It may not be grand, but any aid in these challenging times is truly appreciated. Accept these potions as a token of my appreciation. They may be of more utility to you now than any wine I could offer. Safe travels, friend.',
    `RequestItemsText` = 'Be wary of those lynxes! My sweet Maelor lost his eye in a fight with one of them.'
WHERE `entry` = 41218;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $C. The roads are safer, and I''ll make sure the charged mana crystals are distributed among the poorest of our kin.',
    `RequestItemsText` = 'Yes, $C?'
WHERE `entry` = 41219;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I express my gratitude, adventurer. However, an unexpected turn of events has altered our plans.$B$BLord Astalor Sunsworn has directed that the resources you''ve gathered should be utilized to orchestrate a lavish feast for his noble supporters. Though it grieves my heart to convey that we won''t be able to extend this bounty to the less fortunate, it is not within my purview to contest his decision. Nonetheless, I appreciate your efforts and generosity in this matter, my friend.',
    `RequestItemsText` = 'Both of these creatures can be found all along the Farstride.'
WHERE `entry` = 41220;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Astalor Sunsworn opens the letter, casually skimming its contents before breaking into a derisive laugh.>$B$BI should have you flayed by my guards for daring to believe you could waltz into my residence and insult me. However, I find myself in need of a messenger. Deliver my response to this... Liadrin, whoever she is. This task is beneath the dignity of any of my guards.',
    `RequestItemsText` = 'Why did my guards let you in here?'
WHERE `entry` = 41221;

UPDATE `quest_template` SET
    `OfferRewardText` = '<You repeat Astalor''s words to the priestess, ensuring no detail is omitted. As you deliver his message, you witness a simmering rage in the priestess''s eyes. A faint green glow emanates from them, transforming her countenance into that of an entirely different person.>$B$BVery well. I anticipated as much from him. What sheer arrogance. No cause is worth the continued suffering of even a single Quel''dorei. We have endured enough, and I will ensure that Astalor comprehends this. Soon...',
    `RequestItemsText` = 'Did you find Astalor?'
WHERE `entry` = 41222;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh! You''ve recovered them! Thank you, thank you!$B$BWhile I''d love to extend an invitation to the party, I''m afraid it''s a closed affair. However, fret not, for there will surely be another occasion for us to have some fun together, won''t there?',
    `RequestItemsText` = 'I just can''t stop thinking about all the fun.'
WHERE `entry` = 41223;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Kaelin wants to give Lin a gift? Say no more.',
    `RequestItemsText` = 'Why hello there. How can I help you?'
WHERE `entry` = 41224;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Kaelin gazes at the stole>$B$BYes, it''s perfect. I... I think. It will suit my beloved splendidly. I can''t wait to see the surprise on her face.',
    `RequestItemsText` = 'Any success?'
WHERE `entry` = 41225;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It was wise of you to come. Now, let us begin.',
    `RequestItemsText` = 'Bal''a dash.'
WHERE `entry` = 41226;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I am pleased you have answered the call. Let us begin your training.',
    `RequestItemsText` = 'Walk with the Light.'
WHERE `entry` = 41227;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Our task is as noble as the heritage we carry.',
    `RequestItemsText` = 'Light bless you.'
WHERE `entry` = 41228;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This will not be cheap, you will be indebted to me greatly.',
    `RequestItemsText` = 'Beware what hides in the shadows.'
WHERE `entry` = 41229;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Let none survive.',
    `RequestItemsText` = 'Raise your weapon to the Sun.'
WHERE `entry` = 41230;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Farstrider legacy must live on.',
    `RequestItemsText` = 'May your arrows fly swiftly.'
WHERE `entry` = 41231;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Allow us to briefly unite your hands with ours, so that we may perform this ritual.',
    `RequestItemsText` = 'Have you gathered them all?'
WHERE `entry` = 41232;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have returned with the core. We may now begin.',
    `RequestItemsText` = 'Please, do tell.'
WHERE `entry` = 41233;

UPDATE `quest_template` SET
    `OfferRewardText` = 'An Ancient of Arcane, how could that possibly be?',
    `RequestItemsText` = 'Go on, then.'
WHERE `entry` = 41234;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I never thought Ordenal to be such a fool, acting without a modicum of considerationŌĆösummoning an Ancient of Arcane, a blatant mockery of our culture and heritage.$B$BNevertheless, your information is valuable. What''s done cannot be undone, and while I abhor the very notion of such an Ancient, I find myself contemplating potential uses for it.$B$BNow be gone.',
    `RequestItemsText` = 'What?'
WHERE `entry` = 41235;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I see. I''ve been investigating the Blood Elf presence in this area for a considerable amount of time, but this is indeed grave news. If they truly have agents infiltrating even the city, swift and decisive action is imperative.',
    `RequestItemsText` = 'Lady Windrunner shall lead us to victory!'
WHERE `entry` = 41236;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Rommath?$B$BThat rat, that vermin! He''s the one who betrayed Vereesa, siding with Astalor, and now this? He will hang for his treachery.$B$BBut first, deliver this news to Lady Vereesa. I sense there''s something more to it...',
    `RequestItemsText` = 'Have you found anything?'
WHERE `entry` = 41237;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Vereesa''s countenance pales as you explain the situation to her.>$B$BI... I didn''t anticipate that it would be someone from the Regency Council, even in my darkest dreams. Who else is conspiring against us? Voren''thal? Astalor? This is profoundly grave news, $N.',
    `RequestItemsText` = 'How was your investigation?'
WHERE `entry` = 41238;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, you are from Felstrider, correct? You are safe; no one can hear us.$B$B<Rommath scrutinizes you, studying your face for an extended moment.>$B$BVery well. I have made all the necessary preparations. If my calculations are correctŌĆöand they areŌĆöwe should be able to establish contact with Prince Kael''Thas.$B$BBy the way, is everything well with Eldin? That fool Astalor has been attempting to amass a force to attack Felstrider, but he has been unsuccessful, as usual.$B$BGood, good. Inform me when you are ready.',
    `RequestItemsText` = 'Who dares interrupt my meditation?'
WHERE `entry` = 41239;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So you see now. Every day, I hear our people label him a traitor, a coward. Yet, I am bound to fulfill his wishes. I do not comprehend his intentions, but I hold steadfast in my belief in him. I only wish more of our people could perceive it in the same light.',
    `RequestItemsText` = 'My Prince...'
WHERE `entry` = 41240;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Ka''zmir''s hands shake as you offer him the crystals.>$B$BQuite the haul. These will do us well. Thank you.',
    `RequestItemsText` = 'I feel ŌĆö edgy.'
WHERE `entry` = 41241;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You return from the ghetto, do you not? Are you present here to assist with their course of action?',
    `RequestItemsText` = 'What is it?'
WHERE `entry` = 41242;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So it had no effect, whatsoever?',
    `RequestItemsText` = 'I hope my theory will be correct.'
WHERE `entry` = 41243;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Welcome, child of Dath''remar, to my current abode.',
    `RequestItemsText` = 'Do tell.'
WHERE `entry` = 41244;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I was coming to check on you since you were gone for a long while, but all I saw was you dismantling them with ease. Skillfully done.',
    `RequestItemsText` = 'Spare none.'
WHERE `entry` = 41245;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Anything interesting you''d like to mention?',
    `RequestItemsText` = 'Not as easy as it may seem, is it?'
WHERE `entry` = 41246;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This belonged to my uncle. He was my guardian, my mentor. I knew he had fallen on these lands but never did I think he''d be without rest. In a way, I think he knew Quel''Thalas fell, which is why he had returned beyond the grave.$B$BYou''ve done me a great service, a reward is due.',
    `RequestItemsText` = 'On with it.'
WHERE `entry` = 41247;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very well.$B$B<Sira crushes the scales, adding them to her potions. The mixture sizzles and begins to glow.>$B$BHere you go. Three potions should suffice. Use them judiciously, for I won''t provide you with more.',
    `RequestItemsText` = 'Any luck?'
WHERE `entry` = 41248;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What could the Naga hope to achieve by attacking the Quel''dorei? Someone must be aiming to inflict further suffering upon these already broken people.',
    `RequestItemsText` = 'Have they been dealt with?'
WHERE `entry` = 41249;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Greetings, I am Rine, and you are in the presence of the Sisters of Autumn.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 41250;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Kael, alive and well in Outland, still concerned about our people? Are you absolutely certain?$B$B<Vereesa''s expression shifts as she delves into deep thought, her brows furrowing and her eyes gazing into the distance.>$B$BThere is much to weigh and consider in the wake of this information. The implications are far-reaching, and I must carefully deliberate on the best course of action for our people. Your delivery of this news has been invaluable, $N, and I am profoundly grateful for the service you have rendered to both me and the entirety of Quel''dorei.',
    `RequestItemsText` = 'What have you learned?'
WHERE `entry` = 41251;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What?$B$B<Melanthe turns away from Briella and sighs.>$B$BOh. You''re here from- yeah okay, sure, thanks. Good job, A plus, gold star. Here''s your paycheck. Go buy some oranges or individuality or something. Bye.',
    `RequestItemsText` = 'If you want me to smile, give me a better reason to do so.'
WHERE `entry` = 41252;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, what a beautiful haul of sweet, sweet crystals. These will be invaluable in my research, truly invaluable. You have done a great service to our people today.',
    `RequestItemsText` = 'I''m sure you will be fine. Just don''t show the crystals to the guards.'
WHERE `entry` = 41253;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Splendid! With these creatures gone, the shore is safer for everyone! And I can finally buy fish at a reasonable price...',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 41254;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here it is, the shipment in question. I thought it was lost for good, but once again, the resilience of our people is remarkable. Thank you, $C. You have done a great service to me.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 41255;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, you found them! Wonderful, thank you. I''m sure in no time at all we shall have these children nurtured and cultivated into beautiful new sprouts.$B$B<She pauses to think for a moment.>$B$BOh. You may not wish to wait around for it- I forget that mortals have a different sense of time than we do. It may be a few years.',
    `RequestItemsText` = 'Ahhh, Autumn! Sometimes I miss the twilight shores of Kalimdor, but there really is something very cozy about this place, cursed history notwithstanding. Do you have the acorns?'
WHERE `entry` = 41256;

UPDATE `quest_template` SET
    `OfferRewardText` = 'He is slain then? I suppose I already finished mourning him years ago. I hope you both learned a valuable lesson from this, though I''m afraid he won''t be learning from any of his other mistakes after this. Take heart, it had to be done and now you know what becomes of one of us who turns to a more sinister solace for our pains.$B$BHere you are, then, you''ve earned this. Take it with you on your journey, and may it serve you well, both as a tool and as a reminder.',
    `RequestItemsText` = 'I should have never trusted him, not with students, and not with my...first edition copy of the Song of Aegwynn.'
WHERE `entry` = 41257;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I humbly salute you, high elf. The resilience displayed by your race in the midst of adversity serves as an inspiration for all of us during these challenging times.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 41258;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, the promised allies finally arrive. Welcome home, kin. There''s a lot of work to be done.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 41259;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done. Shores are much safer thanks to your actions.',
    `RequestItemsText` = 'Have you found the vile creature?'
WHERE `entry` = 41260;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Another children of Dath''remar finds their way into our city. Welcome home.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 41261;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Consider me thoroughly impressed. Outstanding job, $C. Naturally, ensure that the details of this event remain confidential. Let it fade into oblivion.',
    `RequestItemsText` = 'Your mortality wanes with every moment you waste loitering here.'
WHERE `entry` = 41262;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, child. While you may think it is not much, it will make a world''s difference to them.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 41263;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A goblin deep within the mine itself?$B$BThis is big news, and somewhat concerning. I will discuss this with my superiors, but your information has given us exactly what we need. You''ve done well this day, upstart.',
    `RequestItemsText` = 'Let us hope such rumors are not true.'
WHERE `entry` = 41264;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Nice work kid, I knew I could trust my instinct in guiding your destructive hands. It won''t be long until we are back to tree chopping and harvesting once more.',
    `RequestItemsText` = 'It won''t be long until we reclaim the Lumber Yard for ourselves.'
WHERE `entry` = 41265;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Taxxlo begins to read the report, his face growing more and more angry with each passing second.>$B$BVenture Company working with the Mudpaw Gnolls?! First we are shedding gold out of our backside and now this!$B$B<Taxxlo takes a long moment to reflect>$B$BGet out of here, before I toss you off this tower.',
    `RequestItemsText` = 'You better have a good reason for bothering me.'
WHERE `entry` = 41266;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well, $N. The Citadel thanks you for the aid in retrieving this crystal. We shall see it purified or, barring that, destroyed soon enough. Stand proud, as your actions have helped to save many pure souls from the temptation of the fel.$B$BTake this, as a token of the Citadel''s gratitude.',
    `RequestItemsText` = 'The longer that you delay, the more this land may be scarred by the dark energies of fel magic.'
WHERE `entry` = 41267;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Vera sold out already, did she? Well, I suppose we should have been prepared for such a possibility, but you simply can''t rush couture. You wouldn''t want your festive fashion to look like you bought pr├¬t-├Ā-porter Undermine Outfitters, hmm? There''s just one little problem...',
    `RequestItemsText` = 'Yes? I am Madame Gres. How may I assist you?'
WHERE `entry` = 41268;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Welcome back, darling! And you brought me the hides! Aren''t you just a dear. Why, we''ll have these cleaned, tanned, optically whitened, and attached in no time! Well, relatively speaking of course. You can''t rush couture after all.',
    `RequestItemsText` = 'You know, orange is the new purple this season. Have you considered updating your wardrobe, darling?'
WHERE `entry` = 41269;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh hello again, I heard word from Alix that she had received her hides, she already sent some stuff ahead early. You can speak with Mr.Freeze here, he keeps our stock of goods.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 41270;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ralph sold out already, did he? Well, I suppose we should have been prepared for such a possibility, but you simply can''t rush couture. You wouldn''t want your festive fashion to look like you bought pr├¬t-├Ā-porter Undermine Outfitters, hmm? There''s just one little problem...',
    `RequestItemsText` = 'You''re looking for Coco? That''s me, darling, what can I do for you?'
WHERE `entry` = 41271;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Welcome back, darling! And you brought me the hides! Aren''t you just a dear. Why, we''ll have these cleaned, tanned, optically whitened, and attached in no time! Well, relatively speaking of course. You can''t rush couture after all.$B$BI suppose I owe you your supplier''s fee. And if you happen to see Ralph, do let him know to expect a shipment. I would check back with him sooner rather than later- the early bird sets the trend, you know.',
    `RequestItemsText` = 'You know, orange is the new purple this season. Have you considered updating your wardrobe, darling?'
WHERE `entry` = 41272;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh hello again, I heard word from Coco that she had received her hides, she already sent some stuff ahead early. You can speak with Mr.Freeze here, he keeps our stock of goods.',
    `RequestItemsText` = 'You know, orange is the new purple this season. Have you considered updating your wardrobe, darling?'
WHERE `entry` = 41273;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, friendship - love for artistry - devotion to a higher being - and the promise to eternal dedication and faithfulness. Remarkable examples, really, you did splendidly! To be frank with you, I had almost forgotten about all of them, pardon my lack of decorum. This bow has a mind on his own and sometimes I don''t even notice it shooting arrows on its own! Who knows, perhaps you will be its next target on your way out!$B$B<Kwee Q. chuckles at the thought.>$B$BHere, let me reward you for your efforts. Take this box, inside it are the finest garbments in all of Azeroth. Use their alluring charme and woo those cherished in your heart with them!',
    `RequestItemsText` = 'You''ve returned, and with an expression full of glee! Tell me, what have you seen?'
WHERE `entry` = 41274;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oho, so Mayva sent you? That snappy gal hasn''t shown her face around here in AGES! And she wants me to teach you about goldsmithing? Suppose I can''t blame her, really, I AM the greatest jewelcrafter in all of Azeroth afterall.$B$BLet us not wait any longer then, yes?',
    `RequestItemsText` = ''
WHERE `entry` = 41275;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Long travel, I take it? These lands aren''t the most welcoming, but they offer a primal beauty, untouched and rarely seen anywhere else. Still, this isn''t what you are here for, though, correct? Say, who sent you to good old Jarkal?$B$BGoldsmithing? This is an old skill I don''t exercise too often nowadays. The Horde has more use for my alchemical abilities. But should you wish to be taught by me and listen to what I can share, then be my guest.',
    `RequestItemsText` = ''
WHERE `entry` = 41276;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Thegren''s gaze switches between you and the crystal you brought with you. After staring at you for a good amount of time, he nods.>',
    `RequestItemsText` = '<The stone skinned dwarf ignores you with ease, as if you''re not worthy of his time.>'
WHERE `entry` = 41277;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Thegren''s gaze switches between you and the crystal you brought with you. After staring at you for a good amount of time, he nods.>',
    `RequestItemsText` = '<The stone skinned dwarf ignores you with ease, as if you''re not worthy of his time.>'
WHERE `entry` = 41278;

UPDATE `quest_template` SET
    `OfferRewardText` = '<You assume what you are seeing is a smile on the Earthen''s face. The rough gemstone from the giant''s body looks tiny in his broad hands. A nod, that''s all he offers, before telling you to kneel down once more.$B$BUpon placing his palm on you again, you see things a lot more clearly now, although the procedure is still taxing on you. Three gems manifest themselves before your inner eye. Luckily, you recognize them: an emberstone, a star ruby and a citrin. The next thing you see are the same gems getting cut into a facet you have never seen before. Watching intently, you memorize the movements. The wisdom is ingrained into your mind.>',
    `RequestItemsText` = '<Thegren continues his crafts, paying you no attention.>'
WHERE `entry` = 41279;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Comparing them to the dwarf''s flawless cuts, you feel almost embarrassed looking at feeble attempts to replicate his craft. However, to your surprise, another smile whisks itself unto the face of Thegren and the rush of accomplishment invigorates you.$B$BThe next step awaits you.>',
    `RequestItemsText` = '<Thegren waits with a strict expression.>'
WHERE `entry` = 41280;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Presenting the heavy slab of stone to Thegren brings a sensation of pride to you, as you see his amber eyes gleam with excitement. The crystalline shine of the stone reflects beautifully in the harsh sun of the Badlands, making all your hard work pay off even more.$B$BThegren turns to you and nods in approval. The last step is ahead of you.>',
    `RequestItemsText` = '<Thegren tinkers with a few gems.>'
WHERE `entry` = 41281;

UPDATE `quest_template` SET
    `OfferRewardText` = '<The artisan inspects the faceted Lifeblood Gem. His amber eyes diligently observe every cut and edge of the sparkling red jewel. After finishing the evaluation, he hands you the gem back - before bowing down in respect.$B$BYou''ve passed the test! Thegren guides you to his table, eager to share his knowledge with his new pupil.>',
    `RequestItemsText` = '<It looks like he stopped moving altogether.>'
WHERE `entry` = 41282;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Mhm, mhm, not as shabby as I expected it to be. But it clearly bears Mayva''s mark of shoddy craftsmanship. Good thing you are in my hands now, I''ll whip you into a serviceable jewelcrafter in no time! Start by making this lovely trinket here, you should have no troubles replicating itŌĆ” hopefully.',
    `RequestItemsText` = 'If you don''t have it, go get it!'
WHERE `entry` = 41283;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I don''t know about you, but seeing these little treasures shine and sparkle under the light of my prospector''s lens is something I''ll never get tired of. Surely you understand. Now that we got that covered - here, listen close, I won''t repeat myself!',
    `RequestItemsText` = 'These things don''t grow on trees, you know? Or underground. Or anywhere. Nevermind, just pass ŌĆśem already!'
WHERE `entry` = 41284;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Bloodied, drenched, full of mud. Ugh, it breaks my heart to see one of my finer works in such a disrespectful state. Nevertheless, thank you for retrieving it. Tell me, where did you find it, on his beaten corpse or did someone else''s grubby hands pilfered it from him? You know what? Don''t tell me, I''d rather stay oblivious.$B$BAs compensation for your noble deed, I will teach you how to craft this choker yourself.',
    `RequestItemsText` = '<Talvash sighs deeply.>$B$BOh, how much I would give to be back in Gnomeregan!'
WHERE `entry` = 41285;

UPDATE `quest_template` SET
    `OfferRewardText` = '<The Highborne eyes you dismissively.>$B$BFirst this bumbling human down there, and now you? Can an artist not find peace and quiet for once in his life? Tell me, who sent you to The Artificer?',
    `RequestItemsText` = ''
WHERE `entry` = 41286;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great work, I''ve seldom had that many ingredients for jewelcrafting at once in this place. I suppose some form of gratitude is needed towards Gulmire, since he has given me something practical to do whilst waiting for new reports.$B$BBack to you, however. Let me show you how to create these delicate trinkets.',
    `RequestItemsText` = 'Beware of the roaming ogres out there, too many of them for my liking.'
WHERE `entry` = 41287;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It may be faint, but there is power emanating from these gems. The best jewelcrafters are able to extract their mighty essences and amplify them to unprecedented heights. And if you''ll allow me to say this: you are on a good way to reach that point yourself some day.',
    `RequestItemsText` = 'The pearls are often found within thick shelled clams all over Azeroth. Many of the water-dwelling creatures carry those with them.'
WHERE `entry` = 41288;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Harrowing news. What you''re describing is all too familiar - many former troll empires fell to their own hubris, thinking themselves above their people or even their loa. It is all the more relieving to see you return safe and sound.$B$BNow then, shall we pry the information from these tarnished pages?',
    `RequestItemsText` = 'I am sure getting these gemstone will be of no issue for you.'
WHERE `entry` = 41289;

UPDATE `quest_template` SET
    `OfferRewardText` = '<The Highborne eyes you dismissively.>$B$BFirst this bumbling human down there, and now you? Can an artist not find peace and quiet for once in his life? Tell me, who sent you to The Artificer?',
    `RequestItemsText` = ''
WHERE `entry` = 41290;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Soggy and dripping, but still intact. My gratitude is guaranteed, pupil. Well then, let us proceed.',
    `RequestItemsText` = 'I hope my instruments are not damaged by the tides.'
WHERE `entry` = 41291;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Impressive, such profound cuts and grinding work. Anyone can see the blood, sweat and tears you''ve poured into the creation of these. The life one breathes into their artworks is just as important as the technical steps taken. Jewelry without a soul is just a product and an affront to the integrity of the craft''s millenia old legacy.$B$BBut you''ve proven that your heart beats in harmony with Azeroth, attuning yourself to its essence and channeling that energy into your art. As my new pupil, please allow me to pass my sacred knowledge unto you. You have earned it.$B$BOh, and should you ever see any of my former pupils again, tell them they can visit me anytime - I suppose some company can''t hurt after a few years.',
    `RequestItemsText` = 'Stay persistent. Those willing to fail have proven themselves over and over again to be aspiring virtuosos of this craft.'
WHERE `entry` = 41292;

UPDATE `quest_template` SET
    `OfferRewardText` = '<The Artificer inspects your work and the replica.>$B$BClose. Without my guidance, you did an astounding job at repeating my pupil''s steps. Remarkable. Nonetheless, to gauge your true potential, I expect you to craft an artpiece under my guidance. Here, listen close and show me that you listened well.',
    `RequestItemsText` = 'Don''t try to impress me with speed. I hold those who take their time in high regard.'
WHERE `entry` = 41293;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Perceiving the world as it is may appear simple and nothing out of the ordinary, but only those willing to delve deeper are able to gain a profound understanding of its true essence.$B$BYou''ve shown me you are one of them. Pay attention and heed my words, for they will bestow new insight to you.',
    `RequestItemsText` = 'Whether our pieces are used for the benefit or detriment of others is not part of our jurisdiction. The artist fashions their creations with no user in mind, simply its use.'
WHERE `entry` = 41294;

UPDATE `quest_template` SET
    `OfferRewardText` = '<The Artificer is surprisingly solemn at the view of your pieces. A soft chuckle escapes him, before turning back to you.>$B$BThank you. I am glad you sought me out. Here, I will share with you something Gallitrea designed during my tutelage.',
    `RequestItemsText` = 'Sometimes I find myself sentimental at the thought of her whereabouts. Yet it is fruitless to worry about her, albeit difficult to supress.'
WHERE `entry` = 41295;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You reek, $R, horribly. I can smell the despicable stench of naivety and senseless hope on you. Let me take a guess, Sanv K''la and his wretched followers sent you to pry knowledge from my great mind. If that is the case, then I cannot wait to see the disappointment in your face.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 41296;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Damaged, as to be expected. Savage brute. Atleast its contents are intact. You can consider yourself fortunate, then. Still, this scroll... could it be...? Filthy one, your greed has been of great service to me, but your price is not yet ready to be claimed.',
    `RequestItemsText` = 'Have your abilities forsaken you? Useless dreg, I shouldn''t have wasted my time with you.'
WHERE `entry` = 41297;

UPDATE `quest_template` SET
    `OfferRewardText` = '<The broken draenei grabs the decapitated head with unexpected force. Spitting on the bloodied skin of Mato''gar''s head, he throws it unto the ground before stomping it violently into the red sand.>$B$BPathetic wretch, ambassador of ruin and desolation. May your ancestors tear your soul to shreds, for betraying your people, your kin! Taking away our - taking away MY means of escape - it sickens me to my core.',
    `RequestItemsText` = 'To relocate the Draenethyst crystals to Draenor would mean the death for all draenei stranded in his forlorn and sickening world. Kum''isha cannot let this happen.'
WHERE `entry` = 41298;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Tragic and harrowing to hear. Both the intervention of draenei from our homeworld, and Kum''isha''s desperate desire to return to said place. I have led my people to this place in search of a haven, a sanctuary they can someday call home again. With the wisdom on this scroll and the magic of the Draenethyst, we may achieve this - together.$B$BBe rest assured, your deeds for my people will not be forgotten. Let me share insight on these scriptures, as you cannot read its pages yourself.',
    `RequestItemsText` = 'You are back, from the accursed wastes; and alone. Please tell me what happened.'
WHERE `entry` = 41299;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Sending a goon on his own to sort out his problems? Now this is something I hadn''t anticipated of that squirmy little gnome.',
    `RequestItemsText` = 'What is it?'
WHERE `entry` = 41300;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I see you have returned. Now let us ensure you will be able to leave as well...',
    `RequestItemsText` = 'Whether you make these yourself or buy them somewhere else, I do not care. Just ensure they are of high quality, our benefactors value a certain standard.'
WHERE `entry` = 41301;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Talvash opens the bag and looks exasperated.>$B$BWhat?! This is only half of what I was promised! Oh, this damn cutthroat, sleezy slimebag, and damn his very threatening bodyguards too! Well, atleast I am not dead, correct? I have to thank you for that - really, I am grateful! You stuck out your neck for me without even hesitating, that''s something not so common nowadays. Hopefully these thugs will not care to bother me again.$B$BBut do tell me: the jewelry you delivered in my stead, are you a jewelcrafter by chance? If so, please let me share one of my patented designs with you for your valiant heroism!',
    `RequestItemsText` = '$N! What took you so long? I feared they gave you an early visit to the afterlife. So, what is it? Am I safe?'
WHERE `entry` = 41302;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Grizzby? No, he didn''t leave Ratchet, atleast not by boat. But he did make it here, that''s for sure.',
    `RequestItemsText` = ''
WHERE `entry` = 41303;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Tacknazz reads the contract you found on the goblin. The further he reads, the redder his green skin becomes.>$B$BOh, those backstabbing, scab-munching troglodytes! Leaving the Venture Co. was the best thing Nert could''ve ever done, I am sick and tired of their shady tactics. Not only have I lost all my precious jewelry, but also my best contractor, finding a replacement is going to take ages! Oh, Grizzby, you old bastard, you deserved better, much better...',
    `RequestItemsText` = '$N, where have you been? Did you find my jewelry, and where did you leave Grizzby?'
WHERE `entry` = 41304;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, wow! This thing is almost as big as my nose! Those adventurers weren''t lying, that''s for sure. And the necklace you brought, incredibly fine work, truly impressive. You got a nick for jewelcrafting, just like I told you. Really, you helped me out immensely. Those hot-shots in Booty Bay are going to drool over this beauty, just you wait! As thanks for all your hard work and assistance, let me share one of my personal favourite designs with you.',
    `RequestItemsText` = 'Be quick, $N! Creating masterpieces can''t be rushed and the next auction is just a few days away!'
WHERE `entry` = 41305;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Are you here to help poor Sah''rhee?',
    `RequestItemsText` = ''
WHERE `entry` = 41306;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What is this? Traxis'' delivery? I''ve been waiting ages for this! What''s up with that goblin and his lackluster service? Either way, thank you for finishing his work. If he didn''t have such exclusive contact, this would be the last time I''m ordering anything from him.',
    `RequestItemsText` = '<The gnome doesn''t seem to pay attentio to you.>'
WHERE `entry` = 41307;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I dare not call that tiny being a partner, but we share much valuable knowledge between us, so I tolerate her presence and requests. Tell me, what does she require today?',
    `RequestItemsText` = 'What is it you desire, landwalker?'
WHERE `entry` = 41308;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oho, now that''s the stuff. I can tell right away that we can salvage that mess of Traxis with this miracle mixture. Did you come along with Zalashji? He''s a solitary... man? Snake? I don''t know, but so far he didn''t say no to a long and philosophical talk about the history and art of jewelcrafting. Who knows, maybe someday I will tell you how we two met!$B$BSince you helped me with preventing uncomfortable customer confrontations, let me reward you. Am I correct in assuming you''re proficient in jewelcrafting as well? Don''t be surprised, I''m not a master in this craft for nothing. Let me share some of my knowledge for free, as just payment.',
    `RequestItemsText` = 'Back so soon?'
WHERE `entry` = 41309;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Khadgar? A name I haven''t heard in ages and one I thought I''d never hear again following his departure from this world. Wherever he is, be it alive or not - let us hope his spirit is free and unclouded.',
    `RequestItemsText` = 'You are back, what is it you require?'
WHERE `entry` = 41310;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The clutch has found its way back to me, almost like a curse. I am most impressed you returned somewhat unharmed, your power rivals those of great heroes.$B$BNow regarding the clutch...',
    `RequestItemsText` = 'Heed caution, $N. If the demon survived the Third War, then he cannot be underestimated.'
WHERE `entry` = 41311;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The gemstone was split? Curious, but not unexpected given the tower''s state. Still, having it hidden like that - what was Medivh thinking? And this focus... a testament to the dragonflight''s eternal charge of governing magic. I doubt any living mortal could conjure such a device to amplify the flow of energy.$B$BIt is bittersweet, you know? I''ve abjured my life as a sorcerer, yet I cannot deny helping you for the second time now lights up a feeling in my heart long forgotten. My hopes of you putting the horrors of the tower to rest grow after witnessing you succeed in this task. Take the completed head, and search the tower for the rest of it. Most assuredly, this will prove to be pivotal in your exploration of Karazhan.',
    `RequestItemsText` = 'An impossible endeavor, some might say. But the display of your abilities shown tells me enough about you and your endurance.'
WHERE `entry` = 41312;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Those appear positively unnatural. Ley line crystals materialize themselves on rare occasions when fleeting ley essence seeps through the earth, but these... Their formation appears different, almost forced, in a sense. Hm, peculiar...$B$B<Archmage Xylem ponders for a bit, while inspecting the crystals further. Suddenly an epiphany strikes him.>$B$B$N, there are many plausible explanations for this. But to confirm my own theory, I need to conduct some tests first. Will you assist me?',
    `RequestItemsText` = 'Lake Mennar is a focal point of arcane energy, it is not puzzling to see why the Blue Dragonflight congregates at that location. What exactly the blood elves are doing here eludes me, however.'
WHERE `entry` = 41313;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Regrettable, and concerning. I have to be even more selective in my choice of apprentices in the future. It is baffling that Tharessa acted so recklessly, I did not expect such behaviour from her. Granted, her eagerness was apparent, yet I assumed and hoped it to be rooted in her pursuit of knowledge, not power. Whoever she worked for, I will see to it they will be brought to justice for their actions.$B$BNonetheless, with the focus orb back in my possession, we will finally get to the bottom of this leyline conundrum.',
    `RequestItemsText` = 'Have you had any luck in recovering what I seek?'
WHERE `entry` = 41314;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Positively outstanding. What we''ve witnessed proved my suspicions correct: the ley line crystals function as a conduit of energy that, when exposed to concentrated amounts of magic, manifest themselves in arcane monstrosities. If you take a closer look, both crystal remains are identical, meaning the blood elves have altered their own crystal after obtaining it from the Blue Dragonflight - whether they got it by force or cooperation, I am unsure to answer.$B$BThanks to you, my understanding of this land and its inhabitants heightened again. It is concerning, however, to know the Blue Dragonflight is undertaking such suspicious actions. They rarely care for the affairs of mortals, but do not hesitate to halt the abuse of Azeroth''s magic in an instant. Let us observe and hope for the best outcome for now.$B$BAs for your reward; you are a capable jewelcrafter, correct? Let me show you how to fashion a staff that amplifies the wielder''s magical abilities, then.',
    `RequestItemsText` = 'The focus orb will ensure the magical energies do not overload the crystals. So do not fear they might explode violently in your immediate vicinity.'
WHERE `entry` = 41315;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This book...! I''ve heard about it! It''s the last one in a series of masterfully crafted designs and plans for the most elaborate jewelry one can imagine! This one in particular addresses intricate guides to create extremely powerful trinkets with the diamonds of Azeroth.$B$BNow there is only one question: how do we open this damn thing?',
    `RequestItemsText` = 'Oh, a familiar face. Returning for some more training?'
WHERE `entry` = 41316;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ouch, that thing is hot! Must''ve been real tough to get, luckily you''re on the tougher side of life, eh? Now then, let''s not wait any longer and crack this beauty open!$B$B<Fanzy moves the shard over the heavy lock and with a sizzling heat emanating from it, it cracks open, before falling into the sands. Enthusiastically, Fanzy immediately starts flipping throught the tome.>$B$BEmpty. Empty. Empty. Empty! Everything is empty except two pages! I can''t believe this! Is this some kind of sick joke?!',
    `RequestItemsText` = 'Seriously, I cannot wait to get my hands on the sweet, sweet plans inside of this book!'
WHERE `entry` = 41317;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You got the stuff? Great, now then, how about we test this theory of ours?$B$B<Fanzy opens the page of the book and holds it high above her head. When brought near the empty page, the cores and essences liquify and transfer themselves to the parchment - ultimately forming sentences, completing the instruction for this piece of jewelry.>$B$BWOW! Now that was absolutely amazing. Scrap what I said about this book, this is pretty nifty, I have to admit. Incredible, come here, let us scour this page together, we wouldn''t have come this far without your dedication!',
    `RequestItemsText` = 'Don''t underestimate my gnomish intellect. I''ll crack the code in no time!'
WHERE `entry` = 41318;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent work. Just getting your hands on one of these gems is a feat in itself, I can''t imagine how much effort you poured into getting three! Okay, hand all the things over, I''m in the mood to create a MASTERPIECE!$B$B<Fanzy snatches the materials and hastily moves her tiny hands. After a few minutes, she holds the delicate lens into the sunlight, directly in front of the empty page. Surprisingly, instead of burning it, the focused beam of light creates elaborate sentences on the formerly clear paper.>$B$BEUREKA! A complete success! Time to harvest the fruits of our labor! Come here, let''s read together!',
    `RequestItemsText` = 'The lenses I originally envisioned for this amplifier were not cut out to withstand the intense heat. But with the blood of the mountain and the dark iron casing, we might have a good chance at succeeding.'
WHERE `entry` = 41319;

UPDATE `quest_template` SET
    `OfferRewardText` = 'As you can see, what I have witnessed paints a grim picture for my brethren at the Harborage. I have led them to this world in search for safety, and now our past threatens to haunt us once more. I need to prevent this, yet alone I am unable to. Dear stranger, will you assist me like you assisted Sanv K''la?',
    `RequestItemsText` = 'Please, I insist: sit down and make yourself comfortable.'
WHERE `entry` = 41320;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Akh Z''ador takes the slimy, bloody brains and chomps them piece by piece. It is revolting to look at.>$B$BHm, a bit on the spongy side, but not disgusting. I''ve had worse, trust me. Thank you, $N, I can feel the mental weakness fading already.',
    `RequestItemsText` = 'It has been a long time since I''ve tasted brains.'
WHERE `entry` = 41321;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Zesty and spicy - a combination typical for draenei cuisine. Thank you for providing me with enough food to regain my vitality. Your kindness goes a long way, and I wish I could repay you with a traditional meal of my people, one prepared with ingredients from Draenor. But I digress, sentimentalities are of no use here.',
    `RequestItemsText` = 'Despite knowing many of my people''s recipes, I am not a good cook. You can ask anyone in the Harborage, even Noburo was considered a better cook than me!'
WHERE `entry` = 41322;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My cane! I''ve only seen it this disheveled after we escaped Draenor years ago. Eternal gratitude to you, $N. And thisŌĆ” mojo, you call it? This swirling energy is completely foreign to me. Your world will probably never cease to bewilder me.$B$B<Akh Z''ador hits his chest with his fist in respect for your deeds.>',
    `RequestItemsText` = 'I am not naive to think our escape to Azeroth would shield us from every evil there is, yet I cannot feel disheartened by the fact a breeding ground of depravity would have its heart right at the center of our new home.'
WHERE `entry` = 41323;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Master Akh Z''ador sends you?! What a relief! Me and the tribe were worried sick, and had already feared the worst. Losing a close friend, trusted leader and masterful riftwalker like himself would''ve been too much for any of us to bear.',
    `RequestItemsText` = ''
WHERE `entry` = 41324;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A shadowed specter? And it spoke of the enslavement of the Sanv tribe and Akh Z''ador?! This is grim news, $R. For all our sakes, let me be wrong, but I fear the Harborage is in danger, grave danger!',
    `RequestItemsText` = 'Proceed with caution. We do not know what otherworldly horror might await us.'
WHERE `entry` = 41325;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I am devastated. Not even in the wildest of dreams could I have imagined this to happen. Sanv Tas''dal, once my mentor as chieftain and noble leader of our tribe, succumbing to the sweet lies of the Burning Legion. If it wasn''t for you and Akh Z''ador, then my people and I would have followed him back to Draenor, to live the rest of our lives as drones for the Legion''s machinations.$B$BThe Harborage is forever in your debt. Words cannot express how heavy my gratitude towards your selflessness lies, so please: Take this symbol of appreciation from all draenei of this humble sanctuary.',
    `RequestItemsText` = '$N, you are restless. Tell me, could you find Akh Z''ador?'
WHERE `entry` = 41326;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N, I thank you from the bottom of my heart for all you have done for the Harborage. Kas''tal managed to contact me just in time. Any later and I fear for what might''ve happened. Now, to what I wanted to talk with you aboutŌĆ”$B$B<Akh Z''ador presents a flawlessly round and shimmering teal crystal to you unlike anything you''ve seen before.>$B$BWhat you see here is a pure draenethyst gemstone, one of the most rare commodities my people valued back on Draenor. Its status is akin to myth, although they are not the fairytale one might assume. Althoug it is just a theory, I assume this one was created between the clash of Tas''dal''s and my own rift magic. I want you to have it, as thanks - but also as a promise. The draenei of the Harborage will aid you if needed, for without you, we''d be no more. Enkil Toralar, friend, and may the winds of the Twisting Nether be in your favor.',
    `RequestItemsText` = ''
WHERE `entry` = 41327;

UPDATE `quest_template` SET
    `OfferRewardText` = 'An exhausting process, but here it is; another pure gemstone. Please, take good care of it.',
    `RequestItemsText` = 'I''ll be here whenever you need me.'
WHERE `entry` = 41328;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Aw, was this the best ye could get?',
    `RequestItemsText` = 'Ahoy, captain! Managed to sneak a peak over me new recipe, have ye? You know ale''s closer to me heart and I am happy to provide to the rest of the lads anytime. And I believe so would ye. This takes us to the real problem, cap''n.$B$BSee, the ale''s fine but the lads be getting restless. It be too warm outside for us to drink just ale all day! And blasted be the Sea Witch if we''d ever work sober. So as the captain of this crew, you must assume responsibility! Bah, me tongue be dancing around me mouth too much.$B$BWe need rum Cap''n.'
WHERE `entry` = 41329;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That''s the good stuff! The lads be already licking they lips.',
    `RequestItemsText` = 'Ahoy, captain! Managed to sneak a peak over me new recipe, have ye? You know ale''s closer to me heart and I am happy to provide to the rest of the lads anytime. And I believe so would ye. This takes us to the real problem, cap''n.$B$BSee, the ale''s fine but the lads be getting restless. It be too warm outside for us to drink just ale all day! And blasted be the Sea Witch if we''d ever work sober. So as the captain of this crew, you must assume responsibility! Bah, me tongue be dancing around me mouth too much.$B$BWe need rum Cap''n.'
WHERE `entry` = 41330;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oho, now where''d you get that? Something ye''d toast at the table of the Pirate King! If there were one...',
    `RequestItemsText` = 'Ahoy, captain! Managed to sneak a peak over me new recipe, have ye? You know ale''s closer to me heart and I am happy to provide to the rest of the lads anytime. And I believe so would ye. This takes us to the real problem, cap''n.$B$BSee, the ale''s fine but the lads be getting restless. It be too warm outside for us to drink just ale all day! And blasted be the Sea Witch if we''d ever work sober. So as the captain of this crew, you must assume responsibility! Bah, me tongue be dancing around me mouth too much.$B$BWe need rum Cap''n.'
WHERE `entry` = 41331;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Shiver me timbers! The damned thing feels like the kiss of a Siren.',
    `RequestItemsText` = 'Ahoy, captain! Managed to sneak a peak over me new recipe, have ye? You know ale''s closer to me heart and I am happy to provide to the rest of the lads anytime. And I believe so would ye. This takes us to the real problem, cap''n.$B$BSee, the ale''s fine but the lads be getting restless. It be too warm outside for us to drink just ale all day! And blasted be the Sea Witch if we''d ever work sober. So as the captain of this crew, you must assume responsibility! Bah, me tongue be dancing around me mouth too much.$B$BWe need rum Cap''n.'
WHERE `entry` = 41332;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Thegren is examining the book with great interest. After a while he nods, places the book on the table and turns to you. Instinctively, you kneel, before feeling the rough texture of his skin. In a surge of knowledge, the instructions of cutting an elaborate ruby gemstone manifest inside your mind.>',
    `RequestItemsText` = '<Thegren''s stony expression appears to turn joyful upon seeing you.>'
WHERE `entry` = 41333;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Thegren is examining the book with great interest. After a while he nods, places the book on the table and turns to you. Instinctively, you kneel, before feeling the rough texture of his skin. In a surge of knowledge, the instructions of refining an imperial topaz manifest inside your mind.>',
    `RequestItemsText` = '<Thegren''s stony expression appears to turn joyful upon seeing you.>'
WHERE `entry` = 41334;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A peculiar tome, I have to admit. It bears an ancient sigil, one I am not familiar with. Most interesting... Either way, deciphering this book should pose no hindrance to me. Please, give me a moment and I will share what knowledge I can unlock from its pages.',
    `RequestItemsText` = 'Oh, $N! A pleasure to see you again. Tell me, has time been treating you well?'
WHERE `entry` = 41335;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Back in Eldre''thalas, we studied countless, now long forgotten runes in our arcane sanctums under the order of Queen Azshara. Many of these I have forgotten over time, while others out of shame. Nonetheless, it seems my knowledge from that bygone era allowed us to gain new wisdom - wisdom you may use at your own discretion. Here, listen closely. It is time for a new lesson, pupil.',
    `RequestItemsText` = 'Don''t worry. Runes express their power depending on the context they are used in. It won''t cause the book to summon any ghastly fiends, friend.'
WHERE `entry` = 41336;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A peculiar tome, I have to admit. It bears an ancient sigil, one I am not familiar with. Most interesting... Either way, deciphering this book should pose no hindrance to me. Please, give me a moment and I will share what knowledge I can unlock from its pages.',
    `RequestItemsText` = 'Oh, $N! A pleasure to see you again. Tell me, has time been treating you well?'
WHERE `entry` = 41337;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Moonglade sending support is assuring to hear, young one. The turmoil we are facing should be the concern of us all, is it not perilous to ignore it.',
    `RequestItemsText` = 'Greetings, adventurer. To ensure our world''s continued existence, we accept anyone willing to assist.'
WHERE `entry` = 41338;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A spectre, you say? In the form of a white stag? If what your eyes witnessed is true, then we cannot idle around any longer!',
    `RequestItemsText` = 'The hill''s latent magic can even be felt by those not in tune with the wild. It attracting evildoers is something we cannot ignore.'
WHERE `entry` = 41339;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $C. Seeing you complete this task so quickly reassures me to not be doubtful of what I will be asking of you. You may be unaware, but my brethren and I are Malorne''s scions. It was his union with the Moon Goddess Elune that bore life to our father Cenarius - and he in turn created us. This is not only a concern for the safety of Mount Hyjal or even to my family, but also to all of Azeroth.',
    `RequestItemsText` = '$N! Arch Druid Dreamwind informed me about what transpired on Mount Hyjal. Do you have the dream shards with you?'
WHERE `entry` = 41340;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Setting eyes upon these powerful trinkets reminds mortals like you of the forces present in this world. While they may be beyond one''s comprehension, do not underestimate your role in all of this. Mortals have proven themselves time and time again to be vital in the alteration of fate on Azeroth. Everything you do has its consequences, either immediate or eventually.',
    `RequestItemsText` = 'A noble being like Malorne, whose love and care for nature precedes anything we know, must be protected.'
WHERE `entry` = 41341;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It is finished. The fear weighing heavy on my heart is fading after hearing from your valiant deeds. Using my ability to gaze into the Emerald Dream, I will return this fragment back to my grandfather. Simply holding it makes me feel his radiant and powerful aura once more.$B$BIt will take a considerable amount of time for him to regain his full strength, however Ysera and his fellow Wild Gods are at his side, protecting their beloved friend and mentor.$B$BYour devotion to the White Stag and his legacy is commendable. To honor your heroic and selfless nature, let me offer you the teachings to shift into Malorne''s stag form itself.',
    `RequestItemsText` = 'Don''t fret, use all your might to vanquish the Nightmare''s influence.'
WHERE `entry` = 41342;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A comically large candle. Are you a jokester?',
    `RequestItemsText` = 'What is it Mage?'
WHERE `entry` = 41343;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Big candle for Big Whiskers! My mission in this scary place is finished. Big Whiskers gives you this as thanks. Very fun book, look!',
    `RequestItemsText` = 'Where big candle?'
WHERE `entry` = 41344;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The seas rumble and a wave of dread washes over Azshara. Something emerges from the ocean!',
    `RequestItemsText` = 'The rudimentary altar emits a primal and unsettling aura. The troll lying next to it may be a grim indication of what powers it may hold. Still, it seems one could present some offerings on its rough surface...'
WHERE `entry` = 41345;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The chest opens and a wet odor escapes it. Inside you find some rusted trinkets - and a surprisingly immaculate piece of something broken. Picking it up, you feel a sense of danger coming from it. Harrowing.',
    `RequestItemsText` = 'This old chest blends into the interior of the cave almost seamlessly. The letter ŌĆśG'' is engraved atop the lock. Next to it, a tattered book, or rather what is left of it. Quickly glancing over it, you surmise this chest belonged to someone who lived here on the island. The last readable entry says something about getting some fish for today''s meal.'
WHERE `entry` = 41346;

UPDATE `quest_template` SET
    `OfferRewardText` = '<The blind drunkard is visibly intoxicated. Hiccups and burps are the only signs showing he is still with you. It appears he is almost at death''s door.>$B$BWhaddya want?! Can''t ya see that I am kinda busy ''ere?!',
    `RequestItemsText` = ''
WHERE `entry` = 41347;

UPDATE `quest_template` SET
    `OfferRewardText` = '<The search seems hopeless, surely this journal will not yield anything either.>',
    `RequestItemsText` = ''
WHERE `entry` = 41348;

UPDATE `quest_template` SET
    `OfferRewardText` = '<After a few minutes of hard work rummaging through the dirt, you come across a skeleton. Judging from the tusks, they are orcish remains. Two things catch your attention: A necklace, identical in appearance to the one Gorak described in his journal - this must be his mate Melar. Sadly it is not Tillia''s necklace. The other thing you notice is a ruined sword, broken, whether over time or in battle is unclear.>',
    `RequestItemsText` = '<The dirt mound looks suspicious, almost out of place. A relic of the past, hidden by the passage of time and untouched by mortal hands.>'
WHERE `entry` = 41349;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This sword is etched deep into my consciousness, something I cannot forget even if desired. Should your time allow it, let me tell you the story of my finest pupil.',
    `RequestItemsText` = 'Do you wish to have a fine blade forged for you? I am afraid I have to disappoint, my smithing days are over. A memory of this long forgotten place is all I am now.'
WHERE `entry` = 41350;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Tillia is speechless at the task you accomplished. Marveling at her long lost treasure, she regains her composure and begins speaking.>$B$BIncredible, positively stunning! You are a masterful detective, getting to the bottom of this decade-old conundrum in such a short time. Were I back at my estate, I would have my brother knight you into our personal entourage. But alas, I believe the thrill of the world is what beckons you, while my undeath binds me to this place. Fret not, however - with my necklace returned, I can endure this endless limbo in contempt.$B$BAs promised, you shall receive this in turn: a prized ruby ring by the lord of the tower himself, Guardian Medivh.',
    `RequestItemsText` = '$N! A pleasure to see you. Say, has your search been fruitful?'
WHERE `entry` = 41351;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This ring... is from my aunt Tillia? No, it... it can''t be. Auntie never parted ways with her jewelry, only those she cherished most were gifted with them. Does that mean...? Even after I stole her most favoured necklace from her... Stranger, how did you acquire this anyway?! Tillia went missing decades ago on her trip to the cursed tower of the guardian.$B$BIt makes no difference. Take your baubles and go. It is over for me either way, what good does an expensive ring bring me? Sell it, wear it, I don''t care. Just leave me in my misery.',
    `RequestItemsText` = '<He appears to be somewhat sober compared to the last time you met.>$B$BWho goes there?! Do I know you?'
WHERE `entry` = 41352;

UPDATE `quest_template` SET
    `OfferRewardText` = 'By Elune. I gather it was not chance that brought that item into your hands.',
    `RequestItemsText` = 'Leave me to my own. There is nothing here for you.'
WHERE `entry` = 41353;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Believe it or not, you have shown great kindness.',
    `RequestItemsText` = 'Whether Suffering or Anguished you must guide them.'
WHERE `entry` = 41354;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A most treasured item. One of the final relics of this once mighty city.',
    `RequestItemsText` = 'Was your quest fruitful or are you yet to fulfill your task?'
WHERE `entry` = 41355;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You once more succeed to fulfill your task. For whatever kin you have left, I do hope they feel pride when they think of you.',
    `RequestItemsText` = 'I sense you have braved foes stronger than these Giants. I doubt you require further council.'
WHERE `entry` = 41356;

UPDATE `quest_template` SET
    `OfferRewardText` = 'As every great wielder of the Arcane, Malygos has the thirst of knowledge and experiment. He infused his own mana into the ice of Northrend. Perhaps whatever may be closest to a ŌĆ£primordialŌĆØ birthplace of a possible elemental. That is to say, his foolish experiment didn''t end well. As you have seen, it did not look like an elemental. But a cold ruthless means of death.',
    `RequestItemsText` = 'That thing is better of destroyed.'
WHERE `entry` = 41357;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A fair concern. I owe you no explanation ŌĆō but I suppose Al''Dorel is different.',
    `RequestItemsText` = 'What brings you here?'
WHERE `entry` = 41358;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I- I am afraid I have to agree with her words to a degree. But to harbor such hatred and encourage genocide of entire races? My heart sinks.',
    `RequestItemsText` = 'What news?'
WHERE `entry` = 41359;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I dread the day I will have to fight one I called friend. Alas.$B$BKel''theril like many other Highborne settlements was filled with magic. Magic that was lost to the ages ŌĆō I am the last survivor of these lands that have yet to flee it. I have had these draconic artifacts ever since the lake swallowed my home. Take one, it is yours now. Something to remind you of me. Until we meet again.',
    `RequestItemsText` = 'I wish we would have met in better circumstances.'
WHERE `entry` = 41360;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Blood of the Mountain! Getting your hands on one of those beauties has been really difficult, ever since Thaurissan''s loyalists took control over all mining operations in and around the Blackrock. And this one seems to be a special kind...',
    `RequestItemsText` = 'Stranger, you better be here for a good reason.'
WHERE `entry` = 41361;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I appreciate the effort, $N. This was definitely not an easy task, yet you provided me with such quality materials in no time at all.$B$BGemstones like the Blood of the Mountain require an extraordinary amount of precision and patience. Just the tiniest bit of unnecessary pressure and the entire jewel cracks in two. Watch closely, for I have only one chance to teach you. You can keep the gemstone once I''m done. See it as thanks for bringing me such a peculiar example of a gem.',
    `RequestItemsText` = 'The Dark Iron pride themselves on their mastery over the mountain''s body. Seldom has anyone else shown such expertise in manipulating Dark Iron ore and the countless unique gemstones found within its crust.'
WHERE `entry` = 41362;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Intriguing. These samples radiate a magic not unfamiliar to me, on first glance I''d even say they emanate druidic magic. Ofcourse, I shouldn''t jump to conclusions. Further research within the Cenarion Circle will be needed. Surely their venerable druids can solve the origin of their volatile growth.$B$B$N, you have my appreciation. Please, take one of these as compensation for your troubles.',
    `RequestItemsText` = 'Be careful. Not only is this den of nightmares highly dangerous, but also your journey through Horde territory.'
WHERE `entry` = 41363;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So the Shadowfang Keep will soon be raided. Good. While you''re here, you wouldn''t mind doing me a favor, would you?',
    `RequestItemsText` = 'We do our mistress'' bidding.'
WHERE `entry` = 41364;

UPDATE `quest_template` SET
    `OfferRewardText` = 'While the living are now seen as a threat, his death was unjustifiable. It needed to be done...$B$BI will mourn you for the rest of my days, William.',
    `RequestItemsText` = 'Speak your piece.'
WHERE `entry` = 41365;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I hope his soul may find its peace in the Light once more.',
    `RequestItemsText` = 'A tragic fate.'
WHERE `entry` = 41366;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The darkness of the nightmare loomed over my on thoughts, breaking free emotions that I would usually keep in check. In a way, I regret it has come to this.$B$B<Nalpak sets Zandara''s head on the ground.>$B$BA job well done, is a job well rewarded. You have my thanks $N.',
    `RequestItemsText` = 'One nightmare after the other.'
WHERE `entry` = 41367;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Precious, these notes are. Very precious. I doubt it''d cripple the Scarlets from making more lightforge armor at this point, but at least it''s back in my hands.',
    `RequestItemsText` = 'Don''t worry about Daghelm''s death, he''s most likely a psychotic zealot by now.'
WHERE `entry` = 41368;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Terrifying. Even if these are only remains from a volatile elemental, the sheer pressure coming from it is overwhelming. With this fount of energy, I will be able to combine the rod and the binding together, recreating the Scepter Rod of Medivh. Though now restored, it is still incomplete. The scepter head is missing; where to find it, however, is beyond my knowledge. Shall it fall in your possession, speak to me again, and I will do my best to aid you again.',
    `RequestItemsText` = 'Karazhan is built atop a focal point of ley lines. The beings inside the spire draw from that connection and gain insurmountable strength from that. Be wary.'
WHERE `entry` = 41369;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I am trembling at the sight of the guardian''s essence, that you were able to carry it here is a testament to your mental resilience and physical prowess. Now that all pieces are assembled, restoring the scepter will take but a few moments. Please take a step back, unstable energies and raging magics are expected to erupt during the process.',
    `RequestItemsText` = 'We stand before a fundamental moment in history.'
WHERE `entry` = 41370;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I''ve never seen anything like this gemstone before. The teal color, its structure and surface are incomparable to anything here on Azeroth. Yet again I am amazed by the lengths you go for in search for the truth. Now, let us finish this at last.',
    `RequestItemsText` = 'Think about the place I saw in my vision. Perhaps what you heard reminded you of something or someone you met on your journey already.'
WHERE `entry` = 41371;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I entrust you with the Scepter of Medivh, conduit of ley magic and the primal energies of an alien world. With it you may command the violent magical torrents of Karazhan itself. Don''t get complacent; while you are certainly powerful, the scepter'' former owner is the only person to properly wield it. Nevertheless, the deepest secrets of the accursed tower now lay at your feet, begging to be unveiled by the one strong-minded enough to brave its treacherous reaches.$B$BGo forth and claim the truth you fought so valiantly for! Let the conquest of Karazhan be one of the milestones of your heroic legacy!',
    `RequestItemsText` = 'Let us not wait too long. We don''t want to let the magic remain untamed.'
WHERE `entry` = 41372;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, "Recipes of Kezan" by none other than Gastino, where''d you find that?',
    `RequestItemsText` = 'Is everything to your liking, dear guest?'
WHERE `entry` = 41373;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A crumbled piece of paper. It''s sad to see it reduced to this, no matter what. I will restore it for you, as holding it made me remember it.',
    `RequestItemsText` = 'Did you find what you seek?'
WHERE `entry` = 41374;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Are you mocking me? This looks like something a child wroŌĆō$B$B<Lydros stares silently into thin air for a few moments.>',
    `RequestItemsText` = 'You seem to carry something that caught your eye. Let me see it.'
WHERE `entry` = 41375;

UPDATE `quest_template` SET
    `OfferRewardText` = 'And there we have it, with the glyph complete it can now be used. As to whether you choose to or not, remains up to you.',
    `RequestItemsText` = 'A certain nostalgia flows through my bones.'
WHERE `entry` = 41376;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, the fabled Scythe of Elune has been found. Dreamwind has been wise to send you to me, even if his efforts to heal Hyjal are misguided.',
    `RequestItemsText` = 'What is it?'
WHERE `entry` = 41377;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Impressive. Now, give the blood to me. I will prepare what is needed.',
    `RequestItemsText` = 'It is imperative that the Scythe is cleansed.'
WHERE `entry` = 41378;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Pure worgen blood, just like Ur described... Yes, this will be very useful. But now listen, as I have much to share.',
    `RequestItemsText` = 'You''ve returned.'
WHERE `entry` = 41379;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, the fabled Scythe of Mu''sha has been found. This Arch Druid Dreamwind has been wise to send you to me.',
    `RequestItemsText` = 'Yes, child?'
WHERE `entry` = 41380;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Exquisite work, as always. Now, hand it to me.',
    `RequestItemsText` = 'Scythe of Musha must be cleansed.'
WHERE `entry` = 41381;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Pure worgen blood, just like Ur described. Yes, this will be very useful. They were once the favourite children of Elune, and to have their uncorrupted blood... It will be the key during the ritual...  But now listen, as I have much to share.',
    `RequestItemsText` = 'You''ve returned.'
WHERE `entry` = 41382;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So now you know. We don''t have much time left. You must find them, so that the Scythe can be cleansed.',
    `RequestItemsText` = 'Time is of the essence.'
WHERE `entry` = 41383;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The foul pricolich Gnarlmoon is dead! Impressive indeed. You have saved us all.',
    `RequestItemsText` = 'Do not hesitate.'
WHERE `entry` = 41384;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Father Lycan... A name steeped in shadows, yet one that may hold the key to our salvation. This journal you''ve unearthed, while enigmatic, could be the catalyst for unlocking the truth behind his sinister presence. Let us delve into Ur''s teachings once more, for within lies the wisdom to decipher this mystery.',
    `RequestItemsText` = 'I cannot leave Nordrassil, not yet.'
WHERE `entry` = 41385;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The vile pricolich Lycan is dead! You stopped him and avenged Velinde!',
    `RequestItemsText` = 'Is it done?'
WHERE `entry` = 41386;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Ironvine Root is an aggressive plant. When uprooted it clings around its captor, trying to drag it to the ground, ultimately wearing them down. You, however, did not bend to this natural force. Your mind was clear, your will iron. The last person to pass this test was my apprentice Sakgoth, many years ago. Perhaps I have found someone extraordinary in you. The upcoming trials will tell if I am correct in my assumption.$B$B<Mathias takes a dagger and with a swift cut you almost couldn''t see, he removes the gripping vines from your body.>$B$BWe shouldn''t let it get to waste, you can brew excellent tea with this root.',
    `RequestItemsText` = 'This ordeal will show me if you got what it takes.'
WHERE `entry` = 41387;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Commendable. Taking these lessons to heart is imperative for your future success on this road you''ve taken.',
    `RequestItemsText` = 'No lesson is the same. Comprehending the connection between them and the mistakes made allows you to grasp their wisdom.'
WHERE `entry` = 41388;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The master is an enigmatic man, and I will most likely never fully understand the ways of his mind. Luckily that''s not what we are here for, right?$B$BThis pearl you brought, truly something else. Every student of the master''s receives a personal gift from him - and technically me - as proof of their accomplishments. Mine is the stinger of a scorpid I''ve slain in the Thousand Needles. And for you... what do you think of a pendant?',
    `RequestItemsText` = 'Just what happened up there? It smells like burned flesh in there.'
WHERE `entry` = 41389;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Renzik sent you? Good. I could use a bit more manpower.',
    `RequestItemsText` = ''
WHERE `entry` = 41390;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Jared Voss? I hate that this name rings several bells. If what is in this document is true, then we should make haste immediately.',
    `RequestItemsText` = 'Back so soon? I hope not with empty hands...'
WHERE `entry` = 41391;

UPDATE `quest_template` SET
    `OfferRewardText` = 'By the mines of Kezan! This smells horrible. One whiff of it and any grown sailor will fall over in a heartbeat. $N, excellent job. While we were able to secure this end of the operations, we still have to investigate where exactly they''re getting all the supplies from, as I am sure the Venture Co. is simply a middle man. Still, so far you did great and for that I''ve got a reward for you. Stay clear of trouble, adventurer, wouldn''t want to see you getting killed.',
    `RequestItemsText` = 'Don''t waste time. I''m not as patient as Master Shaw.'
WHERE `entry` = 41392;

UPDATE `quest_template` SET
    `OfferRewardText` = '<The giant''s eye is incredibly hot, yet it matters little to Mathias. Sizzling noises erupt from his hand while he inspects the stone you brought him. After having marveled at it long enough, Mathias dunks it into a nearby water bucket, filling the room with steam. The steam clears, and what you see in his burned hand is an immaculate glass marble.>$B$BSuch an interesting material. I''ve always wanted to get my hands on one of these, just to experience their intense heat. Impressive work, $N. You''ve proven yourself to me. Welcome to the fold.',
    `RequestItemsText` = 'Do not falter now.'
WHERE `entry` = 41393;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The soul of a Dreadlord... Everything seems to be in order. Now, it''s time to cleanse the Scythe of Elune!',
    `RequestItemsText` = 'Have you found the materials needed yet?'
WHERE `entry` = 41394;

UPDATE `quest_template` SET
    `OfferRewardText` = '<You place the three shards inside the empty spaces and after a short clicking noise, a lid opens underneath. Within you find a singular, ordinary gemstone.>',
    `RequestItemsText` = '<There are three indentations in the shape of a rhombus.>'
WHERE `entry` = 41395;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These will do just fine. Alongside these potent mushrooms, I can create an exceptionally powerful dreamveil for you. Without it I fear you may be pulled into the Dream prematurely, without ever being able to return. Now brace yourself, $N. For you to be granted Dreamsight, you will be seeking an audience with one of the oldest green dragons known to Azeroth.',
    `RequestItemsText` = 'It may be within my abilities to peer into the Emerald Dream, but those boons only affect myself - it cannot sadly be used for others. Fret not, however. I will assist you wherever I can.'
WHERE `entry` = 41396;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I see. As solemn as it is, Vithekus'' disdain is understandable. An ancient being like himself can all so easily be swayed from his benevolence after witnessing the misdeeds of mortals throughout the eons. Still I had hoped he would continue to see the potential your people hold.$B$BNevertheless, knowing he can be reasoned with and did not fall victim to the Nightmare lifts a burdening worry from my heart.',
    `RequestItemsText` = 'It concerns me to not have heard of Vithekus for so long. I wish for his safety, the Dream is no longer the sanctuary that it used to be.'
WHERE `entry` = 41397;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Tranquility sets upon the Twilight Grove. The Nightmare has been fended off once more, but for how long, no one can tell. Your heart tells you the battle for the Emerald Dream is not yet over, yet you find solace in knowing its stalwart defenders will continue the righteous battle. In front of you towers arguably nature''s greatest force. The teal fur, glistening like a starlit sky; his eyes reflecting a deep blue sea of infinite wisdom. You expect the force of his power to crush you, but instead that all so familiar warmth, like a sunny breeze gliding over dew laden grass in the morning, washes over you.$B$BTurning your eyes upwards, your gaze meets the demigod''s and a feeling of power rushes through your body. An incomparable sensation; of growth, appreciation and love. As quickly as it came, so did it vanish. Feeling reborn, you pay your respects to the Waywatcher before leaving him to his duties.>',
    `RequestItemsText` = '<The great stag stares at you, instilling awe in your very being. You stand before a demigod.>'
WHERE `entry` = 41398;

