UPDATE `quest_template` SET
    `OfferRewardText` = 'This ring is infused with the power of my ancestors! Tread wisely...',
    `RequestItemsText` = 'Have you brought me that which I require?'
WHERE `entry` = 41517;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A wise contribution. This text will be of ample use for the master. As for your reward, take this book; a summary of the master''s knowledge he amassed over the years. Once you are done studying, return it to Nora upstairs.',
    `RequestItemsText` = 'Nothing in this world is free. Your growth has to be earned.'
WHERE `entry` = 41518;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Pandaren? Yes, I heard about them, but many consider them a legend, or a fairytale for the kids. But I heard from some very credible people that they actually exist!$B$BThat''s not really important, right? You want to know more about the art of staff fighting. Not my strongest suit for sure... Master Mathias could tell you more, but his time is very valuable, so you have to prove yourself! And actually, I have an amazing idea how you can earn his respect!',
    `RequestItemsText` = 'Greetings! I am usually busy deciphering these old texts Sakgoth is bringing me, but I got a moment to spare.'
WHERE `entry` = 41519;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Are my eyes deceiving me? No, they cannot be. It is indeed the staff of the legendary Chen StormstoutŌĆöbrewmaster, warrior, and a friend to many. So, it seems the old tales were true after all. Well done, $N.$B$BNow, considering the effort you''ve put into recovering this relic, it would be a travesty to simply shelve it, don''t you think? So, let''s see what secrets it holds. Shall we?',
    `RequestItemsText` = 'Pupil, a pleasure to see you hard at work. Nora told me all about it. Did you finish the task she sent you out to do?'
WHERE `entry` = 41520;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A wise contribution. This text will be of ample use for the master. As for your reward, take this book; a summary of the master''s knowledge he amassed over the years. Once you are done studying, return it to Nora upstairs.',
    `RequestItemsText` = 'Nothing in this world is free. Your growth has to be earned.'
WHERE `entry` = 41521;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Mastery of throwing weapons? Why on Azeroth would you want to focus on that?$B$B<She eyes you, surprised and curious.>$B$BWell, I have to be honest with you. I''ve never spent much time on understanding the intricacies of thrown weapons. I just never felt it was worth the effort. So, I can''t really help you with it myself. However, with direct tutoring from Master Brightheart, we could get you up to speed in no time!$B$BI can arrange a private lesson with him for you, but there''s a catch. You''ll have to help us in return!',
    `RequestItemsText` = 'Greetings! I am usually busy deciphering these old texts Sakgoth is bringing me, but I got a moment to spare.'
WHERE `entry` = 41522;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Mathias Brightheart studies the axes carefully>$B$BAh, you may be wondering what makes these axes so special. To the untrained eye, they may seem like ordinary throwing axes, perhaps a bit larger. But there is more to them than meets the eye.$B$BObserve how perfectly balanced they are, right at the midpoint of the hilt. The Amani, a truly ingenious tribe, mastered the art of balancing these axes so precisely that they spin rapidly and unpredictably in flight, making them nearly impossible to dodge or parry. Countless elven lives have been claimed by these weapons, and many more will fall to their deadly precision...$B$BBut I digress. You have done well to recover these for me. Now listen closely, for I will not repeat myself!',
    `RequestItemsText` = 'Pupil, a pleasure to see you hard at work. Nora told me all about it. Did you finish the task she sent you out to do?'
WHERE `entry` = 41523;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A wise contribution. This text will be of ample use for the master. As for your reward, take this book; a summary of the master''s knowledge he amassed over the years. Once you are done studying, return it to Nora upstairs.',
    `RequestItemsText` = 'Nothing in this world is free. Your growth has to be earned.'
WHERE `entry` = 41524;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Effective and loudŌĆōwhy yes, that would be a gun. What got you so curious?',
    `RequestItemsText` = 'Greetings! I am usually busy deciphering these old texts Sakgoth is bringing me, but I got a moment to spare.'
WHERE `entry` = 41525;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Powder from the Blackrock Mountain, exquisite. Its explosive power is more destructive than usual. So, how was it, facing someone with a gun?$B$B<Mathias frowns at your answer.>$B$BHe used an axe and hounds to fight? How disappointing, I will have to scold Nora later. It matters not, come pupil let me give you that which you crave for.',
    `RequestItemsText` = 'Pupil, a pleasure to see you hard at work. Nora told me all about it. Did you finish the task she sent you out to do?'
WHERE `entry` = 41526;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A wise contribution. This text will be of ample use for the master. As for your reward, take this book; a summary of the master''s knowledge he amassed over the years. Once you are done studying, return it to Nora upstairs.',
    `RequestItemsText` = 'Nothing in this world is free. Your growth has to be earned.'
WHERE `entry` = 41527;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Mastery of Crossbows, yesŌĆ” Very technical literature. Can''t blame you for not grasping its lessons right away - took me two years of study to understand Master''s intellectual meanderings. But I guess you don''t really have that much timeŌĆ” Of course! What about doing Master Brightheart a favor? Arranging a meeting with him afterwards for some personal training would be definitely possible. With direct tutoring you could be one step closer in mastering the crossbow.$B$BComing back to that favor; I reckon you''re familiar with the Scarlet Crusade?',
    `RequestItemsText` = 'Greetings! I am usually busy deciphering these old texts Sakgoth is bringing me, but I got a moment to spare.'
WHERE `entry` = 41528;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What a tragic decision to join the Scarlet Crusade. Talent like his would''ve been more useful elsewhere, but that is irrelevant now. I reckon you disposed of him? Oh, don''t give me that look. His fate was sealed, and Willey knew that as well. While I wish he could tell me his family secrets in person, I am no fool to think he''d ever agree to that. So for now, this beautiful crossbow must suffice - and what a beautiful one this is. I will have a great time analyzing it thoroughly. Now for your reward - shall we begin?',
    `RequestItemsText` = 'Pupil, a pleasure to see you hard at work. Nora told me all about it. Did you finish the task she sent you out to do?'
WHERE `entry` = 41529;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A wise contribution. This text will be of ample use for the master. As for your reward, take this book; a summary of the master''s knowledge he amassed over the years. Once you are done studying, return it to Nora upstairs.',
    `RequestItemsText` = 'Nothing in this world is free. Your growth has to be earned.'
WHERE `entry` = 41530;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh! Mastery of Bows - yes, I know that one very well. A heavy topic among the ranged weapons, considering the bow is older than its younger counterpart, the gun. Many civilizations, especially those not prolific in magic, have this weapon ingrained in their culture. Still, before I digress too much into the finer details - you seek assistance with understanding the essence of one of the master''s compendiums?$B$BI''m afraid I''m not the most suitable person to help you, given that I lack the practical prowess to demonstrate the teachings to you. And the master is incredibly busy, as you surely knowŌĆ” But I think I can help with that, if you assist us in turn.',
    `RequestItemsText` = 'Greetings! I am usually busy deciphering these old texts Sakgoth is bringing me, but I got a moment to spare.'
WHERE `entry` = 41531;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh! What a marvelous weapon you carry. Nora told me all about it. Time has gnawed heavily upon this weary thing, but with a few touch ups here and there, it will regain its strength to be properly wielded yet again. Where do you say you found it? On a Highborne specter in the Ruins of Dire Maul? How thrilling, please tell me all about it once we are done with the training.$B$BNow then, listen well. You will not get another chance to be tutored about this. You earned my time and I value it highly - don''t disappoint me!',
    `RequestItemsText` = 'Pupil, a pleasure to see you hard at work. Nora told me all about it. Did you finish the task she sent you out to do?'
WHERE `entry` = 41532;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A wise contribution. This text will be of ample use for the master. As for your reward, take this book; a summary of the master''s knowledge he amassed over the years. Once you are done studying, return it to Nora upstairs.',
    `RequestItemsText` = 'Nothing in this world is free. Your growth has to be earned.'
WHERE `entry` = 41533;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You believe polearms to be neglected as a weapon? Bah, you''re starting to sound like the master more and more.',
    `RequestItemsText` = 'Greetings! I am usually busy deciphering these old texts Sakgoth is bringing me, but I got a moment to spare.'
WHERE `entry` = 41534;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Was it ridiculous to fight a large opponent wielding a smaller armament? I doubt itŌĆōafter all, I believe you have now seen that the polearms are getting the respect they deserve. Come pupil, I will tell you the story of the Dancing Spear and afterwards I will teach you the dance.',
    `RequestItemsText` = 'Pupil, a pleasure to see you hard at work. Nora told me all about it. Did you finish the task she sent you out to do?'
WHERE `entry` = 41535;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A wise contribution. This text will be of ample use for the master. As for your reward, take this book; a summary of the master''s knowledge he amassed over the years. Once you are done studying, return it to Nora upstairs.',
    `RequestItemsText` = 'Nothing in this world is free. Your growth has to be earned.'
WHERE `entry` = 41536;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A hard potion to swallow that one, isn''t it? To both condemn and praise a being almost in perfect balance. It may make you question the concept of right and wrong, wouldn''t it? Well, it shouldn''t. Remember that the purpose of the book is connected to the skills of warŌĆōthe fact it vilifies Marduk to that point is already something noticeable and out of place.$B$BClose your heart to it, and open your mind to your next task.',
    `RequestItemsText` = 'Greetings! I am usually busy deciphering these old texts Sakgoth is bringing me, but I got a moment to spare.'
WHERE `entry` = 41537;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A good deed, one that I will reward with my teachings. A welcomed justice for the people of Darrowshire was served, one that I dearly hope brings them some peace. Nora will handle the runeblade, you should not concern yourself with it further. Now, ready your arms pupil, I will not hold back.',
    `RequestItemsText` = 'Pupil, a pleasure to see you hard at work. Nora told me all about it. Did you finish the task she sent you out to do?'
WHERE `entry` = 41538;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A wise contribution. This text will be of ample use for the master. As for your reward, take this book; a summary of the master''s knowledge he amassed over the years. Once you are done studying, return it to Nora upstairs.',
    `RequestItemsText` = 'Nothing in this world is free. Your growth has to be earned.'
WHERE `entry` = 41539;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Truly our dwarven cousins have a grand admiration for hammers. But I am afraid that legend is just a legendŌĆōuntil proven otherwise of course.',
    `RequestItemsText` = 'Greetings! I am usually busy deciphering these old texts Sakgoth is bringing me, but I got a moment to spare.'
WHERE `entry` = 41540;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I suppose you could tell Nora was acting a tad personal when it came to the High Foreman, but if she didn''t share her story I most certainly won''t. You did well to return Fingerbreaker. Let us begin our lesson and afterwards you may tell me how Bargul was with that hammer.',
    `RequestItemsText` = 'Pupil, a pleasure to see you hard at work. Nora told me all about it. Did you finish the task she sent you out to do?'
WHERE `entry` = 41541;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A wise contribution. This text will be of ample use for the master. As for your reward, take this book; a summary of the master''s knowledge he amassed over the years. Once you are done studying, return it to Nora upstairs.',
    `RequestItemsText` = 'Nothing in this world is free. Your growth has to be earned.'
WHERE `entry` = 41542;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I was wondering when you were going to find that one. Believe it or not it is a favourite of the master. You would believe that not to be the case given the history between humans and orcs. Alas, the master sees beyond the concept of race, after all to him there is only the mastery of war.$B$BAre you ready for a humble pilgrimage?',
    `RequestItemsText` = 'Greetings! I am usually busy deciphering these old texts Sakgoth is bringing me, but I got a moment to spare.'
WHERE `entry` = 41543;

UPDATE `quest_template` SET
    `OfferRewardText` = 'An ominous yet symbolic gift. Does his battle spirit still echoes that canyon? Ah, I often dream of meeting him in battle. Ready your weapon pupil, and learn. I will honour you as a warrior as you honoured a warrior of the past.',
    `RequestItemsText` = 'Pupil, a pleasure to see you hard at work. Nora told me all about it. Did you finish the task she sent you out to do?'
WHERE `entry` = 41544;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A wise contribution. This text will be of ample use for the master. As for your reward, take this book; a summary of the master''s knowledge he amassed over the years. Once you are done studying, return it to Nora upstairs.',
    `RequestItemsText` = 'Nothing in this world is free. Your growth has to be earned.'
WHERE `entry` = 41545;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''re an amusing sort $N. Your fists against the world, eh? Admirable...',
    `RequestItemsText` = 'Greetings! I am usually busy deciphering these old texts Sakgoth is bringing me, but I got a moment to spare.'
WHERE `entry` = 41546;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A mighty legend among the elves of Kalimdor. You show great spirit taking on it with nothing but your fists! Come, let us spar--perhaps I can teach you something new.',
    `RequestItemsText` = 'Pupil, a pleasure to see you hard at work. Nora told me all about it. Did you finish the task she sent you out to do?'
WHERE `entry` = 41547;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A wise contribution. This text will be of ample use for the master. As for your reward, take this book; a summary of the master''s knowledge he amassed over the years. Once you are done studying, return it to Nora upstairs.',
    `RequestItemsText` = 'Nothing in this world is free. Your growth has to be earned.'
WHERE `entry` = 41548;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Quite the odd one, right? The master''s a knowledgeable man even beyond the art of war. Even I was astonished by the range of anatomical research I could find within this book. Still, theory is certainly fine, but what does it accomplish if not applied into practice? Luckily - well, lucky may not be the proper word to use in a situation like this - I can make sure the master teaches you the practical aspects of his work, if you assist us in a more delicate matter.',
    `RequestItemsText` = 'Greetings! I am usually busy deciphering these old texts Sakgoth is bringing me, but I got a moment to spare.'
WHERE `entry` = 41549;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You look lively, considering the place you''ve been to to get your hands on this. I expect this Damian to have been quite skilled with daggers, a shame his delusions and frail mind rendered him into an abomination. My gratitude for removing this pustule from our world. Aberrations like him cannot be allowed to wreak havoc, neither now nor in the future. I expect you to continue assisting in keeping Azeroth a safer place. Now then, join me - let us take a look at what those beauties can do.',
    `RequestItemsText` = 'Pupil, a pleasure to see you hard at work. Nora told me all about it. Did you finish the task she sent you out to do?'
WHERE `entry` = 41550;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I knew you wouldn''t forget my teachings that easily. Still, the renewal was very much needed. An art as intricate as Goldsmithing cannot be mastered unless one focuses on it entirely. I am grateful for your continued interest in this ancient craft, my pupil. May you find enlightenment in it.',
    `RequestItemsText` = ''
WHERE `entry` = 41551;

UPDATE `quest_template` SET
    `OfferRewardText` = '<You kneel down and his stony palm gently touches your forehead. In an ecstatic rush of power, all the basic knowledge you acquired by his teachings long ago come rushing back to you.>',
    `RequestItemsText` = ''
WHERE `entry` = 41552;

UPDATE `quest_template` SET
    `OfferRewardText` = 'If that bloody bastard thinks he can one-up me, he can think again! Once I have formulated the recipe for the perfect brew, he can come here and kiss my boot!',
    `RequestItemsText` = ''
WHERE `entry` = 41553;

UPDATE `quest_template` SET
    `OfferRewardText` = 'If that bloody bastard thinks he can one-up me, he can think again! Once I have formulated the recipe for the perfect brew, he can come here and kiss my boot!',
    `RequestItemsText` = ''
WHERE `entry` = 41554;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Aha! There it is, the elusive Razorfen Grog. Pass it over, I''ll give it a thorough test.$B$B<Hal''togg uncorks the bottle and takes a deep whiff of the ale''s scent. He grimaces, but quickly regains composure. Putting the bottle to his lips, he takes a small sip of the alcohol.>$B$BYes, ofcourse. This is definitely brewed with briarthorn, it has the same distinct flavor. But something is different. Perhaps?',
    `RequestItemsText` = 'I sure hope they don''t brew it from briarthorn; I once tried it myself and it was absolutely horrible!'
WHERE `entry` = 41555;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes! These are nice and hot, perfect for stoking the fire. I will keep these for now and use them at a later point; right now we have more urgent things to do!',
    `RequestItemsText` = 'That I would learn brewing techniques from Quilboar is something I wouldn''t have expected to happen today.'
WHERE `entry` = 41556;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You really found it! A legendary schnapps, rarely seen or tasted by the outside world. Let''s give it a try!$B$B<A deep chug and half of the schnapps is missing. Hal''togg''s green face turns slightly red. This brew seems to be a kicker!>$B$BWow, this drink surely packs a punch, now I know why they say it fires you up. A burning taste combined with a sweet aftertaste. If I didn''t know better I''d say they mixed a special sort of hops into it. Finding out which type of hops they used might be difficult however...',
    `RequestItemsText` = 'These zealots protect their secrets viciously, but we are even more vicious in our quest for the ultimate brew.'
WHERE `entry` = 41557;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, I remember their distinctively strong smell. The earthy tones will perfectly compliment my other ingredients once I brew it at a high enough temperature.',
    `RequestItemsText` = 'Any luck with the Silver Hops?'
WHERE `entry` = 41558;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Very good. I''m tempted to try chewing one myself, but luckily my voice of reasoning is loud enough to prevent me from doing it.',
    `RequestItemsText` = 'Chewing hops. Ugh.'
WHERE `entry` = 41559;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Saying they are smoky was an understatement. Such a potent aroma. I''ll tell you what, $N, we might''ve struck gold with this one!',
    `RequestItemsText` = 'Their living conditions may cause them to be brittle, care on how you handle them.'
WHERE `entry` = 41560;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Runn Tum Tubers! At last, the final ingredient for my magnum opus. Quickly, hand them over.$B$B<Hal''togg cuts up the roots and throws them into his distillery. The intense heat of the apparatus causes the tubers to quickly cook, adding their unique flavour to the mixture. The brew turns into a dark, golden hue, exuding a strong scent you''ve never smelled before.>$B$BAha, Success! $N, we''ve done it; we''ve created the perfect brew! Once the distillat cooled down, you''ll be the first person to taste my greatest creation! You have my thanks, friend. Together we''ve shown that the dwarves are not the so-called masters of ale that they think they are! Cheers!',
    `RequestItemsText` = 'I cannot contain my excitement. My year long endeavors will finally bear fruit!'
WHERE `entry` = 41561;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ouch! These are quite spiky, how peculiar. Just their soft texture and lovely fragrance tell me these will have a strong sweet taste, perfect!',
    `RequestItemsText` = 'Any luck with the Yellow Hops?'
WHERE `entry` = 41562;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, nothing like the rich smell of a freshly picked bundle of hops! Great work out there.',
    `RequestItemsText` = 'I once tried Lordaeron Ale. Oh boy, let me tell you, the fight that followed was a nasty one.'
WHERE `entry` = 41563;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Thaldon takes a deep whiff of the uprooted hops. He looks ecstatic.>$B$BWhat a dream, with this at hand I cannot lose!',
    `RequestItemsText` = 'The soil of the Hinterlands is fertile, which makes for a sturdy and durable plant.'
WHERE `entry` = 41564;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent, let me try it immediately!$B$B<Thaldon pours the magical water into this distillery, turning the dark brown beverage into a sparkling golden brew.>$B$BIncredible, simply amazing! My brew will reach unmatched heights of taste and texture!',
    `RequestItemsText` = 'Some may brand me a heretic for putting elemental water into my ale, but to those I say: You lack vision!'
WHERE `entry` = 41565;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good samples, I will have them added into my mixture and tell you if anything changed. Their scent alone is giving me a good feeling about it!',
    `RequestItemsText` = 'The Arathi Highlands are a place with lots of Goldthorn vegetation, if you''re a skilled herbalist you could pick your own in its vast fields and hills.'
WHERE `entry` = 41566;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My plans, completely torn apart! I hope Blackbreath got what he deserved for disrespecting the result of year long hardship, blood, sweat and tears! Luckily I can still read the important parts of the formula. Thank you, $N. I know you risked hide and hair going into that accursed mountain for me. With these back in my possession, we are finally at the end of the journey.',
    `RequestItemsText` = '<Thandol is murmuring unintelligible curses into his beard.>'
WHERE `entry` = 41567;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Thandol''s eyes widen in bewilderment at the sight of the Golden Hops.>$B$BYou''ve found it! You''ve really found it! This is a once in a lifetime occurrence, $N. The Thunderbrew Golden Lager will become the ultimate brew with just a few small sprinkles of this legendary hops. Friend, I cannot thank you enough. Through your courage and resilience, I was able to realize my family''s century old endeavor of creating the perfect ale. It is only fair for you to be the first to taste my magnum opus. Once my distillery cooled down and I tapped the first pint, you''ll be able to taste a beer worthy for the Creators!',
    `RequestItemsText` = 'We are this close to achieve something of magnanimous gravity! I will go down in history as the creator of the legendary, ultimate ale!'
WHERE `entry` = 41568;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now that''s what I call a boogy!',
    `RequestItemsText` = 'You better start shuffling your feet.'
WHERE `entry` = 41569;

