UPDATE `quest_template` SET
    `OfferRewardText` = 'What a horrid prospect. To think we stood at the precipice of another invasion by the Burning Legion. $N, your actions and those of your compatriots did not only save Azeroth from another war, but also quelled the threat of one of the most powerful dreadlords known to us. Second to only Tichondrius, the harbinger of the LegionŌĆÖs invasion seven years ago, legends of his might circulated the Council of Six in Dalaran. Unimaginable to see such a commanding figure finally meet its demise.$B$BYou were correct in bringing his vile heart to me. I am able to burn the fel essence from its flesh, albeit very taxing for my body. That is but a small sacrifice, however. Nothing is too little when given the opportunity to remove such a putrid presence from our world. Whatever remains of this, you can keep. As a trophy; a remembrance of the feat you accomplished this day.',
    `RequestItemsText` = 'This horrible stench! $N, what have you brought with you?!'
WHERE `entry` = 41577;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Behold, your reward awaits: the crown, forged anew and ready to serve you in battle.',
    `RequestItemsText` = 'Gathering the materials shall be no easy task.'
WHERE `entry` = 41578;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The item is restored and improved. May it serve you well in battle.',
    `RequestItemsText` = 'You must obtain the required materials if you wish to wield the power of this item.'
WHERE `entry` = 41579;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Don it with pride; you have more than earned it.',
    `RequestItemsText` = 'Whatever the cost, it will be worth it.'
WHERE `entry` = 41580;

UPDATE `quest_template` SET
    `OfferRewardText` = 'May they serve you well until death claims you.',
    `RequestItemsText` = 'Trust in yourself to find the materials; you must do so if you wish for us to continue.'
WHERE `entry` = 41581;

