UPDATE `quest_template` SET
    `OfferRewardText` = 'About time, I was gettin'' scared, thought I might''a lost em!$B$BThey are a bit more dirty than I remember though, for muckin'' up my tools yer gonna get a silver less, no hard feelings!',
    `RequestItemsText` = 'You got em yet? Or you just waitin'' around?'
WHERE `entry` = 55000;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Finally, I was devising a plan but all I could come up with was a flame thrower and a bomb. Big no-nos if ya know anything about oil safety!$B$BIt might not be ALL of em, but a few less of the seafood is good enough for me!',
    `RequestItemsText` = 'You get rid of them yet? Time''s tickin'' here and I need that platform up and running!'
WHERE `entry` = 55001;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You the new delivery kid from Razor Hill? Didn''t really think that old orc would get the order here that quick. You better not tell him we''ve just been giving him flak! He might start to think he''s doing too good a job, or something!',
    `RequestItemsText` = 'What, was there anything that I could help with?'
WHERE `entry` = 55002;

UPDATE `quest_template` SET
    `OfferRewardText` = '<The goblin quickly tinkers with the acquired scales>$B$BThe energy in these babies is off the chart! My hunches were correct, maybe this will work!$B$BOh, my chances of gettin'' promoted to Head Technician just went up, about fifteen percent for sure!',
    `RequestItemsText` = 'Find those lizards yet? I said they were at Thunder Ridge!'
WHERE `entry` = 55003;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Hargosh takes his time preparing the food, and begins to cook with an utmost determination. The aroma and smell starts as something horrific, but begins to turn pleasant as the fire cooks. Soon enough, the orc takes a bite from his creation.>$B$BMmn... Yes... Hah! This will do just the trick. The kick is strong in this, just like an orcish axe! You''ve done me a service, here.',
    `RequestItemsText` = 'Have you gathered everything I need yet?'
WHERE `entry` = 55004;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Nice job. He actually built the shredder, you say?$B$BGuess he was always smarter than he looked. I almost gave up on you and was about to put up a bounty. You can have the bounty reward instead.',
    `RequestItemsText` = 'Any luck finding him?'
WHERE `entry` = 55005;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Some green gnome was using it to power a giant robot? What a waste!$B$B<Grimzlow takes the capacitor and inserts it to the machine behind him.>$B$BThere, this should work well enough. If it doesn''t explode, that is. Thanks for the hussle by the way. Feel free to take one of these prototypes as reward, and don''t stick your fingers into any turning pieces if you want to keep them.',
    `RequestItemsText` = 'Time is ticking, and there''s no telling when disaster might strike.'
WHERE `entry` = 55006;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Look at all this barren nothingness in Azshara!$B$BWhat do you mean theres stuff all around us? I meant as in nobody is doing any work here, all this wasted potential. Such a shame that I''m here doing this rather than setting up factories all over, heh.',
    `RequestItemsText` = 'Have you found him yet?'
WHERE `entry` = 55007;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This dead goblin seems to fit the description of a goblin being dead in elvish ruins. He is covered in marks of struggle, bruises, and puncture wounds.$B$BYou begin your search for the Surveying Gear amongst the scattered bones and blood.',
    `RequestItemsText` = 'You find that lout yet?'
WHERE `entry` = 55008;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, just as I suspected, dead... Wait, he lost it?!$B$BDamn you Frix, you blasted, good for nothing, worthless...',
    `RequestItemsText` = 'Hmm?'
WHERE `entry` = 55009;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Did you find it? Oh...$B$BDamn I was getting ready to pack it up and start heading into exile, you really saved my hide here kid, and BIG time. Here, this is Frix''s necklace. He gave it to me before he headed out, aparently the metal messed with the survey gear. It''s probably coated in bad luck, last thing I want is to keep it.',
    `RequestItemsText` = 'Have you found the Surveying Gear yet?'
WHERE `entry` = 55010;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Toss me in a dirty sack and cover me in oil! Here I thought everyone went and forgot about me. Blastentom is running with the Horde now huh? Let me see that letter and he''s paying upfront?',
    `RequestItemsText` = 'Hey, hey, move along! Nothing to see here!'
WHERE `entry` = 55011;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah there, there. You got all the stuff I needed and you came back quick enough not to be a disappointment.',
    `RequestItemsText` = 'Look at you go!'
WHERE `entry` = 55012;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Not only did you find him but he''s willing to come help? Great, I should start searching through my pockets.$B$BHe''s a gold sink! But the stuff that maniac creates is totally worth it.',
    `RequestItemsText` = 'So, how did it go?'
WHERE `entry` = 55013;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Finally got it huh? Here, let''s try and see if we can get some energy off this thing.$B$B<Gazztoggle quickly begins his task, soon producing many small objects and devices. He takes quite a healthy amount of the powder and places it within one machine after the other. After a few minutes of trying, he seems to give up using the Essence.>$B$BDamn! Looks like this isn''t actually viable. I''d best come up with something else.',
    `RequestItemsText` = 'Get to gathering that ghost dust, pal!'
WHERE `entry` = 55014;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Glad you came back in one piece. Now, did you get those shards?!$B$B<The goblin greedily takes the ley-shards and begins to tinker with them. It is not long before the unstable shards crackle and fizzle, beginning to turn to dust.>$B$BDamned! These crystals are worthless, junk even, too unstable and not even in the good way...$B$BI''m really going to have to use my noggin here.',
    `RequestItemsText` = 'What, are the Naga being too much trouble?'
WHERE `entry` = 55015;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, took you long enough! Had trouble finding the blasted things? Oh well, gimme!$B$B<Gazztoggle takes the Antlers from you, quickly moving to test their power.>$B$BYes! Finally something! Who would have guessed this would be worth our time...$B$BThanks again, $N, for all you''ve done.',
    `RequestItemsText` = 'What? Getting bored of searching for them?'
WHERE `entry` = 55016;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, didn''t I send you to Azshara?$B$BDon''t tell me you''ve been in the tavern this entire time!$B$BThis is from Gazztoggle, I figured he had run with Sparkwater''s money, I was getting ready to call up my people to go and give him a REAL visit.$B$BHe seems to have found some promising results at least.',
    `RequestItemsText` = 'He''s in Sparkwater!'
WHERE `entry` = 55017;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wait... You actually pulled it off?$B$BI can''t believe you managed to interfere with the Dragonkin in such a way! Haha!$B$BWith this staff I could power Sparkwater for weeks, maybe even set up my own shop here...$B$BOh, take this!',
    `RequestItemsText` = 'What? We''re on the brink of greatness here, you gotta get that staff.'
WHERE `entry` = 55018;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''re looking for Zuul? Well that would be me, what''s this?',
    `RequestItemsText` = 'Why hello there, stranger, what brings you to Stonard?'
WHERE `entry` = 55019;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What is it you require from Commander Ruag? It had better be important.',
    `RequestItemsText` = 'He is located within the large building in the encampment.'
WHERE `entry` = 55020;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It seems you''ve done well, I''ll be pleased to have fewer orcs go missing.',
    `RequestItemsText` = 'The Swamp has earned its name, has it not?'
WHERE `entry` = 55021;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Really? I didn''t actually expect the chance to go.$B$BThis means a lot to me, it''s the chance to correct wrongs and make rights.$B$BI realize that there should be no competition between brothers and getting this note only serves to remind me that we should be proud of who we are.',
    `RequestItemsText` = 'Have you heard word from my brother?'
WHERE `entry` = 55022;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, a letter?$B$B<Rugnar begins to read intently.>$B$BWell, this is unexpected news, I must offer my thanks for everything you''ve done. The last thing I expected was a letter back so quickly. Take this, for all of the troubles.',
    `RequestItemsText` = 'I wonder if my message reached him. I hope I get to see him soon...'
WHERE `entry` = 55023;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh! It''s been a dang while since I''ve been able to drink! You''ve surely saved us.',
    `RequestItemsText` = 'Get the booze yet? We''re dying down here!'
WHERE `entry` = 55025;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes? Oh.... HE sent you?$B$BFool was oh so eager to offer his assistance to the Horde for coin. He underestimated the pirates in the area and got himself sank.$B$BNow he wants to call in a favor from an age past, hah. Let''s get this over with.',
    `RequestItemsText` = 'Is there something that I can help you with?'
WHERE `entry` = 55026;

UPDATE `quest_template` SET
    `OfferRewardText` = 'They''ve been putting their hands on things that don''t rightfully belong to them, it''s time they paid the price, and a price they cannot link to me.',
    `RequestItemsText` = 'Have you thrown a wrench in their plans?'
WHERE `entry` = 55027;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Look bud, we don''t got any spare copper already, so beat it.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 55028;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Not you again, don''t tell me Pazzle is coming back to ask for something else.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 55029;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, ain''t that a relief! I thought finding who was hunting us was going to be like finding a drop of water in the ocean, but here we are!',
    `RequestItemsText` = 'So... Did you figure anything out?'
WHERE `entry` = 55030;

UPDATE `quest_template` SET
    `OfferRewardText` = '<The goblin stares at the head of the orc.>$B$BWow, it must have taken a small army to take down Salt Tooth. Either that, or you are much stronger then I thought!',
    `RequestItemsText` = 'Having a hard time finding him? You''re telling me.'
WHERE `entry` = 55031;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It pains my soul to imagine it has come to this, it feels as if there is no light left within this once beautiful forest. I thank you for easing the troubled minds, maybe they can find clarity in the afterlife. Take this, I will need it no longer.',
    `RequestItemsText` = 'If nothing is done, my friends and kin will slay the innocent senselessly. It must be done...'
WHERE `entry` = 55032;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You notice something glinting within the muck, this must be what Gowlfang had spoken of. Upon searching further, you claim your reward.',
    `RequestItemsText` = 'Within the hollowed out tree you see a small pile of muck that is oddly formed.'
WHERE `entry` = 55035;

UPDATE `quest_template` SET
    `OfferRewardText` = '...Laz sent you? Oh, please don''t break my knees! Anything but that...$B$BWait, you''re here to help with the Yeti fur?$B$BWell, isn''t that a relief? I could certainly use help.',
    `RequestItemsText` = 'Oh, where''s the... Yes?$B$BCan''t you see I''m busy here!'
WHERE `entry` = 55036;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I see you got the Yeti Fur. Let me box this up right quick to send to Laz!',
    `RequestItemsText` = 'Have you had any luck hunting the Yeti?'
WHERE `entry` = 55037;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, that took long enough. Last time I deal with him. He''s a horrible contractor.$B$BA goblin should know never to be late, especially not with me. Here, take the extra coin he gave me for actually getting me this fur.$B$BNo doubt you''re responsible for it getting here at all. Without you, I''d be out of a shipment of fancy cloaks.',
    `RequestItemsText` = 'Welcome back to Sparkwater. Did you deal with Tarlo yet?'
WHERE `entry` = 55038;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Dalaran thanks you greatly for your efforts, it is the effort of adventurers like you that not all seems lost in this new world.',
    `RequestItemsText` = 'The tome is of great importance, do act quickly master $R.'
WHERE `entry` = 55039;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Library of Dalaran gets one step closer to what it once was, we thank you greatly for your efforts, hero.',
    `RequestItemsText` = 'The book is of great importance to Dalaran and must be retrieved.'
WHERE `entry` = 55040;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hey, this seems to be it. The damage is certainly going to hurt the resell value when I''m done reading it.',
    `RequestItemsText` = 'Have you checked all of the heights? I got good sources saying he was there.'
WHERE `entry` = 55041;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Shak slips the ring on his own finger and chuckles.>$B$BFinally, that idiot had what was coming to him. Maybe now people will stop calling me by that name!',
    `RequestItemsText` = 'Any luck in finding him out there?'
WHERE `entry` = 55042;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh boy, this eases a Captain''s mind, I was worried some people might go looking before I could find the blasted thing. Here, let''s share a drink!',
    `RequestItemsText` = 'Have you found my sunken beauty''s logbook yet?'
WHERE `entry` = 55043;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hey there, nice view huh?$B$BOh, the boss sent you?',
    `RequestItemsText` = 'He''s gotta be around here somewhere, keep looking!'
WHERE `entry` = 55044;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What''s all this? Axel sent this?$B$BI guess he is working out there after all. This is quite a bit, fine, tell him to keep doing whatever he''s doing then!',
    `RequestItemsText` = 'Yeah? Any luck finding him?'
WHERE `entry` = 55045;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, finally a piece of this rare ore. Let me see if it can be used, thanks $N.',
    `RequestItemsText` = 'The Ore should be a dark black color, go find it!'
WHERE `entry` = 55046;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wow, I haven''t seen these in a long, long time. This means a lot to me, $N.',
    `RequestItemsText` = 'The Pirates can be trouble, but you look like you can handle yourself.'
WHERE `entry` = 55047;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You answered the board did you?$B$BDamn prisoner was able to tunnel his way out of the last hole. We had to board it up after he got out into the ocean. Good thing he''s dealt with.',
    `RequestItemsText` = 'What now?'
WHERE `entry` = 55048;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good to see people like you are out dispensing order to the world, one less rat around is better for all of us. Here, a reward for the good work, Laz always pays for good work.',
    `RequestItemsText` = 'What now?'
WHERE `entry` = 55049;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, how unexpected. Young Grizlik had sent me a drawing of us training together, including a thank you message.$B$BHe aspires to be trained when he grows older. The future generation of the horde, $N. That''s why we are all here.',
    `RequestItemsText` = 'A letter, for me?'
WHERE `entry` = 55050;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well, it certainly has been a while, you got any good news from Booty Bay?$B$BOh, they''re on their way back? Oh and Revilgaz was upset huh? I don''t blame him, heh.$B$BYou''ve saved my crew from an unknown fate and I thank ye for that, $N. Please, take this cutlass, no point in swashbuckling if the ship is gone.',
    `RequestItemsText` = 'Can I help you?'
WHERE `entry` = 55051;

UPDATE `quest_template` SET
    `OfferRewardText` = '',
    `RequestItemsText` = ''
WHERE `entry` = 55055;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great one! There''s no telling how much power all this joy might unleash!',
    `RequestItemsText` = '$N, it is my dearest wish to bring joy and happiness to everyone this Winter Veil Season! However, I find myself currently without any sort of legs or appendages with which to move about, and doing so is quite dangerous given my... Flake-like nature...$B$BI need you and all your friends to join forces and pelt me with the power of SNOW magic! Through the joy channeled by your snowball energy, I shall grow to new heights and be able to unleash something special for all to enjoy!'
WHERE `entry` = 55056;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Quicker than I had imagined! You must be a seasoned explorer. Hopefully one day I will see as much as you have. Thanks, $N.',
    `RequestItemsText` = 'Have you had a chance to gather the materials for my adventure?'
WHERE `entry` = 55200;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Less raptors stalking at the base of our hills puts my mind to rest. Thanks for the work, $N.',
    `RequestItemsText` = 'Have you slain some of the beasts blocking our path?'
WHERE `entry` = 55201;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Cousin Hargin finally coughin up the good stuff, aye?! Well, it''s about damn time! If this stuff is as good as he says it may not last the night! For your troubles...$B$B<Hands over some coins.>$B$BIf you''re lookin for more ways to make some coin, talk to Samuel in Hawk''s Vigil. He''s an adventurer of sorts and could likely use a hand.',
    `RequestItemsText` = 'Aye, is there something you need?'
WHERE `entry` = 55202;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I figured the shipment would come late. Given all of the trouble on the road east of here, it seems Hawk''s Vigil has remained reliable in their shipments.',
    `RequestItemsText` = 'Yes, do you have anything for me? I am currently quite busy.'
WHERE `entry` = 55203;

UPDATE `quest_template` SET
    `OfferRewardText` = 'From Captain Stoutfist, huh? Let''s see here...$B$B<The Dwarf reads the report.>$B$BHe thinks the few mountaineers I have can stop the Dragonmaw?',
    `RequestItemsText` = 'We must keep resolute, though we are in the mountains, we are still dependant to those on the ground to keep supplies moving.'
WHERE `entry` = 55204;

UPDATE `quest_template` SET
    `OfferRewardText` = 'He cannot even lend a single hand to assist us? What is it then we are supposed to do against the Dragonmaw?...$B$BThanks, $N. Take these coins for the trouble. I will have to think of a new plan.',
    `RequestItemsText` = 'Have you got word from Snowbeard? Are fresh men coming?'
WHERE `entry` = 55205;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve done it!$B$BWe may finally sleep a night of peace knowing there are less of the blackbloods stalking the hills and preying upon our citizens. You have done a noble deed, $N.',
    `RequestItemsText` = 'The Dragonmaw must be checked at every instance, lest they gain more courage in their actions.'
WHERE `entry` = 55206;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, Rann sent you? Surely, he didn''t just ramble on about my pie!',
    `RequestItemsText` = 'Hello there, traveler. Welcome to my inn!'
WHERE `entry` = 55207;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Pie pie pie! My, oh my!$B$BI''ve been dreaming of this for days!',
    `RequestItemsText` = 'You''re back this soon? You better have my pie!'
WHERE `entry` = 55208;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, that Fradd. Look at all these new gadgets and gizmos! Wizzing Fraddbangers, Shocking Gynochroms, Tilting Oscillation Inhibitors?!$B$BThis is all state of the art stuff, thanks for the delivery, take this for the trip.',
    `RequestItemsText` = 'Oh, are you here for something, or you just looking to chat about some of my new inventions?'
WHERE `entry` = 55209;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve got it all?$B$BSplendid! Now I can get to work tinkering for you so that I can get to use my own!',
    `RequestItemsText` = 'Have you gathered the materials?!$B$BMy mind is going wild with ideas!'
WHERE `entry` = 55210;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here it is, my creation!$B$BAn engineering masterpiece.$B$BMay it serve you well out there, now, on to my own works!',
    `RequestItemsText` = 'One moment, lad. I''m tinkering!'
WHERE `entry` = 55211;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, Barthos sent you? He''s always looking for supplies. He''s lucky to have saved my hide in the past. I still owe him for that!',
    `RequestItemsText` = 'Welcome to the Airfield! Do you have any business with the senate, or our operations here?'
WHERE `entry` = 55212;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, Orion! What a friend, he always comes in clutch right at the perfect time!$B$BI was on my last few sputtercogs! What do you mean by job at Ironforge Airport?$B$BWhy would I want to do that when I can tinker here in my own shop!',
    `RequestItemsText` = 'Have you got those parts from the Airfield I sent you for?'
WHERE `entry` = 55213;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I have spent quite some time researching into what is going on, something lingers within the air, as if the presence of forbidden magic is being introduced to Hawk''s Vigil.',
    `RequestItemsText` = 'Is there something I can do for you?'
WHERE `entry` = 55215;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, Marge Blackwood sent you, the matter of the dark magic in Hawk''s Vigil? I see.',
    `RequestItemsText` = 'There is much knowledge to learn, is that why you have come to seek my presence?'
WHERE `entry` = 55216;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmm.. So he believes that perhaps this source could be new to the region?$B$BI haven''t thought of that as a possibility.',
    `RequestItemsText` = 'You return from Poppy Zabini?'
WHERE `entry` = 55217;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Interesting report, let me check my records and make sure about the new people within the town.',
    `RequestItemsText` = 'Welcome back, has Marge got any news on all of the trouble?'
WHERE `entry` = 55218;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh...$B$B<Robb Dursley''s cheerful demeanor drops.>$B$BThat is why you''ve come?$B$BWhat we are going to speak of must remain a secret, understood, $N?',
    `RequestItemsText` = 'What would Lord Commander Ryke have to do with me?'
WHERE `entry` = 55219;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Mathias takes the Report and begins to read.>$B$BHmm, I suspected as much, the man was deranged and lost within such magic, it only makes sense he would be behind this ''foul taint'' as Lord Commander Ryke has described it.',
    `RequestItemsText` = 'What is it you require from the SI:7?'
WHERE `entry` = 55220;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent. Now, let us see truly where this man is from. Perhaps we can find some clues on all of this.',
    `RequestItemsText` = 'Have you braved the depths of the Stockades yet?'
WHERE `entry` = 55221;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, I haven''t heard the name Martin Corinth before, but I do remember a Harlus Ashbuckle, what about them?',
    `RequestItemsText` = 'Hello, and welcome to my tavern, looking for a room?'
WHERE `entry` = 55222;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hmm, so, he did leave stuff within Menethil, it seems the man didn''t cover all of his tracks, thankfully for us.',
    `RequestItemsText` = 'Have you got any news from Menethil?'
WHERE `entry` = 55223;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, our suspicions here were correct then, there is a lot of information here that is damning.',
    `RequestItemsText` = 'So, you''ve returned, good news from Stormwind?'
WHERE `entry` = 55224;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The town has been saved! I thank you again $N. Hawk''s Vigil shall remain a place of peace as long as brave souls like yourself walk Azeroth.$B$BHere, take one of these as a token of the town''s gratitude.',
    `RequestItemsText` = 'Has this monster been dealt with?'
WHERE `entry` = 55225;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Not only those be comfy, mind you, it''s also a style. Of course, they do provide protection too.',
    `RequestItemsText` = 'For the gauntlets plans, I''ll be needin'' 20 thorium bars.$B$BAre you alright, sonny? Yer getting'' all red.'
WHERE `entry` = 55300;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I was more worried than a warlock at a paladin party about my sheep. You really put my mind at ease. I can''t thank you enough, partner. Take these homemade goods for the trouble.',
    `RequestItemsText` = 'Hurry! My farm''s fallin'' apart without them sheep. Get a wiggle on it.'
WHERE `entry` = 60005;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Lulu looks around with a new shimmer in her eyes. She prances around merrily, occasionally lowering her head to chomp at some yummy grass.You pat yourself on the back and bask in the fulfillment that comes with aiding a defenseless creature.$B$BLulu instinctively follows you to your next destination.',
    `RequestItemsText` = 'Baa-a-a-a-a-ah!$B$B<Lulu quivers in hopeless fear.>'
WHERE `entry` = 60007;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It brings back good memories to work with the same tools she passed down to me.$B$BI get to weave the same stitches as the ones she taught me before she passed, and that warms my heart.$B$BYou''ve been a real help to this little ol'' farm family, $N. Bless you.',
    `RequestItemsText` = 'Don''t dilly-dally for too long. Time''s a precious thing.'
WHERE `entry` = 60008;

UPDATE `quest_template` SET
    `OfferRewardText` = '',
    `RequestItemsText` = ''
WHERE `entry` = 60009;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hey, there we are! Thanks! As promised, some money, and some pizza bottles!$B$BOh, I didn''t mention those?',
    `RequestItemsText` = 'Didja get the flowers?I sure hope Dadanga gives me the recipe for the elixir soon. Almost out of money...'
WHERE `entry` = 60010;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There''s only one passion we paladins are allowed to foster. Passion to serve and protect.',
    `RequestItemsText` = 'To know the weaknesses of the enemies and bringing Justice you will need all prowess you can muster. Above all else you will need your faith in the Light more than ever and the Light shall grant you the strength.'
WHERE `entry` = 60011;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There''s only one passion we paladins are allowed to foster. Passion to serve and protect.',
    `RequestItemsText` = 'To know the weaknesses of the enemies and bringing Justice you will need all prowess you can muster. Above all else you will need your faith in the Light more than ever and the Light shall grant you the strength.'
WHERE `entry` = 60012;

UPDATE `quest_template` SET
    `OfferRewardText` = '',
    `RequestItemsText` = ''
WHERE `entry` = 60013;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $R!$B$BThat cursed Sea Witch has been driving back our Sentinels time and again, without her direction they will be easier to defeat.',
    `RequestItemsText` = 'If the Naga successfully obtain the$B$Bknowledge scattered in that place, no force will drive them out.'
WHERE `entry` = 60020;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Splendid, splendid! Everything that I requested, and in such good condition as well. I hope that I can look forward to your continued cooperation. If you ever need more coins, you know where to find me.',
    `RequestItemsText` = 'I can tell just by looking at you that you, my friend, have an eye for FASHION! Don''t try to hide it: I can see it in your bold attire, undeterred by the scoffs of the unenlightened philistines.'
WHERE `entry` = 60030;

