    `OfferRewardText` = 'Splendid, splendid! Everything that I requested, and in such good condition as well. I hope that I can look forward to your continued cooperation. If you ever need more coins, you know where to find me.',
    `RequestItemsText` = 'I can tell just by looking at you that you, my friend, have an eye for FASHION! Don''t try to hide it: I can see it in your bold attire, undeterred by the scoffs of the unenlightened philistines.'
WHERE `entry` = 60035;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh my! Oh my, oh my, oh my! Yes, these are absolutely perfect! Their lustre, their smoothness, their perfection!$B$BHere, take these coins for your trouble. I knew that you wouldn''t disappoint me. You are well and truly FABULOUS!',
    `RequestItemsText` = 'Have I got a FABULOUS deal for you today!'
WHERE `entry` = 60036;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, you''re back! And you''ve brought me pie! Finally, I can enjoy that sweet, delicious pumpkin pie!',
    `RequestItemsText` = 'Come back when you have that pie, please!'
WHERE `entry` = 60040;

UPDATE `quest_template` SET
    `OfferRewardText` = 'By the Light!$B$BMy dear child, I can''t tell you what a blessing you''ve been to all of us here on the farm!$B$BYou''ve done more than enough to earn a pie, $N! Take it with my deepest gratitude!',
    `RequestItemsText` = 'Oh, tell me you put those dirty beasts in the ground! What about my pumpkins? Did you manage to find my sweet pumpkins?'
WHERE `entry` = 60041;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You did what? All by yourself?$B$BWell, that''s great news! Hopefully those gnolls won''t cause us trouble from now on.$B$BHow did you know? Did Terry commission you? No matter, please take this as a reward for your trouble.',
    `RequestItemsText` = 'I hope you have some good news for me, $N!'
WHERE `entry` = 60042;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I am so happy to hear that Teresa is going to visit us!',
    `RequestItemsText` = 'Greetings! Are you new here?'
WHERE `entry` = 60050;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great! Let''s get you some new know-how to about thing or two.',
    `RequestItemsText` = 'I see you''re back. Have you managed to find everything required, yes?'
WHERE `entry` = 60060;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, it''s good to see you back. It is inspiring to see younglings get back to the roots of the best traditions we''ve had to survive properly, with dignity and respect to the Earth-Mother!',
    `RequestItemsText` = 'I have no doubts your venture was fruitful and you have procured all the seeds.'
WHERE `entry` = 60061;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Have you fulfilled Mal''adris'' last request? You are sadly too late. He succumbed to his injuries not long ago; I did everything I could to save his life, but it was not enough. Us members of the Argent Dawn are well aware of what our duty in these lands entails, yet when the time eventually comes for every one of us, rarely do they come to terms with it. I''ve seen it countless times, and it never gets any more bearable.$B$BLet this be a warning to you, adventurer. Should you still wish to venture into the abyss that awaits you beyond this hill, then be well aware. Death awaits at every corner.',
    `RequestItemsText` = 'You''ve returned...'
WHERE `entry` = 60065;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The gryphon sniffs the air that surrounds you excitedly, sensing the treats you''ve brought. His pupils grow wide and he chirps with joy at the sight of his favorite Chew Toy in your hand.$B$BHe looks happy!',
    `RequestItemsText` = 'The gryphon stares at you but doesn''t seem to be very satisfied with all his cawing and disturbed jabbering. He clearly looks hungry and frustrated. Perhaps a handful of famous Dwarven Mild could do some good?'
WHERE `entry` = 60070;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A defeated enemy should know their place. Hopefully, that will be the last of the Witherbark.',
    `RequestItemsText` = 'Show them no mercy.'
WHERE `entry` = 60071;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well fought, well slainŌĆöbut this is not the end.',
    `RequestItemsText` = 'Who knows what abomination they seek to summon?'
WHERE `entry` = 60072;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You slaughtered them with ease and precision, like a butcher claiming his due.',
    `RequestItemsText` = 'A hard task, but one that must be done.'
WHERE `entry` = 60073;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A crushing defeat, a miserable life. Yet, I feel this story is far from overŌĆöfor no matter how many trolls you slay, they always return. Mh... here, a reward well earned.',
    `RequestItemsText` = 'Strike while the iron is hot.'
WHERE `entry` = 60074;

UPDATE `quest_template` SET
    `OfferRewardText` = 'By the Gods it actually worked! I can''t believe it!$B$BI mean... of course it worked, worked just fine.$B$BThis changes everything. Thank you $R, it took no small amount of courage to step into that portal not knowing for certain what was on the other side. I''m sure you got promised a reward, so here it is, your very own Portable Wormhole Generator.$B$BUse it well, and for your own good don''t fiddle around with it. Good luck!',
    `RequestItemsText` = 'Nothing to be afraid of... Nothing at all!'
WHERE `entry` = 60104;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My slippers! Thank you very much! You have shown a great kindness to me. Please take this coin for your troubles. Dark lady watch over you.',
    `RequestItemsText` = 'Hello again, $N. Have you made the trip to the shore North of Solliden Farmstead yet?'
WHERE `entry` = 60107;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thanks, hero, it had to be done. Take this, the last memory I have left of him.',
    `RequestItemsText` = 'Did you do it? This can''t wait no longer.'
WHERE `entry` = 60108;

UPDATE `quest_template` SET
    `OfferRewardText` = 'High Sorcerer Andromath sent you?$B$BMy, how the time flies when you''re watching insanity and horror unfold from every angle.$B$BI will have to return with my findings and reassure him that I have not fallen to the same madness as those who are trapped here.',
    `RequestItemsText` = 'There is untold darkness that will forever linger inside of these walls.'
WHERE `entry` = 60109;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Do not be troubled by what needed be done, $N. Githyss was aggressive beyond our ability to manage. The reason for this, I do not know, but one I hope to uncover in my research. Hold your head with pride; you have ensured the continued safety of Shadowglen.',
    `RequestItemsText` = 'We must put the broodmother down. I am afraid we have no other choice...'
WHERE `entry` = 60110;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Then it is done? It pains me greatly that it had come to this, but your actions today have ensured safe passage to Darnassus for our people.$B$BYour valor shall not go unrewarded, $C. Elune''s blessing be upon you, always.',
    `RequestItemsText` = 'Agal and Greenpaw were once honorable and powerful allies. Now, in their madness, they pose a great threat to all who travel this road. There cannot be peace so long as they live, $C.'
WHERE `entry` = 60111;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. It is a shame they never broke free of the Scourge''s control. They would''ve made powerful allies.',
    `RequestItemsText` = 'They all used to explore Tirisfal together. Karrel was a blacksmith, Daniel was a huntsman and Stephen''s wisdom guided them all. To see them like this breaks my heart.'
WHERE `entry` = 60112;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good. Goooood. This should be plenty of blood to perfect my plague. The other apothecaries would be jealous of this advantage.',
    `RequestItemsText` = 'It shouldn''t be hard to find the Solliden Farmstead. That''s where you got the pumpkins from... if you can''t remember that, then I suggest getting a brain replacement.'
WHERE `entry` = 60113;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Great! That''s the spirit. Here''s some stuff I had laying around from a buddy of mine who left for Loch Modan and never came back.',
    `RequestItemsText` = 'Did you kill him? You best be careful now, this is no ordinary wendigo.'
WHERE `entry` = 60114;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Already I feel that our people are safer thanks to your decisive blow against the Bristlebacks, $N. Your actions speak highly of your dedication to protecting our tribe.$B$BMay the Earth Mother guide your path.',
    `RequestItemsText` = 'Have you found anything, $N?'
WHERE `entry` = 60115;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now our forces may enter the Monastery fresh for battle and with the advantage of surprise. Varimathras shall be pleased.',
    `RequestItemsText` = 'Well?'
WHERE `entry` = 60116;

UPDATE `quest_template` SET
    `OfferRewardText` = '<The Deathguard looks you over approvingly.>$B$BYes, yes you''ll do. Come here $C.',
    `RequestItemsText` = ''
WHERE `entry` = 60117;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent to see you again! My butler observed your actions from a rise in the mountains. Thank you so much for making the roadway safer. One day Wayne Manor will be restored and we can''t have ogres all over the place!',
    `RequestItemsText` = 'Hello again! I assume since you''re here the task is complete? No?$B$BA pity.'
WHERE `entry` = 60119;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Fantastic, you found them. I was getting worried thinking about harpies armed with rifles. You think they can pull a trigger with those talons? On second thought, never mind. I don''t wanna think about it.',
    `RequestItemsText` = 'I don''t want to get shot. Do you?'
WHERE `entry` = 60120;

UPDATE `quest_template` SET
    `OfferRewardText` = '<The goblin notices you over a giant gulp from his cup>.$B$BYeah, what do you want? Oh the supplies made it? Too bad, I''m done with this gig.$B$BMaybe I could be a pirate...',
    `RequestItemsText` = 'I drink alone, pal.'
WHERE `entry` = 60121;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Praise the ancestors, you''ve got my ammo! I have many orders to fill in the next two hours. You say Rezlak fought harpies for these supplies? Guess it''s money well-spent.',
    `RequestItemsText` = '<She pauses in the middle of packing orders to look at you hopefully. Your empty hands cause a scowl>.'
WHERE `entry` = 60122;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The news came just before you arrived. We''re truly in your debt.$B$BHere, a reward fitting for a hero such as yourself.',
    `RequestItemsText` = 'Only you and your friends can save Naralex, you are our only hope.'
WHERE `entry` = 60124;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You did find them! I will send these to Moonglade immediately.',
    `RequestItemsText` = 'Did you collect the flowers? They might reveal something about the Nightmare.'
WHERE `entry` = 60125;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Interesting... someone placed a curse upon this ring. I would assume to prevent it from being kept by any would-be thieves. If a murloc had the ring, it would seem that the curse failed to serve its intended purpose.$B$B<Zaldimar utters an incantation while gesturing with his hand. A blinding flash of light explodes from the ring, which appears as a lustrous golden band.>$B$BHere you are.',
    `RequestItemsText` = 'Why are you showing me this dirty trinket? Look, there''s young Mages in need of my attention, so I really don''t have time for... Oh? A magical enchantment, you say?'
WHERE `entry` = 60130;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It''s important to keep their numbers in check but not to hunt them to the brink. You''ve done a great service for the Horde this day, $C. Go with honor.',
    `RequestItemsText` = 'You smell of the sea, $C. Tell me the beast is slain so I can get the fisherman back to work.'
WHERE `entry` = 60131;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Azeroth is a far better place with less spiders alive in it.',
    `RequestItemsText` = 'Eight legs is too many.'
WHERE `entry` = 60132;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. The sacrifice of these poor animals will help me to unravel this mysterious taint seeping into the grassland and develop a cure for its effects.',
    `RequestItemsText` = 'It is with a heavy heart that I must send you to do this deed, $N.$B$BDo not delay, the herds only grow weaker.'
WHERE `entry` = 60133;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I saw a small herd of gazelle pass by the Crossroads while you were gone. They traveled like the wind itself carried their hooves higher, and it gave me much joy to see them run freely. Thank you, $N, for your help.',
    `RequestItemsText` = 'Is it done? We can prevent harm to all of the Earthmother''s creatures if only the grazers are protected against this poison.'
WHERE `entry` = 60134;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $R! At long last, Palkeote is at peace. You have done a great service today, and the beasts of this land know it in their own way.$B$BSuch an effort should be rewarded.',
    `RequestItemsText` = 'Have you found the grey mother?'
WHERE `entry` = 60135;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Harnor bows.>$B$BI am glad that the grey mother has found peace at last.$B$BYou and your allies have my thanks, and the thanks of all the kodo of this land.',
    `RequestItemsText` = 'Have you found Palkeote? Do not face her alone ŌĆō there is no honor in a hunt without hope.'
WHERE `entry` = 60137;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have overcome the greatest trial a Mulgore hunter can face, and you have emerged with greater strength ŌĆō and wisdom ŌĆō for your efforts.$B$BCarry it with you as you step further into the world, young $C, and honor the memory of the beasts you defeated by remembering their lessons.',
    `RequestItemsText` = 'The kodo wander Mulgore far and wide. You may need to search for some time to find the herd. Patience is one of the lessons of the hunt.'
WHERE `entry` = 60138;

UPDATE `quest_template` SET
    `OfferRewardText` = 'For the first time in weeks I think I can close my eyes and not hear their chittering. It''s done.$B$B<Blackarm laughs aloud, exasperated>.$B$BYou will be counted among the great heroes of the Horde for this effort, $C, if I have anything to say about it. Have some of these healing potions for your trouble. With any luck, I won''t need so many anymore.',
    `RequestItemsText` = 'Is it done? Have you scoured the land for the stinging menace?'
WHERE `entry` = 60139;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Austil takes the bandages and uses them to lash some of his looser extremities into place.>$B$BAh, thank you. This will do nicely.$B$BI''m sorry if I snapped at you before. Having bits of oneself threatening to escape at any moment does tend to make one a little grumpy.$B$BBut I feel much better now. Maybe I''ll go even talk to old Farthing.',
    `RequestItemsText` = 'Every minute that passes is another minute for pieces to fall off of me, $N!'
WHERE `entry` = 60140;

UPDATE `quest_template` SET
    `OfferRewardText` = '<You explain why Brother WIlhelm sent you. Eldrin''s angry, defensive posture softens as you explain, and eventually you see the shine of tears in his eyes.>$B$BMiles away and as busy serving the Light as he is, yet he still finds time to help us. It pains me to burden him so yet again. He''s already done so much for us, you see.$B$BThings''ve been hard this year, so I''ve been goin'' without so Sara and Eric don''t have to, and... Well, thank you. Bless Brother Wilhelm, and bless you, $N.$B$BHere. I know it''s not much, but Sara makes them for the locals. Maybe you can find some use in it. Take it! It''s the least we can do in return for your selfless deed.',
    `RequestItemsText` = 'Are you here from Stormwind?$B$BWe told you before, we don''t have any money left to spare for Lady Prestor''s coffers! Can''t you see I have a family to feed?'
WHERE `entry` = 60141;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Tormus takes the letter and reads it. He furrows his brows before giving a hearty laugh.>$B$BA gnome looking to be a blacksmith? It has been a long time since we had a gnome join our ranks. Well, why not? Perhaps he''ll be the next Klockmort Spannerspan!$B$BI appreciate you bringing this to me, $C. Here, some extra stones to give your weapon an extra edge in battle.',
    `RequestItemsText` = 'Here to learn how to swing a smithing hammer, friend?'
WHERE `entry` = 60142;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, you''ve found it! You have my eternal gratitude, $N!$B$BWill a well-tailored shirt suffice as compensation for your efforts? I keep a number of different colors in stock to suit any taste. Please, take your pick.$B$BIf a shirt is not to your liking, perhaps I could interest you in some raw material for your own purposes?',
    `RequestItemsText` = 'Have you found my sewing kit, $N?'
WHERE `entry` = 60143;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Though your journey has only just begun, you''ve already proven yourself an invaluable asset to Northshire.$B$BChoose your reward. You''ve earned it.',
    `RequestItemsText` = 'I assume you killed the beast?'
WHERE `entry` = 60145;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have struck a blow to their numbers, and returned in one piece.$B$BTake one, you earned it.',
    `RequestItemsText` = 'What are you waiting for?'
WHERE `entry` = 60147;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Splendid! With the broodmother gone we can finally reclaim the mine. Well done.',
    `RequestItemsText` = 'They keep coming back, something is amiss.'
WHERE `entry` = 60148;

UPDATE `quest_template` SET
    `OfferRewardText` = 'With heroes like you we might even push them out of Mulgore.$B$BTake one, it''s the least we can do.',
    `RequestItemsText` = 'Show them that we are not to be meddled with.'
WHERE `entry` = 60150;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The Baron sent you? How kind of him to actually send reinforcements, come hear mate, lend me your ear, can''t just say it out loud!',
    `RequestItemsText` = 'Rid me of these fools, my crew stands above all other.'
WHERE `entry` = 60152;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good work, $N, I''ll feed this to the crocodiles.$B$B<The Baron tosses the head into a bucket.>$B$BWhat''s this?$B$BHe still has an eyepatch on, you can have it if you want, or I will give you this pearled necklace, you can only take one.$B$BThank you for your services, do stick around, you never know when I''ll need more muscle.',
    `RequestItemsText` = 'Move it, or we both lose our lives!'
WHERE `entry` = 60153;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Such a relief it is to know that those spiders will threaten Elwynn no more. Please accept this coin on behalf of Stormwind.',
    `RequestItemsText` = 'Their numbers are increasing every second you waste. We can''t afford to wait any longer.'
WHERE `entry` = 60154;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, wonderful legs! Grill ''em, boil ''em, put ŌĆśem in a pot.$B$BYou... want a reward? I think this should be enough.',
    `RequestItemsText` = 'Get a move on. My customers are waiting!'
WHERE `entry` = 60155;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This little fella doesnŌĆÖt seem all too happy to be in your company. Oh well, thatŌĆÖs to be expected. Still, good job, pal! LetŌĆÖs go to the next step.',
    `RequestItemsText` = 'You need to maintain your focus, or the animal will not bend to your will.'
WHERE `entry` = 60160;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Looking determined. I like that, I get the same look when I test out a new shipment of rifles. Gets me giddy just thinking about it!',
    `RequestItemsText` = 'Their pinchers can hurt quite badly, but donŌĆÖt let that break your focus.'
WHERE `entry` = 60161;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, buddy. This is all I can teach you about taming beasts in the wild. With this knowledge you can call, dismiss and tame most animals you encounter on Azeroth. Be proud of this, only a select few actually learn this from me.',
    `RequestItemsText` = 'I am sure you got this, trust in your abilities that got you this far, pal.'
WHERE `entry` = 60162;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oho, a young goblin. We see your folk around here more often these last days. The Durotar Labor Union is a valuable asset to the HordeŌĆÖs resources.$B$BYou wish to learn how to train your pet? Very well, with my teachings you will be able to teach your pet new skills, feed it and revive it, should it fall in battle.$B$BIf you seek further lessons, return to me later, after you and your pet gathered more experience on your journeys.',
    `RequestItemsText` = ''
WHERE `entry` = 60163;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have arrived. I have heard a great many deal of things about you, if at least half is true you will prove to be very fun to watch.',
    `RequestItemsText` = ''
WHERE `entry` = 70000;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N, truly well done.$B$BYou have earned your place as my apprentice, for your first lesson you must read this tome. The survival of your group depends on you to be able to hand out as many refreshments as you can.$B$BRemember, you must not take anything lightly! Thirst may be your worst enemy under some circumstances.$B$BNow go study my newest apprentice.',
    `RequestItemsText` = 'While I may not be going anywhere my patience isn''t one to be tested.'
WHERE `entry` = 70001;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Welcome $C, I assume you are here to learn about the secrets of the Twisting Nether and how you may claim them as your own.$B$BI may have something to teach you, but it won''t be easy in the slightest.',
    `RequestItemsText` = ''
WHERE `entry` = 70002;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Daio laughs maniacally>$B$BYou actually pulled that one off, who would''ve thought. You''re insane $N, maybe even more than this old fool.$B$BNow get ready it''s time for a lesson not many are worthy of.',
    `RequestItemsText` = 'You will remind yourself of this feat for years to come, that is if you do come back.'
WHERE `entry` = 70003;

UPDATE `quest_template` SET
    `OfferRewardText` = '',
    `RequestItemsText` = ''
WHERE `entry` = 70010;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Loruk sent you to check on me? Is he still thinking I''m a small calf with no horns?',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 70020;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you $N, this will mend our friend.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 70021;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My horns are ready and sharpened, alas my spear was stolen by those demons, the vermin felt the blessings of the Earthmother on it!$B$BIt''s not your fault $N, you''ve bravely fought them and for that I am in your debt, here, have this necklace as a token of my gratitude.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 70022;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I was expecting someone else to give me this report, $R, what happened to Norvok?',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 70023;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Already done?',
    `RequestItemsText` = 'Clean the camp of the wildthorn menace and I will see you rewarded.'
WHERE `entry` = 70024;

UPDATE `quest_template` SET
    `OfferRewardText` = 'With the interference of the elves gone we can resume our duty in peace. Thank you $N, you are more capable than I thought.',
    `RequestItemsText` = 'Go get your hands dirty, leave none alive, and if anything make sure more of the peons don''t die.'
WHERE `entry` = 70025;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have my thanks $N, your work helped me and my men more than you''d imagine, as a sign of gratitude the leatherworker made this for you.',
    `RequestItemsText` = 'Remember, only hunt the eldest of the bears.'
WHERE `entry` = 70026;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now, what do I do with you?',
    `RequestItemsText` = 'So, Grushak finally reporting on his peons doing their job for once?'
WHERE `entry` = 70027;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good. While their numbers are Legions and our arms never rest, we will prevail thanks to the sheer desire to survive overcoming their plans to conquer.$B$BCome, I have few items saved as payment. Choose whichever fits you best.',
    `RequestItemsText` = 'I take it you''re not a coward, so why are you still here?'
WHERE `entry` = 70028;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A Dreadlord of all things? This won''t be easy, at your current state you''re nothing more than a twig in a cyclone, but there are other ways.',
    `RequestItemsText` = 'Hopefully you will survive to tell the story, $C.'
WHERE `entry` = 70029;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, hello mon, I didn''t notice you, what do you want?',
    `RequestItemsText` = 'Three little elves hugging the trees, ol'' Jin''Zil will be cooking soon!'
WHERE `entry` = 70030;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My stew is almost done, let''s have a taste.$B$BTerrible!$B$BI mean, it tastes better than my wife''s cooking.',
    `RequestItemsText` = 'Hey, $N, I wonder what $R tastes like.$B$BBut don''t worry I won''t be eating you! Maybe.'
WHERE `entry` = 70031;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That daft fool just won''t let go of it! I told him we were not playing on coin, gah.$B$B<Grimeye clears his throat.>$B$BIn any case $N, well done. Now let''s go kill us a dreadlord.',
    `RequestItemsText` = 'What took you this long?'
WHERE `entry` = 70032;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done something not many can do, $C, walk with pride from this day onward.$B$BThis old orc is reminded of the past but from now on he will dream of the future.$B$BI will set fire to the head and mention you the slayer to our clan, but the ancestors tell me your path only begins my dear friend.$B$BI truly hope you will one day find what you seek.',
    `RequestItemsText` = 'Bring me his severed head and I will set it on fire!'
WHERE `entry` = 70033;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This spear served my family for many generations.$B$BI am saddened that I was the one to bring it to its end, and brought shame upon my tribe.$B$B<Norvok takes a deep breath through his huge nostrils and lets the air out with a smile.>$B$BDon''t look sad my newest friend, you helped me more than you know, this is not the end but merely the beginning.$B$BI will reforge the blade and make it more sturdy, after all even when you cut a hawk''s wings his beak is as dangerous as ever.',
    `RequestItemsText` = 'Y-yes?'
WHERE `entry` = 70034;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This will be a great help, $C.',
    `RequestItemsText` = 'Are you still here?'
WHERE `entry` = 70040;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. You know I''ve been thinking about what that dwarf said about ogres pitching tents and it just dawned on me!$B$BI''m going to make sure there''s at least one dwarf who can''t pitch a tent anymore!$B$BAnyways, here is your reward.',
    `RequestItemsText` = 'Any luck finding that cloth I need?'
WHERE `entry` = 70049;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have no idea how much your help means to me.$B$BHere''s a little token of my appreciation.',
    `RequestItemsText` = 'That drunk old dwarf. Ugh! Please come back as soon as you can.'
WHERE `entry` = 70050;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yeah, that''s perfect! Absolutely perfect! You''ve made this goblin so happy he can almost cry. Here''s your pay. Now move along, I got fuel to sell.',
    `RequestItemsText` = 'Hey, pal. I know those ships aren''t going anywhere, but could you pick up your feet and get going?'
WHERE `entry` = 70051;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''re back, great.$B$BAnd I see you picked something up as a trophy. Strange, but whatever floats your boat, bub!$B$BHere''s some coin for your troubles.',
    `RequestItemsText` = 'In life we make choices we sometimes regret, and Tazan will be sure to regret this one.'
WHERE `entry` = 70052;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''re saying they were smaller in size? That''d explain their hunger.$B$BHowever, what would make them leave their nest so early and why all of them?$B$B<Warg ponders the thought for a while and turns back to you.>$B$BHere''s the payment as promised. I will investigate further.',
    `RequestItemsText` = 'Are you done already, $N?'
WHERE `entry` = 70053;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good work, $C. What''s that shovel you''ve got there? I think I recognize the initials.',
    `RequestItemsText` = 'A good deed during dark times, that''s what you''re about to do.'
WHERE `entry` = 70054;

UPDATE `quest_template` SET
    `OfferRewardText` = 'While I am glad we reduced their number it never pleases me to take lives, directly or indirectly.',
    `RequestItemsText` = 'My trust rests with you, $N. Please, do not fail me.'
WHERE `entry` = 70055;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have my gratitude for aiding Paige. She''s been in that camp for a great deal of time.$B$BAlas, there''s little we can do in the situation we''re in.',
    `RequestItemsText` = 'Yes, $C?'
WHERE `entry` = 70056;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What do you have there, $C?$B$BOh, where did you find this?$B$BThis was the shovel my father had given me back when we worked the farmstead years ago. It served me well, and reminds me of him.$B$BMemories of a better time.$B$B<Sven stares at the shovel and hands it back to you.>$B$BIt was a nice gesture of you to bring me this, $N, but I have no use for it anymore.$B$BDo with it what you will.',
    `RequestItemsText` = 'What is it?'
WHERE `entry` = 70057;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''d be a great asset to the Night Watch but I am more than certain you wouldn''t bore yourself with guard duty. Here''s a little reward for a job well done.',
    `RequestItemsText` = 'Back so soon?'
WHERE `entry` = 70058;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Nice job, kid. If you keep that up, you might be a foreman in, uh, eighteen or nineteen years.$B$BCompetition''s tough, y''know.',
    `RequestItemsText` = 'You know what they say. Time is money, employee.'
WHERE `entry` = 80100;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Nice! Just you wait. Mama Sprat''s gonna make magic out of these here buzzard bits.$B$BYou won''t even know you''re eatin'' a bird that feeds on rotting corpses!$B$BUh... Forget I said that.',
    `RequestItemsText` = 'I''ve got the best meals anywhere!'
WHERE `entry` = 80101;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Nicely done, recruit! Consider yourself officially on my star employee list. Stick with old Nert and you''re gonna go far!$B$BOh, uh... I guess if I''ve got you doing bruiser work, it might be worth arming you with something more than sharp wits. Just don''t tell anyone I gave you this weapon for free!',
    `RequestItemsText` = 'Stupid elves love trees so much. You know they grew themselves a giant tree to live in off the coast?$B$BThey got the magic to grow a tree the size of a city and they never think of the lumber market. It''s madness.'
WHERE `entry` = 80102;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This doesn''t make any sense. Why would they leave such valuable stuff behind?$B$BWhere the heck did everybody go?',
    `RequestItemsText` = 'This stuff will burn for years if you let it. There''s a reason it''s a goblin trade secret. But there''s no profit in burning down a whole forest!'
WHERE `entry` = 80103;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You know, sometimes farmers tell me their chickens are better than mine because their chickens don''t blow up.$B$BPersonally, I think my chickens are better - for the exact same reason. Anyways, thanks for picking me up some parts.$B$BHopefully I can whip something up that might be helpful against... whatever is going on in this valley.',
    `RequestItemsText` = 'Well, what are you waiting for?$B$BYou''re supposed to be some kind of big tough enforcer now, right? Go get me some parts!'
WHERE `entry` = 80104;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Nert looks over the note.>$B$BWell... That probably ain''t good. But we didn''t come this far just to quit because something scared off the last crew. Can''t go back to the boss empty-handed, right?$B$B<Nert looks troubled as he waves you off, perhaps trying to convince himself more than you that all is well.>',
    `RequestItemsText` = 'Why are you bringin'' me a piece of paper, kid? Do I look like your teacher?'
WHERE `entry` = 80105;

UPDATE `quest_template` SET
    `OfferRewardText` = 'This place gives me the willies. The sooner we''re out of here, the better, right kid?',
    `RequestItemsText` = 'I don''t like the look of ŌĆśem any more than you do, kid. But what choice we got?'
WHERE `entry` = 80106;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The first of many? Nope, nope, nope. I don''t care what the boss says, I am not gettin'' cursed by some angry ghost. We gotta get outta here, kid.',
    `RequestItemsText` = 'This place gives me the heebie-jeebies.'
WHERE `entry` = 80107;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Alright, we made it to Durotar. Step 1 complete.$B$BNow for Step 2 of my master plan... That I just made up.',
    `RequestItemsText` = 'Alright, we made it to Durotar.$B$BStep 1 complete. Now for Step 2 of my master plan. That I just now made up...'
WHERE `entry` = 80108;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What is this? Boar meat? You present this to me like an offering rather than delivering supplies...$B$BYou say Nert sent you? Nert Blastentom?',
    `RequestItemsText` = 'Hail, goblin. Are you with the caravan from Ratchet we''re expecting?'
WHERE `entry` = 80109;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A gift on behalf of you and your goblin refugee companions? You wish to join the Horde?! Listen, goblin...$B$B<You offer the boar ribs in an enticing manner, and after a moment of hesitation, Gar''Thok hungrily grabs the ribs. He devours the food with relish, making a mess but looking satisfied.>$B$BA goblin giving food freely. Hmm, I will see what I can do... First, formalities.$B$BAre you prepared to fight with honor among the ranks of the Warchief''s army? To be his blade and shield in lands unknown?',
    `RequestItemsText` = 'You don''t look like the caravan from Ratchet. What business do you have in Razor Hill?$B$B<Gar''Thok sniffs the air and starts to salivate.>$B$BIs that Torka''s cooking I smell? What I wouldn''t give for some of his boar ribs...'
WHERE `entry` = 80110;

UPDATE `quest_template` SET
    `OfferRewardText` = 'If it isn''t my old buddy, $N! Man, we''ve made some good memories together, yeah?$B$BI ain''t giving out no discounts, though. You know how it is.',
    `RequestItemsText` = '$N, pal, great to see ya. Let''s have a quick chat.'
WHERE `entry` = 80115;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So peach, you got my money? No? What do you mean no?!$B$BTsk, I guess you''re still a low grade thief. In that case, I guess I could teach you the ropes.$B$BIt''s not like I like you or anything... You still gotta pay me back!',
    `RequestItemsText` = 'If it ain''t $N. You thieving scoundrel.$B$BWhat do you mean it was your gig?'
WHERE `entry` = 80116;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You got my letter, $N?$B$BGood, good. Let''s do something about your shoddy aim. Before you know it, you''ll be putting holes in gold pieces from a hundred yards away.$B$BWhat? No, no, no! It was a figure of speech! Don''t go wasting perfectly good coin.',
    `RequestItemsText` = 'Shhhh, $N. Not so loud. I''m trying to take that buzzard out of the sky.'
WHERE `entry` = 80117;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Heya, sweetie! Great to see ya. Ready for Mama Wiz to teach you all these sparklin'' spells?',
    `RequestItemsText` = 'I been looking for you, $N! I got a new spell I''d like to try out, and I need an assistant.'
WHERE `entry` = 80118;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ooh, just in time! Ready to embrace the shadows?',
    `RequestItemsText` = '$N! Welcome, welcome. The dark arts await, friend.'
WHERE `entry` = 80119;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good job!$B$BDon''t tell the boss I was taking a break.',
    `RequestItemsText` = 'Oh, you''re back already?'
WHERE `entry` = 80120;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Beautiful! This will do nicely.$B$BNow watch and learn, kid - You only get to forcibly rip a demon from the void for the first time once in your life.',
    `RequestItemsText` = 'Was I not crystal clear? I need a crystal full of shadow magic for the summoning spell.'
WHERE `entry` = 80121;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You wish to assist?$B$BWell, your offer is welcome, $C. I have been the lone ranger at this lodge for years, so you can imagine my shock at seeing so many of my kind arriving with news that my homeland has fallen. Now, I have to contend with a hundred refugees.$B$BWe have much work to do, friend, but the burden will be lessened with the refugees assisting. We Quel''dorei must stand united now more than ever; we only have each other now.',
    `RequestItemsText` = ''
WHERE `entry` = 80200;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N. With this, we should have more than enough wood to keep our people warm and bellies full.',
    `RequestItemsText` = 'Do you have the wood, $N?'
WHERE `entry` = 80201;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N. This is only the beginning, but removing those vermin will ensure the refugees remain safe for now.$B$BWe have more work to do, though. The more assistance we get from you, the more help we can provide your people.',
    `RequestItemsText` = 'Well, $R, has the deed been done?'
WHERE `entry` = 80203;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A whole armed camp? Damn, this is a problem. We''ll need to devote resources into dealing with it that we don''t have. Thank you for your help, $N! We may call upon you again once we figure out how to handle this.',
    `RequestItemsText` = 'Have you spotted the Shadowforge scout?'
WHERE `entry` = 80204;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You got the water?$B$BThank you, $N. At least that''s one less problem we have to deal with.$B$BThe children will have water, and the progress on the well is going wonderfully!',
    `RequestItemsText` = 'Did you get it? The children are thirsty.'
WHERE `entry` = 80205;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, you know about it, then? My scouts have confirmed it.$B$BIt''s that damned Shadowforge raiding party you found. We should have struck right away, but instead I wanted to prepare... damn it!$B$BIt''s as if they knew we were onto them. You didn''t attack any of them, did you?$B$BWell, no matter. There is no time for regret. It is time to act!$B$BThe refugees have been put in cages, and the Dark Irons are preparing to ritually sacrifice them to their god, the Firelord Ragnaros.$B$BWe can''t allow it, $N! I''m going to need your help with this!',
    `RequestItemsText` = 'What is it, $N? Now is not the time.'
WHERE `entry` = 80206;

UPDATE `quest_template` SET
    `OfferRewardText` = 'They are all safe. I can''t believe it, we averted a disaster! I can''t thank you enough, $N! We take our duty very seriously, and losing those people would have been terrible.$B$BNow, we need to take care of that raiding party. There is someone who wants to speak with you about that. Go see Vyrin.',
    `RequestItemsText` = 'Time is of the essence, $N. Do not delay!'
WHERE `entry` = 80207;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You did well, $N. You deserve all the praise you''re getting.$B$BIt may not seem like much to save a few refugees, but consider that this is just the start of your journey. You exhibited great courage, too.$B$BI can safely say that I am proud to have met you. However, there is another matter we must talk about.$B$BSeveral of the refugee caravans have decided to move on to Stormwind. We can escort them part of the way there, but eventually they will arrive in a region beset by strife.$B$BBandits and beasts run amok while we are ordered to outlying areas such as this lodge.$B$BWe can''t go against our orders, but adventurers like you can make a difference back home.$B$BThink about it and talk to me again.',
    `RequestItemsText` = 'The hero of the hour returns, huh?'
WHERE `entry` = 80208;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Kathy Wake sent you?! You''ve certainly made connections if an SI... I mean, if a member of the Alliance military sent you!$B$BIf you''re here to assist, I can assure you that we''ll need the help. I have requested for reinforcements from the capital several times, but received nothing.$B$BIf Kathy vouches for you, then that''s good enough for me. I believe I have your first assignment in mind!$B$BOh, and don''t forget to visit the inn. You may want to attune your hearthstone there.',
    `RequestItemsText` = 'A high elf here? What can I do for you, stranger?'
WHERE `entry` = 80209;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wonderful! This will last a while until we can acquire supplies from the Alliance.$B$BWe can also use the seeds from the pumpkins to plan our own pumpkin patch.',
    `RequestItemsText` = 'Did you get the pumpkins and berries?'
WHERE `entry` = 80210;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So you''ve chosen to begin your training? I am pleased, $N. Very pleased. Talk to me again and I will do my best to guide you with my knowledge.$B$BIn time, I believe you will grow to become someone all rangers can be proud of calling a comrade!$B$BMy bearded friend, Claude Erksine, can also assist you with beast-related training once you are ready.',
    `RequestItemsText` = 'Yes? What is it?'
WHERE `entry` = 80211;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Light be with you, $N!$B$BIt honors and brings me endless joy to see you take the first step on the path of becoming a paladin.$B$BKnow that I shall do my utmost to guide you through the tenets and through your training.$B$BTalk to me again whenever you wish to seek my counsel.',
    `RequestItemsText` = 'Follow the Light.'
WHERE `entry` = 80212;

UPDATE `quest_template` SET
    `OfferRewardText` = 'By the Sun, you''ve come!$B$BMany of our people have lost their faith in the Light of the Sun as they wander like sheep lost in the dark. Together, we can be the beacon guiding them to salvation and to the warmth of the Sun!$B$BI shall do my best to be your beacon, $N. Ask and I will teach you what I can.',
    `RequestItemsText` = 'May the Sun''s Light shine upon you.'
WHERE `entry` = 80213;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, $N, I take it you''re here to become my apprentice?$B$BIf so, then know that I will not coddle you. You will be serving under a proud member of the Magisterium.$B$BAs such, you will be taught what I deem necessary for your progress. Continue to perform adequately and I shall continue to guide you.$B$BEventually, you will be fit enough for the Magisterium.$B$BTalk to me again once you are prepared.',
    `RequestItemsText` = 'The Magisterium is the most prestigious group that a mage can be a part of.'
WHERE `entry` = 80214;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So, you really came, huh?$B$BAmusing. Well, you''ve completed your first test, but don''t think that it''s your last.$B$BLet''s see how well you fare under my training. Talk to me again when you''re ready and I''ll teach you some tricks. If you continue to show potential, then expect me to continue teaching you.',
    `RequestItemsText` = 'Stick to the shadows, prot├®g├®.'
WHERE `entry` = 80215;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I must say that your appearance gives me hope.$B$BFew of our people take on the path of the sword. It is a long and arduous journey, but I have faith that you can overcome it with my training.$B$BIt doesn''t matter how many rangers or mages you have. In the end, you need someone on the frontlines to win battles.$B$BWhen you''re ready to take up that mantle, talk to me again.',
    `RequestItemsText` = 'Wielding the sword is just as majestic as it is powerful.'
WHERE `entry` = 80216;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, yes. While these clearly weren''t harvested by an expert, you did a pretty good job. Very well, $N, you''ve proven to be a capable $R. You know, some might not see them as very dangerous, but indeed they are. Here, some coin for your troubles, and I made you a cape from the remaining pelts.',
    `RequestItemsText` = 'Are you done yet, $N? We need the supplies.'
WHERE `entry` = 80217;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Nice job, $N. I''ll be sure to tell the others of your help.',
    `RequestItemsText` = 'If there''s one thing a goblin is always in need of, it''s dynamite!$B$BWhether it''s used to excavate, blow up enemies, or just to watch things go KABOOM!$B$BAnyways, bring me 20 heavy dynamite and I''ll be sure to put in a good word for you. Be sure to bring me quality dynamite too.$B$BI don''t care where you find it either, unless you were to find it off the corpse of a gnome. In that case, be sure to wipe it down with disinfectant before you bring it to me.$B$BGnomes have a characteristically unpleasant odor that I find, quite frankly, to be repulsive.'
WHERE `entry` = 80219;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah have you arrived from Alah''Thalas?$B$BIt''s good to hear our people are settling in safely. I am Illyanah Dawnstar, Quel''dorei representative.$B$BThe House of Nobles have granted us this street as a place to live and house our refugees for now. Of course you''re welcome to stay as well, we have lodgings, although our permanent housing building is filled to the brim, the Inn can spare a bed for a few nights.$B$BRest assured that plans are in motion to improve the situation of our people... permanently. Alas I must return to my book keeping, stay safe friend!',
    `RequestItemsText` = 'Yes? What can I do for you?'
WHERE `entry` = 80220;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahh, so you seek to assist us in our effort?$B$BWonderfulŌĆ”$B$BOur people have set up a new settlement called Alah''thalas on the coast north of Stratholme, bordering Quel''thalas. However, setting up a new home is difficult and we have run into our share of issues.$B$BYour help will definitely be appreciated! I shall sum up our situation for you.',
    `RequestItemsText` = 'Yes? What can I do for you, stranger?'
WHERE `entry` = 80250;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh you''ve come to assist Alah''thalas!$B$BI''m quite happy I must say, I knew Caledra could find nice people! I''m surprised she found a $C as capable as you!$B$BThe loss of Quel''thalas has grieved me greatly, but now I see hope, hope that our people can have a future again!$B$BTalk to me when you are ready and I will send you to Alah''thalas!',
    `RequestItemsText` = 'Oh my! What can I do for you, $R?'
WHERE `entry` = 80251;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh? That''s a nice haul... Good to see that you can be counted on, $R!$B$BAlright, time to calibrate these crystals so they can be integrated into the network...$B$BYou are still here?... Oh right, you want a reward, yes, yes. Now move along.',
    `RequestItemsText` = 'Have you gotten the crystals yet?$B$BI don''t care what you have to deal with...Rats or whatever''s down there, I expect this task to be done!'
WHERE `entry` = 80252;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What''s that you got there?...$B$BBy the Sunwell! These are perfect! Yes yes, I''m sure some of these will assist our cause! You have my thanks $R, you have my thanks indeed...$B$BHere is your little trinket, now get going!$B$BI have research to do.',
    `RequestItemsText` = 'What are you waiting for?$B$BEvery moment you delay some fat Ogre can crush an irreplaceable relic!$B$BGet going! We''re counting on you.'
WHERE `entry` = 80253;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done friend, well done indeedŌĆ” Keep this up and we will continue the work started by our ancestors.$B$BThe vile Forest Trolls and the Scourge cannot be allowed to grow in numbers, it is our duty to keep them both down and eventually exterminate them.',
    `RequestItemsText` = 'Well then? Is the deed done?'
WHERE `entry` = 80254;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You wish to assist me?... I suppose I can spare a moment to explain what you must do.',
    `RequestItemsText` = 'More interruptions! What is it?'
WHERE `entry` = 80256;

UPDATE `quest_template` SET
    `OfferRewardText` = 'These will do just fine. Not all of them are of the highest quality but they will be useful. Thank you $C.$B$BAh yes, here is your reward.$B$BReturn soon, $C.$B$BSelama Ashal''anore!',
    `RequestItemsText` = 'This will make a difference in the battle to come, please do not take it lightly.'
WHERE `entry` = 80258;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank the Sunwell! You have no idea how much this means to me.$B$BPeace and quiet is crucial while doing such vital work.$B$BUse this whistle to call the girl, and then you can listen to all of her problems instead of me.',
    `RequestItemsText` = 'I need your help!'
WHERE `entry` = 80260;

UPDATE `quest_template` SET
    `OfferRewardText` = 'She''s not in the Mage District. But we can''t give up!',
    `RequestItemsText` = 'Please, will you help me?$B$BPretty please?'
WHERE `entry` = 80261;

UPDATE `quest_template` SET
    `OfferRewardText` = 'She''s not here either... Mommy, where are you?!',
    `RequestItemsText` = 'I''m going to cry really hard if we can''t find her!'
WHERE `entry` = 80262;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Mommy is out there somewhere. Let''s continue please!',
    `RequestItemsText` = 'We cannot give up! We have to find her. I don''t know what I''d ever do without her.'
WHERE `entry` = 80263;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Mommy... N-No, I am sure we can find her, right?',
    `RequestItemsText` = 'Please, keep helping me. She can''t be far!'
WHERE `entry` = 80264;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Her mom is missing, you say? Give me a moment to look her up in our extensive collection of documents.$B$BThe girl''s name is Teslinah? We do have records of her and her mother''s arrival in Stormwind with the other refugees, but the two of them never showed up at the City hall for their registration.$B$BThis is a troubling discovery. We can''t have people going missing in Stormwind. I will investigate, but until my investigation is completed, can I count on you to care for the girl?$B$BSince she was registered here in Stormwind, I will issue some bonds to feed her properly.',
    `RequestItemsText` = 'Yes? What can I do for you, $R?'
WHERE `entry` = 80265;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Arcanist Anu''delen sent you? Finally, some good news, this damned expedition has just been one disaster after another. We made progress at first but not long after, everything went downhill.$B$BOur equipment broke, people thought the place was haunted, and some even claimed that they heard voices talking to them. But that last one is nonsense, I assure you.',
    `RequestItemsText` = 'Who are you, $R?'
WHERE `entry` = 80289;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So it was haunted, after all? It''s a shame we could not talk to the spirit, but I guess it''s for the best. Anyways, let''s see that tablet. Ah, it''s written in Thalassian, that makes things a bit easier. It details the establishment of Ishnu''danil as the new home of the Highborne and Alah''aran.$B$BBut look at this part. It''s a verse about a well, to be precise, a well of power. And what is this? Look here at the bottom. There''s a message inscribed here, but this does not match the writing style from before. It states:$B$B<Avoid the Shalla''aran. Avoid the Ishnu''danil. There is only darkness here>.$B$BIshnu''danil translates to Fortune''s Peak, but Shalla''aran means the Shadow Well. If something that powerful lies somewhere around here, we must find out more about it!',
    `RequestItemsText` = 'Did you get it?'
WHERE `entry` = 80290;

UPDATE `quest_template` SET
    `OfferRewardText` = 'If you didn''t find Thalo, it must mean that the skeleton was his. Oh well. And what is this about black slimes emerging from the well''s waters? So they were right, most intriguing.$B$BAnyways, your help here is appreciated, but I think it''s high time for you to leave. I still have research to do here, and you should inform Arcanist about our findings here, should you not?',
    `RequestItemsText` = 'You are back!? That is... good. Tell me, what did you find down there?'
WHERE `entry` = 80291;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Most of his expedition is dead, and he decided to remain there? Has he lost his mind!? A haunted place with talks of dark whispers and monsters coming out of the corrupted well is certainly not what I was hoping for us to find there.$B$BNevertheless, the information you brought may prove valuable to us. This is a lot to take in, and it''s a damn shame that such a powerful well ended up being corrupted. And this is where your work ends, and mine begins. Oh, and I almost forgot, here is little something for your valiant efforts.',
    `RequestItemsText` = 'Took you long enough, $N. You''re alone. Where is Scryer Thas''alah?'
WHERE `entry` = 80292;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ya seek to help us? Good, good. The Warchief allowed me to stay here and commission servants of the Horde willing to aid our cause.$B$BWe''ve named our new home Amani''Alor and already we have begun settling in, but as ya can imagine, settling in a new land be coming with its own issues.',
    `RequestItemsText` = 'What brings you here?'
WHERE `entry` = 80300;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The foul stench be starting to clear. Ya did good mon. Ya deserve a reward for ya efforts.$B$BKnow that in time, this place will not only be an asset to the Revantusk, but the Horde as a whole.',
    `RequestItemsText` = 'Is it done? Have the spirits been put to rest?'
WHERE `entry` = 80301;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ya looking to help the Revantusk, too? Well ain''tcha a fine diplomat of the Horde.$B$BThey be the last sane forest tribe and our cousins, so it be me pleasure to help them. Trolls around Azeroth been at odds for many many years, so it fill me with hope seeing tribes uniting under the Horde.$B$BIf ya ever wish to travel to Amani''Alor, just speak to me.',
    `RequestItemsText` = ''
WHERE `entry` = 80302;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You''ve proven your worth yet again, $C. We may not have been able to recover what they stole, but at least we set them back from launching their expedition.',
    `RequestItemsText` = 'Did you manage to recover any trinkets? Tell me of your battles.'
WHERE `entry` = 80303;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Spirits be with ya, $R. Ya efforts will keep us trolls healing up nicely. The Horde been nothing but kind to us, and we''ll see to it ya be repaid in kind.',
    `RequestItemsText` = 'How goes the squeezing, mon?'
WHERE `entry` = 80304;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yeah, yeah, pal, in a minute!$B$BWhat''s the rush?',
    `RequestItemsText` = 'Why are you still here, $N?$B$BIf you wanted to buy me a drink, I''m sorry, but I you''re not my type. Unless, of course, you''ve got enough coin. Then, maybe something can be arranged.'
WHERE `entry` = 80305;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The early investor reaps the most interest.',
    `RequestItemsText` = 'Hey there, sweetie. Wanna play a quick game of chance with your local beauty, Agne?'
WHERE `entry` = 80306;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Quark''s tobacco?$B$BWe might have a problem.$B$BWait! No reason to be aggressive. Listen.$B$B<Wiley throws in a few coins to dissuade you from violence with quivering little hands.>',
    `RequestItemsText` = 'I''m running really low on my supplies, here, $N. Could seriously use that cargo right about now!'
WHERE `entry` = 80307;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What, pirates?! Pirates?!$B$BScrew pirates, sweet mother of goblins!$B$BFor crying out loud, argh, gnomish bastards!$B$BI guess these crates will do. I owe you one, $N. ErŌĆöactually, I don''t. Here, just take this membership card instead. You''ve earned it. You''re officially a member of Quark''s Shack, now. Gamble your heart away, pal.',
    `RequestItemsText` = 'There''s gonna be a big problem if I can''t get my missing cargo shipments.'
WHERE `entry` = 80308;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So Odo be right again. Never doubted my gut feelin''. We should go speak to Quark and confront Sturk to arrest ''im.',
    `RequestItemsText` = 'I tell ya, mon, my gut be fo'' real! Get th'' criminal.'
WHERE `entry` = 80309;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Now, with that done, I have to figure out a way to recover the money I lost. Thanks for the help, pal. Stick around. You''re a valuable member, now. Also, here! Can''t give ya loads of cash, but drinks are on me today.',
    `RequestItemsText` = 'Just get him out of my sight before I give him a good smackdown!'
WHERE `entry` = 80310;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Another one with thirst for knowledge? Good, good! I know what you need. I know what you want!$B$BYes, we know what you crave for!',
    `RequestItemsText` = 'Hrrm? Yes, what, huh?$B$BChok''Garok. Yes, it''s us! Yes, two heads!'
WHERE `entry` = 80311;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, yes! That''s what we need! The arcane is strong to weave on with this one! Yes, powerful casting!$B$BYou take this weapon now, go be proud and strong. Yes, yes.$B$BChok''Garok powerful, yes!',
    `RequestItemsText` = 'You have the parts yet? Yes, yes, bring the parts!'
WHERE `entry` = 80312;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Good, good. We be having much to do, so don''t go scurrying yet mon.',
    `RequestItemsText` = ''
WHERE `entry` = 80313;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I haven''t gotten one of these in years, mon. Do ya understand the meaning of this gesture?$B$BThis be a voodoo doll of Warleader Zol''majin himself, given in confidence to another troll. This doll will eventually reach Vol''jin, so Zol''majin be putting his life in the hands of the Darkspear.$B$BThis be a symbol of great trust between the tribes. This gesture may be returned in kind with time.',
    `RequestItemsText` = 'Ya mon? Ya say ya got something for me?'
WHERE `entry` = 80314;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I can feel the life flowing back into my leaves, $R. That druid really worked some magic with that salve. I wonder what''s inside? I''ll study it closely until I find out so that other trees like me don''t get sick, too!',
    `RequestItemsText` = 'Please hurry, $R. I don''t know how much longer my leaves have before they completely fall away.'
WHERE `entry` = 80315;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A belt, huh? Clever and crafty, but we best not go poking around in any secret compartments in it. I''ll get this back to Ratchet so it can be safely investigated. You''ve been a big help! Thanks!',
    `RequestItemsText` = 'Is it done? Did you find anything?'
WHERE `entry` = 80320;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Yes, $C, I made this. What of it?',
    `RequestItemsText` = 'What are you looking for?'
WHERE `entry` = 80321;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Kiro sent you, no doubt. I didn''t tell that cursed woman about my ability for her to send me customers!$B$BIf she has an urgent enough reason, then just give me the coin and show me the mark of fel. But I don''t promise you''ll like the answer I have to give about its source.',
    `RequestItemsText` = 'A customer! Greetings, $C. Take a look at what I have to offer.'
WHERE `entry` = 80322;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Interesting.$B$B<Gazlowe turns the belt over in his hands.>$B$BNeeru Fireblade, eh? I wonder what Neeru is trying to pull right under Thrall''s nose?$B$BGo on, now, $N. I''ve got a few contacts to reach out to. I''ll get in touch with you when the next step is to be taken.',
    `RequestItemsText` = 'Welcome back, $N. You still have the belt?'
WHERE `entry` = 80323;

UPDATE `quest_template` SET
    `OfferRewardText` = 'There you are! I was wondering where you''d run off to. You didn''t think I''d notice you go missing?$B$BWell at least you''re here now, so let''s get down to business.',
    `RequestItemsText` = ''
WHERE `entry` = 80330;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So you''re not completely incompetent. Alright then, let''s really test your beast-wranglin'' skills!',
    `RequestItemsText` = 'Go on, then. Show ŌĆśem who''s boss.'
WHERE `entry` = 80331;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You made that look easy! You got a bright future in this hunter business, pal. You''ll be bagging dragons in no time.$B$BYou can take that to the bank. I got a good intuition about these sorta things.',
    `RequestItemsText` = 'Well? C''mon, kid! If you can''t even tame a crab, you can kiss your dreams of taming a crocolisk goodbye!'
WHERE `entry` = 80332;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Look at you, kid! You grew up so fast. It''s enough to make this old goblin tear up. Almost. Thanks for the merchandise. These are some great specimens. Now, you''re gonna have to choose one of your own.$B$BI''ve taught you all I know and given you my spare collar. It''s pretty much unbreakable, but try to be careful with it anyway, alright?$B$BYou can summon and dismiss a pet whenever you want from now on. Flex that confidence you been building up with this training and all the critters in the land will call you master before long.$B$BIn no time at all, you and your pet will make an unstoppable duo! Payment due for these lessons when that day comes, by the way.',
    `RequestItemsText` = 'Move it, kid. You want to miss your chance to be a legendary beast-tamer? I mean, same goes for dying to scorpid venom, so... Don''t take that big a chance.'
WHERE `entry` = 80333;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A young $C, I see. Yes, I will grant you the skills you need to train and guide your pet. Not only will you be able to teach your pet new abilities, you will now be able to feed your pet, as well as revive it, should it fall in battle.$B$BNow, go, $C. We will speak again, at a later date.',
    `RequestItemsText` = ''
WHERE `entry` = 80334;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, hello there! Hmm... I believe I can help you, yes!',
    `RequestItemsText` = ''
WHERE `entry` = 80339;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, my! Well done. This rod definitely requires further testing, and you can get a better choice of companion in the process.',
    `RequestItemsText` = 'Did you tame it yet? Did it work? Don''t worry, you can tame another one if you don''t like the attitude of this particular boar.'
WHERE `entry` = 80340;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wonderful! Now that''s a pretty feline! Of course, in the end, I''ll leave it up to you what beast you would like to tame.',
    `RequestItemsText` = 'Snow leopards are white and spotted to blend into the snow. They might be hard to find.'
WHERE `entry` = 80341;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done, $N! Marvelous! Together we''ve proven to those snooty dwarves that we gnomes are just as capable Mountaineers as they are! Your brilliant success is more than enough to stifle any further snickering and teasing.$B$BFor that, I thank you, $N. As promised, here''s the schematic and instructions for the G.N.O.E.M.R. Taming Rod!$B$BNow get out there, find yourself a companion, and show the world Gnomeregan''s best!',
    `RequestItemsText` = 'Did you get an Ice Claw Bear yet?'
WHERE `entry` = 80342;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Spinpistol sent you? That must mean her hairbrained scheme panned out after all. That wee lass you trained with actually managed to accomplish her crazy scheme of taming beasts, then? I''ll be... And you helped her? You''re clearly more than meets the eye, already on your way to becoming a great $C, I see.$B$BVery well. I can bestow you with the skills you need to train and guide your pet. Not only will you be able to teach your pet new abilities, but you will also be able to feed your pet as well as revive it if it falls in battle.$B$BRemember that the key to getting the most from your new pet is to respect it and treat it well. In turn, your pet will be your most loyal friend.',
    `RequestItemsText` = ''
WHERE `entry` = 80343;

UPDATE `quest_template` SET
    `OfferRewardText` = 'One thing you should always remember is that you gotta respect the world you''re livin'' in. The beasts that choose to fight along side you; the shine of your weapon; the weight of your ammo; the bite of a bitter wind; all these things you need to know intimately.$B$BFixated as the gnomes may be on technology and machinery, never forget that respect for nature it essential to a hunter. I''ll do what I can to help you, but most of the work''s up to you. Anytime you think you''re ready, come back and talk to me. I''ll train you when I can.',
    `RequestItemsText` = 'Ya made it! Good to hear! Betcha didn''t have to track me to find the place either. Haha!$B$BOur profession is pretty steeped in tradition, $N. Learning the ways of the land. Learning to track a bear through the mountains. Even just surviving on wits alone takes a great deal of courage and cunning. Think you''re capable?$B$BCan''t say I''m sure ye''ve got what it takes. A gnome hunter, eh? I can see you''re determined to succeed and put your own twist on the profession, though, so who am I to stop ye?'
WHERE `entry` = 80350;

UPDATE `quest_template` SET
    `OfferRewardText` = '$N, you''re a doll! This is great, I can''t thank you enough.$B$BIf you get any more you know where to find me.',
    `RequestItemsText` = 'Any luck finding the oil?'
WHERE `entry` = 80352;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah yes, that''s absolutely great bub. Just toss them right there, here''s the pay.$B$BThere''s always work for you here if you need it.',
    `RequestItemsText` = 'Can you believe it? He went back to cutting!$B$BPlease tell me you got a few back.'
WHERE `entry` = 80353;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It will take time for our loa to begin to feel as if this is their home, just as it will take time for us to accept it as ours. We will grow together and nurture their spirits while they safeguard our homes. Halazzi''s cunning keep your wits, until then.',
    `RequestItemsText` = 'Akil''darah has blessed the winds at your back with what strength she has.'
WHERE `entry` = 80360;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Greetings, ranger. Yes, perhaps it is time for you.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 80366;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, excellent. Give me but a moment to concoct a brew. Give it a taste.',
    `RequestItemsText` = 'Has your hunt gone well?'
WHERE `entry` = 80369;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wonderful! We thank you for your generous donation, $N!',
    `RequestItemsText` = 'We are currently accepting donations for wool cloth. A donation of sixty pieces of wool cloth will net you full recognition by Alah''thalas for your generous actions. Our stores are such on wool that we would only need sixty pieces from you total; we should be able to acquire enough from others in the realm to support our drive.$B$BIf you have the sixty pieces of wool cloth on you and are ready to donate them, I''m able to take them from you now.'
WHERE `entry` = 80370;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wonderful! We thank you for your generous donation, $N!',
    `RequestItemsText` = 'As with most other fabrics, our stocks of silk are at an all-time low. Our stores are such that we''d only need sixty pieces of silk from you total; we should be able to reach our goal with the support of others.$B$BA benevolent gift such as silk, might I add, would certainly increase your local standing in the community! If you have the sixty pieces of silk cloth on you and are ready to donate them, I''m able to take them from you now.'
WHERE `entry` = 80371;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wonderful! We thank you for your generous donation, $N!',
    `RequestItemsText` = 'Mageweave is running low, and we could use your help to replenish our stocks!  By counting on the community as a whole, we would only need a donation of 60 pieces of mageweave cloth from you to enable us to reach our goal.  Such generosity would not go unnoticed by the Alah''thalas, I assure you!$B$BIf you have the sixty pieces of mageweave cloth on you and are ready to donate them, I''m able to take them from you now.'
WHERE `entry` = 80372;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Fantastic - these will go right to use, I assure you. Thank you again for your assistance! We''d certainly be lost without you.$B$BWith all the donations you''ve made, I would certainly process any additional runecloth donations you care to make in the future. Just be sure to check in with me, and I''ll personally make sure that your good deeds won''t go unrecognized!',
    `RequestItemsText` = '$N, you''ve been a tremendous contributor to our cloth drive. As we work hard to replenish our reserves, one form of cloth remains critically low - runecloth. We are in absolutely dire need of it, and we hope that you will be able to help us as you have in the past!$B$BIf you are willing, please bring me what runecloth you can spare. We''ll initially accept a single donation of sixty, and then we''ll go from there.'
WHERE `entry` = 80373;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Greetings once again, $N! Our need for runecloth is constant, and we can always use additional resources if you are willing to part with them. For an additional stack of twenty runecloth, I will make sure that you are recognized for your continuing efforts on behalf of Alah''thalas.',
    `RequestItemsText` = 'Whenever you are ready to hand in the stack of runecloth, I''ll accept it.'
WHERE `entry` = 80374;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wonderful! We thank you for your generous donation, $N!',
    `RequestItemsText` = 'We are currently accepting donations for wool cloth. A donation of sixty pieces of wool cloth will net you full recognition by Amani''alor for your generous actions. Our stores are such on wool that we would only need sixty pieces from you total; we should be able to acquire enough from others in the realm to support our drive.$B$BIf you have the sixty pieces of wool cloth on you and are ready to donate them, I''m able to take them from you now.'
WHERE `entry` = 80375;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wonderful! We thank you for your generous donation, $N!',
    `RequestItemsText` = 'As with most other fabrics, our stocks of silk are at an all-time low. Our stores are such that we''d only need sixty pieces of silk from you total; we should be able to reach our goal with the support of others.$B$BA benevolent gift such as silk, might I add, would certainly increase your local standing in the community! If you have the sixty pieces of silk cloth on you and are ready to donate them, I''m able to take them from you now.'
WHERE `entry` = 80376;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wonderful! We thank you for your generous donation, $N!',
    `RequestItemsText` = 'Mageweave is running low, and we could use your help to replenish our stocks!  By counting on the community as a whole, we would only need a donation of 60 pieces of mageweave cloth from you to enable us to reach our goal.  Such generosity would not go unnoticed by the Amani''Alor, I assure you!$B$BIf you have the sixty pieces of mageweave cloth on you and are ready to donate them, I''m able to take them from you now.'
WHERE `entry` = 80377;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Fantastic - these will go right to use, I assure you. Thank you again for your assistance! We''d certainly be lost without you.$B$BWith all the donations you''ve made, I would certainly process any additional runecloth donations you care to make in the future. Just be sure to check in with me, and I''ll personally make sure that your good deeds won''t go unrecognized!',
    `RequestItemsText` = '$N, you''ve been a tremendous contributor to our cloth drive. As we work hard to replenish our reserves, one form of cloth remains critically low - runecloth. We are in absolutely dire need of it, and we hope that you will be able to help us as you have in the past!$B$BIf you are willing, please bring me what runecloth you can spare. We''ll initially accept a single donation of sixty, and then we''ll go from there.'
WHERE `entry` = 80378;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Greetings once again, $N! Our need for runecloth is constant, and we can always use additional resources if you are willing to part with them. For an additional stack of twenty runecloth, I will make sure that you are recognized for your continuing efforts on behalf of Amani''alor.',
    `RequestItemsText` = 'Whenever you are ready to hand in the stack of runecloth, I''ll accept it.'
WHERE `entry` = 80379;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You got the goods? Sweet! I''ll get cookin'', but first, I promised you the Saltcrabs formula for a perfect brunch, didn''t I? Well first, you set down a blanket, then you put up an umbrella! That was worth the effort, now wasn''t it? Thanks for the meats, $N. I''m gonna knock the pants off these partygoers!',
    `RequestItemsText` = 'Time''s a-tickin'', bub. Can''t waste what''s left of it before this big palooza so I can surprise the culprit with my amazing spicy crab souffle. It''s a cutthroat cooking competition out here that drives people to do these crazy things, $N, but I''m always one step ahead.'
WHERE `entry` = 80380;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Excellent work. I''ll give you a tour of the inside of my mansion when the Shellcoin value reaches 1000 gold.$B$BIn the meantime, take some old hand-me-downs. They look like they might fit you.',
    `RequestItemsText` = 'What are you waiting for? Get in now. Buy buy buy!$B$BHurry before the market value skyrockets!'
WHERE `entry` = 80381;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Sweet, my party''s gonna rock! I can''t wait to see what kind of clout these boys bring.$B$BIf they''re really high rollers, they''ll buy a whole bar''s worth of booze.$B$BThanks again for your help. Why don''t you join us on this beautiful beach front? Not looking like that, though. You''ve gotta have the right stitching to kick it with me. Take these and put them on.',
    `RequestItemsText` = 'Hurry up or you''ll cramp my style! I don''t want these guys to think I left their invites for last.'
WHERE `entry` = 80382;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You did it! Now that shark can get back to its lifestyle as the apex predator in the sea instead of being strung up like a trophy which is what these goblins would have done to it.$B$BI have a little memento for you as a reward. Take good care of it, okay?',
    `RequestItemsText` = 'Did you know that sharks have skeletons made of cartilage and not bones?'
WHERE `entry` = 80383;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ahahahhah! Good job, mon! For my part of the deal...$B$B<Lau''Tiki crack opens one of the shells and extracts something from it.>$B$BHere''s da secret, mon. This tiny pesky bastard might come in handy when ya tame it and feed it. Though never fully trust it, dey like nibbling on fingers.',
    `RequestItemsText` = 'Hunt them, bring me their shells!'
WHERE `entry` = 80384;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Your help is appreciated, sugar, keep them coming!',
    `RequestItemsText` = 'I never thought we''d have a fresh start, and not in my wildest dreams I''d think we''d do that under the Horde''s flag, but what do you know, here we are.$B$BWe currently are a small group of goblins that ran away with only scraps and dust in our pockets, but slowly we will make a name for ourselves, and if you want, you can be part of that.$B$BThe Labor Union grows day by day, goblins come our way to find a new meaning in life under the Horde''s gaze, but we lack both means and resources.$B$BIf you wish to be part of the Union''s future bring me a handful of Whirring Bronze Gizmos whenever you can. You will eventually get paid.'
WHERE `entry` = 80386;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well then, have you decided, $C? Do you have what it takes to become Immortal? Once you start walking this path, you will not be able to abandon it. It will forever dominate your destiny. Only those who follow the same path will be of aid to you.$B$BNo mail will ever bring you good news. No auction will take your money.$B$BVery well. Should you die, your soul will forever be mine. If you survive the trials ahead, we shall meet again one day.',
    `RequestItemsText` = ''
WHERE `entry` = 80388;

UPDATE `quest_template` SET
    `OfferRewardText` = 'What''s this, a letter from Gazlowe?',
    `RequestItemsText` = 'Durotar Labor Union, has a nice ring to it, doesn''t it?'
WHERE `entry` = 80390;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My hunger has finally been sated, and my belly feels overjoyed!$B$BYou can have these odd objects I found while scavenging for tools as well as my friendship and gratitude. Hopefully in time I can find my way back to my homeland.$B$BThank you so much friend. I have the strength and soon I will have the tools to hunt for myself now as I seek a way home, you need not worry for me anymore, may our paths unite again one day.',
    `RequestItemsText` = 'Did you get the meat? I feel my strength wane...'
WHERE `entry` = 80391;

UPDATE `quest_template` SET
    `OfferRewardText` = 'A package for me? From my sister? thank you so much. Here is your payment as promised.$B$BActually there is one more thing I would like you to help me out with...',
    `RequestItemsText` = 'Welcome to Quel''Danil, how may I be of assistance?'
WHERE `entry` = 80392;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have my deepest gratitude, $C, and of course I''ll make sure to thank Loania, too. You must be curious why a human is among us. If you are interested, then I shall tell you...',
    `RequestItemsText` = 'Yes, $C? What brings you here?'
WHERE `entry` = 80393;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh you''re an adventurer that has come to investigate the lights aren''t you? Don''t worry, I was merely experimenting with a special matter transmitter and it is of no danger to anyone!$B$BFear not, my experiment will be of use to everyone once it succeeds! On the other hand, I have a task for you if you wish to keep this area safer!',
    `RequestItemsText` = 'Oh my, greetings! Who are you?'
WHERE `entry` = 80395;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wonderful. I wonder what it felt like to have their blood splatter all over you, or what came into your mind as you heard them scream in pain and fall like the vermin they are.$B$BI wish I could have been there to see it for myself, heh.$B$BNonetheless, know that thanks to your violent deeds many lives were saved. Now, of course I''ll be sure to reward youŌĆ” Hmm, let''s seeŌĆ” Yes, this will be something you can either use or sell for compensation.$B$BI''ll make sure to tell others of your deeds. Hopefully we''ll meet again, $N.',
    `RequestItemsText` = 'Well, did you do it?'
WHERE `entry` = 80396;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Thank you, $N! With the Venture Company''s activities unchecked, this surely isn''t the end of those sap beasts, but for now the forest is quiet and already healing. Here, take a few of my potions in thanks for your hard work. They should help you travel swiftly in this mountainous terrain.',
    `RequestItemsText` = 'Have you rid the mountaintop of those sap beasts? Rest here for a moment and recover your strength.'
WHERE `entry` = 80397;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Is that an actual intact Pounder Mainframe?! Where did you get this?$B$BThe possibilities with this are endless! Tell you what, if you allow me to copy the data from this mainframe then I will help you build a Pounder of your own!',
    `RequestItemsText` = 'Hello there, $R, are you here for one of my inventions?'
WHERE `entry` = 80398;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Zalazane''s mojo and his apprentice''s head? A job well-done. Here, I''ve got a reward for you. Just pick which one you want.',
    `RequestItemsText` = 'What do you have there, $N?'
WHERE `entry` = 80399;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, me bonnie, precious, darling book! What did those scunnered bampots dae to ye?$B$BThank ye, $C, I''ll never forget yer kindness.$B$BI''ll be sure to add a dedication to yer name once I put me book back together!',
    `RequestItemsText` = 'Wreckin'' me camp, stealin'' me belongings, eatin'' me haggis and even settin'' me camp ablaze are nowhere near as horrible a crime as stealin'' me bonnie book!$B$BMake ''em suffer worse than a gryphon with clipped wings!'
WHERE `entry` = 80400;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That''s all the components! Wonderful!$B$BWhile you were gone, I''ve been busy engineering your Pounder. All that''s left is to apply the components you''ve brought and to paint it.$B$BI didn''t do the paint job yet so you could pick a color!',
    `RequestItemsText` = 'Welcome back! How did it go? Did you get the items yet?'
WHERE `entry` = 80401;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I suppose I can use the help. There''s not much here a $C would be interested in, anyway.',
    `RequestItemsText` = 'How can I be sure that I can trust you?'
WHERE `entry` = 80403;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Drazzit accepts the cargo from you.>$B$BI''m so hungry, I could eat a dragon! Thank goodness Moxie finally got some of that cargo down here. We''ve been reduced to playing dice against the ogre for whatever he''s managed to kill on his hunting trips!',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 80404;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Wow! You certainly found a lot more than I expected would be out there. I''m not sure how much Drazzit thought we were going to find out here, but he''s going to have to be happy with this for now.',
    `RequestItemsText` = '<Moxie looks frantic with worry.>$B$BDid the cargo survive? Did you find any of it?'
WHERE `entry` = 80405;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Hello again, $N! I see that Reas succeeded in her task.$B$BGood, good! I have need of your aid again!',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 80407;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You really got 12 brains?! Sick! Well, money is money.',
    `RequestItemsText` = 'Yes?'
WHERE `entry` = 80408;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The person you''ve been helping has been working to change history. Not only that, but the crystal you''ve been using is no simple invention, it is a time crystal, and it has been somehow corrupted and twisted!$B$BI first took notice of this in when time was altered in the Barrens and I intended to observe, but now? I can''t ignore this. I''ll be taking this corrupt time crystal and I will find that gnome and take her into custody.$B$BI will do my best to investigate this entire affair and I may ask for your help later. Do not work for her anymore or I''ll have to punish you.  Also I found this in a crate by the crystal, it was supposed to be your reward I guess. Normally I''d confiscate it, but I''ll look the other way if you help me capture her the next time she shows up.',
    `RequestItemsText` = 'Hello, $N!'
WHERE `entry` = 80409;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Remember back in Tanaris when I told you I''d call for you when the time came? Well, that time has come. I''ve found her!',
    `RequestItemsText` = 'There you are, $N! You''re late! Or early. Well, it doesn''t matter, at least you came.'
WHERE `entry` = 80410;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It seems that this mysterious dragon seeks to corrupt the timeways. I have my disagreements with Kheyna over her disruptive actions, but I''ve put them aside now because of this greater threat. It seems that this dragon she was hunting has caused a major disruption at a specific point in time.  She also mentioned a master so there may be more of them. I hope I can count on you when the time comes. For now, we will do our best to keep things stable as we figure out how to move ahead from here. Kheyna will cooperate with us under strict supervision. Her fate will be decided after this is dealt with.  We have prepared this replica sword as your reward.',
    `RequestItemsText` = 'There you are. I have been given much to ponder on.'
WHERE `entry` = 80411;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Do not mind the weirdness here too much, it''s all timey wimey.$B$BYou''ll get used to it... Maybe. Anyway. Thank you for coming and welcome to the Caverns of Time!$B$BThis is where the Bronze Dragonflight lives, and it is also where the time ways to different periods in history are.$B$BThe corridors that you can see here are ever changing and shifting.$B$BFrom one moment to the next a corridor before you can be replaced with another.$B$BAlas you can never truly experience the timeways with your limited perception of time.$B$BBut I digress, we have a job to do!',
    `RequestItemsText` = 'There you are... Try not to step into the time streams, and whatever you do never try to enter the hourglass.'
WHERE `entry` = 80604;

UPDATE `quest_template` SET
    `OfferRewardText` = '<Kheyna stares somberly at the head, her ocular implants contracts for a moment>$B$BAntnormi was like a sister to me once.$B$BI wish this could have ended differently, but alas... We did what we had to.$B$BFor the time being I will remain here until Chromie figures out what to do with me. I was once a Bronze dragon after all, maybe I can be one again if we find a cure.$B$BRemember when I had you collect brains for me? That work paid off, and I''ve made a version of my implant that can connect to your brain without needing to drill into your skull.$B$BIt''s your reward for what you''ve done. Take it, it''ll help you.$B$BI also wish to introduce myself to you properly. My real name is Keridormi. I''ve never had many friends, so thank you for everything you''ve done for me.$B$BPerhaps we will meet again in time. Stay safe!',
    `RequestItemsText` = 'Please... You cannot let her win!'
WHERE `entry` = 80605;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You did it? Wonderous!$B$BMaybe now they''ll think twice before making my glove disappear.$B$BWait, they didn''t take my glove?$B$BWell, hopefully they don''t take my other one now...',
    `RequestItemsText` = 'Did you find one of the mysterious masters of our world yet?'
WHERE `entry` = 80606;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Here''s the letter, I hope I won''t have to do this again.',
    `RequestItemsText` = 'Just take it off my hands before the guards think we''re doing something shady.'
WHERE `entry` = 80700;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, my ring.$B$BIt seems you''ve made it, apologies for the secrecy but we must be careful, even our walls have ears that do not belong to the organisation.',
    `RequestItemsText` = 'How can I help you, stranger?'
WHERE `entry` = 80701;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So we were right, this would''ve been valuable information if we didn''t already receive another report.$B$BSorry about that, $N. I will be needing your help once more.',
    `RequestItemsText` = 'How is your task going?'
WHERE `entry` = 80702;

UPDATE `quest_template` SET
    `OfferRewardText` = 'So this is all you could salvage from the idiots that willingly murdered our caravan, eh?$B$BIŌĆÖll take him to the dungeon, good job.',
    `RequestItemsText` = 'The Scarlet Crusade must be put to an end.'
WHERE `entry` = 80703;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You are at an impasse, not sure how to proceed. Given the circumstances you must make the best out of what you have.$B$BWhile contemplating the matter you take a wide look around the room, noticing that Stoutfist and the other guards left some means of approach to you. It''s time for you to decide how to approach the interrogation of the prisoner.$B$BThe coffee mug on the table tells you it''d be best to persuade him. The iron maiden next to him gives you other ideas.',
    `RequestItemsText` = 'The figure in front of you is displeased at your sight and is practically tearing you apart in their mind.'
WHERE `entry` = 80704;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Reaching for the quill and ink, you note the information you extracted from Vladeus thus finalizing the report.',
    `RequestItemsText` = 'The report seems incomplete, other than some basic information of the prisoner there''s really nothing useful there.'
WHERE `entry` = 80705;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Reaching for the quill and ink, you note the information you extracted from Vladeus thus finalizing the report.',
    `RequestItemsText` = 'The report seems incomplete, other than some basic information of the prisoner there''s really nothing useful there.'
WHERE `entry` = 80706;

UPDATE `quest_template` SET
    `OfferRewardText` = 'It seems you got what you needed then, we will send the prisoner back to Stormwind so they decide his fate.$B$BWhatever you did to obtain this information, I won''t judge it, I just hope you are content with your own choices.',
    `RequestItemsText` = '<You are welcomed with nothing but a silent stare.>'
WHERE `entry` = 80707;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Bold accusation, $R, I almost feel offended.$B$BI fear it was not me, things wouldŌĆÖve been simpler. I assume you got a name from your prisoner. Tell me what happened.',
    `RequestItemsText` = 'How can I assist?'
WHERE `entry` = 80708;

UPDATE `quest_template` SET
    `OfferRewardText` = 'WeŌĆÖve been expecting at least a handful of new recruits, not just one.$B$BExplain yourself immediately.',
    `RequestItemsText` = 'Speak quickly or move along.'
WHERE `entry` = 80709;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Perfect condition, if anything this rotten could be called something other than disgusting.$B$BBlasted Scourge, I hope the High General is right.$B$BNow onto your next task, recruit.',
    `RequestItemsText` = 'DonŌĆÖt worry yourself with details, do as you were told.'
WHERE `entry` = 80710;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Welcome back, brother and may the Light bless us both in the days to come.$B$BHereŌĆÖs your insignia and hereŌĆÖs the map for the entrance, the High General will be very pleased to have you.$B$BFor the Scarlet Crusade, for the Light and for Lordaeron!',
    `RequestItemsText` = 'ItŌĆÖs a simple task, kill and collect, what more do you want?'
WHERE `entry` = 80711;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, $N, here to do my bidding. I expect you to be quicker if you deem yourself worthy of remaining in my service.',
    `RequestItemsText` = 'Kneel all you like, mortal. I do so enjoy a good groveling.'
WHERE `entry` = 80720;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The fanatics of the Scarlet Crusade are behind this?$B$BHere I thought such cunning to be bereaved of their agitable little brains.',
    `RequestItemsText` = 'I will empty your veins if you dare dawdle before me for one more fruitless instant.'
WHERE `entry` = 80721;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I can smell the sweet stench of man-blood on you, $N. Good, very good.$B$BAs for Deathguard Mavonius there, the Undertakers and Apothecaries can tend to him, and I expect that to be the last of your concerns.',
    `RequestItemsText` = 'You return already.$B$BHow is Meverius? Not too tarnished, I hope?'
WHERE `entry` = 80722;

UPDATE `quest_template` SET
    `OfferRewardText` = 'My name is Zinge, $C.$B$BShow me what you''ve brought and I shall help you as I can, if such is my lord''s command.',
    `RequestItemsText` = 'Zwinker...Yes, I can see that Lord Varimathras sent you.'
WHERE `entry` = 80723;

UPDATE `quest_template` SET
    `OfferRewardText` = 'If your tale and the effects of this potion are true, you were right to come to me.$B$BThis is a weapon that should never lay in the hands of the Scarlet Crusade. As for what it is, you will have to indulge me momentarily.',
    `RequestItemsText` = 'Another visitor.'
WHERE `entry` = 80724;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You had to battle a mage for it?$B$BI presume he failed to speak his name as you slew him, but that ought to be no concern of ours.$B$BYou fulfilled your end of the bargain, $N, and it is now my turn to repay the debt.',
    `RequestItemsText` = 'Were you successful?'
WHERE `entry` = 80725;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Bah, draughts, potions and stones. Could there be anything more tedious?$B$BAt least that so-called ''lich'' made himself useful. As did you.$B$BYou have pleased me once more.',
    `RequestItemsText` = 'My loyal $R returns.$B$BGo on, speak.'
WHERE `entry` = 80726;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Do you think me a fool, $N? Did you think I would be unaware of what occurs within my own realm, within my own throne room?$B$B<Sylvanas shreds the report with her hands.>',
    `RequestItemsText` = '<Sylvanas takes the report you give her. She does not open it.>'
WHERE `entry` = 80727;

UPDATE `quest_template` SET
    `OfferRewardText` = 'That will suffice. Lay it here for a moment. It will not take me long.',
    `RequestItemsText` = 'Yes, the Banshee Queen forewarned me of your arrival. Do you have the uniform at hand?$B$BIt might make amends for the unfortunate feelings I hear you roused in her.'
WHERE `entry` = 80728;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Ah, another recruit, what took you so long to get here?',
    `RequestItemsText` = 'Speak quickly or move along.'
WHERE `entry` = 80729;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Listen here pal, I am trying to make a living, so you either buy something or scram!$B$BOf course unless you got something else to talk about but make it quick!',
    `RequestItemsText` = 'Now do you want to buy something or just bother me?'
WHERE `entry` = 80730;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well. I will now teach you what I know to uphold our agreement.',
    `RequestItemsText` = 'Bring me 3 Scales of Onyxia.'
WHERE `entry` = 80735;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have done well.',
    `RequestItemsText` = 'What are you waiting for? Bring me 3 Refined Scales of Onyxia. Are you not eager for my knowledge?'
WHERE `entry` = 80736;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Endulge in the secret recipe of the Gurubashi with glee. You are as reknowned as their most savage fighters.',
    `RequestItemsText` = 'So, made your mind up?'
WHERE `entry` = 80738;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Power now lies at your fingertips. Use this enchantment wisely, and you can overcome great obstacles.',
    `RequestItemsText` = 'So, made your mind up?'
WHERE `entry` = 80739;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Oh, it''s you! And you got it back. Elune herself thanks you for your kindness. Here''s a surprise for you.',
    `RequestItemsText` = 'Happy Lunar Festival!'
WHERE `entry` = 80740;

UPDATE `quest_template` SET
    `OfferRewardText` = 'The lanterns have drifted far, carrying your blessings to the world.$B$BMay the light youŌĆÖve set forth bring peace and joy to you and yours during this festival.$B$BTake these mooncakes as a token of our gratitude.',
    `RequestItemsText` = 'What a beautiful moonlit night!'
WHERE `entry` = 80745;

UPDATE `quest_template` SET
    `OfferRewardText` = 'I will now grant you the skills you need to train and guide your pet. Not only will you be able to teach your pet new abilities, you will now be able to feed your pet, as well as revive it, should it fall in battle.$B$BNow, go. Gather your beasts and turn them to the cause of the Dark Lady.',
    `RequestItemsText` = ''
WHERE `entry` = 80755;

UPDATE `quest_template` SET
    `OfferRewardText` = 'Well done! I was starting to think no one would take down that monster!',
    `RequestItemsText` = 'Clear your head of impure thoughts, $C. We must trust the light to guide us to victory.'
WHERE `entry` = 140821;

UPDATE `quest_template` SET
    `OfferRewardText` = 'You have proven yourself a worthy warrior, $N. Well done.',
    `RequestItemsText` = 'Waste no time. We must strike at once!'
WHERE `entry` = 1140820;


